function bytesFromBase64(value) {
  const bin = atob(value);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i += 1) out[i] = bin.charCodeAt(i);
  return out;
}

function cleanText(value, fallback = "-") {
  const text = String(value ?? "").trim();
  return text || fallback;
}

function isReservedUserSpaceId(value) {
  return RESERVED_USER_SPACE_IDS.has(cleanText(value, "").toLowerCase());
}

function sanitizeUserSpaces(spaces, fallback = []) {
  if (!Array.isArray(spaces)) return fallback;
  const seen = new Set();
  return spaces.reduce((items, space) => {
    if (!space || typeof space !== "object") return items;
    const id = cleanText(space.id, "").toLowerCase();
    if (!id || isReservedUserSpaceId(id) || seen.has(id)) return items;
    seen.add(id);
    items.push({
      ...space,
      id,
      title: cleanText(space.title || id, id),
    });
    return items;
  }, []);
}

function truncateText(value, max = 180) {
  const text = String(value ?? "").replace(/\s+/g, " ").trim();
  if (!text) return "";
  return text.length > max ? `${text.slice(0, max - 1)}...` : text;
}

function formatTurnElapsed(ms) {
  const totalSeconds = Math.max(0, Math.floor(Number(ms || 0) / 1000));
  if (totalSeconds < 60) return `${totalSeconds}s`;
  const totalMinutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  if (totalMinutes < 60) return `${totalMinutes}m ${String(seconds).padStart(2, "0")}s`;
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  return `${hours}h ${String(minutes).padStart(2, "0")}m`;
}

function redactValue(value) {
  if (value == null) return value;
  if (typeof value === "string") {
    if (/bearer\s+[a-z0-9._-]+/i.test(value)) return "[redacted bearer token]";
    if (value.length > 260) return truncateText(value, 260);
  }
  if (Array.isArray(value)) return value.map(redactValue);
  if (typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value).map(([key, item]) => {
        if (/password|token|secret|api[_-]?key|authorization/i.test(key)) return [key, "[redacted]"];
        return [key, redactValue(item)];
      })
    );
  }
  return value;
}

function summarizeEventTarget(target) {
  if (!target) return "unknown";
  const element = target.closest?.("button,input,textarea,select,s-select,a,[data-panel],[data-widget-id],[data-widget-app]");
  if (!element) return target.tagName ? target.tagName.toLowerCase() : "unknown";
  if (element.dataset?.widgetId) return `widget:${element.dataset.widgetId}`;
  if (element.dataset?.widgetApp) return `app:${element.dataset.widgetApp}`;
  if (element.dataset?.panel) return `panel:${element.dataset.panel}`;
  if (element.id) return `#${element.id}`;
  const label = element.getAttribute("aria-label") || element.getAttribute("title") || element.textContent || element.tagName;
  return truncateText(label, 48);
}

function describeEventTarget(target) {
  if (!target || !target.tagName) return { tag: "unknown" };
  const element = target;
  const closestWidget = element.closest?.("[data-widget-id]");
  const closestPanel = element.closest?.("[data-panel]");
  const classes = Array.from(element.classList || []).slice(0, 8);
  const path = [];
  let current = element;
  while (current && current !== els.app && path.length < 5) {
    const tag = current.tagName ? current.tagName.toLowerCase() : "";
    if (!tag) break;
    const id = current.id ? `#${current.id}` : "";
    const className = current.classList?.[0] ? `.${current.classList[0]}` : "";
    path.push(`${tag}${id}${className}`);
    current = current.parentElement;
  }
  return {
    tag: element.tagName.toLowerCase(),
    id: element.id || "",
    classes,
    role: element.getAttribute("role") || "",
    aria_label: element.getAttribute("aria-label") || "",
    title: truncateText(element.getAttribute("title") || "", 80),
    data_panel: element.dataset?.panel || closestPanel?.dataset?.panel || "",
    data_widget_id: element.dataset?.widgetId || closestWidget?.dataset?.widgetId || "",
    path,
    form_value: safeElementFormValue(element),
  };
}

function safeElementFormValue(element) {
  if (!element || !["INPUT", "TEXTAREA", "SELECT"].includes(element.tagName)) return null;
  const type = String(element.getAttribute("type") || element.type || element.tagName).toLowerCase();
  const identity = [
    element.id || "",
    element.name || "",
    element.getAttribute("aria-label") || "",
    element.getAttribute("placeholder") || "",
    Array.from(element.classList || []).join(" "),
  ].join(" ").toLowerCase();
  if (/password|secret|token|api[_-]?key|authorization|credential|cookie|session/.test(`${identity} ${type}`)) {
    return { type, redacted: true, length: String(element.value || "").length };
  }
  if (type === "file" || type === "hidden") return { type, redacted: true, length: 0 };
  if (type === "checkbox" || type === "radio") return { type, checked: Boolean(element.checked) };
  const value = String(element.value ?? "");
  const numericLike = ["number", "range", "color", "date", "datetime-local", "month", "time", "week"].includes(type);
  const configLike = Boolean(element.closest?.("#configModal") || /config|area|distance|space/.test(identity));
  return {
    type,
    value: numericLike || configLike ? truncateText(value, 120) : "",
    length: value.length,
    redacted: !(numericLike || configLike),
  };
}

function roundedNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? Math.round(number) : 0;
}

function compactRect(rect) {
  if (!rect) return null;
  return {
    left: roundedNumber(rect.left),
    top: roundedNumber(rect.top),
    width: roundedNumber(rect.width),
    height: roundedNumber(rect.height),
  };
}

function eventElementAtPoint(event) {
  return event?.target?.tagName
    ? event.target
    : document.elementFromPoint?.(Number(event?.clientX || 0), Number(event?.clientY || 0));
}

function pointerTraceEntry(event, phase) {
  const target = eventElementAtPoint(event);
  const targetRect = target?.getBoundingClientRect?.();
  const viewportRect = els.spaceViewport?.getBoundingClientRect?.();
  const started = state.activePointers.get(event.pointerId);
  const clientX = roundedNumber(event.clientX);
  const clientY = roundedNumber(event.clientY);
  const targetLeft = Number(targetRect?.left || 0);
  const targetTop = Number(targetRect?.top || 0);
  const viewportLeft = Number(viewportRect?.left || 0);
  const viewportTop = Number(viewportRect?.top || 0);
  return {
    kind: "pointer",
    phase,
    pointer_id: Number(event.pointerId || 0),
    pointer_type: event.pointerType || "",
    is_primary: event.isPrimary !== false,
    button: Number(event.button ?? -1),
    buttons: Number(event.buttons || 0),
    client: { x: clientX, y: clientY },
    target_offset: {
      x: roundedNumber(clientX - targetLeft),
      y: roundedNumber(clientY - targetTop),
    },
    space_viewport_offset: viewportRect ? {
      x: roundedNumber(clientX - viewportLeft),
      y: roundedNumber(clientY - viewportTop),
    } : null,
    target: summarizeEventTarget(target),
    target_detail: describeEventTarget(target),
    target_rect: compactRect(targetRect),
    capture: {
      target_has_pointer_capture: Boolean(target?.hasPointerCapture?.(event.pointerId)),
      active_element: summarizeEventTarget(document.activeElement),
    },
    duration_ms: started ? roundedNumber(performance.now() - started.startedAt) : 0,
    distance_px: started ? roundedNumber(Math.hypot(clientX - started.startX, clientY - started.startY)) : 0,
  };
}

function androidFastPointerTraceEntry(event, phase) {
  const started = state.activePointers.get(event.pointerId);
  const clientX = roundedNumber(event.clientX);
  const clientY = roundedNumber(event.clientY);
  return {
    kind: "pointer",
    phase,
    pointer_id: Number(event.pointerId || 0),
    pointer_type: event.pointerType || "",
    is_primary: event.isPrimary !== false,
    button: Number(event.button ?? -1),
    buttons: Number(event.buttons || 0),
    client: { x: clientX, y: clientY },
    target: started?.target || summarizeEventTarget(event.target),
    duration_ms: started ? roundedNumber(performance.now() - started.startedAt) : 0,
    distance_px: started ? roundedNumber(Math.hypot(clientX - started.startX, clientY - started.startY)) : 0,
    android_fast_trace: true,
  };
}

function appendInteractionTrace(entry, options = {}) {
  state.interactionTrace.push({
    schema: "hermes.space_os.interaction_event.v1",
    id: `int_${Date.now().toString(36)}_${(state.interactionSeq += 1).toString(36)}`,
    timestamp: new Date().toISOString(),
    active_panel: state.activePanel,
    ...(options.redact === false ? entry : redactValue(entry)),
  });
  const traceLimit = isAndroidNativeShell() ? ANDROID_INTERACTION_TRACE_LIMIT : INTERACTION_TRACE_LIMIT;
  if (state.interactionTrace.length > traceLimit) {
    state.interactionTrace.splice(0, state.interactionTrace.length - traceLimit);
  }
  if (options.publish !== false) {
    scheduleObservationRender();
    scheduleObservationPublish();
  }
}

function recordPointerInteraction(event, phase) {
  const now = performance.now();
  if (phase === "down") {
    state.activePointers.set(event.pointerId, {
      pointerId: event.pointerId,
      pointerType: event.pointerType || "",
      target: summarizeEventTarget(event.target || eventElementAtPoint(event)),
      startX: roundedNumber(event.clientX),
      startY: roundedNumber(event.clientY),
      currentX: roundedNumber(event.clientX),
      currentY: roundedNumber(event.clientY),
      startedAt: now,
      lastMoveAt: 0,
    });
  }
  const pointer = state.activePointers.get(event.pointerId);
	  if (phase === "move") {
	    if (isAndroidNativeShell()) {
	      if (androidCanvasNavigationActive(now)) return;
	      if (!pointer || now - pointer.lastMoveAt < ANDROID_POINTER_MOVE_SAMPLE_MS) return;
      pointer.lastMoveAt = now;
      pointer.currentX = roundedNumber(event.clientX);
      pointer.currentY = roundedNumber(event.clientY);
      appendInteractionTrace(androidFastPointerTraceEntry(event, phase), { publish: false, redact: false });
      return;
    }
    if (!pointer || now - pointer.lastMoveAt < POINTER_MOVE_SAMPLE_MS) return;
    pointer.lastMoveAt = now;
    pointer.currentX = roundedNumber(event.clientX);
    pointer.currentY = roundedNumber(event.clientY);
    appendInteractionTrace(pointerTraceEntry(event, phase), { publish: false });
    scheduleObservationPublish();
    return;
  }
  if (isAndroidNativeShell()) {
    appendInteractionTrace(androidFastPointerTraceEntry(event, phase), { publish: false, redact: false });
    if (["up", "cancel"].includes(phase)) state.activePointers.delete(event.pointerId);
    if (["up", "cancel"].includes(phase)) window.setTimeout(scheduleObservationPublish, ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS);
    return;
  }
  appendInteractionTrace(pointerTraceEntry(event, phase));
  if (["up", "cancel"].includes(phase)) state.activePointers.delete(event.pointerId);
}

function recordWheelInteraction(event) {
  const now = performance.now();
  if (now - state.lastWheelTraceAt < WHEEL_TRACE_SAMPLE_MS) return;
  state.lastWheelTraceAt = now;
  const target = eventElementAtPoint(event);
  appendInteractionTrace({
    kind: "wheel",
    delta: {
      x: roundedNumber(event.deltaX),
      y: roundedNumber(event.deltaY),
      mode: Number(event.deltaMode || 0),
    },
    client: { x: roundedNumber(event.clientX), y: roundedNumber(event.clientY) },
    target: summarizeEventTarget(target),
    target_detail: describeEventTarget(target),
    target_rect: compactRect(target?.getBoundingClientRect?.()),
    canvas_distance: Number(canvasDistance().toFixed(2)),
  }, { publish: false });
  scheduleObservationPublish();
}

function recordSpaceScrollInteraction() {
  const now = performance.now();
  if (now - state.lastScrollTraceAt < SCROLL_TRACE_SAMPLE_MS) return;
  state.lastScrollTraceAt = now;
  appendInteractionTrace({
    kind: "scroll",
    target: "space-viewport",
    scroll: {
      left: roundedNumber(els.spaceViewport?.scrollLeft || 0),
      top: roundedNumber(els.spaceViewport?.scrollTop || 0),
    },
    canvas_distance: Number(canvasDistance().toFixed(2)),
    canvas_area: serializableSpaceArea(canvasAreaSize()),
  }, { publish: false });
  scheduleObservationPublish();
}

function recordViewportInteraction(kind = "viewport.resize") {
  appendInteractionTrace({
    kind,
    viewport: {
      width: roundedNumber(window.innerWidth),
      height: roundedNumber(window.innerHeight),
      visual_width: roundedNumber(window.visualViewport?.width || window.innerWidth),
      visual_height: roundedNumber(window.visualViewport?.height || window.innerHeight),
    },
  }, { publish: false });
  scheduleObservationPublish();
}

function installInteractionTrace() {
  if (state.pointerTraceInstalled) return;
  state.pointerTraceInstalled = true;
  if (isAndroidNativeShell()) {
    window.addEventListener("wheel", recordWheelInteraction, { capture: true, passive: true });
    window.addEventListener("resize", () => recordViewportInteraction("viewport.resize"), { passive: true });
    window.visualViewport?.addEventListener("resize", () => recordViewportInteraction("visual_viewport.resize"), { passive: true });
    return;
  }
  window.addEventListener("pointerdown", (event) => recordPointerInteraction(event, "down"), { capture: true, passive: true });
  window.addEventListener("pointermove", (event) => recordPointerInteraction(event, "move"), { capture: true, passive: true });
  window.addEventListener("pointerup", (event) => recordPointerInteraction(event, "up"), { capture: true, passive: true });
  window.addEventListener("pointercancel", (event) => recordPointerInteraction(event, "cancel"), { capture: true, passive: true });
  window.addEventListener("wheel", recordWheelInteraction, { capture: true, passive: true });
  els.spaceViewport?.addEventListener("scroll", recordSpaceScrollInteraction, { passive: true });
  window.addEventListener("resize", () => recordViewportInteraction("viewport.resize"), { passive: true });
  window.visualViewport?.addEventListener("resize", () => recordViewportInteraction("visual_viewport.resize"), { passive: true });
}

function recordUserEvent(type, options = {}) {
  const deferPublish = Boolean(options.deferPublish);
  const event = {
    schema: "hermes.space_os.user_event.v1",
    id: `evt_${Date.now().toString(36)}_${(state.eventSeq += 1).toString(36)}`,
    timestamp: new Date().toISOString(),
    type,
    source: options.source || "wasm-agent",
    target: options.target || "",
    summary: truncateText(options.summary || type, 160),
    data: options.redact === false ? (options.data || {}) : redactValue(options.data || {}),
    redacted: Boolean(options.redacted),
    duration_ms: Number.isFinite(options.duration_ms) ? Math.round(options.duration_ms) : null,
  };
  state.userEvents.push(event);
  if (state.userEvents.length > USER_EVENT_LIMIT) {
    state.userEvents.splice(0, state.userEvents.length - USER_EVENT_LIMIT);
  }
  if (deferPublish && isAndroidNativeShell() && androidNativePerfSafeMode()) {
    return event;
  }
  if (deferPublish) {
    window.setTimeout(() => {
      scheduleObservationRender();
      scheduleObservationPublish();
    }, ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS);
  } else {
    scheduleObservationRender();
    scheduleObservationPublish();
  }
  return event;
}

function markAndroidNativeUserInput() {
  androidNativeLastUserInputAt = Date.now();
}

function installAndroidNativeUxBudgetGuards() {
  if (!isAndroidNativeShell() || state.androidNativeUxBudgetGuardsInstalled) return;
  state.androidNativeUxBudgetGuardsInstalled = true;
  ["pointerdown", "pointermove", "pointerup", "touchstart", "touchmove", "keydown", "input", "wheel"].forEach((type) => {
    window.addEventListener(type, markAndroidNativeUserInput, { capture: true, passive: true });
  });
}

function androidNativeQueryParam(name, fallback = "") {
  try {
    const params = new URL(window.location.href).searchParams;
    return cleanText(params.get(name), fallback);
  } catch {
    return fallback;
  }
}

function androidNativeFlagParam(name) {
  const value = androidNativeQueryParam(name, "").toLowerCase();
  return value === "1" || value === "true" || value === "yes" || value === "on";
}

function androidNativePerfSafeMode() {
  return Boolean(window.__WASM_AGENT_ANDROID_PERF_SAFE_MODE__ === true || androidNativeFlagParam("perfSafeMode") || androidNativeFlagParam("perf_safe_mode"));
}

function androidNativeWakeDisabled() {
  return androidNativePerfSafeMode() || androidNativeQueryParam("wake", "").toLowerCase() === "off";
}

function androidNativeBridgeDiagnosticsOff() {
  return androidNativePerfSafeMode() || androidNativeQueryParam("bridgeDiagnostics", androidNativeQueryParam("bridge_diagnostics", "")).toLowerCase() === "off";
}

function androidNativeControlAutoStartEnabled() {
  const mode = androidNativeQueryParam("nativeControl", androidNativeQueryParam("native_control", "")).toLowerCase();
  if (["1", "true", "yes", "on"].includes(mode)) return true;
  if (["0", "false", "no", "off"].includes(mode)) return false;
  return !androidNativePerfSafeMode();
}

function androidNativeCountReason(map, reason = "unknown") {
  const key = cleanText(reason, "unknown").slice(0, 80);
  map[key] = (Number(map[key]) || 0) + 1;
}

function androidNativeRecordTouch(kind = "touch", reason = "") {
  if (!isAndroidNativeShell()) return;
  if (kind !== "ignored") androidNativeResponsiveness.touch_event_count += 1;
  if (reason) {
    androidNativeResponsiveness.ignored_touch_count += 1;
    androidNativeCountReason(androidNativeResponsiveness.ignored_touch_reasons, reason);
  }
  if (kind === "pan_start") androidNativeResponsiveness.canvas_pan_start_count += 1;
  if (kind === "pan_move") androidNativeResponsiveness.canvas_pan_move_count += 1;
  if (kind === "pan_end") androidNativeResponsiveness.canvas_pan_end_count += 1;
}

function androidNativeRecordMiniMap(kind = "requested", reason = "") {
  if (!isAndroidNativeShell()) return;
  if (kind === "requested") androidNativeResponsiveness.minimap_render_requested_count += 1;
  else if (kind === "executed") androidNativeResponsiveness.minimap_render_executed_count += 1;
  else if (kind === "viewport") androidNativeResponsiveness.minimap_render_executed_count += 1;
  else {
    androidNativeResponsiveness.minimap_render_skipped_count += 1;
    androidNativeCountReason(androidNativeResponsiveness.minimap_render_skip_reasons, reason || kind);
  }
}

function androidNativeRecordMomentumTapEvent(phase = "event", event = null, extra = {}) {
  if (!isAndroidNativeShell()) return;
  const trace = Array.isArray(androidNativeResponsiveness.momentum_tap_trace)
    ? androidNativeResponsiveness.momentum_tap_trace
    : [];
  const point = event ? androidEventClientPoint(event) : { x: 0, y: 0 };
  trace.push({
    at_ms: roundedPerfMs(performance.now()),
    phase: cleanText(phase, "").slice(0, 60),
    type: cleanText(event?.type || "", "").slice(0, 40),
    target: cleanText(event ? summarizeEventTarget(event.target) : "", "").slice(0, 120),
    x: Math.round(Number(point.x || 0)),
    y: Math.round(Number(point.y || 0)),
    momentum_active: Boolean(state.spacePanMomentumActive),
    minimap_visible: Boolean(state.spaceMiniMapVisible),
    minimap_hidden: Boolean(els.spaceMiniMap?.hidden),
    android_scroll_deferred_ms: Math.max(0, Math.round(Number(state.androidSpaceScrollDeferredUntil || 0) - performance.now())),
    recent_navigation_ms: Math.max(0, Math.round(performance.now() - Number(state.spaceNavigationInputAt || 0))),
    active_panel: cleanText(state.activePanel, ""),
    ...extra,
  });
  androidNativeResponsiveness.momentum_tap_trace = trace.slice(-24);
}

function androidNativeRecentUserInput(ms = ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS) {
  return Date.now() - androidNativeLastUserInputAt < ms;
}

function androidNativeInputPending() {
  try {
    return Boolean(navigator.scheduling?.isInputPending?.({ includeContinuous: true }));
  } catch {
    return false;
  }
}

function androidNativeResponsivenessOverloadedNow() {
  return Boolean(
    androidNativeResponsiveness.max_frame_gap_ms >= ANDROID_NATIVE_RESPONSIVENESS_OVERLOADED_MS
      || androidNativeResponsiveness.max_event_loop_lag_ms >= ANDROID_NATIVE_RESPONSIVENESS_OVERLOADED_MS
      || androidNativeResponsiveness.max_long_task_ms >= ANDROID_NATIVE_RESPONSIVENESS_OVERLOADED_MS
      || androidNativeInputPending()
  );
}

function androidNativeControlCanRun(options = {}) {
  const heavy = Boolean(options.heavy);
  const quietMs = heavy ? ANDROID_NATIVE_CONTROL_HEAVY_QUIET_MS : ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS;
  if (document.hidden && !options.allowHidden) return { ok: false, reason: "document_hidden" };
  if (!options.force && androidNativeResponsivenessOverloadedNow()) return { ok: false, reason: "app_overloaded" };
  if (androidNativeRecentUserInput(quietMs)) return { ok: false, reason: "recent_user_input" };
  if (androidNativeInputPending()) return { ok: false, reason: "input_pending" };
  return { ok: true, reason: "budget_available" };
}

function runAndroidNativeIdleTask(task, options = {}) {
  return new Promise((resolve) => {
    const startedAt = Date.now();
    const run = () => {
      const budget = androidNativeControlCanRun({ heavy: true, allowHidden: options.allowHidden });
      if (!budget.ok && !options.force) {
        const maxWaitMs = Number.isFinite(Number(options.maxWaitMs))
          ? Math.max(0, Number(options.maxWaitMs))
          : 30000;
        if (Date.now() - startedAt < maxWaitMs) {
          window.setTimeout(() => {
            if (typeof window.requestIdleCallback === "function") {
              window.requestIdleCallback(run, { timeout: ANDROID_NATIVE_CONTROL_IDLE_TIMEOUT_MS });
            } else {
              run();
            }
          }, ANDROID_NATIVE_CONTROL_HEAVY_QUIET_MS);
          return;
        }
        resolve({ ok: false, skipped: true, reason: budget.reason, waited_ms: Date.now() - startedAt });
        return;
      }
      try {
        resolve(task());
      } catch (error) {
        resolve({ ok: false, error: errorMessage(error) });
      }
    };
    const timeoutMs = Number.isFinite(Number(options.timeoutMs))
      ? Number(options.timeoutMs)
      : ANDROID_NATIVE_CONTROL_IDLE_TIMEOUT_MS;
    if (typeof window.requestIdleCallback === "function") {
      window.requestIdleCallback(run, { timeout: timeoutMs });
    } else {
      window.setTimeout(run, 0);
    }
  });
}

function androidNativeYield(ms = 0) {
  const delayMs = Math.max(0, Number(ms) || 0);
  if (delayMs > 0) return new Promise((resolve) => window.setTimeout(resolve, delayMs));
  if (typeof window.scheduler?.postTask === "function") {
    return window.scheduler.postTask(() => undefined, { priority: "user-blocking" }).catch(() => {});
  }
  if (typeof MessageChannel === "function") {
    return new Promise((resolve) => {
      const channel = new MessageChannel();
      channel.port1.onmessage = () => {
        channel.port1.close();
        resolve();
      };
      channel.port2.postMessage(0);
    });
  }
  return Promise.resolve();
}

function androidNativeAfterPaint() {
  return new Promise((resolve) => {
    const raf = window.requestAnimationFrame || ((callback) => window.setTimeout(() => callback(performance.now()), 16));
    raf(() => raf(resolve));
  });
}

function androidNativeRunVisual(task, label = "visual") {
  if (!isAndroidNativeShell()) return task?.();
  markAndroidNativeUserInput();
  state.androidNativeVisualLaneUntil = Date.now() + ANDROID_NATIVE_VISUAL_SETTLE_MS;
  const started = performance.now();
  try {
    return task?.();
  } finally {
    state.androidNativeLastVisualTask = {
      label: cleanText(label, "visual"),
      duration_ms: Math.max(0, Math.round(performance.now() - started)),
      at: new Date().toISOString(),
    };
  }
}

function androidNativeAfterQuiet(task, label = "quiet") {
  if (!isAndroidNativeShell()) return window.setTimeout(() => task?.(), 0);
  return window.setTimeout(() => {
    if (androidNativeRecentUserInput(ANDROID_NATIVE_VISUAL_SETTLE_MS) || androidNativeInputPending()) {
      androidNativeAfterQuiet(task, label);
      return;
    }
    void androidNativeAfterPaint().then(async () => {
      if (androidNativeRecentUserInput(ANDROID_NATIVE_VISUAL_SETTLE_MS) || androidNativeInputPending()) {
        androidNativeAfterQuiet(task, label);
        return;
      }
      const started = performance.now();
      try {
        await task?.();
      } finally {
        state.androidNativeLastQuietTask = {
          label: cleanText(label, "quiet"),
          duration_ms: Math.max(0, Math.round(performance.now() - started)),
          at: new Date().toISOString(),
        };
      }
    });
  }, ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS);
}

function androidNativeAfterPaintTask(task, label = "after-paint") {
  if (!isAndroidNativeShell()) {
    window.requestAnimationFrame?.(() => task?.()) || window.setTimeout(() => task?.(), 0);
    return 0;
  }
  void androidNativeAfterPaint().then(() => {
    const started = performance.now();
    try {
      task?.();
    } finally {
      state.androidNativeLastAfterPaintTask = {
        label: cleanText(label, "after-paint"),
        duration_ms: Math.max(0, Math.round(performance.now() - started)),
        at: new Date().toISOString(),
      };
    }
  });
  return 0;
}

async function waitForAndroidNativeInputQuiet(quietMs = ANDROID_NATIVE_INPUT_FIRST_QUIET_MS, options = {}) {
  if (!isAndroidNativeShell()) return;
  if (Number(quietMs) <= 0) return;
  const maxWaitMs = Number.isFinite(Number(options.maxWaitMs)) ? Number(options.maxWaitMs) : 20000;
  const startedAt = Date.now();
  while (
    !document.hidden
      && (androidNativeRecentUserInput(quietMs) || androidNativeInputPending())
      && Date.now() - startedAt < maxWaitMs
  ) {
    await androidNativeYield(250);
  }
}

async function waitForAndroidNativeFirstShellQuiet(reason = "startup", options = {}) {
  if (!isAndroidNativeShell()) return;
  if (!state.androidNativeFirstShellVisibleAtMs && state.androidNativeCachedShellPaintPromise) {
    await state.androidNativeCachedShellPaintPromise.catch(() => null);
  }
  const quietMs = Number.isFinite(Number(options.quietMs))
    ? Math.max(0, Number(options.quietMs))
    : ANDROID_NATIVE_INPUT_FIRST_QUIET_MS;
  if (quietMs <= 0) {
    clientBootMark("android_first_shell_quiet_window", {
      reason,
      quiet_ms: 0,
    });
    return;
  }
  const shellVisibleAt = Number(state.androidNativeFirstShellVisibleAtMs || 0);
  if (shellVisibleAt > 0) {
    const remaining = quietMs - Math.max(0, performance.now() - shellVisibleAt);
    if (remaining > 0) await androidNativeYield(remaining);
  }
  await waitForAndroidNativeInputQuiet(quietMs, {
    maxWaitMs: Number.isFinite(Number(options.maxWaitMs)) ? Number(options.maxWaitMs) : 20000,
  });
  clientBootMark("android_first_shell_quiet_window", {
    reason,
    quiet_ms: Math.round(quietMs),
  });
}

async function androidNativeHydrationYield(reason = "hydration") {
  if (!isAndroidNativeShell()) return;
  await waitForAndroidNativeInputQuiet(ANDROID_NATIVE_INPUT_FIRST_QUIET_MS, { maxWaitMs: 20000 });
  clientBootMark("android_input_first_yield", { reason });
  await androidNativeYield(ANDROID_NATIVE_HYDRATION_STEP_DELAY_MS);
}

function eventCounts() {
  return state.userEvents.reduce((counts, event) => {
    counts[event.type] = (counts[event.type] || 0) + 1;
    return counts;
  }, {});
}

function latestEvents(count = 36) {
  return state.userEvents.slice(-count).reverse();
}

function latestNonAgentClick() {
  return [...state.userEvents].reverse().find((event) => {
    if (!["workspace.click", "workspace.context_menu_requested"].includes(event.type)) return false;
    const target = String(event.target || "");
    const path = event.data?.target?.path || [];
    const id = event.data?.target?.id || "";
    return !target.includes("agent") && id !== "agentSendButton" && !path.some((item) => String(item).includes("agent-"));
  }) || null;
}

function buildObservationSnapshot() {
  const viewportRect = els.spaceViewport?.getBoundingClientRect?.() || { width: 0, height: 0 };
  const usableViewportRect = spaceViewportUsableRect() || viewportRect;
  const visualViewport = window.visualViewport;
  const browserRect = els.browserScreen?.getBoundingClientRect?.() || { width: 0, height: 0 };
  const activeSpace = activeSpaceContext();
  const recentErrors = state.userEvents
    .filter((event) => event.type.endsWith(".error") || event.data?.error)
    .slice(-8);
  const snapshot = {
    schema: "hermes.space_os.observation.v1",
    timestamp: new Date().toISOString(),
    cap: compactAgentCapabilityMap(),
    workspace: {
      active_panel: state.activePanel,
      active_space_id: activeSpace.id,
      active_space_name: activeSpace.name,
      active_space_display_name: activeSpace.display_name,
      active_space: activeSpace,
      active_widget: state.activeWidgetId || "",
      layout_version: SPACE_LAYOUT_SCHEMA,
      modules: MODULE_DEFINITIONS.map((module) => ({
        id: module.id,
        title: module.title,
        enabled: isModuleEnabled(module.id),
        status: module.status,
      })),
      timeline: state.timeline ? {
        branch: state.timeline.branch,
        head: state.timeline.head,
        dirty: state.timeline.dirty,
        dirty_count: state.timeline.dirty_count,
        checkpoint_count: state.timeline.checkpoints?.length || 0,
      } : null,
      widget_count: document.querySelectorAll(".widget[data-widget-id]").length,
      shared_room: activeSharedRoom() ? {
        id: activeSharedRoom().id || "",
        online_count: Number(activeSharedRoom().online_count || 0),
        member_count: Number(activeSharedRoom().member_count || 0),
        online_device_count: Number(activeSharedRoom().online_device_count || 0),
        last_sync_at: state.lastSharedSpaceSyncAt,
      } : null,
      viewport: { width: Math.round(viewportRect.width || 0), height: Math.round(viewportRect.height || 0) },
      viewport_diagnostics: {
        visual: visualViewport ? {
          width: Math.round(visualViewport.width || 0),
          height: Math.round(visualViewport.height || 0),
          offset_top: Math.round(visualViewport.offsetTop || 0),
          offset_left: Math.round(visualViewport.offsetLeft || 0),
        } : null,
        layout: {
          width: Math.round(window.innerWidth || 0),
          height: Math.round(window.innerHeight || 0),
        },
        space_viewport: {
          width: Math.round(viewportRect.width || 0),
          height: Math.round(viewportRect.height || 0),
        },
        usable_canvas: {
          width: Math.round(usableViewportRect.width || 0),
          height: Math.round(usableViewportRect.height || 0),
        },
        bottom_inset_px: viewportBottomInsetPx(),
        applied_canvas_padding_bottom_px: Math.round(appliedCanvasBottomPaddingPx()),
      },
    },
    browser: {
      url: state.browserCapture?.url || els.browserUrlInput?.value || "",
      domain: browserUrlHost(state.browserCapture?.url || els.browserUrlInput?.value || ""),
      status: els.browserStatus?.textContent || "",
      stream_mode: isBrowserStreamOpen() ? "websocket" : state.browserLive ? "polling" : "idle",
      live: Boolean(state.browserLive),
      busy: Boolean(state.browserBusy),
      pending_url: state.browserPendingUrl,
      frame_count: state.browserFrameCount,
      session_id: state.browserSessionId ? "present" : "",
      viewport: { width: Math.round(browserRect.width || 0), height: Math.round(browserRect.height || 0) },
      last_error: state.browserCapture?.status === "error" ? state.browserCapture.meta : "",
    },
    fleet: {
      bridge_ready: state.bridgeReady,
      bridge_url: state.bridgeUrl,
      selected_node: state.selectedNode,
      node_count: state.nodes.length,
      nodes: state.nodes.slice(0, 12).map((node) => ({
        id: node.id,
        status: node.status,
        runtime: node.runtime,
        running: node.running,
        model: node.model,
      })),
      resources: state.resources ? {
        cpu_percent: state.resources.cpu?.percent,
        memory_percent: state.resources.memory?.percent,
        disk_percent: state.resources.disk?.percent,
        uptime: state.resources.uptime?.display,
      } : null,
      last_error: state.lastError,
    },
    avatar_chat: {
      target_selector: agentNodeSelectDiagnostic(),
    },
    tasks: {
      active_task_id: state.taskId,
      status: state.taskId ? "running" : state.bridgeReady ? "idle" : "offline",
      recent: state.tasks.slice(0, 8).map((task) => ({
        id: task.task_id || task.id || "",
        status: task.status || "",
        target_node: task.target_node || "",
        preview: taskPreview(task),
      })),
      last_output_summary: truncateText(els.taskOutput?.textContent || "", 240),
    },
    logs: {
      selected_node: state.selectedNode,
      last_loaded: state.lastLogSummary,
      visible_summary: truncateText(els.logsOutput?.textContent || "", 240),
    },
    wis: state.wisSandbox ? state.wisSandbox.inspect() : null,
    wis_debug: wisDebugSnapshot(),
    analytics: {
      event_count: state.userEvents.length,
      event_limit: USER_EVENT_LIMIT,
      counts: eventCounts(),
      recent_errors: recentErrors,
      last_interaction_at: state.userEvents.at(-1)?.timestamp || "",
      last_non_agent_click: latestNonAgentClick(),
    },
    interaction: {
      trace_limit: INTERACTION_TRACE_LIMIT,
      trace_count: state.interactionTrace.length,
      recent_trace: state.interactionTrace.slice(-48).reverse(),
      active_pointers: Array.from(state.activePointers.values()).map((pointer) => ({
        pointer_id: Number(pointer.pointerId || 0),
        pointer_type: pointer.pointerType || "",
        target: pointer.target || "",
        start: { x: roundedNumber(pointer.startX), y: roundedNumber(pointer.startY) },
        current: { x: roundedNumber(pointer.currentX), y: roundedNumber(pointer.currentY) },
        duration_ms: roundedNumber(performance.now() - pointer.startedAt),
        distance_px: roundedNumber(Math.hypot(pointer.currentX - pointer.startX, pointer.currentY - pointer.startY)),
      })),
    },
    user_events: latestEvents(40),
  };
  state.observationSnapshot = snapshot;
  return snapshot;
}

function scheduleObservationRender() {
  window.clearTimeout(state.observationRenderTimer);
  if (isAndroidNativeShell() && state.activePanel !== "observe") return;
  state.observationRenderTimer = window.setTimeout(renderObservation, isAndroidNativeShell() ? ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS : 80);
}

function scheduleObservationPublish() {
  window.clearTimeout(state.observationPublishTimer);
  const delayMs = isAndroidNativeShell() ? ANDROID_NATIVE_CONTROL_HEAVY_QUIET_MS : 250;
  state.observationPublishTimer = window.setTimeout(() => {
    if (isAndroidNativeShell() && androidNativeRecentUserInput(ANDROID_NATIVE_CONTROL_HEAVY_QUIET_MS)) {
      scheduleObservationPublish();
      return;
    }
    void publishObservationSnapshot();
  }, delayMs);
}

async function publishObservationSnapshot() {
  if (state.observationPublishBusy) {
    scheduleObservationPublish();
    return;
  }
  state.observationPublishBusy = true;
  try {
    await fetch("/observation/latest", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(buildObservationSnapshot()),
    });
  } catch {
    // Observation publishing is a local debug affordance; UI behavior should not depend on it.
  } finally {
    state.observationPublishBusy = false;
  }
}

function renderObservation() {
  if (!els.observationSnapshot) return;
  if (!isModuleEnabled("observation")) {
    els.observationCount.textContent = "off";
    els.observationStats.replaceChildren(metric("Module", "Disabled"));
    els.observationTimeline.replaceChildren();
    els.observationSnapshot.textContent = "";
    return;
  }
  const snapshot = buildObservationSnapshot();
  els.observationCount.textContent = `${state.userEvents.length} events`;
  const counts = snapshot.analytics.counts;
  const topCounts = Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 6);
  els.observationStats.replaceChildren(
    ...[
      ["Panel", snapshot.workspace.active_panel],
      ["Widget", snapshot.workspace.active_widget || "-"],
      ["Browser", snapshot.browser.domain || "-"],
      ["Stream", snapshot.browser.stream_mode],
      ["Events", String(snapshot.analytics.event_count)],
      ["Errors", String(snapshot.analytics.recent_errors.length)],
      ...topCounts.map(([type, count]) => [type, String(count)]),
    ].map(([label, value]) => metric(label, value))
  );
  els.observationTimeline.replaceChildren(
    ...latestEvents(18).map((event) => {
      const item = document.createElement("div");
      item.className = "observation-event";
      const title = document.createElement("strong");
      title.textContent = event.type;
      const meta = document.createElement("div");
      meta.className = "node-meta";
      meta.textContent = `${new Date(event.timestamp).toLocaleTimeString()} / ${event.target || event.source}`;
      const summary = document.createElement("div");
      summary.className = "observation-summary";
      summary.textContent = event.summary;
      item.append(title, meta, summary);
      return item;
    })
  );
  els.observationSnapshot.textContent = JSON.stringify(snapshot, null, 2);
}

function wisSurfaceState() {
  try {
    return state.wisSandbox?.inspect?.() || null;
  } catch (error) {
    state.lastError = error.message || String(error);
    return null;
  }
}

function wisArtifactTargets() {
  const targets = new Map();
  const add = (target) => {
    const id = cleanText(target.id, "");
    if (!id || targets.has(id)) return;
    targets.set(id, target);
  };
  add({ id: "home", panel: "home", title: "space-home", shared_space_id: "" });
  if (isAdminUser()) add({ id: "admin", panel: "admin", title: "space-admin", shared_space_id: "" });
  state.userSpaces.forEach((space) => add({
    id: cleanText(space.id, ""),
    panel: cleanText(space.id, ""),
    title: cleanText(space.title || space.id, space.id),
    shared_space_id: cleanText(space.shared_space_id, ""),
  }));
  const active = activeSpaceContext();
  add({
    id: active.id,
    panel: active.panel,
    title: active.display_name || active.name || active.id,
    shared_space_id: active.shared_space_id || "",
  });
  return Array.from(targets.values());
}

function wisArtifactTargetsForOrigin(origin = "auto") {
  const allTargets = wisArtifactTargets();
  if (!isAndroidNativeShell()) return allTargets;
  if (!["startup", "bootstrap", "auto", "poll"].includes(String(origin || ""))) return allTargets;
  if (state.activePanel === "wis" || widgetById("wis")?.classList?.contains("is-widget-active")) return allTargets;
  return [];
}

function decorateWisArtifact(artifact, payload, target, sourceLabel) {
  return {
    ...artifact,
    id: cleanText(artifact.id, ""),
    title: cleanText(artifact.title || artifact.id, artifact.id),
    space_id: cleanText(payload.space_id || target.id, target.id),
    panel: cleanText(target.panel || payload.space_id || target.id, target.id),
    shared_space_id: cleanText(payload.shared_space_id, ""),
    scope: cleanText(payload.scope, ""),
    source_label: sourceLabel,
    updated_at: cleanText(artifact.updated_at, ""),
  };
}

function logWisArtifactFlow(stage, detail = {}) {
  const data = {
    stage,
    artifact_id: cleanText(detail.artifact_id || detail.id, ""),
    type: cleanText(detail.type || detail.schema || "wis-artifact", "wis-artifact"),
    title: cleanText(detail.title, ""),
    space_id: cleanText(detail.space_id, ""),
    shared_space_id: cleanText(detail.shared_space_id, ""),
    origin: cleanText(detail.origin, ""),
    transport: cleanText(detail.transport, "http"),
    render_count: Number.isFinite(detail.render_count) ? detail.render_count : state.wisArtifacts.length,
  };
  try {
    console.info("[wasm-agent wis-artifact]", stage, data);
  } catch {
    // Console diagnostics are optional.
  }
  recordUserEvent("wis.artifact_flow", {
    target: data.artifact_id ? `wis:${data.artifact_id}` : "wis-artifacts",
    summary: `WIS artifact ${stage}`,
    data,
  });
}

function wisArtifactKey(artifact = {}) {
  const shared = cleanText(artifact.shared_space_id, "");
  const space = cleanText(artifact.space_id || artifact.panel, "home");
  const id = cleanText(artifact.id || artifact.artifact_id, "main");
  return `${shared ? `shared:${shared}` : `space:${space}`}:${id}`;
}

function readActiveWisArtifactPreference() {
  try {
    const payload = JSON.parse(localStorage.getItem(WIS_ACTIVE_ARTIFACT_STORAGE_KEY) || "null");
    return payload && typeof payload === "object" ? payload : null;
  } catch {
    return null;
  }
}

function saveActiveWisArtifactPreference(artifact = {}) {
  try {
    localStorage.setItem(WIS_ACTIVE_ARTIFACT_STORAGE_KEY, JSON.stringify({
      id: cleanText(artifact.id, ""),
      title: cleanText(artifact.title, ""),
      space_id: cleanText(artifact.space_id, ""),
      panel: cleanText(artifact.panel, ""),
      shared_space_id: cleanText(artifact.shared_space_id, ""),
      scope: cleanText(artifact.scope, ""),
      saved_at: new Date().toISOString(),
    }));
  } catch {
    // Restoring the last WIS artifact is helpful but never required.
  }
}

function wisArtifactMatchesActivePanel(artifact = {}, panel = state.activePanel) {
  const storageId = activeSpaceStorageId(panel);
  const sharedSpaceId = sharedUserSpaceForPanel(panel)?.shared_space_id || "";
  return cleanText(artifact.space_id || artifact.panel, "") === storageId
    || Boolean(sharedSpaceId && cleanText(artifact.shared_space_id, "") === sharedSpaceId);
}

function wisArtifactHasLocalCameraConfig(artifact = {}) {
  const prefix = `${cleanText(artifact.id, "")}:`;
  if (!prefix || prefix === ":") return false;
  return Object.keys(state.wisCameraConfigs || {}).some((key) => key.startsWith(prefix));
}

function maybeRestoreWisArtifact(origin = "auto") {
  if (state.wisActiveArtifact || state.wisArtifactRestoreBusy || !state.wisArtifacts.length) return;
  const candidates = state.wisArtifacts.filter((artifact) => wisArtifactMatchesActivePanel(artifact));
  if (!candidates.length) return;
  const saved = readActiveWisArtifactPreference();
  const savedKey = saved ? wisArtifactKey(saved) : "";
  const savedMatch = savedKey ? candidates.find((artifact) => wisArtifactKey(artifact) === savedKey) : null;
  const cameraMatch = candidates.find(wisArtifactHasLocalCameraConfig);
  const patchMatch = String(origin || "").includes("patch") ? candidates[0] : null;
  const target = savedMatch || cameraMatch || patchMatch;
  if (!target) return;
  state.wisArtifactRestoreBusy = true;
  void openWisArtifact(target, { restore: true }).finally(() => {
    state.wisArtifactRestoreBusy = false;
  });
}

function targetForWisArtifactPayload(payload = {}) {
  const spaceId = cleanText(payload.space_id, activeSpaceStorageId());
  const sharedSpaceId = cleanText(payload.shared_space_id, "");
  return wisArtifactTargets().find((target) => (
    cleanText(target.id, "") === spaceId
    || (sharedSpaceId && cleanText(target.shared_space_id, "") === sharedSpaceId)
  )) || {
    id: spaceId,
    panel: spaceId,
    title: spaceId,
    shared_space_id: sharedSpaceId,
  };
}

function upsertWisArtifactSummary(summary = {}, origin = "patch") {
  const artifactId = cleanText(summary.id || summary.artifact_id, "");
  if (!artifactId) return null;
  const payload = {
    space_id: cleanText(summary.space_id, activeSpaceStorageId()),
    shared_space_id: cleanText(summary.shared_space_id, ""),
    scope: cleanText(summary.scope, ""),
  };
  const target = targetForWisArtifactPayload(payload);
  const decorated = decorateWisArtifact({
    id: artifactId,
    title: cleanText(summary.title || artifactId, artifactId),
    schema: cleanText(summary.schema || WIS_PATCH_SCHEMA, ""),
    updated_at: cleanText(summary.updated_at, new Date().toISOString()),
  }, payload, target, cleanText(summary.source_label || `${target.title || target.id} / ${payload.shared_space_id ? "shared" : "local"}`, ""));
  const key = wisArtifactKey(decorated);
  const next = state.wisArtifacts.filter((item) => wisArtifactKey(item) !== key);
  next.push(decorated);
  state.wisArtifacts = next.sort((left, right) => String(right.updated_at).localeCompare(String(left.updated_at)));
  logWisArtifactFlow("state-upsert", { ...decorated, origin, render_count: state.wisArtifacts.length });
  renderArtifacts();
  return decorated;
}

async function refreshWisArtifactsAfterPatch(result = {}, origin = "patch") {
  const patches = Array.isArray(result.patches) && result.patches.length ? result.patches : [result];
  const applied = patches.filter((patch) => patch?.applied && cleanText(patch.artifact_id, ""));
  if (!applied.length) return state.wisArtifacts;
  logWisArtifactFlow("patch-response", {
    origin,
    artifact_id: applied.map((patch) => patch.artifact_id).join(","),
    type: result.schema || WIS_PATCH_SCHEMA,
    transport: "http",
  });
  for (const patch of applied) {
    const query = new URLSearchParams({ space: cleanText(patch.space_id, activeSpaceStorageId()) });
    if (patch.shared_space_id) query.set("shared_space", patch.shared_space_id);
    try {
      const payload = await fetchJson(`/wis/artifacts/${encodeURIComponent(patch.artifact_id)}?${query.toString()}`, { timeoutMs: 10000 });
      const artifact = payload.artifact && typeof payload.artifact === "object" ? payload.artifact : {};
      upsertWisArtifactSummary({
        id: payload.artifact_id || patch.artifact_id,
        title: artifact.title || patch.title || patch.artifact_id,
        schema: artifact.schema || payload.schema || "",
        space_id: payload.space_id || patch.space_id,
        shared_space_id: payload.shared_space_id || patch.shared_space_id,
        scope: payload.scope || patch.scope,
        updated_at: artifact.updated_at || patch.updated_at,
        source_label: `${targetForWisArtifactPayload(payload).title || payload.space_id} / ${payload.shared_space_id ? "shared" : "local"}`,
      }, origin);
      logWisArtifactFlow("read-after-patch", {
        origin,
        artifact_id: payload.artifact_id || patch.artifact_id,
        title: artifact.title || "",
        schema: artifact.schema || payload.schema || "",
        space_id: payload.space_id || patch.space_id,
        shared_space_id: payload.shared_space_id || patch.shared_space_id,
        transport: "http",
      });
    } catch (error) {
      upsertWisArtifactSummary({
        id: patch.artifact_id,
        title: patch.title || patch.artifact_id,
        space_id: patch.space_id,
        shared_space_id: patch.shared_space_id,
        scope: patch.scope,
        updated_at: patch.updated_at,
      }, origin);
      logWisArtifactFlow("read-after-patch-error", {
        origin,
        artifact_id: patch.artifact_id,
        space_id: patch.space_id,
        shared_space_id: patch.shared_space_id,
        type: error.message || "error",
      });
    }
  }
  return loadWisArtifacts(origin);
}

async function loadWisArtifacts(origin = "auto") {
  if (!state.authUser || state.wisArtifactsBusy) return state.wisArtifacts;
  state.wisArtifactsBusy = true;
  renderArtifacts();
  try {
    await loadWisCameraArtifactRuntime(`wis_artifacts:${origin}`);
    const requests = [];
    const seen = new Set();
    for (const target of wisArtifactTargetsForOrigin(origin)) {
      const localKey = `${target.id}:local`;
      if (!seen.has(localKey)) {
        seen.add(localKey);
        const query = new URLSearchParams({ space: target.id });
        requests.push(fetchJson(`/wis/artifacts?${query.toString()}`, { timeoutMs: 8000 })
          .then((payload) => ({ payload, target, label: `${target.title} / local` }))
          .catch((error) => ({ error, target, label: `${target.title} / local` })));
      }
      if (target.shared_space_id) {
        const sharedKey = `${target.shared_space_id}:shared`;
        if (!seen.has(sharedKey)) {
          seen.add(sharedKey);
          const query = new URLSearchParams({ space: target.id, shared_space: target.shared_space_id });
          requests.push(fetchJson(`/wis/artifacts?${query.toString()}`, { timeoutMs: 8000 })
            .then((payload) => ({ payload, target, label: `${target.title} / shared` }))
            .catch((error) => ({ error, target, label: `${target.title} / shared` })));
        }
      }
    }
    const responses = await Promise.all(requests);
    const artifacts = [];
    responses.forEach((response) => {
      if (!response.payload) return;
      const items = Array.isArray(response.payload.artifacts) ? response.payload.artifacts : [];
      items.forEach((artifact) => artifacts.push(decorateWisArtifact(artifact, response.payload, response.target, response.label)));
    });
    state.wisArtifacts = artifacts.sort((left, right) => String(right.updated_at).localeCompare(String(left.updated_at)));
    state.wisArtifactsLoadedAt = new Date().toISOString();
    logWisArtifactFlow("state-refresh", {
      origin,
      artifact_id: artifacts.map((artifact) => artifact.id).slice(0, 12).join(","),
      type: "wis-artifacts-list",
      transport: "http-refresh",
      render_count: state.wisArtifacts.length,
    });
    recordUserEvent("wis.artifacts_loaded", {
      target: "wis-artifacts",
      summary: `Loaded ${state.wisArtifacts.length} WIS artifacts`,
      data: { origin, count: state.wisArtifacts.length },
    });
    renderArtifacts();
    maybeRestoreWisArtifact(origin);
    return state.wisArtifacts;
  } finally {
    state.wisArtifactsBusy = false;
    renderArtifacts();
  }
}

function wisArtifactAvailableInPanel(panel = state.activePanel) {
  const artifact = state.wisActiveArtifact;
  if (!artifact) return false;
  if (cleanText(artifact.space_id, "") === activeSpaceStorageId(panel)) return true;
  const sharedSpaceId = sharedUserSpaceForPanel(panel)?.shared_space_id || "";
  return Boolean(sharedSpaceId && sharedSpaceId === artifact.shared_space_id);
}

function installWisSandbox(definition, artifact = null) {
  stopAllWisCameraStreams();
  stopAllWisCameraTimers();
  if (state.wisUnsubscribe) {
    try {
      state.wisUnsubscribe();
    } catch {
      // The old sandbox may already be disposed by a reload.
    }
  }
  state.wisAutomationInstalled = false;
  state.wisUnsubscribe = null;
  state.wisSandbox = createWisSandbox(definition);
  state.wisActiveArtifact = artifact;
  state.wisLastExport = state.wisSandbox.exportSpace();
  installWisAutomationHook();
  if (artifact) {
    const meta = widgetMeta("wis");
    meta.title = cleanText(artifact.title, "Artifacts");
    meta.iconText = compactWidgetShortLabel(meta.title) || "Apps";
    saveWidgetLayout();
    applyWidgetChrome(widgetById("wis"));
    renderAppLayer();
  }
  scheduleWisRender();
}

async function openWisArtifact(artifact, options = {}) {
  if (!artifact?.id) return;
  const query = new URLSearchParams({ space: artifact.space_id || activeSpaceStorageId() });
  if (artifact.shared_space_id) query.set("shared_space", artifact.shared_space_id);
  const payload = await fetchJson(`/wis/artifacts/${encodeURIComponent(artifact.id)}?${query.toString()}`, { timeoutMs: 10000 });
  const loaded = {
    id: cleanText(payload.artifact_id || artifact.id, artifact.id),
    title: cleanText(payload.artifact?.title || artifact.title || artifact.id, artifact.id),
    space_id: cleanText(payload.space_id || artifact.space_id, artifact.space_id),
    panel: cleanText(artifact.panel || payload.space_id || artifact.space_id, artifact.space_id),
    shared_space_id: cleanText(payload.shared_space_id || artifact.shared_space_id, ""),
    scope: cleanText(payload.scope || artifact.scope, ""),
  };
  installWisSandbox(payload.artifact, loaded);
  saveActiveWisArtifactPreference(loaded);
  if (loaded.panel && isPanelAvailable(loaded.panel)) setPanel(loaded.panel);
  setWidgetMinimized("wis", false);
  if (!options.restore) closeArtifactsModal();
  recordUserEvent("wis.artifact_opened", {
    target: `wis:${loaded.id}`,
    summary: `${options.restore ? "Restored" : "Opened"} WIS artifact ${loaded.title}`,
    data: { ...loaded, restore: Boolean(options.restore) },
  });
}

function scheduleWisRender() {
  if (state.wisRenderScheduled) return;
  state.wisRenderScheduled = true;
  const scheduleFrame = window.requestAnimationFrame || ((callback) => window.setTimeout(callback, 16));
  scheduleFrame(() => {
    state.wisRenderScheduled = false;
    renderWis();
    scheduleObservationRender();
    scheduleObservationPublish();
  });
}

function compactWisAction(action) {
  return {
    type: action?.type || "",
    targetId: action?.targetId || "",
    documentId: action?.documentId || "",
    value_length: action?.value === undefined ? 0 : String(action.value).length,
  };
}

function runWisAction(action, origin = "surface") {
  if (!state.wisSandbox) return { ok: false, error: "wis_unavailable" };
  const request = action && typeof action === "object" ? action : {};
  const result = state.wisSandbox.act(request);
  recordUserEvent("wis.automation_action", {
    source: origin === "automation" ? "wasm-agent-automation" : "wis",
    target: `wis:${request.targetId || request.documentId || request.type || "surface"}`,
    summary: `${request.type || "act"} ${result.ok ? "ok" : "failed"}`,
    data: {
      action: compactWisAction(request),
      result,
      surface: wisSurfaceState()?.document?.id || "",
    },
  });
  return result;
}

function wisCameraConfigKey(slot) {
  const artifactId = cleanText(state.wisActiveArtifact?.id, "local");
  return `${artifactId}:${cleanText(slot, "camera")}`;
}

function redactCameraUrl(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return "";
  try {
    const parsed = new URL(raw);
    if (parsed.username || parsed.password) {
      parsed.username = "user";
      parsed.password = "***";
    }
    return parsed.toString();
  } catch {
    return raw.replace(/\/\/([^/@:]+):([^/@]+)@/, "//user:***@");
  }
}

function classifyWisCameraUrl(url = "") {
  const raw = cleanText(url, "");
  const lower = raw.toLowerCase();
  if (lower.startsWith("rtmp://")) {
    return { kind: "push", mediaMode: "rtmp-push-ingest", element: "push-frame", browserPlayable: true };
  }
  if (lower.startsWith("rtsp://")) {
    return { kind: "url", mediaMode: "rtsp-relay-required", element: "relay", browserPlayable: false };
  }
  if (lower.includes("/cgi-bin/snapshot.cgi")) {
    return { kind: "url", mediaMode: "jpeg-snapshot-poll", element: "snapshot", browserPlayable: true };
  }
  if (/\.(mjpeg|mjpg)(\?|#|$)/i.test(lower) || lower.includes("mjpeg") || lower.includes("mjpg")) {
    return { kind: "url", mediaMode: "mjpeg-http", element: "img", browserPlayable: true };
  }
  if (/\.(jpg|jpeg|png|gif|webp)(\?|#|$)/i.test(lower)) {
    return { kind: "url", mediaMode: "image-http", element: "img", browserPlayable: true };
  }
  if (/\.m3u8(\?|#|$)/i.test(lower)) {
    return { kind: "url", mediaMode: "hls-http", element: "video", browserPlayable: true };
  }
  if (/^(https?:)?\/\//i.test(raw) || /\.(mp4|webm|ogg)(\?|#|$)/i.test(lower)) {
    return { kind: "url", mediaMode: "browser-video-url", element: "video", browserPlayable: true };
  }
  return { kind: "url", mediaMode: "unknown", element: "message", browserPlayable: false };
}

function intelbrasHostPort(host = "") {
  const cleanHost = cleanText(host, "").replace(/^[a-z]+:\/\//i, "").replace(/\/.*$/, "");
  if (cleanHost.startsWith("[")) return cleanHost.match(/^\[[^\]]+\]:(\d+)$/)?.[1] || "";
  return cleanHost.match(/:(\d+)$/)?.[1] || "";
}

function intelbrasHostWithoutPort(host = "") {
  const cleanHost = cleanText(host, "").replace(/^[a-z]+:\/\//i, "").replace(/\/.*$/, "");
  if (!cleanHost) return "";
  try {
    const parsed = new URL(`http://${cleanHost}`);
    const parsedHost = parsed.hostname || cleanHost;
    return parsedHost.includes(":") && !parsedHost.startsWith("[") ? `[${parsedHost}]` : parsedHost;
  } catch {
    if (cleanHost.startsWith("[")) return cleanHost.replace(/^\[([^\]]+)\].*$/, "[$1]");
    return cleanHost.replace(/:\d+$/, "");
  }
}

function intelbrasRtspUrl({ host = "", user = "", password = "", channel = 1, subtype = 0, port = 554 } = {}) {
  const cleanHost = cleanText(host, "").replace(/^rtsp:\/\//i, "").replace(/\/.*$/, "");
  const hostWithoutPort = cleanHost.replace(/:\d+$/, "");
  const parsedPort = intelbrasHostPort(cleanHost) || port;
  const safeChannel = Math.max(1, Math.round(Number(channel) || 1));
  const safeSubtype = Math.max(0, Math.min(1, Math.round(Number(subtype) || 0)));
  const auth = user || password ? `${encodeURIComponent(user)}:${encodeURIComponent(password)}@` : "";
  return `rtsp://${auth}${hostWithoutPort}:${Math.max(1, Math.round(Number(parsedPort) || 554))}/cam/realmonitor?channel=${safeChannel}&subtype=${safeSubtype}`;
}

function intelbrasMjpegUrl({ host = "", user = "", password = "", channel = 1, subtype = 1, port = 80, scheme = "http" } = {}) {
  const cleanHost = cleanText(host, "").replace(/^https?:\/\//i, "").replace(/\/.*$/, "");
  const hostWithoutPort = cleanHost.replace(/:\d+$/, "");
  const parsedPort = cleanHost.match(/:(\d+)$/)?.[1] || port;
  const safeChannel = Math.max(1, Math.round(Number(channel) || 1));
  const safeSubtype = Math.max(0, Math.min(1, Math.round(Number(subtype) || 1)));
  const safeScheme = cleanText(scheme, "http").toLowerCase() === "https" ? "https" : "http";
  const defaultPort = safeScheme === "https" ? 443 : 80;
  const auth = user || password ? `${encodeURIComponent(user)}:${encodeURIComponent(password)}@` : "";
  return `${safeScheme}://${auth}${hostWithoutPort}:${Math.max(1, Math.round(Number(parsedPort) || defaultPort))}/cgi-bin/mjpg/video.cgi?channel=${safeChannel}&subtype=${safeSubtype}`;
}

function intelbrasSnapshotUrl({ host = "", user = "", password = "", channel = 1, subtype = "", port = 80, scheme = "http" } = {}) {
  const cleanHost = cleanText(host, "").replace(/^https?:\/\//i, "").replace(/\/.*$/, "");
  const hostWithoutPort = cleanHost.replace(/:\d+$/, "");
  const parsedPort = cleanHost.match(/:(\d+)$/)?.[1] || port;
  const safeChannel = Math.max(1, Math.round(Number(channel) || 1));
  const safeSubtype = cleanText(subtype, "");
  const safeScheme = cleanText(scheme, "http").toLowerCase() === "https" ? "https" : "http";
  const defaultPort = safeScheme === "https" ? 443 : 80;
  const auth = user || password ? `${encodeURIComponent(user)}:${encodeURIComponent(password)}@` : "";
  const params = new URLSearchParams({ channel: String(safeChannel) });
  if (safeSubtype !== "") params.set("subtype", String(Math.max(0, Math.min(1, Math.round(Number(safeSubtype) || 0)))));
  return `${safeScheme}://${auth}${hostWithoutPort}:${Math.max(1, Math.round(Number(parsedPort) || defaultPort))}/cgi-bin/snapshot.cgi?${params.toString()}`;
}

function parseIntelbrasCameraShortcut(source = "") {
  const text = cleanText(source, "");
  const parts = text.split(/\s+/).filter(Boolean);
  const first = (parts.shift() || "").toLowerCase();
  if (!first.startsWith("intelbras")) return null;
  let mode = first.includes("push") || first.includes("rtmp") ? "push" : (first.includes("capture") || first.includes("portal") ? "capture" : (first.includes("rtsp") ? "rtsp" : (first.includes("snapshot") || first.includes("snap") || first.includes("jpeg") ? "snapshot" : (first.includes("https") ? "https" : "credentials"))));
  const next = (parts[0] || "").toLowerCase();
  if (["credentials", "credential", "creds", "login", "auto", "direct", "relay", "proxy", "capture", "portal", "rtsp", "rtmp", "push", "http", "https", "mjpeg", "mjpg", "snapshot", "snap", "jpeg"].includes(next)) {
    mode = ["credentials", "credential", "creds", "login", "auto", "direct", "relay", "proxy"].includes(next)
      ? "credentials"
      : (next === "push" || next === "rtmp" ? "push" : (next === "capture" || next === "portal" ? "capture" : (next === "rtsp" ? "rtsp" : (next === "snapshot" || next === "snap" || next === "jpeg" ? "snapshot" : (next === "https" ? "https" : "mjpeg")))));
    parts.shift();
  }
  return {
    mode,
    host: cleanText(parts[0], ""),
    channel: cleanText(parts[1], ""),
    subtype: cleanText(parts[2], ""),
  };
}

function stopWisCameraStream(slot) {
  const key = cleanText(slot, "");
  const stream = key ? state.wisCameraStreams.get(key) : null;
  if (!stream) return;
  for (const track of stream.getTracks?.() || []) track.stop();
  state.wisCameraStreams.delete(key);
}

function stopWisCameraTimer(slot) {
  const key = cleanText(slot, "");
  const timer = key ? state.wisCameraTimers.get(key) : null;
  if (!timer) return;
  if (timer && typeof timer === "object" && timer.kind === "wis-camera-scheduler-task") {
    state.wisCameraSchedulerTasks?.delete?.(key);
    state.wisCameraTimers.delete(key);
    return;
  }
  clearTimeout(timer);
  clearInterval(timer);
  state.wisCameraTimers.delete(key);
}

function stopAllWisCameraStreams() {
  for (const slot of Array.from(state.wisCameraStreams.keys())) stopWisCameraStream(slot);
}

function stopAllWisCameraTimers() {
  for (const slot of Array.from(state.wisCameraTimers.keys())) stopWisCameraTimer(slot);
}

function wisCameraAppScheduler() {
  if (!state.wisCameraSchedulerTasks) state.wisCameraSchedulerTasks = new Map();
  if (!state.wisCameraScheduler) {
    state.wisCameraScheduler = {
      timer: 0,
      tasks: state.wisCameraSchedulerTasks,
    };
  }
  return state.wisCameraScheduler;
}

function armWisCameraAppScheduler() {
  const scheduler = wisCameraAppScheduler();
  if (scheduler.timer || !scheduler.tasks.size) return;
  const now = performance.now();
  let nextAt = Infinity;
  scheduler.tasks.forEach((task) => {
    nextAt = Math.min(nextAt, Number(task.nextAt || now));
  });
  if (!Number.isFinite(nextAt)) return;
  scheduler.timer = window.setTimeout(() => {
    scheduler.timer = 0;
    const runNow = performance.now();
    scheduler.tasks.forEach((task) => {
      if (Number(task.nextAt || 0) > runNow + 1) return;
	      if (cleanText(task.mode, "live") === "live" && wisCameraRecordedOwnsStream(task.streamId || task.slot)) {
	        scheduler.tasks.delete(task.slot);
	        state.wisCameraTimers.delete(task.slot);
	        traceWisCameraBoundary("live.scheduler.commit", {
	          decision: "BLOCKED",
	          streamId: task.streamId || task.slot,
	          slot: task.slot,
	          ownerAtCommit: wisCameraTimelineOwnerStateContract(state, task.streamId || task.slot),
	          generation: Number(recordedWisCameraSession(task.streamId || task.slot)?.generation || 0),
	          frameSource: "live-scheduler",
	          reason: "scheduler-live-task",
	          ...wisCameraLoopOwnerSnapshot(task.streamId || task.slot, task.slot),
	        });
	        logWisCameraMediaEvent("camera.timeline.live_update.blocked_by_recorded_owner", {
          streamId: task.streamId || task.slot,
          reason: "scheduler-live-task",
          ...wisCameraLoopOwnerSnapshot(task.streamId || task.slot, task.slot),
        }, { always: true, sampleMs: 1000 });
        return;
      }
      const budget = wisCameraPerformanceBudgetContract(state, task.streamId || task.slot, {
        env: window,
        mode: task.mode || "live",
      });
      const intervalMs = Math.max(Number(task.intervalMs || 1000), Number(budget.visualMinIntervalMs || 0));
      if (budget.allowVisualWork || task.allowWhenSuspended) {
        try {
          task.callback?.(budget);
        } catch (error) {
          logWisCameraMediaEvent("camera.scheduler.task.error", {
            streamId: task.streamId || task.slot,
            error: error?.message || String(error),
          }, { sampleMs: 1000 });
        }
      }
      task.nextAt = performance.now() + (budget.allowVisualWork ? intervalMs : Number(budget.retryMs || 2500));
    });
    armWisCameraAppScheduler();
  }, Math.max(0, Math.round(nextAt - now)));
}

function scheduleWisCameraTimer(slot, callback, intervalMs, options = {}) {
  const key = cleanText(slot, "");
  if (!key || typeof callback !== "function") return null;
  stopWisCameraTimer(key);
  const scheduler = wisCameraAppScheduler();
  const task = {
    kind: "wis-camera-scheduler-task",
    slot: key,
    streamId: cleanText(options.streamId, key),
    mode: cleanText(options.mode, "live"),
    intervalMs: Math.max(250, Math.round(Number(intervalMs) || 1000)),
    callback,
    allowWhenSuspended: Boolean(options.allowWhenSuspended),
    nextAt: performance.now() + Math.max(0, Number(options.delayMs || 0)),
  };
  scheduler.tasks.set(key, task);
  state.wisCameraTimers.set(key, task);
  if (scheduler.timer) {
    window.clearTimeout(scheduler.timer);
    scheduler.timer = 0;
  }
  armWisCameraAppScheduler();
  return task;
}

function nudgeWisCameraTimer(slot) {
  const key = cleanText(slot, "");
  const task = key ? state.wisCameraSchedulerTasks?.get?.(key) : null;
  if (!task) return;
  task.nextAt = performance.now();
  const scheduler = wisCameraAppScheduler();
  if (scheduler.timer) {
    window.clearTimeout(scheduler.timer);
    scheduler.timer = 0;
  }
  armWisCameraAppScheduler();
}

function ensureWisCameraVisibilityObserver() {
  if (state.wisCameraVisibilityObserverInstalled) return;
  state.wisCameraVisibilityObserverInstalled = true;
  if (!state.wisCameraVisibilityElements) state.wisCameraVisibilityElements = new Map();
  if ("IntersectionObserver" in window) {
    state.wisCameraVisibilityObserver = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        const meta = state.wisCameraVisibilityElements?.get(entry.target);
        if (!meta) return;
        const focused = wisSurfaceIsFocusedCamera(wisSurfaceState()) && wisFocusedCameraSlot() === meta.slot;
        setWisCameraVisibilityState(state, meta.streamId, {
          slot: meta.slot,
          visible: Boolean(entry.isIntersecting),
          ratio: Number(entry.intersectionRatio || 0),
          focused,
          active: focused || widgetById("wis")?.classList?.contains("is-widget-active"),
          pageHidden: document.hidden,
        });
        if (entry.isIntersecting && !document.hidden) {
          nudgeWisCameraTimer(meta.slot);
          nudgeWisCameraTimer(meta.streamId);
          wisCameraActivePlaybackLoop(state, meta.streamId)?.schedule?.("viewport-visible");
        }
      });
    }, { threshold: [0, 0.01, 0.25, 0.6, 1] });
  }
  document.addEventListener("visibilitychange", () => {
    const hidden = document.hidden;
    state.wisCameraVisibilityElements?.forEach((meta, element) => {
      if (element.isConnected === false) {
        state.wisCameraVisibilityObserver?.unobserve?.(element);
        state.wisCameraVisibilityElements.delete(element);
        return;
      }
      const rect = element.getBoundingClientRect?.();
      const visible = !hidden && (!rect || (rect.width > 0 && rect.height > 0 && rect.bottom >= 0 && rect.right >= 0 && rect.top <= window.innerHeight && rect.left <= window.innerWidth));
      setWisCameraVisibilityState(state, meta.streamId, {
        slot: meta.slot,
        visible,
        ratio: visible ? 1 : 0,
        focused: wisSurfaceIsFocusedCamera(wisSurfaceState()) && wisFocusedCameraSlot() === meta.slot,
        active: visible,
        pageHidden: hidden,
      });
      if (!hidden) {
        nudgeWisCameraTimer(meta.slot);
        nudgeWisCameraTimer(meta.streamId);
        wisCameraActivePlaybackLoop(state, meta.streamId)?.schedule?.("page-visible");
      }
    });
  });
}

function trackWisCameraVisibility(element, slot, streamId) {
  if (!element || !streamId) return;
  ensureWisCameraVisibilityObserver();
  const cleanSlot = cleanText(slot, "");
  const key = cleanText(streamId, cleanSlot);
  const focused = wisSurfaceIsFocusedCamera(wisSurfaceState()) && wisFocusedCameraSlot() === cleanSlot;
  state.wisCameraVisibilityElements?.set(element, { slot: cleanSlot, streamId: key });
  element.dataset.wisCameraStreamId = key;
  setWisCameraVisibilityState(state, key, {
    slot: cleanSlot,
    visible: !document.hidden,
    ratio: document.hidden ? 0 : 1,
    focused,
    active: focused || widgetById("wis")?.classList?.contains("is-widget-active"),
    pageHidden: document.hidden,
  });
  state.wisCameraVisibilityObserver?.observe?.(element);
}

function wisCameraBudget(streamId, mode = "live") {
  return wisCameraPerformanceBudgetContract(state, streamId, { env: window, mode });
}

function localWisCameraConfig(slot) {
  return state.wisCameraConfigs[wisCameraConfigKey(slot)] || null;
}

function saveLocalWisCameraConfig(slot, config) {
  const key = wisCameraConfigKey(slot);
  if (!config) delete state.wisCameraConfigs[key];
  else state.wisCameraConfigs[key] = {
    kind: cleanText(config.kind, ""),
    url: cleanText(config.url, ""),
    label: cleanText(config.label, ""),
    mediaMode: cleanText(config.mediaMode, ""),
    element: cleanText(config.element, ""),
    browserPlayable: Boolean(config.browserPlayable || config.browser_playable || config.element === "img" || config.element === "video"),
    vendor: cleanText(config.vendor, ""),
    mode: cleanText(config.mode, ""),
    preferredMode: cleanText(config.preferredMode || config.preferred_mode, ""),
    credentialProfile: Boolean(config.credentialProfile || config.credential_profile),
    relayMode: cleanText(config.relayMode || config.relay_mode, ""),
    channel: cleanText(config.channel, ""),
    subtype: cleanText(config.subtype, ""),
    host: cleanText(config.host, ""),
    port: cleanText(config.port, ""),
    rtspPort: cleanText(config.rtspPort || config.rtsp_port, ""),
    streamId: cleanText(config.streamId || config.stream_id, ""),
    ingestUrl: cleanText(config.ingestUrl || config.ingest_url, ""),
    statusUrl: cleanText(config.statusUrl || config.status_url, ""),
    frameUrl: cleanText(config.frameUrl || config.frame_url, ""),
    streamUrl: cleanText(config.streamUrl || config.stream_url, ""),
    replayUrl: cleanText(config.replayUrl || config.replay_url, ""),
    fps: Number.isFinite(Number(config.fps)) ? Number(config.fps) : 0,
    quality: Number.isFinite(Number(config.quality)) ? Number(config.quality) : 0,
    portalUrl: cleanText(config.portalUrl || config.portal_url, ""),
    accessScope: cleanText(config.accessScope || config.access_scope, ""),
    secretPolicy: cleanText(config.secretPolicy || config.secret_policy, ""),
    shareable: Boolean(config.shareable),
    updatedAt: cleanText(config.updatedAt, new Date().toISOString()),
  };
  saveWisCameraConfigs();
}

function applyWisCameraConfig(slot, config) {
  const sanitized = {
    kind: cleanText(config.kind, ""),
    label: cleanText(config.label, ""),
    mediaMode: cleanText(config.mediaMode, ""),
    element: cleanText(config.element, ""),
    url: config.url ? redactCameraUrl(config.url) : "",
    vendor: cleanText(config.vendor, ""),
    mode: cleanText(config.mode, ""),
    preferredMode: cleanText(config.preferredMode || config.preferred_mode, ""),
    credentialProfile: Boolean(config.credentialProfile || config.credential_profile),
    relayMode: cleanText(config.relayMode || config.relay_mode, ""),
    channel: cleanText(config.channel, ""),
    subtype: cleanText(config.subtype, ""),
    host: cleanText(config.host, ""),
    port: cleanText(config.port, ""),
    rtspPort: cleanText(config.rtspPort || config.rtsp_port, ""),
    streamId: cleanText(config.streamId || config.stream_id, ""),
    ingestUrl: cleanText(config.ingestUrl || config.ingest_url, ""),
    statusUrl: cleanText(config.statusUrl || config.status_url, ""),
    frameUrl: cleanText(config.frameUrl || config.frame_url, ""),
    streamUrl: cleanText(config.streamUrl || config.stream_url, ""),
    replayUrl: cleanText(config.replayUrl || config.replay_url, ""),
    fps: Number.isFinite(Number(config.fps)) ? Number(config.fps) : 0,
    quality: Number.isFinite(Number(config.quality)) ? Number(config.quality) : 0,
    portalUrl: config.portalUrl ? redactCameraUrl(config.portalUrl) : "",
    accessScope: cleanText(config.accessScope, ""),
    secretPolicy: cleanText(config.secretPolicy, ""),
    shareable: Boolean(config.shareable),
    browserPlayable: Boolean(config.browserPlayable || config.browser_playable),
    clientLocal: true,
    updatedAt: new Date().toISOString(),
  };
  return runWisAction({ type: "configureCamera", slot, config: sanitized }, "surface");
}

function wisCameraConfigForSlot(slot) {
  const key = cleanText(slot, "");
  if (!key) return {};
  const camera = wisSurfaceState()?.state?.cameras?.[key];
  const surfaceCamera = camera && typeof camera === "object" ? normalizeWisCameraConfigForSlot(key, camera) : {};
  // Surface-provided RTMP push configs are durable artifact intent; prefer them
  // over stale per-browser DVR credentials from earlier local experiments.
  if (wisCameraIsPushConfig(surfaceCamera)) return surfaceCamera;
  const local = localWisCameraConfig(key);
  if (local?.kind) return normalizeWisCameraConfigForSlot(key, maybePreferIntelbrasRelayCameraConfig(key, local));
  if (surfaceCamera?.kind) return surfaceCamera;
  return wisDefaultPushCameraConfigForSlot(key);
}

function wisDefaultPushCameraConfigForSlot(slot = "") {
  return createWisDefaultPushCameraConfigForSlot(slot, {
    slot,
    label: "DVR RTMP push",
    vendor: "intelbras",
    endpoints: WIS_CAMERA_CONTROLLER_CONTRACT.endpoints,
  });
}

function wisCameraIsPushConfig(camera = {}) {
  return isWisCameraPushConfig(camera);
}

function normalizeWisCameraConfigForSlot(slot, camera = {}) {
  return normalizeWisCameraConfigForSlotContract(slot, camera, {
    endpoints: WIS_CAMERA_CONTROLLER_CONTRACT.endpoints,
  });
}

function cameraUrlHasCredentials(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return false;
  try {
    const parsed = new URL(raw, window.location.href);
    return Boolean(parsed.username || parsed.password);
  } catch {
    return /\/\/[^/@:]+:[^/@]+@/.test(raw);
  }
}

function cameraPotentiallyMixedContent(url = "") {
  const raw = cleanText(url, "");
  if (!raw || window.location.protocol !== "https:") return false;
  try {
    return new URL(raw, window.location.href).protocol === "http:";
  } catch {
    return /^http:\/\//i.test(raw);
  }
}

function cameraUrlWithoutCredentials(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return "";
  try {
    const parsed = new URL(raw, window.location.href);
    parsed.username = "";
    parsed.password = "";
    return parsed.toString();
  } catch {
    return raw.replace(/^(https?:\/\/)[^/@]+@/i, "$1");
  }
}

function cameraOriginUrl(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return "";
  try {
    const parsed = new URL(raw, window.location.href);
    parsed.username = "";
    parsed.password = "";
    parsed.pathname = "/";
    parsed.search = "";
    parsed.hash = "";
    return parsed.toString();
  } catch {
    const stripped = cameraUrlWithoutCredentials(raw);
    return stripped.replace(/^(https?:\/\/[^/]+).*/i, "$1/");
  }
}

function cameraPortalUrl(camera = {}) {
  const savedPortal = cleanText(camera.portalUrl || camera.portal_url, "");
  if (savedPortal && !cameraPortalUrlLooksLikeRtspTunnel(camera, savedPortal)) return savedPortal;
  if (intelbrasCameraUsesRtspPort(camera)) {
    const recoveryUrl = intelbrasHttpRecoveryUrl(camera, "http");
    if (recoveryUrl) return cameraOriginUrl(recoveryUrl);
  }
  return cameraOriginUrl(camera.url || "")
    || (camera.host ? `http://${cleanText(camera.host, "").replace(/^https?:\/\//i, "").replace(/\/.*$/, "")}/` : "");
}

function cameraHttpsUrl(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return "";
  try {
    const parsed = new URL(raw, window.location.href);
    parsed.protocol = "https:";
    if (!parsed.port || parsed.port === "80") parsed.port = "443";
    return parsed.toString();
  } catch {
    return raw.replace(/^http:\/\//i, "https://").replace(/:80(\/|$)/, ":443$1");
  }
}

function cameraHttpUrl(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return "";
  try {
    const parsed = new URL(raw, window.location.href);
    parsed.protocol = "http:";
    if (!parsed.port || parsed.port === "443") parsed.port = "80";
    return parsed.toString();
  } catch {
    return raw.replace(/^https:\/\//i, "http://").replace(/:443(\/|$)/, ":80$1");
  }
}

function cameraUrlParts(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return {};
  try {
    const parsed = new URL(raw, window.location.href);
    const redactedAuth = parsed.password === "***";
    const protocol = parsed.protocol.replace(/:$/, "").toLowerCase();
    return {
      scheme: ["rtsp", "http", "https"].includes(protocol) ? protocol : "",
      host: parsed.hostname,
      port: parsed.port,
      user: parsed.username && !redactedAuth ? decodeURIComponent(parsed.username) : "",
      password: parsed.password && !redactedAuth ? decodeURIComponent(parsed.password) : "",
    };
  } catch {
    return {};
  }
}

function intelbrasRtspPortFromCamera(camera = {}, seed = {}) {
  const explicit = cleanText(camera.rtspPort || camera.rtsp_port || seed.rtspPort || seed.rtsp_port, "");
  if (explicit) return explicit;
  const hostPort = intelbrasHostPort(seed.host || camera.host || "");
  if (hostPort) return hostPort;
  const parts = cameraUrlParts(camera.url || "");
  const rtspContext = parts.scheme === "rtsp"
    || camera.relayMode === "same-origin-rtsp-mjpeg"
    || camera.relay_mode === "same-origin-rtsp-mjpeg"
    || camera.element === "rtsp-relay"
    || camera.mediaMode === "rtsp-mjpeg-relay"
    || camera.mediaMode === "rtsp-relay-required";
  if (rtspContext) return cleanText(seed.port, "") || cleanText(camera.port, "") || parts.port || "554";
  return "554";
}

function intelbrasCameraUsesRtspPort(camera = {}) {
  const parts = cameraUrlParts(camera.url || "");
  return parts.scheme === "rtsp"
    || camera.relayMode === "same-origin-rtsp-mjpeg"
    || camera.relay_mode === "same-origin-rtsp-mjpeg"
    || camera.element === "rtsp-relay"
    || camera.mediaMode === "rtsp-mjpeg-relay"
    || camera.mediaMode === "rtsp-relay-required";
}

function intelbrasHttpRecoveryConfigFromCamera(camera = {}, overrides = {}) {
  const seed = intelbrasConfigFromCamera(camera, overrides);
  if (!intelbrasCameraUsesRtspPort(camera)) return seed;
  const scheme = cleanText(overrides.scheme, "").toLowerCase() === "https" ? "https" : "http";
  return {
    ...seed,
    host: intelbrasHostWithoutPort(seed.host || camera.host || ""),
    port: cleanText(overrides.port, scheme === "https" ? "443" : "80"),
    scheme,
  };
}

function intelbrasHttpRecoveryUrl(camera = {}, scheme = "http") {
  const config = intelbrasHttpRecoveryConfigFromCamera(camera, { scheme });
  return config.host ? intelbrasMjpegUrl(config) : "";
}

function cameraPortalUrlLooksLikeRtspTunnel(camera = {}, url = "") {
  if (!intelbrasCameraUsesRtspPort(camera)) return false;
  const parts = cameraUrlParts(url);
  if (parts.scheme === "rtsp") return true;
  if (!["http", "https"].includes(parts.scheme)) return false;
  const rtspPort = cleanText(intelbrasRtspPortFromCamera(camera), "");
  if (!rtspPort || parts.port !== rtspPort) return false;
  const sourceHost = intelbrasHostWithoutPort(camera.host || cameraUrlParts(camera.url || "").host || "").replace(/^\[|\]$/g, "");
  return !sourceHost || parts.host === sourceHost;
}

function intelbrasAuthForHost(host = "") {
  const targetHost = cleanText(host, "").replace(/^https?:\/\//i, "").replace(/:\d+$/, "").replace(/\/.*$/, "");
  for (const config of Object.values(state.wisCameraConfigs || {})) {
    const parts = cameraUrlParts(config?.url || "");
    if (!parts.user && !parts.password) continue;
    if (!targetHost || parts.host === targetHost || cleanText(config?.host, "").replace(/:\d+$/, "") === targetHost) {
      return { user: parts.user, password: parts.password };
    }
  }
  return { user: "", password: "" };
}

function intelbrasConfigFromCamera(camera = {}, overrides = {}) {
  const rawUrl = camera.url || camera.portalUrl || camera.portal_url || "";
  const parts = cameraUrlParts(rawUrl);
  let queryChannel = "";
  let querySubtype = "";
  try {
    const params = new URL(cleanText(rawUrl, ""), window.location.href).searchParams;
    queryChannel = cleanText(params.get("channel"), "");
    querySubtype = cleanText(params.get("subtype"), "");
  } catch {
    // Some saved camera values are redacted or partial; explicit config wins.
  }
  const host = cleanText(overrides.host, "") || cleanText(camera.host, "") || parts.host;
  const auth = intelbrasAuthForHost(host);
  return {
    host,
    user: cleanText(overrides.user, "") || parts.user || auth.user,
    password: cleanText(overrides.password, "") || parts.password || auth.password,
    channel: cleanText(overrides.channel, "") || cleanText(camera.channel, "") || queryChannel || "1",
    subtype: cleanText(overrides.subtype, "") || cleanText(camera.subtype, "") || querySubtype,
    port: cleanText(overrides.port, "") || cleanText(camera.port, "") || parts.port || (parts.scheme === "rtsp" ? "554" : (parts.scheme === "https" ? "443" : "80")),
    scheme: cleanText(overrides.scheme, "") || parts.scheme || (camera.url && /^https:/i.test(camera.url) ? "https" : "http"),
  };
}

function appendCameraCacheBuster(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return "";
  try {
    const parsed = new URL(raw, window.location.href);
    parsed.searchParams.set("wasm_agent_ts", String(Date.now()));
    return parsed.toString();
  } catch {
    const join = raw.includes("?") ? "&" : "?";
    return `${raw}${join}wasm_agent_ts=${Date.now()}`;
  }
}

function openCameraUrl(url = "") {
  const target = cleanText(url, "");
  if (!target) return;
  window.open(target, "_blank", "noopener");
}

function rememberWisCameraDebugEvent(slot, event = {}) {
  const key = `${cleanText(slot, "camera")}:${cleanText(event.type, "event")}`;
  const now = Date.now();
  const previous = state.wisCameraDebugEvents.get(key);
  state.wisCameraDebugEvents.set(key, {
    type: cleanText(event.type, "event"),
    slot: cleanText(slot, "camera"),
    at: new Date(now).toISOString(),
    seenMs: Number(previous?.seenMs || 0),
    media_mode: cleanText(event.mediaMode || event.media_mode, ""),
    element: cleanText(event.element, ""),
    vendor: cleanText(event.vendor, ""),
    mode: cleanText(event.mode, ""),
    url: redactCameraUrl(event.url || ""),
    detail: cleanText(event.detail, ""),
  });
  return !previous || now - Number(previous.seenMs || 0) > 15000;
}

function publishWisCameraDebugSnapshot(slot, event = {}) {
  const key = `${cleanText(slot, "camera")}:${cleanText(event.type, "event")}`;
  const current = state.wisCameraDebugEvents.get(key) || {};
  current.seenMs = Date.now();
  state.wisCameraDebugEvents.set(key, current);
  void publishClientSnapshot(`wis-camera-${cleanText(event.type, "debug")}`, { scope: "state", silent: true });
}

function appendWisCameraAction(element, label, onClick) {
  const button = document.createElement("button");
  button.type = "button";
  button.className = "wis-camera-action";
  button.textContent = label;
  button.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    onClick();
  });
  element.append(button);
  return button;
}

function clearWisCameraSlot(slot) {
  stopWisCameraStream(slot);
  stopWisCameraTimer(slot);
  saveLocalWisCameraConfig(slot, null);
  runWisAction({ type: "clearCamera", slot }, "surface");
  renderWis();
}

async function startWisCameraCapture(slot, camera = {}) {
  const getDisplayMedia = navigator.mediaDevices?.getDisplayMedia?.bind(navigator.mediaDevices);
  if (!getDisplayMedia) {
    window.alert("This browser does not expose tab/window capture to wasm-agent.");
    return { ok: false, error: "get_display_media_unavailable" };
  }
  try {
    stopWisCameraStream(slot);
    stopWisCameraTimer(slot);
    const stream = await getDisplayMedia({ video: true, audio: false });
    state.wisCameraStreams.set(slot, stream);
    const config = {
      kind: "capture",
      url: cleanText(camera.url, ""),
      label: camera.vendor === "intelbras" ? "Intelbras portal capture" : "Browser tab capture",
      mediaMode: "displayCapture",
      element: "video",
      vendor: cleanText(camera.vendor, ""),
      mode: "capture",
    };
    saveLocalWisCameraConfig(slot, config);
    const result = applyWisCameraConfig(slot, config);
    renderWis();
    return result;
  } catch (error) {
    rememberWisCameraDebugEvent(slot, {
      type: "capture-error",
      mediaMode: "displayCapture",
      element: "video",
      vendor: camera.vendor,
      mode: "capture",
      url: camera.url,
      detail: error.message || String(error),
    });
    publishWisCameraDebugSnapshot(slot, { type: "capture-error" });
    return { ok: false, error: error.message || String(error) };
  }
}

async function startWisIntelbrasPortalCapture(slot, camera = {}, url = "", options = {}) {
  const channel = cleanText(camera.channel, "");
  const portalUrl = cameraOriginUrl(url || cameraPortalUrl(camera) || "http://192.168.1.78/");
  if (options.openPortal && portalUrl) openCameraUrl(portalUrl);
  window.alert(channel
    ? `Select the Intelbras DVR tab/window showing CAM ${channel} in the next browser picker.`
    : "Select the Intelbras DVR tab/window in the next browser picker.");
  return startWisCameraCapture(slot, {
    ...camera,
    vendor: "intelbras",
    url: portalUrl,
    portalUrl,
    label: channel ? `Intelbras CAM ${channel} capture` : "Intelbras portal capture",
  });
}

function saveWisCameraPortal(slot, camera, url, label) {
  stopWisCameraStream(slot);
  stopWisCameraTimer(slot);
  const next = {
    kind: "url",
    url,
    label,
    mediaMode: "dvr-portal",
    element: "portal",
    vendor: cleanText(camera.vendor, ""),
    mode: "portal",
    host: cleanText(camera.host, ""),
    channel: cleanText(camera.channel, ""),
    portalUrl: url,
    accessScope: cleanText(camera.accessScope || camera.access_scope, ""),
    secretPolicy: cleanText(camera.secretPolicy || camera.secret_policy, ""),
    shareable: Boolean(camera.shareable),
  };
  saveLocalWisCameraConfig(slot, next);
  applyWisCameraConfig(slot, next);
  renderWis();
}

function saveWisCameraStreamUrl(slot, camera, url, label, mediaMode = "", element = "") {
  stopWisCameraStream(slot);
  stopWisCameraTimer(slot);
  const classified = classifyWisCameraUrl(url);
  const next = {
    ...camera,
    kind: "url",
    url,
    label,
    mediaMode: cleanText(mediaMode, "") || classified.mediaMode || cleanText(camera.mediaMode, ""),
    element: cleanText(element, "") || classified.element || cleanText(camera.element, ""),
  };
  saveLocalWisCameraConfig(slot, next);
  applyWisCameraConfig(slot, next);
  renderWis();
}

function retryWisCameraRtspSlot(slot) {
  stopWisCameraTimer(slot);
  state.wisCameraRtspRetryAfter.delete(slot);
  renderWis();
}

async function checkWisCameraDvrReachability(slot, camera) {
  const seed = camera.vendor === "intelbras" ? intelbrasConfigFromCamera(camera) : {};
  const sourceParts = cameraUrlParts(camera.url || "");
  const rtspPort = sourceParts.scheme === "rtsp"
    ? (sourceParts.port || cleanText(camera.rtspPort || camera.rtsp_port, "") || cleanText(camera.port, "") || "554")
    : (camera.relayMode === "same-origin-rtsp-mjpeg" || camera.element === "rtsp-relay" || camera.mediaMode === "rtsp-mjpeg-relay"
      ? cleanText(camera.rtspPort || camera.rtsp_port, "") || cleanText(camera.port, "554")
      : "554");
  try {
    const payload = await fetchJson("/camera/diagnostics", {
      method: "POST",
      timeoutMs: 9000,
      body: {
        url: cameraUrlWithoutCredentials(cleanText(camera.url, "")),
        portalUrl: cameraPortalUrl(camera),
        host: seed.host || cleanText(camera.host, ""),
        rtspPort,
        timeoutMs: 2000,
      },
    });
    const rows = Array.isArray(payload?.tcp) ? payload.tcp : [];
    const summary = rows.map((row) => {
      const target = `${cleanText(row.host, "")}:${cleanText(row.port, "")}`;
      return `${cleanText(row.label, "port")} ${target} ${row.ok ? "OK" : cleanText(row.error, "unreachable")}`;
    }).join("\n");
    window.alert(`DVR reachability from wasm-agent\n\n${summary || "No checks returned."}\n\n${cleanText(payload?.advice, "")}`);
    if (rememberWisCameraDebugEvent(slot, {
      type: "camera-diagnostics",
      mediaMode: camera.mediaMode,
      element: camera.element,
      vendor: camera.vendor,
      mode: camera.mode,
      url: camera.url,
      detail: cleanText(payload?.advice, ""),
    })) {
      publishWisCameraDebugSnapshot(slot, { type: "camera-diagnostics" });
    }
  } catch (error) {
    window.alert(error.message || "Camera diagnostics could not run.");
  }
}

function appendWisCameraRecoveryActions(element, slot, camera, options = {}) {
  const rawUrl = cleanText(camera.url, "");
  const added = new Set();
  const add = (label, onClick) => {
    if (added.has(label)) return;
    added.add(label);
    appendWisCameraAction(element, label, onClick);
  };
  const intelbrasSource = camera.vendor === "intelbras" || cleanText(camera.label, "").toLowerCase().includes("intelbras");
  const rtspSource = rawUrl.toLowerCase().startsWith("rtsp://")
    || camera.element === "rtsp-relay"
    || camera.mediaMode === "rtsp-mjpeg-relay"
    || camera.mediaMode === "rtsp-relay-required"
    || camera.relayMode === "same-origin-rtsp-mjpeg";
  const currentStream = cameraUrlWithoutCredentials(rawUrl);
  const httpRecoveryUrl = intelbrasSource && rtspSource ? intelbrasHttpRecoveryUrl(camera, "http") : "";
  const httpsRecoveryUrl = intelbrasSource && rtspSource ? intelbrasHttpRecoveryUrl(camera, "https") : "";
  const httpStream = cameraUrlWithoutCredentials(httpRecoveryUrl || cameraHttpUrl(rawUrl));
  const httpsStream = cameraUrlWithoutCredentials(httpsRecoveryUrl || cameraHttpsUrl(rawUrl));
  const currentOrigin = cameraPortalUrl(camera);
  const httpOrigin = cameraOriginUrl(httpStream);
  const httpsOrigin = cameraOriginUrl(httpsStream);
  const mixedContent = cameraPotentiallyMixedContent(rawUrl);
  const includeStream = options.includeStream !== false;
  const snapshotConfig = intelbrasSource ? intelbrasHttpRecoveryConfigFromCamera(camera, { scheme: cameraUrlParts(rawUrl || currentOrigin).scheme || "http" }) : null;
  const snapshotUrl = snapshotConfig?.host ? intelbrasSnapshotUrl(snapshotConfig) : "";

  if (rtspSource) {
    add("Retry RTSP", () => retryWisCameraRtspSlot(slot));
  }
  if ((rtspSource || intelbrasSource) && (rawUrl || camera.host)) {
    add("Check DVR", () => {
      void checkWisCameraDvrReachability(slot, camera);
    });
  }
  if (includeStream && !mixedContent && currentStream) {
    add("Open current", () => openCameraUrl(currentStream));
  }
  if (httpOrigin) add("Open DVR HTTP", () => openCameraUrl(httpOrigin));
  if (httpsOrigin && httpsOrigin !== httpOrigin) add("Open DVR HTTPS", () => openCameraUrl(httpsOrigin));
  if (mixedContent && httpsStream && httpsStream !== currentStream) {
    add("Try HTTPS stream", () => saveWisCameraStreamUrl(
      slot,
      camera,
      httpsStream,
      `${camera.label || "Camera URL"} (HTTPS)`,
      cleanText(camera.mediaMode, "").replace("http", "https") || "mjpeg-https"
    ));
  }
  if (!mixedContent && httpStream && httpStream !== currentStream) {
    add("Try HTTP stream", () => saveWisCameraStreamUrl(
      slot,
      camera,
      httpStream,
      `${camera.label || "Camera URL"} (HTTP)`,
      cleanText(camera.mediaMode, "").replace("https", "http") || "mjpeg-http"
    ));
  }
  if (httpOrigin) add("Use HTTP portal", () => saveWisCameraPortal(slot, camera, httpOrigin, camera.vendor === "intelbras" ? "Intelbras DVR HTTP portal" : "DVR HTTP portal"));
  if (httpsOrigin && httpsOrigin !== httpOrigin) add("Use HTTPS portal", () => saveWisCameraPortal(slot, camera, httpsOrigin, camera.vendor === "intelbras" ? "Intelbras DVR HTTPS portal" : "DVR HTTPS portal"));
  if (snapshotUrl) {
    add("Try snapshot", () => {
      if (!snapshotConfig.user && !snapshotConfig.password) {
        void tryWisCameraSnapshotSlot(slot);
        return;
      }
      saveWisCameraStreamUrl(
        slot,
        {
          ...camera,
          ...snapshotConfig,
          vendor: "intelbras",
          mode: "snapshot",
          browserPlayable: true,
        },
        snapshotUrl,
        `Intelbras CAM ${snapshotConfig.channel || camera.channel || ""} snapshot`.trim(),
        "jpeg-snapshot-poll",
        "snapshot"
      );
    });
  }
  add(camera.vendor === "intelbras" ? "Capture Intelbras" : "Capture tab", () => {
    if (camera.vendor === "intelbras") void startWisIntelbrasPortalCapture(slot, camera, currentOrigin || httpOrigin);
    else void startWisCameraCapture(slot, camera);
  });
  if (camera.vendor === "intelbras") {
    add("Use credentials", () => {
      void configureWisIntelbrasCredentialProfile(slot, camera, camera);
    });
  }
  if (!mixedContent && rawUrl && cameraUrlHasCredentials(rawUrl) && currentStream && currentStream !== rawUrl) {
    add("Use browser auth", () => saveWisCameraStreamUrl(slot, camera, currentStream, `${camera.label || "Camera URL"} (browser auth)`, camera.mediaMode));
  }
  add("Reconfigure", () => {
    void configureWisCameraSlot({ props: { slot, camera } });
  });
  add("Clear", () => clearWisCameraSlot(slot));
}

function openWisCameraPortalForSlot(slot) {
  const camera = wisCameraConfigForSlot(slot);
  const portalUrl = cameraPortalUrl(camera);
  if (!portalUrl) {
    window.alert("No portal URL is configured for this camera.");
    return;
  }
  openCameraUrl(portalUrl);
}

async function captureWisCameraSlot(slot) {
  const camera = wisCameraConfigForSlot(slot);
  if (camera.vendor === "intelbras") return startWisIntelbrasPortalCapture(slot, camera, cameraPortalUrl(camera));
  return startWisCameraCapture(slot, camera);
}

async function tryWisCameraSnapshotSlot(slot) {
  const camera = wisCameraConfigForSlot(slot);
  let snapshot = intelbrasHttpRecoveryConfigFromCamera(camera);
  if (!snapshot.host) {
    window.alert("No Intelbras DVR host is configured for this camera.");
    return { ok: false, error: "missing_host" };
  }
  if (!snapshot.user && !snapshot.password) {
    const user = window.prompt("Intelbras DVR/NVR username. It stays only in this browser.", "admin");
    if (user === null) return { ok: false, error: "cancelled" };
    const password = window.prompt("Intelbras DVR/NVR password. It stays only in this browser.", "");
    if (password === null) return { ok: false, error: "cancelled" };
    snapshot = { ...snapshot, user, password };
  }
  const url = intelbrasSnapshotUrl(snapshot);
  const next = {
    ...camera,
    kind: "url",
    url,
    label: `Intelbras CAM ${snapshot.channel || camera.channel || "1"} snapshot`,
    mediaMode: "jpeg-snapshot-poll",
    element: "snapshot",
    browserPlayable: true,
    vendor: "intelbras",
    mode: "snapshot",
    host: snapshot.host,
    port: snapshot.port,
    channel: snapshot.channel,
    subtype: snapshot.subtype,
    portalUrl: cameraPortalUrl(camera) || cameraOriginUrl(url),
    accessScope: cleanText(camera.accessScope || camera.access_scope, "shared-space"),
    secretPolicy: "per-device-browser-session",
    shareable: true,
  };
  saveLocalWisCameraConfig(slot, next);
  const result = applyWisCameraConfig(slot, next);
  renderWis();
  return result;
}

function normalizeIntelbrasCredentialPlaybackMode(mode = "auto") {
  const requested = cleanText(mode, "auto").toLowerCase();
  if (["credentials", "credential", "creds", "login", "auto", "direct", "relay", "proxy"].includes(requested)) return "relay";
  if (requested === "rtsp") return "rtsp";
  if (requested === "https") return "https";
  if (requested === "snapshot" || requested === "snap" || requested === "jpeg") return "snapshot";
  if (requested === "mjpeg" || requested === "mjpg" || requested === "http") return "mjpeg";
  return "relay";
}

function intelbrasCredentialPortForMode(mode, current = {}) {
  const saved = cleanText(current.port, "");
  if (mode === "relay" && cleanText(current.relayMode || current.relay_mode, "") !== "same-origin-rtsp-mjpeg") return "554";
  if (saved && cleanText(current.mode, "") === mode) return saved;
  if (mode === "rtsp" || mode === "relay") return "554";
  if (mode === "https") return "443";
  return "80";
}

function intelbrasCredentialCameraConfig({ host = "", user = "", password = "", channel = "1", subtype = "0", mode = "auto", port = "", current = {} } = {}) {
  const cleanMode = normalizeIntelbrasCredentialPlaybackMode(mode);
  const hostPort = intelbrasHostPort(host);
  const cleanPort = hostPort || cleanText(port, intelbrasCredentialPortForMode(cleanMode, current));
  const trueStreamMode = cleanMode === "relay" || cleanMode === "rtsp";
  const url = trueStreamMode
    ? intelbrasRtspUrl({ host, user, password, channel, subtype, port: cleanPort })
    : (cleanMode === "snapshot"
      ? intelbrasSnapshotUrl({ host, user, password, channel, subtype, port: cleanPort, scheme: "http" })
      : intelbrasMjpegUrl({ host, user, password, channel, subtype, port: cleanPort, scheme: cleanMode === "https" ? "https" : "http" }));
  const classified = trueStreamMode
    ? { kind: "url", mediaMode: "rtsp-mjpeg-relay", element: "rtsp-relay", browserPlayable: true }
    : (cleanMode === "snapshot"
      ? { kind: "url", mediaMode: "jpeg-snapshot-poll", element: "snapshot", browserPlayable: true }
      : { kind: "url", mediaMode: cleanMode === "https" ? "mjpeg-https" : "mjpeg-http", element: "img", browserPlayable: true });
  const portalHost = trueStreamMode ? intelbrasHostWithoutPort(host) : host;
  const portalUrl = cameraOriginUrl(intelbrasMjpegUrl({ host: portalHost, port: 80, scheme: "http" }));
  return {
    ...classified,
    vendor: "intelbras",
    mode: cleanMode,
    preferredMode: cleanText(mode, "auto"),
    credentialProfile: true,
    relayMode: trueStreamMode ? "same-origin-rtsp-mjpeg" : "",
    host: cleanText(host, ""),
    port: cleanPort,
    rtspPort: trueStreamMode ? cleanPort : cleanText(current.rtspPort || current.rtsp_port, ""),
    channel: cleanText(channel, "1"),
    subtype: cleanMode === "snapshot" ? cleanText(subtype, "") : cleanText(subtype, "0"),
    url,
    portalUrl,
    accessScope: "shared-space",
    secretPolicy: "per-device-browser-session",
    shareable: true,
    label: cleanMode === "rtsp"
      ? "Intelbras true RTSP stream relay"
      : (cleanMode === "relay"
        ? "Intelbras true live RTSP stream"
        : (cleanMode === "snapshot"
        ? "Intelbras credentials JPEG snapshot"
        : (cleanMode === "https" ? "Intelbras credentials HTTPS MJPEG" : "Intelbras credentials HTTP MJPEG"))),
  };
}

function maybePreferIntelbrasRelayCameraConfig(slot, camera = {}) {
  if (camera.vendor !== "intelbras" || !camera.credentialProfile || camera.relayMode === "same-origin-rtsp-mjpeg") return camera;
  if (["capture", "portal"].includes(cleanText(camera.mode, "").toLowerCase())) return camera;
  const seed = intelbrasConfigFromCamera(camera);
  if (!seed.host) return camera;
  const next = intelbrasCredentialCameraConfig({
    ...seed,
    mode: "credentials",
    current: camera,
  });
  saveLocalWisCameraConfig(slot, next);
  return next;
}

function cameraPushStatusUrl(streamId = "cam-1") {
  return createWisCameraPushEndpoints(streamId, WIS_CAMERA_CONTROLLER_CONTRACT.endpoints).statusUrl;
}

function cameraPushFrameUrl(streamId = "cam-1") {
  return createWisCameraPushEndpoints(streamId, WIS_CAMERA_CONTROLLER_CONTRACT.endpoints).frameUrl;
}

function cameraPushStreamUrl(streamId = "cam-1") {
  return createWisCameraPushEndpoints(streamId, WIS_CAMERA_CONTROLLER_CONTRACT.endpoints).streamUrl;
}

function cameraPushReplayUrl(streamId = "cam-1", seconds = 300) {
  return createWisCameraPushEndpoints(streamId, WIS_CAMERA_CONTROLLER_CONTRACT.endpoints, { replaySeconds: seconds }).replayUrl;
}

function cameraPushPlaybackResolvedStartMs(frame = {}, options = {}) {
  const frameMs = Number(frame?.timestamp_ms ?? frame?.timestampMs ?? frame?.snapped_timestamp_ms ?? frame?.snappedTimestampMs);
  if (Number.isFinite(frameMs) && frameMs > 0) return frameMs;
  const optionMs = Number(options.fromMs ?? options.from_ms);
  if (Number.isFinite(optionMs) && optionMs > 0) return optionMs;
  return wisCameraTimelinePlaybackStartMs(frame);
}

function cameraPushPlaybackUrl(streamId = "cam-1", frame = {}, options = {}) {
  return createWisCameraPushEndpoints(streamId, WIS_CAMERA_CONTROLLER_CONTRACT.endpoints, {
    frame: frame?.id,
    fromMs: cameraPushPlaybackResolvedStartMs(frame, options),
    fps: options.fps,
    follow: options.follow,
  }).playbackUrl;
}

function cameraPushTimelineUrl(streamId = "cam-1", options = {}) {
  return createWisCameraPushEndpoints(streamId, WIS_CAMERA_CONTROLLER_CONTRACT.endpoints, {
    mode: options.mode,
    timelineSeconds: options.seconds,
  }).timelineUrl;
}

function cameraCacheBustedUrl(url = "") {
  const raw = cleanText(url, "");
  if (!raw) return "";
  return `${raw}${raw.includes("?") ? "&" : "?"}t=${Date.now()}`;
}

async function startWisCameraPushIngest(streamId, options = {}) {
  return fetchJson("/camera/push/start", {
    method: "POST",
    timeoutMs: 12000,
    body: {
      stream_id: cleanText(streamId, "cam-1"),
      publicHost: window.location.hostname,
      fps: Number(options.fps || 15),
      quality: Number(options.quality || 2),
    },
  });
}

async function configureWisIntelbrasPushCameraSlot(slot, current = {}, defaults = {}) {
  const channel = window.prompt("DVR channel number to push from the MHDX", cleanText(defaults.channel, "") || cleanText(current.channel, "") || "1");
  if (channel === null) return { ok: false, error: "cancelled" };
  const streamId = window.prompt("wasm-agent push stream id", cleanText(defaults.streamId || defaults.stream_id, "") || cleanText(current.streamId || current.stream_id, "") || `cam-${Math.max(1, Math.round(Number(channel) || 1))}`);
  if (streamId === null) return { ok: false, error: "cancelled" };
  const payload = await startWisCameraPushIngest(streamId, defaults);
  const actualStreamId = cleanText(payload?.stream_id || streamId, "cam-1");
  const ingestUrl = cleanText(payload?.ingest?.url, "");
  const config = createWisCameraPushConfig({
    slot,
    label: `Intelbras CAM ${cleanText(channel, "1")} RTMP push`,
    vendor: "intelbras",
    channel: cleanText(channel, "1"),
    streamId: actualStreamId,
    ingestUrl,
    urls: {
      statusUrl: cameraPushStatusUrl(actualStreamId),
      frameUrl: cameraPushFrameUrl(actualStreamId),
      streamUrl: cameraPushStreamUrl(actualStreamId),
      replayUrl: cameraPushReplayUrl(actualStreamId),
    },
    fps: 15,
    quality: 2,
  });
  stopWisCameraStream(slot);
  stopWisCameraTimer(slot);
  saveLocalWisCameraConfig(slot, config);
  const result = applyWisCameraConfig(slot, config);
  window.alert(`RTMP ingest is listening.\n\nConfigure the DVR RTMP/custom live stream URL as:\n${ingestUrl}\n\nFor the best image, choose the DVR main/high-quality stream and H.264 when available.`);
  renderWis();
  return result;
}

async function configureWisIntelbrasCredentialProfile(slot, current = {}, defaults = {}) {
  const seed = intelbrasConfigFromCamera(current, defaults);
  const host = window.prompt("Intelbras DVR/NVR IP, DDNS host, or RTSP tunnel host reachable from wasm-agent", cleanText(defaults.host, "") || seed.host || "192.168.1.78");
  if (host === null) return { ok: false, error: "cancelled" };
  if (!cleanText(host, "")) return { ok: false, error: "missing_host" };
  const user = window.prompt("Intelbras DVR/NVR username", cleanText(defaults.user, "") || seed.user || "admin");
  if (user === null) return { ok: false, error: "cancelled" };
  const password = window.prompt("Intelbras DVR/NVR password. It stays only in this browser.", cleanText(defaults.password, "") || seed.password || "");
  if (password === null) return { ok: false, error: "cancelled" };
  const channel = window.prompt("Camera channel number on the DVR", cleanText(defaults.channel, "") || seed.channel || "1");
  if (channel === null) return { ok: false, error: "cancelled" };
  const subtype = window.prompt("Stream: 0 main/high quality, 1 extra/low bandwidth", cleanText(defaults.subtype, "") || cleanText(current.subtype, "") || "0");
  if (subtype === null) return { ok: false, error: "cancelled" };
  const requestedMode = cleanText(defaults.mode, "").toLowerCase();
  const preferredMode = ["snapshot", "snap", "jpeg", "mjpeg", "mjpg", "http", "https", "rtsp"].includes(requestedMode)
    ? requestedMode
    : cleanText(current.preferredMode || current.preferred_mode, "auto");
  const cleanMode = normalizeIntelbrasCredentialPlaybackMode(preferredMode);
  const promptedPort = window.prompt(
    cleanMode === "https"
      ? "Intelbras HTTPS port reachable from wasm-agent"
      : (cleanMode === "snapshot" || cleanMode === "mjpeg"
        ? "Intelbras HTTP port reachable from wasm-agent"
        : "Intelbras RTSP/tunnel port reachable from wasm-agent"),
    cleanText(defaults.port, "") || intelbrasHostPort(host) || seed.port || intelbrasCredentialPortForMode(cleanMode, current)
  );
  if (promptedPort === null) return { ok: false, error: "cancelled" };
  const port = cleanText(promptedPort, intelbrasCredentialPortForMode(cleanMode, current));
  stopWisCameraStream(slot);
  stopWisCameraTimer(slot);
  const config = intelbrasCredentialCameraConfig({
    host,
    user,
    password,
    channel,
    subtype,
    mode: preferredMode,
    port,
    current,
  });
  saveLocalWisCameraConfig(slot, config);
  const result = applyWisCameraConfig(slot, config);
  window.alert(cleanMode === "rtsp"
    ? "Intelbras credentials saved locally. WIS will decode the true DVR RTSP feed through wasm-agent now."
    : (cleanMode === "relay"
      ? "Intelbras credentials saved locally. WIS will decode the true DVR RTSP feed through wasm-agent now."
      : "Intelbras credentials saved locally. WIS will try the browser-safe stream now; recovery actions stay available if the DVR blocks this endpoint."));
  renderWis();
  return result;
}

async function publishWisCameraAccessToShared() {
  const active = activeSpaceContext();
  const sharedSpaceId = cleanText(active.shared_space_id || active.room?.id, "");
  if (!sharedSpaceId) {
    window.alert("This space is not shared yet.");
    return null;
  }
  const snapshot = wisSurfaceState();
  const artifact = state.wisActiveArtifact || {};
  if (!snapshot?.tree || !artifact.id) return null;
  const cameras = snapshot.state?.cameras && typeof snapshot.state.cameras === "object" ? snapshot.state.cameras : {};
  const operations = [
    { op: "add_document", document_id: snapshot.document?.id || "main", title: artifact.title || snapshot.document?.title || "Cameras", node: snapshot.tree },
    { op: "set_state", document_id: snapshot.document?.id || "main", key: "cameraAccess", value: snapshot.state?.cameraAccess || {} },
  ];
  Object.entries(cameras).forEach(([slot, config]) => {
    if (!slot || !config || typeof config !== "object") return;
    operations.push({ op: "set_state", document_id: snapshot.document?.id || "main", key: `cameras.${slot}`, value: config });
  });
  const patch = {
    schema: WIS_PATCH_SCHEMA,
    artifact_id: artifact.id,
    title: artifact.title || snapshot.document?.title || "Cameras",
    space_id: active.storage_id || active.id || activeSpaceStorageId(),
    shared_space_id: sharedSpaceId,
    operations,
  };
  const result = await fetchJson("/wis/artifacts/patch", {
    method: "POST",
    timeoutMs: 12000,
    body: { patch },
  });
  await refreshWisArtifactsAfterPatch(result, "camera-access-share");
  recordUserEvent("wis.camera_access_shared", {
    source: "wis",
    target: `wis:${artifact.id}`,
    summary: "Published camera access metadata to shared space",
    data: { artifact_id: artifact.id, shared_space_id: sharedSpaceId, cameras: Object.keys(cameras).length },
  });
  return result;
}

async function configureWisCameraSlot(node = {}) {
  const slot = wisCameraSlotFromNode(node);
  const current = localWisCameraConfig(slot) || node.props?.camera || {};
  const value = window.prompt(
    "Camera source for this device. Enter device, intelbras, intelbras push, intelbras capture, clear, or paste a browser-playable http(s) MJPEG/HLS/video URL. RTSP is detected but needs a relay.",
    current.kind === "device" ? "device" : cleanText(current.url, "")
  );
  if (value === null) return { ok: false, error: "cancelled" };
  const source = cleanText(value, "");
  if (!source || source.toLowerCase() === "clear" || source.toLowerCase() === "none") {
    stopWisCameraStream(slot);
    stopWisCameraTimer(slot);
    saveLocalWisCameraConfig(slot, null);
    const result = runWisAction({ type: "clearCamera", slot }, "surface");
    renderWis();
    return result;
  }
  const intelbrasShortcut = parseIntelbrasCameraShortcut(source);
  if (intelbrasShortcut) {
    return configureWisIntelbrasCameraSlot(slot, current, intelbrasShortcut);
  }
  if (["push", "rtmp", "rtmp-push", "dvr-push"].includes(source.toLowerCase())) {
    return configureWisIntelbrasPushCameraSlot(slot, current, {});
  }
  if (source.toLowerCase() === "capture" || source.toLowerCase() === "screen" || source.toLowerCase() === "tab") {
    return startWisCameraCapture(slot, current);
  }
  if (source.toLowerCase() === "device" || source.toLowerCase() === "local" || source.toLowerCase() === "webcam") {
    const getUserMedia = navigator.mediaDevices?.["getUserMedia"]?.bind(navigator.mediaDevices);
    if (!getUserMedia) {
      window.alert("This browser does not expose camera capture to wasm-agent.");
      return { ok: false, error: "get_user_media_unavailable" };
    }
    stopWisCameraStream(slot);
    stopWisCameraTimer(slot);
    const stream = await getUserMedia({ video: true, audio: false });
    state.wisCameraStreams.set(slot, stream);
    saveLocalWisCameraConfig(slot, { kind: "device", label: "This device camera", mediaMode: "getUserMedia", element: "video" });
    const result = applyWisCameraConfig(slot, { kind: "device", label: "This device camera", mediaMode: "getUserMedia", element: "video" });
    renderWis();
    return result;
  }
  stopWisCameraStream(slot);
  stopWisCameraTimer(slot);
  const classified = classifyWisCameraUrl(source);
  const pushStreamId = classified.kind === "push"
    ? (/^cam-\d+$/i.test(slot) ? slot : "cam-1")
    : "";
  const config = {
    ...classified,
    url: source,
    label: classified.kind === "push"
      ? "DVR RTMP push"
      : (classified.mediaMode === "rtsp-relay-required" ? "RTSP needs client relay" : "Camera URL"),
    streamId: pushStreamId,
    ingestUrl: classified.kind === "push" ? source : "",
    statusUrl: pushStreamId ? cameraPushStatusUrl(pushStreamId) : "",
    frameUrl: pushStreamId ? cameraPushFrameUrl(pushStreamId) : "",
  };
  saveLocalWisCameraConfig(slot, config);
  const result = applyWisCameraConfig(slot, config);
  if (!classified.browserPlayable) {
    window.alert("Saved locally, but this source is not directly browser-playable. Use an HTTP MJPEG/HLS/video URL, or add a client-side relay/publisher for RTSP.");
  }
  renderWis();
  return result;
}

async function configureWisIntelbrasCameraSlot(slot, current = {}, defaults = {}) {
  const seededMode = cleanText(defaults.mode, "") || cleanText(current.preferredMode || current.preferred_mode, "") || cleanText(current.mode, "") || "credentials";
  if (["push", "rtmp", "rtmp-push", "dvr-push"].includes(seededMode.toLowerCase())) {
    return configureWisIntelbrasPushCameraSlot(slot, current, defaults);
  }
  if (["credentials", "credential", "creds", "login", "auto", "direct", "relay", "proxy"].includes(seededMode.toLowerCase())) {
    return configureWisIntelbrasCredentialProfile(slot, current, defaults);
  }
  const mode = window.prompt("Intelbras mode: push for DVR RTMP push, credentials for same-origin relay, capture for portal tab capture, snapshot for direct JPEG polling, https for HTTPS MJPEG, mjpeg for HTTP, rtsp for client publisher", seededMode);
  if (mode === null) return { ok: false, error: "cancelled" };
  const requestedMode = cleanText(mode, "https").toLowerCase();
  if (["push", "rtmp", "rtmp-push", "dvr-push"].includes(requestedMode)) {
    return configureWisIntelbrasPushCameraSlot(slot, current, { ...defaults, mode: "push" });
  }
  if (["credentials", "credential", "creds", "login", "auto", "direct", "relay", "proxy"].includes(requestedMode)) {
    return configureWisIntelbrasCredentialProfile(slot, current, { ...defaults, mode: "credentials" });
  }
  const cleanMode = requestedMode === "capture" || requestedMode === "portal"
    ? "capture"
    : (requestedMode === "rtsp" ? "rtsp" : (requestedMode === "snapshot" || requestedMode === "snap" || requestedMode === "jpeg" ? "snapshot" : (requestedMode === "http" || requestedMode === "mjpeg" || requestedMode === "mjpg" ? "mjpeg" : "https")));
  const host = window.prompt("Intelbras DVR/NVR IP or host on this network", cleanText(defaults.host, "") || cleanText(current.host, "") || "192.168.1.78");
  if (host === null) return { ok: false, error: "cancelled" };
  if (cleanMode === "capture") {
    const portalUrl = cameraOriginUrl(intelbrasMjpegUrl({ host, port: 80, scheme: "http" }));
    return startWisIntelbrasPortalCapture(slot, {
      ...current,
      vendor: "intelbras",
      url: portalUrl,
      portalUrl,
      host: cleanText(host, ""),
      channel: cleanText(defaults.channel || current.channel, ""),
      accessScope: "shared-space",
      secretPolicy: "per-device-browser-session",
      shareable: true,
    }, portalUrl);
  }
  const port = window.prompt(cleanMode === "rtsp" ? "Intelbras RTSP port" : (cleanMode === "https" ? "Intelbras HTTPS port" : (cleanMode === "snapshot" ? "Intelbras HTTP snapshot port" : "Intelbras HTTP port")), cleanText(current.port, "") || (cleanMode === "rtsp" ? "554" : (cleanMode === "https" ? "443" : "80")));
  if (port === null) return { ok: false, error: "cancelled" };
  const user = window.prompt("Intelbras DVR/NVR username", "admin");
  if (user === null) return { ok: false, error: "cancelled" };
  const password = window.prompt("Intelbras DVR/NVR password. It stays only in this browser.", "");
  if (password === null) return { ok: false, error: "cancelled" };
  const channel = window.prompt("Camera channel number on the DVR", cleanText(defaults.channel, "") || cleanText(current.channel, "") || "1");
  if (channel === null) return { ok: false, error: "cancelled" };
  let subtype = cleanText(defaults.subtype, "") || cleanText(current.subtype, "");
  if (cleanMode !== "snapshot") {
    subtype = window.prompt("Stream: 0 main/high quality, 1 extra/low bandwidth", subtype || "0");
    if (subtype === null) return { ok: false, error: "cancelled" };
  }
  stopWisCameraStream(slot);
  stopWisCameraTimer(slot);
  const url = cleanMode === "rtsp"
    ? intelbrasRtspUrl({ host, user, password, channel, subtype, port })
    : (cleanMode === "snapshot"
      ? intelbrasSnapshotUrl({ host, user, password, channel, subtype, port, scheme: "http" })
      : intelbrasMjpegUrl({ host, user, password, channel, subtype, port, scheme: cleanMode === "https" ? "https" : "http" }));
  const classified = cleanMode === "rtsp"
    ? classifyWisCameraUrl(url)
    : (cleanMode === "snapshot"
      ? { kind: "url", mediaMode: "jpeg-snapshot-poll", element: "snapshot", browserPlayable: true }
      : { kind: "url", mediaMode: cleanMode === "https" ? "mjpeg-https" : "mjpeg-http", element: "img", browserPlayable: true });
  const config = {
    ...classified,
    vendor: "intelbras",
    mode: cleanMode,
    host: cleanText(host, ""),
    port: cleanText(port, "554"),
    channel: cleanText(channel, "1"),
    subtype: cleanMode === "snapshot" ? cleanText(subtype, "") : cleanText(subtype, "0"),
    url,
    portalUrl: cameraOriginUrl(intelbrasMjpegUrl({ host, port: 80, scheme: "http" })),
    accessScope: "shared-space",
    secretPolicy: "per-device-browser-session",
    shareable: true,
    label: cleanMode === "rtsp" ? "Intelbras RTSP needs client publisher" : (cleanMode === "snapshot" ? "Intelbras JPEG snapshot" : (cleanMode === "https" ? "Intelbras HTTPS MJPEG" : "Intelbras HTTP MJPEG")),
  };
  saveLocalWisCameraConfig(slot, config);
  const result = applyWisCameraConfig(slot, config);
  window.alert(cleanMode === "rtsp"
    ? "Intelbras RTSP URL saved locally for this device. Browser playback still needs a client-side publisher/relay."
    : (cleanMode === "snapshot"
      ? "Intelbras snapshot URL saved locally. If the DVR HTTP API and browser auth allow it, WIS will poll JPEG frames directly."
      : `${cleanMode === "https" ? "Intelbras HTTPS" : "Intelbras HTTP"} MJPEG URL saved locally. If the DVR extra stream exposes MJPEG and the browser accepts its auth, it should render directly.`));
  renderWis();
  return result;
}

function exportWisSpace(origin = "surface") {
  if (!state.wisSandbox) return null;
  const payload = state.wisSandbox.exportSpace();
  state.wisLastExport = payload;
  recordUserEvent("wis.space_exported", {
    source: origin === "automation" ? "wasm-agent-automation" : "wis",
    target: `wis:${payload.space?.id || "space"}`,
    summary: `Exported ${payload.space?.id || "WIS space"}`,
    data: {
      schema: payload.schema,
      document_count: payload.space?.documents?.length || 0,
      backend_dependency: payload.guarantees?.backendDependency,
      iframe_primary_architecture: payload.guarantees?.iframePrimaryArchitecture,
    },
  });
  renderWis();
  return payload;
}

function installWisAutomationHook() {
  if (!state.wisSandbox || state.wisAutomationInstalled) return;
  state.wisUnsubscribe = state.wisSandbox.subscribe(scheduleWisRender);
  installWisCameraTraceDumpHelper();
  window.wasmAgentWis = {
    inspect() {
      return wisSurfaceState();
    },
    act(action) {
      const result = runWisAction(action, "automation");
      return { result, surface: wisSurfaceState() };
    },
    exportSpace() {
      return exportWisSpace("automation");
    },
    createCameraArtifact(options = {}) {
      return createWisFocusedCameraArtifact(options);
    },
    cameraController() {
      return WIS_CAMERA_CONTROLLER_CONTRACT;
    },
    dumpCameraTrace(streamId = "") {
      return dumpWisCameraTrace(streamId);
    },
  };
  state.wisAutomationInstalled = true;
}

function wisFocusState() {
  const active = document.activeElement;
  if (!active?.dataset?.wisNodeId) return null;
  return {
    id: active.dataset.wisNodeId,
    start: Number.isFinite(active.selectionStart) ? active.selectionStart : null,
    end: Number.isFinite(active.selectionEnd) ? active.selectionEnd : null,
  };
}

function restoreWisFocus(focus) {
  if (!focus?.id || !els.wisViewport) return;
  const target = Array.from(els.wisViewport.querySelectorAll("[data-wis-node-id]"))
    .find((element) => element.dataset.wisNodeId === focus.id);
  if (!target) return;
  target.focus({ preventScroll: true });
  if (target instanceof HTMLInputElement && focus.start !== null && focus.end !== null) {
    try {
      target.setSelectionRange(focus.start, focus.end);
    } catch {
      // Some input types do not support text selection.
    }
  }
}

function wisSurfaceIsFocusedCamera(snapshot = null) {
  return isWisFocusedCameraSurface(snapshot || wisSurfaceState());
}

function wisFocusedCameraSlot(snapshot = null) {
  return focusedWisCameraSlotFromSurface(snapshot || wisSurfaceState(), "cam-1");
}

async function configureFocusedWisCamera() {
  const snapshot = wisSurfaceState();
  const slot = wisFocusedCameraSlot(snapshot) || "cam-1";
  if (!slot) return { ok: false, error: "missing_slot" };
  const camera = snapshot?.state?.cameras?.[slot] || {};
  recordUserEvent("wis.camera_header_config", {
    source: "wis",
    target: `wis:${slot}`,
    summary: `Opened camera config for ${slot}`,
    data: { slot },
  });
  return configureWisCameraSlot({ id: `${slot}-header-config`, props: { slot, data: { slot }, camera } });
}

function wisCameraBaseStreamId(slot, camera = {}) {
  return wisCameraBaseStreamIdContract(slot, camera);
}

function wisCameraQualityMode(streamId) {
  const key = cleanText(streamId, "cam-1");
  return state.wisCameraQualityModes.get(key) || "primary";
}

function wisCameraQualityStreamId(slot, camera = {}) {
  const base = wisCameraBaseStreamId(slot, camera);
  const mode = wisCameraQualityMode(base);
  return wisCameraQualityStreamIdContract(slot, camera, mode);
}

function wisCameraSlotForStreamId(streamId, preferredSlot = "") {
  const key = cleanText(streamId, "");
  const preferred = cleanText(preferredSlot, "");
  const candidates = [];
  const addCandidate = (slot) => {
    const cleanSlot = cleanText(slot, "");
    if (cleanSlot && !candidates.includes(cleanSlot)) candidates.push(cleanSlot);
  };
  addCandidate(preferred);
  addCandidate(wisFocusedCameraSlot() || "");
  addCandidate(key);
  try {
    const cameras = wisSurfaceState()?.state?.cameras;
    if (cameras && typeof cameras === "object") Object.keys(cameras).forEach(addCandidate);
  } catch {
    // Slot resolution is best effort; callers still validate the camera config.
  }
  for (const slot of candidates) {
    const camera = wisCameraConfigForSlot(slot) || {};
    if (!wisCameraIsPushConfig(camera)) continue;
    const base = wisCameraBaseStreamId(slot, camera);
    const primary = cleanText(camera.primaryStreamId || camera.primary_stream_id, base);
    const extra = cleanText(camera.extraStreamId || camera.extra_stream_id || camera.subStreamId || camera.sub_stream_id, `${base}-extra`);
    if ([base, primary, extra, wisCameraQualityStreamId(slot, camera)].some((candidate) => cleanText(candidate, "") === key)) return slot;
  }
  return preferred || wisFocusedCameraSlot() || key || "cam-1";
}

function wisCameraTimelineMode(streamId) {
  const key = cleanText(streamId, "cam-1");
  return state.wisCameraTimelineModes.get(key) || "live";
}

function setWisCameraNotice(streamId, message = "", tone = "info", ttlMs = 2800) {
  const key = cleanText(streamId, "cam-1");
  if (!message) state.wisCameraNotices.delete(key);
  else state.wisCameraNotices.set(key, { message: cleanText(message, ""), tone: cleanText(tone, "info"), until: Date.now() + ttlMs });
  const slot = wisFocusedCameraSlot() || "cam-1";
  const camera = wisCameraConfigForSlot(slot) || {};
  renderWisCameraHeader(camera?.kind ? { ...camera, _slot: slot } : null);
}

function currentWisCameraNotice(streamId) {
  const key = cleanText(streamId, "cam-1");
  const notice = state.wisCameraNotices.get(key);
  if (!notice) return null;
  if (notice.until && Date.now() > notice.until) {
    state.wisCameraNotices.delete(key);
    return null;
  }
  return notice;
}

function cameraTimelineFrameLabel(frame = {}) {
  const seekTargetMs = Number(frame?.seek_target_ms ?? frame?.seekTargetMs);
  const labelFrame = Number.isFinite(seekTargetMs) && seekTargetMs > 0
    ? { ...frame, timestamp_ms: seekTargetMs }
    : frame;
  return wisCameraTimelineFrameLabelContract(labelFrame);
}

function selectedWisCameraTimelineFrame(streamId) {
  const key = cleanText(streamId, "");
  return key ? state.wisCameraTimelineSelections.get(key) || null : null;
}

function wisCameraTimelineFrameTimestampMs(frame = null, fallback = Date.now()) {
  const timestampMs = Number(frame?.timestamp_ms ?? frame?.timestampMs ?? frame?.snapped_timestamp_ms ?? frame?.snappedTimestampMs ?? fallback);
  return Number.isFinite(timestampMs) && timestampMs > 0 ? timestampMs : fallback;
}

function wisCameraTimelineFramePlaybackKey(frame = null) {
  return wisCameraTimelineFramePlaybackKeyContract(frame);
}

function wisCameraTimelineForStream(streamId) {
  const key = cleanText(streamId, "");
  if (key && state.wisCameraTimeline.streamId === key) return state.wisCameraTimeline;
  return {
    streamId: key,
    mode: key ? wisCameraTimelineMode(key) : "live",
    day: "",
    frames: [],
    range: null,
    availableRange: null,
    loadedAt: 0,
    loading: false,
    error: "",
  };
}

function wisCameraSegmentForTarget(streamId, targetTimeMs = 0, options = {}) {
  const key = cleanText(streamId, "");
  const timeline = wisCameraTimelineForStream(key);
  const frames = Array.isArray(timeline.frames) ? timeline.frames : [];
  const requestedFrame = options.requestedFrame && typeof options.requestedFrame === "object" ? options.requestedFrame : null;
  const target = Number(targetTimeMs);
  const targetTime = Number.isFinite(target) ? target : wisCameraTimelinePlaybackStartMs(requestedFrame, Date.now());
  const windowModel = wisCameraTimelineTimeWindow(timeline, frames, { playbackPosition: targetTime });
  const frame = requestedFrame?.id
    ? requestedFrame
    : wisCameraTimelineFrameClosestToTime(frames, targetTime, windowModel);
  if (!frame) {
    traceWisCameraBoundary("archive.frame.resolved", {
      functionName: "wisCameraSegmentForTarget",
      streamId: key,
      requestedTimestampMs: targetTime,
      archiveWindowStartMs: Number(timeline?.availableRange?.start_ms ?? timeline?.available_range?.start_ms ?? windowModel.visibleStart ?? 0),
      archiveWindowEndMs: Number(timeline?.availableRange?.end_ms ?? timeline?.available_range?.end_ms ?? windowModel.visibleEnd ?? 0),
      resolvedTimestampMs: null,
      recordedPlaybackPossible: false,
      fetchResult: "empty",
      frameCount: frames.length,
    });
    return null;
  }
  const snappedTimestampMs = wisCameraTimelineFrameTimestampMs(frame, targetTime);
  traceWisCameraBoundary("archive.frame.resolved", {
    functionName: "wisCameraSegmentForTarget",
    streamId: key,
    requestedTimestampMs: targetTime,
    archiveWindowStartMs: Number(timeline?.availableRange?.start_ms ?? timeline?.available_range?.start_ms ?? windowModel.visibleStart ?? 0),
    archiveWindowEndMs: Number(timeline?.availableRange?.end_ms ?? timeline?.available_range?.end_ms ?? windowModel.visibleEnd ?? 0),
    resolvedTimestampMs: snappedTimestampMs,
    recordedPlaybackPossible: Boolean(frame?.id && frame?.url),
    fetchResult: frame?.id && frame?.url ? "non-empty" : "empty",
    frameCount: frames.length,
    segmentId: cleanText(frame?.id, ""),
    segmentUrl: cleanText(frame?.url, ""),
  });
  return {
    ...frame,
    timestamp_ms: snappedTimestampMs,
    seek_target_ms: targetTime,
    snapped_timestamp_ms: snappedTimestampMs,
  };
}

const wisCameraMediaLogAt = new Map();

function wisCameraVerboseDiagnosticsEnabled() {
  try {
    return Boolean(window.WASM_AGENT_CAMERA_DEBUG || localStorage.getItem("wasmAgent.cameraDebug") === "1");
  } catch {
    return false;
  }
}

function logWisCameraMediaEvent(event, data = {}, options = {}) {
  if (event === "camera.visual.blink_detected") {
    if (!(state.wisCameraBlinkEvents instanceof Map)) state.wisCameraBlinkEvents = new Map();
    const blinkStreamId = cleanText(data.streamId || data.cameraId, "");
    if (blinkStreamId) state.wisCameraBlinkEvents.set(blinkStreamId, Number(state.wisCameraBlinkEvents.get(blinkStreamId) || 0) + 1);
  }
  const verbose = wisCameraVerboseDiagnosticsEnabled();
  let perfDebug = verbose;
  try {
    perfDebug = perfDebug || localStorage.getItem("wasmAgent.cameraPerfDebug") === "1";
  } catch {
    perfDebug = verbose;
  }
  const critical = event === "camera.visual.blink_detected"
    || event === "camera.playback.transition"
    || event === "camera.timeline.seek"
    || event === "camera.loop.owner"
    || event === "camera.visual.frame_commit"
    || event.includes("ownership")
    || event.includes("blocked_by_recorded_owner")
    || event.includes("stale_writer")
    || event.includes(".error")
    || event.includes("violation");
  const perfSample = event === "camera.perf.sample";
  const always = Boolean(options.always && critical);
  if (perfSample && !perfDebug) return;
  if (!always && !critical && !verbose && !(perfSample && perfDebug)) return;
  const sampleMs = Number(options.sampleMs || 0);
  const now = performance.now();
  if (sampleMs > 0) {
    const key = `${event}:${cleanText(data.streamId, "")}`;
    const lastAt = Number(wisCameraMediaLogAt.get(key) || 0);
    if (lastAt > 0 && now - lastAt < sampleMs) return;
    wisCameraMediaLogAt.set(key, now);
	  }
	  const payload = { event, t: now, cameraArtifactBuild: WIS_CAMERA_ARTIFACT_BUILD, ...data };
	  traceWisCameraBoundary(event, payload);
	  try {
	    console.debug("[camera]", event, payload);
  } catch {
    // Camera media diagnostics are best effort.
  }
}

function cloneWisCameraTraceValue(value) {
  try {
    if (typeof structuredClone === "function") return structuredClone(value);
  } catch {
    // Fall through to JSON cloning.
  }
  try {
    return JSON.parse(JSON.stringify(value ?? null));
  } catch {
    return value == null ? value : String(value);
  }
}

function wisCameraCurrentTraceStreamId(streamId = "") {
  const explicit = cleanText(streamId, "");
  if (explicit) return explicit;
  const recordedKeys = [];
  try {
    state.wisCameraRecordedSessions?.forEach?.((session, key) => {
      if (session?.mode === "recorded" && key) recordedKeys.push(cleanText(key, ""));
    });
  } catch {
    // Trace helpers must never disturb camera playback.
  }
  if (recordedKeys.length) return recordedKeys[recordedKeys.length - 1];
  const timelineStream = cleanText(state.wisCameraTimeline?.streamId, "");
  if (timelineStream) return timelineStream;
  const slot = wisFocusedCameraSlot() || "cam-1";
  const camera = wisCameraConfigForSlot(slot) || {};
  return wisCameraQualityStreamId(slot, camera);
}

function wisCameraControlTargetSummary(target = null) {
  if (!target) return null;
  const button = target.closest?.("[data-wis-camera-control]") || target;
  const row = target.closest?.(".wis-camera-timeline-controls-row");
  const rect = button?.getBoundingClientRect?.();
  return {
    tagName: cleanText(button?.tagName, ""),
    className: cleanText(button?.className, ""),
    control: cleanText(button?.dataset?.wisCameraControl, ""),
    streamId: cleanText(button?.dataset?.wisCameraStreamId || row?.dataset?.streamId, ""),
    slot: cleanText(button?.dataset?.wisCameraSlot, ""),
    action: cleanText(button?.dataset?.wisCameraAction, ""),
    icon: cleanText(button?.dataset?.icon, ""),
    disabledReason: cleanText(button?.dataset?.wisCameraDisabledReason, ""),
    disabled: Boolean(button?.disabled),
    ariaDisabled: cleanText(button?.getAttribute?.("aria-disabled"), ""),
    ariaPressed: cleanText(button?.getAttribute?.("aria-pressed"), ""),
    title: cleanText(button?.getAttribute?.("title"), ""),
    rect: rect ? {
      left: Math.round(Number(rect.left || 0)),
      top: Math.round(Number(rect.top || 0)),
      width: Math.round(Number(rect.width || 0)),
      height: Math.round(Number(rect.height || 0)),
    } : null,
  };
}

function wisCameraTraceEventStreamId(entry = {}) {
  const item = entry && typeof entry === "object" ? entry : {};
  return cleanText(item.streamId || item.cameraId || item.artifactId || item.mediaStreamId || item.visibleImageStreamId, "");
}

function wisCameraLatestTraceEvent(events = [], predicate = null) {
  for (let index = events.length - 1; index >= 0; index -= 1) {
    const entry = events[index];
    if (!entry || typeof entry !== "object") continue;
    if (!predicate || predicate(entry)) return entry;
  }
  return null;
}

function wisCameraTraceNumber(...values) {
  for (const value of values) {
    const numeric = Number(value);
    if (Number.isFinite(numeric)) return numeric;
  }
  return 0;
}

function wisCameraTraceHasNumber(value) {
  return value !== null && value !== undefined && value !== "" && Number.isFinite(Number(value));
}

function wisCameraPlaybackUrlParts(playbackUrl = "") {
  const raw = cleanText(playbackUrl, "");
  if (!raw) return { playbackUrl: "", playbackUrlFromMs: 0, playbackUrlFollow: "" };
  try {
    const parsed = new URL(raw, window.location?.href || "http://localhost/");
    return {
      playbackUrl: raw,
      playbackUrlFromMs: wisCameraTraceNumber(
        parsed.searchParams.get("from_ms"),
        parsed.searchParams.get("timestamp_ms"),
        parsed.searchParams.get("timestampMs")
      ),
      playbackUrlFollow: cleanText(parsed.searchParams.get("follow"), ""),
    };
  } catch {
    return { playbackUrl: raw, playbackUrlFromMs: 0, playbackUrlFollow: "" };
  }
}

function wisCameraVisibleImageSummary(media = null) {
  if (!media) return null;
  const rect = media.getBoundingClientRect?.();
  const style = window.getComputedStyle ? window.getComputedStyle(media) : null;
  const connected = Boolean(media.isConnected);
  const visible = Boolean(
    connected
    && rect
    && Number(rect.width || 0) > 0
    && Number(rect.height || 0) > 0
    && rect.bottom >= 0
    && rect.right >= 0
    && rect.top <= window.innerHeight
    && rect.left <= window.innerWidth
    && style?.display !== "none"
    && style?.visibility !== "hidden"
    && style?.opacity !== "0"
  );
  const surface = media.closest?.(".wis-node-webcam_placeholder[data-wis-camera-slot]");
  const src = cleanText(media.currentSrc || media.src || media.dataset?.wisLastGoodSrc || "", "");
  return {
    streamId: cleanText(media.dataset?.wisMediaStreamId || media.dataset?.wisCameraStreamId || surface?.dataset?.wisCameraStreamId, ""),
    owner: cleanText(media.dataset?.wisMediaOwner, ""),
    frameMs: wisCameraTraceNumber(media.dataset?.wisPlaybackFrameMs, media.dataset?.wisFrameTimestampMs),
    srcPrefix: src.slice(0, 180),
    isConnected: connected,
    isVisible: visible,
    rect: rect ? {
      left: Math.round(Number(rect.left || 0)),
      top: Math.round(Number(rect.top || 0)),
      width: Math.round(Number(rect.width || 0)),
      height: Math.round(Number(rect.height || 0)),
    } : null,
  };
}

function wisCameraVisibleImagesForTrace() {
  return Array.from(document.querySelectorAll?.(".wis-camera-image, .wis-camera-video") || [])
    .map((media) => wisCameraVisibleImageSummary(media))
    .filter(Boolean);
}

function wisCameraControllerStreamIdForTrace(streamId = "") {
  const key = cleanText(streamId, "");
  const controllers = state.wisCameraArtifactControllers;
  if (key && controllers?.get?.(key)) return key;
  try {
    const keys = Array.from(controllers?.keys?.() || []).map((candidate) => cleanText(candidate, "")).filter(Boolean);
    return keys[keys.length - 1] || "";
  } catch {
    return "";
  }
}

function wisCameraVisibleImageForStream(streamId = "") {
  const key = cleanText(streamId, "");
  const images = wisCameraVisibleImagesForTrace();
  return images.find((image) => image.isVisible && image.streamId === key)
    || images.find((image) => image.streamId === key)
    || images.find((image) => image.isVisible)
    || images[0]
    || null;
}

function wisCameraOwnerStateFromControllerMode(mode = "live") {
  const cleanMode = cleanText(mode, "live");
  if (cleanMode === "live") return WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  if (["seeking", "buffering", "loading"].includes(cleanMode)) return WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING;
  if (["paused", "ended", "gap", "stalled", "error"].includes(cleanMode)) return WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PAUSED;
  return WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PLAYING;
}

function wisCameraReadControllerState(controller = null) {
  try {
    return controller?.getState?.() || null;
  } catch {
    return null;
  }
}

function wisCameraPlayPauseStateForStream(streamId = "", options = {}) {
  const button = options.button || null;
  const targetSummary = button ? wisCameraControlTargetSummary(button) : {};
  const clickedControlStreamId = cleanText(targetSummary.streamId || streamId, "");
  const key = clickedControlStreamId || wisCameraCurrentTraceStreamId(streamId);
  const controller = options.controller !== undefined
    ? options.controller
    : (key ? state.wisCameraArtifactControllers?.get?.(key) : null);
  const controllerState = wisCameraReadControllerState(controller);
  const controllerMode = cleanText(controllerState?.playbackClock?.mode, "");
  const controllerOwnerState = controllerMode
    ? wisCameraOwnerStateFromControllerMode(controllerMode)
    : WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  const session = options.session !== undefined ? options.session : recordedWisCameraSession(key);
  const appOwnerState = key ? wisCameraTimelineOwnerStateContract(state, key) : WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  const sessionOwnerState = session
    ? wisCameraPlaybackOwnerState(session, controllerOwnerState || appOwnerState)
    : WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  const sessionStatus = cleanText(session?.status || session?.state, "");
  let owner = WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  if (session) {
    if (["seeking", "buffering", "loading"].includes(sessionStatus)) owner = WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING;
    else if (session.clockPaused || session.userPaused || sessionStatus === "paused") owner = WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PAUSED;
    else owner = WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PLAYING;
  } else if (controllerOwnerState !== WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE) owner = controllerOwnerState;
  else if (appOwnerState !== WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE) owner = appOwnerState;
  const mode = controllerMode
    || sessionStatus
    || cleanText(session?.mode, "")
    || (owner === WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE ? "live" : "recorded");
  const paused = owner === WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PAUSED;
  const seeking = owner === WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING;
  const playing = owner === WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PLAYING;
  const notRecorded = owner === WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  const action = playing ? "pause" : "play";
  const icon = playing ? "pause" : "play";
  const label = playing ? "Pause" : "Play";
  const title = notRecorded
    ? "Not in recorded mode"
    : (seeking ? "Recorded playback is seeking" : (playing ? "Pause recorded playback" : "Resume recorded playback"));
  const disabledReason = notRecorded
    ? "not-recorded-mode"
    : (seeking ? "recorded-seeking" : (!session ? "no-recorded-session" : ""));
  const expectedPressed = playing ? "true" : "false";
  const visibleImage = wisCameraVisibleImageForStream(key);
  const domAction = cleanText(targetSummary.action, "");
  const domIcon = cleanText(targetSummary.icon || (domAction === "pause" ? "pause" : (domAction === "play" ? "play" : "")), "");
  const domPressed = cleanText(targetSummary.ariaPressed, "");
  const domDisabledReason = cleanText(targetSummary.disabledReason, "");
  const domMismatch = Boolean(button) && (
    (domAction && domAction !== action)
    || (domIcon && domIcon !== icon)
    || (domPressed && domPressed !== expectedPressed)
    || (domDisabledReason && domDisabledReason !== disabledReason)
  );
  return {
    streamId: key,
    clickedControlStreamId: key,
    controllerStreamId: controller ? key : "",
    visibleImageStreamId: cleanText(visibleImage?.streamId, ""),
    controllerFound: Boolean(controller),
    sessionFound: Boolean(session),
    owner,
    mode,
    paused,
    seeking,
    playing,
    action,
    icon,
    label,
    title,
    disabledReason,
    expectedPressed,
    generation: Number(session?.generation || controllerState?.generation || controllerState?.playbackClock?.generation || 0),
    session,
    controller,
    controllerMode,
    appOwnerState,
    sessionOwnerState,
    controllerOwnerState,
    domAction,
    domIcon,
    domPressed,
    domDisabledReason,
    domMismatch,
    button: targetSummary,
  };
}

function wisCameraPlayPauseTraceContext(resolved = {}, extra = {}) {
  const after = extra.afterState || null;
  const { afterState: _afterState, ...safeExtra } = extra;
  const beforeOwner = cleanText(extra.ownerBefore ?? resolved.owner, "");
  const beforeMode = cleanText(extra.modeBefore ?? resolved.mode, "");
  const beforePaused = Boolean(extra.pausedBefore ?? resolved.paused);
  const beforeIcon = cleanText(extra.iconBefore ?? (resolved.domIcon || resolved.icon), "");
  const afterOwner = cleanText(extra.ownerAfter ?? after?.owner ?? resolved.owner, "");
  const afterMode = cleanText(extra.modeAfter ?? after?.mode ?? resolved.mode, "");
  const afterPaused = Boolean(extra.pausedAfter ?? after?.paused ?? resolved.paused);
  const afterIcon = cleanText(extra.iconAfter ?? after?.icon ?? resolved.icon, "");
  return {
    clickedControlStreamId: cleanText(extra.clickedControlStreamId ?? resolved.clickedControlStreamId ?? resolved.streamId, ""),
    controllerStreamId: cleanText(extra.controllerStreamId ?? resolved.controllerStreamId, ""),
    visibleImageStreamId: cleanText(extra.visibleImageStreamId ?? resolved.visibleImageStreamId, ""),
    ownerBefore: beforeOwner,
    modeBefore: beforeMode,
    pausedBefore: beforePaused,
    iconBefore: beforeIcon,
    ownerAfter: afterOwner,
    modeAfter: afterMode,
    pausedAfter: afterPaused,
    iconAfter: afterIcon,
    generation: Number(extra.generation ?? after?.generation ?? resolved.generation ?? 0),
    rejectionReason: cleanText(extra.rejectionReason || "", ""),
    controllerFound: Boolean(extra.controllerFound ?? resolved.controllerFound),
    action: cleanText(extra.action ?? resolved.action, ""),
    expectedAction: cleanText(extra.expectedAction ?? resolved.action, ""),
    expectedIcon: cleanText(extra.expectedIcon ?? resolved.icon, ""),
    disabledReason: cleanText(extra.disabledReason ?? resolved.disabledReason, ""),
    ...safeExtra,
  };
}

function wisCameraPlayPausePointerContext(event = null) {
  const documentRef = event?.target?.ownerDocument || document;
  const topElement = Number.isFinite(Number(event?.clientX)) && Number.isFinite(Number(event?.clientY))
    ? documentRef?.elementFromPoint?.(Number(event.clientX), Number(event.clientY))
    : null;
  return {
    pointerType: cleanText(event?.pointerType, ""),
    clientX: Number(event?.clientX || 0),
    clientY: Number(event?.clientY || 0),
    elementFromPoint: topElement ? {
      tagName: cleanText(topElement.tagName, ""),
      className: cleanText(topElement.className, ""),
      control: cleanText(topElement.dataset?.wisCameraControl, ""),
    } : null,
  };
}

function traceWisCameraPlayPauseButtonEvent(kind = "click", streamId = "", button = null, event = null) {
  const resolved = wisCameraPlayPauseStateForStream(streamId, { button });
  traceWisCameraPlayPause(`controls.playpause.${cleanText(kind, "event")}`, resolved.streamId, wisCameraPlayPauseTraceContext(resolved, {
    control: "play-pause",
    nativeDisabled: Boolean(button?.disabled),
    ariaDisabled: cleanText(button?.getAttribute?.("aria-disabled"), ""),
    target: wisCameraControlTargetSummary(button),
    ...wisCameraPlayPausePointerContext(event),
  }));
  return true;
}

function wisCameraPlaybackTracePayload(streamId = "", extra = {}) {
  const key = wisCameraCurrentTraceStreamId(streamId);
  const session = recordedWisCameraSession(key);
  const controller = key ? state.wisCameraArtifactControllers?.get?.(key) : null;
  let controllerState = null;
  try {
    controllerState = controller?.getState?.() || null;
  } catch {
    controllerState = null;
  }
  const timeline = wisCameraTimelineForStream(key);
  const frames = Array.isArray(timeline.frames) ? timeline.frames : [];
  const controllerMode = cleanText(controllerState?.playbackClock?.mode, "");
  const appOwnerState = key ? wisCameraTimelineOwnerStateContract(state, key) : WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  const controllerOwnerState = controllerMode ? wisCameraOwnerStateFromControllerMode(controllerMode) : WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
  const ownerState = appOwnerState !== WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE
    ? appOwnerState
    : controllerOwnerState;
  const windowModel = wisCameraTimelineTimeWindow(timeline, frames, {
    playbackPosition: Number(session ? wisCameraRecordedClockMs(session) : 0),
  });
  const activeLoop = key ? wisCameraActivePlaybackLoop(state, key) : null;
  const playbackClockMs = Number(session
    ? wisCameraRecordedClockMs(session)
    : (controllerState?.playbackClock?.anchorRecordingTimeMs ? controller?.getCurrentPlaybackTimeMs?.() : 0));
  return {
    streamId: key,
    owner: ownerState,
    appOwnerState,
    controllerOwnerState,
    controllerMode,
    currentMode: cleanText(controllerMode || session?.status || session?.mode || timeline.mode, "live"),
    paused: Boolean(session?.userPaused || session?.clockPaused || session?.status === "paused" || controllerState?.playbackClock?.mode === "paused"),
    playbackRate: Number(session?.playbackRate || session?.rate || controllerState?.playbackClock?.rate || 1),
    requestedTimestampMs: Number(session?.requestedSeekTimestampMs || controllerState?.playbackClock?.targetTimeMs || 0),
    persistedSeekTimestampMs: Number(session?.persistedSeekTimestampMs || session?.requestedSeekTimestampMs || controllerState?.playbackClock?.targetTimeMs || 0),
    mediaAnchorMs: Number(session?.anchorRecordingTimeMs || controllerState?.playbackClock?.anchorRecordingTimeMs || 0),
    wallAnchorMs: Number(session?.anchorWallTimeMs || controllerState?.playbackClock?.anchorWallTimeMs || 0),
    playbackClockMs: Number.isFinite(playbackClockMs) ? playbackClockMs : 0,
    visibleFrameMs: Number(session?.lastDisplayedFrameTimeMs || controllerState?.playbackClock?.displayedRecordingTimeMs || 0),
    archiveWindowStartMs: Number(timeline?.availableRange?.start_ms ?? timeline?.available_range?.start_ms ?? timeline?.range?.start_ms ?? windowModel.visibleStart ?? 0),
    archiveWindowEndMs: Number(timeline?.availableRange?.end_ms ?? timeline?.available_range?.end_ms ?? timeline?.range?.end_ms ?? windowModel.visibleEnd ?? 0),
    generation: Number(session?.generation || controllerState?.generation || 0),
    sessionId: cleanText(session?.id, ""),
	    controllerFound: Boolean(controller),
	    activePlaybackLoops: activeLoop && !activeLoop.disposed ? 1 : 0,
	    activeReaders: activeLoop?.readerActive ? 1 : 0,
	    playbackReaderCreatedCount: Number(session?.playbackReaderCreatedCount || activeLoop?.playbackReaderCreatedCount || 0),
	    playbackReaderDoneCount: Number(session?.playbackReaderDoneCount || activeLoop?.playbackReaderDoneCount || 0),
	    playbackReaderAbortCount: Number(session?.playbackReaderAbortCount || activeLoop?.playbackReaderAbortCount || 0),
	    playbackReaderErrorCount: Number(session?.playbackReaderErrorCount || activeLoop?.playbackReaderErrorCount || 0),
	    playbackChunksReceived: Number(session?.playbackChunksReceived || activeLoop?.playbackChunksReceived || 0),
	    playbackFramesParsed: Number(session?.playbackFramesParsed || activeLoop?.playbackFramesParsed || 0),
	    playbackFramesCommitted: Number(session?.playbackFramesCommitted || activeLoop?.playbackFramesCommitted || 0),
	    playbackReaderLastDoneReason: cleanText(session?.playbackReaderLastDoneReason || activeLoop?.playbackReaderLastDoneReason, ""),
	    playbackReaderLifetimeMs: Number(session?.playbackReaderLifetimeMs || activeLoop?.playbackReaderLifetimeMs || 0),
	    ...extra,
	  };
	}

function traceWisCameraPlayPause(event, streamId = "", extra = {}) {
  const priority = {};
  [
    "control",
    "action",
    "reason",
    "rejectionReason",
    "clickedControlStreamId",
    "controllerStreamId",
    "visibleImageStreamId",
    "ownerBefore",
    "modeBefore",
    "pausedBefore",
    "iconBefore",
    "ownerAfter",
    "modeAfter",
    "pausedAfter",
    "iconAfter",
    "generation",
    "expectedAction",
    "expectedIcon",
    "disabledReason",
    "controllerFound",
    "mismatch",
  ].forEach((key) => {
    if (Object.prototype.hasOwnProperty.call(extra, key)) priority[key] = extra[key];
  });
  return traceWisCameraBoundary(event, { ...priority, ...wisCameraPlaybackTracePayload(streamId, extra) });
}

function dumpWisCameraTrace(streamId = "") {
  const key = wisCameraCurrentTraceStreamId(streamId);
  const trace = Array.isArray(window.__WIS_CAMERA_TRACE_ALL__)
    ? window.__WIS_CAMERA_TRACE_ALL__
    : (Array.isArray(window.__WIS_CAMERA_TRACE__) ? window.__WIS_CAMERA_TRACE__ : []);
  const session = recordedWisCameraSession(key);
  const activeLoop = key ? wisCameraActivePlaybackLoop(state, key) : null;
  const perf = key ? (sampleWisCameraPerf(state, key, {}, null, { force: true }) || {}) : {};
  const events = trace
    .map((entry) => cloneWisCameraTraceValue(entry))
    .filter((entry) => entry && typeof entry === "object" && !Array.isArray(entry));
  const last300Events = events.slice(-300);
  const eventBelongsToCurrentStream = (entry) => {
    const eventStreamId = wisCameraTraceEventStreamId(entry);
    return !key || !eventStreamId || eventStreamId === key;
  };
  const committedRecordedFrames = Array.from(new Set(events
    .filter((entry) => (
      eventBelongsToCurrentStream(entry)
      && ((entry.event === "camera.visual.frame_commit" && cleanText(entry.mode, "recorded") === "recorded" && entry.decodedOk !== false)
      || entry.event === "recorded.commit.accepted"
      )
    ))
    .map((entry) => Number(entry.frameTimestampMs || entry.visibleFrameMs || entry.timestampMs || 0))
    .filter((timestampMs) => Number.isFinite(timestampMs) && timestampMs > 0)))
    .sort((a, b) => a - b);
  const controlButtonEvents = events
    .filter((entry) => cleanText(entry.event, "").startsWith("controls.")
      || entry.event === "playback.control.clicked"
      || cleanText(entry.event, "").startsWith("playback.pause")
      || cleanText(entry.event, "").startsWith("playback.resume"))
    .slice(-80);
  const playbackFetchEvents = events
    .filter((entry) => [
      "archive.fetch.started",
      "archive.fetch.result",
      "camera.media.playback_stream.start",
      "camera.media.playback_stream.first_packet",
      "camera.media.playback_stream.abort",
	      "camera.media.playback_stream.restart",
	      "camera.media.playback_stream.stall_suspected",
	      "camera.media.playback_stream.duplicate_ignored",
	      "camera.media.playback_reader.created",
	      "camera.media.playback_reader.read_started",
	      "camera.media.playback_reader.read_result",
	      "camera.media.playback_reader.done",
	      "camera.media.playback_reader.abort",
	      "camera.media.playback_reader.error",
	      "camera.media.playback_frame.parsed",
	      "camera.server.seek.requested",
      "camera.server.first_frame.received",
      "camera.server.first_frame.offset_from_seek",
      "camera.server.stream.gap_suspected",
      "camera.server.stream.stall_suspected",
      "camera.server.stream.restart",
    ].includes(cleanText(entry.event, "")))
    .slice(-120);
  const timelineSeekEvents = events
    .filter((entry) => [
      "timeline.pointer",
      "timeline.commit",
      "timeline.seek.persisted",
      "timeline.seek.overwritten",
      "timeline.pending.seek.applied",
      "timeline.app.setFrame",
      "camera.seekRequested",
      "camera.seekRequested.entrypoint",
      "camera.seekRequested.state",
      "archive.frame.resolved",
      "recorded.render.entrypoint",
      "recorded.render.rejected",
    ].includes(cleanText(entry.event, "")))
    .slice(-120);
  const ownerTransitions = events
    .filter((entry) => entry.event === "ownerMutation" || entry.event === "camera.playback.transition")
    .slice(-80);
  const countMatching = (predicate) => events.reduce((count, entry) => count + (predicate(entry) ? 1 : 0), 0);
  const current = wisCameraPlaybackTracePayload(key);
  const focusedSlot = wisFocusedCameraSlot() || "";
  const focusedCamera = focusedSlot ? wisCameraConfigForSlot(focusedSlot) : {};
  const activeCameraStreamId = focusedSlot ? wisCameraQualityStreamId(focusedSlot, focusedCamera) : "";
  const visibleImages = wisCameraVisibleImagesForTrace();
  const visibleImage = visibleImages.find((image) => image.isVisible && image.streamId === key)
    || visibleImages.find((image) => image.isVisible && image.streamId === activeCameraStreamId)
    || visibleImages.find((image) => image.isVisible)
    || visibleImages[0]
    || null;
  const clickedTimelineEvent = wisCameraLatestTraceEvent(events, (entry) => ["timeline.commit", "timeline.pointer"].includes(cleanText(entry.event, "")));
  const clickedControlEvent = wisCameraLatestTraceEvent(controlButtonEvents, (entry) => cleanText(entry.event, "").startsWith("controls.")
    || cleanText(entry.event, "") === "playback.control.clicked");
  const resolvedFrameEvent = wisCameraLatestTraceEvent(events, (entry) => {
    if (!eventBelongsToCurrentStream(entry)) return false;
    if (wisCameraTraceHasNumber(entry.resolvedFrameTimestampMs) || wisCameraTraceHasNumber(entry.resolvedTimestampMs)) return true;
    return ["archive.frame.resolved", "camera.seekRequested", "camera.seekRequested.entrypoint", "camera.seekRequested.state", "recorded.render.entrypoint"]
      .includes(cleanText(entry.event, ""))
      && wisCameraTraceHasNumber(entry.frameTimestampMs);
  });
  const playbackUrlEvent = wisCameraLatestTraceEvent(events, (entry) => eventBelongsToCurrentStream(entry)
    && cleanText(entry.playbackUrl, "").includes("/camera/push-playback"));
  const playbackUrlDetails = wisCameraPlaybackUrlParts(playbackUrlEvent?.playbackUrl || "");
  const playPauseButton = document.querySelector?.(`.wis-camera-timeline-controls-row [data-wis-camera-control="play-pause"][data-wis-camera-stream-id="${CSS.escape(key)}"]`)
    || document.querySelector?.(".wis-camera-timeline-controls-row [data-wis-camera-control='play-pause']")
    || null;
  return cloneWisCameraTraceValue({
    build: WIS_CAMERA_ARTIFACT_BUILD,
    currentStreamId: key,
    activeCameraSlot: focusedSlot,
    appOwnerState: current.appOwnerState,
    controllerOwnerState: current.controllerOwnerState,
    controllerMode: current.controllerMode,
    currentOwner: current.owner,
    currentMode: current.currentMode,
    paused: current.paused,
    playbackRate: current.playbackRate,
    requestedTimestampMs: current.requestedTimestampMs,
    persistedSeekTimestampMs: current.persistedSeekTimestampMs,
    resolvedFrameTimestampMs: wisCameraTraceNumber(
      resolvedFrameEvent?.resolvedFrameTimestampMs,
      resolvedFrameEvent?.resolvedTimestampMs,
      resolvedFrameEvent?.frameTimestampMs
    ),
    mediaAnchorMs: current.mediaAnchorMs,
    wallAnchorMs: current.wallAnchorMs,
	    playbackClockMs: current.playbackClockMs,
	    visibleFrameMs: current.visibleFrameMs || Number(visibleImage?.frameMs || 0),
    clickedTimelineStreamId: wisCameraTraceEventStreamId(clickedTimelineEvent),
    clickedControlStreamId: wisCameraTraceEventStreamId(clickedControlEvent),
    controllerStreamId: wisCameraControllerStreamIdForTrace(key),
    activeCameraStreamId,
    visibleImageStreamId: cleanText(visibleImage?.streamId, ""),
    playbackUrl: playbackUrlDetails.playbackUrl,
    playbackUrlFromMs: playbackUrlDetails.playbackUrlFromMs,
    playbackUrlFollow: playbackUrlDetails.playbackUrlFollow,
	    activePlaybackLoops: Number(perf.activePlaybackLoops ?? current.activePlaybackLoops ?? (activeLoop && !activeLoop.disposed ? 1 : 0)),
	    activeReaders: Number(perf.activeReaders ?? current.activeReaders ?? (activeLoop?.readerActive ? 1 : 0)),
	    playbackReaderCreatedCount: Number(perf.playbackReaderCreatedCount ?? current.playbackReaderCreatedCount ?? 0),
	    playbackReaderDoneCount: Number(perf.playbackReaderDoneCount ?? current.playbackReaderDoneCount ?? 0),
	    playbackReaderAbortCount: Number(perf.playbackReaderAbortCount ?? current.playbackReaderAbortCount ?? 0),
	    playbackReaderErrorCount: Number(perf.playbackReaderErrorCount ?? current.playbackReaderErrorCount ?? 0),
	    playbackChunksReceived: Number(perf.playbackChunksReceived ?? current.playbackChunksReceived ?? 0),
	    playbackFramesParsed: Number(perf.playbackFramesParsed ?? current.playbackFramesParsed ?? 0),
	    playbackFramesCommitted: Number(perf.playbackFramesCommitted ?? current.playbackFramesCommitted ?? committedRecordedFrames.length),
	    playbackReaderLastDoneReason: cleanText(perf.playbackReaderLastDoneReason || current.playbackReaderLastDoneReason, ""),
	    playbackReaderLifetimeMs: Number(perf.playbackReaderLifetimeMs ?? current.playbackReaderLifetimeMs ?? 0),
	    committedRecordedFrameCount: committedRecordedFrames.length,
    committedRecordedFrames,
    holdAheadFrameCount: countMatching((entry) => cleanText(entry.reason, "").includes("hold-ahead") || cleanText(entry.event, "").includes("hold_ahead")),
    duplicateFrameCount: countMatching((entry) => cleanText(entry.event, "").includes("duplicate") || cleanText(entry.reason, "").includes("duplicate")),
    staleRejectCount: countMatching((entry) => cleanText(entry.event, "").includes("stale") || cleanText(entry.event, "").includes("rejected") || cleanText(entry.reason, "").includes("stale")),
    liveBlockedCount: countMatching((entry) => cleanText(entry.event, "").includes("blocked_by_recorded_owner") || entry.decision === "BLOCKED"),
    playButtonClicks: countMatching((entry) => (entry.event === "playback.control.clicked" && entry.control === "play") || (entry.event === "controls.playpause.click" && entry.action === "play")),
    pauseButtonClicks: countMatching((entry) => (entry.event === "playback.control.clicked" && entry.control === "pause") || (entry.event === "controls.playpause.click" && entry.action === "pause")),
    resumeButtonClicks: countMatching((entry) => cleanText(entry.event, "").startsWith("playback.resume.") || (entry.event === "playback.control.clicked" && entry.control === "play")),
    playPauseButton: wisCameraControlTargetSummary(playPauseButton),
    controlButtonEvents,
    visibleImages,
    playbackFetchEvents,
    timelineSeekEvents,
    ownerTransitions,
    last300Events,
  });
}

function installWisCameraTraceDumpHelper() {
  try {
    window.dumpWisCameraTrace = (streamId = "") => dumpWisCameraTrace(streamId);
  } catch {
    // Console helper installation is diagnostic only.
  }
}

installWisCameraTraceDumpHelper();

async function copyWisCameraTraceDump(streamId = "") {
  const key = wisCameraCurrentTraceStreamId(streamId);
  const dump = dumpWisCameraTrace(key);
  const text = JSON.stringify(dump, null, 2);
  try {
    if (!navigator.clipboard?.writeText) throw new Error("clipboard-writeText-unavailable");
    await navigator.clipboard.writeText(text);
    setWisCameraNotice(key, "Camera trace copied", "success");
    traceWisCameraBoundary("controls.copytrace.copied", wisCameraPlaybackTracePayload(key, {
      control: "copy-trace",
      action: "copy",
      reason: "debug-action",
      dumpBuild: dump.build,
      eventCount: Array.isArray(dump.last300Events) ? dump.last300Events.length : 0,
    }));
  } catch (error) {
    setWisCameraNotice(key, "Camera trace available in console", "warn");
    traceWisCameraBoundary("controls.copytrace.copy_failed", wisCameraPlaybackTracePayload(key, {
      control: "copy-trace",
      action: "copy",
      reason: "debug-action",
      error: error?.message || String(error),
    }));
    try {
      console.info("WIS camera trace dump", dump);
    } catch {
      // Console diagnostics are best effort.
    }
  }
  return dump;
}

function wisCameraPlaybackOwnerMode(session = null, fallback = "live") {
  if (!session || typeof session !== "object") return cleanText(fallback, "live");
  const status = cleanText(session.status || session.state, "");
  if (["seeking", "buffering", "loading"].includes(status)) return "seeking";
  if (session.mode === "recorded") return "recorded";
  if (status === "error") return "error";
  return cleanText(fallback, "live");
}

function wisCameraPlaybackOwnerState(session = null, fallback = WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE) {
  if (session?.ownerState || session?.timelineOwnerState) {
    const explicit = cleanText(session.ownerState || session.timelineOwnerState, "").toUpperCase();
    if (Object.values(WIS_CAMERA_TIMELINE_OWNER_STATES).includes(explicit)) return explicit;
  }
  const status = cleanText(session?.status || session?.state, "");
  if (session?.mode === "recorded") {
    if (["seeking", "buffering", "loading"].includes(status)) return WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING;
    if (["paused", "ended", "gap", "stalled", "error"].includes(status)) return WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PAUSED;
    return WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PLAYING;
  }
  const fallbackState = cleanText(fallback, WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE).toUpperCase();
  return Object.values(WIS_CAMERA_TIMELINE_OWNER_STATES).includes(fallbackState)
    ? fallbackState
    : WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE;
}

function wisCameraRecordedOwnsStream(streamId) {
  const key = cleanText(streamId, "");
  return Boolean(key && wisCameraRecordedOwnsTimelineContract(state, key));
}

function wisCameraLoopOwnerSnapshot(streamId, slot = "") {
  const key = cleanText(streamId, "");
  const cleanSlot = cleanText(slot, key);
  const playbackLoop = key ? wisCameraActivePlaybackLoop(state, key) : null;
  const liveTimer = (key && state.wisCameraTimers.get(key)) || (cleanSlot && state.wisCameraTimers.get(cleanSlot)) || null;
  const recordedSession = recordedWisCameraSession(key);
  const recordedOwns = wisCameraRecordedOwnsStream(key);
  return {
    streamId: key,
    ownerState: wisCameraTimelineOwnerStateContract(state, key),
    liveLoopActiveCount: liveTimer && !recordedOwns ? 1 : 0,
    liveLoopIgnoredCount: liveTimer && recordedOwns ? 1 : 0,
    recordedLoopActiveCount: playbackLoop && !playbackLoop.disposed ? 1 : 0,
    activeGeneration: Number(recordedSession?.generation || playbackLoop?.generation || 0),
    activeReaders: playbackLoop?.readerActive ? 1 : 0,
    recordedSessionId: cleanText(recordedSession?.id, ""),
  };
}

function logWisCameraLoopOwner(streamId, reason = "", slot = "") {
  logWisCameraMediaEvent("camera.loop.owner", {
    ...wisCameraLoopOwnerSnapshot(streamId, slot),
    reason,
  }, { always: true, sampleMs: 500 });
}

function enterWisCameraRecordedMode(streamId, frame = null, options = {}) {
  const key = cleanText(streamId, "");
  if (!key) return null;
  const slot = cleanText(options.slot, wisFocusedCameraSlot() || key);
	  const existingSession = recordedWisCameraSession(key);
	  const previousMode = wisCameraPlaybackOwnerMode(existingSession, wisCameraTimelineMode(key));
	  const previousOwnerState = wisCameraPlaybackOwnerState(existingSession);
	  if (wisCameraTimelineMode(key) !== "recorded") state.wisCameraTimelineModes.set(key, "recorded");
	  const liveLoopSnapshotBeforeStop = wisCameraLoopOwnerSnapshot(key, slot);
	  stopWisCameraTimer(slot);
	  stopWisCameraTimer(key);
  const timestampMs = Number(
    options.timestampMs
      ?? options.targetTimeMs
      ?? frame?.seek_target_ms
      ?? frame?.seekTargetMs
      ?? frame?.timestamp_ms
      ?? frame?.timestampMs
      ?? 0
  );
	  setWisCameraTimelineOwnerState(state, key, WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING, {
	    generation: Number(options.generation || existingSession?.generation || 0),
	    sessionId: cleanText(existingSession?.id, ""),
	    reason: cleanText(options.reason, "timeline-seek"),
	    caller: "enterWisCameraRecordedMode",
	  });
	  traceWisCameraBoundary("ownerMutation", {
	    streamId: key,
	    previousOwner: previousOwnerState,
	    nextOwner: WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING,
	    transition: `${previousOwnerState} -> ${WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING}`,
	    reason: cleanText(options.reason, "timeline-seek"),
	    caller: "enterWisCameraRecordedMode",
	    generation: Number(options.generation || existingSession?.generation || 0),
	    frameLayerOwner: "recorded",
	    ...wisCameraLoopOwnerSnapshot(key, slot),
	  }, { stack: true });
	  traceWisCameraBoundary("live.commit", {
	    decision: "BLOCKED",
	    streamId: key,
	    ownerAtCommit: WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING,
	    generation: Number(options.generation || existingSession?.generation || 0),
	    frameTimestampMs: Number.isFinite(timestampMs) ? timestampMs : 0,
	    frameSource: "live-owner-fence",
	    reason: "recorded-owner-fence",
	    liveLoopActiveBeforeStop: Number(liveLoopSnapshotBeforeStop.liveLoopActiveCount || 0),
	    liveLoopIgnoredBeforeStop: Number(liveLoopSnapshotBeforeStop.liveLoopIgnoredCount || 0),
	    ...wisCameraLoopOwnerSnapshot(key, slot),
	  });
  logWisCameraMediaEvent("camera.playback.transition", {
    streamId: key,
    fromMode: previousMode,
    toMode: "seeking",
    fromOwnerState: previousOwnerState,
    toOwnerState: WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING,
    ownerStateTransition: `${previousOwnerState} -> ${WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING}`,
    frameLayerOwner: "recorded",
    reason: cleanText(options.reason, "timeline-seek"),
    timestampMs: Number.isFinite(timestampMs) ? timestampMs : 0,
    generation: Number(options.generation || existingSession?.generation || 0),
  }, { always: true });
  logWisCameraMediaEvent("camera.timeline.seek", {
    streamId: key,
    targetTimestampMs: Number.isFinite(timestampMs) ? timestampMs : 0,
    resolvedTimestampMs: Number(frame?.timestamp_ms || frame?.timestampMs || timestampMs || 0),
    ratio: Number(options.ratio),
    segmentId: cleanText(frame?.id, ""),
    segmentUrl: cleanText(frame?.url, ""),
    generation: Number(options.generation || existingSession?.generation || 0),
    reason: cleanText(options.reason, "timeline-seek"),
  }, { always: true });
  logWisCameraLoopOwner(key, "enter-recorded", slot);
  return existingSession;
}

function wisCameraImageHasRecordedOwner(image) {
  return image?.dataset?.wisMediaOwner === "recorded-playback";
}

function blockLiveWisCameraImageWrite(image, streamId, reason = "live-write") {
  const activeSession = recordedWisCameraSession(streamId);
  if (!wisCameraImageHasRecordedOwner(image) && !activeSession && !wisCameraRecordedOwnsStream(streamId)) return false;
  traceWisCameraBoundary("live.commit", {
    decision: "BLOCKED",
    streamId,
    ownerAtCommit: wisCameraTimelineOwnerStateContract(state, streamId),
    generation: Number(activeSession?.generation || image?.dataset?.wisMediaGeneration || 0),
    frameTimestampMs: Number(image?.dataset?.wisPlaybackFrameMs || 0),
    frameSource: image?.dataset?.wisPlaybackStream || "live",
    imageOwner: image?.dataset?.wisMediaOwner || "",
    reason,
    ...wisCameraLoopOwnerSnapshot(streamId),
  });
  logWisCameraMediaEvent("camera.media.live.write.blocked_by_recorded_owner", {
    streamId,
    generation: Number(activeSession?.generation || image?.dataset?.wisMediaGeneration || 0),
    imageOwner: image?.dataset?.wisMediaOwner,
    reason,
    sessionId: cleanText(activeSession?.id, ""),
  }, { sampleMs: 1000 });
  logWisCameraMediaEvent("camera.timeline.live_update.blocked_by_recorded_owner", {
    streamId,
    generation: Number(activeSession?.generation || image?.dataset?.wisMediaGeneration || 0),
    ownerState: wisCameraTimelineOwnerStateContract(state, streamId),
    reason,
    sessionId: cleanText(activeSession?.id, ""),
  }, { always: true, sampleMs: 1000 });
  return true;
}

function wisCameraPlaybackController(streamId) {
  const key = cleanText(streamId, "");
  if (!key) return null;
  if (!(state.wisCameraArtifactControllers instanceof Map)) state.wisCameraArtifactControllers = new Map();
  let controller = state.wisCameraArtifactControllers.get(key);
  if (!controller) {
    controller = createCameraArtifactController({
      artifactId: key,
      documentId: wisSurfaceState()?.document?.id || "main",
      env: window,
      diagnostics: true,
      getTimelineModel: () => wisCameraTimelineForStream(key),
      getPlaybackState: () => recordedWisCameraSession(key),
      findSegmentForTime: async (targetTimeMs, context = {}) => wisCameraSegmentForTarget(key, targetTimeMs, context),
	      onSeekPending: (context = {}) => {
	        const slot = wisFocusedCameraSlot() || "cam-1";
	        const segment = wisCameraSegmentForTarget(key, context.targetTimeMs || context.timestampMs, {
	          requestedFrame: context.requestedFrame,
	        });
	        traceWisCameraBoundary("camera.seekRequested.entrypoint", {
	          functionName: "wisCameraPlaybackController.onSeekPending",
	          streamId: key,
	          requestedTimestampMs: Number(context.targetTimeMs || context.timestampMs || 0),
	          archiveWindowStartMs: Number(state.wisCameraTimeline?.availableRange?.start_ms ?? state.wisCameraTimeline?.available_range?.start_ms ?? state.wisCameraTimeline?.range?.start_ms ?? 0),
	          archiveWindowEndMs: Number(state.wisCameraTimeline?.availableRange?.end_ms ?? state.wisCameraTimeline?.available_range?.end_ms ?? state.wisCameraTimeline?.range?.end_ms ?? 0),
	          resolvedTimestampMs: Number(segment?.timestamp_ms || segment?.timestampMs || 0),
	          recordedPlaybackPossible: Boolean(segment?.id && segment?.url),
	          generation: Number(context.generation || 0),
	          ownerBeforeSeek: wisCameraTimelineOwnerStateContract(state, key),
	          reason: context.reason || "timeline-seek",
	        });
	        if (!segment?.id || !segment?.url) return null;
	        stopWisCameraTimer(slot);
        stopWisCameraTimer(key);
        state.wisCameraTimelineSelections.set(key, segment);
        const preservePaused = Boolean(recordedWisCameraSession(key)?.userPaused);
        const session = startWisCameraRecordedSession(key, segment, {
          explicitSeek: true,
          restart: true,
          generation: context.generation,
          reason: context.reason || "timeline-seek",
          timestampMs: context.targetTimeMs || context.timestampMs,
          ratio: context.target?.ratio,
          paused: preservePaused,
        });
        if (session) {
          session.status = "seeking";
          session.state = "seeking";
          session.ownerState = WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING;
          session.timelineOwnerState = WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_SEEKING;
          session.frameOwner = "recorded";
          session.timelineOwner = "recorded";
          session.clockPaused = true;
          session.userPaused = preservePaused;
          session.currentWallTime = Number(context.targetTimeMs || segment.seek_target_ms || segment.timestamp_ms || session.currentWallTime || 0);
          session.updatedAt = Date.now();
        }
        logWisCameraLoopOwner(key, "seek-pending", slot);
        if (!renderWisCameraPlaybackInPlace(key, segment, { force: true, generation: context.generation })) renderWis();
        updateWisCameraRecordedPlaybackUi(key, { currentMs: session?.currentWallTime, timeline: true });
        return segment;
      },
      loadSegment: async (segment, context = {}) => {
        const activeSession = recordedWisCameraSession(key);
        if (
          activeSession
          && Number(activeSession.generation || 0) === Number(context.generation || 0)
          && wisCameraTimelineFramePlaybackKey(activeSession.requestedFrame || activeSession.frame) === wisCameraTimelineFramePlaybackKey(segment)
        ) {
          state.wisCameraTimelineSelections.set(key, segment);
          return { ...segment, playbackClockSource: "media" };
        }
        setWisCameraTimelineFrame(key, segment, {
          force: context.source === "user",
          fromController: true,
          restartSession: true,
          source: context.source || "programmatic",
          reason: context.reason || "controller-seek",
          generation: context.generation,
        });
        return { ...segment, playbackClockSource: "media" };
      },
      drawFrameAt: (timestampMs) => {
        updateWisCameraRecordedPlaybackUi(key, { currentMs: timestampMs });
      },
      updateTimelineVisualOnly: (timestampMs) => {
        updateWisCameraRecordedPlaybackUi(key, { currentMs: timestampMs, timelineOnly: true });
        const timeline = wisCameraTimelineForStream(key);
        const frames = Array.isArray(timeline.frames) ? timeline.frames : [];
        const { visibleStart, visibleEnd } = wisCameraTimelineTimeWindow(timeline, frames, { playbackPosition: timestampMs });
        return visibleEnd > visibleStart ? clamp(((timestampMs - visibleStart) / (visibleEnd - visibleStart)) * 100, 0, 100) : null;
      },
      previewTimelineTarget: (target = {}, detail = {}) => {
        const footer = widgetById("wis")?.querySelector?.(".wis-camera-timeline");
        const scrubber = footer?.querySelector?.(`.wis-camera-timeline-scrubber[data-stream-id="${CSS.escape(key)}"]`);
        const title = footer?.querySelector?.(".wis-camera-timeline-title");
        const timeline = wisCameraTimelineForStream(key);
        const frames = Array.isArray(timeline.frames) ? timeline.frames : [];
        const frame = target.snappedFrame || wisCameraTimelineFrameClosestToTime(frames, target.targetTime, target);
        const index = frame ? Math.max(0, frames.findIndex((candidate) => cleanText(candidate?.id, "") === cleanText(frame.id, ""))) : -1;
        const maxIndex = Math.max(0, frames.length - 1);
        const displayTimeMs = Number(target.targetTime ?? frame?.timestamp_ms ?? frame?.timestampMs);
        const progress = Number.isFinite(displayTimeMs) && target.visibleEnd > target.visibleStart
          ? clamp(((displayTimeMs - target.visibleStart) / (target.visibleEnd - target.visibleStart)) * 100, 0, 100)
          : (maxIndex > 0 && index >= 0 ? (index / maxIndex) * 100 : 100);
        scrubber?.style?.setProperty(detail.visualOnly ? "--wis-camera-timeline-preview" : "--wis-camera-timeline-progress", `${progress}%`);
        if (detail.visualOnly && scrubber?.dataset) scrubber.dataset.wisTimelinePreviewing = "1";
        if (scrubber && index >= 0) scrubber.setAttribute("aria-valuenow", String(index));
        const labelFrame = Number.isFinite(displayTimeMs) ? { ...(frame || {}), timestamp_ms: displayTimeMs } : frame;
        if (scrubber && labelFrame) scrubber.setAttribute("aria-valuetext", cameraTimelineFrameLabel(labelFrame));
        if (title && labelFrame) title.textContent = `Point ${cameraTimelineFrameLabel(labelFrame)}`;
      },
      resetTimelinePreview: () => updateWisCameraRecordedPlaybackUi(key),
      onTimelineLoadNeeded: (target = {}, context = {}) => {
        setPendingWisCameraTimelineSeek(key, target.visibleEnd > target.visibleStart
          ? {
            ratio: target.ratio,
            targetTime: target.targetTime,
            visibleStart: target.visibleStart,
            visibleEnd: target.visibleEnd,
            retentionStart: target.retentionStart,
            retentionEnd: target.retentionEnd,
            playbackPosition: target.playbackPosition,
          }
          : target.ratio, context.mode || wisCameraTimelineMode(key));
        const timeline = wisCameraTimelineForStream(key);
        if (!timeline.loading) void loadWisCameraTimeline(key, context.reason || "timeline-interaction", context.mode || wisCameraTimelineMode(key));
      },
      recordEvent: (type, payload = {}) => {
        if (type === "camera.timeline.programmatic.sync") return;
        recordUserEvent(`wis.${type}`, {
          source: "wis-camera-artifact",
          target: `wis:${key}`,
          summary: type,
          data: { slot: key, ...payload },
        });
      },
    });
    state.wisCameraArtifactControllers.set(key, controller);
  }
  const snapshot = wisSurfaceState();
  controller.configure({
    artifactId: state.wisActiveArtifact?.id || key,
    documentId: snapshot?.document?.id || "main",
    timeline: wisCameraTimelineForStream(key),
    frames: wisCameraTimelineForStream(key).frames || [],
    mode: wisCameraTimelineMode(key),
  });
  return controller;
}

function stopWisCameraPlaybackController(streamId, reason = "stop") {
  const key = cleanText(streamId, "");
  const controller = key && state.wisCameraArtifactControllers instanceof Map ? state.wisCameraArtifactControllers.get(key) : null;
  controller?.cleanup?.(reason);
}

function setWisCameraTextContent(element, text = "") {
  if (!element) return;
  const nextText = String(text ?? "");
  if (element.textContent !== nextText) element.textContent = nextText;
}

function stopWisCameraPlaybackStream(streamId) {
  const key = cleanText(streamId, "");
  if (!key) return;
  const session = recordedWisCameraSession(key);
  stopWisCameraPlaybackController(key, "playback-stream-stop");
  stopWisCameraPlaybackState(state, key);
  releaseMediaStreamWriter(key, { kind: "recorded-playback", generation: session?.generation });
}

function toggleWisCameraRecordedPlayback(camera = {}, event = null) {
  const button = event?.currentTarget?.closest?.("[data-wis-camera-control='play-pause']")
    || event?.target?.closest?.("[data-wis-camera-control='play-pause']")
    || null;
  const targetSummary = wisCameraControlTargetSummary(button || event?.target || null);
  const slot = cleanText(targetSummary?.slot || camera._slot, wisFocusedCameraSlot() || "cam-1");
  const streamId = cleanText(targetSummary?.streamId, wisCameraQualityStreamId(slot, camera));
  const controller = streamId ? wisCameraPlaybackController(streamId) : null;
  let beforeState = wisCameraPlayPauseStateForStream(streamId, { button, controller });
  const renderForCurrentState = () => {
    const currentCamera = wisCameraConfigForSlot(slot) || camera || {};
    if (wisCameraIsPushConfig(currentCamera)) renderWisCameraTimelineFooter({ ...currentCamera, _slot: slot });
  };
  const currentButton = () => widgetById("wis")?.querySelector?.(
    `[data-wis-camera-control="play-pause"][data-wis-camera-stream-id="${CSS.escape(streamId)}"]`
  ) || null;
  const resolveAfterState = () => wisCameraPlayPauseStateForStream(streamId, {
    button: currentButton() || button,
    controller,
  });
  const traceWithState = (eventName, resolved, extra = {}) => traceWisCameraPlayPause(eventName, streamId, wisCameraPlayPauseTraceContext(resolved, {
    control: "play-pause",
    slot,
    target: targetSummary,
    focusedSlot: wisFocusedCameraSlot() || "",
    timelineStreamId: cleanText(state.wisCameraTimeline?.streamId, ""),
    sessionKeys: Array.from(state.wisCameraRecordedSessions?.keys?.() || []).map((key) => cleanText(key, "")).filter(Boolean).slice(-10),
    ...extra,
  }));
  traceWithState("controls.playpause.resolvedTarget", beforeState);
  traceWithState("controls.playpause.controllerFound", beforeState, {
    controllerFound: Boolean(controller),
  });
  traceWithState("controls.playpause.uiStateMismatch", beforeState, {
    mismatch: beforeState.domMismatch,
    domAction: beforeState.domAction,
    domIcon: beforeState.domIcon,
    expectedAction: beforeState.action,
    expectedIcon: beforeState.icon,
  });
  traceWithState("controls.playpause.beforeState", beforeState);
  traceWisCameraBoundary("playback.control.clicked", {
    ...wisCameraPlaybackTracePayload(streamId, wisCameraPlayPauseTraceContext(beforeState, {
      control: "play-pause",
      action: beforeState.action,
      slot,
    })),
    control: beforeState.action,
  });
  if (beforeState.domMismatch) {
    renderForCurrentState();
    const afterState = resolveAfterState();
    const reason = "ui-state-mismatch-corrected";
    setWisCameraNotice(streamId, "Play/Pause state refreshed", "warn", 2400);
    traceWithState(`playback.${beforeState.action === "pause" ? "pause" : "resume"}.rejected`, beforeState, {
      rejectionReason: reason,
      reason,
      afterState,
    });
    traceWithState("controls.playpause.afterState", beforeState, {
      rejectionReason: reason,
      reason,
      afterState,
    });
    return;
  }
  if (beforeState.disabledReason) {
    const reason = beforeState.disabledReason;
    setWisCameraNotice(streamId, reason === "not-recorded-mode" ? "Play/Pause unavailable: not in recorded mode" : "Play/Pause unavailable", "warn", 3200);
    renderForCurrentState();
    const afterState = resolveAfterState();
    traceWithState("playback.resume.rejected", beforeState, {
      rejectionReason: reason,
      reason,
      afterState,
    });
    traceWithState("controls.playpause.afterState", beforeState, {
      rejectionReason: reason,
      reason,
      afterState,
    });
    return;
  }
  const session = beforeState.session;
  if (beforeState.action === "play") {
    traceWithState("playback.resume.called", beforeState, {
      reason: "timeline-play-button",
    });
    const resumed = resumeWisCameraPlaybackState(state, streamId, {
      sessionId: session?.id,
      generation: session?.generation,
      reason: "timeline-play-button",
    });
    const controllerStarted = controller?.resumePlayback?.({ source: "control", reason: "timeline-play-button", generation: session?.generation });
    renderForCurrentState();
    const afterState = resolveAfterState();
    if (!resumed) {
      const reason = "state-resume-returned-null";
      traceWithState("playback.resume.rejected", beforeState, {
        rejectionReason: reason,
        reason,
        controllerStarted: Boolean(controllerStarted),
        afterState,
      });
    } else {
      traceWithState("playback.resume.started", beforeState, {
        controllerStarted: Boolean(controllerStarted),
        afterState,
      });
    }
    if (!wisCameraActivePlaybackLoop(state, streamId) && resumed?.frame) {
      renderWisCameraPlaybackInPlace(streamId, resumed.frame, { force: true, generation: resumed.generation });
    }
    traceWithState("controls.playpause.afterState", beforeState, { afterState });
    return;
  }
  traceWithState("playback.pause.called", beforeState, {
    reason: "timeline-pause-button",
  });
  const pausedSession = pauseWisCameraPlaybackState(state, streamId, {
    sessionId: session?.id,
    generation: session?.generation,
    reason: "timeline-pause-button",
  });
  const controllerPaused = controller?.pausePlayback?.({ source: "control", reason: "timeline-pause-button", generation: session?.generation });
  renderForCurrentState();
  const afterState = resolveAfterState();
  if (!pausedSession) {
    const reason = "state-pause-returned-null";
    traceWithState("playback.pause.rejected", beforeState, {
      rejectionReason: reason,
      reason,
      controllerPaused: Boolean(controllerPaused),
      afterState,
    });
  } else {
    traceWithState("playback.pause.applied", beforeState, {
      controllerPaused: Boolean(controllerPaused),
      afterState,
    });
  }
  traceWithState("controls.playpause.afterState", beforeState, { afterState });
}

function wisMonotonicNow() {
  return wisCameraMonotonicNow();
}

function recordedWisCameraSession(streamId) {
  const key = cleanText(streamId, "");
  const session = key ? wisCameraPlaybackStateContract(state, key) : null;
  return session?.mode === "recorded" ? session : null;
}

function wisCameraRecordedClockMs(session = null, nowMs = wisMonotonicNow()) {
  return wisCameraPlaybackClockMsContract(session, nowMs);
}

function stopWisCameraRecordedClock(streamId) {
  const key = cleanText(streamId, "");
  const timer = key ? state.wisCameraRecordedTickTimers.get(key) : null;
  if (!timer) return;
  if (timer && typeof timer === "object" && timer.kind === "wis-camera-scheduler-task") {
    stopWisCameraTimer(`recorded-clock:${key}`);
  } else {
    clearInterval(timer);
    clearTimeout(timer);
  }
  state.wisCameraRecordedTickTimers.delete(key);
}

function syncWisCameraPlayPauseButtonForSession(streamId, session = null) {
  const key = cleanText(streamId, "");
  if (!key) return false;
  const widget = widgetById("wis");
  const footer = widget?.querySelector?.(".wis-camera-timeline");
  const button = footer?.querySelector?.(`[data-wis-camera-control="play-pause"][data-wis-camera-stream-id="${CSS.escape(key)}"]`);
  if (!button) return false;
  const resolved = wisCameraPlayPauseStateForStream(key, { button, session });
  const expectedAction = resolved.action;
  const expectedTitle = resolved.title;
  const expectedPressed = resolved.expectedPressed;
  const expectedIcon = resolved.icon;
  const expectedDisabledReason = resolved.disabledReason;
  const currentAction = cleanText(button.dataset?.wisCameraAction, "");
  const currentIcon = cleanText(button.dataset?.icon, "");
  const currentTitle = cleanText(button.getAttribute?.("title"), "");
  const currentPressed = cleanText(button.getAttribute?.("aria-pressed"), "");
  const currentDisabledReason = cleanText(button.dataset?.wisCameraDisabledReason, "");
  if (
    currentAction === expectedAction
    && currentIcon === expectedIcon
    && currentTitle === expectedTitle
    && currentPressed === expectedPressed
    && currentDisabledReason === expectedDisabledReason
  ) return false;
  traceWisCameraPlayPause("controls.playpause.uiStateMismatch", key, wisCameraPlayPauseTraceContext(resolved, {
    control: "play-pause",
    action: currentAction,
    expectedAction,
    expectedIcon,
    expectedTitle,
    expectedPressed,
    expectedDisabledReason,
    status: cleanText(session?.status, ""),
    clockPaused: Boolean(session?.clockPaused),
    button: wisCameraControlTargetSummary(button),
    mismatch: true,
  }));
  if (footer?.dataset) footer.dataset.wisTimelineSignature = "playpause-state-mismatch";
  const slot = wisCameraSlotForStreamId(key, button.dataset?.wisCameraSlot || "");
  const camera = wisCameraConfigForSlot(slot) || focusedWisCameraTimelineConfig() || {};
  if (wisCameraIsPushConfig(camera)) renderWisCameraTimelineFooter({ ...camera, _slot: slot });
  return true;
}

function updateWisCameraRecordedPlaybackUi(streamId, options = {}) {
  const key = cleanText(streamId, "");
  const session = recordedWisCameraSession(key);
  if (!session) return;
  if (syncWisCameraPlayPauseButtonForSession(key, session)) return;
  const overrideMs = Number(options.currentMs);
  const currentMs = Number.isFinite(overrideMs) && overrideMs > 0 ? overrideMs : wisCameraRecordedClockMs(session);
  if (!state.wisCameraTimelineUiState) state.wisCameraTimelineUiState = new Map();
  const uiState = state.wisCameraTimelineUiState.get(key) || { lastTimelineAt: 0, lastProgress: null, lastAriaAt: 0 };
  state.wisCameraTimelineUiState.set(key, uiState);
  const nowMs = performance.now();
  const forceUi = Boolean(options.force || options.userInteracting);
  const budget = wisCameraBudget(key, "timeline");
  if (!forceUi && !budget.allowTimelineWork) return;
  if (options.timelineOnly && !forceUi && nowMs - Number(uiState.lastTimelineAt || 0) < Number(budget.timelineMinIntervalMs || 250)) return;
  const widget = widgetById("wis");
  const footer = widget?.querySelector?.(".wis-camera-timeline");
  const title = footer?.querySelector?.(".wis-camera-timeline-title");
  const setTimelineText = (element, text = "") => {
    const nextText = String(text ?? "");
    if (element && element.textContent !== nextText) {
      element.textContent = nextText;
      noteWisCameraPerf(state, key, "timelinePatches");
    }
  };
  if (!options.timelineOnly) setTimelineText(title, wisCameraRecordedTimelineTitle(session, currentMs));
  const sessionElement = session.id
    ? widget?.querySelector?.(`[data-wis-recorded-session-id="${CSS.escape(session.id)}"]`)
    : null;
  const status = sessionElement?.querySelector?.(".wis-camera-sync-status");
	  if (status && ["seeking", "buffering", "loading", "catching-up", "rebuffering", "restarting", "stalled", "gap", "ended"].includes(session.status)) {
    setTimelineText(status, wisCameraRecordedTimelineTitle(session, currentMs));
  }
  if (options.timeline === false) return;
  const timeline = state.wisCameraTimeline.streamId === key ? state.wisCameraTimeline : null;
  const frames = Array.isArray(timeline?.frames) ? timeline.frames : [];
  const { visibleStart, visibleEnd } = wisCameraTimelineTimeWindow(timeline || {}, frames, { playbackPosition: currentMs });
  if (visibleEnd > visibleStart) {
    const progress = clamp(((currentMs - visibleStart) / (visibleEnd - visibleStart)) * 100, 0, 100);
    const scrubber = footer?.querySelector?.(`.wis-camera-timeline-scrubber[data-stream-id="${CSS.escape(key)}"]`);
    if (scrubber?.classList?.contains("is-scrubbing") || scrubber?.dataset?.wisTimelinePreviewing === "1") {
      logWisCameraMediaEvent("camera.timeline.scrub.programmatic_sync_skipped", {
        streamId: key,
        generation: Number(session.generation || 0),
        timestampMs: currentMs,
        playbackProgress: progress,
        previewProgress: scrubber?.style?.getPropertyValue("--wis-camera-timeline-preview") || "",
        elementConnected: scrubber?.isConnected !== false,
      }, { sampleMs: 1000 });
      return;
    }
    const previousProgress = Number(uiState.lastProgress);
    const progressDelta = Number.isFinite(previousProgress) ? Math.abs(progress - previousProgress) : Infinity;
    if (!forceUi && nowMs - Number(uiState.lastTimelineAt || 0) < Number(budget.timelineMinIntervalMs || 250) && progressDelta < 0.35) {
      return;
    }
    const progressValue = `${progress}%`;
    if (scrubber?.style?.getPropertyValue?.("--wis-camera-timeline-progress") !== progressValue) {
      scrubber?.style?.setProperty("--wis-camera-timeline-progress", progressValue);
      noteWisCameraPerf(state, key, "timelinePatches");
      uiState.lastProgress = progress;
      uiState.lastTimelineAt = nowMs;
      traceWisCameraBoundary("timeline.progress.updated", {
        streamId: key,
        owner: wisCameraTimelineOwnerStateContract(state, key),
        requestedTimestampMs: Number(session.requestedSeekTimestampMs || 0),
        persistedSeekTimestampMs: Number(session.persistedSeekTimestampMs || session.requestedSeekTimestampMs || 0),
        mediaAnchorMs: Number(session.anchorRecordingTimeMs || 0),
        wallAnchorMs: Number(session.anchorWallTimeMs || 0),
        playbackClockMs: currentMs,
        visibleFrameMs: Number(session.lastDisplayedFrameTimeMs || 0),
        archiveWindowStartMs: Number(timeline?.availableRange?.start_ms ?? timeline?.available_range?.start_ms ?? timeline?.range?.start_ms ?? visibleStart ?? 0),
        archiveWindowEndMs: Number(timeline?.availableRange?.end_ms ?? timeline?.available_range?.end_ms ?? timeline?.range?.end_ms ?? visibleEnd ?? 0),
        generation: Number(session.generation || 0),
        paused: Boolean(session.clockPaused),
        playbackRate: Number(session.playbackRate || session.rate || 1),
        progress,
      });
    }
    const valueText = cameraTimelineFrameLabel({ timestamp_ms: currentMs });
    if ((forceUi || nowMs - Number(uiState.lastAriaAt || 0) >= 1000) && scrubber?.getAttribute?.("aria-valuetext") !== valueText) {
      scrubber?.setAttribute?.("aria-valuetext", valueText);
      noteWisCameraPerf(state, key, "timelinePatches");
      uiState.lastAriaAt = nowMs;
    }
  }
}

function startWisCameraRecordedClock(streamId) {
  const key = cleanText(streamId, "");
  if (!key) return;
  stopWisCameraRecordedClock(key);
  updateWisCameraRecordedPlaybackUi(key, { force: true });
  const task = scheduleWisCameraTimer(`recorded-clock:${key}`, () => {
    updateWisCameraRecordedPlaybackUi(key, { timelineOnly: true });
  }, 500, { streamId: key, mode: "timeline" });
  state.wisCameraRecordedTickTimers.set(key, task);
}

function startWisCameraRecordedSession(streamId, frame = null, options = {}) {
  const key = cleanText(streamId, "");
  if (!key || !frame?.id) return null;
  const existing = recordedWisCameraSession(key);
  if (!options.restart && wisCameraTimelineFramePlaybackKey(existing?.frame) === wisCameraTimelineFramePlaybackKey(frame)) return existing;
  enterWisCameraRecordedMode(key, frame, {
    reason: options.reason || "recorded-session-start",
    timestampMs: options.timestampMs,
    generation: options.generation,
    ratio: options.ratio,
  });
  stopWisCameraTimer(key);
  stopWisCameraRecordedClock(key);
  const session = startWisCameraPlaybackSeek(state, key, frame, {
    explicitSeek: options.explicitSeek,
    restart: options.restart,
    generation: options.generation,
    paused: options.paused,
    userPaused: options.paused,
    reason: options.reason,
  });
  logWisCameraLoopOwner(key, "recorded-session-start");
  return session;
}

function stopWisCameraRecordedSession(streamId) {
  const key = cleanText(streamId, "");
  if (!key) return;
  const session = recordedWisCameraSession(key);
  traceWisCameraBoundary("fallback.live", {
    functionName: "stopWisCameraRecordedSession",
    streamId: key,
    reason: "recorded-session-stop",
    explicit: false,
    previousOwner: wisCameraPlaybackOwnerState(session, wisCameraTimelineOwnerStateContract(state, key)),
    generation: Number(session?.generation || 0),
    sessionId: cleanText(session?.id, ""),
    ...wisCameraLoopOwnerSnapshot(key),
  }, { stack: true });
  stopWisCameraRecordedClock(key);
  stopWisCameraPlaybackController(key, "recorded-session-stop");
  stopWisCameraPlaybackState(state, key);
  releaseMediaStreamWriter(key, { kind: "recorded-playback", generation: session?.generation });
}

function wisCameraSurfaceElement(slot = "") {
  const key = cleanText(slot, "");
  if (!key) return null;
  return widgetById("wis")?.querySelector?.(`.wis-node-webcam_placeholder[data-wis-camera-slot="${CSS.escape(key)}"]`) || null;
}

function renderWisCameraPlaybackInPlace(streamId, frame = null, options = {}) {
  const key = cleanText(streamId, "");
  if (!key) return false;
  const slot = wisCameraSlotForStreamId(key, options.slot || frame?._slot || frame?.slot || "");
  const camera = wisCameraConfigForSlot(slot) || {};
  if (!wisCameraIsPushConfig(camera) || wisCameraQualityStreamId(slot, camera) !== key) {
    traceWisCameraBoundary("recorded.render.rejected", wisCameraPlaybackTracePayload(key, {
      functionName: "renderWisCameraPlaybackInPlace",
      streamId: key,
      slot,
      focusedSlot: wisFocusedCameraSlot() || "",
      reason: "stream-slot-mismatch",
      qualityStreamId: wisCameraQualityStreamId(slot, camera),
      baseStreamId: wisCameraBaseStreamId(slot, camera),
      frameId: cleanText(frame?.id, ""),
    }));
    return false;
  }
  const element = wisCameraSurfaceElement(slot);
  if (!element) {
    traceWisCameraBoundary("recorded.render.rejected", wisCameraPlaybackTracePayload(key, {
      functionName: "renderWisCameraPlaybackInPlace",
      streamId: key,
      slot,
      focusedSlot: wisFocusedCameraSlot() || "",
      reason: "surface-element-missing",
      frameId: cleanText(frame?.id, ""),
    }));
    return false;
  }
  const showCameraIssue = (text, type = "recorded-playback-error") => {
    element.classList.remove("has-camera");
    element.replaceChildren();
    const span = document.createElement("span");
    span.className = "wis-camera-message warn";
    span.textContent = text;
    element.append(span);
    publishWisCameraDebugSnapshot(slot, { type });
  };
  renderWisCameraPushArchiveFrame(element, slot, camera, frame || selectedWisCameraTimelineFrame(key), showCameraIssue, options);
  applyWisCameraZoom(element, key);
  installWisCameraZoomSelection(element, key);
  renderWisCameraTimelineFooter({ ...camera, _slot: slot });
  return true;
}

function returnWisCameraToLive(streamId) {
  const key = cleanText(streamId, "");
  if (!key) return;
  const session = recordedWisCameraSession(key);
  traceWisCameraBoundary("fallback.live", {
    functionName: "returnWisCameraToLive",
    streamId: key,
    reason: "live-button",
    explicit: true,
    previousOwner: wisCameraPlaybackOwnerState(session, WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PLAYING),
    nextOwner: WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE,
    generation: Number(session?.generation || 0),
    sessionId: cleanText(session?.id, ""),
    ...wisCameraLoopOwnerSnapshot(key),
  }, { stack: true });
  state.wisCameraTimelineSelections.delete(key);
  stopWisCameraRecordedSession(key);
  logWisCameraMediaEvent("camera.playback.transition", {
    streamId: key,
    fromMode: wisCameraPlaybackOwnerMode(session, "recorded"),
    toMode: "live",
    fromOwnerState: wisCameraPlaybackOwnerState(session, WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PLAYING),
    toOwnerState: WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE,
    ownerStateTransition: `${wisCameraPlaybackOwnerState(session, WIS_CAMERA_TIMELINE_OWNER_STATES.RECORDED_PLAYING)} -> ${WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE}`,
    frameLayerOwner: "live",
    reason: "live-button",
    timestampMs: Number(session?.currentWallTime || session?.recordedStartWallTime || 0),
    generation: Number(session?.generation || 0),
  }, { always: true });
  logWisCameraLoopOwner(key, "return-live");
  setWisCameraTimelineMode(key, "live");
}

function setWisCameraTimelineFrame(streamId, frame = null, options = {}) {
  const key = cleanText(streamId, "");
  if (!key) return;
  traceWisCameraBoundary("timeline.app.setFrame", wisCameraPlaybackTracePayload(key, {
    functionName: "setWisCameraTimelineFrame",
    frameId: cleanText(frame?.id, ""),
    requestedTimestampMs: Number(frame?.seek_target_ms || frame?.seekTargetMs || frame?.timestamp_ms || frame?.timestampMs || 0),
    frameTimestampMs: Number(frame?.timestamp_ms || frame?.timestampMs || 0),
    fromController: Boolean(options.fromController),
    force: Boolean(options.force),
    restartSession: options.restartSession === undefined ? null : Boolean(options.restartSession),
    source: cleanText(options.source, ""),
    reason: cleanText(options.reason, ""),
    requestedGeneration: Number(options.generation ?? options.playbackGeneration ?? options.seekToken ?? 0),
  }));
  const requestedGeneration = Number(options.generation ?? options.playbackGeneration ?? options.seekToken);
  const activeRecordedSession = recordedWisCameraSession(key);
  if (Number.isFinite(requestedGeneration) && requestedGeneration > 0 && Number(activeRecordedSession?.generation || 0) > Math.round(requestedGeneration)) {
    logWisCameraMediaEvent("camera.media.stale_writer.ignored", {
      streamId: key,
      generation: Math.round(requestedGeneration),
      activeGeneration: Number(activeRecordedSession?.generation || 0),
      reason: "timeline-frame-stale-generation",
    }, { sampleMs: 1000 });
    return activeRecordedSession;
  }
  const force = Boolean(options.force);
  if (frame?.id && frame?.url && !options.fromController) {
    stopWisCameraPlaybackController(key, "timeline-direct-select");
  }
  let session = null;
  if (frame?.id && frame?.url) {
    state.wisCameraTimelineSelections.set(key, frame);
    session = startWisCameraRecordedSession(key, frame, {
      explicitSeek: !options.autoplay,
      restart: options.restartSession === undefined ? force : Boolean(options.restartSession),
      generation: options.generation,
      reason: options.reason || "timeline-frame-selected",
      timestampMs: frame.seek_target_ms || frame.seekTargetMs || frame.timestamp_ms || frame.timestampMs,
      ratio: options.ratio,
    });
  } else {
    state.wisCameraTimelineSelections.delete(key);
    stopWisCameraRecordedSession(key);
  }
  stopWisCameraTimer(key);
  const autoplay = Boolean(options.autoplay);
  recordUserEvent(frame?.id ? (autoplay ? "wis.camera_timeline_advanced" : "wis.camera_timeline_selected") : "wis.camera_timeline_live", {
    source: "wis",
    target: `wis:${key}`,
    summary: frame?.id
      ? `${autoplay ? "Advanced to" : "Selected"} CAM timeline point ${cameraTimelineFrameLabel(frame)}`
      : `Returned ${key} to live camera`,
    data: { slot: key, frame_id: cleanText(frame?.id, ""), autoplay },
  });
  if (frame?.id) {
    if (!renderWisCameraPlaybackInPlace(key, frame, { force })) renderWis();
    return session;
  }
  renderWis();
  return session;
}

function frameAtTimelineRatio(frames = [], ratio = 1) {
  return wisCameraTimelineFrameAtRatio(frames, ratio);
}

function setPendingWisCameraTimelineSeek(streamId, seek = 1, mode = "") {
  const key = cleanText(streamId, "");
  if (!key) return;
  const pending = createWisCameraPendingTimelineSeek(key, seek, cleanText(mode, wisCameraTimelineMode(key)));
  if (pending) state.wisCameraTimelinePendingSeeks.set(key, pending);
}

function applyPendingWisCameraTimelineSeek(streamId, frames = [], mode = "") {
  const key = cleanText(streamId, "");
  if (!key || !frames.length) return false;
  const pending = state.wisCameraTimelinePendingSeeks.get(key);
  if (!pending) return false;
  const timelineMode = cleanText(mode, wisCameraTimelineMode(key));
  const frame = resolveWisCameraPendingTimelineSeek(pending, frames, timelineMode, state.wisCameraTimeline);
  if (!frame) return false;
  state.wisCameraTimelinePendingSeeks.delete(key);
  const targetTimeMs = Number(pending.targetTime ?? pending.target_time ?? frame.timestamp_ms ?? frame.timestampMs);
  const controller = wisCameraPlaybackController(key);
  traceWisCameraBoundary("timeline.pending.seek.applied", wisCameraPlaybackTracePayload(key, {
    functionName: "applyPendingWisCameraTimelineSeek",
    targetTimeMs,
    frameId: cleanText(frame?.id, ""),
    controllerFound: Boolean(controller),
    mode: timelineMode,
  }));
  if (controller && Number.isFinite(targetTimeMs) && targetTimeMs > 0) {
    void controller.seekTo(targetTimeMs, {
      source: "user",
      reason: "pending-timeline-seek",
      frame,
      restart: true,
    }).catch((error) => {
      state.lastError = error.message || String(error);
    });
  } else {
    setWisCameraTimelineFrame(key, frame, { force: true, source: "user", reason: "pending-timeline-seek" });
  }
  return true;
}

function scheduleWisCameraTimelinePlayback(streamId, frame = null) {
  const key = cleanText(streamId, "");
  if (!key || !frame?.id) return;
  stopWisCameraTimer(key);
}

function focusedWisCameraTimelineConfig() {
  const snapshot = wisSurfaceState();
  if (!wisSurfaceIsFocusedCamera(snapshot)) return null;
  const slot = wisFocusedCameraSlot(snapshot) || "cam-1";
  const camera = wisCameraConfigForSlot(slot) || {};
  return wisCameraIsPushConfig(camera) ? { ...camera, _slot: slot } : null;
}

function armWisCameraTimelineLoadWatchdog(streamId, mode, startedAt, loadSeq) {
  window.setTimeout(() => {
    const timeline = state.wisCameraTimeline || {};
    if (
      !timeline.loading
      || timeline.streamId !== streamId
      || timeline.mode !== mode
      || Number(timeline.loadingStartedAt || timeline.loading_started_at || 0) !== Number(startedAt)
      || Number(state.wisCameraTimelineLoadSeq || 0) !== Number(loadSeq)
    ) return;
    state.wisCameraTimeline = {
      ...timeline,
      streamId,
      mode,
      loading: false,
      loadingStartedAt: 0,
      loadedAt: 0,
      error: "Timeline load stalled; retrying...",
    };
    renderWisCameraTimelineFooter(focusedWisCameraTimelineConfig());
    void loadWisCameraTimeline(streamId, "stale-watchdog", mode);
  }, WIS_CAMERA_TIMELINE_LOAD_STALE_MS);
}

async function loadWisCameraTimeline(streamId, origin = "manual", mode = "") {
  const key = cleanText(streamId, "cam-1");
  const timelineMode = cleanText(mode, wisCameraTimelineMode(key));
  const currentTimeline = state.wisCameraTimeline || {};
  const loadingStartedAt = Number(currentTimeline.loadingStartedAt || currentTimeline.loading_started_at || 0);
  const loadingAgeMs = loadingStartedAt > 0 ? Date.now() - loadingStartedAt : Infinity;
  if (
    currentTimeline.loading
    && currentTimeline.streamId === key
    && currentTimeline.mode === timelineMode
    && loadingAgeMs < WIS_CAMERA_TIMELINE_LOAD_STALE_MS
  ) return;
  const startedAt = Date.now();
  const loadSeq = Number(state.wisCameraTimelineLoadSeq || 0) + 1;
  state.wisCameraTimelineLoadSeq = loadSeq;
  state.wisCameraTimeline = {
    ...state.wisCameraTimeline,
    streamId: key,
    mode: timelineMode,
    loading: true,
    loadingStartedAt: startedAt,
    error: "",
  };
  renderWisCameraTimelineFooter(focusedWisCameraTimelineConfig());
  armWisCameraTimelineLoadWatchdog(key, timelineMode, startedAt, loadSeq);
  try {
    const payload = await fetchJson("/camera/push-timeline", {
      method: "POST",
      timeoutMs: 10000,
      body: { stream_id: key, mode: timelineMode, seconds: 600 },
    });
    if (Number(state.wisCameraTimelineLoadSeq || 0) !== loadSeq) return;
    state.wisCameraTimeline = {
      streamId: cleanText(payload?.stream_id, key),
      mode: cleanText(payload?.mode, timelineMode),
      day: cleanText(payload?.day, ""),
      frames: Array.isArray(payload?.frames) ? payload.frames : [],
      range: payload?.range && typeof payload.range === "object" ? payload.range : null,
      availableRange: payload?.available_range && typeof payload.available_range === "object" ? payload.available_range : null,
      loadedAt: Date.now(),
      loadingStartedAt: 0,
      loading: false,
      error: "",
    };
    recordUserEvent("wis.camera_timeline_loaded", {
      source: "wis",
      target: `wis:${key}`,
      summary: `Loaded ${state.wisCameraTimeline.frames.length} ${timelineMode} camera timeline points`,
      data: { slot: key, origin, mode: timelineMode, frame_count: state.wisCameraTimeline.frames.length },
    });
    if (applyPendingWisCameraTimelineSeek(key, state.wisCameraTimeline.frames, timelineMode)) return;
  } catch (error) {
    if (Number(state.wisCameraTimelineLoadSeq || 0) !== loadSeq) return;
    state.wisCameraTimeline = {
      ...state.wisCameraTimeline,
      streamId: key,
      mode: timelineMode,
      loading: false,
      loadedAt: Date.now(),
      loadingStartedAt: 0,
      error: error.message || String(error),
    };
  }
  renderWisCameraTimelineFooter(focusedWisCameraTimelineConfig());
}

function shouldLoadWisCameraTimeline(streamId, mode = "") {
  const key = cleanText(streamId, "");
  if (!key) return false;
  const timelineMode = cleanText(mode, wisCameraTimelineMode(key));
  return shouldLoadWisCameraTimelineContract(state.wisCameraTimeline, key, timelineMode);
}

function scheduleWisCameraTimelineLoad(streamId, origin = "render", mode = "") {
  const key = cleanText(streamId, "");
  if (!shouldLoadWisCameraTimeline(key, mode)) return;
  const timelineMode = cleanText(mode, wisCameraTimelineMode(key));
  queueMicrotask(() => {
    if (shouldLoadWisCameraTimeline(key, timelineMode)) void loadWisCameraTimeline(key, origin, timelineMode);
  });
}

function setWisCameraTimelineMode(streamId, mode = "live") {
  const key = cleanText(streamId, "cam-1");
  const nextMode = cleanText(mode, "live") === "recorded" ? "recorded" : "live";
  traceWisCameraBoundary(nextMode === "live" ? "fallback.live" : "timeline.mode", {
    functionName: "setWisCameraTimelineMode",
    streamId: key,
    previousMode: wisCameraTimelineMode(key),
    nextMode,
    previousOwner: wisCameraTimelineOwnerStateContract(state, key),
    nextOwner: nextMode === "live" ? WIS_CAMERA_TIMELINE_OWNER_STATES.LIVE : wisCameraTimelineOwnerStateContract(state, key),
    explicit: nextMode === "live",
    reason: "timeline-mode-button",
    ...wisCameraLoopOwnerSnapshot(key),
  }, { stack: true });
  state.wisCameraTimelineModes.set(key, nextMode);
  state.wisCameraTimelineSelections.delete(key);
  if (nextMode === "live") stopWisCameraRecordedSession(key);
  stopWisCameraTimer(key);
  recordUserEvent("wis.camera_timeline_mode", {
    source: "wis",
    target: `wis:${key}`,
    summary: nextMode === "recorded" ? `Detected recorded range for ${key}` : `Returned ${key} to last 10 minutes`,
    data: { slot: key, mode: nextMode },
  });
  void loadWisCameraTimeline(key, "mode", nextMode);
  renderWis();
}

function maybeLoadFocusedWisCameraTimeline(origin = "focus") {
  const snapshot = wisSurfaceState();
  if (!wisSurfaceIsFocusedCamera(snapshot)) return;
  const slot = wisFocusedCameraSlot(snapshot) || "cam-1";
  const camera = wisCameraConfigForSlot(slot) || {};
  if (!wisCameraIsPushConfig(camera)) return;
  const streamId = wisCameraQualityStreamId(slot, camera);
  const timelineMode = wisCameraTimelineMode(streamId);
  if (!shouldLoadWisCameraTimeline(streamId, timelineMode)) return;
  void loadWisCameraTimeline(streamId, origin, timelineMode);
}

function wisCameraTimelineWidgetActive(widget = widgetById("wis")) {
  return Boolean(widget?.classList?.contains("is-widget-active"));
}

function syncWisCameraTimelineVisibility(widget = widgetById("wis")) {
  const footer = widget?.querySelector?.(".wis-camera-timeline");
  if (!footer) return;
  footer.hidden = !wisCameraTimelineWidgetActive(widget);
}

function syncWisCameraAspect(element, media) {
  const width = Number(media?.videoWidth || media?.naturalWidth || 0);
  const height = Number(media?.videoHeight || media?.naturalHeight || 0);
  if (!Number.isFinite(width) || !Number.isFinite(height) || width <= 0 || height <= 0) return;
  const aspect = `${Math.round(width)} / ${Math.round(height)}`;
  element?.style?.setProperty?.("--wis-camera-aspect", aspect);
  element?.closest?.(".wis-widget")?.style?.setProperty?.("--wis-camera-aspect", aspect);
}

function wisNodeClass(type) {
  return `wis-node wis-node-${String(type || "element").replace(/[^a-z0-9_-]/gi, "-").toLowerCase()}`;
}

async function loadWisCameraRelaySnapshot(slot, camera, image, showCameraIssue) {
  try {
    const payload = await fetchJson("/camera/snapshot", {
      method: "POST",
      timeoutMs: 12000,
      body: {
        url: cleanText(camera.url, ""),
        vendor: cleanText(camera.vendor, ""),
        mode: cleanText(camera.mode, ""),
        timeoutMs: 8000,
      },
    });
    const dataUrl = cleanText(payload?.image?.data_url, "");
    if (!dataUrl.startsWith("data:image/")) {
      showCameraIssue("Camera relay did not return an image.", "snapshot-relay-error");
      return;
    }
    if (blockLiveWisCameraImageWrite(image, slot, "snapshot-relay")) return;
    image.src = dataUrl;
    if (rememberWisCameraDebugEvent(slot, {
      type: "snapshot-relay-loaded",
      mediaMode: camera.mediaMode,
      element: camera.element,
      vendor: camera.vendor,
      mode: camera.mode,
      url: camera.url,
      detail: "Loaded camera frame through the wasm-agent same-origin snapshot relay.",
    })) {
      publishWisCameraDebugSnapshot(slot, { type: "snapshot-relay-loaded" });
    }
    syncWisCameraAspect(image.closest?.(".wis-node-webcam_placeholder[data-wis-camera-slot]") || image.closest?.("[data-wis-camera-slot]"), image);
  } catch (error) {
    showCameraIssue(error.message || "Camera relay could not fetch the DVR snapshot.", "snapshot-relay-error");
  }
}

async function openWisCameraRtspRelaySession(slot, camera, image, showCameraIssue) {
  try {
    const payload = await fetchJson("/camera/rtsp-session", {
      method: "POST",
      timeoutMs: 12000,
      body: {
        url: cleanText(camera.url, ""),
        vendor: cleanText(camera.vendor, ""),
        mode: cleanText(camera.mode, ""),
        timeoutMs: 20000,
        fps: 5,
      },
    });
    const streamUrl = cleanText(payload?.stream?.url, "");
    if (!streamUrl.startsWith("/camera/rtsp-stream?")) {
      showCameraIssue("Camera RTSP relay did not return a playable stream URL.", "rtsp-relay-error");
      return;
    }
    if (blockLiveWisCameraImageWrite(image, slot, "rtsp-stream-relay")) return;
    image.src = `${streamUrl}&slot=${encodeURIComponent(slot)}&t=${Date.now()}`;
    if (rememberWisCameraDebugEvent(slot, {
      type: "rtsp-relay-opened",
      mediaMode: camera.mediaMode,
      element: camera.element,
      vendor: camera.vendor,
      mode: camera.mode,
      url: camera.url,
      detail: "Opened the true DVR RTSP realmonitor feed through the wasm-agent same-origin relay.",
    })) {
      publishWisCameraDebugSnapshot(slot, { type: "rtsp-relay-opened" });
    }
  } catch (error) {
    showCameraIssue(error.message || "Camera RTSP relay could not open the true DVR feed.", "rtsp-relay-error");
  }
}

async function loadWisCameraRtspFrame(element, slot, camera, image, status, showCameraIssue) {
  try {
    const payload = await fetchJson("/camera/rtsp-frame", {
      method: "POST",
      timeoutMs: 24000,
      body: {
        url: cleanText(camera.url, ""),
        vendor: cleanText(camera.vendor, ""),
        mode: cleanText(camera.mode, ""),
        timeoutMs: 8000,
        quality: 4,
      },
    });
    const dataUrl = cleanText(payload?.image?.data_url, "");
    if (!dataUrl.startsWith("data:image/")) {
      showCameraIssue("Camera RTSP frame relay did not return an image.", "rtsp-frame-error");
      return false;
    }
    if (blockLiveWisCameraImageWrite(image, slot, "rtsp-frame-relay")) return false;
    image.src = dataUrl;
    syncWisCameraAspect(element, image);
    if (status?.isConnected) status.remove();
    if (!image.isConnected) {
      element.append(image);
      element.classList.add("has-camera");
    }
    if (rememberWisCameraDebugEvent(slot, {
      type: "rtsp-frame-loaded",
      mediaMode: camera.mediaMode,
      element: camera.element,
      vendor: camera.vendor,
      mode: camera.mode,
      url: camera.url,
      detail: "Loaded a verified current frame from the DVR RTSP realmonitor feed.",
    })) {
      publishWisCameraDebugSnapshot(slot, { type: "rtsp-frame-loaded" });
    }
    return true;
  } catch (error) {
    const message = error.message || "Camera RTSP frame relay could not read a real frame.";
    state.wisCameraRtspRetryAfter.set(slot, {
      until: Date.now() + 30000,
      message,
    });
    showCameraIssue(message, "rtsp-frame-error");
    return false;
  }
}

async function openWisCameraStreamRelaySession(slot, camera, image, showCameraIssue) {
  try {
    const payload = await fetchJson("/camera/stream-session", {
      method: "POST",
      timeoutMs: 12000,
      body: {
        url: cleanText(camera.url, ""),
        vendor: cleanText(camera.vendor, ""),
        mode: cleanText(camera.mode, ""),
        timeoutMs: 20000,
      },
    });
    const streamUrl = cleanText(payload?.stream?.url, "");
    if (!streamUrl.startsWith("/camera/stream?")) {
      showCameraIssue("Camera stream relay did not return a playable stream URL.", "stream-relay-error");
      return;
    }
    if (blockLiveWisCameraImageWrite(image, slot, "mjpeg-stream-relay")) return;
    image.src = `${streamUrl}&slot=${encodeURIComponent(slot)}&t=${Date.now()}`;
    if (rememberWisCameraDebugEvent(slot, {
      type: "stream-relay-opened",
      mediaMode: camera.mediaMode,
      element: camera.element,
      vendor: camera.vendor,
      mode: camera.mode,
      url: camera.url,
      detail: "Opened camera MJPEG feed through the wasm-agent same-origin stream relay.",
    })) {
      publishWisCameraDebugSnapshot(slot, { type: "stream-relay-opened" });
    }
  } catch (error) {
    showCameraIssue(error.message || "Camera stream relay could not open the DVR MJPEG feed.", "stream-relay-error");
  }
}

function wisCameraShouldUseRtspRelay(camera = {}, url = "") {
  const rawUrl = cleanText(url || camera.url, "");
  const lowerUrl = rawUrl.toLowerCase();
  if (!lowerUrl.startsWith("rtsp://")) return false;
  return camera.relayMode === "same-origin-rtsp-mjpeg"
    || camera.mediaMode === "rtsp-mjpeg-relay"
    || camera.mediaMode === "rtsp-relay-required"
    || camera.element === "rtsp-relay"
    || camera.vendor === "intelbras"
    || cleanText(camera.label, "").toLowerCase().includes("intelbras")
    || cameraUrlHasCredentials(rawUrl)
    || Boolean(camera.credentialProfile || camera.credential_profile);
}

function wisCameraShouldUseStreamRelay(camera = {}, url = "") {
  const rawUrl = cleanText(url || camera.url, "");
  const lowerUrl = rawUrl.toLowerCase();
  const intelbrasSource = camera.vendor === "intelbras"
    || cleanText(camera.label, "").toLowerCase().includes("intelbras")
    || lowerUrl.includes("/cgi-bin/mjpg/video.cgi");
  if (!intelbrasSource || !rawUrl) return false;
  return camera.relayMode === "same-origin-mjpeg"
    || camera.mediaMode === "mjpeg-stream-relay"
    || camera.element === "mjpeg-relay"
    || cameraPotentiallyMixedContent(rawUrl)
    || cameraUrlHasCredentials(rawUrl)
    || Boolean(camera.credentialProfile || camera.credential_profile);
}

function wisCameraShouldPromoteSnapshotToRtspRelay(camera = {}, url = "") {
  const rawUrl = cleanText(url || camera.url, "");
  const lowerUrl = rawUrl.toLowerCase();
  if (!lowerUrl.includes("/cgi-bin/snapshot.cgi")) return false;
  const intelbrasSource = camera.vendor === "intelbras"
    || cleanText(camera.label, "").toLowerCase().includes("intelbras")
    || lowerUrl.includes("/cgi-bin/snapshot.cgi");
  if (!intelbrasSource) return false;
  return cameraUrlHasCredentials(rawUrl)
    || cameraPotentiallyMixedContent(rawUrl)
    || Boolean(camera.credentialProfile || camera.credential_profile);
}

function intelbrasTrueStreamCameraFromSnapshot(camera = {}, url = "") {
  const seed = intelbrasConfigFromCamera({ ...camera, url: url || camera.url });
  if (!seed.host) return camera;
  const rtspPort = intelbrasRtspPortFromCamera(camera, seed);
  const streamUrl = intelbrasRtspUrl({
    host: seed.host,
    user: seed.user,
    password: seed.password,
    channel: seed.channel,
    subtype: seed.subtype || "0",
    port: rtspPort,
  });
  return {
    ...camera,
    kind: "url",
    url: streamUrl,
    label: cleanText(camera.label, "") || `Intelbras CAM ${seed.channel || "1"} true stream`,
    mediaMode: "rtsp-mjpeg-relay",
    element: "rtsp-relay",
    browserPlayable: true,
    vendor: "intelbras",
    mode: "relay",
    relayMode: "same-origin-rtsp-mjpeg",
    host: seed.host,
    port: rtspPort,
    rtspPort,
    channel: seed.channel || "1",
    subtype: seed.subtype || "0",
    portalUrl: cameraPortalUrl(camera) || cameraOriginUrl(streamUrl),
  };
}

function wisCameraShouldUseSnapshotRelay(camera = {}, url = "") {
  const rawUrl = cleanText(url || camera.url, "");
  const intelbrasSource = camera.vendor === "intelbras"
    || cleanText(camera.label, "").toLowerCase().includes("intelbras")
    || rawUrl.toLowerCase().includes("/cgi-bin/snapshot.cgi");
  if (!intelbrasSource || !rawUrl) return false;
  return camera.relayMode === "same-origin-snapshot"
    || camera.mediaMode === "jpeg-snapshot-relay"
    || camera.element === "snapshot-relay"
    || cameraPotentiallyMixedContent(rawUrl)
    || cameraUrlHasCredentials(rawUrl)
    || Boolean(camera.credentialProfile || camera.credential_profile);
}

function renderWisCameraRelayImage(element, slot, camera, showCameraIssue) {
  const streamId = wisCameraBaseStreamId(slot, camera);
  const image = document.createElement("img");
  image.className = "wis-camera-image wis-camera-snapshot";
  image.alt = camera.label || slot;
  image.addEventListener("load", () => syncWisCameraAspect(element, image));
  let inFlight = false;
  const refresh = () => {
    if (!wisCameraBudget(streamId, "live").allowVisualWork) return;
    if (inFlight) return;
    inFlight = true;
    void loadWisCameraRelaySnapshot(slot, camera, image, showCameraIssue).finally(() => {
      inFlight = false;
    });
  };
  element.classList.add("has-camera");
  element.append(image);
  refresh();
  scheduleWisCameraTimer(slot, refresh, 2500, { streamId, mode: "live" });
}

function renderWisCameraStreamRelayImage(element, slot, camera, showCameraIssue) {
  const image = document.createElement("img");
  image.className = "wis-camera-image wis-camera-stream";
  image.alt = camera.label || slot;
  image.addEventListener("load", () => {
    syncWisCameraAspect(element, image);
    if (rememberWisCameraDebugEvent(slot, {
      type: "stream-relay-loaded",
      mediaMode: camera.mediaMode,
      element: camera.element,
      vendor: camera.vendor,
      mode: camera.mode,
      url: camera.url,
      detail: "Browser loaded the same-origin camera MJPEG relay.",
    })) {
      publishWisCameraDebugSnapshot(slot, { type: "stream-relay-loaded" });
    }
  }, { once: true });
  image.addEventListener("error", () => {
    showCameraIssue("Camera stream relay did not render the DVR MJPEG feed.", "stream-relay-error");
  }, { once: true });
  element.classList.add("has-camera");
  element.append(image);
  void openWisCameraStreamRelaySession(slot, camera, image, showCameraIssue);
}

function renderWisCameraRtspRelayImage(element, slot, camera, showCameraIssue) {
  const streamId = wisCameraBaseStreamId(slot, camera);
  const retry = state.wisCameraRtspRetryAfter.get(slot);
  if (retry && retry.until > Date.now()) {
    const span = document.createElement("span");
    span.className = "wis-camera-message warn";
    span.textContent = retry.message || "Camera RTSP frame relay is waiting before retrying.";
    element.append(span);
    appendWisCameraRecoveryActions(element, slot, camera, { includeStream: false });
    return;
  }
  if (retry) state.wisCameraRtspRetryAfter.delete(slot);
  const image = document.createElement("img");
  image.className = "wis-camera-image wis-camera-stream wis-camera-rtsp";
  image.alt = camera.label || slot;
  image.addEventListener("load", () => syncWisCameraAspect(element, image));
  const status = document.createElement("span");
  status.className = "wis-camera-message warn";
  status.textContent = "Checking true DVR RTSP frame...";
  element.append(status);
  let inFlight = false;
  const refresh = () => {
    if (!wisCameraBudget(streamId, "live").allowVisualWork) return;
    if (inFlight) return;
    inFlight = true;
    void loadWisCameraRtspFrame(element, slot, camera, image, status, showCameraIssue).finally(() => {
      inFlight = false;
    });
  };
  refresh();
  scheduleWisCameraTimer(slot, refresh, 2000, { streamId, mode: "live" });
}

function wisCameraPushFramePollMs(camera = {}) {
  return wisCameraPushFramePollMsContract(camera);
}

function renderWisCameraPushFramePolling(element, slot, camera, showCameraIssue) {
  const streamId = wisCameraQualityStreamId(slot, camera);
  const activeRecordedSession = recordedWisCameraSession(streamId);
  if (activeRecordedSession || wisCameraRecordedOwnsStream(streamId)) {
    logWisCameraMediaEvent("camera.media.live.write.blocked_by_recorded_owner", {
      streamId,
      generation: Number(activeRecordedSession?.generation || 0),
      sessionId: cleanText(activeRecordedSession?.id, ""),
      reason: "push-frame-poll-render-blocked",
    }, { sampleMs: 1000 });
    logWisCameraMediaEvent("camera.timeline.live_update.blocked_by_recorded_owner", {
      streamId,
      generation: Number(activeRecordedSession?.generation || 0),
      ownerState: wisCameraTimelineOwnerStateContract(state, streamId),
      sessionId: cleanText(activeRecordedSession?.id, ""),
      reason: "push-frame-poll-render-blocked",
    }, { always: true, sampleMs: 1000 });
    if (activeRecordedSession) {
      renderWisCameraPushArchiveFrame(element, slot, camera, activeRecordedSession.frame || activeRecordedSession.requestedFrame, showCameraIssue, {
        generation: activeRecordedSession.generation,
      });
    }
    return;
  }
  const baseStreamId = wisCameraBaseStreamId(slot, camera);
  const configuredFrameUrl = streamId === baseStreamId
    ? (cleanText(camera.frameUrl || camera.frame_url, "") || cameraPushFrameUrl(streamId))
    : cameraPushFrameUrl(streamId);
  const image = document.createElement("img");
  const liveOwner = { kind: "live", streamId, generation: 0 };
  image.className = "wis-camera-image wis-camera-stream wis-camera-push is-frame-polled";
  image.alt = camera.label || slot;
  if (!claimMediaWriter(image, liveOwner)) {
    logWisCameraMediaEvent("camera.media.live.write.blocked_by_recorded_owner", {
      streamId,
      generation: 0,
      reason: "push-frame-poll-claim",
    }, { sampleMs: 1000 });
    logWisCameraMediaEvent("camera.timeline.live_update.blocked_by_recorded_owner", {
      streamId,
      generation: 0,
      ownerState: wisCameraTimelineOwnerStateContract(state, streamId),
      reason: "push-frame-poll-claim",
    }, { always: true, sampleMs: 1000 });
    return;
  }
  const status = document.createElement("span");
  status.className = "wis-camera-message warn";
  status.textContent = "Connecting to live DVR frames...";
  const actions = document.createElement("div");
  actions.className = "wis-camera-fallback";
  const ingestUrl = cleanText(camera.ingestUrl || camera.ingest_url, "");
  if (ingestUrl) {
    appendWisCameraAction(actions, "Copy RTMP URL", () => {
      void navigator.clipboard?.writeText?.(ingestUrl);
    });
  }
  appendWisCameraRecoveryActions(actions, slot, camera, { includeStream: false });
  element.append(status, actions);

  let frameInFlight = false;
  let statusInFlight = false;
  let frameLoaded = false;
  let lastStatusAt = 0;

  const showStatusBeforeFirstFrame = (text) => {
    if (frameLoaded) return;
    status.textContent = text;
    if (!status.isConnected) element.append(status);
    if (!actions.isConnected) element.append(actions);
  };

  const refreshFrame = () => {
    if (!wisCameraBudget(streamId, "live").allowVisualWork) return;
    if (blockLiveWisCameraImageWrite(image, streamId, "push-frame-poll-refresh")) return;
    if (frameInFlight) return;
    frameInFlight = true;
    const loader = new Image();
    loader.decoding = "async";
    loader.alt = image.alt;
    loader.addEventListener("load", () => {
      frameInFlight = false;
      if (blockLiveWisCameraImageWrite(image, streamId, "push-frame-poll")) return;
      if (!isMediaWriterCurrent(image, liveOwner)) {
        logWisCameraMediaEvent("camera.media.stale_writer.ignored", {
          streamId,
          generation: 0,
          ownerKind: "live",
          imageOwner: image.dataset?.wisMediaOwner,
          reason: "push-frame-poll-stale-owner",
        }, { sampleMs: 1000 });
        return;
      }
      image.src = loader.src;
      noteWisCameraPerf(state, streamId, "srcChanges");
      image.dataset.wisPlaybackStream = "live";
      image.dataset.wisPlaybackFrameMs = "";
      image.dataset.wisPlaybackFrameId = "";
      rememberWisCameraLastGoodFrameFromImage(state, streamId, image, null, {
        ownerKind: "live",
        generation: 0,
      });
      syncWisCameraAspect(element, loader);
      status.remove();
      actions.remove();
      if (!image.isConnected) element.append(image);
      element.classList.add("has-camera");
      applyWisCameraZoom(element, streamId);
      frameLoaded = true;
      if (rememberWisCameraDebugEvent(slot, {
        type: "push-frame-polled-loaded",
        mediaMode: camera.mediaMode,
        element: camera.element,
        vendor: camera.vendor,
        mode: camera.mode,
        detail: `Live DVR RTMP push frame ${streamId} loaded with last-good-frame retention.`,
      })) {
        publishWisCameraDebugSnapshot(slot, { type: "push-frame-polled-loaded" });
      }
    }, { once: true });
    loader.addEventListener("error", () => {
      frameInFlight = false;
      if (blockLiveWisCameraImageWrite(image, streamId, "push-frame-poll-error")) return;
      showStatusBeforeFirstFrame("Waiting for the first live DVR frame...");
    }, { once: true });
    loader.src = cameraCacheBustedUrl(configuredFrameUrl);
  };

  const refreshStatus = async () => {
    if (!wisCameraBudget(streamId, "live").allowVisualWork) return;
    if (blockLiveWisCameraImageWrite(image, streamId, "push-frame-status-refresh")) return;
    if (statusInFlight) return;
    statusInFlight = true;
    try {
      const payload = await fetchJson(cameraPushStatusUrl(streamId), { timeoutMs: 8000 });
      const stateLabel = cleanText(payload?.state, "listening");
      const frameAvailable = Boolean(payload?.frame?.available);
      if (blockLiveWisCameraImageWrite(image, streamId, "push-frame-status-result")) return;
      if (!frameAvailable) {
        showStatusBeforeFirstFrame(stateLabel === "listening"
          ? `Listening for DVR RTMP push${ingestUrl ? `: ${ingestUrl}` : "."}`
          : "RTMP ingest is not running. Reconfigure this camera to start it.");
        return;
      }
      if (stateLabel === "stale") {
        const age = Math.round(Number(payload?.frame?.age_sec || 0));
        showStatusBeforeFirstFrame(age > 0
          ? `Camera feed is stale. Last frame was ${age}s ago; waiting for live frames...`
          : "Camera feed is stale; waiting for live frames...");
        return;
      }
      if (rememberWisCameraDebugEvent(slot, {
        type: "push-frame-loaded",
        mediaMode: camera.mediaMode,
        element: camera.element,
        vendor: camera.vendor,
        mode: camera.mode,
        detail: `Live DVR RTMP push stream ${streamId} has current frames.`,
      })) {
        publishWisCameraDebugSnapshot(slot, { type: "push-frame-loaded" });
      }
    } catch (error) {
      if (blockLiveWisCameraImageWrite(image, streamId, "push-frame-status-error")) return;
      if (!frameLoaded) showCameraIssue(error.message || "DVR RTMP push status could not be read.", "push-frame-error");
    } finally {
      statusInFlight = false;
    }
  };

  const tick = () => {
    if (blockLiveWisCameraImageWrite(image, streamId, "push-frame-poll-tick")) return;
    refreshFrame();
    const now = Date.now();
    if (now - lastStatusAt >= 5000) {
      lastStatusAt = now;
      void refreshStatus();
    }
  };
  tick();
  scheduleWisCameraTimer(slot, tick, wisCameraPushFramePollMs(camera), { streamId, mode: "live" });
}

function renderWisCameraPushArchiveFrame(element, slot, camera, frame, showCameraIssue, options = {}) {
  const streamId = wisCameraQualityStreamId(slot, camera);
  stopWisCameraTimer(slot);
  stopWisCameraTimer(streamId);
  const session = recordedWisCameraSession(streamId);
  const archiveFrameUrl = cameraCacheBustedUrl(cleanText(frame?.url, ""));
  const budget = wisCameraBudget(streamId, "recorded");
  const requestedFps = Number(camera.fps || camera.frameFps || camera.frame_fps || 15);
  const playbackFps = Math.max(1, Math.round(Math.min(Number.isFinite(requestedFps) && requestedFps > 0 ? requestedFps : 15, budget.recordedVisualFps || 1)));
  const playbackUrl = cameraCacheBustedUrl(cameraPushPlaybackUrl(streamId, frame, {
    fps: playbackFps,
    follow: false,
  }) || archiveFrameUrl);
  traceWisCameraBoundary("recorded.render.entrypoint", {
    functionName: "renderWisCameraPushArchiveFrame",
    streamId,
    slot,
    generation: Number(options.generation || session?.generation || 0),
    sessionId: cleanText(session?.id, ""),
    frameId: cleanText(frame?.id, ""),
    frameTimestampMs: wisCameraTimelinePlaybackStartMs(frame, wisCameraTimelineFrameTimestampMs(frame, 0)),
    archiveFrameUrl,
    playbackUrl,
    visibleLayerOwner: element?.querySelector?.(".wis-camera-image, .wis-camera-video")?.dataset?.wisMediaOwner || "",
    ownerState: wisCameraTimelineOwnerStateContract(state, streamId),
    ...wisCameraLoopOwnerSnapshot(streamId, slot),
  });
  return renderWisCameraPushArchiveFrameContract(state, {
    element,
    streamId,
    slot,
    camera,
    frame,
    force: options.force,
    generation: options.generation,
    archiveFrameUrl,
    playbackUrl,
    env: window,
    document,
    showCameraIssue,
    playbackController: () => wisCameraPlaybackController(streamId),
    onFrameDisplayed: (_session, displayedFrame = null) => {
      const displayedMs = wisCameraTimelinePlaybackStartMs(displayedFrame, wisCameraTimelineFrameTimestampMs(displayedFrame, 0));
      updateWisCameraRecordedPlaybackUi(streamId, {
        currentMs: displayedMs,
        timeline: false,
      });
    },
    onEnded: () => updateWisCameraRecordedPlaybackUi(streamId),
    onError: () => updateWisCameraRecordedPlaybackUi(streamId),
    onMissingFrame: () => state.wisCameraTimelineSelections.delete(streamId),
    onMediaEvent: (event, payload = {}, detail = {}) => logWisCameraMediaEvent(event, payload, {
      sampleMs: detail.sampleMs ?? (event.includes(".sample") ? 1000 : 0),
      always: detail.always,
    }),
    syncAspect: (targetElement, image) => syncWisCameraAspect(targetElement, image),
    applyZoom: (targetElement, targetStreamId) => applyWisCameraZoom(targetElement, targetStreamId),
  });
}

function renderWisCameraPushImage(element, slot, camera, showCameraIssue) {
  const streamId = wisCameraQualityStreamId(slot, camera);
  const activeRecordedSession = recordedWisCameraSession(streamId);
  const timelineFrame = activeRecordedSession?.frame || activeRecordedSession?.requestedFrame || selectedWisCameraTimelineFrame(streamId);
  if (timelineFrame) {
    renderWisCameraPushArchiveFrame(element, slot, camera, timelineFrame, showCameraIssue, {
      generation: activeRecordedSession?.generation,
    });
    return;
  }
  renderWisCameraPushFramePolling(element, slot, camera, showCameraIssue);
}

function applyWisCameraZoom(element, streamId) {
  const zoom = state.wisCameraZoomSelections.get(streamId);
  const media = element.querySelector(".wis-camera-video, .wis-camera-image");
  element.classList.toggle("is-zoom-selecting", Boolean(zoom?.selecting));
  element.classList.toggle("is-zoomed", Boolean(zoom?.rect));
  if (!media || !zoom?.rect) {
    media?.style?.removeProperty?.("--wis-camera-zoom-origin-x");
    media?.style?.removeProperty?.("--wis-camera-zoom-origin-y");
    media?.style?.removeProperty?.("--wis-camera-zoom-scale");
    return;
  }
  const rect = zoom.rect;
  const scale = clamp(1 / Math.max(0.18, Math.max(rect.w, rect.h)), 1.15, 5);
  media.style.setProperty("--wis-camera-zoom-origin-x", `${(rect.x + rect.w / 2) * 100}%`);
  media.style.setProperty("--wis-camera-zoom-origin-y", `${(rect.y + rect.h / 2) * 100}%`);
  media.style.setProperty("--wis-camera-zoom-scale", String(scale));
}

function installWisCameraZoomSelection(element, streamId) {
  const zoom = state.wisCameraZoomSelections.get(streamId);
  if (!zoom?.selecting) return;
  let start = null;
  let box = null;
  const pointForEvent = (event) => {
    const rect = element.getBoundingClientRect();
    return {
      x: clamp((event.clientX - rect.left) / Math.max(1, rect.width), 0, 1),
      y: clamp((event.clientY - rect.top) / Math.max(1, rect.height), 0, 1),
    };
  };
  const updateBox = (current) => {
    if (!box || !start) return;
    const left = Math.min(start.x, current.x) * 100;
    const top = Math.min(start.y, current.y) * 100;
    const width = Math.abs(current.x - start.x) * 100;
    const height = Math.abs(current.y - start.y) * 100;
    box.style.left = `${left}%`;
    box.style.top = `${top}%`;
    box.style.width = `${width}%`;
    box.style.height = `${height}%`;
  };
  const startSelect = (event) => {
    if (!isPrimaryPointer(event)) return;
    event.preventDefault();
    event.stopPropagation();
    start = pointForEvent(event);
    box = document.createElement("div");
    box.className = "wis-camera-zoom-box";
    element.append(box);
    updateBox(start);
    try {
      element.setPointerCapture(event.pointerId);
    } catch {
      // Pointer capture can be unavailable during rapid touch transitions.
    }
  };
  const moveSelect = (event) => {
    if (!start) return;
    event.preventDefault();
    event.stopPropagation();
    updateBox(pointForEvent(event));
  };
  const endSelect = (event) => {
    if (!start) return;
    event.preventDefault();
    event.stopPropagation();
    const end = pointForEvent(event);
    const rect = {
      x: Math.min(start.x, end.x),
      y: Math.min(start.y, end.y),
      w: Math.abs(end.x - start.x),
      h: Math.abs(end.y - start.y),
    };
    box?.remove();
    start = null;
    try {
      element.releasePointerCapture(event.pointerId);
    } catch {
      // Capture may already be released by the browser.
    }
    if (rect.w < 0.04 || rect.h < 0.04) {
      state.wisCameraZoomSelections.delete(streamId);
      setWisCameraNotice(streamId, "Zoom cancelled", "info");
    } else {
      state.wisCameraZoomSelections.set(streamId, { selecting: false, rect });
      setWisCameraNotice(streamId, "Zoom applied", "success");
    }
    renderWis();
  };
  element.addEventListener("pointerdown", startSelect);
  element.addEventListener("pointermove", moveSelect);
  element.addEventListener("pointerup", endSelect);
  element.addEventListener("pointercancel", () => {
    box?.remove();
    start = null;
  });
}

function renderWisCameraNode(element, node) {
  const slot = wisCameraSlotFromNode(node);
  stopWisCameraTimer(slot);
  const camera = wisCameraConfigForSlot(slot) || node.props?.camera || wisSurfaceState()?.state?.cameras?.[slot] || {};
  const streamId = wisCameraIsPushConfig(camera) ? wisCameraQualityStreamId(slot, camera) : wisCameraBaseStreamId(slot, camera);
  noteWisCameraPerf(state, streamId, "renders");
  element.dataset.wisCameraSlot = slot;
  trackWisCameraVisibility(element, slot, streamId);
  const existingMedia = element.querySelector?.(".wis-camera-video, .wis-camera-image") || null;
  if (existingMedia?.tagName === "IMG") {
    rememberWisCameraLastGoodFrameFromImage(state, streamId, existingMedia, selectedWisCameraTimelineFrame(streamId), {
      ownerKind: existingMedia.dataset?.wisMediaOwner,
      generation: existingMedia.dataset?.wisMediaGeneration,
    });
  }
  const preservePendingRecordedMedia = Boolean(wisCameraIsPushConfig(camera) && selectedWisCameraTimelineFrame(streamId) && existingMedia);
  if (preservePendingRecordedMedia) {
    element.querySelectorAll?.(".wis-camera-message, .wis-camera-fallback")?.forEach((node) => node.remove?.());
  } else {
    if (existingMedia) noteWisCameraPerf(state, streamId, "domReplacements");
    element.replaceChildren();
  }
  const message = (text, tone = "") => {
    const span = document.createElement("span");
    span.className = tone ? `wis-camera-message ${tone}` : "wis-camera-message";
    span.textContent = text;
    element.append(span);
  };
  const showCameraIssue = (text, type = "load-error", issueCamera = camera) => {
    stopWisCameraTimer(slot);
    element.classList.remove("has-camera");
    if (element.querySelector?.(".wis-camera-video, .wis-camera-image")) noteWisCameraPerf(state, streamId, "domReplacements");
    element.replaceChildren();
    const wrapper = document.createElement("div");
    wrapper.className = "wis-camera-fallback";
    const span = document.createElement("span");
    span.className = "wis-camera-message warn";
    span.textContent = text;
    wrapper.append(span);
    element.append(wrapper);
    appendWisCameraRecoveryActions(wrapper, slot, issueCamera);
    if (rememberWisCameraDebugEvent(slot, {
      type,
      mediaMode: issueCamera.mediaMode,
      element: issueCamera.element,
      vendor: issueCamera.vendor,
      mode: issueCamera.mode,
      url: issueCamera.url,
      detail: text,
    })) {
      publishWisCameraDebugSnapshot(slot, { type });
    }
  };
  if (!camera || !camera.kind) {
    message(node.text || node.props?.label || "No feed configured");
    return;
  }
  if (camera.kind === "push" || camera.element === "push-frame" || camera.mediaMode === "rtmp-push-ingest") {
    renderWisCameraPushImage(element, slot, camera, showCameraIssue);
    applyWisCameraZoom(element, streamId);
    installWisCameraZoomSelection(element, streamId);
    return;
  }
  if (camera.kind === "device" || camera.kind === "capture") {
    const stream = state.wisCameraStreams.get(slot);
    if (!stream) {
      message(camera.kind === "capture" ? "DVR tab capture is not active here." : "This device camera is not active here.", "warn");
      if (camera.kind === "capture") {
        appendWisCameraRecoveryActions(element, slot, camera, { includeStream: false });
      }
      return;
    }
    const video = document.createElement("video");
    video.className = "wis-camera-video";
    video.autoplay = true;
    video.muted = wisCameraAudioMuted(streamId);
    video.playsInline = true;
    video.srcObject = stream;
    element.classList.add("has-camera");
    element.append(video);
    applyWisCameraZoom(element, streamId);
    installWisCameraZoomSelection(element, streamId);
    void video.play?.().catch(() => {});
    return;
  }
  if (camera.kind === "url") {
    const url = cleanText(camera.url, "");
    if (!url || url.includes("user:***@")) {
      message("Camera URL is configured on another client.", "warn");
      return;
    }
    if (camera.mediaMode === "rtsp-relay-required") {
      if (wisCameraShouldUseRtspRelay(camera, url)) {
        renderWisCameraRtspRelayImage(element, slot, camera, showCameraIssue);
        return;
      }
      message(camera.vendor === "intelbras"
        ? "Intelbras RTSP saved locally. Needs client publisher or browser-playable URL."
        : "RTSP source needs a client relay or browser-playable URL.", "warn");
      appendWisCameraRecoveryActions(element, slot, camera, { includeStream: false });
      return;
    }
    if (camera.element === "portal" || camera.mediaMode === "dvr-portal") {
      message(camera.vendor === "intelbras" ? "Intelbras DVR portal opens in a browser tab." : "DVR portal opens in a browser tab.", "warn");
      appendWisCameraRecoveryActions(element, slot, camera, { includeStream: false });
      return;
    }
    if (camera.element === "mjpeg-relay" || camera.mediaMode === "mjpeg-stream-relay") {
      renderWisCameraStreamRelayImage(element, slot, camera, showCameraIssue);
      return;
    }
    if (camera.element === "rtsp-relay" || camera.mediaMode === "rtsp-mjpeg-relay") {
      renderWisCameraRtspRelayImage(element, slot, camera, showCameraIssue);
      return;
    }
    if (camera.element === "snapshot-relay" || camera.mediaMode === "jpeg-snapshot-relay") {
      renderWisCameraRelayImage(element, slot, camera, showCameraIssue);
      return;
    }
    if (camera.element === "snapshot" || camera.mediaMode === "jpeg-snapshot-poll") {
      if (wisCameraShouldPromoteSnapshotToRtspRelay(camera, url)) {
        const rtspCamera = intelbrasTrueStreamCameraFromSnapshot(camera, url);
        renderWisCameraRtspRelayImage(element, slot, rtspCamera, (text, type) => showCameraIssue(text, type, rtspCamera));
        return;
      }
      if (wisCameraShouldUseSnapshotRelay(camera, url)) {
        renderWisCameraRelayImage(element, slot, camera, showCameraIssue);
        return;
      }
      const image = document.createElement("img");
      image.className = "wis-camera-image wis-camera-snapshot";
      image.alt = camera.label || slot;
      image.addEventListener("load", () => {
        syncWisCameraAspect(element, image);
        if (rememberWisCameraDebugEvent(slot, {
          type: "snapshot-loaded",
          mediaMode: camera.mediaMode,
          element: camera.element,
          vendor: camera.vendor,
          mode: camera.mode,
          url,
          detail: "Browser loaded the Intelbras JPEG snapshot endpoint.",
        })) {
          publishWisCameraDebugSnapshot(slot, { type: "snapshot-loaded" });
        }
      });
      image.addEventListener("error", () => {
        let text = "Intelbras snapshot did not load from this browser.";
        if (cameraPotentiallyMixedContent(url)) {
          text = "HTTPS cannot embed this HTTP DVR snapshot. Open wasm-agent over local HTTP or enable HTTPS on the DVR.";
        } else if (cameraUrlHasCredentials(url)) {
          text = "Intelbras snapshot did not load. The browser may be blocking embedded DVR credentials, or the snapshot API is disabled.";
        }
        showCameraIssue(text, "snapshot-error");
      }, { once: true });
      const refresh = () => {
        if (!wisCameraBudget(streamId, "live").allowVisualWork) return;
        if (blockLiveWisCameraImageWrite(image, slot, "snapshot-direct")) return;
        image.src = appendCameraCacheBuster(url);
      };
      element.classList.add("has-camera");
      element.append(image);
      refresh();
      scheduleWisCameraTimer(slot, refresh, 2000, { streamId, mode: "live" });
      return;
    }
    if (camera.element === "img") {
      if (wisCameraShouldUseStreamRelay(camera, url)) {
        renderWisCameraStreamRelayImage(element, slot, camera, showCameraIssue);
        return;
      }
      const image = document.createElement("img");
      image.className = "wis-camera-image";
      image.alt = camera.label || slot;
      image.addEventListener("load", () => {
        syncWisCameraAspect(element, image);
        if (rememberWisCameraDebugEvent(slot, {
          type: "image-loaded",
          mediaMode: camera.mediaMode,
          element: camera.element,
          vendor: camera.vendor,
          mode: camera.mode,
          url,
          detail: "Browser loaded the camera image/MJPEG element.",
        })) {
          publishWisCameraDebugSnapshot(slot, { type: "image-loaded" });
        }
      }, { once: true });
      image.addEventListener("error", () => {
        let text = "Camera image/MJPEG did not load from this browser.";
        if (cameraPotentiallyMixedContent(url)) {
          text = "HTTPS cannot embed this HTTP DVR stream. Open wasm-agent over local HTTP or use HTTPS on the DVR.";
        } else if (cameraUrlHasCredentials(url)) {
          text = "Camera image/MJPEG did not load. The browser may be blocking embedded DVR credentials, or this Intelbras endpoint is not enabled.";
        }
        showCameraIssue(text, "image-error");
      }, { once: true });
      if (blockLiveWisCameraImageWrite(image, slot, "image-direct")) return;
      image.src = url;
      element.classList.add("has-camera");
      element.append(image);
      return;
    }
    if (camera.element === "video") {
      const video = document.createElement("video");
      video.className = "wis-camera-video";
      video.controls = true;
      video.autoplay = true;
      video.muted = true;
      video.playsInline = true;
      video.addEventListener("loadeddata", () => {
        syncWisCameraAspect(element, video);
        if (rememberWisCameraDebugEvent(slot, {
          type: "video-loaded",
          mediaMode: camera.mediaMode,
          element: camera.element,
          vendor: camera.vendor,
          mode: camera.mode,
          url,
          detail: "Browser loaded the camera video element.",
        })) {
          publishWisCameraDebugSnapshot(slot, { type: "video-loaded" });
        }
      }, { once: true });
      video.addEventListener("error", () => {
        let text = "Camera video URL did not play in this browser.";
        if (cameraPotentiallyMixedContent(url)) {
          text = "HTTPS cannot embed this HTTP camera stream. Open wasm-agent over local HTTP or use HTTPS on the DVR.";
        }
        showCameraIssue(text, "video-error");
      }, { once: true });
      video.src = url;
      element.classList.add("has-camera");
      element.append(video);
      void video.play?.().catch(() => {});
      return;
    }
  }
  message(camera.label || "Camera source is not playable here.", "warn");
}

function renderWisTreeNode(node) {
  if (!node) return document.createTextNode("");
  let element;
  if (node.type === "document") element = document.createElement("div");
  else if (node.type === "section") element = document.createElement("section");
  else if (node.type === "heading") element = document.createElement(`h${clamp(Number(node.level) || 2, 1, 6)}`);
  else if (node.type === "paragraph") element = document.createElement("p");
  else if (node.type === "text") element = document.createElement("p");
  else if (node.type === "card") element = document.createElement("section");
  else if (node.type === "divider") element = document.createElement("hr");
  else if (node.type === "button") element = document.createElement("button");
  else if (node.type === "input") element = document.createElement("input");
  else if (node.type === "list") element = document.createElement("ul");
  else if (node.type === "list-item") element = document.createElement("li");
  else element = document.createElement("div");

  element.dataset.wisNodeId = node.id || "";
  element.className = wisNodeClass(node.type);
  if (node.role) element.setAttribute("role", node.role);
  const extraClass = String(node.props?.className || "").replace(/[^A-Za-z0-9_ -]/g, "").trim();
  if (extraClass) element.classList.add(...extraClass.split(/\s+/).filter(Boolean));
  if (node.props?.layout === "grid") element.classList.add("wis-layout-grid");

  if (node.type === "button") {
    element.type = "button";
    element.textContent = node.text || node.props?.label || node.id || "Action";
    element.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      if (node.props?.action === "configure_camera") {
        void configureWisCameraSlot(node).catch((error) => {
          state.lastError = error.message || String(error);
          recordUserEvent("wis.camera_config_failed", {
            source: "wis",
            target: `wis:${wisCameraSlotFromNode(node)}`,
            summary: state.lastError,
            data: { slot: wisCameraSlotFromNode(node) },
          });
        });
        return;
      }
      if (node.props?.action === "capture_camera") {
        void captureWisCameraSlot(wisCameraSlotFromNode(node)).catch((error) => {
          state.lastError = error.message || String(error);
        });
        return;
      }
      if (node.props?.action === "snapshot_camera") {
        void tryWisCameraSnapshotSlot(wisCameraSlotFromNode(node)).catch((error) => {
          state.lastError = error.message || String(error);
        });
        return;
      }
      if (node.props?.action === "open_camera_portal") {
        openWisCameraPortalForSlot(wisCameraSlotFromNode(node));
        return;
      }
      if (node.props?.action === "clear_camera") {
        clearWisCameraSlot(wisCameraSlotFromNode(node));
        return;
      }
      if (node.props?.action === "share_camera_access") {
        void publishWisCameraAccessToShared().catch((error) => {
          state.lastError = error.message || String(error);
          window.alert(state.lastError);
        });
        return;
      }
      runWisAction({ type: "click", targetId: node.id }, "surface");
    });
  } else if (node.type === "input") {
    element.type = "text";
    element.value = node.props?.value || "";
    element.placeholder = node.props?.placeholder || "";
    element.setAttribute("aria-label", node.props?.placeholder || node.id || "Input");
    element.addEventListener("input", (event) => {
      runWisAction({ type: "input", targetId: node.id, value: event.target.value }, "surface");
    });
  } else if (node.type === "card" && node.props?.title) {
    const title = document.createElement("strong");
    title.className = "wis-card-title";
    title.textContent = node.props.title;
    element.append(title);
  } else if (node.type === "webcam_placeholder") {
    renderWisCameraNode(element, node);
  } else if (node.text) {
    element.textContent = node.text;
  }

  if (node.type !== "divider") {
    for (const child of node.children || []) element.append(renderWisTreeNode(child));
  }
  return element;
}

function renderWisSmallRow(className, title, meta) {
  const row = document.createElement("div");
  row.className = className;
  const strong = document.createElement("strong");
  const span = document.createElement("span");
  strong.textContent = title;
  span.textContent = meta;
  row.append(strong, span);
  return row;
}

function renderWisExportValue(payload) {
  if (!els.wisExportValue || !payload) return;
  const text = JSON.stringify(payload, null, 2);
  els.wisExportValue.value = text.length > WIS_EXPORT_PREVIEW_LIMIT
    ? `${text.slice(0, WIS_EXPORT_PREVIEW_LIMIT)}\n...`
    : text;
}

function wisCameraToolButton(label, title, onClick, options = {}) {
  return createWisCameraToolButton(document, label, title, onClick, options);
}

function wisCameraAudioAvailable(slot, camera = {}) {
  if (wisCameraIsPushConfig(camera)) return false;
  const stream = state.wisCameraStreams.get(cleanText(slot, ""));
  if (stream?.getAudioTracks?.().length) return true;
  return Boolean(camera.audioAvailable || camera.audio_available || camera.hasAudio || camera.has_audio);
}

function wisCameraAudioMuted(streamId) {
  const key = cleanText(streamId, "cam-1");
  return state.wisCameraAudioMuted.has(key) ? state.wisCameraAudioMuted.get(key) !== false : true;
}

function toggleWisCameraAudio(camera = {}) {
  const slot = cleanText(camera._slot, wisFocusedCameraSlot() || "cam-1");
  const streamId = wisCameraQualityStreamId(slot, camera);
  if (!wisCameraAudioAvailable(slot, camera)) return;
  const muted = !wisCameraAudioMuted(streamId);
  state.wisCameraAudioMuted.set(streamId, muted);
  setWisCameraNotice(streamId, muted ? "Audio muted" : "Audio on", "info");
  renderWis();
}

function toggleWisCameraZoom(camera = {}) {
  const slot = cleanText(camera._slot, wisFocusedCameraSlot() || "cam-1");
  const streamId = wisCameraQualityStreamId(slot, camera);
  const existing = state.wisCameraZoomSelections.get(streamId);
  if (existing?.rect || existing?.selecting) {
    state.wisCameraZoomSelections.delete(streamId);
    setWisCameraNotice(streamId, "Zoom reset", "info");
  } else {
    state.wisCameraZoomSelections.set(streamId, { selecting: true, rect: null });
    setWisCameraNotice(streamId, "Select zoom area", "info", 4000);
  }
  renderWis();
}

function canvasBlob(canvas, type = "image/png", quality = 0.92) {
  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error("Could not encode snapshot."));
    }, type, quality);
  });
}

async function imageBlobAsPng(blob) {
  const bitmap = await createImageBitmap(blob);
  const canvas = document.createElement("canvas");
  canvas.width = Math.max(1, bitmap.width);
  canvas.height = Math.max(1, bitmap.height);
  const ctx = canvas.getContext("2d");
  ctx.drawImage(bitmap, 0, 0);
  bitmap.close?.();
  return canvasBlob(canvas, "image/png");
}

async function copyImageBlobToClipboard(blob) {
  if (!navigator.clipboard?.write || typeof ClipboardItem === "undefined") {
    throw new Error("Image clipboard is not available in this browser.");
  }
  let copyBlob = blob;
  if (blob.type !== "image/png") {
    try {
      copyBlob = await imageBlobAsPng(blob);
    } catch {
      copyBlob = blob;
    }
  }
  await navigator.clipboard.write([new ClipboardItem({ [copyBlob.type || "image/png"]: copyBlob })]);
}

function downloadSnapshotFallback(blob, streamId) {
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = `${cleanText(streamId, "camera")}-snapshot-${Date.now()}.jpg`;
  document.body.append(anchor);
  anchor.click();
  anchor.remove();
  setTimeout(() => URL.revokeObjectURL(url), 2000);
}

async function currentWisCameraSnapshotBlob(slot, camera = {}) {
  const streamId = wisCameraQualityStreamId(slot, camera);
  const media = wisCameraSurfaceElement(slot)?.querySelector(".wis-camera-video, .wis-camera-image");
  if (media) {
    const width = Math.max(1, media.videoWidth || media.naturalWidth || media.clientWidth || 1);
    const height = Math.max(1, media.videoHeight || media.naturalHeight || media.clientHeight || 1);
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext("2d");
    ctx.drawImage(media, 0, 0, width, height);
    return canvasBlob(canvas, "image/png");
  }
  if (wisCameraIsPushConfig(camera)) {
    const selected = selectedWisCameraTimelineFrame(streamId);
    const url = selected?.url || cameraPushFrameUrl(streamId);
    const response = await fetch(cameraCacheBustedUrl(url), { cache: "no-store" });
    if (!response.ok) throw new Error("Current camera frame is not available.");
    return response.blob();
  }
  throw new Error("No visible camera frame is available.");
}

async function copyWisCameraSnapshot(camera = {}) {
  const slot = cleanText(camera._slot, wisFocusedCameraSlot() || "cam-1");
  const streamId = wisCameraQualityStreamId(slot, camera);
  try {
    const blob = await currentWisCameraSnapshotBlob(slot, camera);
    try {
      await copyImageBlobToClipboard(blob);
      setWisCameraNotice(streamId, "Snapshot copied", "success");
    } catch (error) {
      downloadSnapshotFallback(blob, streamId);
      setWisCameraNotice(streamId, "Clipboard blocked; downloaded snapshot", "warn", 4200);
    }
  } catch (error) {
    setWisCameraNotice(streamId, error.message || "Snapshot failed", "warn", 4200);
  }
}

async function toggleWisCameraQuality(camera = {}) {
  const slot = cleanText(camera._slot, wisFocusedCameraSlot() || "cam-1");
  const baseStreamId = wisCameraBaseStreamId(slot, camera);
  const previousActiveStreamId = wisCameraQualityStreamId(slot, camera);
  const previousRecordedSession = recordedWisCameraSession(previousActiveStreamId);
  const preserveRecordedTimestampMs = previousRecordedSession ? wisCameraRecordedClockMs(previousRecordedSession) : 0;
  const currentMode = state.wisCameraQualityModes.get(baseStreamId) || "primary";
  const primed = state.wisCameraQualityPrimed.has(baseStreamId);
  const nextMode = primed && currentMode === "primary" ? "extra" : "primary";
  if (nextMode === "extra") {
    const extraStreamId = cleanText(camera.extraStreamId || camera.extra_stream_id || camera.subStreamId || camera.sub_stream_id, `${baseStreamId}-extra`);
    try {
      const payload = await fetchJson(cameraPushStatusUrl(extraStreamId), { timeoutMs: 5000 });
      if (!payload?.frame?.available) throw new Error("Extra stream is not receiving frames.");
    } catch (error) {
      state.wisCameraQualityPrimed.add(baseStreamId);
      setWisCameraNotice(baseStreamId, error.message || "Extra stream is not available", "warn", 4200);
      renderWisCameraHeader(camera);
      return;
    }
  }
  state.wisCameraQualityPrimed.add(baseStreamId);
  state.wisCameraQualityModes.set(baseStreamId, nextMode);
  const activeStreamId = wisCameraQualityStreamId(slot, camera);
  if (previousRecordedSession) {
    stopWisCameraRecordedSession(previousActiveStreamId);
    state.wisCameraTimelineModes.set(activeStreamId, "recorded");
    if (Number.isFinite(preserveRecordedTimestampMs) && preserveRecordedTimestampMs > 0) {
      setPendingWisCameraTimelineSeek(activeStreamId, {
        ratio: 1,
        targetTime: preserveRecordedTimestampMs,
        playbackPosition: preserveRecordedTimestampMs,
      }, "recorded");
    }
  }
  state.wisCameraTimelineSelections.delete(baseStreamId);
  state.wisCameraTimelineSelections.delete(activeStreamId);
  stopWisCameraTimer(baseStreamId);
  stopWisCameraTimer(activeStreamId);
  setWisCameraNotice(baseStreamId, nextMode === "extra" ? "Extra quality" : "Principal quality", "info");
  renderWis();
}

function renderWisCameraHeader(camera = null) {
  const widget = widgetById("wis");
  if (!widget) return;
  const actions = widget.querySelector(".widget-head-actions");
  if (!actions) return;
  if (!camera) {
    renderWisCameraArtifactHeader({
      documentRef: document,
      actionsElement: actions,
      configButton: els.wisCameraConfigButton,
      camera: null,
    });
    return;
  }
  const slot = cleanText(camera._slot, wisFocusedCameraSlot() || "cam-1");
  const isPush = wisCameraIsPushConfig(camera);
  const streamId = isPush ? wisCameraQualityStreamId(slot, camera) : wisCameraBaseStreamId(slot, camera);
  const baseStreamId = wisCameraBaseStreamId(slot, camera);
  renderWisCameraArtifactHeader({
    documentRef: document,
    actionsElement: actions,
    configButton: els.wisCameraConfigButton,
    camera,
    slot,
    streamId,
    baseStreamId,
    isPush,
    zoom: state.wisCameraZoomSelections.get(streamId),
    notice: currentWisCameraNotice(streamId) || currentWisCameraNotice(baseStreamId),
    muted: wisCameraAudioMuted(streamId),
    audioAvailable: wisCameraAudioAvailable(slot, camera),
    qualityMode: wisCameraQualityMode(baseStreamId),
    controlsInTimeline: true,
    onConfigure: (targetCamera) => void configureWisCameraSlot({ id: `${slot}-header-config`, props: { slot, data: { slot }, camera: targetCamera } }).catch((error) => {
      state.lastError = error.message || String(error);
      recordUserEvent("wis.camera_header_config_failed", {
        source: "wis",
        target: `wis:${slot}`,
        summary: state.lastError,
        data: { slot },
      });
    }),
    onToggleZoom: toggleWisCameraZoom,
    onCopySnapshot: (targetCamera) => void copyWisCameraSnapshot(targetCamera),
    onToggleAudio: toggleWisCameraAudio,
    onToggleQuality: (targetCamera) => void toggleWisCameraQuality(targetCamera),
  });
}

function formatCameraTimelineRange(range = null, mode = "live") {
  return formatWisCameraTimelineRange(range, mode);
}

function renderWisCameraTimelineFooter(camera = null) {
  const widget = widgetById("wis");
  if (!widget) return;
  let footer = widget.querySelector(".wis-camera-timeline");
  const slot = camera ? cleanText(camera._slot, wisFocusedCameraSlot() || "cam-1") : "";
  const streamId = camera ? wisCameraQualityStreamId(slot, camera) : "";
  const show = wisCameraIsPushConfig(camera || {}) && streamId;
	  if (!show) {
	    footer?.remove();
	    return;
	  }
	  footer?.setAttribute?.("data-camera-artifact-build", WIS_CAMERA_ARTIFACT_BUILD);
	  if (!footer) {
	    footer = document.createElement("div");
	    footer.className = "wis-camera-timeline";
	    footer.dataset.cameraArtifactBuild = WIS_CAMERA_ARTIFACT_BUILD;
	    const keepTimelineInteractionInWidget = (event) => {
      if (event.type === "pointerdown" || event.type === "click") bringWidgetForward(widget);
      const target = event.target;
      const handledByTimelineControl = Boolean(target?.closest?.(".wis-camera-timeline-scrubber, .wis-camera-timeline-controls-row, .wis-camera-timeline-actions"));
      const playPauseTarget = target?.closest?.("[data-wis-camera-control='play-pause']");
      if (playPauseTarget && (event.type === "pointerdown" || event.type === "click")) {
        traceWisCameraBoundary(`controls.playpause.footer.${event.type}`, wisCameraPlaybackTracePayload(playPauseTarget.dataset?.wisCameraStreamId || streamId, {
          control: "play-pause",
          action: cleanText(playPauseTarget.dataset?.wisCameraAction, ""),
          target: wisCameraControlTargetSummary(playPauseTarget),
          footerStreamId: streamId,
        }));
      }
      if (event.type === "pointerdown" || event.type === "keydown" || event.type === "click") {
        if (!handledByTimelineControl) maybeLoadFocusedWisCameraTimeline("timeline-interaction");
      }
      event.stopPropagation();
    };
    ["pointerdown", "pointermove", "pointerup", "pointercancel", "click", "dblclick", "wheel", "keydown", "input", "change"].forEach((type) => {
      footer.addEventListener(type, keepTimelineInteractionInWidget);
    });
  }
  const surface = widget.querySelector(".wis-surface");
  if (surface && footer.parentElement !== surface) surface.append(footer);
  syncWisCameraTimelineVisibility(widget);
  const activeScrubber = streamId
    ? footer.querySelector?.(`.wis-camera-timeline-scrubber[data-stream-id="${CSS.escape(streamId)}"].is-scrubbing`)
    : null;
  if (activeScrubber?.isConnected) {
    logWisCameraMediaEvent("camera.timeline.attach.deferred_during_scrub", {
      streamId,
      generation: Number(recordedWisCameraSession(streamId)?.generation || 0),
      elementConnected: true,
    }, { sampleMs: 1000 });
    return;
  }
  const mode = wisCameraTimelineMode(streamId);
  if (wisCameraTimelineWidgetActive(widget)) scheduleWisCameraTimelineLoad(streamId, "footer-render", mode);
  const timeline = state.wisCameraTimeline.streamId === streamId ? state.wisCameraTimeline : {
    streamId,
    mode,
    day: "",
    frames: [],
    range: null,
    availableRange: null,
    loadedAt: 0,
    loading: false,
    error: "",
  };
  const frames = timeline.frames || [];
  const cameraPlaybackController = wisCameraPlaybackController(streamId);
  const recordedSession = recordedWisCameraSession(streamId);
  const playPauseState = wisCameraPlayPauseStateForStream(streamId, {
    controller: cameraPlaybackController,
    session: recordedSession,
  });
  const selected = recordedSession?.frame || selectedWisCameraTimelineFrame(streamId);
  const footerSignature = [
    streamId,
    mode,
    Number(timeline.loadedAt || 0),
    timeline.loading ? "loading" : "ready",
    cleanText(timeline.error, ""),
    frames.length,
    cleanText(recordedSession?.id, ""),
    cleanText(recordedSession?.status, ""),
    recordedSession?.clockPaused ? "paused" : "running",
    playPauseState.owner,
    playPauseState.mode,
    playPauseState.action,
    playPauseState.icon,
    playPauseState.disabledReason,
    wisCameraQualityMode(wisCameraBaseStreamId(slot || streamId, camera)),
    state.wisCameraZoomSelections.has(streamId) ? "zoom" : "nozoom",
    wisCameraAudioMuted(streamId) ? "muted" : "audio",
    cleanText(selected?.id, ""),
  ].join("|");
  const existingScrubber = footer.querySelector?.(`.wis-camera-timeline-scrubber[data-stream-id="${CSS.escape(streamId)}"]`);
  if (existingScrubber && footer.dataset.wisTimelineSignature === footerSignature) {
    cameraPlaybackController?.configure?.({
      timelineElement: existingScrubber,
      timeline,
      frames,
      mode,
    });
    updateWisCameraRecordedPlaybackUi(streamId);
    return;
  }
  const playbackClockMs = recordedSession ? wisCameraRecordedClockMs(recordedSession) : 0;
  const selectedIndex = selected?.id
    ? frames.findIndex((frame) => frame.id === selected.id)
    : frames.length - 1;
  const actualIndex = Math.max(0, selectedIndex);
  const currentFrame = frames[actualIndex] || null;
  const committedTimelineTitle = () => {
    const activeSession = recordedWisCameraSession(streamId);
    if (activeSession) return wisCameraRecordedTimelineTitle(activeSession, wisCameraRecordedClockMs(activeSession));
    const activeSelected = selectedWisCameraTimelineFrame(streamId);
    if (activeSelected?.id) return `Viewing ${cameraTimelineFrameLabel(activeSelected)}`;
    return wisCameraTimelineMode(streamId) === "recorded" ? "Recorded footage" : "Live";
  };
  const label = committedTimelineTitle();
  const meta = document.createElement("div");
  meta.className = "wis-camera-timeline-meta";
  const title = document.createElement("span");
  title.className = "wis-camera-timeline-title";
  title.textContent = label;
	  const detail = document.createElement("span");
	  detail.textContent = timeline.error
	    ? timeline.error
	    : `${formatCameraTimelineRange(timeline.range || timeline.availableRange, mode)}${frames.length ? ` / ${frames.length} points` : ""} / ${WIS_CAMERA_ARTIFACT_BUILD}`;
	  meta.append(title, detail);

  const maxFrameIndex = Math.max(0, frames.length - 1);
  const timelineWindow = wisCameraTimelineTimeWindow(timeline, frames, {
    playbackPosition: playbackClockMs || Number(selected?.timestamp_ms || currentFrame?.timestamp_ms || 0),
  });
  const { visibleStart, visibleEnd } = timelineWindow;
  const hasVisibleTimelineWindow = visibleEnd > visibleStart;
  const scrubber = document.createElement("div");
  scrubber.className = "wis-camera-timeline-scrubber";
  scrubber.setAttribute("role", "slider");
  scrubber.tabIndex = frames.length ? 0 : -1;
  scrubber.setAttribute("aria-label", "Camera timeline point");
  scrubber.dataset.streamId = streamId;
  scrubber.setAttribute("aria-valuemin", "0");
  scrubber.setAttribute("aria-valuemax", String(maxFrameIndex));
  scrubber.setAttribute("aria-disabled", frames.length ? "false" : "true");
  const rail = document.createElement("span");
  rail.className = "wis-camera-timeline-rail";
  const fill = document.createElement("span");
  fill.className = "wis-camera-timeline-fill";
  scrubber.append(rail, fill);
  let previewTimelineIndex = actualIndex;
  const progressForTimelineTime = (timestampMs = 0, fallbackIndex = previewTimelineIndex) => {
    const timeMs = Number(timestampMs);
    if (Number.isFinite(timeMs) && hasVisibleTimelineWindow) {
      return clamp(((timeMs - visibleStart) / (visibleEnd - visibleStart)) * 100, 0, 100);
    }
    return maxFrameIndex > 0 ? (fallbackIndex / maxFrameIndex) * 100 : 100;
  };
  const previewTimelineFrame = (index = previewTimelineIndex, displayTimeMs = null, options = {}) => {
    previewTimelineIndex = clamp(Math.round(Number(index) || 0), 0, maxFrameIndex);
    const frame = frames[previewTimelineIndex] || null;
    const timestampMs = Number(displayTimeMs ?? wisCameraTimelinePlaybackStartMs(frame, frame?.timestamp_ms ?? frame?.timestampMs));
    const progress = frame ? progressForTimelineTime(timestampMs, previewTimelineIndex) : 100;
    scrubber.style.setProperty("--wis-camera-timeline-progress", `${progress}%`);
    scrubber.style.removeProperty("--wis-camera-timeline-preview");
    delete scrubber.dataset.wisTimelinePreviewing;
    scrubber.setAttribute("aria-valuenow", String(previewTimelineIndex));
    const labelFrame = Number.isFinite(timestampMs) ? { ...(frame || {}), timestamp_ms: timestampMs } : frame;
    scrubber.setAttribute("aria-valuetext", labelFrame ? cameraTimelineFrameLabel(labelFrame) : "No points yet");
    if (options.updateTitle !== false) {
      title.textContent = labelFrame ? `Point ${cameraTimelineFrameLabel(labelFrame)}` : "No points yet";
    }
  };
  previewTimelineFrame(actualIndex, null, { updateTitle: false });

  const controlsRow = document.createElement("div");
  controlsRow.className = "wis-camera-timeline-controls-row";
  controlsRow.dataset.wisCameraTimelineControls = "1";
  controlsRow.dataset.streamId = streamId;
  const activeZoom = Boolean(state.wisCameraZoomSelections.get(streamId)?.rect || state.wisCameraZoomSelections.get(streamId)?.selecting);
  const playPause = wisCameraToolButton(playPauseState.label, playPauseState.title, (event) => {
    toggleWisCameraRecordedPlayback({ ...camera, _slot: slot || streamId }, event);
  }, {
    icon: playPauseState.icon,
    control: "play-pause",
    streamId,
    slot: slot || streamId,
    action: playPauseState.action,
    active: playPauseState.playing,
    pressed: playPauseState.playing,
    traceEvent: (kind, button, event) => traceWisCameraPlayPauseButtonEvent(kind, streamId, button, event),
  });
  if (playPauseState.disabledReason) {
    playPause.setAttribute("aria-disabled", "true");
    playPause.dataset.wisCameraDisabledReason = playPauseState.disabledReason;
    playPause.classList.add("is-disabled");
  }
  traceWisCameraBoundary("controls.playpause.buttonRendered", wisCameraPlaybackTracePayload(streamId, wisCameraPlayPauseTraceContext(playPauseState, {
    control: "play-pause",
    action: playPauseState.action,
    slot: slot || streamId,
    disabled: Boolean(playPause.disabled),
    ariaDisabled: cleanText(playPause.getAttribute("aria-disabled"), ""),
    icon: playPauseState.icon,
    title: cleanText(playPause.title, ""),
  })));
  const zoomButton = wisCameraToolButton(activeZoom ? "Reset" : "Zoom", activeZoom ? "Reset zoom" : "Select zoom area", () => {
    toggleWisCameraZoom({ ...camera, _slot: slot || streamId });
  }, { icon: "zoom", control: "zoom", streamId, slot: slot || streamId, action: activeZoom ? "reset" : "select", active: activeZoom, pressed: activeZoom });
  const snapshotButton = wisCameraToolButton("Snap", "Copy snapshot", () => {
    void copyWisCameraSnapshot({ ...camera, _slot: slot || streamId });
  }, { icon: "snapshot", control: "snapshot", streamId, slot: slot || streamId, action: "copy" });
  const audioAvailable = wisCameraAudioAvailable(slot || streamId, camera);
  const muted = wisCameraAudioMuted(streamId);
  const audioButton = wisCameraToolButton(muted ? "Muted" : "Audio", audioAvailable ? (muted ? "Turn audio on" : "Mute audio") : "No audio available", () => {
    toggleWisCameraAudio({ ...camera, _slot: slot || streamId });
  }, {
    icon: muted ? "muted" : "audio",
    control: "audio",
    streamId,
    slot: slot || streamId,
    action: muted ? "unmute" : "mute",
    disabled: !audioAvailable,
    active: audioAvailable && !muted,
    pressed: audioAvailable && !muted,
  });
  const baseStreamId = wisCameraBaseStreamId(slot || streamId, camera);
  const qualityMode = wisCameraQualityMode(baseStreamId);
  const qualityButton = wisCameraToolButton(qualityMode === "extra" ? "Extra" : "Main", "Toggle main/extra stream quality", () => {
    void toggleWisCameraQuality({ ...camera, _slot: slot || streamId });
  }, { icon: "quality", control: "quality", streamId, slot: slot || streamId, action: qualityMode === "extra" ? "primary" : "extra", active: true, pressed: qualityMode === "extra" });
  const traceButton = wisCameraToolButton("Trace", "Copy Camera Trace", () => {
    void copyWisCameraTraceDump(streamId);
  }, { icon: "trace", control: "copy-trace", streamId, slot: slot || streamId, action: "copy" });
  const live = wisCameraToolButton(recordedSession ? "Return to live" : "Live", recordedSession ? "Return to live camera" : "Use live last 10 minutes", () => {
    returnWisCameraToLive(streamId);
  }, { icon: "live", control: "live", streamId, slot: slot || streamId, action: "live", active: mode === "live" && !recordedSession, pressed: mode === "live" && !selected && !recordedSession });
  const recorded = wisCameraToolButton(timeline.loading && mode === "recorded" ? "Detecting" : "Recorded", "Detect recorded footage range", () => {
    setWisCameraTimelineMode(streamId, "recorded");
  }, { icon: "recorded", control: "recorded", streamId, slot: slot || streamId, action: "recorded", active: mode === "recorded" || Boolean(recordedSession), pressed: mode === "recorded" || Boolean(recordedSession), disabled: Boolean(timeline.loading && mode === "recorded") });
  controlsRow.append(playPause, zoomButton, snapshotButton, qualityButton, audioButton, traceButton, recorded, live);

	  footer.dataset.wisTimelineSignature = footerSignature;
	  footer.dataset.cameraArtifactBuild = WIS_CAMERA_ARTIFACT_BUILD;
	  noteWisCameraPerf(state, streamId, "timelinePatches");
  footer.replaceChildren(meta, controlsRow, scrubber);
  cameraPlaybackController?.configure?.({
    timelineElement: scrubber,
    timeline,
    frames,
    mode,
  });
}

function renderWis() {
  if (!els.wisViewport) return;
  installWisAutomationHook();
  if (!isModuleEnabled("wis")) {
    widgetById("wis")?.classList.remove("is-camera-artifact");
    renderWisCameraHeader(null);
    renderWisCameraTimelineFooter(null);
    if (els.wisStatus) {
      els.wisStatus.hidden = false;
      els.wisStatus.textContent = "off";
    }
    if (els.wisCameraConfigButton) els.wisCameraConfigButton.hidden = true;
    els.wisViewport.replaceChildren();
    els.wisNodeList?.replaceChildren();
    els.wisEventList?.replaceChildren();
    if (els.wisAutomationState) els.wisAutomationState.textContent = "";
    return;
  }

  const snapshot = wisSurfaceState();
  if (!snapshot) return;
  if (!state.wisLastExport) state.wisLastExport = state.wisSandbox.exportSpace();
  const focus = wisFocusState();
  const focusedCamera = wisSurfaceIsFocusedCamera(snapshot);
  const focusedSlot = wisFocusedCameraSlot(snapshot) || "cam-1";
  const focusedCameraConfig = focusedCamera ? { ...wisCameraConfigForSlot(focusedSlot), _slot: focusedSlot } : {};
  const focusedStreamId = focusedCamera && wisCameraIsPushConfig(focusedCameraConfig)
    ? wisCameraQualityStreamId(focusedSlot, focusedCameraConfig)
    : "";
  const focusedRecordedSession = focusedStreamId ? recordedWisCameraSession(focusedStreamId) : null;
  const wisWidget = widgetById("wis");
  wisWidget?.classList.toggle("is-camera-artifact", focusedCamera);
  if (wisWidget) {
    if (focusedCamera) wisWidget.tabIndex = 0;
    else wisWidget.removeAttribute("tabindex");
  }
  if (els.wisStatus) {
    els.wisStatus.hidden = focusedCamera;
    if (!focusedCamera) els.wisStatus.textContent = snapshot.sandbox.status || "sandbox";
  }
  if (els.wisCameraConfigButton) els.wisCameraConfigButton.hidden = true;
  renderWisCameraHeader(focusedCamera ? focusedCameraConfig : null);
  renderWisCameraTimelineFooter(focusedCamera ? focusedCameraConfig : null);
  if (els.wisLocation) els.wisLocation.textContent = snapshot.navigation.url || snapshot.document?.id || "";
  if (els.wisDocumentId) els.wisDocumentId.textContent = snapshot.document?.id || "-";
  if (els.wisNodeCount) els.wisNodeCount.textContent = String(snapshot.nodeCount || 0);
  if (els.wisElementCount) els.wisElementCount.textContent = String(snapshot.elementCount || 0);
  if (els.wisSandboxStatus) {
    const permissions = snapshot.sandbox.permissions || {};
    els.wisSandboxStatus.textContent = [
      snapshot.sandbox.status || "isolated",
      permissions.backend === false ? "backend off" : "backend on",
      permissions.iframe === false ? "iframe off" : "iframe on",
    ].join(" / ");
  }

  const recordedPlaybackDom = focusedRecordedSession?.id
    ? els.wisViewport.querySelector(`[data-wis-recorded-session-id="${CSS.escape(focusedRecordedSession.id)}"]`)
    : null;
  if (recordedPlaybackDom) {
    updateWisCameraRecordedPlaybackUi(focusedStreamId);
  } else {
    els.wisViewport.replaceChildren(renderWisTreeNode(snapshot.tree));
  }
  restoreWisFocus(focus);

  els.wisNodeList?.replaceChildren(
    ...snapshot.nodes.slice(0, 14).map((node) => (
      renderWisSmallRow("wis-node-row", node.id || node.type, `${node.type}${node.child_count ? ` / ${node.child_count}` : ""}`)
    ))
  );
  els.wisEventList?.replaceChildren(
    ...snapshot.recentEvents.slice(0, 8).map((event) => (
      renderWisSmallRow("wis-event-row", event.type, `${event.target || "surface"} / ${new Date(event.timestamp).toLocaleTimeString()}`)
    ))
  );
  if (els.wisAutomationState) {
    els.wisAutomationState.textContent = JSON.stringify({
      schema: snapshot.schema,
      document: snapshot.document,
      state: snapshot.state,
      actions: snapshot.automation.actions.slice(0, 10),
      inspect: snapshot.automation.inspect,
      act: snapshot.automation.act,
    }, null, 2);
  }
  renderWisExportValue(state.wisLastExport);
}

function moduleCard(module) {
  const enabled = isModuleEnabled(module.id);
  const core = Boolean(module.core);
  const unavailable = !moduleServerAvailable(module.id);
  const card = document.createElement("article");
  card.className = `module-card${enabled ? " enabled" : ""}${core ? " core" : ""}${unavailable ? " unavailable" : ""}`;

  const copy = document.createElement("div");
  copy.className = "module-copy";
  const title = document.createElement("strong");
  title.textContent = module.title;
  const detail = document.createElement("p");
  detail.textContent = module.detail;
  const meta = document.createElement("span");
  meta.textContent = module.status;
  copy.append(title, detail, meta);

  const label = document.createElement("label");
  label.className = "module-toggle";
  const input = document.createElement("input");
  input.type = "checkbox";
  input.checked = enabled;
  input.disabled = core || unavailable;
  input.setAttribute("aria-label", `${enabled ? "Disable" : "Enable"} ${module.title}`);
  const control = document.createElement("span");
  control.textContent = unavailable ? "Unavailable" : (core ? "Core" : (enabled ? "On" : "Off"));
  input.addEventListener("change", () => {
    setModuleEnabled(module.id, input.checked);
  });
  label.append(input, control);

  card.append(copy, label);
  return card;
}

function renderModuleList(container) {
  if (!container) return;
  container.replaceChildren(...MODULE_DEFINITIONS.map(moduleCard));
}

function renderModules() {
  renderModuleList(els.moduleList);
  renderModuleList(els.homeModuleList);
}

function renderTimeline() {
  if (!els.timelineGraph || !els.timelineDetails) return;
  const timeline = state.timeline;
  if (!isModuleEnabled("timeline")) {
    els.timelineStatus.textContent = "off";
    els.timelineGraph.replaceChildren();
    els.timelineDetails.replaceChildren(metric("Module", "Disabled"));
    return;
  }
  if (!timeline) {
    els.timelineStatus.textContent = "pending";
    els.timelineGraph.replaceChildren(metric("Timeline", "Not loaded"));
    els.timelineDetails.replaceChildren(metric("Status", "Refresh timeline"));
    return;
  }
  els.timelineStatus.textContent = timeline.dirty ? `${timeline.dirty_count} dirty` : "clean";
  els.timelineStatus.className = `widget-chip ${timeline.dirty ? "" : "ok"}`;
  els.timelineBranch.textContent = timeline.branch || "branch";
  const recent = (timeline.recent || []).slice(0, 5);
  const checkpoints = (timeline.checkpoints || []).slice(0, 5);
  els.timelineGraph.replaceChildren(
    ...[
      ...checkpoints.map((checkpoint) => ({ kind: "checkpoint", label: checkpoint.name, meta: checkpoint.head, checkpoint })),
      ...recent.map((line) => ({ kind: "commit", label: line, meta: "" })),
    ].slice(0, 7).map((item) => {
      const row = document.createElement("div");
      row.className = `timeline-node ${item.kind}`;
      const dot = document.createElement("span");
      dot.className = "timeline-dot";
      const copy = document.createElement("div");
      const title = document.createElement("strong");
      title.textContent = item.label;
      const meta = document.createElement("span");
      meta.textContent = item.meta || item.kind;
      copy.append(title, meta);
      if (item.checkpoint?.ref) {
        const action = document.createElement("button");
        action.type = "button";
        action.className = "timeline-stepback-button";
        action.textContent = "Stepback";
        action.title = "Restore to the point before this checkpoint run";
        action.addEventListener("click", (event) => {
          event.preventDefault();
          event.stopPropagation();
          void stepbackTimeline(item.checkpoint.ref, timeline.timeline_id || activeSpaceStorageId());
        });
        row.append(dot, copy, action);
        return row;
      }
      row.append(dot, copy);
      return row;
    })
  );
  const actionRows = (timeline.actions || []).map((action) => [
    action.label,
    action.enabled ? action.description : `${action.description} (planned)`,
  ]);
  els.timelineDetails.replaceChildren(
    metric("Branch", `${timeline.branch} @ ${timeline.head}`),
    metric("Worktree", timeline.dirty ? `${timeline.dirty_count} changed paths` : "Clean"),
    metric("Checkpoints", String(timeline.checkpoints?.length || 0)),
    ...actionRows.map(([label, value]) => metric(label, value))
  );
}

async function loadTimeline(origin = "auto") {
  if (!isModuleEnabled("timeline") || state.timelineBusy) return;
  state.timelineBusy = true;
  if (els.timelineRefreshButton) els.timelineRefreshButton.disabled = true;
  const startedAt = performance.now();
  try {
    const payload = await fetchJson(`/timeline/status?space=${encodeURIComponent(activeSpaceStorageId())}`, { timeoutMs: 10000 });
    state.timeline = payload.timeline || null;
    renderTimeline();
    if (origin !== "auto") {
      recordUserEvent("timeline.loaded", {
        target: "timeline",
        summary: `Loaded ${state.timeline?.branch || "timeline"} at ${state.timeline?.head || "head"}`,
        data: { dirty: state.timeline?.dirty, dirty_count: state.timeline?.dirty_count },
        duration_ms: performance.now() - startedAt,
      });
    }
  } catch (error) {
    state.lastError = error.message;
    if (els.timelineStatus) {
      els.timelineStatus.textContent = "error";
      els.timelineStatus.className = "widget-chip err";
    }
    recordUserEvent("timeline.load_error", {
      target: "timeline",
      summary: error.message,
      data: { error: error.message },
      duration_ms: performance.now() - startedAt,
    });
  } finally {
    state.timelineBusy = false;
    if (els.timelineRefreshButton) els.timelineRefreshButton.disabled = false;
  }
}

function applyModuleVisibility() {
  document.querySelectorAll("[data-module-target]").forEach((element) => {
    const moduleId = element.dataset.moduleTarget;
    const enabled = isModuleEnabled(moduleId);
    element.hidden = !enabled;
    element.classList.toggle("module-disabled", !enabled);
  });
  if (!isModuleEnabled("embedded-assistant")) setAgentOpen(false);
  if (!isModuleEnabled("host-browser")) {
    if (isBrowserStreamOpen() || state.browserLive) stopBrowserLive();
    els.browserScreen.classList.remove("is-busy");
  }
  if (!isPanelAvailable(state.activePanel)) setPanel("modules");
}

function setModuleEnabled(moduleId, enabled) {
  if (!moduleServerAvailable(moduleId)) {
    renderModules();
    applyModuleVisibility();
    return;
  }
  if (moduleDefinitionById(moduleId)?.core) {
    state.moduleSettings[moduleId] = true;
    renderModules();
    return;
  }
  const previous = isModuleEnabled(moduleId);
  state.moduleSettings[moduleId] = Boolean(enabled);
  saveModuleSettings();
  applyModuleVisibility();
  renderModules();
  renderObservation();
  if (previous !== Boolean(enabled)) {
    recordUserEvent("modules.setting_changed", {
      target: `module:${moduleId}`,
      summary: `${enabled ? "Enabled" : "Disabled"} ${moduleId}`,
      data: { module_id: moduleId, enabled: Boolean(enabled) },
    });
  }
}

function percent(value) {
  const number = Number(value);
  if (!Number.isFinite(number)) return 0;
  return Math.max(0, Math.min(100, number));
}

function bytes(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return "-";
  const units = ["B", "KB", "MB", "GB", "TB"];
  let size = number;
  let unit = 0;
  while (size >= 1024 && unit < units.length - 1) {
    size /= 1024;
    unit += 1;
  }
  return `${size.toFixed(size >= 10 ? 0 : 1)} ${units[unit]}`;
}

function compactCount(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number < 0) return "-";
  if (number >= 1_000_000_000) return `${(number / 1_000_000_000).toFixed(1)}B`;
  if (number >= 1_000_000) return `${(number / 1_000_000).toFixed(1)}M`;
  if (number >= 1_000) return `${(number / 1_000).toFixed(1)}K`;
  return String(Math.round(number));
}

function formatCost(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return "$0";
  if (number < 0.01) return `<$0.01`;
  return `$${number.toFixed(2)}`;
}

function formatSignedCount(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return "";
  return `+${compactCount(number)}`;
}

function compactGb(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return "-";
  const gb = number / (1024 ** 3);
  return `${gb.toFixed(1).replace(".", ",")}GB`;
}

function activeSpaceStorageId(panel = state.activePanel) {
  if (isUserSpacePanel(panel)) return panel;
  if (isAdminPanel(panel)) return "admin";
  return "home";
}

function activeSpaceContext(panel = state.activePanel) {
  const normalized = normalizePanel(panel);
  const storageId = activeSpaceStorageId(normalized);
  const userSpace = userSpaceById(normalized);
  const sharedSpaceId = cleanText(userSpace?.shared_space_id || "", "");
  const room = sharedSpaceId ? state.sharedRooms[sharedSpaceId] : null;
  const name = normalized === "home"
    ? "space-home"
    : isAdminPanel(normalized)
      ? "space-admin"
      : cleanText(userSpace?.title || normalized, normalized);
  const displayName = activeSpaceTitle(normalized);
  return {
    id: storageId,
    storage_id: storageId,
    panel: normalized,
    kind: normalized === "home" ? "home" : isAdminPanel(normalized) ? "admin" : "user",
    name,
    title: name,
    display_name: displayName,
    shared: Boolean(userSpace?.shared || sharedSpaceId),
    shared_space_id: sharedSpaceId,
    room: room ? {
      id: room.id || sharedSpaceId,
      online_count: Number(room.online_count || 0),
      member_count: Number(room.member_count || 0),
      online_device_count: Number(room.online_device_count || 0),
    } : null,
  };
}

function defaultWidgetLayoutForPanel(panel = state.activePanel) {
  return {
    ...Object.fromEntries(spaceApps(panel).map((app) => [app.id, { minimized: true }])),
    ...FIXED_WIDGET_LAYOUT,
  };
}

function layoutKeysForPanel(panel = state.activePanel) {
  return new Set([
    "__canvas",
    ...spaceApps(panel).map((app) => app.id),
    ...Object.keys(FIXED_WIDGET_LAYOUT),
  ]);
}

function sanitizeWidgetLayoutForPanel(layout, panel = state.activePanel) {
  if (!layout || typeof layout !== "object") return {};
  const allowedKeys = layoutKeysForPanel(panel);
  return Object.fromEntries(
    Object.entries(layout).filter(([key]) => allowedKeys.has(key))
  );
}

function saveWidgetLayout() {
  const spaceId = activeSpaceStorageId();
  state.widgetLayout = sanitizeWidgetLayoutForPanel(state.widgetLayout);
  state.spaceWidgetLayouts[spaceId] = state.widgetLayout;
  saveLocalSpaceWidgetLayouts();
}

function applySpaceWidgetLayout(panel = state.activePanel) {
  const spaceId = activeSpaceStorageId(panel);
  const layout = state.spaceWidgetLayouts[spaceId];
  state.widgetLayout = {
    ...defaultWidgetLayoutForPanel(panel),
    ...sanitizeWidgetLayoutForPanel(layout, panel),
  };
  const metadataArea = userSpaceAreaForPanel(panel);
  const area = metadataArea
    ? writeCanvasAreaSize(canvasLayout(), metadataArea)
    : canvasAreaSize();
  if (!metadataArea) syncSpaceAreaMetadata(panel, area);
  applyCanvasGeometry({ renderMiniMap: false });
  applyWidgetLayout();
  if (isAndroidNativeShell()) scheduleAndroidSpaceMiniMapRender("panel");
  else renderSpaceMiniMap();
}

function defaultModuleSettings() {
  return {
    ...Object.fromEntries(MODULE_DEFINITIONS.map((module) => [module.id, module.defaultEnabled !== false])),
    __imageAnalyzerRevision: IMAGE_CARD_ANALYZER_REVISION,
  };
}

function readModuleSettings() {
  const defaults = defaultModuleSettings();
  try {
    const raw = JSON.parse(localStorage.getItem(MODULE_SETTINGS_STORAGE_KEY) || "{}");
    if (!raw || typeof raw !== "object") return defaults;
    const knownModuleIds = new Set(MODULE_DEFINITIONS.map((module) => module.id));
    const stored = Object.fromEntries(
      Object.entries(raw)
        .filter(([key]) => knownModuleIds.has(key))
        .map(([key, value]) => [key, Boolean(value)])
    );
    for (const module of MODULE_DEFINITIONS) {
      if (module.core) stored[module.id] = true;
    }
    const settings = { ...defaults, ...stored };
    if (raw.__imageAnalyzerRevision !== IMAGE_CARD_ANALYZER_REVISION) {
      for (const moduleId of ["image-card-core", "barcode-reader", "ocr"]) {
        settings[moduleId] = defaults[moduleId] !== false;
      }
    }
    settings.__imageAnalyzerRevision = IMAGE_CARD_ANALYZER_REVISION;
    return settings;
  } catch {
    return defaults;
  }
}

function saveModuleSettings() {
  try {
    localStorage.setItem(MODULE_SETTINGS_STORAGE_KEY, JSON.stringify({
      ...state.moduleSettings,
      __imageAnalyzerRevision: IMAGE_CARD_ANALYZER_REVISION,
    }));
  } catch {
    // Module settings are local convenience state; defaults keep the app usable.
  }
}

function readLauncherPreference() {
  try {
    const raw = JSON.parse(localStorage.getItem(LAUNCHER_PREF_STORAGE_KEY) || "{}");
    return Boolean(raw?.mobileTop);
  } catch {
    return false;
  }
}

function saveLauncherPreference() {
  try {
    localStorage.setItem(LAUNCHER_PREF_STORAGE_KEY, JSON.stringify({ mobileTop: Boolean(state.mobileLauncherTop) }));
  } catch {
    // Launcher placement is local UI preference; defaults keep navigation available.
  }
}

function readLocalSpaceWidgetLayouts() {
  try {
    const raw = JSON.parse(localStorage.getItem(SPACE_WIDGET_LAYOUTS_STORAGE_KEY) || "{}");
    if (!raw || typeof raw !== "object") return {};
    return Object.fromEntries(
      Object.entries(raw).filter(([, layout]) => layout && typeof layout === "object")
    );
  } catch {
    return {};
  }
}

function readWisCameraConfigs() {
  return readWisCameraArtifactConfigs(localStorage);
}

function saveLocalSpaceWidgetLayouts() {
  try {
    localStorage.setItem(SPACE_WIDGET_LAYOUTS_STORAGE_KEY, JSON.stringify(state.spaceWidgetLayouts || {}));
  } catch {
    // Device layout is ephemeral and client-local by default.
  }
}

function saveWisCameraConfigs() {
  saveWisCameraArtifactConfigs(state.wisCameraConfigs || {}, localStorage);
}

function userSpaceAreaForPanel(panel = state.activePanel) {
  const space = isUserSpacePanel(panel) ? userSpaceById(panel) : null;
  return spaceAreaFromMetadata(space?.space_area);
}

function canvasAreaSizeForPanel(panel = state.activePanel) {
  const metadataArea = userSpaceAreaForPanel(panel);
  if (metadataArea) return metadataArea;
  const layout = state.spaceWidgetLayouts?.[activeSpaceStorageId(panel)];
  const canvas = layout?.__canvas && typeof layout.__canvas === "object" ? layout.__canvas : {};
  return spaceAreaFromMetadata({
    width_px: canvas.widthPx ?? canvas.width_px,
    height_px: canvas.heightPx ?? canvas.height_px,
  }) || legacyCanvasDensityAreaSize(canvas) || initialCanvasAreaSize();
}

function syncSpaceAreaMetadata(panel, area = canvasAreaSize(), options = {}) {
  if (!isUserSpacePanel(panel)) return null;
  const index = state.userSpaces.findIndex((space) => space.id === panel);
  if (index < 0) return null;
  const spaceArea = serializableSpaceArea(area);
  const targetSpace = state.userSpaces[index];
  const sharedSpaceId = targetSpace.shared_space_id || "";
  if (sameSpaceArea(targetSpace.space_area, spaceArea)) return spaceArea;
  state.userSpaces = state.userSpaces.map((space) => {
    const sameSharedSpace = sharedSpaceId && space.shared_space_id === sharedSpaceId;
    if (space.id !== panel && !sameSharedSpace) return space;
    return {
      ...space,
      space_area: spaceArea,
    };
  });
  if (options.persist !== false) persistSpaceAreaMetadata(panel, spaceArea);
  return spaceArea;
}

function syncActiveSpaceAreaMetadata(area = canvasAreaSize(), options = {}) {
  return syncSpaceAreaMetadata(state.activePanel, area, options);
}

function sharedUserSpaceForPanel(panel = state.activePanel) {
  const space = isUserSpacePanel(panel) ? userSpaceById(panel) : null;
  return space?.shared_space_id ? space : null;
}

function activeSharedRoom() {
  const sharedSpaceId = sharedUserSpaceForPanel()?.shared_space_id || "";
  return sharedSpaceId ? state.sharedRooms[sharedSpaceId] || null : null;
}

function sharedSpacePointerDeviceSlot(payload = {}) {
  const rawHash = payload.device_hash ?? payload.deviceHash;
  if (rawHash !== undefined && rawHash !== null && rawHash !== "") {
    const value = Number(rawHash);
    if (Number.isFinite(value)) return `bin-${(value >>> 0).toString(36)}`;
  }
  const deviceId = cleanText(payload.device_id || payload.deviceId, "");
  return deviceId ? `bin-${hashSharedPointerString(deviceId).toString(36)}` : "";
}

function sharedSpacePointerUserSlot(userId = "") {
  const clean = cleanText(userId, "");
  return clean ? String(numericSharedPointerId(clean)) : "";
}

function sharedSpacePointerKey(event = {}) {
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  const userId = cleanText(event.sender_user_id || payload.user_id || payload.userId, "");
  const deviceSlot = sharedSpacePointerDeviceSlot(payload);
  const userSlot = sharedSpacePointerUserSlot(userId);
  if (userSlot) return `${userSlot}:user`;
  if (!userId && !deviceSlot) return "";
  return `device:${deviceSlot}`;
}

function sharedSpacePointerColor(seed = "") {
  let hash = 0;
  for (const char of String(seed || "space")) hash = ((hash * 31) + char.charCodeAt(0)) >>> 0;
  const hue = hash % 360;
  return `hsl(${hue} 88% 66%)`;
}

function activeSharedSpacePointerId(room = activeSharedRoom()) {
  const currentUserId = cleanText(room?.current_user_id || state.authUser?.id, "");
  const userSlot = sharedSpacePointerUserSlot(currentUserId);
  if (userSlot) return `${userSlot}:user`;
  return `device:bin-${sharedSpacePointerLocalDeviceHash().toString(36)}`;
}

function localSharedSpacePointerKey(target = currentSharedSpacePointerTarget()) {
  const key = activeSharedSpacePointerId(target?.room);
  if (key) return key;
  const userId = cleanText(state.authUser?.id, "local");
  return `${userId}:user`;
}

function currentSharedSpacePointerTarget() {
  const space = sharedUserSpaceForPanel();
  const room = space?.shared_space_id ? state.sharedRooms[space.shared_space_id] || null : null;
  if (!space?.shared_space_id || !room?.id) return null;
  return { space, room };
}

function sharedSpacePointerLiveUrl(target = currentSharedSpacePointerTarget()) {
  if (!target?.space?.shared_space_id) return "";
  const url = appWebSocketUrl("/spaces/room/live");
  url.searchParams.set("shared_space_id", target.space.shared_space_id);
  url.searchParams.set("space_id", target.space.id);
  return url.toString();
}

function sharedSpacePointerLiveConnected(target = currentSharedSpacePointerTarget()) {
  if (!("WebSocket" in window)) return false;
  const sharedSpaceId = cleanText(target?.space?.shared_space_id || "", "");
  return Boolean(
    sharedSpaceId
    && state.sharedSpacePointerLiveSpaceId === sharedSpaceId
    && state.sharedSpacePointerLiveSocket?.readyState === WebSocket.OPEN
    && state.sharedSpacePointerLiveReady
  );
}

function closeSharedSpacePointerLiveSocket(options = {}) {
  if (state.sharedSpacePointerLiveReconnectTimer) {
    window.clearTimeout(state.sharedSpacePointerLiveReconnectTimer);
    state.sharedSpacePointerLiveReconnectTimer = 0;
  }
  const socket = state.sharedSpacePointerLiveSocket;
  state.sharedSpacePointerLiveSocket = null;
  state.sharedSpacePointerLiveReady = false;
  state.sharedSpacePointerLiveSpaceId = "";
  state.sharedSpacePointerLiveToken += 1;
  if (socket && socket.readyState !== WebSocket.CLOSED) {
    try {
      socket.close();
    } catch {
      // Socket may already be closing.
    }
  }
  if (options.reconnect) scheduleSharedSpacePointerLiveReconnect("close");
}

function scheduleSharedSpacePointerLiveReconnect(origin = "reconnect") {
  const target = currentSharedSpacePointerTarget();
  if (!state.authUser || !target?.space?.shared_space_id || !("WebSocket" in window)) return;
  if (state.sharedSpacePointerLiveReconnectTimer) return;
  state.sharedSpacePointerLiveReconnectTimer = window.setTimeout(() => {
    state.sharedSpacePointerLiveReconnectTimer = 0;
    startSharedSpacePointerLiveSocket(origin);
  }, SHARED_SPACE_POINTER_LIVE_RECONNECT_MS);
}

function handleSharedSpacePointerLiveMessage(message = {}) {
  const type = cleanText(message.type, "");
  if (type === "ready") {
    state.sharedSpacePointerLiveReady = true;
    return;
  }
  if (type === "ping") {
    try {
      state.sharedSpacePointerLiveSocket?.send(JSON.stringify({ type: "pong", ts: message.ts || Date.now() }));
    } catch {
      // The close handler reconnects if this room is still active.
    }
    return;
  }
  if (type === "event") {
    const event = message.event && typeof message.event === "object" ? message.event : {};
    const sharedSpaceId = cleanText(message.shared_space_id || event.shared_space_id || state.sharedSpacePointerLiveSpaceId, "");
    if (event.kind === SHARED_SPACE_POINTER_EVENT_KIND) mergeSharedSpacePointerEvents(sharedSpaceId, [event]);
  }
}

function sharedSpacePointerLocalUserNumber() {
  return numericSharedPointerId(state.authUser?.id || "");
}

function sharedSpacePointerLocalDeviceHash() {
  return hashSharedPointerString(clientDeviceId());
}

function sharedSpacePointerBinaryUserLabel(userNumber) {
  const target = Number(userNumber) >>> 0;
  const room = activeSharedRoom();
  const entries = [
    ...(Array.isArray(room?.members) ? room.members : []),
    ...(Array.isArray(room?.presence) ? room.presence : []),
  ];
  const match = entries.find((entry) => numericSharedPointerId(socialUserId(entry) || entry?.user_id || "") === target);
  if (match) return socialUserLabel(match, String(target));
  return target === sharedSpacePointerLocalUserNumber() ? publicUserLabel(state.authUser) : `Member ${target || ""}`.trim();
}

function noteSharedSpacePointerDiagnosticAverage(name, value, alpha = 0.18) {
  const number = Number(value);
  if (!Number.isFinite(number)) return;
  const diagnostics = state.sharedSpacePointerDiagnostics;
  const previous = Number(diagnostics[name] || 0);
  diagnostics[name] = previous ? previous * (1 - alpha) + number * alpha : number;
}

function handleSharedSpacePointerLiveBinary(data, options = {}) {
  const receivedAt = performance.now();
  const decodedAt = performance.now();
  const diagnostics = state.sharedSpacePointerDiagnostics;
  const transport = cleanText(options.transport || "binary", "binary");
  const isRtc = transport === "rtc";
  const packet = decodeSharedPointerBinaryPacket(data, {
    receivedAtMs: receivedAt,
    receiverEpochMs: Date.now(),
    previousClockOffsetMs: Number(diagnostics.clockOffsetMs || 0),
    alpha: SHARED_SPACE_POINTER_REALTIME_CLOCK_OFFSET_ALPHA,
  });
  diagnostics.binaryDecodeMs = diagnostics.binaryDecodeMs
    ? diagnostics.binaryDecodeMs * 0.88 + (performance.now() - decodedAt) * 0.12
    : performance.now() - decodedAt;
  if (!packet || !packet.samples.length) {
    if (isRtc) diagnostics.rtcDrops += 1;
    else diagnostics.binaryDrops += 1;
    return;
  }
  diagnostics.clockOffsetMs = packet.clockOffsetMs;
  const byteLength = Number(packet.byteLength || data?.byteLength || 0);
  if (isRtc) {
    diagnostics.rtcReceived += 1;
    diagnostics.rtcBytesReceived += byteLength;
  } else {
    diagnostics.binaryReceived += 1;
    diagnostics.binaryBytesReceived += byteLength;
  }
  const sentAtReceiverMs = Number(packet.sentPerfMs || 0) + Number(packet.clockOffsetMs || 0);
  noteSharedSpacePointerDiagnosticAverage("transportLatencyMs", clamp(receivedAt - sentAtReceiverMs, 0, 5000));
  diagnostics.transport = transport;
  const localUser = sharedSpacePointerLocalUserNumber();
  const localDevice = sharedSpacePointerLocalDeviceHash();
  if (packet.userId === localUser && packet.deviceHash === localDevice) return;
  const roomId = cleanText(state.sharedSpacePointerLiveSpaceId || currentSharedSpacePointerTarget()?.room?.id || "", "");
  if (!roomId) return;
  const latest = packet.samples[packet.samples.length - 1];
  const key = packet.userId ? `${packet.userId}:user` : `device:bin-${packet.deviceHash.toString(36)}`;
  const pointers = { ...(state.sharedSpacePointers[roomId] || {}) };
  if (Number(pointers[key]?.realtime_seq || 0) >= Number(packet.seq || 0)) return;
  appendSharedSpacePointerPendingRealtime(roomId, key, packet.samples, receivedAt);
  const point = cleanSharedSpacePointerPoint(latest);
  if (!point) return;
  pointers[key] = {
    key,
    user_id: String(packet.userId || ""),
    device_id: `bin-${packet.deviceHash.toString(36)}`,
    device_hash: packet.deviceHash,
    user_label: sharedSpacePointerBinaryUserLabel(packet.userId),
    type: "move",
    x: point.x,
    y: point.y,
    color: sharedSpacePointerColor(key),
    event_id: `bin-${packet.seq}`,
    pointer_event_id: `bin-${packet.seq}`,
    path: [],
    realtime_seq: packet.seq,
    realtime_source: transport,
    realtime_sample_count: packet.samples.length,
    source_sent_at_ms: packet.sentEpochMs,
    received_at: receivedAt,
    pulse_id: cleanText(pointers[key]?.pulse_id || "", ""),
    click_until: Number(pointers[key]?.click_until || 0),
    last_seen_at: Date.now(),
  };
  state.sharedSpacePointers[roomId] = pointers;
  state.sharedSpacePointerFollowTarget = { shared_space_id: roomId, key, x: point.x, y: point.y, at: Date.now() };
  scheduleSharedSpacePointerRender(isRtc ? "pointer-rtc" : "pointer-binary");
  scheduleSharedSpacePointerNavigationFollow();
}

function startSharedSpacePointerLiveSocket(origin = "active") {
  const target = currentSharedSpacePointerTarget();
  const sharedSpaceId = cleanText(target?.space?.shared_space_id || "", "");
  if (!state.authUser || !sharedSpaceId || !("WebSocket" in window)) return null;
  const existing = state.sharedSpacePointerLiveSocket;
  if (existing && state.sharedSpacePointerLiveSpaceId === sharedSpaceId && [WebSocket.CONNECTING, WebSocket.OPEN].includes(existing.readyState)) {
    return existing;
  }
  if (existing) closeSharedSpacePointerLiveSocket();
  if (state.sharedSpacePointerLiveReconnectTimer) {
    window.clearTimeout(state.sharedSpacePointerLiveReconnectTimer);
    state.sharedSpacePointerLiveReconnectTimer = 0;
  }
  const url = sharedSpacePointerLiveUrl(target);
  if (!url) return null;
  const token = state.sharedSpacePointerLiveToken + 1;
  state.sharedSpacePointerLiveToken = token;
  state.sharedSpacePointerLiveReady = false;
  state.sharedSpacePointerLiveSpaceId = sharedSpaceId;
  const socket = new WebSocket(url);
  socket.binaryType = "arraybuffer";
  state.sharedSpacePointerLiveSocket = socket;
  socket.addEventListener("open", () => {
    if (state.sharedSpacePointerLiveToken !== token) return;
    try {
      socket.send(JSON.stringify({ type: "hello", origin }));
    } catch {
      // The close handler reconnects if this room is still active.
    }
  });
  socket.addEventListener("message", (event) => {
    if (state.sharedSpacePointerLiveToken !== token) return;
    if (typeof event.data !== "string") {
      if (event.data instanceof ArrayBuffer) {
        handleSharedSpacePointerLiveBinary(event.data);
      } else if (event.data instanceof Blob) {
        void event.data.arrayBuffer().then((buffer) => handleSharedSpacePointerLiveBinary(buffer)).catch(() => {});
      }
      return;
    }
    try {
      handleSharedSpacePointerLiveMessage(JSON.parse(event.data));
    } catch (error) {
      recordUserEvent("workspace.shared_space_pointer_live_error", {
        target: `space:${target.space.id}`,
        summary: error.message || String(error),
        data: { shared_space_id: sharedSpaceId, error: error.message || String(error) },
      });
    }
  });
  socket.addEventListener("close", () => {
    if (state.sharedSpacePointerLiveToken !== token) return;
    state.sharedSpacePointerLiveSocket = null;
    state.sharedSpacePointerLiveReady = false;
    scheduleSharedSpacePointerLiveReconnect("close");
  });
  socket.addEventListener("error", () => {
    if (state.sharedSpacePointerLiveToken !== token) return;
    state.sharedSpacePointerLiveReady = false;
  });
  return socket;
}

function sendSharedSpacePointerLiveEvent(target, body = {}, options = {}) {
  const socket = startSharedSpacePointerLiveSocket("pointer-send");
  if (!socket || !sharedSpacePointerLiveConnected(target)) return false;
  if (Number(socket.bufferedAmount || 0) > SHARED_SPACE_POINTER_LIVE_BUFFER_LIMIT_BYTES) return options.liveOnly === true;
  const liveBody = options.liveOnly ? { ...body, live_only: true } : body;
  try {
    socket.send(JSON.stringify({
      type: "event",
      request_id: remoteControlId("space_ptr"),
      body: liveBody,
    }));
    return true;
  } catch {
    return false;
  }
}

function createSharedSpacePointerBinaryBuffer(samples = [], seq = 0, now = performance.now()) {
  return encodeSharedPointerBinaryPacket({
    userId: state.authUser?.id || "",
    deviceId: clientDeviceId(),
    seq,
    sentPerfMs: now,
    sentEpochMs: Date.now(),
    samples,
  }, {
    limit: SHARED_SPACE_POINTER_REALTIME_SAMPLE_LIMIT,
  });
}

function sendSharedSpacePointerBinaryEvent(target, samples = [], seq = 0, now = performance.now(), packetBuffer = null) {
  const socket = startSharedSpacePointerLiveSocket("pointer-binary-send");
  if (!socket || !sharedSpacePointerLiveConnected(target)) return false;
  const diagnostics = state.sharedSpacePointerDiagnostics;
  if (Number(socket.bufferedAmount || 0) > SHARED_SPACE_POINTER_BINARY_BUFFER_LIMIT_BYTES) {
    diagnostics.binaryDrops += 1;
    diagnostics.transport = "binary-drop";
    return true;
  }
  const buffer = packetBuffer || createSharedSpacePointerBinaryBuffer(samples, seq, now);
  if (!buffer) return false;
  try {
    socket.send(buffer);
    diagnostics.binarySent += 1;
    diagnostics.binaryBytesSent += buffer.byteLength;
    diagnostics.transport = "binary";
    return true;
  } catch {
    diagnostics.binaryDrops += 1;
    return false;
  }
}

function sharedSpacePointerRtcSupported() {
  return Boolean(window.isSecureContext && window.RTCPeerConnection);
}

function sharedSpacePointerRtcLocalDeviceId(room = activeSharedRoom()) {
  return cleanText(room?.current_device_id || clientDeviceId(), "");
}

function sharedSpacePointerRtcPeerEntries(room = activeSharedRoom()) {
  const localDeviceId = sharedSpacePointerRtcLocalDeviceId(room);
  const entries = Array.isArray(room?.presence) ? room.presence : [];
  return entries.filter((entry) => entry?.device_id && entry.device_id !== localDeviceId);
}

function sharedSpacePointerRtcPeerLabel(entry = {}) {
  const user = cleanText(entry.user_label || entry.user_id || "", "");
  const device = cleanText(entry.label || entry.device_id || "", "");
  return user && device ? `${user} / ${device}` : user || device || "peer";
}

function updateSharedSpacePointerRtcDiagnostics() {
  const peers = Object.values(state.sharedSpacePointerRtc.peers || {}).filter(Boolean);
  const open = peers.filter((peer) => peer.channel?.readyState === "open");
  state.sharedSpacePointerRtc.openCount = open.length;
  state.sharedSpacePointerDiagnostics.rtcPeers = peers.length;
  state.sharedSpacePointerDiagnostics.rtcOpen = open.length;
}

function closeSharedSpacePointerRtcPeer(deviceId) {
  const rtc = state.sharedSpacePointerRtc;
  const key = cleanText(deviceId, "");
  const peer = rtc.peers?.[key];
  if (!peer) return;
  try {
    peer.channel?.close?.();
  } catch {
    // Peer teardown is best effort.
  }
  try {
    peer.pc?.close?.();
  } catch {
    // Peer teardown is best effort.
  }
  delete rtc.peers[key];
  updateSharedSpacePointerRtcDiagnostics();
}

function closeSharedSpacePointerRtcPeers() {
  const rtc = state.sharedSpacePointerRtc;
  Object.keys(rtc.peers || {}).forEach(closeSharedSpacePointerRtcPeer);
  Object.assign(rtc, {
    roomId: "",
    peers: {},
    processedSignalIds: new Set(),
    signalQueue: Promise.resolve(),
    signalBusy: false,
    openCount: 0,
  });
  updateSharedSpacePointerRtcDiagnostics();
}

function sharedSpacePointerSignalPayload(event = {}) {
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  return payload.pointer_schema === SHARED_SPACE_POINTER_SIGNAL_SCHEMA ? payload : null;
}

function sharedSpacePointerSignalFresh(event = {}) {
  const created = Date.parse(cleanText(event.created_at || "", ""));
  if (!Number.isFinite(created)) return true;
  return Date.now() - created <= SHARED_SPACE_POINTER_RTC_STALE_MS;
}

function sharedSpacePointerRtcShouldOffer(room, entry) {
  const localDeviceId = sharedSpacePointerRtcLocalDeviceId(room);
  const peerDeviceId = cleanText(entry?.device_id || "", "");
  if (!localDeviceId || !peerDeviceId || localDeviceId === peerDeviceId) return false;
  return sharedVoiceShouldInitiateRoomOffer(localDeviceId, peerDeviceId);
}

function attachSharedSpacePointerRtcChannel(peer, channel) {
  if (!peer || !channel) return;
  peer.channel = channel;
  channel.binaryType = "arraybuffer";
  channel.bufferedAmountLowThreshold = SHARED_SPACE_POINTER_RTC_BUFFER_LIMIT_BYTES / 2;
  channel.addEventListener("open", () => {
    peer.status = "open";
    peer.openedAt = performance.now();
    updateSharedSpacePointerRtcDiagnostics();
  });
  channel.addEventListener("close", () => {
    peer.status = "closed";
    updateSharedSpacePointerRtcDiagnostics();
  });
  channel.addEventListener("error", () => {
    peer.status = "error";
    state.sharedSpacePointerDiagnostics.rtcDrops += 1;
    updateSharedSpacePointerRtcDiagnostics();
  });
  channel.addEventListener("message", (event) => {
    if (event.data instanceof ArrayBuffer) {
      handleSharedSpacePointerLiveBinary(event.data, { transport: "rtc" });
    } else if (event.data instanceof Blob) {
      void event.data.arrayBuffer().then((buffer) => handleSharedSpacePointerLiveBinary(buffer, { transport: "rtc" })).catch(() => {
        state.sharedSpacePointerDiagnostics.rtcDrops += 1;
      });
    }
  });
}

function createSharedSpacePointerPeerConnection(peer) {
  const pc = new RTCPeerConnection({
    iceServers: sharedVoiceIceServers(),
    bundlePolicy: "max-bundle",
    rtcpMuxPolicy: "require",
  });
  pc.addEventListener("icecandidate", (event) => {
    if (!event.candidate) return;
    void sendSharedSpacePointerRtcSignal(peer, "ice-candidate", {
      candidate: JSON.stringify(event.candidate.toJSON ? event.candidate.toJSON() : event.candidate),
    }).catch(() => {
      state.sharedSpacePointerDiagnostics.rtcDrops += 1;
    });
  });
  pc.addEventListener("datachannel", (event) => {
    attachSharedSpacePointerRtcChannel(peer, event.channel);
  });
  const update = () => {
    peer.status = pc.connectionState || pc.iceConnectionState || peer.status || "connecting";
    updateSharedSpacePointerRtcDiagnostics();
  };
  pc.addEventListener("connectionstatechange", update);
  pc.addEventListener("iceconnectionstatechange", update);
  return pc;
}

function ensureSharedSpacePointerRtcPeer(room, entry, options = {}) {
  if (!sharedSpacePointerRtcSupported() || !room?.id) return null;
  const deviceId = cleanText(entry?.device_id || options.deviceId || "", "");
  const localDeviceId = sharedSpacePointerRtcLocalDeviceId(room);
  if (!deviceId || !localDeviceId || deviceId === localDeviceId) return null;
  const rtc = state.sharedSpacePointerRtc;
  if (rtc.roomId && rtc.roomId !== room.id) closeSharedSpacePointerRtcPeers();
  rtc.roomId = room.id;
  rtc.peers ||= {};
  let peer = rtc.peers[deviceId];
  if (!peer) {
    peer = {
      deviceId,
      userId: cleanText(entry?.user_id || "", ""),
      label: sharedSpacePointerRtcPeerLabel(entry),
      callId: cleanText(options.callId || "", ""),
      pc: null,
      channel: null,
      pendingIceCandidates: [],
      makingOffer: false,
      ignoreOffer: false,
      polite: String(localDeviceId) > String(deviceId),
      createdAt: Date.now(),
      lastOfferAt: 0,
      status: "new",
    };
    rtc.peers[deviceId] = peer;
  }
  peer.userId = cleanText(entry?.user_id || peer.userId || "", "");
  peer.label = sharedSpacePointerRtcPeerLabel(entry || { device_id: deviceId, user_id: peer.userId, label: peer.label });
  peer.polite = String(localDeviceId) > String(deviceId);
  if (options.callId) peer.callId = cleanText(options.callId, peer.callId || "");
  if (!peer.pc || peer.pc.connectionState === "closed") {
    peer.pc = createSharedSpacePointerPeerConnection(peer);
    if (sharedSpacePointerRtcShouldOffer(room, { device_id: deviceId })) {
      attachSharedSpacePointerRtcChannel(
        peer,
        peer.pc.createDataChannel("wasm-agent-pointer", { ordered: false, maxRetransmits: 0 }),
      );
    }
  }
  updateSharedSpacePointerRtcDiagnostics();
  return peer;
}

async function sendSharedSpacePointerRtcSignal(peer, type, details = {}) {
  const space = sharedUserSpaceForPanel();
  const room = activeSharedRoom();
  const fromDeviceId = sharedSpacePointerRtcLocalDeviceId(room);
  if (!space?.shared_space_id || !room?.id || !peer?.deviceId || !fromDeviceId) return null;
  if (!peer.callId) peer.callId = `ptr_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
  const payload = await fetchJson("/spaces/room", {
    method: "POST",
    timeoutMs: 7000,
    body: {
      action: "signal",
      kind: SHARED_SPACE_POINTER_SIGNAL_KIND,
      space_id: space.id,
      shared_space_id: space.shared_space_id,
      payload: {
        pointer_schema: SHARED_SPACE_POINTER_SIGNAL_SCHEMA,
        call_id: peer.callId,
        room_id: room.id,
        type,
        from_user_id: cleanText(room.current_user_id || state.authUser?.id || "", ""),
        from_device_id: fromDeviceId,
        to_device_id: peer.deviceId,
        ...details,
      },
    },
  });
  const nextRoom = payload.room || null;
  if (nextRoom?.id) {
    state.sharedRooms[nextRoom.id] = nextRoom;
    mergeSharedSpacePointerEvents(nextRoom.id, nextRoom.events);
    queueSharedSpacePointerPeerProcessing(nextRoom);
  }
  return nextRoom;
}

async function setSharedSpacePointerRtcLocalDescription(peer, description, timeoutMs = 1200) {
  const pc = peer?.pc;
  if (!pc) return description;
  let settled = false;
  const pending = pc.setLocalDescription(description);
  await Promise.race([
    pending.then(
      () => {
        settled = true;
      },
      (error) => {
        settled = true;
        throw error;
      },
    ),
    new Promise((resolve) => window.setTimeout(resolve, timeoutMs)),
  ]);
  if (!settled) pending.catch(() => { state.sharedSpacePointerDiagnostics.rtcDrops += 1; });
  return pc.localDescription || description;
}

async function makeSharedSpacePointerRtcOffer(peer) {
  const pc = peer?.pc;
  if (!pc || peer.makingOffer) return;
  try {
    peer.makingOffer = true;
    if (!peer.callId) peer.callId = `ptr_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
    peer.lastOfferAt = Date.now();
    const offer = await pc.createOffer();
    const localOffer = await setSharedSpacePointerRtcLocalDescription(peer, offer);
    await sendSharedSpacePointerRtcSignal(peer, "offer", { sdp: localOffer?.sdp || offer.sdp || "" });
  } finally {
    peer.makingOffer = false;
  }
}

async function flushSharedSpacePointerRtcIce(peer) {
  const pc = peer?.pc;
  if (!pc?.remoteDescription?.type || !peer.pendingIceCandidates.length) return;
  const pending = peer.pendingIceCandidates.splice(0);
  for (const candidate of pending) await pc.addIceCandidate(candidate);
}

async function addSharedSpacePointerRtcIce(peer, candidate) {
  const pc = peer?.pc;
  if (!pc || !candidate) return;
  if (!pc.remoteDescription?.type) {
    peer.pendingIceCandidates.push(candidate);
    if (peer.pendingIceCandidates.length > 80) {
      peer.pendingIceCandidates.splice(0, peer.pendingIceCandidates.length - 80);
    }
    return;
  }
  await pc.addIceCandidate(candidate);
}

async function handleSharedSpacePointerRtcSignal(event, payload, room) {
  if (!payload || !room?.id || payload.room_id !== room.id) return true;
  const currentDeviceId = sharedSpacePointerRtcLocalDeviceId(room);
  if (!currentDeviceId || payload.from_device_id === currentDeviceId) return true;
  if (payload.to_device_id && payload.to_device_id !== currentDeviceId) return true;
  const entry = sharedSpacePointerRtcPeerEntries(room).find((item) => item.device_id === payload.from_device_id) || {
    device_id: payload.from_device_id,
    user_id: payload.from_user_id || "",
    label: "Browser",
  };
  const peer = ensureSharedSpacePointerRtcPeer(room, entry, { callId: payload.call_id });
  const pc = peer?.pc;
  if (!peer || !pc) return false;
  if (payload.type === "offer" && payload.call_id !== peer.callId) {
    if (!peer.polite && peer.callId) return true;
    peer.callId = cleanText(payload.call_id, peer.callId || "");
  }
  if (payload.call_id !== peer.callId) return true;
  if (payload.type === "offer") {
    const offerCollision = peer.makingOffer || pc.signalingState !== "stable";
    peer.ignoreOffer = !peer.polite && offerCollision;
    if (peer.ignoreOffer) return true;
    if (offerCollision) await pc.setLocalDescription({ type: "rollback" });
    await pc.setRemoteDescription({ type: "offer", sdp: String(payload.sdp || "") });
    await flushSharedSpacePointerRtcIce(peer);
    const answer = await pc.createAnswer();
    const localAnswer = await setSharedSpacePointerRtcLocalDescription(peer, answer);
    await sendSharedSpacePointerRtcSignal(peer, "answer", { sdp: localAnswer?.sdp || answer.sdp || "" });
    return true;
  }
  if (payload.type === "answer") {
    if (pc.signalingState !== "stable") {
      await pc.setRemoteDescription({ type: "answer", sdp: String(payload.sdp || "") });
      await flushSharedSpacePointerRtcIce(peer);
    }
    return true;
  }
  if (payload.type === "ice-candidate") {
    try {
      const candidate = typeof payload.candidate === "string" ? JSON.parse(payload.candidate) : payload.candidate;
      await addSharedSpacePointerRtcIce(peer, candidate);
    } catch (error) {
      if (!peer.ignoreOffer) throw error;
    }
    return true;
  }
  return true;
}

async function syncSharedSpacePointerRtcPeers(room) {
  if (!sharedSpacePointerRtcSupported() || !room?.id) return false;
  const entries = sharedSpacePointerRtcPeerEntries(room);
  const devices = new Set(entries.map((entry) => entry.device_id));
  for (const peer of Object.values(state.sharedSpacePointerRtc.peers || {})) {
    if (!devices.has(peer.deviceId)) closeSharedSpacePointerRtcPeer(peer.deviceId);
  }
  for (const entry of entries) {
    const peer = ensureSharedSpacePointerRtcPeer(room, entry);
    if (!peer) continue;
    const channelOpen = peer.channel?.readyState === "open";
    const shouldOffer = sharedSpacePointerRtcShouldOffer(room, entry);
    const retryDue = Date.now() - Number(peer.lastOfferAt || 0) > SHARED_SPACE_POINTER_RTC_OFFER_RETRY_MS;
    if (shouldOffer && !channelOpen && retryDue && !peer.makingOffer) {
      await makeSharedSpacePointerRtcOffer(peer);
    }
  }
  updateSharedSpacePointerRtcDiagnostics();
  return entries.length > 0;
}

async function processSharedSpacePointerRtcRoom(room) {
  const rtc = state.sharedSpacePointerRtc;
  if (!sharedSpacePointerRtcSupported() || rtc.signalBusy || !room?.id) return;
  rtc.signalBusy = true;
  try {
    if (rtc.roomId && rtc.roomId !== room.id) closeSharedSpacePointerRtcPeers();
    rtc.roomId = room.id;
    const events = Array.isArray(room.events) ? room.events : [];
    for (const event of events) {
      if (!event?.id || rtc.processedSignalIds.has(event.id)) continue;
      if (event.kind !== SHARED_SPACE_POINTER_SIGNAL_KIND || !sharedSpacePointerSignalFresh(event)) continue;
      const payload = sharedSpacePointerSignalPayload(event);
      if (!payload) continue;
      const handled = await handleSharedSpacePointerRtcSignal(event, payload, room);
      if (handled) rtc.processedSignalIds.add(event.id);
    }
    if (rtc.processedSignalIds.size > 180) {
      rtc.processedSignalIds = new Set(Array.from(rtc.processedSignalIds).slice(-120));
    }
    await syncSharedSpacePointerRtcPeers(room);
  } catch {
    state.sharedSpacePointerDiagnostics.rtcDrops += 1;
  } finally {
    rtc.signalBusy = false;
  }
}

function queueSharedSpacePointerPeerProcessing(room) {
  if (!sharedSpacePointerRtcSupported() || !room?.id) return;
  const rtc = state.sharedSpacePointerRtc;
  rtc.signalQueue = rtc.signalQueue
    .then(() => processSharedSpacePointerRtcRoom(room))
    .catch(() => {
      state.sharedSpacePointerDiagnostics.rtcDrops += 1;
    });
}

function sendSharedSpacePointerPeerBinaryEvent(_target, packetBuffer) {
  if (!packetBuffer || !sharedSpacePointerRtcSupported()) return false;
  const diagnostics = state.sharedSpacePointerDiagnostics;
  let sent = 0;
  for (const peer of Object.values(state.sharedSpacePointerRtc.peers || {})) {
    const channel = peer?.channel;
    if (!channel || channel.readyState !== "open") continue;
    if (Number(channel.bufferedAmount || 0) > SHARED_SPACE_POINTER_RTC_BUFFER_LIMIT_BYTES) {
      diagnostics.rtcDrops += 1;
      continue;
    }
    try {
      channel.send(packetBuffer);
      sent += 1;
      diagnostics.rtcSent += 1;
      diagnostics.rtcBytesSent += packetBuffer.byteLength;
    } catch {
      diagnostics.rtcDrops += 1;
    }
  }
  updateSharedSpacePointerRtcDiagnostics();
  if (sent > 0) diagnostics.transport = "rtc";
  return sent > 0;
}

function sharedSpacePointerEventSnapshot(event, fallback = event) {
  return {
    clientX: Number(event?.clientX ?? fallback?.clientX ?? 0),
    clientY: Number(event?.clientY ?? fallback?.clientY ?? 0),
    pointerId: Number(event?.pointerId ?? fallback?.pointerId ?? 0),
    pointerType: cleanText(event?.pointerType || fallback?.pointerType || "", ""),
    button: Number(event?.button ?? fallback?.button ?? 0),
    buttons: Number(event?.buttons ?? fallback?.buttons ?? 0),
    isPrimary: event?.isPrimary ?? fallback?.isPrimary ?? true,
    timeStamp: Number(event?.timeStamp ?? fallback?.timeStamp ?? performance.now()),
  };
}

function sharedSpacePointerPoint(event) {
  const viewport = els.spaceViewport;
  const rect = spaceViewportUsableRect() || viewport?.getBoundingClientRect?.();
  if (!viewport || !rect) return null;
  if (
    event.clientX < rect.left
    || event.clientX > rect.right
    || event.clientY < rect.top
    || event.clientY > rect.bottom
  ) return null;
  const distance = Math.max(SPACE_DISTANCE_MIN, canvasDistance());
  const x = (viewport.scrollLeft + event.clientX - rect.left) / distance;
  const y = (viewport.scrollTop + event.clientY - rect.top) / distance;
  const area = canvasAreaSize();
  return {
    x: clamp(Number(x.toFixed(2)), 0, Math.max(1, area.width)),
    y: clamp(Number(y.toFixed(2)), 0, Math.max(1, area.height)),
  };
}

function cleanSharedSpacePointerPoint(point) {
  const area = canvasAreaSize();
  const x = Number(point?.x);
  const y = Number(point?.y);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return null;
  return {
    x: clamp(Number(x.toFixed(2)), 0, Math.max(1, area.width)),
    y: clamp(Number(y.toFixed(2)), 0, Math.max(1, area.height)),
  };
}

function sameSharedSpacePointerPoint(first, second, tolerance = 0.35) {
  return Boolean(
    first
    && second
    && Math.abs(Number(first.x || 0) - Number(second.x || 0)) <= tolerance
    && Math.abs(Number(first.y || 0) - Number(second.y || 0)) <= tolerance
  );
}

function pushSharedSpacePointerPoint(points, point) {
  const clean = cleanSharedSpacePointerPoint(point);
  if (!clean) return;
  if (!points.length || !sameSharedSpacePointerPoint(points[points.length - 1], clean)) points.push(clean);
}

function compactSharedSpacePointerPath(points) {
  if (points.length <= SHARED_SPACE_POINTER_PATH_MAX_POINTS) return points;
  const compacted = [];
  const lastIndex = points.length - 1;
  for (let index = 0; index < SHARED_SPACE_POINTER_PATH_MAX_POINTS; index += 1) {
    const sourceIndex = Math.round((index * lastIndex) / Math.max(1, SHARED_SPACE_POINTER_PATH_MAX_POINTS - 1));
    pushSharedSpacePointerPoint(compacted, points[sourceIndex]);
  }
  pushSharedSpacePointerPoint(compacted, points[lastIndex]);
  return compacted.slice(-SHARED_SPACE_POINTER_PATH_MAX_POINTS);
}

function densifySharedSpacePointerPath(points = []) {
  const source = [];
  points.forEach((point) => pushSharedSpacePointerPoint(source, point));
  if (source.length <= 1) return source;
  const dense = [source[0]];
  for (let index = 1; index < source.length; index += 1) {
    const from = source[index - 1];
    const to = source[index];
    const distance = Math.hypot(to.x - from.x, to.y - from.y);
    const steps = Math.max(1, Math.ceil(distance / SHARED_SPACE_POINTER_PATH_STEP_PX));
    for (let step = 1; step <= steps; step += 1) {
      const ratio = step / steps;
      pushSharedSpacePointerPoint(dense, {
        x: from.x + (to.x - from.x) * ratio,
        y: from.y + (to.y - from.y) * ratio,
      });
    }
  }
  return compactSharedSpacePointerPath(dense);
}

function sharedSpacePointerPathFromSamples(samples = [], finalPoint = null, previousPoint = null) {
  const points = [];
  pushSharedSpacePointerPoint(points, previousPoint);
  if (Array.isArray(samples)) {
    samples.forEach((sample) => {
      const point = sharedSpacePointerPoint(sample);
      if (point) pushSharedSpacePointerPoint(points, point);
    });
  }
  pushSharedSpacePointerPoint(points, finalPoint);
  return densifySharedSpacePointerPath(points);
}

function sharedSpacePointerRealtimeSamplesFromEvents(samples = [], finalEvent = null, sendNow = performance.now()) {
  const source = Array.isArray(samples) ? samples : [];
  const realtime = [];
  source.forEach((sample) => {
    const point = sharedSpacePointerPoint(sample);
    const at = Number(sample?.timeStamp || sendNow);
    if (point && Number.isFinite(at)) realtime.push({ ...point, at });
  });
  const finalPoint = sharedSpacePointerPoint(finalEvent);
  const finalAt = Number(finalEvent?.timeStamp || sendNow);
  if (finalPoint && Number.isFinite(finalAt)) realtime.push({ ...finalPoint, at: finalAt });
  const deduped = [];
  realtime.forEach((sample) => {
    const last = deduped[deduped.length - 1] || null;
    if (
      last
      && Math.abs(sample.at - last.at) <= 0.05
      && sameSharedSpacePointerPoint(last, sample, 0.08)
    ) return;
    deduped.push(sample);
  });
  return deduped.slice(-SHARED_SPACE_POINTER_REALTIME_SAMPLE_LIMIT);
}

function nextSharedSpacePointerLocalSeq(seq = 0) {
  const requested = Number(seq || 0);
  const next = Math.max(Number(state.sharedSpacePointerLocalSeq || 0) + 1, Number.isFinite(requested) ? requested : 0);
  state.sharedSpacePointerLocalSeq = next;
  return next;
}

function echoSharedSpacePointerLocalEvent(type, event, options = {}) {
  const target = options.target || currentSharedSpacePointerTarget();
  const roomId = cleanText(target?.room?.id || "", "");
  if (!roomId) return false;
  const point = options.point || sharedSpacePointerPoint(event);
  if (!point) return false;
  const now = Number(options.now ?? performance.now());
  const seq = nextSharedSpacePointerLocalSeq(options.seq);
  const key = localSharedSpacePointerKey(target);
  if (!key) return false;
  const previousPoint = type === "move" ? state.sharedSpacePointerLocalLastPoint : null;
  const realtimeSamples = Array.isArray(options.realtimeSamples)
    ? options.realtimeSamples
    : sharedSpacePointerRealtimeSamplesFromEvents(options.samples, event, now);
  const path = Array.isArray(options.path)
    ? options.path
    : type === "move"
      ? sharedSpacePointerPathFromSamples(options.samples, point, previousPoint)
      : [];
  const pointers = { ...(state.sharedSpacePointers[roomId] || {}) };
  const previous = pointers[key] || {};
  const pointerEventId = cleanText(options.pointerEventId || options.pointer_event_id || `local-${seq}`, `local-${seq}`);
  const eventType = cleanText(type || "move", "move");
  const isPulse = ["down", "click"].includes(eventType);
  appendSharedSpacePointerPendingPath(roomId, key, path);
  appendSharedSpacePointerPendingRealtime(roomId, key, realtimeSamples, now);
  pointers[key] = {
    key,
    user_id: cleanText(target.room.current_user_id || state.authUser?.id || "", ""),
    device_id: clientDeviceId(),
    device_hash: sharedSpacePointerLocalDeviceHash(),
    user_label: cleanText(publicUserLabel(state.authUser), "You"),
    type: eventType,
    x: point.x,
    y: point.y,
    color: sharedSpacePointerColor(key),
    event_id: pointerEventId,
    pointer_event_id: pointerEventId,
    path,
    realtime_seq: seq,
    realtime_source: "local",
    realtime_sample_count: realtimeSamples.length,
    source_sent_at_ms: Date.now(),
    received_at: now,
    pulse_id: isPulse ? pointerEventId : cleanText(previous.pulse_id || "", ""),
    click_until: isPulse ? Date.now() + SHARED_SPACE_POINTER_CLICK_TTL_MS : Number(previous.click_until || 0),
    last_seen_at: Date.now(),
  };
  state.sharedSpacePointers[roomId] = pointers;
  if (eventType === "move" || eventType === "down") state.sharedSpacePointerLocalLastPoint = point;
  if (["up", "click"].includes(eventType)) state.sharedSpacePointerLocalLastPoint = null;
  state.sharedSpacePointerDiagnostics.localEchoes += 1;
  state.sharedSpacePointerDiagnostics.transport = "local";
  scheduleSharedSpacePointerRender("pointer-local");
  return true;
}

function sharedSpacePointerPayloadPath(payload = {}, fallbackPoint = null) {
  const points = [];
  const payloadPoints = Array.isArray(payload.points) ? payload.points : [];
  payloadPoints.forEach((point) => pushSharedSpacePointerPoint(points, point));
  pushSharedSpacePointerPoint(points, fallbackPoint);
  return densifySharedSpacePointerPath(points);
}

function sharedSpacePointerPayloadRealtime(payload = {}, fallbackPoint = null, receivedAt = performance.now()) {
  const rt = payload.rt && typeof payload.rt === "object" ? payload.rt : {};
  const compact = Array.isArray(rt.samples) ? rt.samples : (Array.isArray(payload.rt_samples) ? payload.rt_samples : []);
  const sentPerfMs = Number(rt.sent_perf_ms || payload.sent_perf_ms || 0);
  const senderEpochMs = Number(payload.sent_at_ms || rt.sent_at_ms || 0);
  const receiverEpochMs = Date.now();
  const previousOffset = Number(state.sharedSpacePointerDiagnostics.clockOffsetMs || 0);
  const clockOffsetMs = sentPerfMs > 0 && senderEpochMs > 0
    ? estimateSharedPointerClockOffset({
      senderEpochMs,
      senderPerfMs: sentPerfMs,
      receiverEpochMs,
      receiverPerfMs: receivedAt,
    }, previousOffset, {
      alpha: SHARED_SPACE_POINTER_REALTIME_CLOCK_OFFSET_ALPHA,
    })
    : previousOffset;
  state.sharedSpacePointerDiagnostics.clockOffsetMs = clockOffsetMs;
  const fallbackBaseMs = senderEpochMs > 0 ? receivedAt - Math.max(0, receiverEpochMs - senderEpochMs) : receivedAt;
  const decoded = decodeSharedPointerRealtimeSamples(compact, sentPerfMs, clockOffsetMs, {
    limit: SHARED_SPACE_POINTER_REALTIME_SAMPLE_LIMIT,
    receivedAtMs: receivedAt,
    fallbackBaseMs,
  });
  if (decoded.length) {
    return {
      samples: decoded,
      seq: Number(rt.seq || payload.seq || 0),
      clockOffsetMs,
      source: "rt",
    };
  }
  if (fallbackPoint) {
    return {
      samples: [{ x: fallbackPoint.x, y: fallbackPoint.y, at: receivedAt }],
      seq: Number(rt.seq || payload.seq || 0),
      clockOffsetMs,
      source: "fallback",
    };
  }
  return { samples: [], seq: Number(rt.seq || payload.seq || 0), clockOffsetMs, source: "empty" };
}

function sharedSpacePointerTransform(screenX, screenY) {
  return `translate3d(${screenX}px, ${screenY}px, 0) translate(2px, 2px)`;
}

function mergeSharedSpacePointerEvents(sharedSpaceId, events = []) {
  const id = cleanText(sharedSpaceId, "");
  if (!id || !Array.isArray(events)) return false;
  const currentKey = activeSharedSpacePointerId(state.sharedRooms[id]);
  let changed = false;
  let latestId = cleanText(state.sharedSpacePointerLastEventIdBySpace[id] || "", "");
  const pointers = { ...(state.sharedSpacePointers[id] || {}) };
  for (const event of events) {
    const receivedAt = performance.now();
    const receivedEpoch = Date.now();
    if (!event || event.kind !== SHARED_SPACE_POINTER_EVENT_KIND) continue;
    const eventId = cleanText(event.id, "");
    if (eventId && latestId && eventId <= latestId) continue;
    if (eventId && (!latestId || eventId > latestId)) latestId = eventId;
    const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
    const key = sharedSpacePointerKey(event);
    if (!key || key === currentKey) continue;
    const pointerEventId = cleanText(payload.pointer_event_id || payload.pointerEventId, "");
    if (pointerEventId && pointers[key]?.pointer_event_id === pointerEventId) continue;
    const eventType = cleanText(payload.type || "move", "move");
    const isPulse = ["down", "click"].includes(eventType);
    const point = {
      x: clamp(Number(payload.x || 0), 0, CANVAS_AREA_MAX_PX),
      y: clamp(Number(payload.y || 0), 0, CANVAS_AREA_MAX_PX),
    };
    if (!Number.isFinite(point.x) || !Number.isFinite(point.y)) continue;
    const path = sharedSpacePointerPayloadPath(payload, point);
    const realtime = sharedSpacePointerPayloadRealtime(payload, point, receivedAt);
    if (
      eventType === "move"
      && Number(realtime.seq || 0) > 0
      && Number(pointers[key]?.realtime_seq || 0) >= Number(realtime.seq || 0)
    ) {
      continue;
    }
    appendSharedSpacePointerPendingPath(id, key, path);
    appendSharedSpacePointerPendingRealtime(id, key, realtime.samples, receivedAt);
    noteSharedSpacePointerDiagnosticsEvent(event, payload, receivedAt);
    const nextPointer = {
      key,
      user_id: cleanText(event.sender_user_id || payload.user_id || "", ""),
      device_id: cleanText(payload.device_id || "", ""),
      device_hash: Number(payload.device_hash ?? payload.deviceHash ?? hashSharedPointerString(payload.device_id || payload.deviceId || "")) >>> 0,
      user_label: cleanText(payload.user_label || sharedSpaceUserLabel(event.sender_user_id), "Member"),
      type: eventType,
      x: point.x,
      y: point.y,
      color: sharedSpacePointerColor(key),
      event_id: eventId,
      pointer_event_id: pointerEventId,
      path,
      realtime_seq: realtime.seq,
      realtime_source: realtime.source,
      realtime_sample_count: realtime.samples.length,
      created_at: cleanText(event.created_at || "", ""),
      source_sent_at_ms: sharedSpacePointerEventCreatedMs(event, payload),
      received_at: receivedAt,
      pulse_id: isPulse ? cleanText(pointerEventId || eventId || `${key}-${Date.now()}`, "") : cleanText(pointers[key]?.pulse_id || "", ""),
      click_until: isPulse ? Date.now() + SHARED_SPACE_POINTER_CLICK_TTL_MS : Number(pointers[key]?.click_until || 0),
      last_seen_at: receivedEpoch,
    };
    pointers[key] = nextPointer;
    state.sharedSpacePointerFollowTarget = { shared_space_id: id, key, x: nextPointer.x, y: nextPointer.y, at: Date.now() };
    changed = true;
  }
  if (latestId) state.sharedSpacePointerLastEventIdBySpace[id] = latestId;
  state.sharedSpacePointers[id] = pointers;
  if (changed) {
    scheduleSharedSpacePointerRender("pointer-event");
    scheduleSharedSpacePointerNavigationFollow();
  }
  return changed;
}

function sharedSpacePointerEventCreatedMs(event = {}, payload = {}) {
  const sentAt = Number(payload.sent_at_ms || payload.sentAtMs || payload.client_sent_at_ms || payload.clientSentAtMs || 0);
  if (Number.isFinite(sentAt) && sentAt > 0) return sentAt;
  const created = Date.parse(cleanText(event.created_at || payload.created_at, ""));
  return Number.isFinite(created) ? created : 0;
}

function noteSharedSpacePointerDiagnosticsEvent(event = {}, payload = {}, receivedAt = performance.now()) {
  const diagnostics = state.sharedSpacePointerDiagnostics;
  diagnostics.eventCount += 1;
  diagnostics.transport = cleanText(payload.rt?.transport || payload.transport || "json", "json");
  const sourceMs = sharedSpacePointerEventCreatedMs(event, payload);
  if (sourceMs > 0) {
    const latency = clamp(Date.now() - sourceMs, 0, 30000);
    diagnostics.latencyMs = diagnostics.latencyMs ? diagnostics.latencyMs * 0.82 + latency * 0.18 : latency;
  } else {
    diagnostics.latencyMs = diagnostics.latencyMs ? diagnostics.latencyMs * 0.92 : clamp(performance.now() - receivedAt, 0, 30000);
  }
}

function sharedSpacePointerDiagnosticsToggle(enabled = true) {
  state.sharedSpacePointerDiagnosticsEnabled = Boolean(enabled);
  try {
    localStorage.setItem(SHARED_SPACE_POINTER_DIAGNOSTICS_STORAGE_KEY, enabled ? "1" : "0");
  } catch {
    // Diagnostics preference is optional.
  }
  scheduleSharedSpacePointerRender("diagnostics-toggle");
  return state.sharedSpacePointerDiagnosticsEnabled;
}

function sharedSpacePointerPredictionToggle(enabled = true) {
  state.sharedSpacePointerPredictionEnabled = Boolean(enabled);
  try {
    localStorage.setItem(SHARED_SPACE_POINTER_PREDICTION_STORAGE_KEY, enabled ? "1" : "0");
  } catch {
    // Legacy prediction preference is optional.
  }
  Object.values(state.sharedSpacePointerVisuals || {}).forEach((visual) => {
    visual.predictionLeadMs = 0;
    visual.predictionPx = 0;
  });
  state.sharedSpacePointerDiagnostics.predictionLeadMs = 0;
  state.sharedSpacePointerDiagnostics.predictionPx = 0;
  state.sharedSpacePointerDiagnostics.realtimePredictionMs = 0;
  state.sharedSpacePointerDiagnostics.realtimePredictionPx = 0;
  scheduleSharedSpacePointerRender("prediction-toggle");
  return state.sharedSpacePointerPredictionEnabled;
}

try {
  window.setWasmAgentSharedPointerDiagnostics = sharedSpacePointerDiagnosticsToggle;
  window.setWasmAgentSharedPointerPrediction = sharedSpacePointerPredictionToggle;
} catch {
  // Browser debug hook only.
}

function sharedSpacePointerDebugSnapshot() {
  return {
    layer: state.sharedSpacePointerRenderLayer || "dom",
    prediction: state.sharedSpacePointerPredictionEnabled ? "legacy" : "off",
    diagnostics: { ...state.sharedSpacePointerDiagnostics },
    visuals: Object.values(state.sharedSpacePointerVisuals || {}).map((visual) => ({
      key: visual.key,
      x: Number(visual.x || 0),
      y: Number(visual.y || 0),
      targetX: Number(visual.targetX || 0),
      targetY: Number(visual.targetY || 0),
      historyLength: Array.isArray(visual.history) ? visual.history.length : 0,
      mode: visual.mode || "",
      replayMode: visual.replayMode || "",
      replayMs: Number(visual.pathDurationMs || 0),
      predictionLeadMs: Number(visual.predictionLeadMs || 0),
      predictionPx: Number(visual.predictionPx || 0),
      netAgeMs: Number(visual.netAgeMs || 0),
      renderBufferMs: Number(visual.renderBufferMs || 0),
      realtimeSamples: Array.isArray(visual.realtimeSamples) ? visual.realtimeSamples.length : 0,
      realtimeMode: visual.realtimeMode || "",
      pulseId: visual.pulseId || "",
      pulseActive: Boolean(visual.pulseStartedAt && performance.now() - Number(visual.pulseStartedAt || 0) < SHARED_SPACE_POINTER_CLICK_TTL_MS),
      pulseAgeMs: visual.pulseStartedAt ? Math.max(0, performance.now() - Number(visual.pulseStartedAt || 0)) : 0,
      label: visual.label || "",
    })),
  };
}

try {
  window.wasmAgentSharedPointerDebug = sharedSpacePointerDebugSnapshot;
} catch {
  // Browser debug hook only.
}

function sharedSpacePointerSnappedTransform(screenX, screenY) {
  const dpr = window.devicePixelRatio || 1;
  return sharedSpacePointerTransform(
    snapSharedPointerPixel(screenX, dpr),
    snapSharedPointerPixel(screenY, dpr)
  );
}

function sharedSpacePointerTargetId(pointer = {}) {
  return cleanText(pointer.pointer_event_id || pointer.event_id || `${pointer.key}:${pointer.x}:${pointer.y}:${pointer.last_seen_at}`, "");
}

function appendSharedSpacePointerPendingPath(sharedSpaceId, key, path = []) {
  const roomId = cleanText(sharedSpaceId, "");
  const pointerKey = cleanText(key, "");
  if (!roomId || !pointerKey || !Array.isArray(path) || !path.length) return;
  const roomPaths = state.sharedSpacePointerPendingPaths[roomId] || {};
  const points = Array.isArray(roomPaths[pointerKey]) ? roomPaths[pointerKey] : [];
  path.forEach((point) => pushSharedSpacePointerPoint(points, point));
  roomPaths[pointerKey] = points.slice(-SHARED_SPACE_POINTER_PENDING_PATH_LIMIT);
  state.sharedSpacePointerPendingPaths[roomId] = roomPaths;
}

function consumeSharedSpacePointerPendingPath(sharedSpaceId, key, fallbackPath = []) {
  const roomId = cleanText(sharedSpaceId, "");
  const pointerKey = cleanText(key, "");
  const roomPaths = roomId ? state.sharedSpacePointerPendingPaths[roomId] || null : null;
  const points = Array.isArray(roomPaths?.[pointerKey]) ? roomPaths[pointerKey] : [];
  if (roomPaths && pointerKey) delete roomPaths[pointerKey];
  return points.length ? points : fallbackPath;
}

function appendSharedSpacePointerPendingRealtime(sharedSpaceId, key, samples = [], now = performance.now()) {
  const roomId = cleanText(sharedSpaceId, "");
  const pointerKey = cleanText(key, "");
  if (!roomId || !pointerKey || !Array.isArray(samples) || !samples.length) return;
  const roomSamples = state.sharedSpacePointerPendingRealtimeSamples[roomId] || {};
  const existing = Array.isArray(roomSamples[pointerKey]) ? roomSamples[pointerKey] : [];
  const result = appendSharedPointerRealtimeSamples(existing, samples, {
    limit: SHARED_SPACE_POINTER_REALTIME_BUFFER_LIMIT,
    maxAgeMs: SHARED_SPACE_POINTER_REALTIME_MAX_AGE_MS,
    nowMs: now,
  });
  state.sharedSpacePointerDiagnostics.staleDrops += result.dropped;
  roomSamples[pointerKey] = result.samples;
  state.sharedSpacePointerPendingRealtimeSamples[roomId] = roomSamples;
}

function consumeSharedSpacePointerPendingRealtime(sharedSpaceId, key) {
  const roomId = cleanText(sharedSpaceId, "");
  const pointerKey = cleanText(key, "");
  const roomSamples = roomId ? state.sharedSpacePointerPendingRealtimeSamples[roomId] || null : null;
  const samples = Array.isArray(roomSamples?.[pointerKey]) ? roomSamples[pointerKey] : [];
  if (roomSamples && pointerKey) delete roomSamples[pointerKey];
  return samples;
}

function pushSharedSpacePointerScreenTarget(points, x, y) {
  if (!Number.isFinite(x) || !Number.isFinite(y)) return;
  const last = points[points.length - 1] || null;
  if (!last || Math.hypot(x - last.x, y - last.y) >= 0.35) points.push({ x, y });
}

function sharedSpacePointerScreenPath(pointer = {}, targetX = 0, targetY = 0, sourcePath = null) {
  const points = [];
  const path = Array.isArray(sourcePath) && sourcePath.length
    ? sourcePath
    : (Array.isArray(pointer.path) && pointer.path.length ? pointer.path : [{ x: pointer.x, y: pointer.y }]);
  path.forEach((point) => {
    const clean = cleanSharedSpacePointerPoint(point);
    if (clean) pushSharedSpacePointerScreenTarget(points, logicalToScreenPx(clean.x), logicalToScreenPx(clean.y));
  });
  pushSharedSpacePointerScreenTarget(points, targetX, targetY);
  return points;
}

function sharedSpacePointerScreenRealtimeSamples(samples = []) {
  const screenSamples = [];
  (Array.isArray(samples) ? samples : []).forEach((sample) => {
    const clean = cleanSharedSpacePointerPoint(sample);
    const at = Number(sample?.at);
    if (clean && Number.isFinite(at)) {
      screenSamples.push({
        x: logicalToScreenPx(clean.x),
        y: logicalToScreenPx(clean.y),
        at,
      });
    }
  });
  return screenSamples;
}

function sharedSpacePointerDroppedFrameAge(now) {
  const lastDroppedAt = Number(state.sharedSpacePointerDiagnostics.lastDroppedFrameAt || 0);
  return lastDroppedAt > 0 ? now - lastDroppedAt : Number.POSITIVE_INFINITY;
}

function sharedSpacePointerReplayFrame(now) {
  const diagnostics = state.sharedSpacePointerDiagnostics;
  return {
    fps: Number(diagnostics.fps || 0),
    droppedFrameAgeMs: sharedSpacePointerDroppedFrameAge(now),
  };
}

function sharedSpacePointerLowLatencyReplayActive(now) {
  const fps = Number(state.sharedSpacePointerDiagnostics.fps || 0);
  return (fps <= 0 || fps >= SHARED_POINTER_RENDER_DEFAULTS.replayHealthyMinFps)
    && sharedSpacePointerDroppedFrameAge(now) >= SHARED_SPACE_POINTER_RENDER_PATH_DROPPED_COOLDOWN_MS;
}

function sharedSpacePointerFrameProgressCapMs() {
  const fps = Number(state.sharedSpacePointerDiagnostics.fps || 0);
  if (!Number.isFinite(fps) || fps <= 0) return 1000 / 60;
  return clamp(1000 / fps, 1000 / 144, 1000 / 30);
}

function trimSharedSpacePointerReplayPath(points = [], visual, targetX, targetY, now) {
  if (!sharedSpacePointerLowLatencyReplayActive(now)) return points;
  if (!Array.isArray(points) || points.length <= SHARED_SPACE_POINTER_RENDER_PATH_LOW_LATENCY_POINTS) return points;
  const tail = points.slice(-SHARED_SPACE_POINTER_RENDER_PATH_LOW_LATENCY_POINTS);
  const first = tail[0] || null;
  const x = Number(visual?.x);
  const y = Number(visual?.y);
  if (Number.isFinite(x) && Number.isFinite(y) && first && Math.hypot(first.x - x, first.y - y) >= 1.5) {
    tail.unshift({ x, y });
  }
  pushSharedSpacePointerScreenTarget(tail, targetX, targetY);
  return tail;
}

function noteSharedSpacePointerVelocity(visual, targetX, targetY, now, previousTargetAt, previousTargetX, previousTargetY) {
  const fromX = Number(previousTargetX);
  const fromY = Number(previousTargetY);
  if (![fromX, fromY, targetX, targetY].every(Number.isFinite)) return;
  const interval = clamp(now - Number(previousTargetAt || now), SHARED_SPACE_POINTER_SEND_MS, SHARED_SPACE_POINTER_VELOCITY_INTERVAL_MAX_MS);
  const vx = (targetX - fromX) / Math.max(1, interval);
  const vy = (targetY - fromY) / Math.max(1, interval);
  const hadVelocity = Number.isFinite(Number(visual.velocityX)) && Number.isFinite(Number(visual.velocityY));
  visual.velocityX = hadVelocity ? visual.velocityX * 0.55 + vx * 0.45 : vx;
  visual.velocityY = hadVelocity ? visual.velocityY * 0.55 + vy * 0.45 : vy;
  visual.velocityAt = now;
}

function predictSharedSpacePointerFrameTarget(visual, frameTarget, now) {
  if (!state.sharedSpacePointerPredictionEnabled) {
    visual.predictionLeadMs = 0;
    visual.predictionPx = 0;
    return { ...frameTarget, predicted: false };
  }
  const targetAgeMs = Math.max(0, now - Number(visual.targetReceivedAt || now));
  const velocityAgeMs = Math.max(0, now - Number(visual.velocityAt || now));
  const remaining = Math.hypot(Number(visual.targetX || 0) - Number(visual.x || 0), Number(visual.targetY || 0) - Number(visual.y || 0));
  const staleMs = SHARED_SPACE_POINTER_PREDICTION_STALE_MS;
  const leadCeiling = velocityAgeMs > staleMs || (!frameTarget.pathActive && remaining < 6)
    ? 0
    : SHARED_SPACE_POINTER_PREDICTION_MAX_LEAD_MS;
  const predicted = predictSharedPointerPosition(frameTarget, {
    x: Number(visual.velocityX || 0),
    y: Number(visual.velocityY || 0),
  }, {
    maxLeadMs: leadCeiling,
    maxDistancePx: SHARED_SPACE_POINTER_PREDICTION_MAX_PX,
    staleMs,
    targetAgeMs: Math.max(targetAgeMs, velocityAgeMs * 0.35),
  });
  visual.predictionLeadMs = predicted.leadMs;
  visual.predictionPx = predicted.distancePx;
  return { ...frameTarget, x: predicted.x, y: predicted.y, predicted: predicted.predicted };
}

function appendSharedSpacePointerVisualRealtime(visual, samples = [], now = performance.now()) {
  const screenSamples = sharedSpacePointerScreenRealtimeSamples(samples);
  if (!screenSamples.length) return 0;
  const result = appendSharedPointerRealtimeSamples(visual.realtimeSamples || [], screenSamples, {
    limit: SHARED_SPACE_POINTER_REALTIME_BUFFER_LIMIT,
    maxAgeMs: SHARED_SPACE_POINTER_REALTIME_MAX_AGE_MS,
    nowMs: now,
  });
  visual.realtimeSamples = result.samples;
  state.sharedSpacePointerDiagnostics.staleDrops += result.dropped;
  if (screenSamples.length >= 2) {
    const previous = screenSamples[screenSamples.length - 2];
    const latest = screenSamples[screenSamples.length - 1];
    const interval = clamp(latest.at - previous.at, SHARED_SPACE_POINTER_SEND_MS, SHARED_SPACE_POINTER_VELOCITY_INTERVAL_MAX_MS);
    visual.velocityX = (latest.x - previous.x) / Math.max(1, interval);
    visual.velocityY = (latest.y - previous.y) / Math.max(1, interval);
    visual.velocityAt = now;
  }
  return screenSamples.length;
}

function sharedSpacePointerRealtimeFrameTarget(visual, fallbackX, fallbackY, now, pointer = {}) {
  const local = cleanText(pointer.realtime_source || "", "") === "local";
  const predictionEnabled = Boolean(state.sharedSpacePointerPredictionEnabled);
  const result = sampleSharedPointerRealtimeBuffer(visual.realtimeSamples || [], now, {
    bufferDelayMs: local ? 0 : SHARED_SPACE_POINTER_REALTIME_BUFFER_MS,
    maxPredictionMs: predictionEnabled ? (local ? 8 : SHARED_SPACE_POINTER_REALTIME_PREDICTION_MAX_MS) : 0,
    maxPredictionDistancePx: predictionEnabled ? (local ? 18 : SHARED_SPACE_POINTER_REALTIME_PREDICTION_MAX_PX) : 0,
    staleMs: SHARED_SPACE_POINTER_REALTIME_STALE_MS,
  });
  if (!result) return null;
  visual.predictionLeadMs = result.predictionMs;
  visual.predictionPx = result.predictionPx;
  visual.netAgeMs = result.netAgeMs;
  visual.renderBufferMs = result.bufferDelayMs;
  visual.realtimeMode = local ? result.mode.replace(/^net/, "local") : result.mode;
  return {
    x: Number.isFinite(result.x) ? result.x : fallbackX,
    y: Number.isFinite(result.y) ? result.y : fallbackY,
    pathActive: false,
    realtime: true,
    predicted: result.mode === "net-predict",
    mode: local ? visual.realtimeMode : result.mode,
    netAgeMs: result.netAgeMs,
    renderBufferMs: result.bufferDelayMs,
    predictionMs: result.predictionMs,
    predictionPx: result.predictionPx,
    sampleCount: result.sampleCount,
  };
}

function sharedSpacePointerMotionOptions(frameTarget, now) {
  if (frameTarget.realtime) {
    if (cleanText(frameTarget.mode || "", "").startsWith("local")) {
      return { smoothingMs: 1.5, fastSmoothingMs: 1, fastDistancePx: 18, maxSpeedPxPerSecond: 7200 };
    }
    return { smoothingMs: 3, fastSmoothingMs: 2, fastDistancePx: 24, maxSpeedPxPerSecond: 4800 };
  }
  if (!frameTarget.pathActive) return undefined;
  if (sharedSpacePointerLowLatencyReplayActive(now)) {
    return { smoothingMs: 5, fastSmoothingMs: 3, fastDistancePx: 28, maxSpeedPxPerSecond: 9000 };
  }
  return { smoothingMs: 8, fastSmoothingMs: 5, fastDistancePx: 36, maxSpeedPxPerSecond: 5200 };
}

function startSharedSpacePointerVisualPath(visual, pointer, targetX, targetY, now, previousTargetAt, roomId, previousTargetX, previousTargetY) {
  const pendingPath = consumeSharedSpacePointerPendingPath(roomId, pointer.key, pointer.path);
  let points = sharedSpacePointerScreenPath(pointer, targetX, targetY, pendingPath);
  if (points.length < 2 || Math.hypot(targetX - visual.x, targetY - visual.y) >= SHARED_POINTER_RENDER_DEFAULTS.snapDistancePx) {
    visual.pathPoints = [];
    visual.pathStartedAt = 0;
    visual.pathDurationMs = 0;
    visual.pathProgress = 0;
    visual.pathFrameAt = now;
    visual.replayMode = "snap";
    noteSharedSpacePointerVelocity(visual, targetX, targetY, now, previousTargetAt, previousTargetX, previousTargetY);
    return;
  }
  if (Math.hypot(points[0].x - visual.x, points[0].y - visual.y) >= 1.5) {
    points.unshift({ x: visual.x, y: visual.y });
  }
  points = trimSharedSpacePointerReplayPath(points, visual, targetX, targetY, now);
  const arrivalInterval = Math.max(1, now - Number(previousTargetAt || now));
  const replay = adaptiveSharedPointerReplayDuration(arrivalInterval, sharedSpacePointerReplayFrame(now), {
    lowLatencyMinMs: SHARED_SPACE_POINTER_RENDER_PATH_LOW_LATENCY_MIN_MS,
    lowLatencyMaxMs: SHARED_SPACE_POINTER_RENDER_PATH_LOW_LATENCY_MAX_MS,
    stableMinMs: SHARED_SPACE_POINTER_RENDER_PATH_STABLE_MIN_MS,
    stableMaxMs: SHARED_SPACE_POINTER_RENDER_PATH_STABLE_MAX_MS,
    droppedFrameCooldownMs: SHARED_SPACE_POINTER_RENDER_PATH_DROPPED_COOLDOWN_MS,
  });
  visual.pathPoints = points;
  visual.pathStartedAt = now;
  visual.pathProgress = 0;
  visual.pathFrameAt = now;
  visual.pathDurationMs = replay.durationMs;
  visual.replayMode = replay.mode;
  noteSharedSpacePointerVelocity(visual, targetX, targetY, now, previousTargetAt, previousTargetX, previousTargetY);
}

function sharedSpacePointerFrameTarget(visual, fallbackX, fallbackY, now) {
  if (!Array.isArray(visual.pathPoints) || visual.pathPoints.length < 2 || !visual.pathStartedAt || !visual.pathDurationMs) {
    return { x: fallbackX, y: fallbackY, pathActive: false };
  }
  const frameDt = visual.pathFrameAt ? Math.max(0, now - Number(visual.pathFrameAt || now)) : 1000 / 60;
  visual.pathFrameAt = now;
  const progressStep = Math.min(0.34, Math.min(frameDt || 1000 / 60, sharedSpacePointerFrameProgressCapMs()) / Math.max(1, visual.pathDurationMs));
  const progress = clamp(Number(visual.pathProgress || 0) + progressStep, 0, 1);
  visual.pathProgress = progress;
  const point = sampleSharedPointerPath(visual.pathPoints, progress);
  if (progress >= 1) {
    visual.pathPoints = [];
    visual.pathStartedAt = 0;
    visual.pathDurationMs = 0;
    visual.pathProgress = 0;
  }
  return point ? { ...point, pathActive: progress < 1 } : { x: fallbackX, y: fallbackY, pathActive: false };
}

function clearSharedSpacePointerVisuals(layer = null) {
  if (state.sharedSpacePointerVisualFrame) {
    window.cancelAnimationFrame(state.sharedSpacePointerVisualFrame);
    state.sharedSpacePointerVisualFrame = 0;
  }
  Object.values(state.sharedSpacePointerVisuals || {}).forEach((visual) => {
    visual.node?.remove();
    visual.trail?.remove();
  });
  state.sharedSpacePointerVisuals = {};
  state.sharedSpacePointerVisualRoomId = "";
  state.sharedSpacePointerVisualLastAt = 0;
  state.sharedSpacePointerPendingPaths = {};
  state.sharedSpacePointerPendingRealtimeSamples = {};
  state.sharedSpacePointerRenderLayer = "dom";
  const board = els.spaceBoard || spaceSurface();
  (layer || board?.querySelector?.("[data-shared-space-pointer-layer]"))?.remove();
}

function ensureSharedSpacePointerLayer(board) {
  if (!board) return null;
  let layer = board.querySelector("[data-shared-space-pointer-layer]");
  if (!layer) {
    layer = document.createElement("div");
    layer.className = "shared-space-pointer-layer";
    layer.dataset.sharedSpacePointerLayer = "true";
    board.append(layer);
  }
  return layer;
}

function sharedSpacePointerCanvasDpr(width, height) {
  const raw = Math.max(1, Number(window.devicePixelRatio || 1));
  const pixels = Math.max(1, Number(width || 1) * Number(height || 1));
  const maxPixels = 12_000_000;
  return Math.max(1, Math.min(raw, Math.sqrt(maxPixels / pixels)));
}

function ensureSharedSpacePointerCanvas(layer, board) {
  if (state.sharedSpacePointerCanvasFailed || !layer || !board || !("HTMLCanvasElement" in window)) return null;
  let canvas = layer.querySelector("[data-shared-space-pointer-canvas]");
  if (!canvas) {
    canvas = document.createElement("canvas");
    canvas.className = "shared-space-pointer-canvas";
    canvas.dataset.sharedSpacePointerCanvas = "true";
    canvas.setAttribute("aria-hidden", "true");
    layer.prepend(canvas);
  }
  let context = canvas.getContext("2d", { alpha: true, desynchronized: true });
  if (!context) {
    canvas.remove();
    state.sharedSpacePointerCanvasFailed = true;
    return null;
  }
  const rect = board.getBoundingClientRect?.();
  const width = Math.max(1, Math.ceil(board.scrollWidth || board.clientWidth || rect?.width || 1));
  const height = Math.max(1, Math.ceil(board.scrollHeight || board.clientHeight || rect?.height || 1));
  const dpr = sharedSpacePointerCanvasDpr(width, height);
  const pixelWidth = Math.max(1, Math.round(width * dpr));
  const pixelHeight = Math.max(1, Math.round(height * dpr));
  if (canvas.width !== pixelWidth || canvas.height !== pixelHeight) {
    canvas.width = pixelWidth;
    canvas.height = pixelHeight;
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;
  }
  context.setTransform(dpr, 0, 0, dpr, 0, 0);
  context.imageSmoothingEnabled = true;
  return { canvas, context, width, height, dpr };
}

function roundedCanvasRect(context, x, y, width, height, radius) {
  const r = Math.max(0, Math.min(radius, width / 2, height / 2));
  context.beginPath();
  context.moveTo(x + r, y);
  context.lineTo(x + width - r, y);
  context.quadraticCurveTo(x + width, y, x + width, y + r);
  context.lineTo(x + width, y + height - r);
  context.quadraticCurveTo(x + width, y + height, x + width - r, y + height);
  context.lineTo(x + r, y + height);
  context.quadraticCurveTo(x, y + height, x, y + height - r);
  context.lineTo(x, y + r);
  context.quadraticCurveTo(x, y, x + r, y);
  context.closePath();
}

function clippedCanvasLabel(context, label, maxWidth = 140) {
  const text = cleanText(label, "Member");
  if (context.measureText(text).width <= maxWidth) return text;
  let clipped = text;
  while (clipped.length > 1 && context.measureText(`${clipped}...`).width > maxWidth) {
    clipped = clipped.slice(0, -1);
  }
  return `${clipped || "M"}...`;
}

function renderSharedSpacePointerCanvas(surface, entries = [], now = performance.now()) {
  const { context, width, height, dpr } = surface;
  context.clearRect(0, 0, width, height);
  for (const { visual } of entries) {
    const samples = visual.history || [];
    const maxAge = SHARED_SPACE_POINTER_RENDER_HISTORY_MAX_AGE_MS;
    for (const sample of samples) {
      const age = clamp(now - Number(sample.at || 0), 0, maxAge);
      const life = 1 - age / maxAge;
      if (life <= 0) continue;
      context.globalAlpha = life * 0.52;
      context.fillStyle = visual.color || "#7ddcff";
      context.beginPath();
      context.arc(
        snapSharedPointerPixel(Number(sample.x || 0) + 2, dpr),
        snapSharedPointerPixel(Number(sample.y || 0) + 2, dpr),
        2.4 + life * 2.2,
        0,
        Math.PI * 2
      );
      context.fill();
    }
  }
  context.globalAlpha = 1;
  context.font = "700 11px system-ui, -apple-system, BlinkMacSystemFont, sans-serif";
  context.textBaseline = "middle";
  for (const { visual, pointer, pulseActive } of entries) {
    const x = snapSharedPointerPixel(visual.x, dpr);
    const y = snapSharedPointerPixel(visual.y, dpr);
    if (pulseActive && visual.pulseStartedAt) {
      const progress = clamp((now - visual.pulseStartedAt) / SHARED_SPACE_POINTER_CLICK_TTL_MS, 0, 1);
      context.globalAlpha = 0.92 * (1 - progress);
      context.strokeStyle = visual.color || pointer.color || "#7ddcff";
      context.lineWidth = 3;
      context.beginPath();
      context.arc(x + 2, y + 2, 12 + progress * 48, 0, Math.PI * 2);
      context.stroke();
    }
    context.globalAlpha = 1;
    context.fillStyle = visual.color || pointer.color || "#7ddcff";
    context.save();
    context.translate(x + 2, y + 2);
    context.rotate(0.59);
    context.beginPath();
    context.moveTo(0, -9);
    context.lineTo(14, 0);
    context.lineTo(0, 9);
    context.closePath();
    context.fill();
    context.restore();
    const label = clippedCanvasLabel(context, visual.label || pointer.user_label || "Member", 132);
    const textWidth = Math.min(132, context.measureText(label).width);
    const labelX = x + 23;
    const labelY = y + 2;
    const pillWidth = textWidth + 16;
    roundedCanvasRect(context, labelX, labelY - 10, pillWidth, 20, 10);
    context.fillStyle = visual.color || pointer.color || "#7ddcff";
    context.fill();
    context.strokeStyle = "rgba(255, 255, 255, 0.24)";
    context.lineWidth = 1;
    context.stroke();
    context.fillStyle = "#050a12";
    context.fillText(label, labelX + 8, labelY);
  }
  context.globalAlpha = 1;
}

function createSharedSpacePointerTrail(pointer) {
  const trail = document.createElement("div");
  trail.className = "shared-space-pointer-trail";
  trail.dataset.sharedSpacePointerTrail = pointer.key;
  trail.style.setProperty("--shared-pointer-color", pointer.color);
  const fragment = document.createDocumentFragment();
  for (let index = 0; index < SHARED_SPACE_POINTER_RENDER_HISTORY_LIMIT; index += 1) {
    const dot = document.createElement("span");
    dot.setAttribute("aria-hidden", "true");
    fragment.append(dot);
  }
  trail.append(fragment);
  return trail;
}

function createSharedSpacePointerNode(pointer) {
  const node = document.createElement("div");
  node.className = "shared-space-pointer";
  node.dataset.sharedSpacePointer = pointer.key;
  node.innerHTML = '<span class="shared-space-pointer-mark" aria-hidden="true"></span><strong></strong><i aria-hidden="true"></i>';
  return node;
}

function releaseSharedSpacePointerDom(visual) {
  visual.node?.remove();
  visual.trail?.remove();
  visual.node = null;
  visual.trail = null;
  visual.trailDots = [];
}

function ensureSharedSpacePointerDom(layer, visual, pointer) {
  if (!visual.trail) {
    visual.trail = createSharedSpacePointerTrail(pointer);
    visual.trailDots = Array.from(visual.trail.children);
  }
  if (!visual.node) visual.node = createSharedSpacePointerNode(pointer);
  if (!visual.trail.isConnected || !visual.node.isConnected) layer.append(visual.trail, visual.node);
}

function ensureSharedSpacePointerVisual(layer, pointer, targetX, targetY, now) {
  let visual = state.sharedSpacePointerVisuals[pointer.key];
  if (!visual) {
    visual = {
      key: pointer.key,
      node: null,
      trail: null,
      trailDots: [],
      x: targetX,
      y: targetY,
      targetX,
      targetY,
      targetId: "",
      targetReceivedAt: now,
      pathPoints: [],
      pathStartedAt: 0,
      pathDurationMs: 0,
      pathProgress: 0,
      pathFrameAt: now,
      replayMode: "idle",
      velocityX: 0,
      velocityY: 0,
      velocityAt: now,
      predictionLeadMs: 0,
      predictionPx: 0,
      netAgeMs: 0,
      renderBufferMs: SHARED_SPACE_POINTER_REALTIME_BUFFER_MS,
      realtimeSamples: [],
      realtimeMode: "idle",
      lastSeenAt: now,
      lastDistance: canvasDistance(),
      history: [],
      mode: "settled",
      pulseId: "",
      pulseStartedAt: 0,
      label: "",
      color: "",
    };
    state.sharedSpacePointerVisuals[pointer.key] = visual;
  }
  return visual;
}

function renderSharedSpacePointerTrail(visual, now) {
  visual.history = pruneSharedPointerSamples(visual.history, now, {
    limit: SHARED_SPACE_POINTER_RENDER_HISTORY_LIMIT,
    maxAgeMs: SHARED_SPACE_POINTER_RENDER_HISTORY_MAX_AGE_MS,
  });
  const samples = visual.history;
  const dots = visual.trailDots || [];
  const maxAge = SHARED_SPACE_POINTER_RENDER_HISTORY_MAX_AGE_MS;
  for (let index = 0; index < dots.length; index += 1) {
    const dot = dots[index];
    const sample = samples[samples.length - 1 - index];
    if (!sample) {
      dot.style.opacity = "0";
      continue;
    }
    const age = clamp(now - Number(sample.at || 0), 0, maxAge);
    const life = 1 - age / maxAge;
    const dpr = window.devicePixelRatio || 1;
    dot.style.opacity = String(Number((life * 0.52).toFixed(3)));
    dot.style.transform = `translate3d(${snapSharedPointerPixel(sample.x + 2, dpr)}px, ${snapSharedPointerPixel(sample.y + 2, dpr)}px, 0) scale(${Number((0.38 + life * 0.62).toFixed(3))})`;
  }
}

function updateSharedSpacePointerPulse(visual, pointer, now) {
  const pulseId = cleanText(pointer.pulse_id || "", "");
  const clicking = Date.now() < Number(pointer.click_until || 0);
  if (clicking && pulseId && visual.pulseId !== pulseId) {
    visual.pulseId = pulseId;
    visual.pulseStartedAt = now;
  }
  return Boolean(clicking && visual.pulseStartedAt && now - visual.pulseStartedAt < SHARED_SPACE_POINTER_CLICK_TTL_MS);
}

function renderSharedSpacePointerClickPulse(visual, pointer, now) {
  const ring = visual.node?.querySelector("i");
  if (!ring) return updateSharedSpacePointerPulse(visual, pointer, now);
  const active = updateSharedSpacePointerPulse(visual, pointer, now);
  if (!active) {
    ring.style.opacity = "0";
    ring.style.transform = "scale(0.24)";
    visual.node?.classList.remove("is-clicking");
    return false;
  }
  const progress = clamp((now - visual.pulseStartedAt) / SHARED_SPACE_POINTER_CLICK_TTL_MS, 0, 1);
  ring.style.opacity = String(Number((0.92 * (1 - progress)).toFixed(3)));
  ring.style.transform = `scale(${Number((0.24 + progress * 2.01).toFixed(3))})`;
  visual.node?.classList.add("is-clicking");
  return progress < 1;
}

function renderSharedSpacePointerDiagnostics(layer, now, liveCount, activeCount) {
  const existing = layer?.querySelector?.("[data-shared-space-pointer-diagnostics]");
  if (!state.sharedSpacePointerDiagnosticsEnabled) {
    existing?.remove();
    return;
  }
  if (!layer) return;
  let node = existing;
  if (!node) {
    node = document.createElement("dl");
    node.className = "shared-space-pointer-diagnostics";
    node.dataset.sharedSpacePointerDiagnostics = "true";
    layer.append(node);
  }
  const diagnostics = state.sharedSpacePointerDiagnostics;
  if (!diagnostics.lastEventRateAt) {
    diagnostics.lastEventRateAt = now;
    diagnostics.lastEventRateCount = diagnostics.eventCount;
  } else if (now - diagnostics.lastEventRateAt >= 1000) {
    diagnostics.eventRate = (diagnostics.eventCount - diagnostics.lastEventRateCount) * 1000 / Math.max(1, now - diagnostics.lastEventRateAt);
    diagnostics.lastEventRateAt = now;
    diagnostics.lastEventRateCount = diagnostics.eventCount;
  }
  if (now - Number(diagnostics.lastRenderAt || 0) < SHARED_SPACE_POINTER_DIAGNOSTICS_UPDATE_MS) return;
  diagnostics.lastRenderAt = now;
  const queueLength = Number(state.sharedSpacePointerMoveSamples?.length || 0);
  const rows = [
    ["FPS", diagnostics.fps ? diagnostics.fps.toFixed(0) : "0"],
    ["Dropped", String(diagnostics.droppedFrames || 0)],
    ["Events", `${diagnostics.eventRate.toFixed(1)}/s`],
    ["Latency", `${Math.round(diagnostics.latencyMs || 0)}ms`],
    ["Samples", `${diagnostics.sampleCount || 0}/${activeCount}`],
    ["Queue", String(queueLength)],
    ["Mode", diagnostics.mode || "idle"],
    ["Replay", `${diagnostics.replayMode || "idle"} ${Math.round(diagnostics.replayMs || 0)}ms`],
    ["Lead", `${Math.round(diagnostics.predictionLeadMs || 0)}ms/${Math.round(diagnostics.predictionPx || 0)}px`],
    ["NetAge", `${Math.round(diagnostics.netAgeMs || 0)}ms`],
    ["Buffer", `${Math.round(diagnostics.renderBufferMs || 0)}ms`],
    ["InputSend", `${Math.round(diagnostics.inputToSendMs || 0)}ms`],
    ["Wire", `${Math.round(diagnostics.transportLatencyMs || 0)}ms`],
    ["Paint", `${Math.round(diagnostics.paintLatencyMs || 0)}ms`],
    ["Predict", state.sharedSpacePointerPredictionEnabled ? `${Math.round(diagnostics.realtimePredictionMs || 0)}ms/${Math.round(diagnostics.realtimePredictionPx || 0)}px` : "off"],
    ["Drops", String(diagnostics.staleDrops || 0)],
    ["Input", diagnostics.inputMode || "move"],
    ["Transport", diagnostics.transport || "json"],
    ["Binary", `${diagnostics.binaryReceived || 0}/${diagnostics.binarySent || 0}`],
    ["RTC", `${diagnostics.rtcOpen || 0}/${diagnostics.rtcPeers || 0}`],
    ["Fallback", String(diagnostics.dragFallbackSent || 0)],
    ["Local", String(diagnostics.localEchoes || 0)],
    ["BinKB", `${((diagnostics.binaryBytesReceived + diagnostics.binaryBytesSent) / 1024).toFixed(1)}`],
    ["RtcKB", `${((diagnostics.rtcBytesReceived + diagnostics.rtcBytesSent) / 1024).toFixed(1)}`],
    ["Layer", state.sharedSpacePointerRenderLayer || "dom"],
    ["Live", String(liveCount)],
  ];
  node.replaceChildren(...rows.flatMap(([term, value]) => {
    const dt = document.createElement("dt");
    const dd = document.createElement("dd");
    dt.textContent = term;
    dd.textContent = value;
    return [dt, dd];
  }));
}

function sharedSpacePointerVisibleIdentity(pointer = {}) {
  const userId = cleanText(pointer.user_id || pointer.userId, "");
  if (userId) return `user:${numericSharedPointerId(userId).toString(36)}`;
  const label = cleanText(pointer.user_label || pointer.label, "").toLowerCase();
  if (label) return `label:${label}`;
  return cleanText(pointer.key || pointer.pointer_event_id || pointer.event_id, "");
}

function sharedSpacePointerFreshnessRank(pointer = {}) {
  const source = cleanText(pointer.realtime_source || "", "").toLowerCase();
  if (source === "local") return 70;
  if (source === "rtc") return 60;
  if (source === "binary") return 55;
  if (source === "rt") return 40;
  if (source === "fallback") return 20;
  return 10;
}

function sharedSpacePointerPreferred(first = {}, second = {}) {
  const firstRank = sharedSpacePointerFreshnessRank(first);
  const secondRank = sharedSpacePointerFreshnessRank(second);
  if (firstRank !== secondRank) return firstRank > secondRank ? first : second;
  const firstSeq = Number(first.realtime_seq || 0);
  const secondSeq = Number(second.realtime_seq || 0);
  if (firstSeq !== secondSeq) return firstSeq > secondSeq ? first : second;
  const firstAt = Math.max(Number(first.received_at || 0), Number(first.last_seen_at || 0));
  const secondAt = Math.max(Number(second.received_at || 0), Number(second.last_seen_at || 0));
  return firstAt >= secondAt ? first : second;
}

function selectVisibleSharedSpacePointers(pointers = []) {
  const visibleByIdentity = new Map();
  const hidden = [];
  (Array.isArray(pointers) ? pointers : []).forEach((pointer) => {
    const identity = sharedSpacePointerVisibleIdentity(pointer);
    if (!identity) {
      hidden.push(pointer);
      return;
    }
    const existing = visibleByIdentity.get(identity);
    if (!existing) {
      visibleByIdentity.set(identity, pointer);
      return;
    }
    const preferred = sharedSpacePointerPreferred(existing, pointer);
    visibleByIdentity.set(identity, preferred);
    hidden.push(preferred === existing ? pointer : existing);
  });
  return { visible: Array.from(visibleByIdentity.values()), hidden };
}

function stepSharedSpacePointerVisuals(now = performance.now()) {
  state.sharedSpacePointerVisualFrame = 0;
  const target = currentSharedSpacePointerTarget();
  const board = els.spaceBoard || spaceSurface();
  if (!target || !board) {
    clearSharedSpacePointerVisuals();
    return;
  }
  let layer = ensureSharedSpacePointerLayer(board);
  if (!layer) return;
  if (state.sharedSpacePointerVisualRoomId && state.sharedSpacePointerVisualRoomId !== target.room.id) {
    clearSharedSpacePointerVisuals(layer);
    layer = ensureSharedSpacePointerLayer(board);
    if (!layer) return;
  }
  state.sharedSpacePointerVisualRoomId = target.room.id;
  const previousFrameAt = Number(state.sharedSpacePointerVisualLastAt || 0);
  const dt = previousFrameAt ? clamp(now - previousFrameAt, 0, 96) : 1000 / 60;
  state.sharedSpacePointerVisualLastAt = now;
  const diagnostics = state.sharedSpacePointerDiagnostics;
  if (dt > 0) {
    const instantFps = 1000 / dt;
    diagnostics.fps = diagnostics.fps ? diagnostics.fps * 0.9 + instantFps * 0.1 : instantFps;
    if (dt >= SHARED_SPACE_POINTER_RENDER_DROPPED_FRAME_MS) {
      diagnostics.droppedFrames += Math.max(1, Math.round(dt / (1000 / 60)) - 1);
      diagnostics.lastDroppedFrameAt = now;
    }
  }
  const epochNow = Date.now();
  const pointers = state.sharedSpacePointers[target.room.id] || {};
  const livePointers = Object.values(pointers).filter((pointer) => epochNow - Number(pointer.last_seen_at || 0) <= SHARED_SPACE_POINTER_TTL_MS);
  const selection = selectVisibleSharedSpacePointers(livePointers);
  const live = selection.visible;
  selection.hidden.forEach((pointer) => {
    const key = cleanText(pointer?.key || "", "");
    if (!key) return;
    consumeSharedSpacePointerPendingPath(target.room.id, key, []);
    consumeSharedSpacePointerPendingRealtime(target.room.id, key);
  });
  const canvasSurface = ensureSharedSpacePointerCanvas(layer, board);
  const useCanvas = Boolean(canvasSurface);
  state.sharedSpacePointerRenderLayer = useCanvas ? "canvas" : "dom";
  if (!useCanvas) layer.querySelector("[data-shared-space-pointer-canvas]")?.remove();
  const seen = new Set();
  const canvasEntries = [];
  let keepAnimating = state.sharedSpacePointerDiagnosticsEnabled;
  let sampleCount = 0;
  let mode = "idle";
  let predictionLeadMs = 0;
  let predictionPx = 0;
  let netAgeMs = 0;
  let renderBufferMs = SHARED_SPACE_POINTER_REALTIME_BUFFER_MS;
  let realtimePredictionMs = 0;
  let realtimePredictionPx = 0;
  let realtimeSampleCount = 0;
  let replayMs = 0;
  let replayMode = "idle";
  let paintLatencyMs = 0;
  for (const pointer of live) {
    seen.add(pointer.key);
    const targetX = logicalToScreenPx(pointer.x);
    const targetY = logicalToScreenPx(pointer.y);
    if (!Number.isFinite(targetX) || !Number.isFinite(targetY)) continue;
    const visualWasNew = !state.sharedSpacePointerVisuals[pointer.key];
    const visual = ensureSharedSpacePointerVisual(layer, pointer, targetX, targetY, now);
    const targetId = sharedSpacePointerTargetId(pointer);
    const distanceChanged = Math.abs(Number(visual.lastDistance || 1) - canvasDistance()) > 0.001;
    const pendingRealtime = consumeSharedSpacePointerPendingRealtime(target.room.id, pointer.key);
    if (visual.targetId !== targetId || distanceChanged) {
      const previousTargetAt = Number(visual.targetReceivedAt || now);
      const previousTargetX = Number(visual.targetX);
      const previousTargetY = Number(visual.targetY);
      visual.targetX = targetX;
      visual.targetY = targetY;
      visual.targetId = targetId;
      visual.targetReceivedAt = Number(pointer.received_at || now);
      visual.lastSeenAt = now;
      if (distanceChanged) {
        visual.x = targetX;
        visual.y = targetY;
        visual.history = [];
        visual.pathPoints = [];
        visual.pathStartedAt = 0;
        visual.pathDurationMs = 0;
        visual.pathProgress = 0;
        visual.pathFrameAt = now;
        visual.replayMode = "reset";
        visual.velocityX = 0;
        visual.velocityY = 0;
        visual.velocityAt = now;
        visual.predictionLeadMs = 0;
        visual.predictionPx = 0;
        visual.netAgeMs = 0;
        visual.renderBufferMs = SHARED_SPACE_POINTER_REALTIME_BUFFER_MS;
        visual.realtimeSamples = [];
        visual.realtimeMode = "reset";
        consumeSharedSpacePointerPendingPath(target.room.id, pointer.key, []);
      } else {
        appendSharedSpacePointerVisualRealtime(visual, pendingRealtime, now);
        startSharedSpacePointerVisualPath(
          visual,
          pointer,
          targetX,
          targetY,
          now,
          previousTargetAt,
          target.room.id,
          previousTargetX,
          previousTargetY
        );
      }
    } else {
      visual.targetX = targetX;
      visual.targetY = targetY;
      appendSharedSpacePointerVisualRealtime(visual, pendingRealtime, now);
    }
    if (visualWasNew && Array.isArray(visual.realtimeSamples) && visual.realtimeSamples.length) {
      const seed = sampleSharedPointerRealtimeBuffer(visual.realtimeSamples, now, {
        bufferDelayMs: SHARED_SPACE_POINTER_REALTIME_BUFFER_MS,
        maxPredictionMs: 0,
        maxPredictionDistancePx: 0,
        staleMs: SHARED_SPACE_POINTER_REALTIME_STALE_MS,
      }) || visual.realtimeSamples[0];
      if (
        seed
        && Number.isFinite(Number(seed.x))
        && Number.isFinite(Number(seed.y))
        && Math.hypot(Number(seed.x) - targetX, Number(seed.y) - targetY) < SHARED_POINTER_RENDER_DEFAULTS.snapDistancePx
      ) {
        visual.x = Number(seed.x);
        visual.y = Number(seed.y);
        visual.history = [];
      }
    }
    visual.lastDistance = canvasDistance();
    const realtimeFrameTarget = sharedSpacePointerRealtimeFrameTarget(visual, visual.targetX, visual.targetY, now, pointer);
    const rawFrameTarget = realtimeFrameTarget || sharedSpacePointerFrameTarget(visual, visual.targetX, visual.targetY, now);
    const frameTarget = realtimeFrameTarget || predictSharedSpacePointerFrameTarget(visual, rawFrameTarget, now);
    const next = smoothSharedPointerPosition(
      { x: visual.x, y: visual.y },
      { x: frameTarget.x, y: frameTarget.y },
      dt,
      sharedSpacePointerMotionOptions(frameTarget, now)
    );
    visual.x = next.x;
    visual.y = next.y;
    visual.mode = next.mode;
    if (frameTarget.realtime) mode = frameTarget.mode || "net";
    else if (frameTarget.predicted) mode = "lead";
    else if (frameTarget.pathActive) mode = "path";
    else if (next.mode !== "settled") mode = next.mode;
    if (next.snapped) {
      visual.history = [];
      visual.pathPoints = [];
      visual.pathStartedAt = 0;
      visual.pathDurationMs = 0;
      visual.pathProgress = 0;
      visual.pathFrameAt = now;
      visual.replayMode = "snap";
      visual.realtimeSamples = [];
      visual.realtimeMode = "snap";
      visual.predictionLeadMs = 0;
      visual.predictionPx = 0;
    }
    const label = pointer.user_label || "Member";
    visual.label = label;
    visual.color = pointer.color;
    pushSharedPointerSample(visual.history, { x: visual.x, y: visual.y, at: now }, {
      limit: SHARED_SPACE_POINTER_RENDER_HISTORY_LIMIT,
    });
    let pulseActive = false;
    if (useCanvas) {
      releaseSharedSpacePointerDom(visual);
      pulseActive = updateSharedSpacePointerPulse(visual, pointer, now);
      canvasEntries.push({ visual, pointer, pulseActive });
    } else {
      ensureSharedSpacePointerDom(layer, visual, pointer);
      visual.node.style.transform = sharedSpacePointerSnappedTransform(visual.x, visual.y);
      visual.node.style.setProperty("--shared-pointer-color", pointer.color);
      visual.trail.style.setProperty("--shared-pointer-color", pointer.color);
      visual.node.querySelector("strong").textContent = label;
      renderSharedSpacePointerTrail(visual, now);
      pulseActive = renderSharedSpacePointerClickPulse(visual, pointer, now);
    }
    const remaining = Math.hypot(visual.targetX - visual.x, visual.targetY - visual.y);
    sampleCount += visual.history.length;
    predictionLeadMs = Math.max(predictionLeadMs, Number(visual.predictionLeadMs || 0));
    predictionPx = Math.max(predictionPx, Number(visual.predictionPx || 0));
    netAgeMs = Math.max(netAgeMs, Number(visual.netAgeMs || 0));
    renderBufferMs = Math.max(renderBufferMs, Number(visual.renderBufferMs || 0));
    paintLatencyMs = Math.max(paintLatencyMs, clamp(now - Number(visual.targetReceivedAt || now), 0, 5000));
    if (frameTarget.realtime) {
      realtimePredictionMs = Math.max(realtimePredictionMs, Number(frameTarget.predictionMs || 0));
      realtimePredictionPx = Math.max(realtimePredictionPx, Number(frameTarget.predictionPx || 0));
      realtimeSampleCount += Number(frameTarget.sampleCount || 0);
    }
    replayMs = Math.max(replayMs, Number(visual.pathDurationMs || 0));
    if (visual.replayMode && visual.replayMode !== "idle") replayMode = visual.replayMode;
    keepAnimating = keepAnimating
      || remaining > SHARED_POINTER_RENDER_DEFAULTS.settlePx
      || frameTarget.pathActive
      || visual.history.length > 0
      || pulseActive;
  }
  if (useCanvas) renderSharedSpacePointerCanvas(canvasSurface, canvasEntries, now);
  Object.entries(state.sharedSpacePointerVisuals).forEach(([key, visual]) => {
    if (seen.has(key)) return;
    visual.node?.remove();
    visual.trail?.remove();
    consumeSharedSpacePointerPendingPath(target.room.id, key, []);
    consumeSharedSpacePointerPendingRealtime(target.room.id, key);
    delete state.sharedSpacePointerVisuals[key];
  });
  diagnostics.sampleCount = sampleCount;
  diagnostics.predictionLeadMs = predictionLeadMs;
  diagnostics.predictionPx = predictionPx;
  diagnostics.netAgeMs = netAgeMs;
  diagnostics.renderBufferMs = renderBufferMs;
  diagnostics.paintLatencyMs = paintLatencyMs;
  diagnostics.realtimePredictionMs = realtimePredictionMs;
  diagnostics.realtimePredictionPx = realtimePredictionPx;
  diagnostics.realtimeSampleCount = realtimeSampleCount;
  diagnostics.inputMode = state.sharedSpacePointerInputMode || "move";
  diagnostics.replayMs = replayMs;
  diagnostics.replayMode = replayMode;
  diagnostics.mode = mode;
  renderSharedSpacePointerDiagnostics(layer, now, live.length, Object.keys(state.sharedSpacePointerVisuals).length);
  if (keepAnimating) scheduleSharedSpacePointerRender("visual-active");
}

function scheduleSharedSpacePointerRender(origin = "pointer-render") {
  const target = currentSharedSpacePointerTarget();
  if (!target) {
    clearSharedSpacePointerVisuals();
    return;
  }
  if (state.sharedSpacePointerVisualFrame) return;
  state.sharedSpacePointerVisualFrame = window.requestAnimationFrame(stepSharedSpacePointerVisuals);
}

function renderSharedSpacePointers() {
  scheduleSharedSpacePointerRender("render-request");
}

function sharedSpacePointerNavigationBlocked() {
  return Boolean(
    state.spacePanActive
    || state.spacePanMomentumActive
    || state.spacePinchActive
    || Boolean(state.activePointers?.size)
    || performance.now() < state.spacePinchSuppressPanUntil
    || performance.now() - Number(state.spaceNavigationInputAt || 0) < 120
  );
}

function sharedSpacePointerFollowScrollTarget(pointer) {
  const viewport = els.spaceViewport;
  const rect = spaceViewportUsableRect() || viewport?.getBoundingClientRect?.();
  if (!viewport || !rect || !pointer) return null;
  const visibleWidth = Math.max(1, Number(rect.width || viewport.clientWidth || 1));
  const visibleHeight = Math.max(1, Number(rect.height || viewport.clientHeight || 1));
  const margin = Math.min(
    SHARED_SPACE_POINTER_FOLLOW_MARGIN_PX,
    Math.max(48, Math.min(visibleWidth, visibleHeight) * 0.28)
  );
  const x = logicalToScreenPx(pointer.x);
  const y = logicalToScreenPx(pointer.y);
  let left = viewport.scrollLeft;
  let top = viewport.scrollTop;
  if (x < viewport.scrollLeft + margin) left = x - margin;
  else if (x > viewport.scrollLeft + visibleWidth - margin) left = x - visibleWidth + margin;
  if (y < viewport.scrollTop + margin) top = y - margin;
  else if (y > viewport.scrollTop + visibleHeight - margin) top = y - visibleHeight + margin;
  return {
    left: clamp(left, 0, Math.max(0, viewport.scrollWidth - viewport.clientWidth)),
    top: clamp(top, 0, Math.max(0, viewport.scrollHeight - viewport.clientHeight)),
  };
}

function stepSharedSpacePointerNavigationFollow() {
  state.sharedSpacePointerFollowFrame = 0;
  const target = state.sharedSpacePointerFollowTarget;
  const active = currentSharedSpacePointerTarget();
  const viewport = els.spaceViewport;
  if (!target || !active || !viewport || target.shared_space_id !== active.room.id) return;
  if (Date.now() - Number(target.at || 0) > SHARED_SPACE_POINTER_TTL_MS) return;
  if (sharedSpacePointerNavigationBlocked()) return;
  const desired = sharedSpacePointerFollowScrollTarget(target);
  if (!desired) return;
  const dx = desired.left - viewport.scrollLeft;
  const dy = desired.top - viewport.scrollTop;
  if (Math.abs(dx) <= SHARED_SPACE_POINTER_FOLLOW_SETTLE_PX && Math.abs(dy) <= SHARED_SPACE_POINTER_FOLLOW_SETTLE_PX) return;
  const stepX = clamp(dx * SHARED_SPACE_POINTER_FOLLOW_EASE, -SHARED_SPACE_POINTER_FOLLOW_MAX_STEP_PX, SHARED_SPACE_POINTER_FOLLOW_MAX_STEP_PX);
  const stepY = clamp(dy * SHARED_SPACE_POINTER_FOLLOW_EASE, -SHARED_SPACE_POINTER_FOLLOW_MAX_STEP_PX, SHARED_SPACE_POINTER_FOLLOW_MAX_STEP_PX);
  if (isAndroidNativeShell()) state.androidSharedPointerFollowScrollAt = performance.now();
  viewport.scrollLeft += Math.abs(stepX) < SHARED_SPACE_POINTER_FOLLOW_SETTLE_PX ? dx : stepX;
  viewport.scrollTop += Math.abs(stepY) < SHARED_SPACE_POINTER_FOLLOW_SETTLE_PX ? dy : stepY;
  if (isAndroidNativeShell()) {
    updateSpaceNavigationHints();
    scheduleSpaceMiniMapViewportSync("shared-pointer-follow");
  } else {
    updateSpaceNavigationHints();
    renderSpaceMiniMap();
  }
  scheduleSharedSpacePointerNavigationFollow();
}

function scheduleSharedSpacePointerNavigationFollow() {
  if (state.sharedSpacePointerFollowFrame || sharedSpacePointerNavigationBlocked()) return;
  state.sharedSpacePointerFollowFrame = window.requestAnimationFrame(stepSharedSpacePointerNavigationFollow);
}

function clearSharedSpacePointerMoveQueue() {
  if (state.sharedSpacePointerMoveFrame) window.cancelAnimationFrame(state.sharedSpacePointerMoveFrame);
  if (state.sharedSpacePointerMoveTimer) window.clearTimeout(state.sharedSpacePointerMoveTimer);
  state.sharedSpacePointerMoveFrame = 0;
  state.sharedSpacePointerMoveTimer = 0;
  state.sharedSpacePointerMoveEvent = null;
  state.sharedSpacePointerMoveSamples = [];
}

function flushSharedSpacePointerMove() {
  state.sharedSpacePointerMoveFrame = 0;
  const event = state.sharedSpacePointerMoveEvent;
  if (!event) return;
  const dueIn = state.sharedSpacePointerLastSentAt + SHARED_SPACE_POINTER_SEND_MS - performance.now();
  if (dueIn > 4) {
    scheduleSharedSpacePointerMoveFlush();
    return;
  }
  state.sharedSpacePointerMoveEvent = null;
  const samples = state.sharedSpacePointerMoveSamples.slice();
  state.sharedSpacePointerMoveSamples = [];
  void sendSharedSpacePointerEvent("move", event, { liveOnly: true, samples, localEcho: false });
}

function scheduleSharedSpacePointerMoveFlush() {
  if (state.sharedSpacePointerMoveFrame || state.sharedSpacePointerMoveTimer) return;
  const dueIn = state.sharedSpacePointerLastSentAt + SHARED_SPACE_POINTER_SEND_MS - performance.now();
  if (dueIn > 4) {
    state.sharedSpacePointerMoveTimer = window.setTimeout(() => {
      state.sharedSpacePointerMoveTimer = 0;
      state.sharedSpacePointerMoveFrame = window.requestAnimationFrame(flushSharedSpacePointerMove);
    }, dueIn);
    return;
  }
  state.sharedSpacePointerMoveFrame = window.requestAnimationFrame(flushSharedSpacePointerMove);
}

function isSharedSpacePointerMove(event) {
  if (event?.isPrimary === false) return false;
  if (event?.pointerType === "mouse") {
    const buttons = Number(event.buttons || 0);
    return !buttons || (buttons & 1) === 1;
  }
  return true;
}

function isSharedSpacePointerDragMove(event) {
  return Number(event?.buttons || 0) !== 0;
}

function queueSharedSpacePointerMove(event, options = {}) {
  if (!isSharedSpacePointerMove(event)) return;
  const now = performance.now();
  if (androidCanvasNavigationActive(now)) return;
  if (isAndroidNativeShell() && isSharedSpacePointerDragMove(event)) return;
  if (options.raw) {
    state.sharedSpacePointerRawInputAt = now;
    state.sharedSpacePointerInputMode = "raw";
  } else if (state.sharedSpacePointerRawInputAt && now - state.sharedSpacePointerRawInputAt < SHARED_SPACE_POINTER_RAW_DEDUPE_MS) {
    return;
  } else {
    state.sharedSpacePointerInputMode = "move";
  }
  const coalesced = typeof event.getCoalescedEvents === "function" ? event.getCoalescedEvents() : [];
  const samples = coalesced.length ? coalesced : [event];
  const latest = samples[samples.length - 1] || event;
  const snapshots = samples.map((sample) => sharedSpacePointerEventSnapshot(sample, event));
  state.sharedSpacePointerMoveSamples.push(...snapshots);
  if (state.sharedSpacePointerMoveSamples.length > SHARED_SPACE_POINTER_SAMPLE_BUFFER_LIMIT) {
    state.sharedSpacePointerMoveSamples = state.sharedSpacePointerMoveSamples.slice(-SHARED_SPACE_POINTER_SAMPLE_BUFFER_LIMIT);
  }
  state.sharedSpacePointerMoveEvent = sharedSpacePointerEventSnapshot(latest, event);
  echoSharedSpacePointerLocalEvent("move", state.sharedSpacePointerMoveEvent, {
    samples: snapshots,
    source: options.raw ? "local-raw" : "local-move",
  });
  scheduleSharedSpacePointerMoveFlush();
}

async function sendSharedSpacePointerEvent(type, event, options = {}) {
  const target = currentSharedSpacePointerTarget();
  if (!target) return;
  const point = sharedSpacePointerPoint(event);
  if (!point) return;
  const now = performance.now();
  if (type === "move" && !options.force && now - state.sharedSpacePointerLastSentAt < SHARED_SPACE_POINTER_SEND_MS) return;
  state.sharedSpacePointerLastSentAt = now;
  const realtimeSamples = sharedSpacePointerRealtimeSamplesFromEvents(options.samples, event, now);
  const latestRealtimeSample = realtimeSamples[realtimeSamples.length - 1] || null;
  if (latestRealtimeSample) {
    noteSharedSpacePointerDiagnosticAverage("inputToSendMs", clamp(now - Number(latestRealtimeSample.at || now), 0, 2000));
  }
  const seq = state.sharedSpacePointerSendSeq + 1;
  state.sharedSpacePointerSendSeq = seq;
  const durableDue = type !== "move" || now - Number(state.sharedSpacePointerLastDurableSentAt || 0) >= SHARED_SPACE_POINTER_DURABLE_MS;
  const liveOnly = type === "move" && options.liveOnly === true && !durableDue;
  const dragFallbackDue = liveOnly
    && isSharedSpacePointerDragMove(event)
    && now - Number(state.sharedSpacePointerLastDragFallbackSentAt || 0) >= SHARED_SPACE_POINTER_DRAG_FALLBACK_MS;
  const pointerEventId = remoteControlId("space_ptr");
  const path = type === "move"
    ? sharedSpacePointerPathFromSamples(options.samples, point, state.sharedSpacePointerLastMovePoint)
    : [];
  if (options.localEcho !== false) {
    echoSharedSpacePointerLocalEvent(type, event, {
      target,
      point,
      now,
      seq,
      pointerEventId,
      samples: options.samples,
      realtimeSamples,
      path,
    });
  }
  if (liveOnly) {
    const packetBuffer = createSharedSpacePointerBinaryBuffer(realtimeSamples, seq, now);
    const peerSent = sendSharedSpacePointerPeerBinaryEvent(target, packetBuffer);
    const socketSent = sendSharedSpacePointerBinaryEvent(target, realtimeSamples, seq, now, packetBuffer);
    if (peerSent || socketSent) {
      state.sharedSpacePointerLastMovePoint = point;
      return;
    }
  }
  const payload = {
    type,
    pointer_event_id: pointerEventId,
    x: point.x,
    y: point.y,
    device_id: clientDeviceId(),
    device_hash: sharedSpacePointerLocalDeviceHash(),
    user_label: publicUserLabel(state.authUser),
    distance: Number(canvasDistance().toFixed(2)),
    sent_at_ms: Date.now(),
    sent_perf_ms: Number(now.toFixed(2)),
    event_time_ms: Number(event?.timeStamp || now),
    rt: {
      v: 1,
      seq,
      transport: "json",
      sent_perf_ms: Number(now.toFixed(2)),
      samples: encodeSharedPointerRealtimeSamples(realtimeSamples, now, {
        limit: SHARED_SPACE_POINTER_REALTIME_SAMPLE_LIMIT,
      }),
    },
  };
  if (path.length > 1) payload.points = path;
  const body = {
    action: "event",
    shared_space_id: target.space.shared_space_id,
    space_id: target.space.id,
    kind: SHARED_SPACE_POINTER_EVENT_KIND,
    payload,
  };
  if (type === "move" || type === "down") state.sharedSpacePointerLastMovePoint = point;
  if (["up", "click"].includes(type)) state.sharedSpacePointerLastMovePoint = null;
  const liveSent = sendSharedSpacePointerLiveEvent(target, body, { liveOnly });
  if (liveSent) {
    if (!liveOnly) state.sharedSpacePointerLastDurableSentAt = now;
    return;
  }
  if (type === "move" && !durableDue && !dragFallbackDue) return;
  if (dragFallbackDue) {
    state.sharedSpacePointerLastDragFallbackSentAt = now;
    state.sharedSpacePointerDiagnostics.dragFallbackSent += 1;
  }
  state.sharedSpacePointerLastDurableSentAt = now;
  void fetchJson("/spaces/room", {
    method: "POST",
    timeoutMs: 2500,
    body,
  }).then((result) => {
    if (result?.room?.id) {
      state.sharedRooms[result.room.id] = result.room;
      mergeSharedSpacePointerEvents(result.room.id, result.room.events);
    }
  }).catch(() => {});
}

async function syncSharedSpacePointers(origin = "pointer-poll") {
  const target = currentSharedSpacePointerTarget();
  if (!target || state.sharedSpacePointerSyncBusy) return;
  state.sharedSpacePointerSyncBusy = true;
  try {
    const payload = await fetchJson("/spaces/room", {
      method: "POST",
      timeoutMs: 2500,
      body: {
        action: "read",
        shared_space_id: target.space.shared_space_id,
        space_id: target.space.id,
      },
    });
    const room = payload.room || null;
    if (room?.id) {
      state.sharedRooms[room.id] = room;
      mergeSharedSpacePointerEvents(room.id, room.events);
      queueSharedSpacePointerPeerProcessing(room);
      renderSharedSpacePointers();
    }
  } catch (error) {
    if (origin !== "pointer-poll") {
      recordUserEvent("workspace.shared_space_pointer_sync_error", {
        target: `space:${target.space.id}`,
        summary: error.message,
        data: { shared_space_id: target.space.shared_space_id, error: error.message },
      });
    }
  } finally {
    state.sharedSpacePointerSyncBusy = false;
  }
}

function updateSharedSpacePointerSync() {
  const shouldRun = Boolean(state.authUser && currentSharedSpacePointerTarget());
  if (!shouldRun) {
    closeSharedSpacePointerLiveSocket();
    clearSharedSpacePointerMoveQueue();
    state.sharedSpacePointerLastMovePoint = null;
    state.sharedSpacePointerLocalLastPoint = null;
    if (state.sharedSpacePointerFollowFrame) window.cancelAnimationFrame(state.sharedSpacePointerFollowFrame);
    state.sharedSpacePointerFollowFrame = 0;
    state.sharedSpacePointerFollowTarget = null;
    if (state.sharedSpacePointerSyncInterval) {
      window.clearInterval(state.sharedSpacePointerSyncInterval);
      state.sharedSpacePointerSyncInterval = 0;
    }
    renderSharedSpacePointers();
    closeSharedSpacePointerRtcPeers();
    return;
  }
  startSharedSpacePointerLiveSocket("pointer-sync");
  queueSharedSpacePointerPeerProcessing(currentSharedSpacePointerTarget()?.room);
  if (!state.sharedSpacePointerSyncInterval) {
    state.sharedSpacePointerSyncInterval = window.setInterval(
      () => void syncSharedSpacePointers("pointer-poll"),
      SHARED_SPACE_POINTER_POLL_MS
    );
    void syncSharedSpacePointers("pointer-start");
  }
}

function installSharedSpacePointerAwareness() {
  document.addEventListener("pointerrawupdate", (event) => queueSharedSpacePointerMove(event, { raw: true }), { capture: true, passive: true });
  document.addEventListener("pointermove", queueSharedSpacePointerMove, { capture: true, passive: true });
  document.addEventListener("pointerdown", (event) => {
    if (!isPrimaryPointer(event)) return;
    clearSharedSpacePointerMoveQueue();
    state.sharedSpacePointerPress = {
      pointer_id: Number(event.pointerId || 0),
      x: Number(event.clientX || 0),
      y: Number(event.clientY || 0),
      at: performance.now(),
    };
    void sendSharedSpacePointerEvent("down", sharedSpacePointerEventSnapshot(event), { force: true });
  }, { capture: true, passive: true });
  document.addEventListener("pointerup", (event) => {
    if (!isPrimaryPointer(event)) return;
    clearSharedSpacePointerMoveQueue();
    const press = state.sharedSpacePointerPress;
    state.sharedSpacePointerPress = null;
    const samePointer = !press?.pointer_id || Number(event.pointerId || 0) === press.pointer_id;
    const quickTap = Boolean(
      press
      && samePointer
      && performance.now() - Number(press.at || 0) <= 700
      && Math.hypot(Number(event.clientX || 0) - Number(press.x || 0), Number(event.clientY || 0) - Number(press.y || 0)) <= 14
    );
    void sendSharedSpacePointerEvent(quickTap ? "click" : "up", sharedSpacePointerEventSnapshot(event), { force: true });
  }, { capture: true, passive: true });
  document.addEventListener("pointercancel", (event) => {
    if (!isPrimaryPointer(event)) return;
    clearSharedSpacePointerMoveQueue();
    state.sharedSpacePointerPress = null;
    void sendSharedSpacePointerEvent("up", sharedSpacePointerEventSnapshot(event), { force: true });
  }, { capture: true, passive: true });
}

function remoteSpaceAreaChanged(before, after) {
  const beforeArea = spaceAreaFromMetadata(before?.space_area);
  const afterArea = spaceAreaFromMetadata(after?.space_area);
  if (!before?.shared_space_id || before.shared_space_id !== after?.shared_space_id || !afterArea) return false;
  return !beforeArea || beforeArea.width !== afterArea.width || beforeArea.height !== afterArea.height;
}

function updateSharedSpaceSyncPolling() {
  const shouldPoll = Boolean(state.authUser && sharedUserSpaceForPanel());
  if (!shouldPoll) {
    if (state.sharedSpaceSyncInterval) {
      window.clearInterval(state.sharedSpaceSyncInterval);
      state.sharedSpaceSyncInterval = 0;
    }
    updateSharedSpacePointerSync();
    return;
  }
  if (!state.sharedSpaceSyncInterval) {
    state.sharedSpaceSyncInterval = window.setInterval(
      () => void syncSharedSpaceForOpenClient("shared-space-poll"),
      SHARED_SPACE_SYNC_POLL_MS
    );
    void syncSharedSpaceForOpenClient("shared-space-start");
  }
  updateSharedSpacePointerSync();
}

async function syncSharedSpaceForOpenClient(origin = "shared-space-poll") {
  if (state.sharedSpaceSyncBusy || !sharedUserSpaceForPanel()) return;
  state.sharedSpaceSyncBusy = true;
  try {
    const room = await loadSharedSpaceRoom({ origin });
    if (room?.id) await syncSharedSpaceChatEvents(room.id, origin);
    state.lastSharedSpaceSyncAt = new Date().toISOString();
  } catch (error) {
    recordUserEvent("workspace.shared_space_sync_error", {
      target: `space:${state.activePanel}`,
      summary: error.message,
      data: { origin, error: error.message },
    });
  } finally {
    state.sharedSpaceSyncBusy = false;
    updateSharedSpaceSyncPolling();
  }
}

function applySharedRoomArea(room, origin = "shared-room") {
  const activeSpace = sharedUserSpaceForPanel();
  const roomArea = spaceAreaFromMetadata(room?.space_area);
  if (!activeSpace || activeSpace.shared_space_id !== room?.id) return false;
  if (!roomArea) {
    renderSpaceTitle();
    renderSpaceLauncher();
    return false;
  }
  const changed = !sameSpaceArea(activeSpace.space_area, roomArea);
  state.userSpaces = state.userSpaces.map((space) => (
    space.shared_space_id === room.id ? { ...space, space_area: serializableSpaceArea(roomArea) } : space
  ));
  if (!changed || !shouldSyncUserSpacesFromServer()) {
    renderSpaceTitle();
    renderSpaceLauncher();
    return false;
  }
  applySpaceWidgetLayout(state.activePanel);
  renderSpaceTitle();
  renderSpaceLauncher();
  recordUserEvent("workspace.shared_space_area_applied", {
    target: `space:${activeSpace.id}`,
    summary: `Applied shared space area ${formatAreaSize(roomArea)}`,
    data: {
      origin,
      space_id: activeSpace.id,
      shared_space_id: room.id,
      width_px: roomArea.width,
      height_px: roomArea.height,
    },
  });
  return true;
}

async function loadSharedSpaceRoom(options = {}) {
  const space = sharedUserSpaceForPanel();
  if (!space) return null;
  const payload = await fetchJson("/spaces/room", {
    method: "POST",
    timeoutMs: 5000,
    body: {
      action: "presence",
      space_id: space.id,
      shared_space_id: space.shared_space_id,
    },
  });
  const room = payload.room || null;
  if (room?.id) {
    state.sharedRooms[room.id] = room;
    mergeSharedSpacePointerEvents(room.id, room.events);
    queueSharedSpacePointerPeerProcessing(room);
    applySharedRoomArea(room, options.origin || "shared-room");
    renderSharedVoice();
    if (state.agentView === "people") renderAgentPeoplePanel();
    queueSharedVoiceRoomProcessing(room);
    updateSharedSpacePointerSync();
  }
  return room;
}

function sharedVoiceIceServers() {
  const configured = state.config?.features?.sharedVoice?.iceServers;
  const source = Array.isArray(configured) && configured.length ? configured : SHARED_VOICE_DEFAULT_ICE_SERVERS;
  const servers = source.map((item) => {
    if (!item || typeof item !== "object") return null;
    const rawUrls = item.urls;
    const urls = Array.isArray(rawUrls)
      ? rawUrls.map((url) => String(url || "").trim()).filter(Boolean)
      : String(rawUrls || "").trim();
    if (!urls || (Array.isArray(urls) && !urls.length)) return null;
    const server = { urls };
    if (item.username) server.username = String(item.username);
    if (item.credential) server.credential = String(item.credential);
    return server;
  }).filter(Boolean);
  return servers.length ? servers : SHARED_VOICE_DEFAULT_ICE_SERVERS;
}

function sharedVoicePayload(event) {
  return sharedVoiceSignalPayload(event, SHARED_VOICE_SIGNAL_SCHEMA);
}

function sharedVoiceEventIsFresh(event) {
  return sharedVoiceSignalIsFresh(event, Date.now(), SHARED_VOICE_STALE_MS);
}

function sharedVoicePresenceEntries(room = activeSharedRoom()) {
  const entries = Array.isArray(room?.presence) ? room.presence : [];
  return entries.filter((entry) => entry && typeof entry === "object" && entry.device_id);
}

function sharedVoiceCurrentClientId() {
  return SHARED_VOICE_LOCAL_CLIENT_ID;
}

function sharedVoiceCurrentDeviceId(_room = activeSharedRoom()) {
  return SHARED_VOICE_LOCAL_DEVICE_ID;
}

function sharedVoiceCurrentUserId(room = activeSharedRoom()) {
  return cleanText(room?.current_user_id, state.authUser?.id || "");
}

function sharedVoiceLocalMembershipState() {
  const voice = state.sharedVoice;
  if (voice.status === "leaving") return "leaving";
  if (voice.connecting) return "joining";
  if (voice.active && voice.localStream) return "joined";
  if (voice.active || voice.waiting) return "joining";
  return "idle";
}

function sharedVoiceDebugLog(eventType, details = {}) {
  try {
    const room = details.room || activeSharedRoom();
    const voice = state.sharedVoice || {};
    const payload = details.payload && typeof details.payload === "object" ? details.payload : {};
    const localDeviceId = sharedVoiceCurrentDeviceId(room);
    const accepted = Object.prototype.hasOwnProperty.call(details, "accepted") ? Boolean(details.accepted) : !details.ignored;
    const record = {
      scope: "wasm-agent.shared-voice",
      at: new Date().toISOString(),
      roomId: cleanText(details.roomId || payload.room_id || voice.roomId || room?.id || "", ""),
      localDeviceId,
      localClientId: sharedVoiceCurrentClientId(),
      localMembershipState: sharedVoiceLocalMembershipState(),
      localJoinEpoch: cleanText(voice.joinEpoch || "", ""),
      eventType: cleanText(eventType || "", ""),
      fromDeviceId: cleanText(details.fromDeviceId || payload.from_device_id || "", ""),
      toDeviceId: cleanText(details.toDeviceId || payload.to_device_id || "", ""),
      peerDeviceId: cleanText(details.peerDeviceId || "", ""),
      callId: cleanText(details.callId || payload.call_id || "", ""),
      accepted,
      ignored: Boolean(details.ignored),
      ignoreReason: cleanText(details.ignoreReason || "", ""),
    };
    console.debug("[wasm-agent shared-voice]", record);
  } catch {
    // Debug logging must never affect voice lifecycle behavior.
  }
}

function sharedVoicePeerByDevice(deviceId, room = activeSharedRoom()) {
  const membership = sharedVoiceMembershipMap(room).get(deviceId);
  if (membership) return sharedVoicePeerEntryFromMembership(membership, room);
  return sharedVoicePresenceEntries(room).find((entry) => entry.device_id === deviceId) || null;
}

function sharedVoicePeerLabel(peer) {
  if (!peer) return "peer";
  const user = cleanText(peer.user_label || peer.userId, "");
  const device = cleanText(peer.label || peer.client_id || peer.clientId || peer.device_id || peer.deviceId, "");
  return user && device ? `${user} / ${device}` : user || device || "peer";
}

function sharedVoiceShouldInitiateOffer(room, peer) {
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  return sharedVoiceShouldInitiateRoomOffer(currentDeviceId, peer?.device_id);
}

function sharedVoiceMembershipMap(room = activeSharedRoom()) {
  return sharedVoiceMemberships(room?.events, {
    kind: SHARED_VOICE_SIGNAL_KIND,
    schema: SHARED_VOICE_SIGNAL_SCHEMA,
    staleMs: SHARED_VOICE_STALE_MS,
    membershipTtlMs: SHARED_VOICE_MEMBERSHIP_STALE_MS,
  });
}

function sharedVoicePeerEntryFromMembership(membership, room = activeSharedRoom()) {
  const payload = membership?.payload || {};
  const presence = sharedVoicePresenceEntries(room).find((entry) => entry.user_id && entry.user_id === membership.userId) || {};
  const clientId = cleanText(payload.from_client_id || "", "");
  const deviceId = cleanText(membership.deviceId || payload.from_device_id || "", "");
  return {
    device_id: deviceId,
    user_id: cleanText(membership.userId || payload.from_user_id || "", ""),
    user_label: cleanText(presence.user_label || payload.from_user_label || payload.from_user_id || "", ""),
    label: cleanText(presence.label || clientId || deviceId || "voice tab", ""),
    client_id: clientId,
    join_epoch: cleanText(membership.joinEpoch || payload.join_epoch || "", ""),
    join_event_id: cleanText(membership.joinEventId || payload.join_event_id || "", ""),
  };
}

function sharedVoiceMembershipPeerEntries(room = activeSharedRoom()) {
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  return Array.from(sharedVoiceMembershipMap(room).values())
    .filter((membership) => membership.deviceId && membership.deviceId !== currentDeviceId)
    .map((membership) => sharedVoicePeerEntryFromMembership(membership, room));
}

function sharedVoiceJoinedPeerCandidates(room = activeSharedRoom()) {
  return sharedVoiceMembershipPeerEntries(room);
}

function sharedVoiceMediaUnavailableReason() {
  if (!window.isSecureContext) return "HTTPS required";
  if (!window.RTCPeerConnection) return "WebRTC unavailable";
  if (!navigator.mediaDevices?.getUserMedia) return "Microphone unavailable";
  return "";
}

function renderSharedVoice() {
  if (!els.sharedVoiceBar) return;
  const space = sharedUserSpaceForPanel();
  const room = activeSharedRoom();
  const voice = state.sharedVoice;
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  const joinedCandidates = sharedVoiceJoinedPeerCandidates(room);
  const peers = sharedVoicePeerStates();
  const connectedPeers = peers.filter(sharedVoicePeerIsConnected);
  const connectingPeers = peers.filter((peer) => peer.pc && !sharedVoicePeerIsConnected(peer));
  const visible = Boolean(space && state.config?.features?.sharedVoice?.enabled !== false);
  els.sharedVoiceBar.hidden = !visible;
  if (!visible) return;
  const connected = connectedPeers.length > 0;
  els.sharedVoiceBar.classList.toggle("is-active", Boolean(voice.active && !voice.error));
  els.sharedVoiceBar.classList.toggle("is-connecting", Boolean((voice.connecting || connectingPeers.length) && !connected && !voice.error));
  els.sharedVoiceBar.classList.toggle("is-error", Boolean(voice.error));
  if (els.sharedVoiceButton) {
    const mediaProblem = sharedVoiceMediaUnavailableReason();
    els.sharedVoiceButton.disabled = voice.active ? false : Boolean(mediaProblem || !room?.id || !currentDeviceId);
    const label = voice.active
      ? "Leave shared voice"
      : joinedCandidates.length
          ? "Join shared voice"
          : "Start shared voice";
    els.sharedVoiceButton.title = mediaProblem || label;
    els.sharedVoiceButton.setAttribute("aria-label", els.sharedVoiceButton.title);
  }
  if (els.sharedVoiceMuteButton) {
    els.sharedVoiceMuteButton.hidden = !voice.active;
    els.sharedVoiceMuteButton.disabled = !voice.localStream;
    els.sharedVoiceMuteButton.setAttribute("aria-pressed", voice.muted ? "true" : "false");
    els.sharedVoiceMuteButton.title = voice.muted ? "Unmute microphone" : "Mute microphone";
    els.sharedVoiceMuteButton.setAttribute("aria-label", els.sharedVoiceMuteButton.title);
  }
  if (els.sharedVoiceRemoteAudio && voice.remoteStream && els.sharedVoiceRemoteAudio.srcObject !== voice.remoteStream) {
    els.sharedVoiceRemoteAudio.srcObject = voice.remoteStream;
    els.sharedVoiceRemoteAudio.play?.().catch(() => {});
  }
  if (els.sharedVoiceStatus) {
    const mediaProblem = sharedVoiceMediaUnavailableReason();
    let text = "start voice";
    if (!currentDeviceId) text = "syncing";
    if (mediaProblem) text = mediaProblem;
    if (!joinedCandidates.length && !voice.active && !mediaProblem && currentDeviceId) text = "alone";
    if (joinedCandidates.length && !voice.active) text = "voice ready";
    if (voice.active && !peers.length) text = "waiting";
    if (voice.waiting) text = "waiting";
    if (voice.connecting || connectingPeers.length) {
      text = peers.length > 1 ? `connecting ${peers.length}` : `connecting ${peers[0]?.label || voice.peerLabel || "peer"}`;
    }
    if (connected) {
      text = connectedPeers.length > 1 ? `${connectedPeers.length} connected` : connectedPeers[0]?.label || voice.peerLabel || "connected";
    }
    if (voice.muted && voice.active) text = `muted ${connectedPeers.length ? text : ""}`.trim();
    if (voice.error) text = voice.error;
    els.sharedVoiceStatus.textContent = text;
    els.sharedVoiceStatus.title = text;
  }
}

function resetSharedVoiceRuntime(keepError = false) {
  const previousError = state.sharedVoice.error;
  if (state.sharedVoice.pollInterval) {
    window.clearInterval(state.sharedVoice.pollInterval);
  }
  closeSharedVoicePeers();
  state.sharedVoice.localStream?.getTracks?.().forEach((track) => track.stop());
  if (els.sharedVoiceRemoteAudio) els.sharedVoiceRemoteAudio.srcObject = null;
  Object.assign(state.sharedVoice, {
    active: false,
    connecting: false,
    waiting: false,
    muted: false,
    peerMuted: false,
    status: "idle",
    error: keepError ? previousError : "",
    roomId: "",
    callId: "",
    peerDeviceId: "",
    peerUserId: "",
    peerLabel: "",
    localStream: null,
    remoteStream: null,
    peerConnection: null,
    peers: {},
    pendingIceCandidates: [],
    pollInterval: 0,
    signalBusy: false,
    signalQueue: Promise.resolve(),
    processedSignalIds: new Set(),
    joinedAtMs: 0,
    joinedEventId: "",
    joinEpoch: "",
    lastMembershipHeartbeatAt: 0,
    makingOffer: false,
    ignoreOffer: false,
    polite: true,
  });
  renderSharedVoice();
}

function startSharedVoicePolling() {
  if (state.sharedVoice.pollInterval) window.clearInterval(state.sharedVoice.pollInterval);
  const configured = Number(state.config?.features?.sharedVoice?.signalingPollMs);
  const pollMs = Number.isFinite(configured) ? clamp(configured, 500, 5000) : SHARED_VOICE_POLL_MS;
  state.sharedVoice.pollInterval = window.setInterval(() => {
    if (!state.sharedVoice.active && !state.sharedVoice.connecting) return;
    void sendSharedVoiceMembershipHeartbeat();
    void loadSharedSpaceRoom({ origin: "shared-voice-poll" }).catch((error) => {
      state.sharedVoice.error = truncateText(error.message || "voice sync failed", 80);
      renderSharedVoice();
    });
  }, pollMs);
}

async function sendSharedVoiceMembershipHeartbeat(force = false) {
  const voice = state.sharedVoice;
  if (!voice.active || !voice.localStream || !voice.joinEpoch) return null;
  if (!force && Date.now() - Number(voice.lastMembershipHeartbeatAt || 0) < SHARED_VOICE_MEMBERSHIP_HEARTBEAT_MS) return null;
  voice.lastMembershipHeartbeatAt = Date.now();
  return sendSharedVoiceRoomSignal("membership", {
    joined: true,
    heartbeat: true,
    call_id: `voice_room_${voice.roomId || activeSharedRoom()?.id || "shared"}`,
    join_epoch: voice.joinEpoch,
    join_event_id: voice.joinedEventId || "",
  }).catch((error) => {
    voice.error = truncateText(error.message || "voice membership failed", 80);
    renderSharedVoice();
    return null;
  });
}

function markSharedVoiceJoinBaseline(room = activeSharedRoom()) {
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  const item = sharedVoiceLatestJoinEvent(room?.events, currentDeviceId, {
    kind: SHARED_VOICE_SIGNAL_KIND,
    schema: SHARED_VOICE_SIGNAL_SCHEMA,
    staleMs: SHARED_VOICE_STALE_MS,
    membershipTtlMs: SHARED_VOICE_MEMBERSHIP_STALE_MS,
  });
  const event = item?.event || null;
  const joinedAtMs = sharedVoiceEventCreatedMs(event) || Date.now();
  state.sharedVoice.joinedAtMs = Math.max(Number(state.sharedVoice.joinedAtMs || 0), joinedAtMs);
  if (event?.id) state.sharedVoice.joinedEventId = event.id;
  if (item?.payload?.join_epoch) state.sharedVoice.joinEpoch = String(item.payload.join_epoch);
}

function sharedVoiceEventBeforeCurrentJoin(event, payload) {
  if (!payload || payload.type === "join") return false;
  return sharedVoiceEventPrecedesBaseline(
    event,
    Number(state.sharedVoice.joinedAtMs || 0),
    state.sharedVoice.joinedEventId || "",
  );
}

function sharedVoiceLocalMembership(room = activeSharedRoom()) {
  return {
    roomId: room?.id || state.sharedVoice.roomId || "",
    deviceId: sharedVoiceCurrentDeviceId(room) || state.sharedVoice.currentDeviceId || "",
    joinEpoch: state.sharedVoice.joinEpoch || "",
    joinEventId: state.sharedVoice.joinedEventId || "",
    joinedAtMs: Number(state.sharedVoice.joinedAtMs || 0),
  };
}

function sharedVoicePeerStates() {
  return Object.values(state.sharedVoice.peers || {}).filter((peer) => peer && peer.deviceId);
}

function sharedVoicePeerIsConnected(peer) {
  const pc = peer?.pc;
  return Boolean(pc && (pc.connectionState === "connected" || ["connected", "completed"].includes(pc.iceConnectionState)));
}

function updateSharedVoiceConnectionStatus() {
  const voice = state.sharedVoice;
  const peers = sharedVoicePeerStates();
  const connectedPeers = peers.filter(sharedVoicePeerIsConnected);
  voice.connecting = Boolean(voice.active && peers.some((peer) => peer.pc && !sharedVoicePeerIsConnected(peer)));
  voice.waiting = Boolean(voice.active && !peers.length);
  if (connectedPeers.length) {
    voice.status = "connected";
    voice.peerLabel = connectedPeers.length > 1 ? `${connectedPeers.length} peers` : connectedPeers[0].label || "peer";
  } else if (voice.connecting) {
    voice.status = "connecting";
    voice.peerLabel = peers[0]?.label || "";
  } else if (voice.waiting) {
    voice.status = "waiting";
    voice.peerLabel = "";
  }
  renderSharedVoice();
}

function setSharedVoicePrimaryPeer(peer) {
  if (!peer) return;
  Object.assign(state.sharedVoice, {
    callId: peer.callId || state.sharedVoice.callId || "",
    peerDeviceId: peer.deviceId || "",
    peerUserId: peer.userId || "",
    peerLabel: peer.label || "",
    remoteStream: peer.remoteStream || state.sharedVoice.remoteStream || null,
    peerConnection: peer.pc || state.sharedVoice.peerConnection || null,
    pendingIceCandidates: peer.pendingIceCandidates || state.sharedVoice.pendingIceCandidates || [],
    makingOffer: Boolean(peer.makingOffer),
    ignoreOffer: Boolean(peer.ignoreOffer),
    polite: Boolean(peer.polite),
  });
}

function ensureSharedVoicePeerAudio(peer) {
  if (!peer?.remoteStream || !els.sharedVoiceBar) return;
  let audio = peer.audioElement || null;
  if (!audio) {
    const primary = els.sharedVoiceRemoteAudio;
    if (primary && (!primary.dataset.sharedVoicePeer || primary.dataset.sharedVoicePeer === peer.deviceId)) {
      audio = primary;
      audio.dataset.sharedVoicePeer = peer.deviceId;
    } else {
      audio = document.createElement("audio");
      audio.autoplay = true;
      audio.playsInline = true;
      audio.hidden = true;
      audio.dataset.sharedVoicePeer = peer.deviceId;
      els.sharedVoiceBar.append(audio);
    }
    peer.audioElement = audio;
  }
  if (audio.srcObject !== peer.remoteStream) audio.srcObject = peer.remoteStream;
  audio.play?.().catch(() => {});
}

function closeSharedVoicePeer(deviceId) {
  const voice = state.sharedVoice;
  const peer = voice.peers?.[deviceId];
  if (!peer) return;
  sharedVoiceDebugLog("peer-connection-closed", {
    accepted: true,
    peerDeviceId: deviceId,
    callId: peer.callId || "",
  });
  peer.pc?.close?.();
  if (peer.audioElement) {
    peer.audioElement.srcObject = null;
    if (peer.audioElement !== els.sharedVoiceRemoteAudio) peer.audioElement.remove();
    else delete peer.audioElement.dataset.sharedVoicePeer;
  }
  delete voice.peers[deviceId];
  if (voice.peerDeviceId === deviceId) {
    Object.assign(voice, {
      callId: "",
      peerDeviceId: "",
      peerUserId: "",
      peerLabel: "",
      remoteStream: null,
      peerConnection: null,
      pendingIceCandidates: [],
      makingOffer: false,
      ignoreOffer: false,
    });
  }
  updateSharedVoiceConnectionStatus();
}

function closeSharedVoicePeers() {
  for (const peer of sharedVoicePeerStates()) {
    peer.pc?.close?.();
    if (peer.audioElement) {
      peer.audioElement.srcObject = null;
      if (peer.audioElement !== els.sharedVoiceRemoteAudio) peer.audioElement.remove();
      else delete peer.audioElement.dataset.sharedVoicePeer;
    }
  }
  state.sharedVoice.peers = {};
}

function sharedVoiceIncomingOfferEvents(room = activeSharedRoom()) {
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  const local = sharedVoiceLocalMembership(room);
  return sharedVoiceIncomingOfferEntries(room?.events, currentDeviceId, {
    kind: SHARED_VOICE_SIGNAL_KIND,
    schema: SHARED_VOICE_SIGNAL_SCHEMA,
    staleMs: SHARED_VOICE_STALE_MS,
  }).filter(({ event, payload }) => (
    !sharedVoiceEventBeforeCurrentJoin(event, payload)
    && sharedVoiceSignalTargetsLocalMembership(payload, local)
  ));
}

function ensureSharedVoicePeer(room, entry, options = {}) {
  const voice = state.sharedVoice;
  const deviceId = cleanText(entry?.device_id || options.deviceId || "", "");
  if (!voice.active || !voice.localStream || !room?.id || !deviceId) return null;
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  if (!currentDeviceId || deviceId === currentDeviceId) return null;
  voice.peers ||= {};
  let peer = voice.peers[deviceId];
  if (!peer) {
    peer = {
      deviceId,
      userId: cleanText(entry?.user_id || "", ""),
      label: sharedVoicePeerLabel(entry),
      callId: cleanText(options.callId || "", ""),
      joinEpoch: cleanText(options.joinEpoch || entry?.join_epoch || "", ""),
      joinEventId: cleanText(options.joinEventId || entry?.join_event_id || "", ""),
      pc: null,
      remoteStream: null,
      audioElement: null,
      pendingIceCandidates: [],
      makingOffer: false,
      ignoreOffer: false,
      polite: String(currentDeviceId) > String(deviceId),
      createdAt: Date.now(),
      lastOfferAt: 0,
      offerSentAt: 0,
      muted: false,
    };
    voice.peers[deviceId] = peer;
  }
  peer.userId = cleanText(entry?.user_id || peer.userId || "", "");
  peer.label = sharedVoicePeerLabel(entry || { device_id: deviceId, user_id: peer.userId, label: peer.label });
  peer.polite = String(currentDeviceId) > String(deviceId);
  if (options.callId) peer.callId = cleanText(options.callId, peer.callId || "");
  if (options.joinEpoch) peer.joinEpoch = cleanText(options.joinEpoch, peer.joinEpoch || "");
  if (options.joinEventId) peer.joinEventId = cleanText(options.joinEventId, peer.joinEventId || "");
  if (!peer.pc) {
    peer.pc = createSharedVoicePeerConnection(peer);
    voice.localStream.getAudioTracks().forEach((track) => peer.pc.addTrack(track, voice.localStream));
    setSharedVoicePrimaryPeer(peer);
    recordUserEvent("workspace.shared_voice_peer_selected", {
      target: `shared-space:${room.id}`,
      summary: `Joined voice with ${peer.label}`,
      data: { shared_space_id: room.id, peer_device_id: peer.deviceId },
      redacted: true,
    });
  }
  return peer;
}

function createSharedVoicePeerConnection(peer) {
  sharedVoiceDebugLog("peer-connection-created", {
    accepted: true,
    peerDeviceId: peer.deviceId,
    callId: peer.callId || "",
  });
  const pc = new RTCPeerConnection({
    iceServers: sharedVoiceIceServers(),
    bundlePolicy: "max-bundle",
    rtcpMuxPolicy: "require",
  });
  pc.addEventListener("icecandidate", (event) => {
    if (!event.candidate) return;
    void sendSharedVoicePeerSignal(peer, "ice-candidate", {
      candidate: JSON.stringify(event.candidate.toJSON ? event.candidate.toJSON() : event.candidate),
    }).catch((error) => {
      state.sharedVoice.error = truncateText(error.message || "ice failed", 80);
      renderSharedVoice();
    });
  });
  pc.addEventListener("track", (event) => {
    const stream = event.streams?.[0] || peer.remoteStream || new MediaStream();
    if (!event.streams?.[0] && event.track && !stream.getTracks().includes(event.track)) {
      stream.addTrack(event.track);
    }
    peer.remoteStream = stream;
    setSharedVoicePrimaryPeer(peer);
    ensureSharedVoicePeerAudio(peer);
    updateSharedVoiceConnectionStatus();
  });
  const updateConnection = () => {
    const status = pc.connectionState || pc.iceConnectionState || "";
    if (["connected", "completed"].includes(pc.iceConnectionState) || pc.connectionState === "connected") {
      peer.status = "connected";
    } else if (["failed", "disconnected", "closed"].includes(status) || pc.iceConnectionState === "failed") {
      peer.status = status || "disconnected";
    }
    setSharedVoicePrimaryPeer(peer);
    updateSharedVoiceConnectionStatus();
  };
  pc.addEventListener("connectionstatechange", updateConnection);
  pc.addEventListener("iceconnectionstatechange", updateConnection);
  return pc;
}

function sharedVoicePeerHasOffer(room, peer) {
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  const events = Array.isArray(room?.events) ? room.events : [];
  return events.some((event) => {
    const payload = sharedVoicePayload(event);
    return event.kind === SHARED_VOICE_SIGNAL_KIND
      && sharedVoiceEventIsFresh(event)
      && payload?.type === "offer"
      && payload.call_id === peer.callId
      && payload.from_device_id === currentDeviceId
      && payload.to_device_id === peer.deviceId;
  });
}

async function makeSharedVoiceOffer(peer) {
  const pc = peer?.pc;
  if (!state.sharedVoice.active || !pc) return;
  try {
    peer.makingOffer = true;
    setSharedVoicePrimaryPeer(peer);
    if (!peer.callId) peer.callId = `voice_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
    peer.lastOfferAt = Date.now();
    const offer = await pc.createOffer({ offerToReceiveAudio: true });
    const localOffer = await setSharedVoiceLocalDescription(peer, offer);
    await sendSharedVoicePeerSignal(peer, "offer", { sdp: localOffer?.sdp || offer.sdp || "" });
    peer.offerSentAt = Date.now();
  } finally {
    peer.makingOffer = false;
    setSharedVoicePrimaryPeer(peer);
  }
}

async function maybeConnectSharedVoiceFromRoom(room) {
  return syncSharedVoiceRoomPeers(room);
}

async function syncSharedVoiceRoomPeers(room) {
  const voice = state.sharedVoice;
  if (!voice.active || !voice.localStream || !room?.id) return false;
  const memberships = sharedVoiceMembershipMap(room);
  const joined = sharedVoiceJoinedPeerCandidates(room);
  const joinedByDevice = new Map(joined.map((entry) => {
    const membership = memberships.get(entry.device_id) || {};
    return [entry.device_id, {
      ...entry,
      join_epoch: membership.joinEpoch || "",
      join_event_id: membership.joinEventId || "",
    }];
  }));
  const incomingOffers = sharedVoiceIncomingOfferEvents(room);
  for (const incoming of incomingOffers) {
    if (!joinedByDevice.has(incoming.payload.from_device_id)) {
      joinedByDevice.set(incoming.payload.from_device_id, sharedVoicePeerByDevice(incoming.payload.from_device_id, room) || {
        device_id: incoming.payload.from_device_id,
        user_id: incoming.payload.from_user_id || "",
        label: "Browser",
      });
    }
  }
  for (const peer of sharedVoicePeerStates()) {
    if (!joinedByDevice.has(peer.deviceId)) closeSharedVoicePeer(peer.deviceId);
  }
  let connected = false;
  for (const incoming of incomingOffers) {
    const entry = joinedByDevice.get(incoming.payload.from_device_id);
    const peer = ensureSharedVoicePeer(room, entry, {
      callId: incoming.payload.call_id,
      joinEpoch: incoming.payload.join_epoch || entry?.join_epoch || "",
      joinEventId: incoming.payload.join_event_id || entry?.join_event_id || "",
    });
    connected = Boolean(peer) || connected;
  }
  for (const entry of joinedByDevice.values()) {
    const peer = ensureSharedVoicePeer(room, entry, {
      joinEpoch: entry.join_epoch || "",
      joinEventId: entry.join_event_id || "",
    });
    if (!peer) continue;
    connected = true;
    if (sharedVoiceShouldInitiateOffer(room, entry)) {
      const shouldRetryMissingOffer = peer.callId
        && !sharedVoicePeerHasOffer(room, peer)
        && Date.now() - Number(peer.lastOfferAt || 0) > 2500;
      if ((!peer.callId || shouldRetryMissingOffer) && !peer.makingOffer) {
        await makeSharedVoiceOffer(peer);
      }
    }
  }
  updateSharedVoiceConnectionStatus();
  return connected;
}

async function sendSharedVoiceRoomSignal(type, details = {}) {
  const space = sharedUserSpaceForPanel();
  const room = activeSharedRoom();
  const voice = state.sharedVoice;
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  if (!space || !room?.id || !currentDeviceId) {
    throw new Error("Shared voice is not ready.");
  }
  const toDeviceId = Object.prototype.hasOwnProperty.call(details, "to_device_id")
    ? cleanText(details.to_device_id || "", "")
    : "";
  const callId = cleanText(details.call_id || voice.callId || `voice_room_${room.id}`, "");
  const joinEpoch = cleanText(details.join_epoch || voice.joinEpoch || "", "");
  const joinEventId = cleanText(details.join_event_id || voice.joinedEventId || "", "");
  const payload = await fetchJson("/spaces/room", {
    method: "POST",
    timeoutMs: 7000,
    body: {
      action: "signal",
      kind: SHARED_VOICE_SIGNAL_KIND,
      space_id: space.id,
      shared_space_id: space.shared_space_id,
      payload: {
        voice_schema: SHARED_VOICE_SIGNAL_SCHEMA,
        call_id: callId,
        room_id: room.id,
        type,
        from_user_id: sharedVoiceCurrentUserId(room),
        from_device_id: currentDeviceId,
        from_client_id: sharedVoiceCurrentClientId(),
        from_account_device_id: cleanText(room.current_device_id || "", ""),
        to_device_id: toDeviceId,
        join_epoch: joinEpoch,
        join_event_id: joinEventId,
        muted: voice.muted,
        ...details,
      },
    },
  });
  sharedVoiceDebugLog(
    type === "join"
      ? "join-event-publish"
      : type === "leave"
        ? "leave-event-publish"
        : `${type}-event-publish`,
    {
      room,
      accepted: true,
      fromDeviceId: currentDeviceId,
      toDeviceId,
      peerDeviceId: toDeviceId,
      callId,
    },
  );
  const nextRoom = payload.room || null;
  if (nextRoom?.id) {
    state.sharedRooms[nextRoom.id] = nextRoom;
    renderSharedVoice();
    if (type === "join") markSharedVoiceJoinBaseline(nextRoom);
    queueSharedVoiceRoomProcessing(nextRoom);
  }
  return nextRoom;
}

async function sendSharedVoicePeerSignal(peer, type, details = {}) {
  if (!peer?.deviceId) throw new Error("Shared voice is not ready.");
  if (!peer.callId) peer.callId = cleanText(details.call_id || `voice_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`, "");
  setSharedVoicePrimaryPeer(peer);
  return sendSharedVoiceRoomSignal(type, {
    ...details,
    call_id: peer.callId,
    to_device_id: peer.deviceId,
    target_join_epoch: peer.joinEpoch || "",
    target_join_event_id: peer.joinEventId || "",
  });
}

async function flushSharedVoiceIceCandidates(peer) {
  const pc = peer?.pc;
  if (!pc?.remoteDescription?.type || !peer.pendingIceCandidates.length) return;
  const pending = peer.pendingIceCandidates.splice(0);
  for (const candidate of pending) {
    await pc.addIceCandidate(candidate);
  }
}

async function addSharedVoiceIceCandidate(peer, candidate) {
  const pc = peer?.pc;
  if (!pc || !candidate) return;
  if (!pc.remoteDescription?.type) {
    peer.pendingIceCandidates.push(candidate);
    if (peer.pendingIceCandidates.length > 80) {
      peer.pendingIceCandidates.splice(0, peer.pendingIceCandidates.length - 80);
    }
    return;
  }
  await pc.addIceCandidate(candidate);
}

async function setSharedVoiceLocalDescription(peer, description, timeoutMs = 1200) {
  const voice = state.sharedVoice;
  const pc = peer?.pc;
  if (!pc) return description;
  let settled = false;
  const pending = pc.setLocalDescription(description);
  await Promise.race([
    pending.then(
      () => {
        settled = true;
      },
      (error) => {
        settled = true;
        throw error;
      },
    ),
    new Promise((resolve) => window.setTimeout(resolve, timeoutMs)),
  ]);
  if (!settled) {
    pending.catch((error) => {
      voice.error = truncateText(error.message || "local voice description failed", 80);
      renderSharedVoice();
    });
  }
  return pc.localDescription || description;
}

function queueSharedVoiceRoomProcessing(room) {
  if (!state.sharedVoice.active || !room?.id) return;
  state.sharedVoice.signalQueue = state.sharedVoice.signalQueue
    .then(async () => {
      await syncSharedVoiceRoomPeers(room);
      await processSharedVoiceRoom(room);
      await syncSharedVoiceRoomPeers(room);
    })
    .catch((error) => {
      state.sharedVoice.error = truncateText(error.message || "voice signal failed", 80);
      renderSharedVoice();
    });
}

async function handleSharedVoiceSignal(event, payload, room) {
  const voice = state.sharedVoice;
  if (!payload) return false;
  const currentDeviceId = sharedVoiceCurrentDeviceId(room);
  if (!voice.active || !voice.localStream) {
    sharedVoiceDebugLog("event-ignored-local-not-joined", {
      room,
      payload,
      accepted: false,
      ignored: true,
      peerDeviceId: payload.from_device_id || "",
      ignoreReason: "local-not-joined",
    });
    return true;
  }
  if (!currentDeviceId || payload.from_device_id === currentDeviceId) {
    sharedVoiceDebugLog("event-ignored-target-mismatch", {
      room,
      payload,
      accepted: false,
      ignored: true,
      peerDeviceId: payload.from_device_id || "",
      ignoreReason: "self-or-missing-local-device",
    });
    return true;
  }
  if (payload.to_device_id && payload.to_device_id !== currentDeviceId) {
    sharedVoiceDebugLog("event-ignored-target-mismatch", {
      room,
      payload,
      accepted: false,
      ignored: true,
      peerDeviceId: payload.from_device_id || "",
      ignoreReason: "target-device-mismatch",
    });
    return true;
  }
  if (payload.room_id && payload.room_id !== room?.id) {
    sharedVoiceDebugLog("event-ignored-target-mismatch", {
      room,
      payload,
      accepted: false,
      ignored: true,
      peerDeviceId: payload.from_device_id || "",
      ignoreReason: "room-mismatch",
    });
    return true;
  }
  if (payload.type === "join" || payload.type === "membership") {
    sharedVoiceDebugLog("remote-participant-joined", {
      room,
      payload,
      accepted: true,
      peerDeviceId: payload.from_device_id || "",
    });
    return true;
  }
  if (payload.type === "leave" || payload.type === "hangup") {
    const peer = voice.peers?.[payload.from_device_id];
    if (!peer || sharedVoiceSignalMatchesRemoteMembership(payload, peer)) closeSharedVoicePeer(payload.from_device_id);
    sharedVoiceDebugLog("remote-participant-left", {
      room,
      payload,
      accepted: true,
      peerDeviceId: payload.from_device_id || "",
    });
    return true;
  }
  if (!sharedVoiceSignalTargetsLocalMembership(payload, sharedVoiceLocalMembership(room))) {
    sharedVoiceDebugLog("event-ignored-epoch-mismatch", {
      room,
      payload,
      accepted: false,
      ignored: true,
      peerDeviceId: payload.from_device_id || "",
      ignoreReason: "target-epoch-mismatch",
    });
    return true;
  }
  const entry = sharedVoicePeerByDevice(payload.from_device_id, room) || {
    device_id: payload.from_device_id,
    user_id: payload.from_user_id || "",
    label: "Browser",
  };
  const membership = sharedVoiceMembershipMap(room).get(payload.from_device_id) || {};
  const peer = ensureSharedVoicePeer(room, {
    ...entry,
    join_epoch: membership.joinEpoch || payload.join_epoch || "",
    join_event_id: membership.joinEventId || payload.join_event_id || "",
  }, {
    callId: payload.type === "offer" ? payload.call_id : "",
    joinEpoch: payload.join_epoch || membership.joinEpoch || "",
    joinEventId: payload.join_event_id || membership.joinEventId || "",
  });
  const pc = peer?.pc;
  if (!peer || !pc) return false;
  if (!sharedVoiceSignalMatchesRemoteMembership(payload, peer)) {
    sharedVoiceDebugLog("event-ignored-epoch-mismatch", {
      room,
      payload,
      accepted: false,
      ignored: true,
      peerDeviceId: payload.from_device_id || "",
      ignoreReason: "remote-epoch-mismatch",
    });
    return true;
  }
  if (payload.type === "offer" && payload.call_id !== peer.callId) {
    if (!peer.polite && peer.callId) {
      sharedVoiceDebugLog("event-ignored-target-mismatch", {
        room,
        payload,
        accepted: false,
        ignored: true,
        peerDeviceId: peer.deviceId,
        ignoreReason: "offer-collision",
      });
      return true;
    }
    peer.callId = payload.call_id;
  }
  if (payload.call_id !== peer.callId) {
    sharedVoiceDebugLog("event-ignored-target-mismatch", {
      room,
      payload,
      accepted: false,
      ignored: true,
      peerDeviceId: peer.deviceId,
      ignoreReason: "call-id-mismatch",
    });
    return true;
  }
  if (payload.type === "mute") {
    sharedVoiceDebugLog("mute-received", {
      room,
      payload,
      accepted: true,
      peerDeviceId: peer.deviceId,
    });
    peer.muted = Boolean(payload.muted);
    voice.peerMuted = sharedVoicePeerStates().some((item) => item.muted);
    renderSharedVoice();
    return true;
  }
  if (payload.type === "offer") {
    sharedVoiceDebugLog("offer-received", {
      room,
      payload,
      accepted: true,
      peerDeviceId: peer.deviceId,
    });
    const description = { type: "offer", sdp: String(payload.sdp || "") };
    const offerCollision = peer.makingOffer || pc.signalingState !== "stable";
    peer.ignoreOffer = !peer.polite && offerCollision;
    if (peer.ignoreOffer) {
      sharedVoiceDebugLog("event-ignored-target-mismatch", {
        room,
        payload,
        accepted: false,
        ignored: true,
        peerDeviceId: peer.deviceId,
        ignoreReason: "offer-collision",
      });
      return true;
    }
    if (offerCollision) {
      await pc.setLocalDescription({ type: "rollback" });
    }
    await pc.setRemoteDescription(description);
    await flushSharedVoiceIceCandidates(peer);
    const answer = await pc.createAnswer();
    const localAnswer = await setSharedVoiceLocalDescription(peer, answer);
    await sendSharedVoicePeerSignal(peer, "answer", { sdp: localAnswer?.sdp || answer.sdp || "" });
    return true;
  }
  if (payload.type === "answer") {
    sharedVoiceDebugLog("answer-received", {
      room,
      payload,
      accepted: true,
      peerDeviceId: peer.deviceId,
    });
    if (pc.signalingState !== "stable") {
      await pc.setRemoteDescription({ type: "answer", sdp: String(payload.sdp || "") });
      await flushSharedVoiceIceCandidates(peer);
    }
    return true;
  }
  if (payload.type === "ice-candidate") {
    sharedVoiceDebugLog("ice-received", {
      room,
      payload,
      accepted: true,
      peerDeviceId: peer.deviceId,
    });
    try {
      const candidate = typeof payload.candidate === "string" ? JSON.parse(payload.candidate) : payload.candidate;
      await addSharedVoiceIceCandidate(peer, candidate);
    } catch (error) {
      if (!peer.ignoreOffer) throw error;
    }
    return true;
  }
  return true;
}

async function processSharedVoiceRoom(room) {
  const voice = state.sharedVoice;
  if (!voice.active || voice.signalBusy) return;
  voice.signalBusy = true;
  try {
    const events = Array.isArray(room?.events) ? room.events : [];
    for (const event of events) {
      if (!event?.id || voice.processedSignalIds.has(event.id)) continue;
      if (event.kind !== SHARED_VOICE_SIGNAL_KIND || !sharedVoiceEventIsFresh(event)) continue;
      const payload = sharedVoicePayload(event);
      if (!payload) continue;
      if (sharedVoiceEventBeforeCurrentJoin(event, payload)) {
        sharedVoiceDebugLog("stale-event-ignored", {
          room,
          payload,
          accepted: false,
          ignored: true,
          peerDeviceId: payload.from_device_id || "",
          ignoreReason: "before-local-join",
        });
        voice.processedSignalIds.add(event.id);
        continue;
      }
      const handled = await handleSharedVoiceSignal(event, payload, room);
      if (handled) voice.processedSignalIds.add(event.id);
    }
    if (voice.processedSignalIds.size > 180) {
      voice.processedSignalIds = new Set(Array.from(voice.processedSignalIds).slice(-120));
    }
  } finally {
    voice.signalBusy = false;
  }
}

async function startSharedVoice() {
  if (state.sharedVoice.active || state.sharedVoice.connecting) return;
  if (state.config?.features?.sharedVoice?.enabled === false) return;
  sharedVoiceDebugLog("local-join-click", { accepted: true });
  const mediaProblem = sharedVoiceMediaUnavailableReason();
  if (mediaProblem) {
    sharedVoiceDebugLog("getUserMedia", {
      accepted: false,
      ignored: true,
      ignoreReason: mediaProblem,
    });
    state.sharedVoice.error = mediaProblem;
    renderSharedVoice();
    return;
  }
  const room = await loadSharedSpaceRoom({ origin: "shared-voice-start" }) || activeSharedRoom();
  if (!room?.id || !room.current_device_id) throw new Error("Shared room is still syncing.");
  resetSharedVoiceRuntime();
  const joinEpoch = sharedVoiceNewJoinEpoch();
  Object.assign(state.sharedVoice, {
    active: true,
    connecting: false,
    waiting: true,
    status: "waiting",
    error: "",
    roomId: room.id,
    joinEpoch,
  });
  renderSharedVoice();
  let gotLocalMedia = false;
  try {
    sharedVoiceDebugLog("getUserMedia", { room, accepted: true, fromDeviceId: sharedVoiceCurrentDeviceId(room) });
    const stream = await navigator.mediaDevices.getUserMedia({
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true,
      },
      video: false,
    });
    gotLocalMedia = true;
    state.sharedVoice.localStream = stream;
    startSharedVoicePolling();
    const joinedRoom = await sendSharedVoiceRoomSignal("join", { joined: true, join_epoch: joinEpoch });
    markSharedVoiceJoinBaseline(joinedRoom || room);
    await sendSharedVoiceMembershipHeartbeat(true);
    recordUserEvent("workspace.shared_voice_started", {
      target: `shared-space:${room.id}`,
      summary: "Started shared voice",
      data: { shared_space_id: room.id },
      redacted: true,
    });
    await maybeConnectSharedVoiceFromRoom(joinedRoom || room);
  } catch (error) {
    sharedVoiceDebugLog(gotLocalMedia ? "voice-start-failed" : "getUserMedia", {
      room,
      accepted: false,
      ignored: true,
      ignoreReason: truncateText(error.message || "voice failed", 80),
    });
    state.sharedVoice.error = truncateText(error.message || "voice failed", 80);
    resetSharedVoiceRuntime(true);
    recordUserEvent("workspace.shared_voice_error", {
      target: `shared-space:${room.id}`,
      summary: state.sharedVoice.error,
      data: { shared_space_id: room.id, error: error.message },
    });
  }
}

async function stopSharedVoice(options = {}) {
  const voice = state.sharedVoice;
  const roomId = voice.roomId || "";
  if (voice.active || voice.connecting) {
    voice.status = "leaving";
    sharedVoiceDebugLog("local-leave-click", {
      accepted: true,
      ignoreReason: cleanText(options.reason, ""),
    });
  }
  if ((voice.active || voice.connecting) && options.notify !== false) {
    const peers = sharedVoicePeerStates().filter((peer) => peer.callId);
    for (const peer of peers) {
      await sendSharedVoicePeerSignal(peer, "hangup", { reason: cleanText(options.reason, "ended") }).catch(() => {});
    }
  }
  if ((voice.active || voice.connecting) && options.notify !== false) {
    await sendSharedVoiceRoomSignal("leave", { reason: cleanText(options.reason, "ended") }).catch(() => {});
  }
  resetSharedVoiceRuntime();
  recordUserEvent("workspace.shared_voice_stopped", {
    target: `shared-space:${roomId || "shared"}`,
    summary: "Stopped shared voice",
    data: { shared_space_id: roomId, reason: options.reason || "" },
  });
}

function sendSharedVoiceLeaveBeacon(reason = "pagehide") {
  const voice = state.sharedVoice;
  const space = sharedUserSpaceForPanel();
  const room = activeSharedRoom();
  if (!voice.joinEpoch || !space?.shared_space_id || !room?.id) return false;
  const body = {
    action: "signal",
    kind: SHARED_VOICE_SIGNAL_KIND,
    space_id: space.id,
    shared_space_id: space.shared_space_id,
    payload: {
      voice_schema: SHARED_VOICE_SIGNAL_SCHEMA,
      call_id: `voice_room_${room.id}`,
      room_id: room.id,
      type: "leave",
      reason,
      from_user_id: sharedVoiceCurrentUserId(room),
      from_device_id: sharedVoiceCurrentDeviceId(room),
      from_client_id: sharedVoiceCurrentClientId(),
      from_account_device_id: cleanText(room.current_device_id || "", ""),
      to_device_id: "",
      join_epoch: voice.joinEpoch,
      join_event_id: voice.joinedEventId || "",
    },
  };
  const payload = JSON.stringify(body);
  sharedVoiceDebugLog("leave-event-publish", {
    room,
    accepted: true,
    fromDeviceId: body.payload.from_device_id,
    toDeviceId: "",
    callId: body.payload.call_id,
    ignoreReason: reason,
  });
  if (navigator.sendBeacon) {
    return navigator.sendBeacon("/spaces/room", new Blob([payload], { type: "application/json" }));
  }
  fetch("/spaces/room", {
    method: "POST",
    cache: "no-store",
    keepalive: true,
    headers: {
      "Content-Type": "application/json",
      "X-Wasm-Agent-Device-Id": clientDeviceId(),
    },
    body: payload,
  }).catch(() => {});
  return true;
}

function toggleSharedVoice() {
  if (state.sharedVoice.active || state.sharedVoice.connecting) {
    void stopSharedVoice({ reason: "user-toggle" });
  } else {
    void startSharedVoice().catch((error) => {
      state.sharedVoice.error = truncateText(error.message || "voice failed", 80);
      renderSharedVoice();
    });
  }
}

function toggleSharedVoiceMute() {
  const voice = state.sharedVoice;
  if (!voice.active || !voice.localStream) return;
  voice.muted = !voice.muted;
  voice.localStream.getAudioTracks().forEach((track) => {
    track.enabled = !voice.muted;
  });
  for (const peer of sharedVoicePeerStates().filter((item) => item.callId)) {
    void sendSharedVoicePeerSignal(peer, "mute", { muted: voice.muted }).catch(() => {});
  }
  renderSharedVoice();
}

function applyLauncherPreference() {
  if (!els.app) return;
  els.app.dataset.mobileLauncher = state.mobileLauncherTop ? "top" : "left";
}

function saveUserSpaces() {
  if (state.authUser) {
    state.userSpaces = sanitizeUserSpaces(state.userSpaces);
    void fetchJson("/spaces", {
      method: "POST",
      timeoutMs: 8000,
      body: { action: "replace", spaces: state.userSpaces },
    }).catch((error) => {
      recordUserEvent("workspace.spaces_save_error", {
        target: "spaces",
        summary: error.message,
        data: { error: error.message },
      });
    });
  }
}

function persistSpaceAreaMetadata(spaceId, spaceArea) {
  const space = userSpaceById(spaceId);
  if (!state.authUser || !space) return;
  void fetchJson("/spaces", {
    method: "POST",
    timeoutMs: 8000,
    body: {
      action: "area",
      space_id: space.id,
      shared_space_id: space.shared_space_id || "",
      space_area: spaceArea,
    },
  }).then((result) => {
    if (Array.isArray(result.spaces)) {
      state.userSpaces = sanitizeUserSpaces(result.spaces, state.userSpaces);
      renderSpaceLauncher();
      updateSharedSpaceSyncPolling();
    }
  }).catch((error) => {
    if (space.shared_space_id && /unsupported space action|invalid_space_action/i.test(error.message || "")) {
      void persistSharedSpaceAreaViaShare(space, spaceArea);
      return;
    }
    recordUserEvent("workspace.space_area_save_error", {
      target: `space:${spaceId}`,
      summary: error.message,
      data: { error: error.message },
    });
  });
}

async function persistSharedSpaceAreaViaShare(space, spaceArea) {
  try {
    const payload = await fetchJson("/spaces/share", {
      method: "POST",
      timeoutMs: 8000,
      body: {
        space_id: space.id,
        shared_space_id: space.shared_space_id || "",
        space_area: spaceArea,
      },
    });
    const room = payload.shared_space || null;
    if (room?.id) state.sharedRooms[room.id] = room;
    await loadUserSpaces({ origin: "space-area-share-fallback" });
    recordUserEvent("workspace.space_area_save_fallback", {
      target: `space:${space.id}`,
      summary: `Saved shared space area ${formatAreaSize(spaceArea)} through share endpoint`,
      data: {
        space_id: space.id,
        shared_space_id: space.shared_space_id || "",
        width_px: spaceArea.width_px || 0,
        height_px: spaceArea.height_px || 0,
      },
    });
  } catch (fallbackError) {
    recordUserEvent("workspace.space_area_save_error", {
      target: `space:${space.id}`,
      summary: fallbackError.message,
      data: { error: fallbackError.message, fallback: "share" },
    });
  }
}

async function loadUserSpaces(options = {}) {
  if (!state.authUser) return;
  const activePanel = state.activePanel;
  const beforeActiveSpace = userSpaceById(activePanel);
  try {
    const payload = await fetchJson("/spaces", { timeoutMs: 8000 });
    state.userSpaces = sanitizeUserSpaces(payload.spaces);
    state.userStorage = payload.storage || null;
    state.spaceWidgetLayouts = readLocalSpaceWidgetLayouts();
    const afterActiveSpace = userSpaceById(activePanel);
    const activeAreaChanged = remoteSpaceAreaChanged(beforeActiveSpace, afterActiveSpace);
    if (shouldSyncUserSpacesFromServer()) applySpaceWidgetLayout(state.activePanel);
    renderSpaceLauncher();
    renderSpaceTitle();
    updateSharedSpaceSyncPolling();
    if (activeAreaChanged && shouldSyncUserSpacesFromServer()) {
      const area = spaceAreaFromMetadata(afterActiveSpace?.space_area);
      recordUserEvent("workspace.shared_space_area_applied", {
        target: `space:${activePanel}`,
        summary: `Applied shared space area ${formatAreaSize(area)}`,
        data: {
          origin: options.origin || "spaces-load",
          space_id: activePanel,
          shared_space_id: afterActiveSpace?.shared_space_id || "",
          width_px: area?.width || 0,
          height_px: area?.height || 0,
        },
      });
    }
  } catch (error) {
    recordUserEvent("workspace.spaces_load_error", {
      target: "spaces",
      summary: error.message,
      data: { error: error.message },
    });
  } finally {
    updateSharedSpaceSyncPolling();
  }
}

function shouldSyncUserSpacesFromServer() {
  return Boolean(state.authUser && !state.configAreaDragActive && (!els.configModal || els.configModal.hidden));
}

async function syncUserSpacesForOpenClient(origin = "auto") {
  if (origin === "startup" || !shouldSyncUserSpacesFromServer()) return;
  await loadUserSpaces({ origin });
}

async function loadLocalStorageEstimate() {
  if (!navigator.storage?.estimate) {
    state.localStorageEstimate = { usage: 0, quota: 0 };
    return;
  }
  try {
    state.localStorageEstimate = await navigator.storage.estimate();
  } catch {
    state.localStorageEstimate = { usage: 0, quota: 0 };
  }
  if (els.configModal && !els.configModal.hidden) renderConfigModal();
}

function isUserSpacePanel(panel) {
  return state.userSpaces.some((space) => space.id === panel);
}

function normalizePanel(panel) {
  const value = cleanText(panel, "home");
  return value === "space" ? "admin" : value;
}

function isAdminPanel(panel) {
  return ADMIN_PANEL_IDS.has(normalizePanel(panel));
}

function moduleDefinitionById(moduleId) {
  return MODULE_DEFINITIONS.find((module) => module.id === moduleId) || null;
}

function moduleServerAvailable(moduleId) {
  if (moduleId === "host-browser") {
    return state.config?.features?.hostBrowser?.enabled !== false;
  }
  return true;
}

function isModuleEnabled(moduleId) {
  if (!moduleServerAvailable(moduleId)) return false;
  if (moduleDefinitionById(moduleId)?.core) return true;
  if (Object.prototype.hasOwnProperty.call(state.moduleSettings, moduleId)) {
    return state.moduleSettings[moduleId] !== false;
  }
  return moduleDefinitionById(moduleId)?.defaultEnabled !== false;
}

function isPanelAvailable(panel) {
  panel = normalizePanel(panel);
  if (panel === "home" || isUserSpacePanel(panel)) return true;
  if (isAdminPanel(panel) && !isAdminUser()) return false;
  if (panel === "observe") return isModuleEnabled("observation");
  return true;
}

function defaultAgentMessage() {
  return {
    role: "assistant",
    content: AGENT_DEFAULT_MESSAGE_CONTENT,
  };
}

function createAgentSession(title = "New session", options = {}) {
  const kind = cleanText(options.kind || "agent", "agent");
  return {
    id: `agent_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`,
    kind,
    title,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
    peer: options.peer && typeof options.peer === "object" ? options.peer : null,
    conversation_id: cleanText(options.conversation_id, ""),
    shared_space_id: cleanText(options.shared_space_id, ""),
    applied_reaction_event_ids: [],
    messages: kind === "direct" || kind === "shared-space" ? [] : [defaultAgentMessage()],
    diagnostics: null,
    changed_files: [],
    context_preview: [],
  };
}

function normalizeStoredImage(image) {
  const source = image && typeof image === "object" ? image : { data_url: image };
  const dataUrl = String(source.data_url || "");
  if (!dataUrl.startsWith("data:image/")) return null;
  if (dataUrlByteLength(dataUrl) > AGENT_IMAGE_MAX_BYTES * 2) return null;
  return {
    data_url: dataUrl,
    name: cleanText(source.name, "Attached image"),
    type: cleanText(source.type, ""),
    size: Number.isFinite(source.size) ? source.size : dataUrlByteLength(dataUrl),
    width: Number.isFinite(source.width) ? source.width : undefined,
    height: Number.isFinite(source.height) ? source.height : undefined,
    image_card: source.image_card && typeof source.image_card === "object" ? source.image_card : undefined,
    asset: source.asset && typeof source.asset === "object" ? source.asset : undefined,
  };
}

function normalizeStoredMessage(message) {
  const source = message && typeof message === "object" ? message : defaultAgentMessage();
  const normalized = {
    ...source,
    role: source.role === "user" ? "user" : "assistant",
    content: String(source.content || ""),
    images: Array.isArray(source.images)
      ? source.images.map(normalizeStoredImage).filter(Boolean).slice(0, AGENT_MAX_IMAGES)
      : undefined,
    attachments: Array.isArray(source.attachments)
      ? source.attachments.filter((item) => item && typeof item === "object").slice(0, AGENT_MAX_IMAGES)
      : undefined,
  };
  if (normalized.pending) {
    if (normalized.run_id || normalized.turn_id) {
      normalized.phase = "Reconnecting...";
      normalized.content = normalized.content || "Reconnecting to the assistant turn...";
    } else {
      normalized.pending = false;
      normalized.phase = "Reloaded";
      normalized.content = normalized.content || "This assistant turn was interrupted by a page reload.";
      normalized.duration_ms = Number.isFinite(normalized.duration_ms)
        ? normalized.duration_ms
        : Date.now() - Number(normalized.turn_started_at || Date.now());
      normalized.actions = (Array.isArray(normalized.actions) ? normalized.actions : []).map((action) => (
        action.status === "running" ? { ...action, status: "error", detail: "Interrupted by reload" } : action
      ));
    }
  }
  if (!normalized.images?.length) delete normalized.images;
  if (!normalized.attachments?.length) delete normalized.attachments;
  return normalized;
}

function normalizeStoredSession(session) {
  const source = session && typeof session === "object" ? session : createAgentSession("Main session");
  const rawKind = cleanText(source.kind || "agent", "agent");
  const kind = rawKind === "direct" || rawKind === "shared-space" ? rawKind : "agent";
  const messages = Array.isArray(source.messages) && source.messages.length
    ? source.messages.map(normalizeStoredMessage)
    : kind === "direct" || kind === "shared-space" ? [] : [defaultAgentMessage()];
  return {
    ...source,
    kind,
    peer: source.peer && typeof source.peer === "object" ? source.peer : null,
    conversation_id: cleanText(source.conversation_id, ""),
    shared_space_id: cleanText(source.shared_space_id, ""),
    sync_cursor: cleanText(source.sync_cursor, ""),
    applied_reaction_event_ids: Array.isArray(source.applied_reaction_event_ids) ? source.applied_reaction_event_ids.slice(-DIRECT_CHAT_MESSAGE_CAP) : [],
    messages,
    diagnostics: source.diagnostics || null,
    changed_files: Array.isArray(source.changed_files) ? source.changed_files : [],
    context_preview: Array.isArray(source.context_preview) ? source.context_preview : [],
  };
}

function readAgentSessions() {
  try {
    const raw = JSON.parse(localStorage.getItem(AGENT_SESSIONS_STORAGE_KEY) || "[]");
    if (Array.isArray(raw) && raw.length) return raw.map(normalizeStoredSession);
  } catch {
    // A missing or corrupt transcript cache should never block the app.
  }
  return [createAgentSession("Main session")];
}

function saveAgentSessions() {
  try {
    localStorage.setItem(AGENT_SESSIONS_STORAGE_KEY, JSON.stringify(state.agentSessions.slice(0, 20)));
  } catch {
    // Session persistence is a convenience; chat should still work without it.
  }
}

function snapshotText(value, max = 12000) {
  const text = String(value ?? "");
  if (text.length <= max) return text;
  return `${text.slice(0, Math.max(0, max - 3))}...`;
}

function compactSnapshotValue(value, depth = 0) {
  if (depth > 7) return snapshotText(value, 400);
  if (value == null || typeof value === "boolean" || typeof value === "number") return value;
  if (typeof value === "string") return snapshotText(value, depth <= 3 ? 12000 : 2000);
  if (Array.isArray(value)) return value.slice(0, depth <= 2 ? 80 : 40).map((item) => compactSnapshotValue(item, depth + 1));
  if (typeof value === "object") {
    const entries = Object.entries(value).slice(0, depth <= 2 ? 120 : 80);
    return Object.fromEntries(entries.map(([key, item]) => {
      const lowered = key.toLowerCase();
      const safeValue = ["apikey", "api_key", "authorization", "password", "secret", "token"].includes(lowered)
        ? "[redacted]"
        : compactSnapshotValue(item, depth + 1);
      return [snapshotText(key, 120), safeValue];
    }));
  }
  return snapshotText(value, 1200);
}

function compactAgentMessageForSnapshot(message = {}, { active = false } = {}) {
  const contentLimit = active ? 12000 : 1200;
  return {
    id: cleanText(message.id, ""),
    role: cleanText(message.role, ""),
    content: snapshotText(message.content, contentLimit),
    pending: Boolean(message.pending),
    phase: cleanText(message.phase, ""),
    timestamp: cleanText(message.timestamp || message.created_at, ""),
    duration_ms: Number(message.duration_ms || 0),
    space_id: cleanText(message.space_id, ""),
    diagnostics: message.diagnostics ? compactSnapshotValue(message.diagnostics, 0) : null,
    actions: Array.isArray(message.actions)
      ? message.actions.slice(active ? -40 : -8).map((action) => compactSnapshotValue(action, 0))
      : [],
    changed_files: Array.isArray(message.changed_files) ? message.changed_files.slice(0, 20).map((item) => compactSnapshotValue(item, 0)) : [],
  };
}

function compactAgentSessionForSnapshot(session = {}, activeSessionId = "") {
  const active = session.id === activeSessionId;
  const messages = Array.isArray(session.messages) ? session.messages : [];
  return {
    id: cleanText(session.id, ""),
    active,
    title: cleanText(session.title, ""),
    kind: cleanText(session.kind, "agent"),
    conversation_id: cleanText(session.conversation_id, ""),
    shared_space_id: cleanText(session.shared_space_id, ""),
    created_at: cleanText(session.created_at, ""),
    updated_at: cleanText(session.updated_at, ""),
    message_count: messages.length,
    messages: messages.slice(active ? -24 : -4).map((message) => compactAgentMessageForSnapshot(message, { active })),
    diagnostics: session.diagnostics ? compactSnapshotValue(session.diagnostics, 0) : null,
    changed_files: Array.isArray(session.changed_files) ? session.changed_files.slice(0, 20).map((item) => compactSnapshotValue(item, 0)) : [],
    context_preview: Array.isArray(session.context_preview) ? session.context_preview.slice(0, 12).map((item) => compactSnapshotValue(item, 0)) : [],
  };
}

function localStorageManifestForSnapshot() {
  const rows = [];
  try {
    for (let index = 0; index < localStorage.length; index += 1) {
      const key = localStorage.key(index) || "";
      if (!key.startsWith("wasmAgent.")) continue;
      const value = localStorage.getItem(key) || "";
      rows.push({
        key,
        bytes: value.length,
        included: key === AGENT_SESSIONS_STORAGE_KEY ? "normalized-agent-sessions" : "manifest-only",
      });
    }
  } catch {
    rows.push({ key: "localStorage", bytes: 0, included: "unavailable" });
  }
  return rows.sort((left, right) => left.key.localeCompare(right.key));
}

function providerConfigForSnapshot(config = {}) {
  return {
    id: cleanText(config.id, ""),
    label: cleanText(config.label || config.name, ""),
    provider: cleanText(config.provider, ""),
    model: cleanText(config.model, ""),
    base_url: cleanText(config.baseUrl || config.base_url, ""),
    has_api_key: Boolean(config.apiKey || config.api_key),
  };
}

function cameraConfigForSnapshot(key, config = {}) {
  const element = cleanText(config.element, "");
  const mediaMode = cleanText(config.mediaMode || config.media_mode, "");
  return {
    key: cleanText(key, ""),
    kind: cleanText(config.kind, ""),
    label: cleanText(config.label, ""),
    media_mode: mediaMode,
    element,
    vendor: cleanText(config.vendor, ""),
    mode: cleanText(config.mode, ""),
    preferred_mode: cleanText(config.preferredMode || config.preferred_mode, ""),
    credential_profile: Boolean(config.credentialProfile || config.credential_profile),
    relay_mode: cleanText(config.relayMode || config.relay_mode, ""),
    host: cleanText(config.host, ""),
    port: cleanText(config.port, ""),
    stream_id: cleanText(config.streamId || config.stream_id, ""),
    channel: cleanText(config.channel, ""),
    subtype: cleanText(config.subtype, ""),
    access_scope: cleanText(config.accessScope || config.access_scope, ""),
    secret_policy: cleanText(config.secretPolicy || config.secret_policy, ""),
    shareable: Boolean(config.shareable),
    browser_playable: Boolean(config.browserPlayable || config.browser_playable || element === "img" || element === "video" || element === "snapshot"),
    ingest_configured: Boolean(config.ingestUrl || config.ingest_url),
    has_url: Boolean(cleanText(config.url, "")),
    url: redactCameraUrl(config.url || ""),
    portal_url: redactCameraUrl(config.portalUrl || config.portal_url || ""),
    updated_at: cleanText(config.updatedAt || config.updated_at, ""),
  };
}

function wisCameraRuntimeForSnapshot() {
  const slots = [];
  try {
    els.wisViewport?.querySelectorAll(".wis-node-webcam_placeholder[data-wis-camera-slot]")?.forEach((element) => {
      const media = element.querySelector("img, video");
      slots.push({
        slot: cleanText(element.dataset.wisCameraSlot, ""),
        has_camera_class: element.classList.contains("has-camera"),
        recorded_session_id: cleanText(element.dataset.wisRecordedSessionId || media?.dataset?.wisRecordedSessionId, ""),
        media_tag: media?.tagName?.toLowerCase?.() || "",
        media_complete: media instanceof HTMLImageElement ? Boolean(media.complete) : null,
        video_ready_state: media instanceof HTMLVideoElement ? media.readyState : null,
        video_network_state: media instanceof HTMLVideoElement ? media.networkState : null,
        message: cleanText(element.querySelector(".wis-camera-message")?.textContent, ""),
      });
    });
  } catch {
    // Runtime diagnostics must never make snapshot collection fragile.
  }
  return slots;
}

function wisCameraPerfForSnapshot() {
  const keys = new Set();
  try {
    if (state.wisCameraPlaybackPerf instanceof Map) {
      state.wisCameraPlaybackPerf.forEach((_value, key) => {
        if (key) keys.add(cleanText(key, ""));
      });
    }
    if (state.wisCameraTimeline?.streamId) keys.add(cleanText(state.wisCameraTimeline.streamId, ""));
    state.wisCameraRecordedSessions?.forEach?.((_session, key) => {
      if (key) keys.add(cleanText(key, ""));
    });
  } catch {
    // Snapshot diagnostics should stay best-effort.
  }
  return Array.from(keys)
    .filter(Boolean)
    .slice(0, 20)
    .map((key) => {
      const sample = sampleWisCameraPerf(state, key, {}, null, { force: true }) || {};
      const badSamples = Number(
        Number(sample.activePlaybackLoops || 0) > 1
        || Number(sample.activeReaders || 0) > 1
        || (sample.mode === "live" && Number(sample.activePlaybackLoops || 0) > 0)
      );
      return {
        ...sample,
        stream_id: key,
        blink_events: Number(state.wisCameraBlinkEvents?.get?.(key) || 0),
        bad_samples: badSamples,
      };
    });
}

function wisCameraTimelineFrameForSnapshot(frame = null) {
  if (!frame || typeof frame !== "object") return null;
  return {
    id: cleanText(frame.id, ""),
    timestamp_ms: Number(frame.timestamp_ms || 0),
    updated_at: cleanText(frame.updated_at, ""),
    bytes: Number(frame.bytes || 0),
    url: cleanText(frame.url, ""),
  };
}

function wisCameraTimelineForSnapshot() {
  const timeline = state.wisCameraTimeline || {};
  const frames = Array.isArray(timeline.frames) ? timeline.frames : [];
  const streamId = cleanText(timeline.streamId, "");
  const recordedSessions = Array.from(state.wisCameraRecordedSessions.entries())
    .slice(0, 20)
    .map(([key, session]) => ({
      stream_id: cleanText(key, ""),
      mode: cleanText(session?.mode, ""),
      status: cleanText(session?.status, ""),
      frame: wisCameraTimelineFrameForSnapshot(session?.frame),
      recorded_start_wall_time: Number(session?.recordedStartWallTime || 0),
      playback_started_at_monotonic: Number(session?.playbackStartedAtMonotonic || 0),
      current_wall_time: Number(wisCameraRecordedClockMs(session) || 0),
      playback_rate: Number(session?.playbackRate || 1),
    }));
  return {
    active_widget: cleanText(state.activeWidgetId, ""),
    widget_active: wisCameraTimelineWidgetActive(widgetById("wis")),
    stream_id: streamId,
    mode: cleanText(timeline.mode, "live"),
    playback_mode: recordedSessions.length ? "recorded" : "live",
    loading: Boolean(timeline.loading),
    error: cleanText(timeline.error, ""),
    loaded_at: Number(timeline.loadedAt || 0),
    loading_started_at: Number(timeline.loadingStartedAt || timeline.loading_started_at || 0),
    load_seq: Number(state.wisCameraTimelineLoadSeq || 0),
    frame_count: frames.length,
    range: timeline.range || null,
    available_range: timeline.availableRange || null,
    first_frame: wisCameraTimelineFrameForSnapshot(frames[0]),
    last_frame: wisCameraTimelineFrameForSnapshot(frames[frames.length - 1]),
    selected_frame: wisCameraTimelineFrameForSnapshot(selectedWisCameraTimelineFrame(streamId)),
    selections: Array.from(state.wisCameraTimelineSelections.entries())
      .slice(0, 20)
      .map(([key, frame]) => ({ stream_id: cleanText(key, ""), frame: wisCameraTimelineFrameForSnapshot(frame) })),
    pending_seeks: Array.from(state.wisCameraTimelinePendingSeeks.entries())
      .slice(0, 20)
      .map(([key, pending]) => ({
        stream_id: cleanText(key, ""),
        ratio: Number(pending?.ratio || 0),
        mode: cleanText(pending?.mode, ""),
        requested_at: Number(pending?.requestedAt || 0),
        target_time: Number(pending?.targetTime || 0),
        retention_start: Number(pending?.retentionStart || 0),
        retention_end: Number(pending?.retentionEnd || 0),
        visible_start: Number(pending?.visibleStart || 0),
        visible_end: Number(pending?.visibleEnd || 0),
        playback_position: Number(pending?.playbackPosition || 0),
      })),
    modes: Array.from(state.wisCameraTimelineModes.entries())
      .slice(0, 20)
      .map(([key, mode]) => ({ stream_id: cleanText(key, ""), mode: cleanText(mode, "live") })),
    recorded_sessions: recordedSessions,
  };
}

function wisDebugSnapshot() {
  const cameraConfigs = Object.entries(state.wisCameraConfigs || {})
    .slice(0, 40)
    .map(([key, config]) => cameraConfigForSnapshot(key, config));
  return {
    active_artifact: state.wisActiveArtifact ? {
      id: cleanText(state.wisActiveArtifact.id, ""),
      title: cleanText(state.wisActiveArtifact.title, ""),
      type: cleanText(state.wisActiveArtifact.type, ""),
      space_id: cleanText(state.wisActiveArtifact.space_id, ""),
      shared_space_id: cleanText(state.wisActiveArtifact.shared_space_id, ""),
      updated_at: cleanText(state.wisActiveArtifact.updated_at, ""),
    } : null,
    artifact_count: state.wisArtifacts.length,
    artifacts_loaded_at: cleanText(state.wisArtifactsLoadedAt, ""),
    camera_artifact_schema: WIS_CAMERA_ARTIFACT_SCHEMA,
    camera_controller_schema: WIS_CAMERA_CONTROLLER_SCHEMA,
    camera_controller: WIS_CAMERA_CONTROLLER_CONTRACT,
    surface: wisSurfaceState(),
    camera_configs: cameraConfigs,
    camera_stream_slots: Array.from(state.wisCameraStreams.keys()).slice(0, 40),
    camera_timer_slots: Array.from(state.wisCameraTimers.keys()).slice(0, 40),
    camera_runtime: wisCameraRuntimeForSnapshot(),
    camera_timeline: wisCameraTimelineForSnapshot(),
    camera_perf: wisCameraPerfForSnapshot(),
    camera_debug_events: Array.from(state.wisCameraDebugEvents.entries())
      .slice(-20)
      .map(([key, event]) => ({ key, ...event })),
  };
}

function filterClientSnapshotScope(snapshot, scope = "all") {
  const requestedScope = cleanText(scope, "all").toLowerCase();
  if (!["context", "tokens", "state", "all"].includes(requestedScope) || requestedScope === "all") {
    return { ...snapshot, scope: requestedScope === "all" ? "all" : requestedScope };
  }
  const base = {
    schema: snapshot.schema,
    snapshot_id: snapshot.snapshot_id,
    created_at: snapshot.created_at,
    reason: snapshot.reason,
    scope: requestedScope,
    device_id: snapshot.device_id,
    page: snapshot.page,
    auth_user: snapshot.auth_user,
  };
  if (requestedScope === "tokens") {
    return {
      ...base,
      active_session_id: snapshot.active_session_id,
      agent: {
        target_node: snapshot.agent?.target_node || "",
        selected_node: snapshot.agent?.selected_node || "",
        model: snapshot.agent?.model || null,
        direct_provider: snapshot.agent?.direct_provider || null,
        token_usage: state.agentTokenUsage || null,
      },
      sessions: [],
    };
  }
  if (requestedScope === "context") {
    return {
      ...base,
      active_space: snapshot.active_space,
      active_session_id: snapshot.active_session_id,
      agent: snapshot.agent,
      sessions: snapshot.sessions,
      wis: snapshot.wis,
    };
  }
  return {
    ...base,
    active_space: snapshot.active_space,
    active_session_id: snapshot.active_session_id,
    agent: snapshot.agent,
    local_storage: snapshot.local_storage,
    wis: snapshot.wis,
  };
}

function buildClientSnapshot(reason = "manual", options = {}) {
  const activeSession = activeAgentSession();
  const activeSessionId = activeSession.id;
  const model = selectedAgentModel();
  const activeProvider = activeAgentDirectProviderConfig(state.agentTargetNode);
  const snapshot = {
    schema: CLIENT_SNAPSHOT_SCHEMA,
    snapshot_id: `client_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`,
    created_at: new Date().toISOString(),
    reason: cleanText(reason, "manual"),
    scope: cleanText(options.scope, "all"),
    device_id: clientDeviceId(),
    page: {
      href: window.location.href,
      path: window.location.pathname,
      visibility: document.visibilityState,
    },
    auth_user: state.authUser ? {
      id: cleanText(state.authUser.id, ""),
      email: cleanText(state.authUser.email, ""),
      name: cleanText(state.authUser.name, ""),
      role: cleanText(state.authUser.role, ""),
    } : null,
    active_space: activeSpaceContext(),
    active_session_id: activeSessionId,
    agent: {
      view: cleanText(state.agentView, "chat"),
      target_node: agentTargetNode(),
      selected_node: cleanText(state.selectedNode, ""),
      mode: cleanText(els.agentModeSelect?.value, "auto"),
      model: model ? {
        id: cleanText(model.id, ""),
        label: cleanText(model.label, ""),
        provider: cleanText(model.provider, ""),
      } : null,
      direct_provider: activeProvider ? providerConfigForSnapshot(activeProvider) : null,
      configured_providers: Array.isArray(state.agentDirectProviders)
        ? state.agentDirectProviders.slice(0, 20).map(providerConfigForSnapshot)
        : [],
    },
    wis: wisDebugSnapshot(),
    sessions: state.agentSessions.slice(0, 20).map((session) => compactAgentSessionForSnapshot(session, activeSessionId)),
    local_storage: localStorageManifestForSnapshot(),
  };
  return filterClientSnapshotScope(snapshot, options.scope || "all");
}

function setClientSnapshotStatus(message = "") {
  state.clientSnapshotStatus = message;
}

async function publishClientSnapshot(reason = "manual", options = {}) {
  if (!state.authUser || state.clientSnapshotBusy) return null;
  state.clientSnapshotBusy = true;
  if (!options.silent) setClientSnapshotStatus("Sending snapshot...");
  try {
    const payload = await fetchJson("/client/snapshot", {
      method: "POST",
      timeoutMs: 10000,
      body: buildClientSnapshot(reason, { scope: options.scope || "all" }),
    });
    const detail = payload.latest_path || payload.path || "backend state";
    if (!options.silent) setClientSnapshotStatus(`Sent ${payload.bytes || 0} bytes`);
    recordUserEvent("client.snapshot_published", {
      target: "client-snapshot",
      summary: `Published browser-local snapshot to ${detail}`,
      data: { snapshot_id: payload.snapshot_id || "", bytes: payload.bytes || 0, reason },
    });
    return payload;
  } catch (error) {
    if (!options.silent) setClientSnapshotStatus(error.message || "Snapshot failed");
    return null;
  } finally {
    state.clientSnapshotBusy = false;
  }
}

async function respondToClientSnapshotRequest(request = {}) {
  const requestId = cleanText(request.request_id || request.requestId, "");
  if (cleanText(request.type, "client.snapshot.request") !== "client.snapshot.request") return null;
  if (!requestId || state.clientSnapshotHandledRequests.has(requestId)) return null;
  const scope = cleanText(request.scope, "all").toLowerCase();
  const payload = buildClientSnapshot(`server-request:${requestId}`, { scope });
  state.clientSnapshotHandledRequests.add(requestId);
  try {
    const response = await fetchJson("/client/snapshot/response", {
      method: "POST",
      timeoutMs: 12000,
      body: {
        schema: CLIENT_SNAPSHOT_RESPONSE_SCHEMA,
        type: "client.snapshot.response",
        request_id: requestId,
        ok: true,
        payload,
      },
    });
    recordUserEvent("client.snapshot_request_responded", {
      target: "client-snapshot",
      summary: `Responded to client snapshot request ${requestId}`,
      data: { request_id: requestId, scope, bytes: response.bytes || 0 },
    });
    return response;
  } catch (error) {
    state.clientSnapshotHandledRequests.delete(requestId);
    await fetchJson("/client/snapshot/response", {
      method: "POST",
      timeoutMs: 8000,
      body: {
        schema: CLIENT_SNAPSHOT_RESPONSE_SCHEMA,
        type: "client.snapshot.response",
        request_id: requestId,
        ok: false,
        error: { message: error.message || String(error) },
      },
    }).catch(() => null);
    return null;
  }
}

async function pollClientSnapshotRequests(origin = "poll") {
  if (!state.authUser || state.clientSnapshotRequestBusy) return;
  if (androidNativeBackgroundSyncDeferred(origin)) return;
  state.clientSnapshotRequestBusy = true;
  try {
    const payload = await fetchJson("/client/snapshot/request", { timeoutMs: 8000 });
    const requests = Array.isArray(payload.requests) ? payload.requests : [];
    for (const request of requests) {
      await respondToClientSnapshotRequest(request);
      if (isAndroidNativeShell()) await androidNativeHydrationYield("client-snapshot-request");
    }
    if (requests.length && origin !== "poll") {
      recordUserEvent("client.snapshot_requests_loaded", {
        target: "client-snapshot",
        summary: `Loaded ${requests.length} pending snapshot requests`,
        data: { origin, count: requests.length },
      });
    }
  } catch {
    // Snapshot polling is a best-effort backend request channel.
  } finally {
    state.clientSnapshotRequestBusy = false;
  }
}

function syncClientSnapshotRequestPolling() {
  if (!state.authUser) {
    if (state.clientSnapshotRequestInterval) {
      window.clearInterval(state.clientSnapshotRequestInterval);
      state.clientSnapshotRequestInterval = 0;
    }
    return;
  }
  if (!state.clientSnapshotRequestInterval) {
    const pollMs = isAndroidNativeShell() ? Math.max(CLIENT_SNAPSHOT_REQUEST_POLL_MS, ANDROID_NATIVE_BACKGROUND_SYNC_POLL_MS) : CLIENT_SNAPSHOT_REQUEST_POLL_MS;
    state.clientSnapshotRequestInterval = window.setInterval(() => {
      if (isAndroidNativeShell()) androidNativeAfterQuiet(() => void pollClientSnapshotRequests("poll"), "client-snapshot-poll");
      else void pollClientSnapshotRequests("poll");
    }, pollMs);
    if (isAndroidNativeShell()) androidNativeAfterQuiet(() => void pollClientSnapshotRequests("start"), "client-snapshot-start");
    else window.setTimeout(() => void pollClientSnapshotRequests("start"), 0);
  }
}

function agentActiveSessionStorageKey(user = state.authUser) {
  const userId = cleanText(user?.id, "anonymous");
  return `${AGENT_ACTIVE_SESSION_STORAGE_KEY}.${userId}.${clientDeviceId()}`;
}

function activeSessionPreference(session = activeAgentSession()) {
  return {
    schema: "hermes.wasm_agent.active_session.v1",
    session_id: cleanText(session?.id, ""),
    kind: cleanText(session?.kind, "agent"),
    conversation_id: cleanText(session?.conversation_id, ""),
    shared_space_id: cleanText(session?.shared_space_id, ""),
    view: state.agentView === "people" ? "people" : "chat",
    saved_at: new Date().toISOString(),
  };
}

function saveActiveAgentSessionPreference() {
  try {
    localStorage.setItem(agentActiveSessionStorageKey(), JSON.stringify(activeSessionPreference()));
  } catch {
    // Active-session restore is best effort and per browser device.
  }
}

function findPreferredAgentSession(preference = {}) {
  const sessionId = cleanText(preference.session_id, "");
  if (sessionId) {
    const match = state.agentSessions.find((session) => session.id === sessionId);
    if (match) return match;
  }
  const conversationId = cleanText(preference.conversation_id, "");
  if (conversationId) {
    const match = state.agentSessions.find((session) => session.conversation_id === conversationId);
    if (match) return match;
  }
  const sharedSpaceId = cleanText(preference.shared_space_id, "");
  if (sharedSpaceId) {
    const match = state.agentSessions.find((session) => session.shared_space_id === sharedSpaceId);
    if (match) return match;
  }
  return null;
}

function restoreActiveAgentSessionPreference() {
  try {
    const raw = JSON.parse(localStorage.getItem(agentActiveSessionStorageKey()) || "{}");
    if (!raw || typeof raw !== "object") return false;
    const preferred = findPreferredAgentSession(raw);
    if (!preferred) return false;
    state.activeAgentSessionId = preferred.id;
    state.agentView = raw.view === "people" ? "people" : "chat";
    return true;
  } catch {
    return false;
  }
}

function agentTranscriptForRequest() {
  return activeAgentSession().messages
    .filter((message) => !message.pending && message.content !== AGENT_DEFAULT_MESSAGE_CONTENT)
    .slice(-6)
    .map((message) => ({
      role: message.role,
      content: truncateText(message.content, 600),
    }));
}

function isAgentContinuationRequest(text = "") {
  const normalized = cleanText(text, "").toLowerCase().replace(/[.!?]+$/g, "").trim();
  return [
    "continue",
    "go on",
    "keep going",
    "resume",
    "continue please",
    "please continue",
    "carry on",
  ].includes(normalized);
}

function compactAgentTimelineRows(message = {}, limit = 10) {
  const timeline = Array.isArray(message.timeline) ? message.timeline : [];
  const actions = Array.isArray(message.actions) ? message.actions : [];
  return [...timeline, ...actions]
    .map((item) => ({
      label: cleanText(item.label || item.event_type || item.id || "", ""),
      status: cleanText(item.status || "", ""),
      detail: truncateText(cleanText(item.detail || item.summary || item.meta || "", ""), 140),
    }))
    .filter((item) => item.label || item.detail)
    .slice(-limit);
}

function latestAgentContinuationContext(session = activeAgentSession()) {
  const messages = Array.isArray(session?.messages) ? session.messages : [];
  const candidates = messages
    .map((message, index) => ({ message, index }))
    .filter(({ message }) => message && message.role === "assistant" && message.content !== AGENT_DEFAULT_MESSAGE_CONTENT)
    .map(({ message, index }) => {
      const content = cleanText(message.content || "", "");
      const status = cleanText(message.agent_run_status || "", "").toLowerCase();
      const phase = cleanText(message.phase || "", "").toLowerCase();
      const timelineCount = compactAgentTimelineRows(message, 20).length;
      const changedCount = Array.isArray(message.changed_files) ? message.changed_files.length : 0;
      const hollow = /no active task context|provide objective/i.test(content);
      const score = (
        (message.pending ? 60 : 0)
        + (status === "interrupted" ? 50 : 0)
        + (phase.includes("error") ? 35 : 0)
        + (/not finished|interrupted|could not answer|needs attention/i.test(content) ? 25 : 0)
        + Math.min(20, timelineCount)
        + Math.min(20, changedCount * 4)
        + (message.run_id ? 5 : 0)
        - (hollow ? 35 : 0)
        + Math.min(10, index / Math.max(1, messages.length))
      );
      return { message, score };
    })
    .filter((item) => item.score > 0)
    .sort((a, b) => b.score - a.score);
  const candidate = candidates[0]?.message || null;
  if (!candidate) return null;
  return {
    schema: "hermes.wasm_agent.avatar_chat.continuation_context.v1",
    source: "avatar-chat-session",
    previous_run_id: cleanText(candidate.run_id || "", ""),
    previous_turn_id: cleanText(candidate.turn_id || "", ""),
    previous_status: cleanText(candidate.agent_run_status || (candidate.pending ? "running" : ""), ""),
    previous_phase: cleanText(candidate.phase || "", ""),
    previous_answer: truncateText(cleanText(candidate.content || "", ""), 900),
    changed_files: (Array.isArray(candidate.changed_files) ? candidate.changed_files : [])
      .map((file) => cleanText(file.path || file.file || file, ""))
      .filter(Boolean)
      .slice(0, 12),
    timeline: compactAgentTimelineRows(candidate, 12),
    instruction: "Continue the previous avatar-chat objective from this compact context; do not ask the user to restate the objective unless the context is empty or contradictory.",
  };
}

function readAgentLayout() {
  try {
    const raw = JSON.parse(localStorage.getItem(AGENT_LAYOUT_STORAGE_KEY) || "{}");
    return raw && typeof raw === "object" ? raw : {};
  } catch {
    return {};
  }
}

function saveAgentLayout() {
  try {
    localStorage.setItem(AGENT_LAYOUT_STORAGE_KEY, JSON.stringify(state.agentLayout));
  } catch {
    // Layout persistence is best effort.
  }
}

function defaultAgentPanelSize() {
  const appRect = appViewportRect();
  if (isCompactViewport()) {
    return {
      width: Math.max(1, Math.round(appRect.width)),
      height: Math.max(1, Math.round(appRect.height)),
    };
  }
  const maxWidth = Math.max(AGENT_PANEL_MIN_WIDTH_PX, appRect.width - AGENT_PANEL_VIEWPORT_GAP_PX * 2);
  const maxHeight = Math.max(AGENT_PANEL_MIN_HEIGHT_PX, appRect.height - AGENT_PANEL_VIEWPORT_GAP_PX * 2);
  return {
    width: Math.min(AGENT_PANEL_DEFAULT_WIDTH_PX, maxWidth),
    height: Math.min(AGENT_PANEL_DEFAULT_HEIGHT_PX, maxHeight),
  };
}

function clampAgentPanelSize(size = {}) {
  const fallback = defaultAgentPanelSize();
  const appRect = appViewportRect();
  if (isCompactViewport()) {
    return {
      width: Math.max(1, Math.round(appRect.width)),
      height: Math.max(1, Math.round(appRect.height)),
    };
  }
  const maxWidth = Math.max(AGENT_PANEL_MIN_WIDTH_PX, appRect.width - AGENT_PANEL_VIEWPORT_GAP_PX * 2);
  const maxHeight = Math.max(AGENT_PANEL_MIN_HEIGHT_PX, appRect.height - AGENT_PANEL_VIEWPORT_GAP_PX * 2);
  return {
    width: clamp(Number(size.width || size.panelWidth || fallback.width), AGENT_PANEL_MIN_WIDTH_PX, maxWidth),
    height: clamp(Number(size.height || size.panelHeight || fallback.height), AGENT_PANEL_MIN_HEIGHT_PX, maxHeight),
  };
}

function applyAgentPanelSize() {
  if (!els.agentPanel) return clampAgentPanelSize(state.agentLayout);
  const size = clampAgentPanelSize(state.agentLayout);
  state.agentLayout.panelWidth = size.width;
  state.agentLayout.panelHeight = size.height;
  els.agentPanel.style.width = `${size.width}px`;
  els.agentPanel.style.height = `${size.height}px`;
  els.agentPanel.style.maxHeight = `${size.height}px`;
  return size;
}

function compactAgentCapabilityMap() {
  const size = clampAgentPanelSize(state.agentLayout);
  return {
    p: "wa1",
    s: [Math.round(size.width), Math.round(size.height)],
    op: "ar W H",
  };
}

function agentCapabilitySystemHint(cap = compactAgentCapabilityMap()) {
  try {
    return ` Cap:${JSON.stringify(cap)}; resize with hidden block \`\`\`wa1\nar W H\n\`\`\`.`;
  } catch {
    return "";
  }
}

function wisPatchClientSystemHint() {
  const space = activeSpaceContext();
  const shared = space.shared_space_id ? ` Shared space id: ${space.shared_space_id}.` : "";
  const example = {
    schema: WIS_PATCH_SCHEMA,
    artifact_id: "main",
    operations: [
      { op: "set_title", title: "Workspace Artifact" },
      {
        op: "append_child",
        parent_id: "doc",
        node: { id: "summary", type: "text", text: "Created from chat." },
      },
    ],
  };
  return [
    `For userland artifacts, dashboards, spaces, widgets, games, or automations, append one fenced json block with schema ${WIS_PATCH_SCHEMA}.`,
    `Current wasm-agent space: ${space.display_name || space.name || space.id} (${space.id}).${shared}`,
    "Omit space_id to target the current space; the client will route shared spaces to the shared WIS artifact store.",
    `Example:\n\`\`\`json\n${JSON.stringify(example)}\n\`\`\``,
    "Do not claim the artifact was applied; the wasm-agent client will append the apply result after validation.",
  ].join("\n");
}

function resizeAgentPanelByCapability(width, height) {
  const next = clampAgentPanelSize({ width, height });
  state.agentLayout.panelWidth = next.width;
  state.agentLayout.panelHeight = next.height;
  applyAgentPanelSize();
  placeAgentPanel();
  saveAgentLayout();
  recordUserEvent("agent.client_resize", {
    target: "agent-panel",
    summary: "Resized wasm-agent-chat from client capability",
    data: { width: next.width, height: next.height },
  });
  return next;
}

function applyAgentClientOpBlock(body = "") {
  const applied = [];
  for (const line of String(body || "").split(/\r?\n/)) {
    const match = line.trim().match(/^ar\s+(\d{2,4})\s+(\d{2,4})$/i);
    if (!match) continue;
    const size = resizeAgentPanelByCapability(Number(match[1]), Number(match[2]));
    applied.push({ op: "ar", s: [Math.round(size.width), Math.round(size.height)] });
  }
  return applied;
}

function applyAgentClientOpsFromReply(reply = "") {
  const source = String(reply || "");
  const ops = [];
  const cleaned = source.replace(/```wa1\s*([\s\S]*?)```/gi, (block, body) => {
    const applied = applyAgentClientOpBlock(body);
    if (!applied.length) return block;
    ops.push(...applied);
    return "";
  }).trim();
  return {
    reply: cleaned || (ops.length ? "Done." : source),
    result: ops.length ? { p: "wa1", ok: true, ops } : null,
  };
}

function extractWisPatchPayloadsFromReply(reply = "") {
  const text = String(reply || "");
  const payloads = [];
  const spans = [];
  const rangesOverlap = ([start, end]) => spans.some(([spanStart, spanEnd]) => start < spanEnd && end > spanStart);
  const jsonObjectEnd = (start) => {
    if (start < 0 || start >= text.length || text[start] !== "{") return null;
    let depth = 0;
    let inString = false;
    let escaped = false;
    for (let index = start; index < text.length; index += 1) {
      const char = text[index];
      if (inString) {
        if (escaped) escaped = false;
        else if (char === "\\") escaped = true;
        else if (char === '"') inString = false;
        continue;
      }
      if (char === '"') inString = true;
      else if (char === "{") depth += 1;
      else if (char === "}") {
        depth -= 1;
        if (depth === 0) return index + 1;
      }
    }
    return null;
  };
  const expandRawJsonSpan = (start, end) => {
    const lineStart = text.lastIndexOf("\n", start - 1) + 1;
    const previousLineEnd = lineStart - 1;
    if (previousLineEnd < 0) return [start, end];
    const previousLineStart = text.lastIndexOf("\n", previousLineEnd - 1) + 1;
    const previousLine = text.slice(previousLineStart, previousLineEnd).trim().toLowerCase();
    const between = text.slice(previousLineEnd, start).trim();
    if (["json", "wis-patch", "patch"].includes(previousLine) && !between) return [previousLineStart, end];
    return [start, end];
  };
  const appendPayload = (payload, span) => {
    if (rangesOverlap(span)) return;
    payloads.push(payload);
    spans.push(span);
  };
  const parsePayload = (block) => {
    if (!String(block || "").includes(WIS_PATCH_SCHEMA)) return null;
    try {
      const payload = JSON.parse(String(block || "").trim());
      return payload?.schema === WIS_PATCH_SCHEMA ? payload : null;
    } catch {
      return null;
    }
  };
  for (const match of text.matchAll(/```(?:json|wis-patch|patch)?\s*\n([\s\S]*?)\n```/gi)) {
    const payload = parsePayload(match[1]);
    if (!payload) continue;
    appendPayload(payload, [match.index, match.index + match[0].length]);
  }
  for (const match of text.matchAll(/<wis-patch>\s*([\s\S]*?)\s*<\/wis-patch>/gi)) {
    const payload = parsePayload(match[1]);
    if (!payload) continue;
    appendPayload(payload, [match.index, match.index + match[0].length]);
  }
  let schemaIndex = text.indexOf(WIS_PATCH_SCHEMA);
  while (schemaIndex !== -1) {
    if (!rangesOverlap([schemaIndex, schemaIndex + WIS_PATCH_SCHEMA.length])) {
      let start = text.lastIndexOf("{", schemaIndex);
      while (start !== -1) {
        const end = jsonObjectEnd(start);
        if (end !== null && end >= schemaIndex) {
          const payload = parsePayload(text.slice(start, end));
          if (payload) {
            appendPayload(payload, expandRawJsonSpan(start, end));
            break;
          }
        }
        start = text.lastIndexOf("{", start - 1);
      }
    }
    schemaIndex = text.indexOf(WIS_PATCH_SCHEMA, schemaIndex + WIS_PATCH_SCHEMA.length);
  }
  let cleaned = text;
  spans.sort((left, right) => right[0] - left[0]).forEach(([start, end]) => {
    cleaned = `${cleaned.slice(0, start).trimEnd()}\n\n${cleaned.slice(end).trimStart()}`;
  });
  return { reply: spans.length ? cleaned.trim() : text, payloads };
}

function currentWisPatchTarget() {
  const space = activeSpaceContext();
  return {
    space_id: activeSpaceStorageId(),
    shared_space_id: cleanText(space.shared_space_id, ""),
  };
}

function normalizeClientWisPatchSpaceId(value, fallback) {
  const raw = cleanText(value, "");
  if (!raw || ["current", "current-space", "current_space", "active-space", "active_space"].includes(raw.toLowerCase())) {
    return fallback;
  }
  return raw;
}

function summarizeWisPatchResult(result = {}) {
  if (result.applied) {
    const patches = Array.isArray(result.patches) ? result.patches : [];
    const targets = patches.map((patch) => patch.artifact_id).filter(Boolean).join(", ");
    return `Applied WIS/userland patch${targets ? ` to ${targets}` : ""}.`;
  }
  const errors = Array.isArray(result.errors) ? result.errors : [];
  return `WIS/userland patch was not applied: ${errors[0] || "no valid patch was provided"}`;
}

function wisPatchActionFromResult(result = {}) {
  const applied = Boolean(result.applied);
  const patches = Array.isArray(result.patches) ? result.patches : [];
  return agentAction("Apply WIS/userland patch", applied ? "done" : "error", applied ? `${patches.length} artifacts / ${result.operations || 0} operations` : summarizeWisPatchResult(result), {
    id: "apply_wis_patch",
    topic: "run-wasm",
    kind: "mutation",
    meta: "client adapter",
    arguments: { schema: WIS_PATCH_SCHEMA },
    preview: JSON.stringify(result, null, 2).slice(0, 1200),
  });
}

async function applyClientWisPatchesFromReply(reply = "") {
  const extracted = extractWisPatchPayloadsFromReply(reply);
  if (!extracted.payloads.length) return { reply, result: null };
  const target = currentWisPatchTarget();
  const result = {
    schema: "hermes.wasm_agent.wis.patch_result.v1",
    applied: false,
    patches: [],
    operations: 0,
    errors: [],
  };
  for (const payload of extracted.payloads) {
    const patch = { ...payload };
    patch.space_id = normalizeClientWisPatchSpaceId(patch.space_id, target.space_id);
    if (target.shared_space_id && !patch.shared_space_id) patch.shared_space_id = target.shared_space_id;
    try {
      const response = await fetchJson("/wis/artifacts/patch", {
        method: "POST",
        timeoutMs: 12000,
        body: patch,
      });
      const patchResult = response.wis_patch || response;
      logWisArtifactFlow("create-response", {
        origin: "client-wis-patch",
        artifact_id: patchResult.artifact_id || patch.artifact_id,
        title: patch.title || "",
        schema: patchResult.schema || response.schema || "",
        space_id: patchResult.space_id || patch.space_id,
        shared_space_id: patchResult.shared_space_id || patch.shared_space_id,
        transport: "http-post",
      });
      result.patches.push(patchResult);
      result.operations += Number(patchResult.operations || 0);
      result.applied = Boolean(result.applied || patchResult.applied);
    } catch (error) {
      result.errors.push(error.message || String(error));
    }
  }
  const summary = summarizeWisPatchResult(result);
  if (result.applied) await refreshWisArtifactsAfterPatch(result, "client-wis-patch");
  return {
    reply: `${extracted.reply || ""}\n\n${summary}`.trim(),
    result,
  };
}

function readAgentModelSettings() {
  try {
    const raw = JSON.parse(localStorage.getItem(AGENT_MODELS_STORAGE_KEY) || "{}");
    if (!raw || typeof raw !== "object") return { models: [], hiddenModels: [], selectedByNode: {}, providerByNode: {} };
    return {
      models: Array.isArray(raw.models) ? raw.models.map(normalizeAgentModelEntry).filter(Boolean) : [],
      hiddenModels: Array.isArray(raw.hiddenModels) ? raw.hiddenModels.map((item) => cleanText(item, "").toLowerCase()).filter(Boolean) : [],
      selectedByNode: raw.selectedByNode && typeof raw.selectedByNode === "object"
        ? Object.fromEntries(Object.entries(raw.selectedByNode).map(([nodeId, model]) => [
            cleanText(nodeId, "orchestrator"),
            normalizeAgentModelEntry(model),
          ]).filter(([, model]) => Boolean(model)))
        : {},
      providerByNode: raw.providerByNode && typeof raw.providerByNode === "object"
        ? Object.fromEntries(Object.entries(raw.providerByNode).map(([nodeId, providerId]) => [
            cleanText(nodeId, "orchestrator"),
            normalizeAgentProviderNodeId(providerId),
          ]).filter(([, providerId]) => Boolean(providerId)))
        : {},
    };
  } catch {
    return { models: [], hiddenModels: [], selectedByNode: {}, providerByNode: {} };
  }
}

function saveAgentModelSettings() {
  try {
    localStorage.setItem(AGENT_MODELS_STORAGE_KEY, JSON.stringify(state.agentModelSettings));
  } catch {
    // Model selection is local convenience state; the default model still works.
  }
}

function readAgentImageProcessingPreference() {
  try {
    return localStorage.getItem(AGENT_IMAGE_PROCESSING_STORAGE_KEY) !== "0";
  } catch {
    return true;
  }
}

function saveAgentImageProcessingPreference() {
  try {
    localStorage.setItem(AGENT_IMAGE_PROCESSING_STORAGE_KEY, state.agentImageProcessingEnabled ? "1" : "0");
  } catch {
    // Image analysis can always fall back to the default runtime preference.
  }
}

function agentDirectProviderStorageKey(user = state.authUser) {
  const id = cleanText(user?.id, "");
  return id ? `${AGENT_DIRECT_PROVIDER_STORAGE_KEY}.${id}` : "";
}

function agentDirectProvidersStorageKey(user = state.authUser) {
  const id = cleanText(user?.id, "");
  return id ? `${AGENT_DIRECT_PROVIDERS_STORAGE_KEY}.${id}` : "";
}

function normalizeAgentProviderNodeId(value = "") {
  const id = cleanText(value, "").toLowerCase().replace(/[^a-z0-9_-]+/g, "_").replace(/^_+|_+$/g, "");
  return /^[a-z0-9][a-z0-9_-]{5,95}$/.test(id) ? id : "";
}

function createAgentProviderNodeId() {
  return `provider_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
}

function directProviderTargetValue(config = state.agentDirectProvider) {
  const id = normalizeAgentProviderNodeId(config?.id || config?.providerId || "");
  return id ? `${AGENT_PROVIDER_TARGET_PREFIX}${encodeURIComponent(id)}` : AGENT_PROVIDER_TARGET_ID;
}

function providerIdFromTargetValue(value = state.agentTargetNode) {
  const raw = cleanText(value, "");
  if (raw === AGENT_PROVIDER_TARGET_ID) return normalizeAgentProviderNodeId(state.agentDirectProvider?.id || "");
  if (!raw.startsWith(AGENT_PROVIDER_TARGET_PREFIX)) return "";
  try {
    return normalizeAgentProviderNodeId(decodeURIComponent(raw.slice(AGENT_PROVIDER_TARGET_PREFIX.length)));
  } catch {
    return "";
  }
}

function normalizeAgentDirectProviderConfigs(raw) {
  const source = Array.isArray(raw)
    ? raw
    : Array.isArray(raw?.providers) ? raw.providers : Array.isArray(raw?.nodes) ? raw.nodes : raw ? [raw] : [];
  const seen = new Set();
  return source.map((item) => {
    const normalized = normalizeAgentDirectProviderConfig(item);
    if (!normalized?.baseUrl || !normalized?.model || !normalized?.apiKey) return null;
    const id = normalizeAgentProviderNodeId(normalized.id || normalized.providerId || "") || createAgentProviderNodeId();
    const next = { ...normalized, id };
    if (seen.has(id)) return null;
    seen.add(id);
    return next;
  }).filter(Boolean);
}

function readAgentDirectProviderConfigs(user = state.authUser) {
  const listKey = agentDirectProvidersStorageKey(user);
  const scopedKey = agentDirectProviderStorageKey(user);
  if (!listKey) return [];
  try {
    const stored = normalizeAgentDirectProviderConfigs(JSON.parse(localStorage.getItem(listKey) || "[]"));
    if (stored.length) return stored;
    if (!isAdminUser(user)) {
      const scoped = normalizeAgentDirectProviderConfigs(JSON.parse(localStorage.getItem(scopedKey) || "{}"));
      const legacy = scoped.length ? scoped : normalizeAgentDirectProviderConfigs(JSON.parse(localStorage.getItem(AGENT_DIRECT_PROVIDER_STORAGE_KEY) || "{}"));
      if (legacy.length) {
        localStorage.setItem(listKey, JSON.stringify(legacy));
        localStorage.removeItem(AGENT_DIRECT_PROVIDER_STORAGE_KEY);
        return legacy;
      }
    }
  } catch {
    // Browser-only provider state is optional; ignore unreadable local storage.
  }
  return [];
}

function readAgentDirectProviderConfig(user = state.authUser) {
  return readAgentDirectProviderConfigs(user)[0] || null;
}

function activeAgentDirectProviderConfig(value = state.agentTargetNode) {
  const targetId = providerIdFromTargetValue(value);
  if (targetId) {
    return state.agentDirectProviders.find((config) => normalizeAgentProviderNodeId(config?.id || "") === targetId)
      || (normalizeAgentProviderNodeId(state.agentDirectProvider?.id || "") === targetId ? state.agentDirectProvider : null);
  }
  if (cleanText(value, "") === AGENT_PROVIDER_TARGET_ID) return state.agentDirectProvider || state.agentDirectProviders[0] || null;
  return state.agentDirectProvider || state.agentDirectProviders[0] || null;
}

function hasDirectProviderConfigured() {
  return state.agentDirectProviders.some((config) => directProviderConfigured(config));
}

function saveAgentDirectProviderConfigs(configs, user = state.authUser) {
  const listKey = agentDirectProvidersStorageKey(user);
  state.agentDirectProviders = normalizeAgentDirectProviderConfigs(configs);
  const activeId = providerIdFromTargetValue(state.agentTargetNode);
  state.agentDirectProvider = state.agentDirectProviders.find((config) => config.id === activeId)
    || state.agentDirectProviders[0]
    || null;
  try {
    if (!listKey) return;
    if (state.agentDirectProviders.length && !isAdminUser(user)) {
      localStorage.setItem(listKey, JSON.stringify(state.agentDirectProviders));
    } else {
      localStorage.removeItem(listKey);
    }
  } catch {
    // Direct provider keys are browser-only convenience state.
  }
}

function loadAgentDirectProviderForUser(user = state.authUser) {
  state.agentDirectProviders = readAgentDirectProviderConfigs(user);
  state.agentDirectProvider = activeAgentDirectProviderConfig() || state.agentDirectProviders[0] || null;
  state.nodeFormOpen = false;
  state.nodeFormDraft = null;
  state.nodeFormMode = "new";
  if (!hasDirectProviderConfigured() && (state.agentTargetNode === AGENT_PROVIDER_TARGET_ID || state.agentTargetNode.startsWith?.(AGENT_PROVIDER_TARGET_PREFIX))) {
    state.agentTargetNode = defaultAgentTargetNode();
  }
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
}

function normalizeAgentHarnessType(value = AGENT_HARNESS_DEFAULT_TYPE) {
  const raw = cleanText(value || AGENT_HARNESS_DEFAULT_TYPE, AGENT_HARNESS_DEFAULT_TYPE).toLowerCase().replace(/[-\s]+/g, "_");
  if (!raw || raw === "agent" || raw === AGENT_HARNESS_DEFAULT_TYPE) return AGENT_HARNESS_DEFAULT_TYPE;
  return raw;
}

function agentHarnessTypeLabel(value = AGENT_HARNESS_DEFAULT_TYPE) {
  const type = normalizeAgentHarnessType(value);
  if (type === "openclaw") return "OpenClaw";
  if (type === "kilocode") return "KiloCode";
  if (type === "claude_code") return "Claude Code";
  if (type === "pi") return "Pi";
  return "Hermes";
}

function normalizeAgentHarnessInfraMode(value = AGENT_HARNESS_DEFAULT_INFRA_MODE) {
  const raw = cleanText(value || AGENT_HARNESS_DEFAULT_INFRA_MODE, AGENT_HARNESS_DEFAULT_INFRA_MODE).toLowerCase().replace(/[-\s]+/g, "_");
  if (["custom", "custom_bridge", "bridge", "own", "own_bridge", "own_infra"].includes(raw)) return AGENT_HARNESS_OWN_INFRA_MODE;
  if (["hermes", "hermes_backend", "hermes_infra", "backend", "backend_infra", "our", "our_infra"].includes(raw)) return AGENT_HARNESS_DEFAULT_INFRA_MODE;
  return raw;
}

function normalizeDirectProviderName(value = "") {
  const raw = cleanText(value, "").toLowerCase().replace(/[\s_]+/g, "-");
  if (raw === "openrouter" || raw === "open-router") return "openrouter";
  if (raw === "opencode-go" || raw === "opencode" || raw === "open-code-go") return "opencode-go";
  return "";
}

function directProviderDefinition(provider = "") {
  return AGENT_DIRECT_PROVIDER_DEFINITIONS[normalizeDirectProviderName(provider)] || null;
}

function directProviderBaseUrlForProvider(provider = "") {
  return directProviderDefinition(provider)?.baseUrl || "";
}

function normalizeDirectProviderModelList(models = []) {
  const seen = new Set();
  return (Array.isArray(models) ? models : []).map((model) => {
    if (typeof model === "string") {
      return { id: cleanText(model, ""), label: cleanText(model, "") };
    }
    return {
      id: cleanText(model?.id, ""),
      label: cleanText(model?.label || model?.name || model?.id, ""),
    };
  }).filter((model) => {
    if (!model.id || seen.has(model.id)) return false;
    seen.add(model.id);
    return true;
  });
}

function directProviderLiveModelOptions(provider = "") {
  const cleanProvider = normalizeDirectProviderName(provider);
  return normalizeDirectProviderModelList(state.agentDirectProviderModels?.[cleanProvider] || []);
}

function directProviderCachedModelOptions(provider = "") {
  const cleanProvider = normalizeDirectProviderName(provider);
  const liveModels = directProviderLiveModelOptions(cleanProvider);
  if (liveModels.length) return liveModels;
  const definition = directProviderDefinition(cleanProvider);
  if (definition && !definition.models?.length) void loadDirectProviderModelSnapshot();
  return normalizeDirectProviderModelList(definition?.models || []);
}

function directProviderModelStatus(provider = "") {
  const cleanProvider = normalizeDirectProviderName(provider);
  return state.agentDirectProviderModelStatus?.[cleanProvider] || { status: "idle", message: "" };
}

function setDirectProviderModelStatus(provider = "", status = {}) {
  const cleanProvider = normalizeDirectProviderName(provider);
  if (!cleanProvider) return;
  state.agentDirectProviderModelStatus = {
    ...(state.agentDirectProviderModelStatus || {}),
    [cleanProvider]: { status: status.status || "idle", message: cleanText(status.message || "", "") },
  };
}

function applyDirectProviderModelSnapshot(snapshot = {}) {
  Object.entries(snapshot && typeof snapshot === "object" ? snapshot : {}).forEach(([provider, models]) => {
    const cleanProvider = normalizeDirectProviderName(provider);
    const definition = directProviderDefinition(cleanProvider);
    if (!definition || definition.models?.length) return;
    definition.models = normalizeDirectProviderModelList(models);
  });
}

function loadDirectProviderModelSnapshot() {
  if (agentDirectProviderModelSnapshotPromise) return agentDirectProviderModelSnapshotPromise;
  agentDirectProviderModelSnapshotPromise = import(AGENT_DIRECT_PROVIDER_MODEL_SNAPSHOT_PATH)
    .then((module) => {
      applyDirectProviderModelSnapshot(module?.PROVIDER_MODEL_SNAPSHOT || {});
      renderNodesPanel();
      return true;
    })
    .catch(() => false);
  return agentDirectProviderModelSnapshotPromise;
}

async function loadDirectProviderModels(provider = "", options = {}) {
  const cleanProvider = normalizeDirectProviderName(provider);
  const definition = directProviderDefinition(cleanProvider);
  if (!cleanProvider || !definition?.modelsPath) return directProviderModelOptions(cleanProvider);
  const liveModels = directProviderLiveModelOptions(cleanProvider);
  if (liveModels.length && !options.force) return liveModels;
  if (AGENT_DIRECT_PROVIDER_MODEL_REQUESTS.has(cleanProvider)) {
    return AGENT_DIRECT_PROVIDER_MODEL_REQUESTS.get(cleanProvider);
  }
  setDirectProviderModelStatus(cleanProvider, { status: "loading", message: `Loading ${definition.label} models` });
  const request = fetchJson(definition.modelsPath, { timeoutMs: 25000 })
    .then((payload) => {
      const models = normalizeDirectProviderModelList(payload?.models || payload?.data || []);
      if (!models.length) throw new Error("No models returned.");
      state.agentDirectProviderModels = { ...(state.agentDirectProviderModels || {}), [cleanProvider]: models };
      setDirectProviderModelStatus(cleanProvider, { status: "ready", message: `${models.length} models loaded` });
      if (state.nodeFormOpen && normalizeDirectProviderName(state.nodeFormDraft?.provider || "") === cleanProvider) {
        syncNodeFormDraftFromInputs({ render: false });
      }
      renderNodesPanel();
      return models;
    })
    .catch((error) => {
      const fallback = directProviderCachedModelOptions(cleanProvider);
      setDirectProviderModelStatus(cleanProvider, fallback.length
        ? { status: "snapshot", message: `Using bundled ${definition.label} models` }
        : { status: "error", message: error?.message || "Model list unavailable" });
      renderNodesPanel();
      return fallback;
    })
    .finally(() => {
      AGENT_DIRECT_PROVIDER_MODEL_REQUESTS.delete(cleanProvider);
    });
  AGENT_DIRECT_PROVIDER_MODEL_REQUESTS.set(cleanProvider, request);
  renderNodesPanel();
  return request;
}

function directProviderModelOptions(provider = "", currentModel = "") {
  const cleanProvider = normalizeDirectProviderName(provider);
  const definition = directProviderDefinition(cleanProvider);
  const options = directProviderCachedModelOptions(cleanProvider);
  const normalizedCurrent = normalizeDirectProviderModel(currentModel, definition?.baseUrl || "", cleanProvider);
  if (normalizedCurrent && !options.some((model) => model.id === normalizedCurrent)) {
    options.push({ id: normalizedCurrent, label: normalizedCurrent });
  }
  return options;
}

async function verifyDirectProviderModelListing(config = {}) {
  const provider = normalizeDirectProviderName(config.provider || directProviderNameFromBaseUrl(config.baseUrl || ""));
  if (!provider) return { ok: false, message: "Missing provider." };
  const models = await loadDirectProviderModels(provider, { force: true });
  const normalizedModel = normalizeDirectProviderModel(config.model || "", config.baseUrl || "", provider);
  if (!models.length) return { ok: false, message: "Provider model listing did not return models." };
  if (normalizedModel && !models.some((model) => model.id === normalizedModel)) {
    return { ok: false, message: `Model ${normalizedModel} was not returned by ${provider}.` };
  }
  return { ok: true, count: models.length };
}

function normalizeAgentDirectProviderConfig(config = {}) {
  if (!config || typeof config !== "object") return null;
  let baseUrl = normalizeDirectProviderBaseUrl(config.baseUrl || config.base_url || "");
  let provider = normalizeDirectProviderName(config.provider || "") || normalizeDirectProviderName(directProviderNameFromBaseUrl(baseUrl));
  const modelGuess = !provider && config.model ? directProviderGuessFromModel(config.model) : null;
  if (!provider && modelGuess?.provider) provider = normalizeDirectProviderName(modelGuess.provider);
  if (!baseUrl && provider) baseUrl = directProviderBaseUrlForProvider(provider);
  const model = normalizeDirectProviderModel(config.model || "", baseUrl, provider);
  const apiKey = String(config.apiKey || config.api_key || "");
  const transport = normalizeProviderTransport(config.transport || config.provider_transport || config.transportMode || "");
  const providerId = normalizeAgentProviderNodeId(config.id || config.providerId || config.provider_id || "");
  const nodeName = cleanText(config.nodeName || config.node_name || "", "").slice(0, 80);
  const harnessSource = config.agentHarness && typeof config.agentHarness === "object"
    ? config.agentHarness
    : config.agentWrapper && typeof config.agentWrapper === "object" ? config.agentWrapper : {};
  const harnessType = normalizeAgentHarnessType(harnessSource.type || config.harnessType || config.wrapperType || config.agentWrapperType || AGENT_HARNESS_DEFAULT_TYPE);
  const harnessInfraMode = normalizeAgentHarnessInfraMode(harnessSource.infraMode || harnessSource.infra_mode || config.harnessInfraMode || AGENT_HARNESS_DEFAULT_INFRA_MODE);
  const harnessName = cleanText(harnessSource.name || config.harnessName || config.wrapperName || config.agentWrapperName || "", "").slice(0, 80);
  const harnessInstructions = cleanText(
    harnessSource.instructions || harnessSource.role || config.harnessInstructions || config.wrapperRole || config.agentWrapperRole || config.topic || config.agentTopic || config.agent_topic || "",
    ""
  ).slice(0, 2000);
  const harnessBridgeUrl = normalizeOwnedAgentBridgeUrl(harnessSource.bridgeUrl || harnessSource.bridge_url || config.harnessBridgeUrl || "");
  const persistedHarnessId = cleanText(config.persistedHarnessId || config.harnessId || harnessSource.persistedHarnessId || harnessSource.harnessId || "", "");
  const persistedNodeId = cleanText(config.persistedNodeId || config.nodeId || harnessSource.persistedNodeId || harnessSource.nodeId || "", "");
  const hasHarnessEnabled = Object.prototype.hasOwnProperty.call(config, "agentHarnessEnabled")
    || Object.prototype.hasOwnProperty.call(config, "agentWrapperEnabled")
    || Object.prototype.hasOwnProperty.call(harnessSource, "enabled");
  const harnessEnabled = hasHarnessEnabled ? Boolean(config.agentHarnessEnabled || config.agentWrapperEnabled || harnessSource.enabled) : Boolean(harnessName || harnessInstructions || harnessBridgeUrl);
  const next = {};
  if (baseUrl) next.baseUrl = baseUrl;
  const endpoint = directProviderEndpointForBaseUrl(baseUrl, provider);
  if (endpoint) next.endpoint = endpoint;
  if (model) next.model = model;
  if (apiKey) next.apiKey = apiKey;
  if (provider) next.provider = provider;
  if (providerId) next.id = providerId;
  if (nodeName) next.nodeName = nodeName;
  if (harnessEnabled) {
    next.agentHarness = {
      enabled: true,
      name: harnessName,
      type: harnessType,
      infraMode: harnessInfraMode,
      bridgeUrl: harnessBridgeUrl,
      instructions: harnessInstructions,
    };
  }
  if (transport !== AGENT_PROVIDER_TRANSPORTS.AUTO) next.transport = transport;
  if (config.baseUrlInferred) next.baseUrlInferred = true;
  if (persistedHarnessId) next.persistedHarnessId = persistedHarnessId;
  if (persistedNodeId) next.persistedNodeId = persistedNodeId;
  const verification = config.verification && typeof config.verification === "object" ? config.verification : {};
  const verifiedAt = cleanText(config.verified_at || config.verifiedAt || verification.checked_at_iso || verification.checkedAtIso || "", "");
  const verifiedFingerprint = cleanText(config.verified_fingerprint || config.verifiedFingerprint || verification.fingerprint || "", "");
  if (verifiedAt && verifiedFingerprint) {
    next.verified_at = verifiedAt;
    next.verified_fingerprint = verifiedFingerprint;
    next.verification = {
      ok: verification.ok !== false,
      fingerprint: verifiedFingerprint,
      mode: cleanText(verification.mode || config.verified_mode || "", ""),
      category: cleanText(verification.category || config.verified_category || "", ""),
      message: cleanText(verification.message || "", ""),
      checked_at: Number(verification.checked_at || config.verified_checked_at || 0) || 0,
      checked_at_iso: verifiedAt,
    };
  }
  return Object.keys(next).length ? next : null;
}

function saveAgentDirectProviderConfig(config, user = state.authUser) {
  const previousFingerprint = directProviderConfigFingerprint(activeAgentDirectProviderConfig());
  const normalized = normalizeAgentDirectProviderConfig(config);
  if (!normalized) {
    const deleteId = providerIdFromTargetValue(state.agentTargetNode) || normalizeAgentProviderNodeId(state.agentDirectProvider?.id || "");
    const next = deleteId
      ? state.agentDirectProviders.filter((item) => normalizeAgentProviderNodeId(item?.id || "") !== deleteId)
      : [];
    saveAgentDirectProviderConfigs(next, user);
    if (!state.agentDirectProviders.length) state.agentTargetNode = AGENT_NONE_TARGET_ID;
    state.agentProviderProbe = null;
    return null;
  }
  const id = normalizeAgentProviderNodeId(normalized.id || normalized.providerId || "")
    || normalizeAgentProviderNodeId(state.nodeFormDraft?.id || state.nodeFormDraft?.providerId || "")
    || (state.nodeFormMode === "edit" ? providerIdFromTargetValue(state.agentTargetNode) : "")
    || createAgentProviderNodeId();
  const saved = { ...normalized, id };
  const next = state.agentDirectProviders.filter((item) => normalizeAgentProviderNodeId(item?.id || "") !== id);
  next.push(saved);
  state.agentTargetNode = directProviderTargetValue(saved);
  saveAgentDirectProviderConfigs(next, user);
  state.agentDirectProvider = saved;
  const savedFingerprint = directProviderConfigFingerprint(saved);
  if (previousFingerprint !== savedFingerprint && state.agentProviderProbe?.fingerprint !== savedFingerprint) state.agentProviderProbe = null;
  return saved;
}

function agentOwnedAgentStorageKey(user = state.authUser) {
  const id = cleanText(user?.id, "");
  return id ? `${AGENT_OWNED_AGENT_STORAGE_KEY}.${id}` : "";
}

function normalizeOwnedAgentBridgeUrl(value = "") {
  const raw = cleanText(value, "").replace(/\/+$/, "");
  if (!raw) return "";
  try {
    const url = new URL(raw);
    if (!["http:", "https:"].includes(url.protocol) || !url.hostname) return "";
    return url.href.replace(/\/+$/, "");
  } catch {
    return "";
  }
}

function normalizeAgentOwnedAgentConfig(config = {}) {
  if (!config || typeof config !== "object") return null;
  const name = cleanText(config.name || config.agentName || "", "").slice(0, 80);
  const role = cleanText(config.role || config.instructions || "", "").slice(0, 2000);
  const type = cleanText(config.type || "hermes", "hermes").toLowerCase();
  const bridgeUrl = normalizeOwnedAgentBridgeUrl(config.bridgeUrl || config.bridge_url || "");
  const hasInput = Boolean(name || role || bridgeUrl);
  if (!hasInput) return null;
  const next = {
    name: name || "My agent",
    role,
    type: type === "hermes" ? "hermes" : "hermes",
    bridgeUrl,
    service: bridgeUrl ? "own-bridge" : "hermes-orchestrator",
  };
  return next;
}

function readAgentOwnedAgentConfig(user = state.authUser) {
  const scopedKey = agentOwnedAgentStorageKey(user);
  if (!scopedKey) return null;
  try {
    return normalizeAgentOwnedAgentConfig(JSON.parse(localStorage.getItem(scopedKey) || "{}"));
  } catch {
    return null;
  }
}

function saveAgentOwnedAgentConfig(config, user = state.authUser) {
  const scopedKey = agentOwnedAgentStorageKey(user);
  state.agentOwnedAgent = normalizeAgentOwnedAgentConfig(config);
  try {
    if (!scopedKey) return;
    if (state.agentOwnedAgent && !isAdminUser(user)) {
      localStorage.setItem(scopedKey, JSON.stringify(state.agentOwnedAgent));
    } else {
      localStorage.removeItem(scopedKey);
    }
  } catch {
    // Owned agent setup is browser-local unless provisioning is submitted.
  }
}

function loadAgentOwnedAgentForUser(user = state.authUser) {
  state.agentOwnedAgent = readAgentOwnedAgentConfig(user);
  state.agentTopicFormOpen = false;
  state.agentTopicDraft = null;
  if (!ownedAgentConfigured() && state.agentTargetNode === AGENT_OWNED_AGENT_TARGET_ID) {
    state.agentTargetNode = defaultAgentTargetNode();
  }
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
}

function directProviderConfigured(config = activeAgentDirectProviderConfig()) {
  return Boolean(config?.baseUrl && config?.model && config?.apiKey);
}

function ownedAgentConfigured() {
  return Boolean(state.agentOwnedAgent?.name || state.agentOwnedAgent?.bridgeUrl || state.agentOwnedAgent?.role);
}

function agentTargetIsDirectProvider(value = state.agentTargetNode) {
  const config = activeAgentDirectProviderConfig(value);
  return Boolean(providerIdFromTargetValue(value) || cleanText(value, "") === AGENT_PROVIDER_TARGET_ID)
    && directProviderConfigured(config)
    && directProviderVerified(config);
}

function agentTargetIsMasterFrontier(value = state.agentTargetNode) {
  return cleanText(value, "") === AGENT_MASTER_FRONTIER_TARGET_ID && isAdminUser();
}

function agentTargetIsOwnedAgent(value = state.agentTargetNode) {
  return cleanText(value, "") === AGENT_OWNED_AGENT_TARGET_ID && ownedAgentConfigured();
}

function agentTargetIsNone(value = state.agentTargetNode) {
  return cleanText(value, "") === AGENT_NONE_TARGET_ID;
}

function agentTargetIsAgentModel(value = state.agentTargetNode) {
  return cleanText(value, "").startsWith(AGENT_MODEL_TARGET_PREFIX);
}

function providerModelDisplayLabel(model) {
  const normalized = normalizeAgentModelEntry(model);
  if (!normalized) return "";
  if (normalized.provider && normalized.name) return `${normalized.provider}:${normalized.name}`;
  return cleanText(normalized.label || normalized.id, "").replace("/", ":");
}

function compactModelDisplayName(model = "", provider = "") {
  const normalized = normalizeAgentModelEntry(typeof model === "object" ? model : { id: model, provider });
  const raw = cleanText(normalized?.id || normalized?.name || normalized?.label || "", "");
  const name = cleanText(normalized?.name || raw, "");
  const source = name && name !== raw ? name : raw;
  if (!source) return "";
  const parts = source.split("/").map((part) => cleanText(part, "")).filter(Boolean);
  if (parts.length > 1) return parts[parts.length - 1];
  return source.replace(/^[-_\s]+|[-_\s]+$/g, "");
}

function cleanDisplayNodeId(nodeId = "") {
  const id = cleanText(nodeId, "");
  return id.endsWith("-main") ? id.slice(0, -5) : id;
}

function agentRuntimeOptionLabel({ mode = "Hermes", name = "", provider = "", model = "" } = {}) {
  const cleanMode = mode === "Direct" ? "Direct" : "Hermes";
  const nodeName = cleanText(name, "Agent");
  const providerName = cleanText(provider, "provider");
  const modelName = compactModelDisplayName(model, providerName) || "model";
  return `${cleanMode}:${nodeName}/${providerName}/${modelName}`;
}

function agentModelTargetValue(model) {
  const key = agentModelKey(model);
  return key ? `${AGENT_MODEL_TARGET_PREFIX}${encodeURIComponent(key)}` : "";
}

function agentModelFromTargetValue(value) {
  const raw = cleanText(value, "");
  if (!raw.startsWith(AGENT_MODEL_TARGET_PREFIX)) return null;
  let key = raw.slice(AGENT_MODEL_TARGET_PREFIX.length);
  try {
    key = decodeURIComponent(key);
  } catch {
    key = "";
  }
  key = cleanText(key, "").toLowerCase();
  if (!key) return null;
  return availableAgentModels().find((model) => agentModelKeys(model).includes(key)) || null;
}

function agentProviderNodeLabel(config = state.agentDirectProvider) {
  const nodeName = cleanText(config?.nodeName, "");
  if (nodeName) return nodeName;
  const provider = cleanText(config?.provider, "provider");
  const model = cleanText(config?.model, "");
  return model ? `${provider}:${model}` : provider;
}

function normalizedAgentTargetName(value = "") {
  return cleanText(value, "").toLowerCase();
}

function agentHarnessLifecycleState(harness = {}) {
  return cleanText(harness?.lifecycle_state || harness?.lifecycleState || "", "");
}

function agentHarnessNodeId(harness = {}) {
  return cleanText(harness?.node_id || harness?.nodeId || "", "");
}

function agentHarnessDisplayName(harness = {}) {
  return cleanText(harness?.harness_name || harness?.harnessName || harness?.name || harness?.node_name || harness?.nodeName, "Agent");
}

function agentHarnessNameKeys(harness = {}) {
  return new Set([
    agentHarnessDisplayName(harness),
    harness?.node_name,
    harness?.nodeName,
  ].map(normalizedAgentTargetName).filter(Boolean));
}

function directProviderNameKeys(config = {}) {
  return new Set([
    agentProviderNodeLabel(config),
    config?.nodeName,
    config?.name,
  ].map(normalizedAgentTargetName).filter(Boolean));
}

function readyUserFleetHarnesses() {
  if (isAdminUser() || !Array.isArray(state.userFleetHarnesses)) return [];
  return state.userFleetHarnesses.filter((harness) => agentHarnessLifecycleState(harness) === "ready" && agentHarnessNodeId(harness));
}

function readyHarnessForDirectProvider(config = {}, harnesses = readyUserFleetHarnesses()) {
  const providerKeys = directProviderNameKeys(config);
  if (!providerKeys.size) return null;
  return harnesses.find((harness) => {
    const harnessKeys = agentHarnessNameKeys(harness);
    return Array.from(providerKeys).some((key) => harnessKeys.has(key));
  }) || null;
}

function directProviderForHarness(harness = {}) {
  if (!Array.isArray(state.agentDirectProviders)) return null;
  return state.agentDirectProviders.find((config) => readyHarnessForDirectProvider(config, [harness])) || null;
}

function userFleetHarnessForNode(nodeId = "") {
  const target = cleanText(nodeId, "");
  if (!target || !Array.isArray(state.userFleetHarnesses)) return null;
  return state.userFleetHarnesses.find((harness) => agentHarnessNodeId(harness) === target) || null;
}

function ownedAgentConfigFromFleetHarness(harness = {}) {
  const infraMode = normalizeAgentHarnessInfraMode(harness?.infra_mode || harness?.infraMode || "");
  const bridgeUrl = normalizeOwnedAgentBridgeUrl(harness?.bridge_url || harness?.bridgeUrl || "");
  if (infraMode !== AGENT_HARNESS_OWN_INFRA_MODE || !bridgeUrl) return null;
  return normalizeAgentOwnedAgentConfig({
    name: agentHarnessDisplayName(harness),
    role: cleanText(harness.instructions || harness.metadata?.instructions || "", ""),
    type: "hermes",
    bridgeUrl,
  });
}

function adoptOwnedAgentFromFleetHarnesses() {
  if (isAdminUser() || ownedAgentConfigured() || !Array.isArray(state.userFleetHarnesses)) return;
  const config = state.userFleetHarnesses.map(ownedAgentConfigFromFleetHarness).find(Boolean);
  if (!config) return;
  saveAgentOwnedAgentConfig(config);
}

function userFleetNodeId(node = {}) {
  return cleanText(node?.node_id || node?.nodeId || node?.id, "");
}

function userFleetAgentNodes() {
  if (isAdminUser() || !Array.isArray(state.userFleetNodes)) return [];
  return state.userFleetNodes.filter((node) => {
    const nodeId = userFleetNodeId(node);
    return nodeId && !isGlobalAgentNodeId(nodeId);
  });
}

function agentNodeDisplayLabel(nodeId) {
  const id = cleanText(nodeId, "");
  if (id === AGENT_MASTER_FRONTIER_TARGET_ID) return AGENT_MASTER_FRONTIER_LABEL;
  if (id === AGENT_FRONTIER_NODE_ID) return "frontier";
  if (id === AGENT_SANDBOX_NODE_ID) return "My agent";
  return id;
}

function activeAgentNodeRunConfig(targetNode = agentTargetNode(), chatModel = selectedAgentModel()) {
  const directProviderConfig = agentTargetIsDirectProvider()
    ? activeAgentDirectProviderConfig(state.agentTargetNode)
    : null;
  const harness = userFleetHarnessForNode(targetNode) || (directProviderConfig ? readyHarnessForDirectProvider(directProviderConfig) : null);
  const providerConfig = directProviderConfig || selectedAgentProviderConfig(targetNode) || (harness ? directProviderForHarness(harness) : null);
  const harnessConfig = providerConfig?.agentHarness && typeof providerConfig.agentHarness === "object" ? providerConfig.agentHarness : {};
  const harnessName = cleanText(harnessConfig.name || "", "");
  const name = cleanText(
    harnessName
      || agentHarnessDisplayName(harness || {})
      || providerConfig?.nodeName
      || agentNodeDisplayLabel(targetNode),
    agentNodeDisplayLabel(targetNode)
  );
  const type = cleanText(
    harnessConfig.type
      || harness?.harness_type
      || harness?.harnessType
      || (providerConfig ? "provider-backed" : "hermes"),
    "hermes"
  );
  const instructions = cleanText(
    harnessConfig.instructions
      || harness?.instructions
      || harness?.metadata?.instructions
      || "",
    ""
  );
  const provider = cleanText(chatModel?.provider || providerConfig?.provider || "", "");
  const model = cleanText(chatModel?.id || providerConfig?.model || "", "");
  return {
    node_id: targetNode,
    name,
    type,
    instructions,
    instruction_source: instructions
      ? harnessConfig.instructions ? "browser-local node form" : "account harness metadata"
      : "none",
    config_source: harness ? "account fleet harness" : providerConfig ? "browser-local provider node" : "node runtime",
    provider,
    model,
    provider_model_source: chatModel?.id ? "chat model selector" : providerConfig ? "browser-local provider node" : "node runtime default",
  };
}

function agentModelTargetKey() {
  return agentTargetIsDirectProvider() ? AGENT_PROVIDER_TARGET_ID : agentTargetNode();
}

function agentProviderConfigById(providerId = "") {
  const id = normalizeAgentProviderNodeId(providerId);
  if (!id) return null;
  return (Array.isArray(state.agentDirectProviders) ? state.agentDirectProviders : [])
    .find((config) => normalizeAgentProviderNodeId(config?.id || "") === id) || null;
}

function selectedAgentProviderConfig(targetNode = state.agentTargetNode) {
  if (agentTargetIsDirectProvider(targetNode)) {
    const directConfig = activeAgentDirectProviderConfig(targetNode);
    return directProviderVerified(directConfig) ? directConfig : null;
  }
  const key = cleanText(targetNode, "") || agentTargetNode();
  const preferredId = normalizeAgentProviderNodeId(state.agentModelSettings.providerByNode?.[key] || "");
  const preferred = agentProviderConfigById(preferredId);
  if (preferred && directProviderVerified(preferred)) return preferred;
  const harnessProvider = directProviderForHarness(userFleetHarnessForNode(key) || {});
  if (harnessProvider && directProviderVerified(harnessProvider)) return harnessProvider;
  if (state.agentDirectProvider && directProviderVerified(state.agentDirectProvider)) return state.agentDirectProvider;
  return verifiedAgentProviderConfigs()[0] || null;
}

function persistAgentProviderSelectionForCurrentTarget(config = null) {
  const providerConfig = config || selectedAgentProviderConfig();
  if (!providerConfig) return null;
  const targetLooksDirect = Boolean(providerIdFromTargetValue(state.agentTargetNode) || state.agentTargetNode === AGENT_PROVIDER_TARGET_ID);
  if (agentTargetIsDirectProvider() || targetLooksDirect) {
    state.agentDirectProvider = providerConfig;
    state.agentTargetNode = directProviderTargetValue(providerConfig);
  } else {
    state.agentModelSettings.providerByNode = state.agentModelSettings.providerByNode || {};
    state.agentModelSettings.providerByNode[agentModelTargetKey()] = normalizeAgentProviderNodeId(providerConfig.id || "");
    saveAgentModelSettings();
  }
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
  return providerConfig;
}

function shouldUseDirectAgentProvider(session = activeAgentSession()) {
  const socialChat = session?.kind === "direct" || session?.kind === "shared-space";
  return Boolean(state.authUser && !isAdminUser() && !socialChat && agentTargetIsDirectProvider());
}

function shouldUseOwnedAgentBridge(session = activeAgentSession()) {
  const socialChat = session?.kind === "direct" || session?.kind === "shared-space";
  return Boolean(state.authUser && !socialChat && agentTargetIsOwnedAgent() && state.agentOwnedAgent?.bridgeUrl);
}

function ownedAgentBridgeUrl(config = state.agentOwnedAgent) {
  return normalizeOwnedAgentBridgeUrl(config?.bridgeUrl || "");
}

function ownedAgentBridgeIsPrivateUrl(value = ownedAgentBridgeUrl()) {
  const bridgeUrl = normalizeOwnedAgentBridgeUrl(value);
  if (!bridgeUrl) return false;
  try {
    return isPrivateProviderHostname(new URL(bridgeUrl).hostname);
  } catch {
    return false;
  }
}

function directProviderConfigFingerprint(config = activeAgentDirectProviderConfig()) {
  if (!config) return "";
  const key = String(config.apiKey || "");
  return [
    normalizeDirectProviderBaseUrl(config.baseUrl || ""),
    cleanText(config.model, ""),
    cleanText(config.provider, ""),
    normalizeProviderTransport(config.transport || ""),
    key.length,
    key.slice(0, 4),
    key.slice(-4),
  ].join("|");
}

function directProviderNameFromBaseUrl(baseUrl) {
  const base = cleanText(baseUrl, "").toLowerCase();
  if (!base) return "";
  if (base.includes("perplexity.ai")) return "perplexity";
  if (base.includes("openrouter.ai")) return "openrouter";
  if (base.includes("api.groq.com")) return "groq";
  if (base.includes("moonshot.ai")) return "moonshot";
  if (base.includes("deepseek.com")) return "deepseek";
  if (base.includes("dashscope.aliyuncs.com")) return "dashscope";
  if (base.includes("generativelanguage.googleapis.com")) return "google";
  if (base.includes("api.x.ai")) return "xai";
  if (base.includes("api.mistral.ai")) return "mistral";
  if (base.includes("api.openai.com")) return "openai";
  if (base.includes("opencode.ai/zen/go")) return "opencode-go";
  if (base.includes("opencode.ai/zen")) return "opencode-zen";
  return "";
}

function normalizeDirectProviderBaseUrl(value) {
  const raw = cleanText(value, "").replace(/\/+$/, "");
  if (!raw) return "";
  if (/^https?:\/\//i.test(raw)) return raw;
  return `https://${raw}`;
}

function normalizeDirectProviderModel(model, baseUrl = "", provider = "") {
  const raw = cleanText(model, "");
  if (!raw) return "";
  const providerName = cleanText(provider || directProviderNameFromBaseUrl(baseUrl), "").toLowerCase();
  if ((providerName === "opencode-go" || providerName === "opencode-zen") && raw.includes("/")) {
    const [prefix, rest] = raw.split("/", 2);
    if (prefix === providerName && rest) return raw.slice(prefix.length + 1);
  }
  return raw;
}

function directProviderEndpointForBaseUrl(baseUrl, provider = "") {
  const base = normalizeDirectProviderBaseUrl(baseUrl);
  if (!base) return "";
  let parsed;
  try {
    parsed = new URL(base);
  } catch {
    return "";
  }
  const normalizedPath = parsed.pathname.replace(/\/+$/, "");
  parsed.pathname = normalizedPath || "";
  parsed.search = "";
  parsed.hash = "";
  const cleanBase = parsed.toString().replace(/\/+$/, "");
  if (normalizedPath.endsWith("/chat/completions")) return cleanBase;
  const providerName = cleanText(provider || directProviderNameFromBaseUrl(cleanBase), "");
  if (providerName === "perplexity") return `${cleanBase}/chat/completions`;
  if (normalizedPath.endsWith("/openai") || normalizedPath.endsWith("/v1")) return `${cleanBase}/chat/completions`;
  return `${cleanBase}/v1/chat/completions`;
}

function normalizeProviderTransport(value) {
  const mode = cleanText(value, "").toLowerCase().replace(/_/g, "-");
  if (["direct", "browser", "browser-direct", "client", "client-direct"].includes(mode)) {
    return AGENT_PROVIDER_TRANSPORTS.BROWSER_DIRECT;
  }
  if (["proxy", "server", "backend", "backend-proxy", "server-proxy"].includes(mode)) {
    return AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY;
  }
  return AGENT_PROVIDER_TRANSPORTS.AUTO;
}

function providerTransportPreference(config = {}) {
  return normalizeProviderTransport(config?.transport || config?.provider_transport || config?.transportMode || "");
}

function providerEndpointUrl(config = {}) {
  const endpoint = cleanText(config?.endpoint || directProviderEndpointForBaseUrl(config?.baseUrl || config?.base_url || "", config?.provider || ""), "");
  if (!endpoint) return null;
  try {
    return new URL(endpoint);
  } catch {
    return null;
  }
}

function providerOriginKey(config = {}) {
  return providerEndpointUrl(config)?.origin || "";
}

function rememberProviderProxyOrigin(config = {}) {
  const origin = providerOriginKey(config);
  if (origin) state.agentProviderProxyOrigins.add(origin);
}

function hasProviderProxyOrigin(config = {}) {
  const origin = providerOriginKey(config);
  return Boolean(origin && state.agentProviderProxyOrigins.has(origin));
}

function isPrivateProviderHostname(hostname = "") {
  const host = cleanText(hostname, "").toLowerCase().replace(/^\[|\]$/g, "");
  if (!host) return false;
  if (host === "localhost" || host === "::1" || host.endsWith(".localhost") || host.endsWith(".local") || host.endsWith(".lan")) return true;
  if (/^127\./.test(host) || /^10\./.test(host) || /^192\.168\./.test(host) || /^169\.254\./.test(host)) return true;
  const match172 = host.match(/^172\.(\d+)\./);
  if (match172) {
    const second = Number(match172[1]);
    if (second >= 16 && second <= 31) return true;
  }
  return /^[a-z0-9-]+$/i.test(host);
}

function providerEndpointIsPrivate(config = {}) {
  const url = providerEndpointUrl(config);
  return Boolean(url && isPrivateProviderHostname(url.hostname));
}

function providerHostPrefersProxy(config = {}) {
  const host = providerEndpointUrl(config)?.hostname.toLowerCase() || "";
  if (!host) return false;
  return Array.from(AGENT_PROVIDER_PROXY_FIRST_HOSTS).some((candidate) => host === candidate || host.endsWith(`.${candidate}`));
}

function providerNamePrefersProxy(config = {}) {
  const provider = cleanText(config?.provider || directProviderNameFromBaseUrl(config?.baseUrl || config?.endpoint || ""), "").toLowerCase();
  return AGENT_PROVIDER_PROXY_FIRST_PROVIDERS.has(provider);
}

function providerTransportPlan(config = {}) {
  const preference = providerTransportPreference(config);
  if (preference === AGENT_PROVIDER_TRANSPORTS.BROWSER_DIRECT) {
    return { mode: AGENT_PROVIDER_TRANSPORTS.BROWSER_DIRECT, reason: "explicit-browser-direct" };
  }
  if (preference === AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY) {
    return { mode: AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY, reason: "explicit-backend-proxy" };
  }
  if (hasProviderProxyOrigin(config)) {
    return { mode: AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY, reason: "remembered-cors-origin" };
  }
  if (providerEndpointIsPrivate(config)) {
    return { mode: AGENT_PROVIDER_TRANSPORTS.BROWSER_DIRECT, reason: "private-or-local-endpoint" };
  }
  if (providerNamePrefersProxy(config) || providerHostPrefersProxy(config)) {
    return { mode: AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY, reason: "known-remote-provider" };
  }
  if (isCompactViewport()) {
    return { mode: AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY, reason: "compact-viewport" };
  }
  return { mode: AGENT_PROVIDER_TRANSPORTS.BROWSER_DIRECT, reason: "public-endpoint-probe" };
}

function validateDirectProviderConfig(config = activeAgentDirectProviderConfig()) {
  const normalized = normalizeAgentDirectProviderConfig(config);
  if (!normalized?.provider) return { ok: false, mode: "config-missing", category: "missing-provider", message: "Missing provider." };
  if (!normalized?.baseUrl) return { ok: false, mode: "config-missing", category: "missing-provider-endpoint", message: "Provider endpoint is not configured." };
  let parsed;
  try {
    parsed = new URL(normalized.baseUrl);
  } catch {
    return { ok: false, mode: "config-missing", category: "malformed-provider-endpoint", message: "Provider endpoint is not valid." };
  }
  if (!["http:", "https:"].includes(parsed.protocol) || !parsed.hostname || /\s/.test(normalized.baseUrl)) {
    return { ok: false, mode: "config-missing", category: "malformed-provider-endpoint", message: "Provider endpoint must be HTTP or HTTPS." };
  }
  if (!normalized.model) return { ok: false, mode: "config-missing", category: "missing-model", message: "Missing model." };
  if (!normalized.apiKey) return { ok: false, mode: "config-missing", category: "missing-api-key", message: "Missing API key." };
  const endpoint = directProviderEndpointForBaseUrl(normalized.baseUrl, normalized.provider);
  if (!endpoint) return { ok: false, mode: "config-missing", category: "malformed-provider-endpoint", message: "Provider endpoint could not be built." };
  return { ok: true, config: { ...normalized, endpoint }, fingerprint: directProviderConfigFingerprint(normalized) };
}

function validateAgentHarnessConfig(config = state.nodeFormDraft) {
  const normalized = normalizeAgentDirectProviderConfig(config) || {};
  const harness = normalized.agentHarness && typeof normalized.agentHarness === "object" ? normalized.agentHarness : null;
  if (!harness?.enabled) return { ok: true, harness: null };
  if (!cleanText(harness.name || "", "")) return { ok: false, category: "missing-harness-name", message: "Agent harness name is required." };
  if (normalizeAgentHarnessType(harness.type) !== AGENT_HARNESS_DEFAULT_TYPE) {
    return { ok: false, category: "agent-not-available", message: `${agentHarnessTypeLabel(harness.type)} is not available yet.` };
  }
  const infraMode = normalizeAgentHarnessInfraMode(harness.infraMode);
  if (![AGENT_HARNESS_DEFAULT_INFRA_MODE, AGENT_HARNESS_OWN_INFRA_MODE].includes(infraMode)) {
    return { ok: false, category: "infra-not-available", message: "Infrastructure option not available yet." };
  }
  if (infraMode === AGENT_HARNESS_OWN_INFRA_MODE && !normalizeOwnedAgentBridgeUrl(harness.bridgeUrl || "")) {
    return { ok: false, category: "missing-bridge-url", message: "Private bridge URL is required." };
  }
  return { ok: true, harness: { ...harness, type: AGENT_HARNESS_DEFAULT_TYPE, infraMode } };
}

function nodeFormNeedsDirectProvider(config = state.nodeFormDraft) {
  const harness = config?.agentHarness && typeof config.agentHarness === "object" ? config.agentHarness : null;
  return !harness?.enabled || normalizeAgentHarnessInfraMode(harness.infraMode) === AGENT_HARNESS_DEFAULT_INFRA_MODE;
}

function nodeFormStatusText(config = nodeFormConfigSource()) {
  const harnessValidation = validateAgentHarnessConfig(config);
  if (!harnessValidation.ok) return harnessValidation.message;
  const harness = harnessValidation.harness;
  if (harness?.enabled && harness.infraMode === "hermes_backend") {
    const cost = Number(state.agentCredits?.agent_harness_cost || 10);
    return `Wasm-Agent-Cloud based (${cost}◇)`;
  }
  if (harness?.enabled && harness.infraMode === AGENT_HARNESS_OWN_INFRA_MODE) {
    if (!harness.bridgeUrl) return "Private bridge URL required";
    return ownedAgentBridgeIsPrivateUrl(harness.bridgeUrl) ? "Private bridge / browser probe" : "Private bridge / server probe";
  }
  return directProviderStatusText(config);
}

function agentHarnessProvisionPayload(config = state.nodeFormDraft) {
  const harness = config?.agentHarness || {};
  return {
    idempotency_key: `harness_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`,
    node_name: config?.nodeName || "",
    harness_name: harness.name || "",
    harness_type: normalizeAgentHarnessType(harness.type || AGENT_HARNESS_DEFAULT_TYPE),
    infra_mode: normalizeAgentHarnessInfraMode(harness.infraMode || AGENT_HARNESS_DEFAULT_INFRA_MODE),
    bridge_url: harness.bridgeUrl || "",
    instructions: harness.instructions || "",
    provider_config: {
      base_url: config?.baseUrl || "",
      provider: config?.provider || "",
      model: config?.model || "",
      api_key: config?.apiKey || "",
    },
  };
}

function directProviderGuessFromModel(model) {
  const id = cleanText(model, "").toLowerCase();
  if (!id) return null;
  if (id.startsWith("opencode-go/")) return { baseUrl: "https://opencode.ai/zen/go/v1", provider: "opencode-go" };
  if (id.startsWith("opencode-zen/")) return { baseUrl: "https://opencode.ai/zen/v1", provider: "opencode-zen" };
  if (id === "deepseek-v4-flash") return { baseUrl: "https://opencode.ai/zen/go/v1", provider: "opencode-go" };
  if (id.includes("deepseek")) return { baseUrl: "https://api.deepseek.com/v1", provider: "deepseek" };
  if (id.includes("kimi") || id.includes("moonshot")) return { baseUrl: "https://api.moonshot.ai/v1", provider: "moonshot" };
  if (id.includes("qwen") || id.includes("dashscope")) return { baseUrl: "https://dashscope.aliyuncs.com/compatible-mode/v1", provider: "dashscope" };
  if (id.includes("gemini")) return { baseUrl: "https://generativelanguage.googleapis.com/v1beta/openai", provider: "google" };
  if (id.includes("grok") || id.startsWith("x-ai/")) return { baseUrl: "https://api.x.ai/v1", provider: "xai" };
  if (id.includes("mistral") || id.includes("mixtral")) return { baseUrl: "https://api.mistral.ai/v1", provider: "mistral" };
  if (id.includes("sonar") || id.includes("perplexity")) return { baseUrl: "https://api.perplexity.ai", provider: "perplexity" };
  if (id.includes("llama") || id.includes("meta-llama")) return { baseUrl: "https://openrouter.ai/api/v1", provider: "openrouter" };
  if (id.includes("/") && !id.startsWith("openai/")) return { baseUrl: "https://openrouter.ai/api/v1", provider: "openrouter" };
  if (id.startsWith("gpt-") || id.startsWith("o1") || id.startsWith("o3") || id.startsWith("o4") || id.startsWith("openai/")) {
    return { baseUrl: "https://api.openai.com/v1", provider: "openai" };
  }
  return null;
}

function directProviderGuessFromKey(apiKey) {
  const key = String(apiKey || "").trim();
  if (!key) return null;
  if (key.startsWith("sk-or-")) return { baseUrl: "https://openrouter.ai/api/v1", provider: "openrouter" };
  if (key.startsWith("gsk_")) return { baseUrl: "https://api.groq.com/openai/v1", provider: "groq" };
  if (key.startsWith("AIza")) return { baseUrl: "https://generativelanguage.googleapis.com/v1beta/openai", provider: "google" };
  if (key.startsWith("xai-")) return { baseUrl: "https://api.x.ai/v1", provider: "xai" };
  return null;
}

function inferDirectProviderBaseUrl(model, apiKey) {
  const modelGuess = directProviderGuessFromModel(model);
  const modelId = cleanText(model, "").toLowerCase();
  if (
    modelGuess
    && (
      modelId === "deepseek-v4-flash"
      || (modelGuess.provider && modelId.startsWith(`${modelGuess.provider}/`))
    )
  ) return modelGuess;
  return directProviderGuessFromKey(apiKey) || modelGuess;
}

function directProviderStatusText(configSource = activeAgentDirectProviderConfig()) {
  const validation = validateDirectProviderConfig(configSource);
  const probe = currentAgentProviderProbe(configSource);
  const providerName = normalizeDirectProviderName(configSource?.provider || directProviderNameFromBaseUrl(configSource?.baseUrl || ""));
  const modelStatus = directProviderModelStatus(providerName);
  const providerDefinition = directProviderDefinition(providerName);
  if (providerName && modelStatus.status === "loading") return modelStatus.message || `Loading ${providerDefinition?.label || "provider"} models`;
  if (providerName && modelStatus.status === "error" && !directProviderModelOptions(providerName, configSource?.model || "").length) {
    return modelStatus.message || "Model list unavailable";
  }
  if (probe && directProviderConfigFingerprint(configSource) === directProviderConfigFingerprint(activeAgentDirectProviderConfig())) {
    return `${probe.mode} / ${probe.category}`;
  }
  if (validation.ok) {
    const config = validation.config;
    const plan = providerTransportPlan(config);
    const transport = plan.mode === AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY ? "server proxy" : "browser direct";
    return config.baseUrlInferred ? `Check provider / ${transport} / inferred ${config.provider || "provider"}` : `Check provider / ${transport}`;
  }
  const config = configSource || {};
  const parts = [];
  if (config.model) parts.push("model");
  if (config.apiKey) parts.push("key");
  if (config.provider) parts.push("provider");
  return parts.length ? `Saved ${parts.join(" + ")} / ${validation.category}` : validation.mode;
}

function nodeFormConfigSource() {
  if (state.nodeFormOpen) {
    return state.nodeFormDraft || {};
  }
  return activeAgentDirectProviderConfig() || {};
}

function openNodeForm(mode = "new", providerId = "") {
  const editTarget = providerId
    ? `${AGENT_PROVIDER_TARGET_PREFIX}${encodeURIComponent(providerId)}`
    : state.agentTargetNode;
  const editConfig = activeAgentDirectProviderConfig(editTarget);
  const editing = mode === "edit";
  state.nodeFormMode = editing ? "edit" : "new";
  state.nodeFormDraft = editing ? { ...(editConfig || {}) } : {};
  if (editing && editConfig) state.agentTargetNode = directProviderTargetValue(editConfig);
  state.nodeFormOpen = true;
  state.nodeFormStatus = "";
  state.nodeFormStatusAttention = false;
  state.agentTopicFormOpen = false;
  state.agentTopicDraft = null;
}

function closeNodeForm() {
  state.nodeFormOpen = false;
  state.nodeFormDraft = null;
  state.nodeFormMode = "new";
  state.nodeFormStatus = "";
  state.nodeFormStatusAttention = false;
}

function setNodeFormStatus(message = "", options = {}) {
  state.nodeFormStatus = cleanText(message, "");
  state.nodeFormStatusAttention = Boolean(options.attention && state.nodeFormStatus);
  if (!els.nodeFormStatus) return;
  els.nodeFormStatus.textContent = state.nodeFormStatus;
  const footer = els.nodeFormStatus.closest?.(".node-form-footer");
  if (footer) {
    footer.classList.toggle("is-attention", state.nodeFormStatusAttention);
    if (state.nodeFormStatusAttention) {
      footer.classList.remove("is-shaking");
      void footer.offsetWidth;
      footer.classList.add("is-shaking");
    } else {
      footer.classList.remove("is-shaking");
    }
  }
}

function syncNodeFormDraftFromInputs({ inferBaseUrl = true, render = false } = {}) {
  if (state.nodeFormStatusAttention) setNodeFormStatus("");
  const current = state.nodeFormDraft || (state.nodeFormMode === "edit" ? activeAgentDirectProviderConfig() || {} : {});
  const currentProvider = normalizeDirectProviderName(current.provider || directProviderNameFromBaseUrl(current.baseUrl || ""));
  const provider = normalizeDirectProviderName(els.agentDirectProviderSelect ? els.agentDirectProviderSelect.value : currentProvider) || currentProvider;
  const providerChanged = Boolean(provider && currentProvider && provider !== currentProvider);
  let model = cleanText(els.agentDirectModelInput ? els.agentDirectModelInput.value : current.model || "", "");
  const modelOptions = directProviderModelOptions(provider, providerChanged ? "" : (model || current.model || ""));
  if (providerChanged || !model || !modelOptions.some((option) => option.id === model)) {
    model = modelOptions[0]?.id || "";
  }
  const nodeName = cleanText(els.nodeNameInput ? els.nodeNameInput.value : current.nodeName || "", "");
  const currentHarness = current.agentHarness && typeof current.agentHarness === "object" ? current.agentHarness : {};
  const harnessEnabled = Boolean(els.nodeAgentWrapperToggle?.checked);
  const harnessName = cleanText(els.nodeWrapperNameInput ? els.nodeWrapperNameInput.value : currentHarness.name || "", "");
  const harnessType = normalizeAgentHarnessType(els.nodeWrapperTypeSelect ? els.nodeWrapperTypeSelect.value : currentHarness.type || AGENT_HARNESS_DEFAULT_TYPE);
  const harnessInfraMode = normalizeAgentHarnessInfraMode(els.nodeHarnessInfraSelect ? els.nodeHarnessInfraSelect.value : currentHarness.infraMode || AGENT_HARNESS_DEFAULT_INFRA_MODE);
  const harnessBridgeUrl = cleanText(els.nodeHarnessBridgeUrlInput ? els.nodeHarnessBridgeUrlInput.value : currentHarness.bridgeUrl || "", "");
  const harnessInstructions = cleanText(els.nodeWrapperRoleInput ? els.nodeWrapperRoleInput.value : currentHarness.instructions || "", "");
  const rawKey = String(els.agentDirectApiKeyInput?.value || "").trim();
  const apiKey = rawKey && rawKey !== AGENT_DIRECT_PROVIDER_KEY_MASK ? rawKey : String(current.apiKey || "");
  const baseUrl = directProviderBaseUrlForProvider(provider) || normalizeDirectProviderBaseUrl(current.baseUrl || "");
  const baseUrlInferred = Boolean(provider && baseUrl);
  state.nodeFormDraft = normalizeAgentDirectProviderConfig({
    baseUrl,
    model,
    apiKey,
    provider,
    id: current.id || "",
    nodeName,
    agentHarnessEnabled: harnessEnabled,
    agentHarness: { enabled: harnessEnabled, name: harnessName, type: harnessType, infraMode: harnessInfraMode, bridgeUrl: harnessBridgeUrl, instructions: harnessInstructions },
    baseUrlInferred,
    transport: current.transport || "",
    persistedHarnessId: current.persistedHarnessId || "",
    persistedNodeId: current.persistedNodeId || "",
  }) || {};
  if (!state.nodeFormStatus && els.nodeFormStatus) els.nodeFormStatus.textContent = nodeFormStatusText(state.nodeFormDraft);
  if (render) renderNodesPanel();
  return state.nodeFormDraft;
}

function currentAgentProviderProbe(config = activeAgentDirectProviderConfig()) {
  const probe = state.agentProviderProbe;
  if (!probe || probe.fingerprint !== directProviderConfigFingerprint(config)) return null;
  return probe;
}

function setAgentProviderProbe(probe) {
  state.agentProviderProbe = probe;
  if (!state.nodeFormStatus && els.nodeFormStatus) els.nodeFormStatus.textContent = directProviderStatusText();
  renderAgentReadinessStatus();
}

function directProviderVerificationFields(config = {}, probe = null) {
  const fingerprint = cleanText(probe?.fingerprint || directProviderConfigFingerprint(config), "");
  const checkedAt = Number(probe?.checked_at || Date.now());
  return {
    verified_at: new Date(Number.isFinite(checkedAt) ? checkedAt : Date.now()).toISOString(),
    verified_fingerprint: fingerprint,
    verification: {
      ok: true,
      fingerprint,
      mode: cleanText(probe?.mode || "", ""),
      category: cleanText(probe?.category || "ready", "ready"),
      message: cleanText(probe?.message || "", ""),
      checked_at: checkedAt,
      checked_at_iso: new Date(Number.isFinite(checkedAt) ? checkedAt : Date.now()).toISOString(),
    },
  };
}

function withDirectProviderVerification(config = {}, probe = null) {
  return {
    ...config,
    ...directProviderVerificationFields(config, probe),
  };
}

function directProviderVerified(config = {}) {
  if (!directProviderConfigured(config)) return false;
  const probe = currentAgentProviderProbe(config);
  if (probe?.ok) return true;
  const fingerprint = directProviderConfigFingerprint(config);
  const verifiedFingerprint = cleanText(config.verified_fingerprint || config.verifiedFingerprint || config.verification?.fingerprint || "", "");
  return Boolean(verifiedFingerprint && verifiedFingerprint === fingerprint && cleanText(config.verified_at || config.verification?.checked_at_iso, ""));
}

function verifiedAgentProviderConfigs() {
  return (Array.isArray(state.agentDirectProviders) ? state.agentDirectProviders : [])
    .filter((config) => directProviderConfigured(config) && directProviderVerified(config));
}

function providerSupportsImageContentParts(config = activeAgentDirectProviderConfig()) {
  const provider = cleanText(config?.provider || "", "").toLowerCase();
  const endpointProvider = directProviderNameFromBaseUrl(config?.endpoint || config?.baseUrl || "");
  const hostProvider = directProviderNameFromBaseUrl(config?.baseUrl || config?.endpoint || "");
  return provider === "openrouter" || endpointProvider === "openrouter" || hostProvider === "openrouter";
}

function providerImageContentParts(entries = []) {
  const parts = [];
  let totalChars = 0;
  for (const entry of Array.isArray(entries) ? entries : []) {
    const url = String(entry?.data_url || "").trim();
    if (!/^data:image\/(png|jpe?g|webp|gif);base64,/i.test(url)) continue;
    if (url.length > AGENT_PROVIDER_IMAGE_PART_MAX_CHARS) continue;
    if (totalChars + url.length > AGENT_PROVIDER_IMAGE_PART_TOTAL_MAX_CHARS) break;
    totalChars += url.length;
    parts.push({
      type: "image_url",
      image_url: { url },
    });
    if (parts.length >= AGENT_MAX_IMAGES) break;
  }
  return parts;
}

function providerVideoContentParts(entries = []) {
  const parts = [];
  for (const entry of Array.isArray(entries) ? entries : []) {
    const url = String(entry?.data_url || "").trim();
    if (!/^data:video\/(mp4|mpeg|quicktime|webm);base64,/i.test(url)) continue;
    if (url.length > AGENT_PROVIDER_VIDEO_PART_MAX_CHARS) continue;
    parts.push({
      type: "video_url",
      videoUrl: { url },
    });
    break;
  }
  return parts;
}

function providerMessagesHaveImageContent(messages = []) {
  return (Array.isArray(messages) ? messages : []).some((message) => (
    Array.isArray(message?.content)
    && message.content.some((part) => part?.type === "image_url" || part?.type === "video_url")
  ));
}

function providerShouldRetryWithoutImage(error) {
  const diagnostic = providerDiagnosticFromError(error);
  const category = cleanText(diagnostic?.category, "");
  const message = cleanText(diagnostic?.message || error?.message, "");
  return category === "request-shape-error" || /image|video|vision|multimodal|content\s*part|image_url|video_url/i.test(message);
}

function providerRequestMessages(message, transcript = [], imageEntries = []) {
  const providerConfig = activeAgentDirectProviderConfig();
  const harness = providerConfig?.agentHarness && typeof providerConfig.agentHarness === "object"
    ? providerConfig.agentHarness
    : null;
  const harnessLines = harness?.enabled ? [
    `Agent harness: ${agentHarnessTypeLabel(harness.type)}`,
    cleanText(harness.name || "", "") ? `Name: ${cleanText(harness.name, "")}` : "",
    cleanText(harness.instructions || "", "") ? `Instructions:\n${cleanText(harness.instructions, "")}` : "",
  ].filter(Boolean) : [];
  const mediaParts = [
    ...providerImageContentParts(imageEntries),
    ...providerVideoContentParts(imageEntries),
  ];
  const text = mediaParts.length
    ? `${message}\n\nRaw media parts are attached in this same user message. If the selected model supports vision/video input, analyze those raw parts directly and use the manifest only as supplemental metadata.`
    : message;
  const userContent = mediaParts.length
    ? [{ type: "text", text }, ...mediaParts]
    : message;
  return [
    {
      role: "system",
      content: [
        "You are a browser/provider-backed chat model in wasm-agent. Answer directly. Backend source-file tools are unavailable on this path, but validated WIS/userland artifact patches can be applied by the client.",
        "Default to English unless the latest user message explicitly asks for another language.",
        harnessLines.length ? `Act through this optional node agent harness:\n${harnessLines.join("\n")}` : "",
        wisPatchClientSystemHint(),
        agentCapabilitySystemHint(),
      ].filter(Boolean).join("\n"),
    },
    ...transcript.slice(-8).map((item) => ({
      role: item.role === "assistant" ? "assistant" : "user",
      content: cleanText(item.content, ""),
    })).filter((item) => item.content),
    { role: "user", content: userContent },
  ];
}

function providerRequestBody(config, messages) {
  return {
    model: cleanText(config?.model, ""),
    stream: false,
    messages: Array.isArray(messages) ? messages : [],
  };
}

function directProviderProbeMessages() {
  return [
    { role: "system", content: "Reply with exactly: wasm-agent-provider-ok" },
    { role: "user", content: "Reply with exactly: wasm-agent-provider-ok" },
  ];
}

function providerDiagnosticFromHttp(status, message = "") {
  if (status === 403 && /cloudflare|browser_signature|site owner has blocked/i.test(message)) {
    return { mode: "unreachable", category: "provider-access-denied", message: message || "Provider edge rejected the request." };
  }
  if (status === 401 || status === 403) return { mode: "auth-failed", category: "auth-failed", message: message || "Provider rejected the API key." };
  if (status === 404) return { mode: "model-failed", category: "model-not-found", message: message || "Provider could not find that model or endpoint." };
  if (status === 400 || status === 422) return { mode: "unreachable", category: "request-shape-error", message: message || "Provider rejected the request shape." };
  if (status >= 500) return { mode: "unreachable", category: "provider-unavailable", message: message || `Provider returned HTTP ${status}.` };
  return { mode: "unreachable", category: "http-error", message: message || `Provider returned HTTP ${status}.` };
}

function providerErrorMessage(payload, fallback = "") {
  const error = payload?.error;
  if (typeof error === "string") return error;
  if (error && typeof error === "object") return cleanText(error.message || error.code || fallback, fallback);
  return fallback;
}

function classifyBrowserProviderError(error) {
  if (error?.diagnostic) return error.diagnostic;
  const message = cleanText(error?.message, "Provider request failed.");
  if (error?.status) return providerDiagnosticFromHttp(Number(error.status), message);
  if (error?.name === "AbortError") {
    return { mode: "unreachable", category: navigator.onLine === false ? "network-offline" : "network-timeout", message: "Provider request timed out." };
  }
  if (/failed to fetch|networkerror|load failed|fetch failed/i.test(message)) {
    if (navigator.onLine === false) {
      return { mode: "unreachable", category: "network-offline", message: "This browser appears offline." };
    }
    return {
      mode: "cors-blocked",
      category: "cors-blocked",
      message: "This provider is reachable only through a server/proxy because the browser is blocked by CORS.",
    };
  }
  return { mode: "unreachable", category: "network-failed", message };
}

function providerDiagnosticFromError(error) {
  if (error?.diagnostic) return error.diagnostic;
  const providerPayload = error?.payload?.provider || error?.payload || null;
  if (providerPayload?.diagnostic) return providerPayload.diagnostic;
  return classifyBrowserProviderError(error);
}

function parseProviderChatPayload(payload, config, mode) {
  const choice = Array.isArray(payload?.choices) ? payload.choices[0] : null;
  const content = choice?.message?.content || choice?.delta?.content || choice?.text || "";
  return {
    reply: cleanText(content, "The provider returned an empty response."),
    usage: payload?.usage || null,
    model: payload?.model || config?.model || "",
    mode,
    raw: payload,
  };
}

async function requestBrowserDirectProvider(config, messages, options = {}) {
  const endpoint = directProviderEndpointForBaseUrl(config.baseUrl, config.provider);
  const response = await fetch(endpoint, {
    method: "POST",
    cache: "no-store",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${config.apiKey}`,
    },
    body: JSON.stringify(providerRequestBody(config, messages)),
    signal: options.signal,
  });
  const text = await response.text();
  let payload = {};
  try {
    payload = text ? JSON.parse(text) : {};
  } catch {
    payload = {};
  }
  if (!response.ok) {
    const diagnostic = providerDiagnosticFromHttp(response.status, providerErrorMessage(payload, text.slice(0, 240)));
    const error = new Error(diagnostic.message);
    error.status = response.status;
    error.payload = payload;
    error.diagnostic = diagnostic;
    throw error;
  }
  return parseProviderChatPayload(payload, config, "browser-direct");
}

async function requestBackendProvider(config, messages, { probe = false } = {}) {
  const payload = await fetchJson(probe ? "/agent/provider/probe" : "/agent/provider/chat", {
    method: "POST",
    timeoutMs: probe ? 45000 : state.agentTurnTimeoutMs,
    body: {
      provider_config: {
        base_url: config.baseUrl,
        model: config.model,
        api_key: config.apiKey,
        provider: config.provider || "",
      },
      messages,
    },
  });
  if (probe) return payload.provider || payload;
  return {
    reply: payload.reply || payload.provider?.reply || "The backend provider proxy returned an empty response.",
    usage: payload.usage || payload.provider?.usage || null,
    model: payload.model || payload.provider?.model || config.model,
    mode: "backend-proxy",
    raw: payload.provider || payload,
  };
}

function debugProviderLog(label, detail = {}) {
  try {
    if (localStorage.getItem("wasmAgent.debugProvider") !== "1") return;
    const safe = { ...detail };
    if (safe.apiKey) delete safe.apiKey;
    console.groupCollapsed(`[wasm-agent provider] ${label}`);
    console.log(safe);
    console.groupEnd();
  } catch {
    // Debug logging is optional.
  }
}

async function probeAgentProviderConnectivity({ allowProxy = true, force = false, config: configSource = activeAgentDirectProviderConfig() } = {}) {
  const validation = validateDirectProviderConfig(configSource);
  if (!validation.ok) {
    const probe = {
      ok: false,
      fingerprint: directProviderConfigFingerprint(configSource),
      mode: validation.mode,
      category: validation.category,
      message: validation.message,
      checked_at: Date.now(),
    };
    setAgentProviderProbe(probe);
    return probe;
  }
  const current = currentAgentProviderProbe(configSource);
  if (!force && current && Date.now() - Number(current.checked_at || 0) < AGENT_PROVIDER_PROBE_TTL_MS) return current;
  const config = validation.config;
  const fingerprint = validation.fingerprint;
  state.agentProviderProbeBusy = true;
  setAgentProviderProbe({
    ok: false,
    fingerprint,
    mode: "checking",
    category: "checking",
    message: "Checking provider connectivity.",
    checked_at: Date.now(),
  });
  const messages = directProviderProbeMessages();
  const transportPlan = providerTransportPlan(config);
  debugProviderLog("probe", { endpoint: config.endpoint, model: config.model, provider: config.provider || "", transport: transportPlan.mode, reason: transportPlan.reason });
  if (transportPlan.mode === AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY) {
    try {
      const backend = await requestBackendProvider(config, messages, { probe: true });
      const probe = {
        ok: true,
        fingerprint,
        mode: AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY,
        category: "ready",
        message: "Backend proxy provider request succeeded.",
        endpoint: backend.endpoint || config.endpoint,
        model: backend.model || config.model,
        transport_reason: transportPlan.reason,
        checked_at: Date.now(),
      };
      setAgentProviderProbe(probe);
      return probe;
    } catch (proxyError) {
      const proxyPayload = proxyError?.payload?.provider || proxyError?.payload;
      const proxyDiagnostic = proxyPayload?.diagnostic || providerDiagnosticFromError(proxyError);
      const probe = {
        ok: false,
        fingerprint,
        mode: proxyDiagnostic.mode || "unreachable",
        category: proxyDiagnostic.category || "backend-proxy-failed",
        message: proxyDiagnostic.message || proxyError.message,
        endpoint: config.endpoint,
        model: config.model,
        transport_reason: transportPlan.reason,
        checked_at: Date.now(),
      };
      setAgentProviderProbe(probe);
      return probe;
    } finally {
      state.agentProviderProbeBusy = false;
      renderAgentReadinessStatus();
    }
  }
  try {
    await requestBrowserDirectProvider(config, messages);
    const probe = {
      ok: true,
      fingerprint,
      mode: AGENT_PROVIDER_TRANSPORTS.BROWSER_DIRECT,
      category: "ready",
      message: "Browser direct provider request succeeded.",
      endpoint: config.endpoint,
      model: config.model,
      transport_reason: transportPlan.reason,
      checked_at: Date.now(),
    };
    setAgentProviderProbe(probe);
    return probe;
  } catch (error) {
    const directDiagnostic = classifyBrowserProviderError(error);
    if (!allowProxy || directDiagnostic.mode !== "cors-blocked") {
      const probe = { ok: false, fingerprint, ...directDiagnostic, endpoint: config.endpoint, model: config.model, transport_reason: transportPlan.reason, checked_at: Date.now() };
      setAgentProviderProbe(probe);
      return probe;
    }
    rememberProviderProxyOrigin(config);
    try {
      const backend = await requestBackendProvider(config, messages, { probe: true });
      const probe = {
        ok: true,
        fingerprint,
        mode: AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY,
        category: "ready",
        message: "Browser direct was blocked by CORS; backend proxy provider request succeeded.",
        endpoint: backend.endpoint || config.endpoint,
        model: backend.model || config.model,
        direct_error: directDiagnostic,
        transport_reason: "cors-fallback",
        checked_at: Date.now(),
      };
      setAgentProviderProbe(probe);
      return probe;
    } catch (proxyError) {
      const proxyPayload = proxyError?.payload?.provider || proxyError?.payload;
      const proxyDiagnostic = proxyPayload?.diagnostic || providerDiagnosticFromError(proxyError);
      const probe = {
        ok: false,
        fingerprint,
        mode: proxyDiagnostic.mode || "unreachable",
        category: proxyDiagnostic.category || "backend-proxy-failed",
        message: proxyDiagnostic.message || proxyError.message,
        endpoint: config.endpoint,
        model: config.model,
        direct_error: directDiagnostic,
        transport_reason: "cors-fallback",
        checked_at: Date.now(),
      };
      setAgentProviderProbe(probe);
      return probe;
    }
  } finally {
    state.agentProviderProbeBusy = false;
    renderAgentReadinessStatus();
  }
}

async function ensureAgentProviderConnection() {
  const probe = await probeAgentProviderConnectivity({ allowProxy: true });
  if (!probe.ok) {
    const error = new Error(probe.message || "Provider is not reachable.");
    error.diagnostic = probe;
    throw error;
  }
  return probe;
}

function activeAgentSession() {
  let session = state.agentSessions.find((item) => item.id === state.activeAgentSessionId);
  if (!session) {
    session = state.agentSessions[0] || createAgentSession("Main session");
    if (!state.agentSessions.length) state.agentSessions.push(session);
    state.activeAgentSessionId = session.id;
  }
  return session;
}

function isGlobalAgentNodeId(nodeId) {
  return GLOBAL_AGENT_NODE_IDS.has(cleanText(nodeId, "").toLowerCase());
}

function defaultAgentTargetNode() {
  return AGENT_FRONTIER_NODE_ID;
}

function readAgentTargetNodeSessionPreference() {
  try {
    return cleanText(window.sessionStorage?.getItem(AGENT_TARGET_NODE_SESSION_STORAGE_KEY) || "", "");
  } catch {
    return "";
  }
}

function saveAgentTargetNodeSessionPreference(nodeId = state.agentTargetNode) {
  try {
    const value = cleanText(nodeId, "");
    if (value) window.sessionStorage?.setItem(AGENT_TARGET_NODE_SESSION_STORAGE_KEY, value);
    else window.sessionStorage?.removeItem(AGENT_TARGET_NODE_SESSION_STORAGE_KEY);
  } catch {
    // Session node preference is UI convenience state; default routing still works.
  }
}

function commitAgentTargetNode(nodeId) {
  state.agentTargetNode = cleanText(nodeId, defaultAgentTargetNode());
  saveAgentTargetNodeSessionPreference(state.agentTargetNode);
  return state.agentTargetNode;
}

function agentMissingTargetValue(nodeId) {
  return `${AGENT_MISSING_TARGET_PREFIX}${encodeURIComponent(cleanText(nodeId, ""))}`;
}

function agentMissingTargetNodeId(value) {
  const raw = cleanText(value, "");
  if (!raw.startsWith(AGENT_MISSING_TARGET_PREFIX)) return "";
  try {
    return cleanText(decodeURIComponent(raw.slice(AGENT_MISSING_TARGET_PREFIX.length)), "");
  } catch {
    return "";
  }
}

function agentTargetIsMissing(value = state.agentTargetNode) {
  return cleanText(value, "").startsWith(AGENT_MISSING_TARGET_PREFIX);
}

function agentTargetNode() {
  const fallback = defaultAgentTargetNode();
  const target = cleanText(state.agentTargetNode || state.selectedNode || fallback, fallback);
  if (agentTargetIsMissing(target)) return agentMissingTargetNodeId(target) || fallback;
  if (agentTargetIsMasterFrontier(target)) return AGENT_FRONTIER_NODE_ID;
  if (
    target === AGENT_PROVIDER_TARGET_ID
    || target.startsWith(AGENT_PROVIDER_TARGET_PREFIX)
    || target === AGENT_SET_PROVIDER_TARGET_ID
    || target === AGENT_SET_HERMES_TARGET_ID
    || target === AGENT_NONE_TARGET_ID
    || target === AGENT_NEW_CONFIG_TARGET_ID
    || target === AGENT_EDIT_CONFIG_TARGET_ID
    || target === AGENT_OWNED_AGENT_TARGET_ID
    || target === AGENT_MASTER_FRONTIER_TARGET_ID
    || agentTargetIsAgentModel(target)
  ) return fallback;
  return !isAdminUser() && isGlobalAgentNodeId(target) ? AGENT_SANDBOX_NODE_ID : target;
}

function availableAgentNodes() {
  const fleetNodes = userFleetAgentNodes();
  const readyHarnesses = readyUserFleetHarnesses();
  const ids = new Set(fleetNodes.length || readyHarnesses.length ? [] : [defaultAgentTargetNode()]);
  if (state.selectedNode && (isAdminUser() || !isGlobalAgentNodeId(state.selectedNode))) ids.add(state.selectedNode);
  fleetNodes.forEach((node) => ids.add(userFleetNodeId(node)));
  readyHarnesses.forEach((harness) => ids.add(agentHarnessNodeId(harness)));
  state.nodes.forEach((node) => {
    if (node.id && (isAdminUser() || !isGlobalAgentNodeId(node.id))) ids.add(node.id);
  });
  return Array.from(ids);
}

function agentModelForNodeOption(nodeId) {
  const selected = normalizeAgentModelEntry(state.agentModelSettings.selectedByNode?.[nodeId]);
  return selected || agentDefaultModelForNode(nodeId);
}

function configuredAgentTargetOptions() {
  const options = [];
  const listedModelKeys = new Set();
  const readyHarnesses = readyUserFleetHarnesses();
  const pushOption = (option) => {
    if (!option?.value || options.some((item) => item.value === option.value)) return;
    options.push(option);
    agentModelKeys(option.model).forEach((key) => listedModelKeys.add(key));
  };
  const pushHarnessOption = (harness) => {
    const lifecycle = agentHarnessLifecycleState(harness);
    const nodeId = agentHarnessNodeId(harness);
    const value = lifecycle === "ready" && nodeId ? nodeId : `harness:${cleanText(harness.id, "")}`;
    if (!value) return;
    const providerConfig = selectedAgentProviderConfig(nodeId) || directProviderForHarness(harness);
    const selectedModel = normalizeAgentModelEntry(state.agentModelSettings.selectedByNode?.[nodeId]);
    const model = selectedModel || normalizeAgentModelEntry({
      id: providerConfig?.model || "",
      provider: providerConfig?.provider || "",
    });
    pushOption({
      value,
      kind: "harness",
      label: lifecycle === "ready"
        ? agentRuntimeOptionLabel({
            mode: "Hermes",
            name: agentHarnessDisplayName(harness),
            provider: model?.provider || providerConfig?.provider || "hermes",
            model: model?.id || providerConfig?.model || "default",
          })
        : `Hermes:${agentHarnessDisplayName(harness)}`,
      detail: lifecycle === "ready" ? cleanDisplayNodeId(nodeId) : agentReadinessPanelMessage({ status: lifecycle }),
      nodeId,
      lifecycle,
      model,
    });
  };
  if (isAdminUser()) {
    const providerConfig = activeAgentDirectProviderConfig() || {};
    pushOption({
      value: AGENT_MASTER_FRONTIER_TARGET_ID,
      kind: "master-frontier",
      label: AGENT_MASTER_FRONTIER_LABEL,
      detail: "direct-head",
      nodeId: AGENT_FRONTIER_NODE_ID,
      model: normalizeAgentModelEntry({
        id: providerConfig?.model || "",
        provider: providerConfig?.provider || "",
        label: providerConfig?.model ? `${providerConfig?.provider || "provider"}:${providerConfig.model}` : "direct-head",
      }),
    });
  }
  readyHarnesses.forEach(pushHarnessOption);
  userFleetAgentNodes().forEach((node) => {
    const nodeId = userFleetNodeId(node);
    pushOption({
      value: nodeId,
      kind: "agent",
      label: agentRuntimeOptionLabel({
        mode: "Hermes",
        name: agentNodeDisplayLabel(nodeId),
        provider: agentModelForNodeOption(nodeId)?.provider || "hermes",
        model: agentModelForNodeOption(nodeId)?.id || "default",
      }),
      detail: cleanDisplayNodeId(nodeId),
      nodeId,
    });
  });
  if (!isAdminUser() && Array.isArray(state.agentDirectProviders)) {
    verifiedAgentProviderConfigs().forEach((config) => {
      if (readyHarnessForDirectProvider(config, readyHarnesses)) return;
      pushOption({
        value: directProviderTargetValue(config),
        kind: "node",
        label: agentRuntimeOptionLabel({
          mode: "Direct",
          name: agentProviderNodeLabel(config),
          provider: config?.provider || "provider",
          model: config?.model || "",
        }),
        detail: cleanDisplayNodeId(config?.persistedNodeId || config?.id || ""),
        model: normalizeAgentModelEntry({
          id: config?.model || "",
          provider: config?.provider || "",
        }),
      });
    });
  }
  if (!isAdminUser() && Array.isArray(state.userFleetHarnesses)) {
    state.userFleetHarnesses.forEach((harness) => {
      if (agentHarnessLifecycleState(harness) === "ready" && agentHarnessNodeId(harness)) return;
      pushHarnessOption(harness);
    });
  }
  if (!isAdminUser() && ownedAgentConfigured()) {
    pushOption({
      value: AGENT_OWNED_AGENT_TARGET_ID,
      kind: "owned-agent",
      label: `agent:${state.agentOwnedAgent?.name || "My agent"}`,
      detail: state.agentOwnedAgent?.bridgeUrl ? "own bridge" : "Hermes service",
      model: normalizeAgentModelEntry({
        id: state.agentOwnedAgent?.type || "hermes",
        provider: state.agentOwnedAgent?.service || "hermes-orchestrator",
        label: state.agentOwnedAgent?.name || "My agent",
      }),
    });
  }
  const readinessReady = Boolean(state.agentReadiness?.ready || state.agentReadiness?.status === "ready");
  const agentSelectable = isAdminUser() || readinessReady;
  availableAgentNodes().forEach((nodeId) => {
    if (!agentSelectable) return;
    const model = agentModelForNodeOption(nodeId);
    pushOption({
      value: nodeId,
      kind: "agent",
      label: agentRuntimeOptionLabel({
        mode: "Hermes",
        name: agentNodeDisplayLabel(nodeId),
        provider: model?.provider || "hermes",
        model: model?.id || model?.label || "default",
      }),
      detail: cleanDisplayNodeId(nodeId),
      model,
      nodeId,
    });
  });
  if (!agentSelectable || !isAdminUser()) return options;
  const modelTargetNode = agentTargetNode();
  agentModelCatalog().forEach((model) => {
    const normalized = normalizeAgentModelEntry(model);
    const keys = agentModelKeys(normalized);
    if (!keys.length || keys.some((key) => listedModelKeys.has(key))) return;
    const value = agentModelTargetValue(normalized);
    const label = providerModelDisplayLabel(normalized) || normalized?.label || normalized?.id;
    if (!value || !label) return;
    pushOption({
      value,
      kind: "agent-model",
      label: `model:${label}`,
      detail: `provider metadata for ${agentNodeDisplayLabel(modelTargetNode)}`,
      model: normalized,
      nodeId: modelTargetNode,
    });
  });
  return options;
}

function agentNodeSelectOptions() {
  const configured = configuredAgentTargetOptions();
  const options = [...configured];
  const savedTarget = readAgentTargetNodeSessionPreference();
  if (savedTarget && !options.some((option) => option.value === savedTarget)) {
    options.unshift({
      value: agentMissingTargetValue(savedTarget),
      label: AGENT_MISSING_TARGET_LABEL,
      detail: cleanDisplayNodeId(savedTarget),
      kind: "missing",
      nodeId: savedTarget,
    });
  }
  if (!configured.length && !isAdminUser()) options.push({ value: AGENT_NONE_TARGET_ID, label: "None", kind: "empty" });
  options.push({
    value: configured.length ? AGENT_EDIT_CONFIG_TARGET_ID : AGENT_NEW_CONFIG_TARGET_ID,
    label: configured.length ? "> Edit..." : "> New...",
    kind: "setup",
  });
  return options;
}

function agentNodeSelectDiagnostic() {
  const configured = configuredAgentTargetOptions();
  const options = agentNodeSelectOptions();
  const selectedValue = cleanText(els.agentNodeSelect?.value || state.agentTargetNode, "");
  const kindCounts = options.reduce((counts, option) => {
    const kind = cleanText(option.kind || "agent", "agent");
    counts[kind] = (counts[kind] || 0) + 1;
    return counts;
  }, {});
  return {
    schema: "hermes.wasm_agent.agent_node_select.diagnostic.v1",
    platform: isWindowsNativeShellHost() ? "windows-native" : isAndroidNativeShell() ? "android-native" : "web",
    native: {
      windows: isWindowsNativeShellHost(),
      android: isAndroidNativeShell(),
    },
    authenticated: Boolean(state.authUser),
    role: cleanText(state.authUser?.role || "", ""),
    is_admin: isAdminUser(),
    selected_value: selectedValue,
    resolved_target_node: agentTargetNode(),
    configured_count: configured.length,
    option_count: options.length,
    option_kinds: kindCounts,
    direct_provider_count: Array.isArray(state.agentDirectProviders) ? state.agentDirectProviders.length : 0,
    verified_direct_provider_count: verifiedAgentProviderConfigs().length,
    provider_storage_scope: "browser-local",
    master_frontier_present: options.some((option) => option.value === AGENT_MASTER_FRONTIER_TARGET_ID),
    master_frontier_selected: selectedValue === AGENT_MASTER_FRONTIER_TARGET_ID,
    options: options.slice(0, 40).map((option) => ({
      value: cleanText(option.value, ""),
      kind: cleanText(option.kind || "agent", "agent"),
      label: cleanText(option.label || option.value, ""),
      detail: cleanText(option.detail || option.nodeId || "", ""),
    })),
  };
}

function preferredAgentNodeSelectValue(options = agentNodeSelectOptions()) {
  const values = new Set(options.map((option) => option.value));
  const savedTarget = readAgentTargetNodeSessionPreference();
  if (savedTarget && values.has(savedTarget)) return savedTarget;
  const missingSavedTarget = savedTarget ? agentMissingTargetValue(savedTarget) : "";
  if (missingSavedTarget && values.has(missingSavedTarget)) return missingSavedTarget;
  const raw = cleanText(state.agentTargetNode, "");
  const readyHarness = options.find((option) => option.kind === "harness" && option.lifecycle === "ready" && option.nodeId && option.value === option.nodeId);
  const rawIsDirectProvider = raw === AGENT_PROVIDER_TARGET_ID || raw.startsWith(AGENT_PROVIDER_TARGET_PREFIX);
  const rawIsDefaultSandbox = raw === defaultAgentTargetNode();
  const rawDirectProviderHarness = rawIsDirectProvider ? readyHarnessForDirectProvider(activeAgentDirectProviderConfig(raw)) : null;
  const rawDirectProviderHarnessNode = agentHarnessNodeId(rawDirectProviderHarness);
  if (readyHarness && (!raw || rawIsDefaultSandbox || raw.startsWith("harness:") || (rawIsDirectProvider && (!values.has(raw) || rawDirectProviderHarness)))) {
    return rawDirectProviderHarnessNode && values.has(rawDirectProviderHarnessNode) ? rawDirectProviderHarnessNode : readyHarness.value;
  }
  const readinessReady = Boolean(state.agentReadiness?.ready || state.agentReadiness?.status === "ready");
  const readinessTarget = readinessReady ? cleanText(state.agentReadiness?.target_node, "") : "";
  if (readinessTarget && values.has(readinessTarget) && (!raw || rawIsDirectProvider || rawIsDefaultSandbox || !values.has(raw))) return readinessTarget;
  if (
    raw
    && values.has(raw)
    && raw !== AGENT_SET_PROVIDER_TARGET_ID
    && raw !== AGENT_SET_HERMES_TARGET_ID
    && raw !== AGENT_NEW_CONFIG_TARGET_ID
    && raw !== AGENT_EDIT_CONFIG_TARGET_ID
  ) return raw;
  if (values.has(AGENT_NONE_TARGET_ID)) return AGENT_NONE_TARGET_ID;
  if (!isAdminUser() && hasDirectProviderConfigured() && state.agentReadiness?.status !== "ready") {
    return directProviderTargetValue(activeAgentDirectProviderConfig() || state.agentDirectProviders[0]);
  }
  return values.has(agentTargetNode()) ? agentTargetNode() : options[0]?.value || defaultAgentTargetNode();
}

function renderAgentNodeSelect() {
  if (!els.agentNodeSelect) return;
  const options = agentNodeSelectOptions();
  const current = preferredAgentNodeSelectValue(options);
  state.agentTargetNode = current;
  if (current === AGENT_PROVIDER_TARGET_ID || current.startsWith(AGENT_PROVIDER_TARGET_PREFIX)) {
    state.agentDirectProvider = activeAgentDirectProviderConfig(current) || state.agentDirectProvider;
  }
  els.agentNodeSelect.replaceChildren(
    ...options.map((item) => {
      const option = document.createElement("option");
      option.value = item.value;
      option.textContent = item.label;
      const meta = cleanText(item.detail || item.nodeId || "", "");
      if (meta) option.dataset.meta = meta;
      return option;
    })
  );
  els.agentNodeSelect.value = current;
  els.agentNodeSelect.title = options.find((item) => item.value === current)?.label || current;
}

function setAgentTargetNode(nodeId) {
  const requested = cleanText(nodeId, defaultAgentTargetNode());
  if (agentTargetIsMissing(requested)) {
    renderAgentNodeSelect();
    return;
  }
  if (requested === AGENT_NONE_TARGET_ID) {
    const previous = state.agentTargetNode;
    commitAgentTargetNode(AGENT_NONE_TARGET_ID);
    closeNodeForm();
    closeAgentModelSetup();
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    if (previous !== AGENT_NONE_TARGET_ID) {
      recordUserEvent("agent.target_node_selected", {
        target: "agent-setup",
        summary: "Chat target changed to None",
        data: { node_id: AGENT_NONE_TARGET_ID, previous_node_id: previous || "" },
      });
    }
    return;
  }
  if (requested === AGENT_NEW_CONFIG_TARGET_ID) {
    openAgentSetupBalloon({
      mode: "provider",
      message: "Edit, add, or delete configured nodes.",
      openProviderForm: true,
      providerFormMode: "new",
    });
    renderAgentNodeSelect();
    return;
  }
  if (requested === AGENT_EDIT_CONFIG_TARGET_ID) {
    openAgentSetupBalloon({
      mode: hasDirectProviderConfigured() ? "provider" : "agent",
      message: "Edit, add, or delete configured nodes.",
      openProviderForm: false,
      providerFormMode: "edit",
    });
    renderAgentNodeSelect();
    return;
  }
  if (requested.startsWith("harness:")) {
    const harness = state.userFleetHarnesses.find((item) => `harness:${cleanText(item.id, "")}` === requested);
    state.agentSetupBalloonOpen = true;
    state.agentSetupMode = "provider";
    state.nodesPanelStatus = agentReadinessPanelMessage({ status: harness?.lifecycle_state || "failed" });
    openNodeForm("new");
    renderAgentNodeSelect();
    renderNodesPanel();
    return;
  }
  if (requested === AGENT_MASTER_FRONTIER_TARGET_ID && isAdminUser()) {
    const previous = state.agentTargetNode;
    commitAgentTargetNode(AGENT_MASTER_FRONTIER_TARGET_ID);
    closeNodeForm();
    closeAgentModelSetup();
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    if (previous !== AGENT_MASTER_FRONTIER_TARGET_ID) {
      recordUserEvent("agent.target_node_selected", {
        target: "master-frontier",
        summary: `Chat target changed to ${AGENT_MASTER_FRONTIER_LABEL}`,
        data: { node_id: AGENT_MASTER_FRONTIER_TARGET_ID, target_node: AGENT_FRONTIER_NODE_ID, previous_node_id: previous || "" },
      });
    }
    return;
  }
  const requestedProvider = activeAgentDirectProviderConfig(requested);
  if ((requested === AGENT_PROVIDER_TARGET_ID || requested.startsWith(AGENT_PROVIDER_TARGET_PREFIX)) && directProviderConfigured(requestedProvider)) {
    const previous = state.agentTargetNode;
    state.agentDirectProvider = requestedProvider;
    commitAgentTargetNode(directProviderTargetValue(requestedProvider));
    closeNodeForm();
    closeAgentModelSetup();
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    if (previous !== state.agentTargetNode) {
      recordUserEvent("agent.target_node_selected", {
        target: "provider-api",
        summary: `Chat target changed to ${agentProviderNodeLabel(requestedProvider)}`,
        data: { node_id: state.agentTargetNode, previous_node_id: previous || "" },
      });
    }
    return;
  }
  if (requested === AGENT_OWNED_AGENT_TARGET_ID && ownedAgentConfigured()) {
    const previous = state.agentTargetNode;
    commitAgentTargetNode(AGENT_OWNED_AGENT_TARGET_ID);
    closeNodeForm();
    closeAgentModelSetup();
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    if (previous !== AGENT_OWNED_AGENT_TARGET_ID) {
      recordUserEvent("agent.target_node_selected", {
        target: "owned-agent",
        summary: `Chat target changed to ${state.agentOwnedAgent?.name || "owned agent"}`,
        data: { node_id: AGENT_OWNED_AGENT_TARGET_ID, previous_node_id: previous || "" },
      });
    }
    return;
  }
  if (agentTargetIsAgentModel(requested)) {
    const model = agentModelFromTargetValue(requested);
    if (!model) {
      renderAgentNodeSelect();
      return;
    }
    const previous = state.agentTargetNode;
    const targetNode = agentTargetNode();
    state.agentTargetNode = targetNode;
    applyAgentModelToTarget(model);
    persistAgentModelSelection();
    commitAgentTargetNode(agentModelTargetValue(model) || targetNode);
    closeNodeForm();
    closeAgentModelSetup();
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    if (previous !== state.agentTargetNode) {
      recordUserEvent("agent.target_node_selected", {
        target: `node:${targetNode}`,
        summary: `Chat model changed to ${model.label || model.id}`,
        data: { node_id: targetNode, model: model.id, previous_node_id: previous || "" },
      });
    }
    state.agentReadiness = null;
    void loadAgentReadiness("target-model");
    return;
  }
  if (requested === AGENT_SET_PROVIDER_TARGET_ID) {
    openAgentSetupBalloon({
      mode: "provider",
      message: "Edit, add, or delete configured nodes.",
      openProviderForm: true,
      providerFormMode: "new",
    });
    renderAgentNodeSelect();
    return;
  }
  if (requested === AGENT_SET_HERMES_TARGET_ID) {
    commitAgentTargetNode(defaultAgentTargetNode());
    openAgentSetupBalloon({
      mode: "agent",
      message: "Set or pick a node before sending chat messages.",
    });
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    return;
  }
  const next = requested === AGENT_PROVIDER_TARGET_ID && directProviderConfigured()
    ? directProviderTargetValue(activeAgentDirectProviderConfig())
    : !isAdminUser() && isGlobalAgentNodeId(requested) ? AGENT_SANDBOX_NODE_ID : requested;
  const previous = state.agentTargetNode;
  commitAgentTargetNode(next);
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
  if (previous !== next) {
    recordUserEvent("agent.target_node_selected", {
      target: next === AGENT_PROVIDER_TARGET_ID ? "provider-api" : `node:${next}`,
      summary: next === AGENT_PROVIDER_TARGET_ID ? "Chat target changed to saved node" : `Chat target node changed to ${next}`,
      data: { node_id: next, previous_node_id: previous || "" },
    });
  }
  if (next === AGENT_PROVIDER_TARGET_ID) return;
  state.agentReadiness = null;
  void loadAgentReadiness("target-node");
}

function normalizeAgentModelEntry(raw) {
  if (!raw) return null;
  const source = typeof raw === "string" ? { id: raw } : raw;
  let id = cleanText(source.id || source.model || source.name || "", "").slice(0, 140);
  let provider = cleanText(source.provider || "", "").slice(0, 64);
  let name = cleanText(source.name || source.model || id, "").slice(0, 140);
  if (!provider && id.includes("/")) {
    const [first, ...rest] = id.split("/");
    provider = cleanText(first, "").slice(0, 64);
    name = cleanText(rest.join("/"), name).slice(0, 140);
  }
  if (provider && name && id === name) id = formatNodeModel(name, provider);
  const label = cleanText(source.label || formatNodeModel(name, provider) || id, "").slice(0, 180);
  const modelId = cleanText(id || formatNodeModel(name, provider) || label, "").slice(0, 180);
  if (!modelId && !label) return null;
  return {
    id: modelId || label,
    name: name || modelId || label,
    provider,
    label: label || modelId,
  };
}

function agentModelKeys(model) {
  const normalized = normalizeAgentModelEntry(model);
  if (!normalized) return [];
  const candidates = [
    normalized.id,
    normalized.label,
    formatNodeModel(normalized.name, normalized.provider),
  ];
  return Array.from(new Set(
    candidates
      .map((item) => cleanText(item, "").toLowerCase())
      .filter(Boolean)
  ));
}

function agentModelKey(model) {
  return agentModelKeys(model)[0] || "";
}

function sameAgentModel(left, right) {
  const normalizedLeft = normalizeAgentModelEntry(left);
  const normalizedRight = normalizeAgentModelEntry(right);
  if (!normalizedLeft || !normalizedRight) return false;
  const leftKeys = new Set(agentModelKeys(left));
  if (agentModelKeys(right).some((key) => leftKeys.has(key))) return true;
  const leftName = cleanText(normalizedLeft.name, "").toLowerCase();
  const rightName = cleanText(normalizedRight.name, "").toLowerCase();
  if (!leftName || leftName !== rightName) return false;
  return !normalizedLeft.provider || !normalizedRight.provider;
}

function agentModelCatalog() {
  state.agentModelSettings.models = Array.isArray(state.agentModelSettings.models)
    ? state.agentModelSettings.models.map(normalizeAgentModelEntry).filter(Boolean)
    : [];
  return state.agentModelSettings.models;
}

function agentHiddenModelKeys() {
  state.agentModelSettings.hiddenModels = Array.isArray(state.agentModelSettings.hiddenModels)
    ? state.agentModelSettings.hiddenModels.map((item) => cleanText(item, "").toLowerCase()).filter(Boolean)
    : [];
  return state.agentModelSettings.hiddenModels;
}

function addAgentModelToCatalog(model) {
  const normalized = normalizeAgentModelEntry(model);
  if (!normalized) return null;
  const catalog = agentModelCatalog();
  const keys = agentModelKeys(normalized);
  state.agentModelSettings.hiddenModels = agentHiddenModelKeys().filter((item) => !keys.includes(item));
  const index = catalog.findIndex((item) => sameAgentModel(item, normalized));
  if (index >= 0) {
    catalog[index] = { ...catalog[index], ...normalized };
  } else {
    catalog.push(normalized);
  }
  return normalized;
}

function removeAgentModelFromCatalog(model) {
  const keys = agentModelKeys(model);
  if (!keys.length) return;
  state.agentModelSettings.models = agentModelCatalog().filter((item) => !sameAgentModel(item, model));
  const hidden = new Set(agentHiddenModelKeys());
  keys.forEach((key) => hidden.add(key));
  state.agentModelSettings.hiddenModels = Array.from(hidden);
}

function agentDefaultModelForNode(nodeId = agentTargetNode()) {
  if (nodeId === AGENT_PROVIDER_TARGET_ID || agentTargetIsDirectProvider()) {
    const providerConfig = activeAgentDirectProviderConfig(nodeId);
    return normalizeAgentModelEntry({
      id: providerConfig?.model || "",
      name: providerConfig?.model || "",
      provider: providerConfig?.provider || "",
    });
  }
  const node = Array.isArray(state.nodes) ? state.nodes.find((n) => n.id === nodeId) : null;
  return normalizeAgentModelEntry({
    id: node?.model || formatNodeModel(node?.modelName, node?.modelProvider),
    name: node?.modelName || node?.model || "",
    provider: node?.modelProvider || "",
  });
}

function availableAgentModels() {
  const models = [];
  const hidden = new Set(agentHiddenModelKeys());
  const add = (model) => {
    const normalized = normalizeAgentModelEntry(model);
    const keys = agentModelKeys(normalized);
    if (!keys.length || keys.some((key) => hidden.has(key))) return;
    const existing = models.find((item) => sameAgentModel(item, normalized));
    if (existing) {
      Object.assign(existing, {
        ...normalized,
        label: existing.label || normalized.label,
      });
    } else {
      models.push(normalized);
    }
  };
  add(agentDefaultModelForNode());
  for (const model of state.agentAvailableModels || []) add(model);
  for (const model of agentModelCatalog()) add(model);
  for (const override of Object.values(nodeModelOverrides())) add(override);
  return models.sort((a, b) => a.label.localeCompare(b.label));
}

function selectedAgentModel() {
  if (agentTargetIsDirectProvider()) return null;
  const selected = state.agentModelSettings.selectedByNode?.[agentModelTargetKey()];
  return normalizeAgentModelEntry(selected) || null;
}

function applyAgentModelToTarget(model) {
  const normalized = normalizeAgentModelEntry(model);
  if (!normalized) return null;
  state.agentModelSettings.selectedByNode = state.agentModelSettings.selectedByNode || {};
  state.agentModelSettings.selectedByNode[agentModelTargetKey()] = {
    id: normalized.id,
    name: normalized.name,
    provider: normalized.provider,
    label: normalized.label,
  };
  addAgentModelToCatalog(normalized);
  return normalized;
}

function persistAgentModelSelection() {
  saveAgentModelSettings();
  renderAgentModelSelect();
}

function applyAgentProviderModel(model) {
  const normalized = normalizeAgentModelEntry(model);
  const providerConfig = activeAgentDirectProviderConfig();
  if (!normalized || !providerConfig) return null;
  saveAgentDirectProviderConfig({
    ...providerConfig,
    model: normalized.id,
    provider: normalized.provider || providerConfig.provider || "",
  });
  state.agentProviderProbe = null;
  state.nodesPanelStatus = "Node model set";
  addAgentModelToCatalog(normalized);
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
  return normalized;
}

function renderAgentModelSelect() {
  if (!els.agentModelSelect) return;
  const defaultModel = agentDefaultModelForNode();
  let activeModel = selectedAgentModel();
  if (activeModel && defaultModel && sameAgentModel(activeModel, defaultModel)) {
    delete state.agentModelSettings.selectedByNode?.[agentModelTargetKey()];
    activeModel = null;
    saveAgentModelSettings();
  }
  const models = availableAgentModels();
  const fragment = document.createDocumentFragment();
  const defaultOption = document.createElement("option");
  defaultOption.value = "__default__";
  defaultOption.textContent = defaultModel?.label || "Default model";
  fragment.append(defaultOption);
  for (const model of models) {
    if (defaultModel && sameAgentModel(model, defaultModel)) continue;
    const option = document.createElement("option");
    option.value = `model:${model.id}`;
    option.textContent = model.label;
    fragment.append(option);
  }
  const separator = document.createElement("option");
  separator.disabled = true;
  separator.textContent = "\u2500\u2500\u2500\u2500\u2500";
  fragment.append(separator);
  const addOption = document.createElement("option");
  addOption.value = "__add__";
  addOption.textContent = agentTargetIsDirectProvider() ? "Edit provider..." : "+ Add model...";
  fragment.append(addOption);
  if (activeModel) {
    const removeOption = document.createElement("option");
    removeOption.value = "__remove__";
    removeOption.textContent = `Remove ${activeModel.label}`;
    fragment.append(removeOption);
  }
  els.agentModelSelect.replaceChildren(fragment);
  els.agentModelSelect.value = activeModel ? `model:${activeModel.id}` : "__default__";
  els.agentModelSelect.title = activeModel?.label || defaultModel?.label || "Default model";
}

async function loadAgentModels() {
  try {
    const payload = await bridgeJson("/v1/models", { timeoutMs: 8000 });
    const data = Array.isArray(payload.data) ? payload.data : [];
    state.agentAvailableModels = data.map((item) => normalizeAgentModelEntry({
      id: item.id,
      name: item.id,
      label: item.id,
    })).filter(Boolean);
    state.agentBridgeModelsDiagnostic = null;
    renderAgentModelSelect();
  } catch (error) {
    state.agentAvailableModels = [];
    handleBridgeModelsReadinessError(error);
    renderAgentModelSelect();
  }
}

function bridgeModelsReadinessMessage(error) {
  const status = Number(error?.status || 0);
  if (!state.authUser || status === 401 || error?.payload?.error?.code === "auth_required") {
    return { status: "auth_required", message: "Sign in to load agent models.", missing_dependency: "account_session" };
  }
  const currentStatus = cleanText(state.agentReadiness?.status, "");
  if (currentStatus === "backend_unavailable") {
    return { status: "backend_unavailable", message: "Backend bridge unavailable.", missing_dependency: state.agentReadiness?.missing_dependency || "wasm_agent_bridge" };
  }
  if (currentStatus === "sandbox_not_provisioned") {
    const balance = Number(state.agentCredits?.balance || 0);
    const cost = Number(state.agentCredits?.agent_harness_cost || state.agentCredits?.provision_main_cost || 10);
    if (balance > 0 && balance < cost) {
      return { status: "insufficient_flux", message: "Insufficient Flux.", missing_dependency: "flux_credits" };
    }
    return { status: "sandbox_not_provisioned", message: "Sandbox not provisioned.", missing_dependency: "account_sandbox" };
  }
  if (status === 403 && !isAdminUser()) {
    return { status: "provider_not_available", message: "Provider not available yet.", missing_dependency: "bridge_models_forbidden" };
  }
  return { status: "backend_unavailable", message: "Backend bridge unavailable.", missing_dependency: "bridge_models" };
}

function handleBridgeModelsReadinessError(error) {
  const mapped = bridgeModelsReadinessMessage(error);
  state.agentBridgeModelsDiagnostic = {
    endpoint: "/bridge/v1/models",
    http_status: Number(error?.status || 0),
    code: error?.payload?.error?.code || "",
    message: error?.message || "",
    readiness_status: mapped.status,
  };
  if (!state.agentReadiness || mapped.status !== "provider_not_available") {
    state.agentReadiness = {
      ok: true,
      schema: "hermes.wasm_agent.agent_readiness.v1",
      ready: false,
      target_node: agentTargetNode(),
      status: mapped.status,
      message: mapped.message,
      missing_dependency: mapped.missing_dependency,
      backend: { diagnostics: state.agentBridgeModelsDiagnostic },
    };
  }
  state.nodesPanelStatus = mapped.message;
  renderAgentReadinessStatus();
}

function defaultAgentModelSetupSteps(activeIndex = 0) {
  const labels = [
    "Validate model id",
    "Write node default",
    "Restart Hermes node",
    "Wait for runtime model",
    "Probe model response",
  ];
  return labels.map((label, index) => ({
    label,
    status: index < activeIndex ? "done" : index === activeIndex ? "running" : "pending",
    detail: "",
  }));
}

function normalizeAgentModelStep(step) {
  const source = step && typeof step === "object" ? step : {};
  return {
    label: cleanText(source.label, "Model setup"),
    status: cleanText(source.status, "pending"),
    detail: cleanText(source.detail, ""),
  };
}

function clearAgentModelSetupTimer() {
  window.clearInterval(state.agentModelSetupTimer);
  state.agentModelSetupTimer = 0;
}

function renderAgentModelSetupBalloon() {
  const setup = state.agentModelSetup;
  if (!els.agentModelBalloon) return;
  els.agentModelBalloon.hidden = !setup.open;
  if (!setup.open) return;
  const removeMode = setup.mode === "remove";
  if (els.agentModelTitle) {
    els.agentModelTitle.textContent = removeMode
      ? "Remove model"
      : setup.busy
        ? "Setting model"
        : "Set model";
  }
  if (els.agentModelInput) {
    els.agentModelInput.readOnly = setup.busy || removeMode;
    if (document.activeElement !== els.agentModelInput || removeMode) {
      els.agentModelInput.value = setup.input || "";
    }
  }
  const steps = (Array.isArray(setup.steps) ? setup.steps : []).map(normalizeAgentModelStep);
  if (els.agentModelProgress) {
    els.agentModelProgress.replaceChildren(...steps.map((step) => {
      const row = document.createElement("div");
      const status = step.status === "failed" ? "failed" : step.status === "done" ? "done" : step.status === "running" ? "running" : "pending";
      row.className = `agent-model-step is-${status}`;
      const body = document.createElement("div");
      const label = document.createElement("strong");
      label.textContent = step.label;
      body.append(label);
      if (step.detail) {
        const detail = document.createElement("span");
        detail.textContent = step.detail;
        body.append(detail);
      }
      row.append(body);
      return row;
    }));
  }
}

function setAgentModelSetup(patch) {
  state.agentModelSetup = {
    ...state.agentModelSetup,
    ...patch,
  };
  renderAgentModelSetupBalloon();
}

function openAgentModelSetup(mode = "add", model = null, options = {}) {
  clearAgentModelSetupTimer();
  const normalized = normalizeAgentModelEntry(model);
  const current = normalized || selectedAgentModel() || agentDefaultModelForNode();
  state.agentSetupBalloonOpen = true;
  state.agentSetupMode = "agent";
  state.agentSetupMessage = "Add, edit, or delete a saved agent model.";
  setAgentBalloon("model");
  setAgentModelSetup({
    open: true,
    mode,
    input: cleanText(current?.id || current?.label || "", "").slice(0, 180),
    busy: false,
    status: "idle",
    steps: mode === "remove"
      ? [{ label: `Remove ${current?.label || "selected model"}`, status: "running", detail: agentTargetNode() }]
      : [],
  });
  renderNodesPanel();
  renderAgentNodeSelect();
  window.requestAnimationFrame(() => {
    els.agentModelInput?.focus();
    if (mode !== "remove") els.agentModelInput?.select();
    if (options.auto) void submitAgentModelSetup();
  });
}

function closeAgentModelSetup() {
  if (state.agentModelSetup.busy) return;
  clearAgentModelSetupTimer();
  setAgentModelSetup({ open: false, status: "idle", steps: [] });
  renderAgentModelSelect();
  renderNodesPanel();
}

function startAgentModelSetupProgress() {
  clearAgentModelSetupTimer();
  let activeIndex = 0;
  setAgentModelSetup({ steps: defaultAgentModelSetupSteps(activeIndex) });
  state.agentModelSetupTimer = window.setInterval(() => {
    activeIndex = Math.min(activeIndex + 1, 4);
    setAgentModelSetup({ steps: defaultAgentModelSetupSteps(activeIndex) });
  }, 1600);
}

function modelSetupInputValue() {
  return cleanText(els.agentModelInput?.value || state.agentModelSetup.input, "").slice(0, 180);
}

function completeAgentModelRemove() {
  const selected = selectedAgentModel();
  if (!selected) {
    closeAgentModelSetup();
    return;
  }
  removeAgentModelFromCatalog(selected);
  delete state.agentModelSettings.selectedByNode?.[agentModelTargetKey()];
  persistAgentModelSelection();
  renderAgentNodeSelect();
  renderNodesPanel();
  setAgentModelSetup({
    busy: false,
    status: "done",
    steps: [{ label: `Removed ${selected.label}`, status: "done", detail: agentTargetNode() }],
  });
  recordUserEvent("agent.model_removed", {
    target: `node:${agentTargetNode()}`,
    summary: `Removed ${selected.label}`,
    data: { model: selected.id },
  });
  window.setTimeout(() => {
    if (state.agentModelSetup.status === "done") closeAgentModelSetup();
  }, 900);
}

async function submitAgentModelSetup(event) {
  event?.preventDefault();
  if (state.agentModelSetup.busy) return;
  if (state.agentModelSetup.mode === "remove") {
    completeAgentModelRemove();
    return;
  }
  const rawModel = modelSetupInputValue();
  if (!rawModel) {
    setAgentModelSetup({
      status: "failed",
      steps: [{ label: "Validate model id", status: "failed", detail: "Model id is required" }],
    });
    return;
  }
  const targetNode = agentTargetNode();
  setAgentModelSetup({
    input: rawModel,
    busy: true,
    status: "running",
  });
  startAgentModelSetupProgress();
  recordUserEvent("agent.model_setup_started", {
    target: `node:${targetNode}`,
    summary: `Setting ${rawModel}`,
    data: { model: rawModel },
  });
  try {
    const payload = await fetchJson("/agent/models/setup", {
      method: "POST",
      timeoutMs: DEFAULT_AGENT_TURN_TIMEOUT_MS + 30000,
      body: {
        target_node: targetNode,
        model: rawModel,
      },
    });
    clearAgentModelSetupTimer();
    const setup = payload.model_setup || {};
    const normalized = normalizeAgentModelEntry(setup.model || rawModel);
    if (normalized) {
      applyAgentModelToTarget(normalized);
      persistAgentModelSelection();
    }
    setAgentModelSetup({
      busy: false,
      status: "done",
      input: normalized?.id || rawModel,
      steps: Array.isArray(setup.steps) ? setup.steps.map(normalizeAgentModelStep) : defaultAgentModelSetupSteps(5),
    });
    await refresh();
    await loadAgentModels();
    const defaultModel = agentDefaultModelForNode(targetNode);
    if (normalized && defaultModel && sameAgentModel(normalized, defaultModel)) {
      delete state.agentModelSettings.selectedByNode?.[targetNode];
      saveAgentModelSettings();
    }
    renderAgentModelSelect();
    renderAgentNodeSelect();
    renderNodesPanel();
    recordUserEvent("agent.model_setup_finished", {
      target: `node:${targetNode}`,
      summary: `Set ${normalized?.label || rawModel}`,
      data: { model: normalized?.id || rawModel },
    });
    window.setTimeout(() => {
      if (state.agentModelSetup.status === "done") closeAgentModelSetup();
    }, 1200);
  } catch (error) {
    clearAgentModelSetupTimer();
    const setup = error.payload?.model_setup || {};
    const fallbackSteps = state.agentModelSetup.steps.length
      ? state.agentModelSetup.steps.map((step) => step.status === "running" ? { ...step, status: "failed", detail: error.message } : step)
      : [{ label: "Set model", status: "failed", detail: error.message }];
    setAgentModelSetup({
      busy: false,
      status: "failed",
      steps: Array.isArray(setup.steps) && setup.steps.length ? setup.steps.map(normalizeAgentModelStep) : fallbackSteps,
    });
    renderAgentModelSelect();
    recordUserEvent("agent.model_setup_failed", {
      target: `node:${targetNode}`,
      summary: error.message,
      data: { model: rawModel, error: error.message },
    });
  }
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function isCompactViewport() {
  return window.matchMedia("(max-width: 820px)").matches;
}

function isPrimaryPointer(event) {
  return event?.isPrimary !== false && (event?.pointerType !== "mouse" || event.button === 0);
}

function visualViewportHeight() {
  const height = Number(window.visualViewport?.height || window.innerHeight || 0);
  if (!Number.isFinite(height) || height <= 0) return 0;
  return Math.floor(height);
}

function viewportBottomInsetPx() {
  const viewport = window.visualViewport;
  const layoutHeight = Math.max(
    Number(document.documentElement?.clientHeight || 0),
    Number(window.innerHeight || 0)
  );
  if (!viewport || !layoutHeight) return 0;
  const visualBottom = Number(viewport.offsetTop || 0) + Number(viewport.height || 0);
  const visualInset = Math.max(0, layoutHeight - visualBottom);
  const appRect = els.app?.getBoundingClientRect?.();
  const appInset = appRect ? Math.max(0, appRect.bottom - visualBottom) : 0;
  const inset = Math.max(visualInset, appInset);
  const keyboardSized = inset > Math.max(96, layoutHeight * 0.18);
  return keyboardSized ? 0 : Math.round(inset);
}

function syncVisualViewportSize() {
  const height = visualViewportHeight();
  if (!height) return;
  document.documentElement.style.setProperty("--wasm-visual-height", `${height}px`);
  document.documentElement.style.setProperty("--wasm-viewport-bottom-inset", `${viewportBottomInsetPx()}px`);
}

function spaceSurface() {
  return els.spaceBoard || els.spaceViewport;
}

function formatMultiplier(value) {
  return `${Number(value).toFixed(2).replace(/\.?0+$/, "")}x`;
}

function logicalToScreenPx(value) {
  return Number(value || 0) * canvasDistance();
}

function screenToLogicalPx(value) {
  return Number(value || 0) / Math.max(SPACE_DISTANCE_MIN, canvasDistance());
}

function spaceLogicalRect(surface = spaceSurface()) {
  const rect = surface?.getBoundingClientRect?.();
  const distance = canvasDistance();
  if (!rect) return { width: 1, height: 1, left: 0, top: 0, right: 1, bottom: 1 };
  return {
    left: rect.left,
    top: rect.top,
    right: rect.left + rect.width / distance,
    bottom: rect.top + rect.height / distance,
    width: Math.max(1, rect.width / distance),
    height: Math.max(1, rect.height / distance),
  };
}

function spaceViewportUsableLogicalRect() {
  const rect = spaceViewportUsableRect();
  const distance = canvasDistance();
  if (!rect) return null;
  return {
    ...rect,
    width: Math.max(1, rect.width / distance),
    height: Math.max(1, rect.height / distance),
  };
}

function appliedCanvasBottomPaddingPx() {
  const value = parseFloat(getComputedStyle(els.mainStage || document.documentElement).paddingBottom);
  return Number.isFinite(value) && value > 0 ? value : 0;
}

function spaceViewportUsableRect() {
  const rect = els.spaceViewport?.getBoundingClientRect?.();
  if (!rect) return null;
  const unappliedInset = isCompactViewport()
    ? Math.max(0, viewportBottomInsetPx() - appliedCanvasBottomPaddingPx())
    : 0;
  const bottom = Math.max(rect.top, rect.bottom - unappliedInset);
  return {
    left: rect.left,
    top: rect.top,
    right: rect.right,
    bottom,
    width: rect.width,
    height: Math.max(1, bottom - rect.top),
  };
}

function widgetCanvasMovementBounds(widget) {
  const board = spaceSurface();
  const boardRect = spaceLogicalRect(board);
  if (!widget || !boardRect?.width || !boardRect?.height) return null;
  return {
    minLeft: SPACE_CANVAS_EDGE_INSET_PX,
    minTop: SPACE_CANVAS_EDGE_INSET_PX,
    maxLeft: Math.max(SPACE_CANVAS_EDGE_INSET_PX, boardRect.width - widget.offsetWidth - SPACE_CANVAS_EDGE_INSET_PX),
    maxTop: Math.max(SPACE_CANVAS_EDGE_INSET_PX, boardRect.height - widget.offsetHeight - SPACE_CANVAS_EDGE_INSET_PX),
    width: boardRect.width,
    height: boardRect.height,
  };
}

function canvasLayout() {
  state.widgetLayout.__canvas = state.widgetLayout.__canvas && typeof state.widgetLayout.__canvas === "object"
    ? state.widgetLayout.__canvas
    : {};
  return state.widgetLayout.__canvas;
}

function normalizedAreaPixel(value, fallback = CANVAS_AREA_MIN_PX) {
  const number = Number(value);
  const base = Number.isFinite(number) ? number : fallback;
  return clamp(Math.round(base), CANVAS_AREA_MIN_PX, CANVAS_AREA_MAX_PX);
}

function spaceAreaFromMetadata(value) {
  if (!value || typeof value !== "object") return null;
  const width = Number(value.width_px ?? value.widthPx ?? value.width);
  const height = Number(value.height_px ?? value.heightPx ?? value.height);
  if (!Number.isFinite(width) || !Number.isFinite(height)) return null;
  return {
    width: normalizedAreaPixel(width),
    height: normalizedAreaPixel(height),
  };
}

function serializableSpaceArea(area = canvasAreaSize()) {
  const normalized = normalizedCanvasAreaSize(area);
  return {
    width_px: normalized.width,
    height_px: normalized.height,
  };
}

function sameSpaceArea(left, right) {
  const a = spaceAreaFromMetadata(left);
  const b = spaceAreaFromMetadata(right);
  return Boolean(a && b && a.width === b.width && a.height === b.height);
}

function initialCanvasAreaSize() {
  const viewport = els.spaceViewport;
  const rect = spaceViewportUsableRect() || viewport?.getBoundingClientRect?.();
  const distance = canvasDistance();
  const width = Number(rect?.width || viewport?.clientWidth || window.innerWidth || 1) / Math.max(SPACE_DISTANCE_MIN, distance);
  const height = Number(rect?.height || viewport?.clientHeight || window.innerHeight || 1) / Math.max(SPACE_DISTANCE_MIN, distance);
  return {
    width: normalizedAreaPixel(width),
    height: normalizedAreaPixel(height),
  };
}

function normalizedCanvasAreaSize(value, fallback = initialCanvasAreaSize()) {
  const raw = value && typeof value === "object" ? value : {};
  return {
    width: normalizedAreaPixel(raw.width ?? raw.widthPx ?? raw.width_px, fallback.width),
    height: normalizedAreaPixel(raw.height ?? raw.heightPx ?? raw.height_px, fallback.height),
  };
}

function legacyCanvasDensityAreaSize(layout) {
  const density = Number(layout?.density);
  if (!Number.isFinite(density) || density <= 0) return null;
  const viewport = initialCanvasAreaSize();
  return normalizedCanvasAreaSize({
    width: viewport.width * density,
    height: viewport.height * density,
  }, viewport);
}

function writeCanvasAreaSize(layout, area) {
  const normalized = normalizedCanvasAreaSize(area);
  layout.widthPx = normalized.width;
  layout.heightPx = normalized.height;
  delete layout.density;
  return normalized;
}

function canvasAreaSize() {
  const layout = canvasLayout();
  const existing = spaceAreaFromMetadata({
    width_px: layout.widthPx ?? layout.width_px,
    height_px: layout.heightPx ?? layout.height_px,
  }) || legacyCanvasDensityAreaSize(layout) || initialCanvasAreaSize();
  return writeCanvasAreaSize(layout, existing);
}

function formatAreaSize(area = canvasAreaSize()) {
  const normalized = normalizedCanvasAreaSize(area);
  return `${normalized.width} x ${normalized.height}px`;
}

function configAreaDraft() {
  return normalizedCanvasAreaSize(state.configAreaDraft || canvasAreaSize());
}

function scheduleAreaMapUpdate(control = null) {
  const wrap = control || els.configDetails?.querySelector?.(".config-area-control");
  if (!wrap || wrap.dataset.areaMapFrame) return;
  wrap.dataset.areaMapFrame = "pending";
  window.requestAnimationFrame(() => {
    delete wrap.dataset.areaMapFrame;
    updateAreaMap(wrap);
  });
}

function setConfigAreaDraft(area, control = null, options = {}) {
  state.configAreaDraft = normalizedCanvasAreaSize(area, configAreaDraft());
  if (options.defer) scheduleAreaMapUpdate(control);
  else updateAreaMap(control);
  return state.configAreaDraft;
}

function configAreaDraftChanged() {
  const draft = configAreaDraft();
  const current = canvasAreaSize();
  return draft.width !== current.width || draft.height !== current.height;
}

function resetConfigAreaDraft(control = null) {
  state.configAreaDraft = canvasAreaSize();
  updateAreaMap(control);
}

function applyConfigAreaDraft(control = null) {
  if (!configAreaDraftChanged()) {
    resetConfigAreaDraft(control);
    return;
  }
  const next = configAreaDraft();
  freezeWidgetPixelLayout();
  setCanvasAreaValue(next, {
    control,
    origin: "apply",
    force: true,
    render: false,
  });
  state.configAreaDraft = canvasAreaSize();
  renderConfigModal();
  window.requestAnimationFrame(() => updateAreaMap());
}

function canvasDistance() {
  const distance = Number(canvasLayout().distance || 1);
  return clamp(Number.isFinite(distance) ? distance : 1, SPACE_DISTANCE_MIN, SPACE_DISTANCE_MAX);
}

function canvasContentExtent() {
  return Object.entries(state.widgetLayout || {}).reduce((current, [key, layout]) => {
    if (key === "__canvas" || !layout || typeof layout !== "object") return current;
    const appLeft = Number(layout.appLeftPx);
    const appTop = Number(layout.appTopPx);
    const widgetLeft = Number(layout.leftPx);
    const widgetTop = Number(layout.topPx);
    const widgetWidth = Number(layout.widthPx);
    const widgetHeight = Number(layout.heightPx);
    if (Number.isFinite(appLeft)) current.width = Math.max(current.width, appLeft + 96);
    if (Number.isFinite(appTop)) current.height = Math.max(current.height, appTop + 104);
    if (Number.isFinite(widgetLeft)) current.width = Math.max(current.width, widgetLeft + (Number.isFinite(widgetWidth) ? widgetWidth : 320));
    if (Number.isFinite(widgetTop)) current.height = Math.max(current.height, widgetTop + (Number.isFinite(widgetHeight) ? widgetHeight : 220));
    return current;
  }, { width: 0, height: 0 });
}

function applyCanvasGeometry(options = {}) {
  const board = spaceSurface();
  const viewport = els.spaceViewport;
  if (!board || !viewport) return;
  const rect = spaceViewportUsableRect() || viewport.getBoundingClientRect();
  const area = canvasAreaSize();
  const distance = canvasDistance();
  const extent = canvasContentExtent();
  const logicalWidth = Math.max(rect.width / distance, area.width, extent.width);
  const logicalHeight = Math.max(rect.height / distance, area.height, extent.height);
  board.style.setProperty("--space-distance", String(distance));
  board.dataset.spaceDistance = String(distance);
  board.style.width = `${Math.max(rect.width, Math.round(logicalWidth * distance))}px`;
  board.style.height = `${Math.max(rect.height, Math.round(logicalHeight * distance))}px`;
  if (options.drawCanvas !== false) drawCanvas();
  if (options.updateNavigation !== false) updateSpaceNavigationHints();
  if (options.renderMiniMap !== false) renderSpaceMiniMap();
  renderSharedSpacePointers();
}

function spaceMapMetrics() {
  const board = spaceSurface();
  const viewport = els.spaceViewport;
  if (!board || !viewport) return null;
  const boardRect = board.getBoundingClientRect();
  const viewportRect = viewport.getBoundingClientRect();
  return {
    board,
    viewport,
    boardRect,
    viewportRect,
    width: Math.max(viewport.clientWidth, board.offsetWidth, boardRect.width),
    height: Math.max(viewport.clientHeight, board.offsetHeight, boardRect.height),
  };
}

function visibleBoardRect(metrics) {
  const left = clamp(metrics.viewport.scrollLeft, 0, metrics.width);
  const top = clamp(metrics.viewport.scrollTop, 0, metrics.height);
  const right = clamp(left + metrics.viewport.clientWidth, left, metrics.width);
  const visibleHeight = (spaceViewportUsableRect()?.height || metrics.viewport.clientHeight);
  const bottom = clamp(top + visibleHeight, top, metrics.height);
  return {
    left,
    top,
    width: Math.max(1, right - left),
    height: Math.max(1, bottom - top),
  };
}

function miniMapPlotMetrics(metrics, mapWidth, mapHeight) {
  const padding = SPACE_MINIMAP_PADDING_PX;
  const availableWidth = Math.max(1, mapWidth - padding * 2);
  const availableHeight = Math.max(1, mapHeight - padding * 2);
  const scale = Math.min(availableWidth / Math.max(1, metrics.width), availableHeight / Math.max(1, metrics.height));
  const boardWidth = Math.max(1, Math.round(metrics.width * scale));
  const boardHeight = Math.max(1, Math.round(metrics.height * scale));
  const width = Math.max(1, boardWidth);
  const height = Math.max(1, boardHeight);
  return {
    boardWidth,
    boardHeight,
    mapWidth: boardWidth + padding * 2,
    mapHeight: boardHeight + padding * 2,
    width,
    height,
    left: padding,
    top: padding,
    scaleX: width / Math.max(1, metrics.width),
    scaleY: height / Math.max(1, metrics.height),
  };
}

function cssPixelValue(element, name, fallback) {
  const value = parseFloat(getComputedStyle(element).getPropertyValue(name));
  return Number.isFinite(value) && value > 0 ? value : fallback;
}

function miniMapProjectRect(rect, plot, minWidth = 1, minHeight = 1) {
  const width = clamp(rect.width * plot.scaleX, minWidth, plot.width);
  const height = clamp(rect.height * plot.scaleY, minHeight, plot.height);
  return {
    left: clamp(rect.left * plot.scaleX, 0, Math.max(0, plot.width - width)),
    top: clamp(rect.top * plot.scaleY, 0, Math.max(0, plot.height - height)),
    width,
    height,
  };
}

function miniMapPixelRect(rect, plot) {
  const maxWidth = Math.max(1, Math.round(plot.width));
  const maxHeight = Math.max(1, Math.round(plot.height));
  const left = clamp(Math.floor(rect.left), 0, Math.max(0, maxWidth - 1));
  const top = clamp(Math.floor(rect.top), 0, Math.max(0, maxHeight - 1));
  const right = clamp(Math.ceil(rect.left + rect.width), left + 1, maxWidth);
  const bottom = clamp(Math.ceil(rect.top + rect.height), top + 1, maxHeight);
  return {
    left,
    top,
    width: Math.max(1, right - left),
    height: Math.max(1, bottom - top),
  };
}

function applyMiniMapPixelRect(element, rect, plot) {
  const pixels = miniMapPixelRect(rect, plot);
  element.style.left = `${pixels.left}px`;
  element.style.top = `${pixels.top}px`;
  element.style.width = `${pixels.width}px`;
  element.style.height = `${pixels.height}px`;
}

function syncSpaceMiniMapViewportBox(reason = "viewport-sync") {
  const map = els.spaceMiniMap;
  if (!map || map.hidden || !state.spaceMiniMapVisible) return false;
  const viewportBox = map.querySelector?.(".space-minimap-viewport");
  if (!viewportBox) return false;
  const metrics = spaceMapMetrics();
  if (!metrics || !spaceMiniMapCanRender(metrics)) return false;
  const mapWidth = cssPixelValue(map, "--space-minimap-max-width", 184);
  const mapHeight = cssPixelValue(map, "--space-minimap-max-height", 112);
  const plot = miniMapPlotMetrics(metrics, mapWidth, mapHeight);
  applyMiniMapPixelRect(viewportBox, miniMapProjectRect(visibleBoardRect(metrics), plot), plot);
  androidNativeRecordMiniMap("viewport", reason);
  return true;
}

function scheduleSpaceMiniMapViewportSync(reason = "viewport-sync") {
  if (!state.spaceMiniMapVisible) return false;
  if (androidSpaceMiniMapViewportFrame) return true;
  androidSpaceMiniMapViewportFrame = requestAnimationFrame(() => {
    androidSpaceMiniMapViewportFrame = 0;
    syncSpaceMiniMapViewportBox(reason);
  });
  return true;
}

function boardRectContains(outer, inner, tolerance = 0.75) {
  return inner.left >= outer.left - tolerance
    && inner.top >= outer.top - tolerance
    && inner.left + inner.width <= outer.left + outer.width + tolerance
    && inner.top + inner.height <= outer.top + outer.height + tolerance;
}

function miniMapProjectAppMarker(entity, plot, visibleRect) {
  const footprintSize = Math.max(entity.width * plot.scaleX, entity.height * plot.scaleY);
  const size = clamp(footprintSize, 2, 6);
  const visibleBounds = boardRectContains(visibleRect, entity)
    ? miniMapProjectRect(visibleRect, plot)
    : { left: 0, top: 0, width: plot.width, height: plot.height };
  const width = Math.min(size, visibleBounds.width);
  const height = Math.min(size, visibleBounds.height);
  const centerX = (entity.left + entity.width / 2) * plot.scaleX;
  const centerY = (entity.top + entity.height / 2) * plot.scaleY;
  return {
    left: clamp(centerX - width / 2, visibleBounds.left, visibleBounds.left + Math.max(0, visibleBounds.width - width)),
    top: clamp(centerY - height / 2, visibleBounds.top, visibleBounds.top + Math.max(0, visibleBounds.height - height)),
    width,
    height,
  };
}

function miniMapEntityFromElement(element, metrics, kind, boardBounds) {
  const rect = element?.getBoundingClientRect?.();
  if (!rect || rect.width <= 0 || rect.height <= 0) return null;
  const rawLeft = rect.left - metrics.viewportRect.left + metrics.viewport.scrollLeft;
  const rawTop = rect.top - metrics.viewportRect.top + metrics.viewport.scrollTop;
  const left = clamp(rawLeft, 0, Math.max(0, boardBounds.width));
  const top = clamp(rawTop, 0, Math.max(0, boardBounds.height));
  const right = clamp(rawLeft + rect.width, 0, Math.max(0, boardBounds.width));
  const bottom = clamp(rawTop + rect.height, 0, Math.max(0, boardBounds.height));
  const width = right - left;
  const height = bottom - top;
  if (width <= 0 || height <= 0) return null;
  return {
    kind,
    left,
    top,
    width,
    height,
  };
}

function miniMapEntityFromRect(rect, kind, boardBounds) {
  const left = clamp(rect.left, 0, Math.max(0, boardBounds.width));
  const top = clamp(rect.top, 0, Math.max(0, boardBounds.height));
  const right = clamp(rect.left + rect.width, 0, Math.max(0, boardBounds.width));
  const bottom = clamp(rect.top + rect.height, 0, Math.max(0, boardBounds.height));
  if (right <= left || bottom <= top) return null;
  return {
    kind,
    left,
    top,
    width: right - left,
    height: bottom - top,
  };
}

function miniMapAppEntityFromButton(button, metrics, boardBounds) {
  const appId = button?.dataset?.widgetApp || "";
  const layout = appId ? state.widgetLayout[appId] || {} : {};
  if (!appId || layout.minimized === false) return null;
  const icon = button.querySelector?.(".space-app-icon");
  const iconEntity = miniMapEntityFromElement(icon || button, metrics, "app", boardBounds);
  if (iconEntity) return iconEntity;
  const width = icon?.offsetWidth || button.offsetWidth || 40;
  const height = icon?.offsetHeight || button.offsetHeight || 40;
  const styleLeft = parseFloat(button.style.left || "");
  const styleTop = parseFloat(button.style.top || "");
  const rawButtonLeft = Number.isFinite(Number(layout.appLeftPx))
    ? logicalToScreenPx(Number(layout.appLeftPx))
    : (Number.isFinite(styleLeft) ? styleLeft : 0);
  const rawButtonTop = Number.isFinite(Number(layout.appTopPx))
    ? logicalToScreenPx(Number(layout.appTopPx))
    : (Number.isFinite(styleTop) ? styleTop : 0);
  const rawLeft = rawButtonLeft + Math.max(0, ((button.offsetWidth || 62) - width) / 2);
  const rawTop = rawButtonTop + 6;
  return miniMapEntityFromRect({ left: rawLeft, top: rawTop, width, height }, "app", boardBounds);
}

function spaceMiniMapEntities(metrics) {
  const boardBounds = { width: metrics.width, height: metrics.height };
  const apps = Array.from(els.appLayer?.querySelectorAll?.(".space-app-button") || [])
    .map((button) => miniMapAppEntityFromButton(button, metrics, boardBounds))
    .filter(Boolean);
  const widgets = Array.from(document.querySelectorAll(".widget[data-widget-id]"))
    .filter((widget) => !widget.hidden && !widget.classList.contains("is-minimized") && !widget.classList.contains("is-maximized"))
    .map((widget) => miniMapEntityFromElement(widget, metrics, "widget", boardBounds))
    .filter(Boolean);
  return [...apps, ...widgets];
}

function miniMapEntityClassName(entity) {
  const classes = ["space-minimap-entity"];
  if (entity.kind.includes("app")) classes.push("is-app");
  if (entity.kind.includes("open")) classes.push("is-open");
  if (entity.kind === "widget") classes.push("is-widget");
  return classes.join(" ");
}

function androidCanvasNavigationActive(now = performance.now()) {
  return Boolean(isAndroidNativeShell() && (
    state.spacePanActive
    || state.spacePanMomentumActive
    || state.spacePinchActive
    || state.activePointers?.size
    || now - Number(state.spaceNavigationInputAt || 0) < ANDROID_CANVAS_INTERACTION_RELEASE_MS
  ));
}

function scheduleAndroidSpaceMiniMapRender(reason = "android-navigation") {
  if (!isAndroidNativeShell()) return false;
  androidNativeRecordMiniMap("requested", reason);
  if (!androidCanvasNavigationActive()) {
    androidNativeRecordMiniMap("skipped", "inactive");
    if (state.spaceMiniMapVisible) setSpaceMiniMapVisible(false);
    return false;
  }
  if (androidSpaceMiniMapRenderTimer) {
    androidNativeRecordMiniMap("skipped", "coalesced");
    return true;
  }
  androidSpaceMiniMapRenderTimer = window.setTimeout(() => {
    androidSpaceMiniMapRenderTimer = 0;
    if (androidCanvasNavigationActive() || androidNativeRecentUserInput(ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS)) {
      androidNativeRecordMiniMap("skipped", "interaction_active");
      scheduleAndroidSpaceMiniMapRender(reason);
      return;
    }
    renderSpaceMiniMap({ force: true, reason });
  }, ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS * 2);
  return true;
}

function renderSpaceMiniMap(options = {}) {
  if (options.force !== true && scheduleAndroidSpaceMiniMapRender(options.reason || "render")) return;
  const map = els.spaceMiniMap;
  const metrics = spaceMapMetrics();
  if (!map || !metrics) {
    androidNativeRecordMiniMap("skipped", "missing_map_or_metrics");
    return;
  }
  if (!spaceMiniMapCanRender(metrics)) {
    map.replaceChildren();
    androidNativeRecordMiniMap("skipped", "not_pannable");
    return;
  }
  androidNativeRecordMiniMap("executed", options.reason || "render");
  const mapWidth = cssPixelValue(map, "--space-minimap-max-width", 184);
  const mapHeight = cssPixelValue(map, "--space-minimap-max-height", 112);
  const plot = miniMapPlotMetrics(metrics, mapWidth, mapHeight);
  map.style.width = `${Math.round(plot.mapWidth)}px`;
  map.style.height = `${Math.round(plot.mapHeight)}px`;
  const boardLayer = document.createElement("div");
  boardLayer.className = "space-minimap-board";
  boardLayer.style.left = `${plot.left}px`;
  boardLayer.style.top = `${plot.top}px`;
  boardLayer.style.width = `${plot.boardWidth}px`;
  boardLayer.style.height = `${plot.boardHeight}px`;
  const visibleRect = visibleBoardRect(metrics);

  spaceMiniMapEntities(metrics).forEach((entity) => {
    const item = document.createElement("span");
    item.className = miniMapEntityClassName(entity);
    const projected = entity.kind.includes("app")
      ? miniMapProjectAppMarker(entity, plot, visibleRect)
      : miniMapProjectRect(entity, plot, 5, 4);
    applyMiniMapPixelRect(item, projected, plot);
    boardLayer.append(item);
  });

  const viewportBox = document.createElement("span");
  viewportBox.className = "space-minimap-viewport";
  const viewportRect = miniMapProjectRect(visibleRect, plot);
  applyMiniMapPixelRect(viewportBox, viewportRect, plot);
  boardLayer.append(viewportBox);
  map.replaceChildren(boardLayer);
}

function updateSpaceNavigationHints() {
  const viewport = els.spaceViewport;
  if (!viewport) return;
  const canLeft = viewport.scrollLeft > 1;
  const canRight = viewport.scrollLeft + viewport.clientWidth < viewport.scrollWidth - 1;
  const canUp = viewport.scrollTop > 1;
  const canDown = viewport.scrollTop + viewport.clientHeight < viewport.scrollHeight - 1;
  viewport.classList.toggle("can-scroll-left", canLeft);
  viewport.classList.toggle("can-scroll-right", canRight);
  viewport.classList.toggle("can-scroll-up", canUp);
  viewport.classList.toggle("can-scroll-down", canDown);
}

function stopSpacePanMomentum() {
  if (state.spacePanMomentumFrame) cancelAnimationFrame(state.spacePanMomentumFrame);
  state.spacePanMomentumFrame = 0;
  state.spacePanMomentumActive = false;
  els.spaceViewport?.classList.remove("is-momentum");
}

function clearAndroidCanvasInputDeferral() {
  if (!isAndroidNativeShell()) return;
  state.androidSpaceScrollDeferredUntil = 0;
  state.spacePinchSuppressPanUntil = 0;
  state.spaceNavigationInputAt = 0;
  if (state.androidSpaceScrollMaintenanceTimer) {
    window.clearTimeout(state.androidSpaceScrollMaintenanceTimer);
    state.androidSpaceScrollMaintenanceTimer = 0;
  }
  if (state.androidNativeScrollPanActive) {
    state.androidNativeScrollPanActive = false;
    androidNativeRecordTouch("pan_end");
  }
}

function isCanvasPanBlockedTarget(target) {
  return Boolean(target?.closest?.([
    ".widget",
    ".space-app-button",
    ".home-actions",
    ".space-title",
    ".space-config-button",
    ".space-minimap",
    ".space-zoom-info",
    ".modal-backdrop",
    ".agent-overlay",
  ].join(",")));
}

function androidMomentumTapClickTarget(target) {
  return target?.closest?.([
    "button",
    "a",
    "input",
    "textarea",
    "select",
    "[role='button']",
    "[data-panel]",
    ".space-app-button",
    ".space-launch-button",
    ".home-actions button",
    ".space-config-button",
    ".widget[data-widget-id]",
  ].join(",")) || null;
}

function androidEventClientPoint(event) {
  const touch = event.changedTouches?.[0] || event.touches?.[0] || null;
  return {
    x: Number(touch?.clientX ?? event.clientX ?? 0),
    y: Number(touch?.clientY ?? event.clientY ?? 0),
  };
}

function rememberAndroidMomentumInterruptedTap(event, clickTarget = androidMomentumTapClickTarget(event.target)) {
  if (!clickTarget) {
    state.androidMomentumInterruptedTap = null;
    return null;
  }
  const point = androidEventClientPoint(event);
  const touch = event.changedTouches?.[0] || event.touches?.[0] || null;
  const pointerId = Number(event.pointerId || touch?.identifier || 0);
  const pending = {
    pointerId,
    target: clickTarget,
    x: point.x,
    y: point.y,
    at: performance.now(),
    clicked: false,
  };
  state.androidMomentumInterruptedTap = pending;
  return pending;
}

function cancelAndroidMomentumForInteractiveTap(event) {
  if (!isAndroidNativeShell() || !state.spacePanMomentumActive) return false;
  if (event.pointerType && event.pointerType !== "touch") return false;
  if (!isSpaceInteractiveTapTarget(event.target) && !isCanvasPanBlockedTarget(event.target)) return false;
  androidNativeRecordMomentumTapEvent("cancel_pointerdown_before", event);
  stopSpacePanMomentum();
  clearAndroidCanvasInputDeferral();
  rememberAndroidMomentumInterruptedTap(event);
  androidNativeRecordTouch("ignored", "momentum_cancel_for_interactive_tap");
  androidNativeRecordMomentumTapEvent("cancel_pointerdown_after", event);
  return true;
}

function clearAndroidCanvasDeferralForScreenOpen(reason = "screen_open") {
  if (!isAndroidNativeShell()) return false;
  const hadMomentum = Boolean(state.spacePanMomentumActive);
  stopSpacePanMomentum();
  clearAndroidCanvasInputDeferral();
  androidNativeRecordTouch("ignored", reason);
  androidNativeRecordMomentumTapEvent(reason);
  return hadMomentum;
}

function finishAndroidMomentumInterruptedTap(event, reason = "momentum_synthetic_click_fallback") {
  const pending = state.androidMomentumInterruptedTap;
  if (!pending) return false;
  const touch = event.changedTouches?.[0] || event.touches?.[0] || null;
  const pointerId = Number(event.pointerId || touch?.identifier || 0);
  if (pending.pointerId && pointerId && pointerId !== pending.pointerId) return false;
  const point = androidEventClientPoint(event);
  const moved = Math.hypot(point.x - pending.x, point.y - pending.y);
  if (moved > 16 || performance.now() - Number(pending.at || 0) > 900) {
    androidNativeRecordMomentumTapEvent("fallback_cancelled", event, { moved_px: Math.round(moved) });
    state.androidMomentumInterruptedTap = null;
    return false;
  }
  androidNativeRecordMomentumTapEvent("fallback_scheduled", event, { moved_px: Math.round(moved), reason });
  window.setTimeout(() => {
    if (state.androidMomentumInterruptedTap !== pending || pending.clicked || !document.contains(pending.target)) return;
    state.androidMomentumInterruptedTap = null;
    androidNativeRecordMomentumTapEvent("fallback_click_dispatch", null, { reason, fallback_target: summarizeEventTarget(pending.target) });
    pending.target.click?.();
    androidNativeRecordTouch("ignored", reason);
  }, 32);
  return true;
}

function isSpaceInteractiveTapTarget(target) {
  return Boolean(target?.closest?.([
    "button",
    "a",
    "input",
    "textarea",
    "select",
    "[role='button']",
    "[data-panel]",
    ".space-app-button",
    ".space-launch-button",
    ".home-actions",
    ".space-config-button",
    ".modal-backdrop",
    ".agent-overlay",
  ].join(",")));
}

function installAndroidMomentumInteractiveTapCancel() {
  if (!isAndroidNativeShell() || androidSpaceMomentumTapCancelInstalled) return;
  androidSpaceMomentumTapCancelInstalled = true;
  document.addEventListener("pointerdown", (event) => {
    cancelAndroidMomentumForInteractiveTap(event);
  }, { capture: true, passive: true });
  document.addEventListener("touchstart", (event) => {
    if (state.spacePanMomentumActive) androidNativeRecordMomentumTapEvent("touchstart_during_momentum", event);
    if (!state.spacePanMomentumActive) return;
    if (!isSpaceInteractiveTapTarget(event.target) && !isCanvasPanBlockedTarget(event.target)) return;
    rememberAndroidMomentumInterruptedTap(event);
    clearAndroidCanvasDeferralForScreenOpen("momentum_cancel_for_touchstart");
  }, { capture: true, passive: true });
  document.addEventListener("pointerdown", (event) => {
    if (!event.target?.closest?.("[data-panel],.space-launch-button,.space-app-button,.home-actions button")) return;
    androidNativeRecordMomentumTapEvent("screen_open_pointerdown", event);
    if (state.spacePanMomentumActive) rememberAndroidMomentumInterruptedTap(event);
    clearAndroidCanvasDeferralForScreenOpen("screen_open_tap");
  }, { capture: true, passive: true });
  document.addEventListener("click", (event) => {
    const pending = state.androidMomentumInterruptedTap;
    if (!pending) return;
    if (pending.target === event.target || pending.target.contains?.(event.target)) {
      pending.clicked = true;
      state.androidMomentumInterruptedTap = null;
      androidNativeRecordMomentumTapEvent("real_click_arrived", event);
    }
  }, { capture: true, passive: true });
  document.addEventListener("pointerup", (event) => {
    if (state.androidMomentumInterruptedTap) androidNativeRecordMomentumTapEvent("pointerup_pending", event);
    finishAndroidMomentumInterruptedTap(event);
  }, { capture: true, passive: true });
  document.addEventListener("touchend", (event) => {
    if (state.androidMomentumInterruptedTap) androidNativeRecordMomentumTapEvent("touchend_pending", event);
    finishAndroidMomentumInterruptedTap(event, "momentum_touch_synthetic_click_fallback");
  }, { capture: true, passive: true });
}

function weightedSpacePanVelocity(samples) {
  const recent = samples.filter((sample) => sample.dt > 0);
  const totalMs = recent.reduce((total, sample) => total + sample.dt, 0);
  if (!totalMs) return { x: 0, y: 0 };
  const weighted = recent.reduce((velocity, sample) => {
    const weight = sample.dt / totalMs;
    velocity.x += sample.vx * weight;
    velocity.y += sample.vy * weight;
    return velocity;
  }, { x: 0, y: 0 });
  return {
    x: clamp(weighted.x * SPACE_PAN_MOMENTUM_LAUNCH_MULTIPLIER, -SPACE_PAN_MOMENTUM_MAX_VELOCITY, SPACE_PAN_MOMENTUM_MAX_VELOCITY),
    y: clamp(weighted.y * SPACE_PAN_MOMENTUM_LAUNCH_MULTIPLIER, -SPACE_PAN_MOMENTUM_MAX_VELOCITY, SPACE_PAN_MOMENTUM_MAX_VELOCITY),
  };
}

function startSpacePanMomentum(viewport, velocityX, velocityY, canPanX, canPanY) {
  stopSpacePanMomentum();
  let vx = Number.isFinite(velocityX) ? velocityX : 0;
  let vy = Number.isFinite(velocityY) ? velocityY : 0;
  if (!canPanX) vx = 0;
  if (!canPanY) vy = 0;
  let previous = performance.now();
  const started = previous;
  const tick = (now) => {
    const dt = Math.min(32, Math.max(1, now - previous));
    previous = now;
    const previousLeft = viewport.scrollLeft;
    const previousTop = viewport.scrollTop;
    if (canPanX) viewport.scrollLeft -= vx * dt;
    if (canPanY) viewport.scrollTop -= vy * dt;
    if (isAndroidNativeShell()) {
      state.androidSpaceScrollDeferredUntil = now + ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS;
      scheduleSpaceMiniMapViewportSync("momentum");
    } else {
      updateSpaceNavigationHints();
      renderSpaceMiniMap();
    }
    const atHorizontalEdge = !canPanX || viewport.scrollLeft <= 0 || viewport.scrollLeft + viewport.clientWidth >= viewport.scrollWidth - 1;
    const atVerticalEdge = !canPanY || viewport.scrollTop <= 0 || viewport.scrollTop + viewport.clientHeight >= viewport.scrollHeight - 1;
    const movedX = !canPanX || Math.abs(viewport.scrollLeft - previousLeft) > 0.2;
    const movedY = !canPanY || Math.abs(viewport.scrollTop - previousTop) > 0.2;
    const decay = Math.pow(SPACE_PAN_MOMENTUM_FRICTION, dt / SPACE_PAN_MOMENTUM_FRAME_MS);
    vx *= decay;
    vy *= decay;
    const speed = Math.hypot(canPanX && !atHorizontalEdge ? vx : 0, canPanY && !atVerticalEdge ? vy : 0);
    if (speed < SPACE_PAN_MOMENTUM_MIN_VELOCITY || now - started > SPACE_PAN_MOMENTUM_MAX_MS || (!movedX && !movedY)) {
      state.spacePanMomentumFrame = 0;
      state.spacePanMomentumActive = false;
      viewport.classList.remove("is-momentum");
      if (isAndroidNativeShell()) {
        window.setTimeout(() => {
          state.androidSpaceScrollDeferredUntil = 0;
          updateSpaceNavigationHints();
          applyMaximizedWidgetLayouts();
          if (state.spaceMiniMapVisible) renderSpaceMiniMap({ force: true, reason: "momentum-end" });
          setSpaceMiniMapVisible(false);
        }, ANDROID_CANVAS_INTERACTION_RELEASE_MS);
      } else {
        setSpaceMiniMapVisible(false);
      }
      return;
    }
    state.spacePanMomentumFrame = requestAnimationFrame(tick);
  };
  if (Math.hypot(vx, vy) < SPACE_PAN_MOMENTUM_MIN_VELOCITY) {
    if (isAndroidNativeShell()) {
      window.setTimeout(() => {
        updateSpaceNavigationHints();
        applyMaximizedWidgetLayouts();
        if (state.spaceMiniMapVisible) renderSpaceMiniMap({ force: true, reason: "pan-end-static" });
        setSpaceMiniMapVisible(false);
      }, ANDROID_CANVAS_INTERACTION_RELEASE_MS);
    } else {
      setSpaceMiniMapVisible(false);
    }
    return;
  }
  state.spacePanMomentumActive = true;
  viewport.classList.add("is-momentum");
  setSpaceMiniMapVisible(true);
  state.spacePanMomentumFrame = requestAnimationFrame(tick);
}

function spaceMiniMapCanRender(metrics = spaceMapMetrics()) {
  if (!metrics) return false;
  return metrics.width > metrics.viewport.clientWidth + 1
    || metrics.height > metrics.viewport.clientHeight + 1;
}

function setSpaceMiniMapVisible(visible) {
  const map = els.spaceMiniMap;
  if (!map) return;
  window.clearTimeout(state.spaceMiniMapHideTimer);
  state.spaceMiniMapHideTimer = 0;
  const nextVisible = Boolean(visible && spaceMiniMapCanRender());
  els.spaceConfigButton?.classList.toggle("is-minimap-suppressed", nextVisible || state.spaceZoomInfoVisible);
  if (nextVisible) {
    state.spaceMiniMapVisible = true;
    map.hidden = false;
    if (isAndroidNativeShell() && androidCanvasNavigationActive()) {
      scheduleAndroidSpaceMiniMapRender("show");
    } else {
      renderSpaceMiniMap();
    }
    window.requestAnimationFrame(() => {
      if (state.spaceMiniMapVisible) map.classList.add("is-visible");
    });
    return;
  }
  state.spaceMiniMapVisible = false;
  map.classList.remove("is-visible");
  els.spaceConfigButton?.classList.toggle("is-minimap-suppressed", state.spaceZoomInfoVisible);
  state.spaceMiniMapHideTimer = window.setTimeout(() => {
    if (!state.spaceMiniMapVisible) map.hidden = true;
  }, SPACE_MINIMAP_HIDE_MS);
}

function forceSpaceMiniMapForPrint() {
  const map = els.spaceMiniMap;
  if (!map || !spaceMiniMapCanRender()) return () => {};
  const wasHidden = map.hidden;
  const wasVisible = state.spaceMiniMapVisible;
  const hadVisibleClass = map.classList.contains("is-visible");
  window.clearTimeout(state.spaceMiniMapHideTimer);
  state.spaceMiniMapHideTimer = 0;
  state.spaceMiniMapVisible = true;
  map.hidden = false;
  renderSpaceMiniMap({ force: true, reason: "print" });
  map.classList.add("is-visible");
  els.spaceConfigButton?.classList.add("is-minimap-suppressed");
  return () => {
    state.spaceMiniMapVisible = wasVisible;
    map.hidden = wasHidden;
    map.classList.toggle("is-visible", hadVisibleClass);
    els.spaceConfigButton?.classList.toggle("is-minimap-suppressed", wasVisible || state.spaceZoomInfoVisible);
  };
}

function installSpaceMiniMapPrintCapture() {
  if (state.spaceMiniMapPrintCaptureInstalled) return;
  state.spaceMiniMapPrintCaptureInstalled = true;
  let restoreMiniMap = null;
  window.addEventListener("beforeprint", () => {
    restoreMiniMap?.();
    restoreMiniMap = forceSpaceMiniMapForPrint();
  });
  window.addEventListener("afterprint", () => {
    restoreMiniMap?.();
    restoreMiniMap = null;
  });
}

function renderSpaceZoomInfo() {
  const info = els.spaceZoomInfo;
  if (!info) return;
  info.textContent = formatMultiplier(canvasDistance());
}

function setSpaceZoomInfoVisible(visible) {
  const info = els.spaceZoomInfo;
  if (!info) return;
  window.clearTimeout(state.spaceZoomInfoHideTimer);
  state.spaceZoomInfoHideTimer = 0;
  const nextVisible = Boolean(visible);
  if (nextVisible) {
    state.spaceZoomInfoVisible = true;
    els.spaceConfigButton?.classList.toggle("is-minimap-suppressed", true);
    renderSpaceZoomInfo();
    info.hidden = false;
    window.requestAnimationFrame(() => {
      if (state.spaceZoomInfoVisible) info.classList.add("is-visible");
    });
    return;
  }
  state.spaceZoomInfoVisible = false;
  info.classList.remove("is-visible");
  els.spaceConfigButton?.classList.toggle("is-minimap-suppressed", state.spaceMiniMapVisible);
  state.spaceZoomInfoHideTimer = window.setTimeout(() => {
    if (!state.spaceZoomInfoVisible) info.hidden = true;
  }, SPACE_MINIMAP_HIDE_MS);
}

function freezeWidgetPixelLayout() {
  const surface = spaceSurface();
  if (!surface) return;
  const surfaceRect = surface.getBoundingClientRect();
  const distance = canvasDistance();
  document.querySelectorAll(".widget[data-widget-id]").forEach((widget) => {
    const id = widget.dataset.widgetId;
    if (!id || widget.hidden || widget.classList.contains("is-minimized") || widget.classList.contains("is-maximized")) return;
    const rect = widget.getBoundingClientRect();
    const layout = widgetLayout(id);
    const left = (rect.left - surfaceRect.left) / distance;
    const top = (rect.top - surfaceRect.top) / distance;
    const width = rect.width / distance;
    const height = rect.height / distance;
    layout.leftPx = Math.round(left);
    layout.topPx = Math.round(top);
    layout.widthPx = Math.round(width);
    layout.heightPx = Math.round(height);
    layout.leftPct = left / Math.max(1, surfaceRect.width / distance);
    layout.topPct = top / Math.max(1, surfaceRect.height / distance);
    layout.widthPct = width / Math.max(1, surfaceRect.width / distance);
    layout.heightPct = height / Math.max(1, surfaceRect.height / distance);
  });
}

function normalizedCanvasDistance(value) {
  const number = Number(value);
  const normalized = clamp(
    Math.round((Number.isFinite(number) ? number : 1) / SPACE_DISTANCE_STEP) * SPACE_DISTANCE_STEP,
    SPACE_DISTANCE_MIN,
    SPACE_DISTANCE_MAX
  );
  return Number(normalized.toFixed(2));
}

function commitCanvasAreaChange(origin = "control") {
  const area = canvasAreaSize();
  saveWidgetLayout();
  syncActiveSpaceAreaMetadata(area);
  recordUserEvent("workspace.space_area_changed", {
    target: `space:${activeSpaceStorageId()}`,
    summary: `Space area ${formatAreaSize(area)}`,
    data: { space_id: activeSpaceStorageId(), width_px: area.width, height_px: area.height, origin },
  });
}

function commitCanvasDistanceChange(origin = "control") {
  saveWidgetLayout();
  recordUserEvent("workspace.space_distance_changed", {
    target: `space:${activeSpaceStorageId()}`,
    summary: `Space distance ${formatMultiplier(canvasDistance())}`,
    data: { space_id: activeSpaceStorageId(), distance: canvasDistance(), origin },
  });
}

function setCanvasAreaValue(value, options = {}) {
  const layout = canvasLayout();
  const next = normalizedCanvasAreaSize(value, canvasAreaSize());
  const previous = canvasAreaSize();
  if (next.width === previous.width && next.height === previous.height && !options.force) return next;
  writeCanvasAreaSize(layout, next);
  applyCanvasGeometry();
  applyWidgetLayout();
  updateAreaMap(options.control);
  if (options.persist !== false) {
    commitCanvasAreaChange(options.origin || "control");
  }
  if (options.render !== false) renderConfigModal();
  return next;
}

function setCanvasArea(delta) {
  freezeWidgetPixelLayout();
  const area = canvasAreaSize();
  return setCanvasAreaValue({ width: area.width + delta, height: area.height + delta }, { origin: "step" });
}

function setCanvasDistanceValue(value, options = {}) {
  const layout = canvasLayout();
  const next = normalizedCanvasDistance(value);
  const previous = canvasDistance();
  if (next === previous && !options.force) return next;
  if (options.freeze !== false) freezeWidgetPixelLayout();
  layout.distance = next;
  applyCanvasGeometry({
    drawCanvas: options.drawCanvas,
    renderMiniMap: options.renderMiniMap,
    updateNavigation: options.updateNavigation,
  });
  if (options.layout === false) {
    applySpaceDistanceScreenPositions();
  } else {
    applyWidgetLayout();
  }
  updateDistanceDial(options.control);
  if (options.zoomInfo) renderSpaceZoomInfo();
  if (options.persist !== false) {
    commitCanvasDistanceChange(options.origin || "control");
  }
  if (options.render !== false) renderConfigModal();
  return next;
}

function setCanvasDistance(delta) {
  return setCanvasDistanceValue(canvasDistance() + delta, { origin: "step" });
}

function applySpaceDistanceScreenPositions() {
  document.querySelectorAll(".space-app-button[data-widget-app]").forEach((button) => {
    const id = button.dataset.widgetApp;
    const layout = id ? state.widgetLayout[id] || {} : {};
    const left = Number(layout.appLeftPx);
    const top = Number(layout.appTopPx);
    if (Number.isFinite(left)) button.style.left = `${logicalToScreenPx(left)}px`;
    if (Number.isFinite(top)) button.style.top = `${logicalToScreenPx(top)}px`;
  });
  document.querySelectorAll(".widget[data-widget-id]").forEach((widget) => {
    if (widget.hidden || widget.classList.contains("is-minimized") || widget.classList.contains("is-maximized")) return;
    const id = widget.dataset.widgetId;
    const layout = id ? state.widgetLayout[id] || {} : {};
    const left = Number(layout.leftPx);
    const top = Number(layout.topPx);
    if (Number.isFinite(left)) widget.style.left = `${logicalToScreenPx(left)}px`;
    if (Number.isFinite(top)) widget.style.top = `${logicalToScreenPx(top)}px`;
  });
}

function scheduleCanvasDistanceCommit(origin = "gesture") {
  window.clearTimeout(state.spaceDistanceCommitTimer);
  state.spaceDistanceCommitTimer = window.setTimeout(() => {
    state.spaceDistanceCommitTimer = 0;
    applyWidgetLayout();
    commitCanvasDistanceChange(origin);
  }, 180);
}

function viewportGestureAnchor(clientX, clientY) {
  const viewport = els.spaceViewport;
  const rect = viewport?.getBoundingClientRect?.();
  if (!viewport || !rect) return null;
  return {
    x: clamp(clientX - rect.left, 0, viewport.clientWidth),
    y: clamp(clientY - rect.top, 0, viewport.clientHeight),
  };
}

function setCanvasDistanceAround(value, anchor, options = {}) {
  const viewport = els.spaceViewport;
  if (!viewport || !anchor) return canvasDistance();
  const previous = canvasDistance();
  const next = normalizedCanvasDistance(value);
  if (next === previous && !options.force) return next;
  const logicalX = (viewport.scrollLeft + anchor.x) / Math.max(SPACE_DISTANCE_MIN, previous);
  const logicalY = (viewport.scrollTop + anchor.y) / Math.max(SPACE_DISTANCE_MIN, previous);
  setCanvasDistanceValue(next, {
    ...options,
    persist: options.persist ?? false,
    render: options.render ?? false,
    renderMiniMap: options.renderMiniMap ?? false,
  });
  viewport.scrollLeft = clamp(Math.round(logicalX * next - anchor.x), 0, Math.max(0, viewport.scrollWidth - viewport.clientWidth));
  viewport.scrollTop = clamp(Math.round(logicalY * next - anchor.y), 0, Math.max(0, viewport.scrollHeight - viewport.clientHeight));
  if (options.updateNavigation !== false) updateSpaceNavigationHints();
  if (options.renderMiniMap !== false) renderSpaceMiniMap();
  return next;
}

function scheduleSpaceZoomMiniMapHide() {
  window.clearTimeout(state.spaceZoomMiniMapTimer);
  state.spaceZoomMiniMapTimer = window.setTimeout(() => {
    state.spaceZoomMiniMapTimer = 0;
    if (!state.spacePinchActive && !state.spacePanMomentumActive) setSpaceZoomInfoVisible(false);
  }, 520);
}

function resetWidgetPosition(widget) {
  const id = widget.dataset.widgetId;
  if (id) {
    const previous = state.widgetLayout[id] || {};
    state.widgetLayout[id] = {
      minimized: Boolean(previous.minimized),
      maximized: Boolean(previous.maximized),
      appLeftPx: previous.appLeftPx,
      appTopPx: previous.appTopPx,
      appLeftPct: previous.appLeftPct,
      appTopPct: previous.appTopPct,
      meta: previous.meta,
      nodePositions: previous.nodePositions,
    };
    saveWidgetLayout();
  }
  widget.style.left = "";
  widget.style.top = "";
  widget.style.right = "";
  widget.style.bottom = "";
  widget.style.zIndex = "";
  widget.style.width = "";
  widget.style.height = "";
  widget.style.aspectRatio = "";
}

function widgetById(widgetId) {
  return document.querySelector(`.widget[data-widget-id="${CSS.escape(widgetId)}"]`);
}

function widgetLayout(widgetId) {
  state.widgetLayout[widgetId] = state.widgetLayout[widgetId] || {};
  return state.widgetLayout[widgetId];
}

function appDefinitionById(widgetId) {
  return SPACE_APP_DEFINITIONS.find((app) => app.id === widgetId) || null;
}

function spaceAppScope(panel = state.activePanel) {
  const spaceId = activeSpaceStorageId(panel);
  if (spaceId === "home") return "home";
  if (spaceId === "admin") return "admin";
  return "user";
}

function mappedAppIdsForPanel(panel = state.activePanel) {
  return new Set(SPACE_APP_MAPPINGS[spaceAppScope(panel)] || []);
}

function widgetAvailableInPanel(widgetId, panel = state.activePanel) {
  if (widgetId === "wis" && wisArtifactAvailableInPanel(panel)) return true;
  if (!isAdminUser() && isAdminPanel(panel)) return false;
  if (!isAdminUser() && isUserSpacePanel(panel)) return false;
  if (Object.prototype.hasOwnProperty.call(FIXED_WIDGET_LAYOUT, widgetId)) return true;
  const app = appDefinitionById(widgetId);
  if (app?.desktopOnly && isCompactViewport()) return false;
  return mappedAppIdsForPanel(panel).has(widgetId);
}

function widgetMeta(widgetId) {
  const layout = widgetLayout(widgetId);
  layout.meta = layout.meta && typeof layout.meta === "object" ? layout.meta : {};
  return layout.meta;
}

function widgetDefaultLabel(widgetId) {
  const definition = appDefinitionById(widgetId);
  if (definition?.label) return definition.label;
  const widget = widgetById(widgetId);
  const title = widget?.querySelector(".widget-head > span:first-child")?.textContent?.trim();
  return title || widgetId;
}

function widgetDefaultShort(widgetId) {
  const definition = appDefinitionById(widgetId);
  if (definition?.short) return definition.short;
  return widgetDefaultLabel(widgetId).slice(0, 4);
}

function widgetTitle(widgetId) {
  const title = cleanText(widgetMeta(widgetId).title, "");
  if (widgetId === "wis" && title.toLowerCase() === "wis") return widgetDefaultLabel(widgetId);
  return title || widgetDefaultLabel(widgetId);
}

function widgetShort(widgetId) {
  const short = cleanText(widgetMeta(widgetId).iconText, "");
  if (widgetId === "wis" && short.toLowerCase() === "wis") return widgetDefaultShort(widgetId).slice(0, 8);
  return (short || widgetDefaultShort(widgetId)).slice(0, 8);
}

function compactWidgetShortLabel(title = "") {
  const clean = cleanText(title, "");
  if (!clean) return "";
  if (/\bcamera|cameras\b/i.test(clean)) return "Cams";
  const word = clean.split(/\s+/).find(Boolean) || clean;
  return word.slice(0, 8);
}

function widgetImage(widgetId) {
  const image = String(widgetMeta(widgetId).image || "").trim();
  return image.startsWith("data:image/") ? image : "";
}

function normalizeDimension(value, fallback, min, max) {
  const number = Number(value);
  if (!Number.isFinite(number)) return fallback;
  return Math.round(clamp(number, min, max));
}

function widgetDimensionBounds(widgetId, surfaceRect = null) {
  const meta = widgetMeta(widgetId);
  const maxSurfaceWidth = Math.max(240, Math.round((surfaceRect?.width || 1800) - 16));
  const maxSurfaceHeight = Math.max(180, Math.round((surfaceRect?.height || 1200) - 16));
  const minWidth = normalizeDimension(meta.minWidth, 320, 180, maxSurfaceWidth);
  const minHeight = normalizeDimension(meta.minHeight, 220, 120, maxSurfaceHeight);
  const maxWidth = Math.max(minWidth, normalizeDimension(meta.maxWidth, maxSurfaceWidth, minWidth, Math.max(minWidth, 4000)));
  const maxHeight = Math.max(minHeight, normalizeDimension(meta.maxHeight, maxSurfaceHeight, minHeight, Math.max(minHeight, 3000)));
  return {
    minWidth,
    minHeight,
    maxWidth: Math.min(maxWidth, maxSurfaceWidth),
    maxHeight: Math.min(maxHeight, maxSurfaceHeight),
  };
}

function applyWidgetChrome(widget) {
  const id = widget?.dataset?.widgetId || "";
  if (!id) return;
  const title = widget.querySelector(".widget-head > span:first-child");
  if (title) title.textContent = widgetTitle(id);
  widget.querySelectorAll("[data-widget-control='minimize']").forEach((button) => {
    button.setAttribute("aria-label", `Minimize ${widgetTitle(id)}`);
  });
  widget.querySelectorAll("[data-widget-control='maximize']").forEach((button) => {
    button.setAttribute("aria-label", `${widget.classList.contains("is-maximized") ? "Restore" : "Maximize"} ${widgetTitle(id)}`);
  });
}

function applyWidgetChromeAll() {
  document.querySelectorAll(".widget[data-widget-id]").forEach((widget) => applyWidgetChrome(widget));
}

function setWidgetMinimized(widgetId, minimized) {
  if (!widgetAvailableInPanel(widgetId)) return;
  const widget = widgetById(widgetId);
  if (!widget) return;
  const layout = widgetLayout(widgetId);
  layout.minimized = Boolean(minimized);
  if (minimized) layout.maximized = false;
  saveWidgetLayout();
  applyWidgetState(widget);
  if (!minimized) {
    applyWidgetLayout();
    ensureOpenedWidgetContained(widget, widgetId);
  }
  renderAppLayer();
  syncResourcePolling();
  recordUserEvent(minimized ? "workspace.widget_minimized" : "workspace.widget_opened", {
    target: `widget:${widgetId}`,
    summary: `${minimized ? "Minimized" : "Opened"} ${widgetId}`,
    data: { widget_id: widgetId },
  });
  if (!minimized) bringWidgetForward(widget);
}

function toggleWidgetMaximized(widgetId) {
  const widget = widgetById(widgetId);
  if (!widget) return;
  const layout = widgetLayout(widgetId);
  layout.maximized = !layout.maximized;
  if (layout.maximized) layout.minimized = false;
  saveWidgetLayout();
  applyWidgetLayout();
  renderAppLayer();
  bringWidgetForward(widget);
  if (widgetId === "browser-proof") scheduleBrowserResizeSync();
  recordUserEvent("workspace.widget_maximize_toggled", {
    target: `widget:${widgetId}`,
    summary: `${layout.maximized ? "Maximized" : "Restored"} ${widgetId}`,
    data: { widget_id: widgetId, maximized: layout.maximized },
  });
}

function clearWidgetGeometryStyle(widget) {
  widget.style.left = "";
  widget.style.top = "";
  widget.style.right = "";
  widget.style.bottom = "";
  widget.style.width = "";
  widget.style.height = "";
  widget.style.aspectRatio = "";
}

function applyMaximizedWidgetLayout(widget) {
  if (!widget) return false;
  widget.style.left = "";
  widget.style.top = "";
  widget.style.right = "auto";
  widget.style.bottom = "auto";
  widget.style.width = "";
  widget.style.height = "";
  widget.style.aspectRatio = "auto";
  widget.style.zIndex = "";
  return true;
}

function applyMaximizedWidgetLayouts() {
  document.querySelectorAll(".widget.is-maximized[data-widget-id]").forEach((widget) => {
    applyMaximizedWidgetLayout(widget);
  });
  syncMaximizedShellState();
}

function syncMaximizedShellState() {
  const hasMaximizedWidget = Boolean(document.querySelector(".widget.is-maximized[data-widget-id]:not([hidden])"));
  els.app?.classList.toggle("has-maximized-widget", hasMaximizedWidget);
}

function applyWidgetState(widget) {
  const id = widget.dataset.widgetId;
  const layout = id ? state.widgetLayout[id] || {} : {};
  widget.classList.toggle("is-minimized", Boolean(layout.minimized));
  widget.classList.toggle("is-maximized", Boolean(layout.maximized));
  widget.hidden = Boolean(layout.minimized);
  widget.querySelectorAll("[data-widget-control='maximize']").forEach((button) => {
    button.classList.toggle("active", Boolean(layout.maximized));
    button.title = layout.maximized ? "Restore" : "Maximize";
    button.setAttribute("aria-label", layout.maximized ? `Restore ${id}` : `Maximize ${id}`);
  });
}

function spaceApps(panel = state.activePanel) {
  if (!isAdminUser() && isAdminPanel(panel)) return [];
  if (!isAdminUser() && isUserSpacePanel(panel) && !wisArtifactAvailableInPanel(panel)) return [];
  const mappedIds = mappedAppIdsForPanel(panel);
  if (wisArtifactAvailableInPanel(panel)) mappedIds.add("wis");
  const spaceId = activeSpaceStorageId(panel);
  return SPACE_APP_DEFINITIONS.filter((app) => {
    if (!mappedIds.has(app.id)) return false;
    if (app.desktopOnly && isCompactViewport()) return false;
    if (app.home && spaceId !== "home") return false;
    return !app.module || isModuleEnabled(app.module);
  });
}

function snapToAppGrid(value) {
  return Math.round(Number(value || 0) / APP_ICON_GRID_PX) * APP_ICON_GRID_PX;
}

function appRect(left, top, width, height) {
  return { left, top, right: left + width, bottom: top + height };
}

function appRectsOverlap(a, b) {
  const gap = 0;
  const tolerance = APP_ICON_COLLISION_TOLERANCE_PX;
  return a.left < b.right + gap - tolerance
    && a.right + gap > b.left + tolerance
    && a.top < b.bottom + gap - tolerance
    && a.bottom + gap > b.top + tolerance;
}

function appPositionFits(left, top, width, height, occupied) {
  const rect = appRect(left, top, width, height);
  return !occupied.some((item) => appRectsOverlap(rect, item));
}

function nearestOpenAppPosition(desiredLeft, desiredTop, width, height, maxLeft, maxTop, occupied) {
  const startLeft = clamp(Math.round(Number(desiredLeft || 0)), SPACE_CANVAS_EDGE_INSET_PX, maxLeft);
  const startTop = clamp(Math.round(Number(desiredTop || 0)), SPACE_CANVAS_EDGE_INSET_PX, maxTop);
  if (appPositionFits(startLeft, startTop, width, height, occupied)) return { left: startLeft, top: startTop };
  const maxRadius = Math.max(maxLeft, maxTop) + width + height;
  for (let radius = APP_ICON_GRID_PX; radius <= maxRadius; radius += APP_ICON_GRID_PX) {
    for (let dx = -radius; dx <= radius; dx += APP_ICON_GRID_PX) {
      for (const dy of [-radius, radius]) {
        const left = clamp(snapToAppGrid(startLeft + dx), SPACE_CANVAS_EDGE_INSET_PX, maxLeft);
        const top = clamp(snapToAppGrid(startTop + dy), SPACE_CANVAS_EDGE_INSET_PX, maxTop);
        if (appPositionFits(left, top, width, height, occupied)) return { left, top };
      }
    }
    for (let dy = -radius + APP_ICON_GRID_PX; dy <= radius - APP_ICON_GRID_PX; dy += APP_ICON_GRID_PX) {
      for (const dx of [-radius, radius]) {
        const left = clamp(snapToAppGrid(startLeft + dx), SPACE_CANVAS_EDGE_INSET_PX, maxLeft);
        const top = clamp(snapToAppGrid(startTop + dy), SPACE_CANVAS_EDGE_INSET_PX, maxTop);
        if (appPositionFits(left, top, width, height, occupied)) return { left, top };
      }
    }
  }
  return { left: startLeft, top: startTop };
}

function createSpaceAppButton(app) {
  const button = document.createElement("button");
  button.className = "space-app-button";
  button.type = "button";
  button.dataset.widgetApp = app.id;
  button.title = widgetTitle(app.id);
  button.setAttribute("aria-label", widgetTitle(app.id));

  const icon = document.createElement("span");
  icon.className = "space-app-icon";
  icon.textContent = widgetShort(app.id).slice(0, 2);
  const label = document.createElement("span");
  label.textContent = widgetShort(app.id);
  button.append(icon, label);
  button.addEventListener("click", (event) => {
    if (button.dataset.dragMoved === "true") {
      button.dataset.dragMoved = "";
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    const layout = widgetLayout(app.id);
    setWidgetMinimized(app.id, !layout.minimized);
  });
  button.addEventListener("contextmenu", (event) => showAppContextMenu(app.id, "app", event));
  installLongPressMenu(button, (event) => showAppContextMenu(app.id, "app", event));
  installAppButtonDragging(button, app.id);
  return button;
}

function positionSpaceAppButton(button, app, index, occupied = []) {
  const layout = widgetLayout(app.id);
  button.title = widgetTitle(app.id);
  button.setAttribute("aria-label", widgetTitle(app.id));
  button.classList.toggle("open", !layout.minimized);
  const icon = button.querySelector(".space-app-icon");
  const image = widgetImage(app.id);
  if (icon) {
    icon.textContent = image ? "" : widgetShort(app.id).slice(0, 2);
    icon.style.backgroundImage = image ? `url("${image}")` : "";
    icon.classList.toggle("has-image", Boolean(image));
  }
  const label = button.querySelector(".space-app-icon + span");
  if (label) label.textContent = widgetShort(app.id);
  const viewportRect = spaceLogicalRect();
  const defaultLeftPct = 0.04 + (index % 3) * 0.088;
  const defaultTopPct = 0.12 + Math.floor(index / 3) * 0.14;
  const buttonWidth = button.offsetWidth || 62;
  const buttonHeight = button.offsetHeight || 70;
  const maxLeftStable = Math.max(SPACE_CANVAS_EDGE_INSET_PX, viewportRect.width - buttonWidth - SPACE_CANVAS_EDGE_INSET_PX);
  const maxTopStable = Math.max(SPACE_CANVAS_EDGE_INSET_PX, viewportRect.height - buttonHeight - SPACE_CANVAS_EDGE_INSET_PX);
  const hasSavedPixelPosition = Number.isFinite(layout.appLeftPx) && Number.isFinite(layout.appTopPx);
  const desiredLeft = Number.isFinite(layout.appLeftPx)
    ? layout.appLeftPx
    : (Number.isFinite(layout.appLeftPct) ? layout.appLeftPct : defaultLeftPct) * viewportRect.width;
  const desiredTop = Number.isFinite(layout.appTopPx)
    ? layout.appTopPx
    : (Number.isFinite(layout.appTopPct) ? layout.appTopPct : defaultTopPct) * viewportRect.height;
  if (layout.appOrganized === true || hasSavedPixelPosition) {
    const left = clamp(Math.round(Number(desiredLeft || 0)), 0, Math.max(0, viewportRect.width - buttonWidth));
    const top = clamp(Math.round(Number(desiredTop || 0)), 0, Math.max(0, viewportRect.height - buttonHeight));
    layout.appLeftPx = left;
    layout.appTopPx = top;
    layout.appLeftPct = left / Math.max(1, viewportRect.width);
    layout.appTopPct = top / Math.max(1, viewportRect.height);
    button.style.left = `${logicalToScreenPx(left)}px`;
    button.style.top = `${logicalToScreenPx(top)}px`;
    occupied.push(appRect(left, top, buttonWidth, buttonHeight));
    return;
  }
  const { left, top } = nearestOpenAppPosition(desiredLeft, desiredTop, buttonWidth, buttonHeight, maxLeftStable, maxTopStable, occupied);
  layout.appLeftPx = left;
  layout.appTopPx = top;
  layout.appLeftPct = left / Math.max(1, viewportRect.width);
  layout.appTopPct = top / Math.max(1, viewportRect.height);
  button.style.left = `${logicalToScreenPx(left)}px`;
  button.style.top = `${logicalToScreenPx(top)}px`;
  occupied.push(appRect(left, top, buttonWidth, buttonHeight));
}

function renderAppLayer() {
  if (!els.appLayer) return;
  const apps = spaceApps();
  const occupied = [];
  const nodes = apps.map((app, index) => {
    let button = state.appButtonCache.get(app.id);
    if (!button) {
      button = createSpaceAppButton(app);
      state.appButtonCache.set(app.id, button);
    }
    positionSpaceAppButton(button, app, index, occupied);
    return button;
  });
  els.appLayer.replaceChildren(...nodes);
}

function organizerTopInsetPx(board) {
  const boardRect = board?.getBoundingClientRect?.();
  const title = els.spaceOrganizeButton?.closest?.(".space-title") || els.spaceLabel?.closest?.(".space-title");
  const titleRect = title?.getBoundingClientRect?.();
  if (!boardRect || !titleRect) return APP_ORGANIZER_TOP_INSET_PX;
  const titleBottom = Math.ceil(screenToLogicalPx(titleRect.bottom - boardRect.top + 4));
  const homeCoreModuleList = activeSpaceStorageId() === "home" ? board.querySelector(".home-actions") : null;
  const homeCoreModuleRect = homeCoreModuleList?.getBoundingClientRect?.();
  const homeCoreModuleBottom = homeCoreModuleRect && homeCoreModuleRect.width && homeCoreModuleRect.height
    ? Math.ceil(screenToLogicalPx(homeCoreModuleRect.bottom - boardRect.top + 4))
    : 0;
  return Math.max(APP_ORGANIZER_TOP_INSET_PX, titleBottom, homeCoreModuleBottom);
}

function organizeSpaceAppsInViewport() {
  const viewport = els.spaceViewport;
  const board = spaceSurface();
  if (!viewport || !board || !els.appLayer) return;
  const apps = spaceApps();
  if (!apps.length) return;
  const buttonWidth = 62;
  const buttonHeight = 70;
  const gapX = 0;
  const gapY = 0;
  const leftInset = 0;
  const topInset = organizerTopInsetPx(board);
  const boardRect = spaceLogicalRect(board);
  const boardWidth = Math.max(buttonWidth, boardRect.width);
  const boardHeight = Math.max(buttonHeight, boardRect.height);
  const visibleWidth = Math.max(1, viewport.clientWidth / canvasDistance());
  const visibleHeight = Math.max(1, viewport.clientHeight / canvasDistance());
  const visibleColumns = Math.max(1, Math.floor((Math.max(buttonWidth, visibleWidth - leftInset) + gapX) / (buttonWidth + gapX)));
  const boardColumns = Math.max(1, Math.floor((boardWidth + gapX) / (buttonWidth + gapX)));
  const columns = Math.min(apps.length, visibleColumns, boardColumns);
  const rows = Math.ceil(apps.length / columns);
  const blockWidth = columns * buttonWidth + Math.max(0, columns - 1) * gapX;
  const blockHeight = rows * buttonHeight + Math.max(0, rows - 1) * gapY;
  const rawStartLeft = snapToAppGrid(screenToLogicalPx(viewport.scrollLeft) + leftInset);
  const startLeft = clamp(rawStartLeft, 0, Math.max(0, boardWidth - blockWidth));
  const rawStartTop = snapToAppGrid(screenToLogicalPx(viewport.scrollTop) + topInset);
  const startTop = clamp(rawStartTop, 0, Math.max(0, boardHeight - blockHeight));
  apps.forEach((app, index) => {
    const column = index % columns;
    const row = Math.floor(index / columns);
    const layout = widgetLayout(app.id);
    const left = Math.round(startLeft + column * (buttonWidth + gapX));
    const top = Math.round(startTop + row * (buttonHeight + gapY));
    layout.appLeftPx = left;
    layout.appTopPx = top;
    layout.appOrganized = true;
    layout.appLeftPct = left / Math.max(1, boardWidth);
    layout.appTopPct = top / Math.max(1, boardHeight);
  });
  const overflowRows = Math.max(0, rows - Math.max(1, Math.floor((visibleHeight - topInset + gapY) / (buttonHeight + gapY))));
  renderAppLayer();
  renderSpaceMiniMap();
  saveWidgetLayout();
  recordUserEvent("workspace.apps_organized", {
    target: `space:${activeSpaceStorageId()}`,
    summary: `Organized ${activeSpaceStorageId()} apps`,
    data: {
      space_id: activeSpaceStorageId(),
      app_count: apps.length,
      columns,
      overflow_rows: overflowRows,
      scroll_left: viewport.scrollLeft,
      scroll_top: viewport.scrollTop,
    },
  });
}

function installAppButtonDragging(button, appId) {
  const viewport = spaceSurface();
  if (!viewport) return;
  button.addEventListener("pointerdown", (event) => {
    if (!isPrimaryPointer(event)) return;
    const startRect = button.getBoundingClientRect();
    const viewportRect = viewport.getBoundingClientRect();
    const startLeft = screenToLogicalPx(startRect.left - viewportRect.left);
    const startTop = screenToLogicalPx(startRect.top - viewportRect.top);
    const startX = event.clientX;
    const startY = event.clientY;
    let moved = false;
    button.classList.add("is-dragging");
    document.body.classList.add("is-app-dragging");
    try {
      button.setPointerCapture(event.pointerId);
    } catch {
      // Pointer capture can be unavailable during rapid touch/context transitions.
    }
    const move = (moveEvent) => {
      if (Math.hypot(moveEvent.clientX - startX, moveEvent.clientY - startY) > 4) moved = true;
      const logicalRect = spaceLogicalRect(viewport);
      const maxLeft = Math.max(SPACE_CANVAS_EDGE_INSET_PX, logicalRect.width - button.offsetWidth - SPACE_CANVAS_EDGE_INSET_PX);
      const maxTop = Math.max(SPACE_CANVAS_EDGE_INSET_PX, logicalRect.height - button.offsetHeight - SPACE_CANVAS_EDGE_INSET_PX);
      const left = clamp(startLeft + screenToLogicalPx(moveEvent.clientX - startX), SPACE_CANVAS_EDGE_INSET_PX, maxLeft);
      const top = clamp(startTop + screenToLogicalPx(moveEvent.clientY - startY), SPACE_CANVAS_EDGE_INSET_PX, maxTop);
      button.style.left = `${logicalToScreenPx(left)}px`;
      button.style.top = `${logicalToScreenPx(top)}px`;
    };
    const end = (endEvent) => {
      button.classList.remove("is-dragging");
      document.body.classList.remove("is-app-dragging");
      window.removeEventListener("pointermove", move);
      window.removeEventListener("pointerup", end);
      window.removeEventListener("pointercancel", end);
      try {
        button.releasePointerCapture(event.pointerId);
      } catch {
        // Capture may already be released by the browser.
      }
      if (!moved) {
        button.style.left = `${logicalToScreenPx(startLeft)}px`;
        button.style.top = `${logicalToScreenPx(startTop)}px`;
        return;
      }
      const layout = widgetLayout(appId);
      const logicalRect = spaceLogicalRect(viewport);
      const maxLeft = Math.max(SPACE_CANVAS_EDGE_INSET_PX, logicalRect.width - button.offsetWidth - SPACE_CANVAS_EDGE_INSET_PX);
      const maxTop = Math.max(SPACE_CANVAS_EDGE_INSET_PX, logicalRect.height - button.offsetHeight - SPACE_CANVAS_EDGE_INSET_PX);
      const occupied = Array.from(els.appLayer.querySelectorAll(".space-app-button"))
        .filter((item) => item !== button)
        .map((item) => {
          const rect = item.getBoundingClientRect();
          return appRect(
            screenToLogicalPx(rect.left - viewportRect.left),
            screenToLogicalPx(rect.top - viewportRect.top),
            screenToLogicalPx(rect.width),
            screenToLogicalPx(rect.height)
          );
        });
      const { left, top } = nearestOpenAppPosition(
        screenToLogicalPx(parseFloat(button.style.left || "0")),
        screenToLogicalPx(parseFloat(button.style.top || "0")),
        button.offsetWidth,
        button.offsetHeight,
        maxLeft,
        maxTop,
        occupied
      );
      button.style.left = `${logicalToScreenPx(left)}px`;
      button.style.top = `${logicalToScreenPx(top)}px`;
      layout.appLeftPx = left;
      layout.appTopPx = top;
      layout.appOrganized = false;
      layout.appLeftPct = left / Math.max(1, logicalRect.width);
      layout.appTopPct = top / Math.max(1, logicalRect.height);
      saveWidgetLayout();
      button.dataset.dragMoved = "true";
      window.setTimeout(() => {
        button.dataset.dragMoved = "";
      }, 0);
      endEvent.preventDefault();
      endEvent.stopPropagation();
      recordUserEvent("workspace.app_moved", {
        target: `app:${appId}`,
        summary: `Moved app ${appId}`,
        data: { app_id: appId, left_pct: layout.appLeftPct, top_pct: layout.appTopPct },
      });
    };
    window.addEventListener("pointermove", move);
    window.addEventListener("pointerup", end, { once: true });
    window.addEventListener("pointercancel", end, { once: true });
  });
}

function installLongPressMenu(target, openMenu) {
  if (!target) return;
  let timer = 0;
  let startX = 0;
  let startY = 0;
  const clear = () => {
    window.clearTimeout(timer);
    timer = 0;
  };
  target.addEventListener("pointerdown", (event) => {
    if (event.pointerType === "mouse" || event.button !== 0) return;
    startX = event.clientX;
    startY = event.clientY;
    clear();
    timer = window.setTimeout(() => {
      timer = 0;
      openMenu(event);
    }, 560);
  });
  target.addEventListener("pointermove", (event) => {
    if (!timer) return;
    if (Math.hypot(event.clientX - startX, event.clientY - startY) > 8) clear();
  });
  target.addEventListener("pointerup", clear);
  target.addEventListener("pointercancel", clear);
  target.addEventListener("lostpointercapture", clear);
}

function applyWidgetLayout() {
  const viewport = spaceSurface();
  if (!viewport) return;
  applyWidgetChromeAll();
  const viewportRect = spaceLogicalRect(viewport);
  let maxZ = state.widgetZ;
  let containedAny = false;
  document.querySelectorAll(".widget[data-widget-id]").forEach((widget) => {
    const id = widget.dataset.widgetId;
    if (!widgetAvailableInPanel(id)) {
      widget.hidden = true;
      widget.classList.add("is-minimized");
      widget.classList.remove("is-maximized");
      return;
    }
    const layout = widgetLayout(id);
    applyWidgetState(widget);
    applyWidgetChrome(widget);
    if (layout?.maximized) {
      applyMaximizedWidgetLayout(widget);
      maxZ = Math.max(maxZ, Number(layout?.z || widget.style.zIndex || 4));
      return;
    }
    if (layout?.minimized) {
      maxZ = Math.max(maxZ, Number(layout?.z || widget.style.zIndex || 4));
      return;
    }
    clearWidgetGeometryStyle(widget);
    const bounds = widgetDimensionBounds(id, viewportRect);
    const widthPx = Number(layout?.widthPx);
    const heightPx = Number(layout?.heightPx);
    const widthPct = Number(layout?.widthPct);
    const heightPct = Number(layout?.heightPct);
    if (Number.isFinite(widthPx) || Number.isFinite(widthPct)) {
      const width = clamp(
        Number.isFinite(widthPx) ? widthPx : widthPct * viewportRect.width,
        bounds.minWidth,
        bounds.maxWidth
      );
      widget.style.width = `${width}px`;
      layout.widthPx = Math.round(width);
      widget.style.aspectRatio = "auto";
    }
    if (Number.isFinite(heightPx) || Number.isFinite(heightPct)) {
      const height = clamp(
        Number.isFinite(heightPx) ? heightPx : heightPct * viewportRect.height,
        bounds.minHeight,
        bounds.maxHeight
      );
      widget.style.height = `${height}px`;
      layout.heightPx = Math.round(height);
      widget.style.aspectRatio = "auto";
    }
    fitWidgetToVisibleViewport(widget, id, { updateLayout: false });
    const leftPx = Number(layout?.leftPx);
    const topPx = Number(layout?.topPx);
    const leftPct = Number(layout?.leftPct);
    const topPct = Number(layout?.topPct);
    if ((Number.isFinite(leftPx) || Number.isFinite(leftPct)) && (Number.isFinite(topPx) || Number.isFinite(topPct))) {
      const maxLeft = Math.max(SPACE_CANVAS_EDGE_INSET_PX, viewportRect.width - widget.offsetWidth - SPACE_CANVAS_EDGE_INSET_PX);
      const maxTop = Math.max(SPACE_CANVAS_EDGE_INSET_PX, viewportRect.height - widget.offsetHeight - SPACE_CANVAS_EDGE_INSET_PX);
      const left = clamp(Number.isFinite(leftPx) ? leftPx : leftPct * viewportRect.width, SPACE_CANVAS_EDGE_INSET_PX, maxLeft);
      const top = clamp(Number.isFinite(topPx) ? topPx : topPct * viewportRect.height, SPACE_CANVAS_EDGE_INSET_PX, maxTop);
      widget.style.left = `${logicalToScreenPx(left)}px`;
      widget.style.top = `${logicalToScreenPx(top)}px`;
      widget.style.right = "auto";
      widget.style.bottom = "auto";
      layout.leftPx = Math.round(left);
      layout.topPx = Math.round(top);
      layout.leftPct = left / Math.max(1, viewportRect.width);
      layout.topPct = top / Math.max(1, viewportRect.height);
    }
    const contained = containWidgetInCanvasBounds(widget, id);
    containedAny = containedAny || contained.changed;
    const restoredZ = clamp(Number(layout?.z || widget.style.zIndex || 4), 4, WIDGET_Z_LIMIT);
    if (layout?.z || widget.style.zIndex) widget.style.zIndex = String(restoredZ);
    maxZ = Math.max(maxZ, restoredZ);
  });
  state.widgetZ = maxZ;
  if (containedAny) saveWidgetLayout();
  syncMaximizedShellState();
  renderAppLayer();
  syncResourcePolling();
}

function fitWidgetToVisibleViewport(widget, widgetId, options = {}) {
  const visibleRect = spaceViewportUsableRect();
  if (!widget || !visibleRect?.width || !visibleRect?.height) return { changed: false };
  const distance = canvasDistance();
  const logicalVisibleRect = spaceViewportUsableLogicalRect() || visibleRect;
  const bounds = widgetDimensionBounds(widgetId, logicalVisibleRect);
  const rect = widget.getBoundingClientRect();
  const width = Math.round(rect.width / distance);
  const height = Math.round(rect.height / distance);
  const allowHorizontalCanvasOverflow = isCompactViewport();
  const nextWidth = allowHorizontalCanvasOverflow ? width : Math.round(clamp(width, 1, bounds.maxWidth));
  const nextHeight = Math.round(clamp(height, 1, bounds.maxHeight));
  const updateLayout = options.updateLayout !== false;
  const layout = updateLayout ? widgetLayout(widgetId) : null;
  let changed = false;
  if (!allowHorizontalCanvasOverflow && width > nextWidth) {
    widget.style.width = `${nextWidth}px`;
    widget.style.right = "auto";
    widget.style.aspectRatio = "auto";
    if (layout) {
      layout.widthPx = nextWidth;
      layout.widthPct = nextWidth / Math.max(1, logicalVisibleRect.width);
    }
    changed = true;
  }
  if (height > nextHeight) {
    widget.style.height = `${nextHeight}px`;
    widget.style.bottom = "auto";
    widget.style.aspectRatio = "auto";
    if (layout) {
      layout.heightPx = nextHeight;
      layout.heightPct = nextHeight / Math.max(1, logicalVisibleRect.height);
    }
    changed = true;
  }
  return { changed, height: Math.round(nextHeight * distance), width: Math.round(nextWidth * distance) };
}

function containWidgetInCanvasBounds(widget, widgetId, options = {}) {
  const board = spaceSurface();
  const boardRect = board?.getBoundingClientRect?.();
  if (!widget || !boardRect?.width || !boardRect?.height) return { changed: false };
  const rect = widget.getBoundingClientRect();
  if (rect.width <= 0 || rect.height <= 0) return { changed: false };
  const distance = canvasDistance();
  const updateLayout = options.updateLayout !== false;
  const layout = updateLayout ? widgetLayout(widgetId) : null;
  const left = (rect.left - boardRect.left) / distance;
  const top = (rect.top - boardRect.top) / distance;
  const width = rect.width / distance;
  const height = rect.height / distance;
  const logicalBoardRect = spaceLogicalRect(board);
  const maxLeft = Math.max(SPACE_CANVAS_EDGE_INSET_PX, logicalBoardRect.width - width - SPACE_CANVAS_EDGE_INSET_PX);
  const maxTop = Math.max(SPACE_CANVAS_EDGE_INSET_PX, logicalBoardRect.height - height - SPACE_CANVAS_EDGE_INSET_PX);
  const nextLeft = clamp(left, SPACE_CANVAS_EDGE_INSET_PX, maxLeft);
  const nextTop = clamp(top, SPACE_CANVAS_EDGE_INSET_PX, maxTop);
  const changed = Math.abs(nextLeft - left) > 0.5 || Math.abs(nextTop - top) > 0.5;
  if (!changed) return { changed: false, left: Math.round(left), top: Math.round(top) };
  widget.style.left = `${Math.round(logicalToScreenPx(nextLeft))}px`;
  widget.style.top = `${Math.round(logicalToScreenPx(nextTop))}px`;
  widget.style.right = "auto";
  widget.style.bottom = "auto";
  if (layout) {
    layout.leftPx = Math.round(nextLeft);
    layout.topPx = Math.round(nextTop);
    layout.leftPct = nextLeft / Math.max(1, logicalBoardRect.width);
    layout.topPct = nextTop / Math.max(1, logicalBoardRect.height);
  }
  return { changed: true, left: Math.round(nextLeft), top: Math.round(nextTop) };
}

function ensureOpenedWidgetContained(widget, widgetId) {
  if (!widget || widget.hidden || widget.classList.contains("is-minimized") || widget.classList.contains("is-maximized")) return;
  const visibleRect = spaceViewportUsableRect();
  if (!visibleRect) return;
  const fit = fitWidgetToVisibleViewport(widget, widgetId);
  const rect = widget.getBoundingClientRect();
  const fullyVisible = rect.left >= visibleRect.left
    && rect.top >= visibleRect.top
    && rect.right <= visibleRect.right
    && rect.bottom <= visibleRect.bottom;
  if (fullyVisible) {
    if (fit.changed) {
      saveWidgetLayout();
      recordUserEvent("workspace.widget_visible_bounds_applied", {
        target: `widget:${widgetId}`,
        summary: `Fit ${widgetId} to the visible canvas`,
        data: { widget_id: widgetId, width_px: fit.width, height_px: fit.height },
      });
    }
    return;
  }
  const layout = widgetLayout(widgetId);
  layout.leftPx = SPACE_CANVAS_EDGE_INSET_PX;
  layout.topPx = SPACE_CANVAS_EDGE_INSET_PX;
  layout.leftPct = 0;
  layout.topPct = 0;
  widget.style.left = `${SPACE_CANVAS_EDGE_INSET_PX}px`;
  widget.style.top = `${SPACE_CANVAS_EDGE_INSET_PX}px`;
  widget.style.right = "auto";
  widget.style.bottom = "auto";
  els.spaceViewport.scrollLeft = 0;
  els.spaceViewport.scrollTop = 0;
  saveWidgetLayout();
  recordUserEvent("workspace.widget_initial_point_applied", {
    target: `widget:${widgetId}`,
    summary: `Moved ${widgetId} to the canvas initial point`,
    data: { widget_id: widgetId, left_px: SPACE_CANVAS_EDGE_INSET_PX, top_px: SPACE_CANVAS_EDGE_INSET_PX, width_px: fit.changed ? fit.width : Math.round(rect.width), height_px: fit.changed ? fit.height : Math.round(rect.height) },
  });
}

function normalizeWidgetStack() {
  const widgets = Array.from(document.querySelectorAll(".widget[data-widget-id]"))
    .sort((a, b) => Number(a.style.zIndex || 4) - Number(b.style.zIndex || 4));
  widgets.forEach((widget, index) => {
    const z = WIDGET_Z_BASE + index;
    widget.style.zIndex = String(z);
    const id = widget.dataset.widgetId;
    if (id && state.widgetLayout[id]) state.widgetLayout[id].z = z;
  });
  state.widgetZ = WIDGET_Z_BASE + widgets.length;
  saveWidgetLayout();
}

function bringWidgetForward(widget) {
  if (state.widgetZ >= WIDGET_Z_LIMIT) normalizeWidgetStack();
  state.widgetZ += 1;
  widget.style.zIndex = String(state.widgetZ);
  const id = widget.dataset.widgetId;
  if (id) {
    const previous = state.activeWidgetId;
    document.querySelectorAll(".widget[data-widget-id].is-widget-active").forEach((item) => {
      item.classList.toggle("is-widget-active", item === widget);
    });
    widget.classList.add("is-widget-active");
    syncWisCameraTimelineVisibility();
    state.widgetLayout[id] = state.widgetLayout[id] || {};
    state.widgetLayout[id].z = state.widgetZ;
    saveWidgetLayout();
    state.activeWidgetId = id;
    if (previous !== id) {
      recordUserEvent("workspace.widget_focused", {
        target: `widget:${id}`,
        summary: `Focused ${id}`,
        data: { widget_id: id, z: state.widgetZ },
      });
    }
  }
}

function clearActiveWidget() {
  document.querySelectorAll(".widget[data-widget-id].is-widget-active").forEach((widget) => {
    widget.classList.remove("is-widget-active");
  });
  state.activeWidgetId = "";
  syncWisCameraTimelineVisibility();
}

function installWidgetDragging() {
  const viewport = spaceSurface();
  if (!viewport) return;

  document.querySelectorAll(".widget[data-widget-id]").forEach((widget) => {
    const handle = widget.querySelector(".widget-head");
    if (!handle) return;

    widget.addEventListener("pointerdown", () => bringWidgetForward(widget));
    widget.addEventListener("focusin", () => bringWidgetForward(widget));

    if (widget.dataset.widgetDblclickReset !== "false") {
      handle.addEventListener("dblclick", (event) => {
        event.preventDefault();
        resetWidgetPosition(widget);
        recordUserEvent("workspace.widget_reset", {
          target: `widget:${widget.dataset.widgetId}`,
          summary: `Reset ${widget.dataset.widgetId} layout`,
          data: { widget_id: widget.dataset.widgetId },
        });
      });
    }
    handle.addEventListener("contextmenu", (event) => showAppContextMenu(widget.dataset.widgetId, "widget", event));
    installLongPressMenu(handle, (event) => showAppContextMenu(widget.dataset.widgetId, "widget", event));

    handle.addEventListener("pointerdown", (event) => {
      if (!isPrimaryPointer(event)) return;
      if (event.target.closest("button,input,textarea,select,s-select,a")) return;
      if (widget.classList.contains("is-maximized")) return;
      event.preventDefault();

      const viewportRect = viewport.getBoundingClientRect();
      const widgetRect = widget.getBoundingClientRect();
      const startLeft = screenToLogicalPx(widgetRect.left - viewportRect.left);
      const startTop = screenToLogicalPx(widgetRect.top - viewportRect.top);
      const startX = event.clientX;
      const startY = event.clientY;

      widget.style.left = `${logicalToScreenPx(startLeft)}px`;
      widget.style.top = `${logicalToScreenPx(startTop)}px`;
      widget.style.right = "auto";
      widget.style.bottom = "auto";
      widget.style.transform = "";
      widget.classList.add("is-dragging");
      document.body.classList.add("is-widget-dragging");
      bringWidgetForward(widget);
      try {
        handle.setPointerCapture(event.pointerId);
      } catch {
        // Pointer capture can be unavailable during rapid touch/context transitions.
      }
      const startedAt = performance.now();
      recordUserEvent("workspace.widget_drag_started", {
        target: `widget:${widget.dataset.widgetId}`,
        summary: `Started dragging ${widget.dataset.widgetId}`,
        data: { widget_id: widget.dataset.widgetId, x: Math.round(startLeft), y: Math.round(startTop) },
      });

      const move = (moveEvent) => {
        const bounds = widgetCanvasMovementBounds(widget);
        if (!bounds) return;
        const left = clamp(startLeft + screenToLogicalPx(moveEvent.clientX - startX), bounds.minLeft, bounds.maxLeft);
        const top = clamp(startTop + screenToLogicalPx(moveEvent.clientY - startY), bounds.minTop, bounds.maxTop);
        widget.style.left = `${logicalToScreenPx(left)}px`;
        widget.style.top = `${logicalToScreenPx(top)}px`;
      };

      const end = () => {
        widget.classList.remove("is-dragging");
        document.body.classList.remove("is-widget-dragging");
        window.removeEventListener("pointermove", move);
        window.removeEventListener("pointerup", end);
        window.removeEventListener("pointercancel", end);
        try {
          handle.releasePointerCapture(event.pointerId);
        } catch {
          // Capture may already be released by the browser.
        }
        const finalLeft = screenToLogicalPx(parseFloat(widget.style.left || "0"));
        const finalTop = screenToLogicalPx(parseFloat(widget.style.top || "0"));
        const bounds = widgetCanvasMovementBounds(widget) || spaceLogicalRect(viewport);
        state.widgetLayout[widget.dataset.widgetId] = {
          ...(state.widgetLayout[widget.dataset.widgetId] || {}),
          leftPx: Math.round(finalLeft),
          topPx: Math.round(finalTop),
          leftPct: finalLeft / Math.max(1, bounds.width),
          topPct: finalTop / Math.max(1, bounds.height),
          z: Number(widget.style.zIndex || 4),
        };
        saveWidgetLayout();
        recordUserEvent("workspace.widget_drag_finished", {
          target: `widget:${widget.dataset.widgetId}`,
          summary: `Finished dragging ${widget.dataset.widgetId}`,
          data: {
            widget_id: widget.dataset.widgetId,
            left_pct: state.widgetLayout[widget.dataset.widgetId].leftPct,
            top_pct: state.widgetLayout[widget.dataset.widgetId].topPct,
          },
          duration_ms: performance.now() - startedAt,
        });
      };

      window.addEventListener("pointermove", move);
      window.addEventListener("pointerup", end, { once: true });
      window.addEventListener("pointercancel", end, { once: true });
    });
  });

  window.addEventListener("resize", applyWidgetLayout);
  applyWidgetLayout();
}

function installWidgetWindowControls() {
  document.querySelectorAll("[data-widget-control='minimize']").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const widget = button.closest(".widget[data-widget-id]");
      if (widget?.dataset.widgetId) setWidgetMinimized(widget.dataset.widgetId, true);
    });
  });
  document.querySelectorAll("[data-widget-control='maximize']").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const widget = button.closest(".widget[data-widget-id]");
      if (widget?.dataset.widgetId) toggleWidgetMaximized(widget.dataset.widgetId);
    });
  });
}

function installWidgetResizing() {
  const viewport = spaceSurface();
  if (!viewport) return;
  document.querySelectorAll(".widget-resize-handle").forEach((handle) => {
    const widget = handle.closest(".widget[data-widget-id]");
    if (!widget) return;
    handle.addEventListener("pointerdown", (event) => {
      if (!isPrimaryPointer(event)) return;
      if (widget.classList.contains("is-maximized")) return;
      event.preventDefault();
      event.stopPropagation();

      const viewportRect = spaceLogicalRect(viewport);
      const boardVisualRect = viewport.getBoundingClientRect();
      const widgetRect = widget.getBoundingClientRect();
      const startLeft = screenToLogicalPx(widgetRect.left - boardVisualRect.left);
      const startTop = screenToLogicalPx(widgetRect.top - boardVisualRect.top);
      const startWidth = widget.offsetWidth;
      const startHeight = widget.offsetHeight;
      const startX = event.clientX;
      const startY = event.clientY;
      const bounds = widgetDimensionBounds(widget.dataset.widgetId, viewportRect);
      const minWidth = bounds.minWidth;
      const minHeight = bounds.minHeight;
      let finished = false;

      widget.style.left = `${logicalToScreenPx(startLeft)}px`;
      widget.style.top = `${logicalToScreenPx(startTop)}px`;
      widget.style.right = "auto";
      widget.style.bottom = "auto";
      widget.style.width = `${startWidth}px`;
      widget.style.height = `${startHeight}px`;
      widget.style.aspectRatio = "auto";
      widget.classList.add("is-resizing");
      document.body.classList.add("is-widget-resizing");
      bringWidgetForward(widget);
      try {
        handle.setPointerCapture(event.pointerId);
      } catch {
        // Pointer capture can be unavailable during rapid touch/context transitions.
      }
      const startedAt = performance.now();
      recordUserEvent("workspace.widget_resize_started", {
        target: `widget:${widget.dataset.widgetId}`,
        summary: `Started resizing ${widget.dataset.widgetId}`,
        data: { widget_id: widget.dataset.widgetId, width: Math.round(startWidth), height: Math.round(startHeight) },
      });

      const move = (moveEvent) => {
        moveEvent.preventDefault();
        const movementBounds = widgetCanvasMovementBounds(widget);
        const maxWidth = Math.min(bounds.maxWidth, Math.max(minWidth, (movementBounds?.maxLeft || viewportRect.width) - startLeft + widget.offsetWidth));
        const maxHeight = Math.min(bounds.maxHeight, Math.max(minHeight, (movementBounds?.maxTop || viewportRect.height) - startTop + widget.offsetHeight));
        const width = clamp(startWidth + screenToLogicalPx(moveEvent.clientX - startX), minWidth, maxWidth);
        const height = clamp(startHeight + screenToLogicalPx(moveEvent.clientY - startY), minHeight, maxHeight);
        widget.style.width = `${width}px`;
        widget.style.height = `${height}px`;
      };

      const end = () => {
        if (finished) return;
        finished = true;
        widget.classList.remove("is-resizing");
        document.body.classList.remove("is-widget-resizing");
        handle.removeEventListener("pointermove", move);
        handle.removeEventListener("pointerup", end);
        handle.removeEventListener("pointercancel", end);
        window.removeEventListener("pointermove", move);
        window.removeEventListener("pointerup", end);
        window.removeEventListener("pointercancel", end);
        try {
          handle.releasePointerCapture(event.pointerId);
        } catch {
          // Capture may already be released by the browser.
        }
        state.widgetLayout[widget.dataset.widgetId] = {
          ...(state.widgetLayout[widget.dataset.widgetId] || {}),
          leftPx: Math.round(screenToLogicalPx(parseFloat(widget.style.left || "0"))),
          topPx: Math.round(screenToLogicalPx(parseFloat(widget.style.top || "0"))),
          widthPx: Math.round(widget.offsetWidth),
          heightPx: Math.round(widget.offsetHeight),
          leftPct: screenToLogicalPx(parseFloat(widget.style.left || "0")) / Math.max(1, viewportRect.width),
          topPct: screenToLogicalPx(parseFloat(widget.style.top || "0")) / Math.max(1, viewportRect.height),
          widthPct: widget.offsetWidth / Math.max(1, viewportRect.width),
          heightPct: widget.offsetHeight / Math.max(1, viewportRect.height),
          z: Number(widget.style.zIndex || 4),
        };
        saveWidgetLayout();
        if (widget.dataset.widgetId === "browser-proof") scheduleBrowserResizeSync();
        recordUserEvent("workspace.widget_resize_finished", {
          target: `widget:${widget.dataset.widgetId}`,
          summary: `Finished resizing ${widget.dataset.widgetId}`,
          data: {
            widget_id: widget.dataset.widgetId,
            width: widget.offsetWidth,
            height: widget.offsetHeight,
          },
          duration_ms: performance.now() - startedAt,
        });
      };

      handle.addEventListener("pointermove", move, { passive: false });
      handle.addEventListener("pointerup", end, { once: true });
      handle.addEventListener("pointercancel", end, { once: true });
      window.addEventListener("pointermove", move, { passive: false });
      window.addEventListener("pointerup", end, { once: true });
      window.addEventListener("pointercancel", end, { once: true });
    });
  });
}

function parseNativeBridgePayload(payload) {
  if (!payload) return payload;
  if (typeof payload === "object") return payload;
  if (typeof payload !== "string") return payload;
  try {
    return JSON.parse(payload);
  } catch {
    return null;
  }
}

function nativeBridgePayload(payload = {}) {
  try {
    return JSON.stringify(payload || {});
  } catch {
    return "{}";
  }
}

function androidDiagnosticsBridge() {
  const bridge = window.WasmAgentAndroidDiagnostics;
  return bridge && typeof bridge === "object" ? bridge : null;
}

function queueAndroidBridgeDiagnostic(kind, payload = {}, target = "diagnostics") {
  if (androidNativeBridgeDiagnosticsOff()) return;
  pendingAndroidBridgeDiagnostics.push({
    kind: cleanText(kind, "event").slice(0, 120),
    target,
    payload: redactClientBootTraceData(payload),
  });
  while (pendingAndroidBridgeDiagnostics.length > 80) pendingAndroidBridgeDiagnostics.shift();
}

function flushAndroidBridgeDiagnostics(reason = "flush") {
  deferAndroidBridgeDiagnostics = false;
  if (androidNativeBridgeDiagnosticsOff()) {
    pendingAndroidBridgeDiagnostics.length = 0;
    clientBootMark("android_bridge_diagnostics_disabled", { reason });
    return;
  }
  if (!pendingAndroidBridgeDiagnostics.length) return;
  const pendingCount = pendingAndroidBridgeDiagnostics.length;
  const droppedCount = Math.max(0, pendingCount - ANDROID_BRIDGE_DIAGNOSTIC_FLUSH_LIMIT);
  const queued = pendingAndroidBridgeDiagnostics
    .splice(Math.max(0, pendingCount - ANDROID_BRIDGE_DIAGNOSTIC_FLUSH_LIMIT), ANDROID_BRIDGE_DIAGNOSTIC_FLUSH_LIMIT);
  pendingAndroidBridgeDiagnostics.length = 0;
  if (droppedCount) {
    queued.unshift({
      kind: "startup_diagnostics_compacted",
      target: "diagnostics",
      payload: {
        reason,
        dropped_count: droppedCount,
        kept_count: queued.length,
      },
    });
  }
  const flushNext = (index = 0) => {
    const diagnosticsBridge = androidDiagnosticsBridge();
    const nativeBridge = window.wasmAgentNative;
    const entry = queued[index];
    if (!entry) {
      clientBootMark("android_bridge_diagnostics_flushed", {
        reason,
        count: queued.length,
        dropped_count: droppedCount,
      });
      return;
    }
    try {
      if (entry.target === "auth" && nativeBridge?.logAuthDiagnostic) {
        nativeBridge.logAuthDiagnostic(entry.kind, nativeBridgePayload(entry.payload));
      } else if (entry.target === "shell" && nativeBridge?.logDiagnostic) {
        nativeBridge.logDiagnostic(entry.kind, nativeBridgePayload(entry.payload));
      } else if (diagnosticsBridge?.record) {
        diagnosticsBridge.record(entry.kind, nativeBridgePayload(entry.payload));
      }
    } catch {
      // Deferred diagnostics must never affect the app.
    }
    window.setTimeout(() => flushNext(index + 1), ANDROID_BRIDGE_DIAGNOSTIC_CHUNK_DELAY_MS);
  };
  window.setTimeout(() => flushNext(0), isAndroidNativeShell() ? ANDROID_BRIDGE_DIAGNOSTIC_FLUSH_DELAY_MS : 1200);
}

function recordAndroidNativeDiagnostic(eventName, payload = {}) {
  if (deferAndroidBridgeDiagnostics) {
    queueAndroidBridgeDiagnostic(eventName, payload, "diagnostics");
    return null;
  }
  const bridge = androidDiagnosticsBridge();
  if (!bridge?.record) return null;
  try {
    return parseNativeBridgePayload(bridge.record(String(eventName || "event"), nativeBridgePayload(payload)));
  } catch {
    return null;
  }
}

const EXPECTED_VOICE_TUNING_BRIDGE_NAME = "WasmAgentNativeVoiceTuning";
const SUPPORTED_VOICE_TUNING_BRIDGE_NAMES = [
  EXPECTED_VOICE_TUNING_BRIDGE_NAME,
  "wasmAgentNative",
  "wasmAgentAndroid",
  "WasmAgentAndroid",
  "AndroidNativeBridge",
];
const VOICE_TUNING_BRIDGE_UNAVAILABLE_MESSAGE = "Native voice tuning is only available in the Android app. Reinstall the latest debug APK if you are already in the app.";
const TUNE_VOICE_BRIDGE_DETAILS_TTL_MS = 2500;
const TUNE_VOICE_STATUS_TTL_MS = 10000;
const VOICE_TUNING_SAFE_METHODS = [
  "getStatus",
  "getBuildInfo",
  "isRecordingSupported",
  "startVoiceTuningSample",
  "stopVoiceTuningSample",
  "deleteLastVoiceTuningSample",
  "resetVoiceTuningRecordings",
  "exportHermesDataset",
  "installHermesWakeModel",
  "installOpenWakeWordBundle",
  "getVoiceTuningDiagnostics",
  "voiceTuningStatus",
  "cancelVoiceTuning",
];

function tuneVoiceWebBuildId() {
  return Array.from(document.scripts)
    .map((item) => item.src || "")
    .find((src) => src.includes("/app.js"))
    ?.split("?v=")[1] || "";
}

function availableNativeBridgeNames() {
  return SUPPORTED_VOICE_TUNING_BRIDGE_NAMES.filter((name) => {
    const bridge = window[name];
    return bridge && typeof bridge === "object";
  });
}

function isAndroidWebViewGuess() {
  const ua = navigator.userAgent || "";
  return /Android/i.test(ua) && (/wv\)/i.test(ua) || /Version\/\d+\.\d+/i.test(ua) || /shell\/android-webview/i.test(ua) || /WASMAgentAndroid/i.test(ua));
}

function getNativeVoiceTuningBridge() {
  for (const name of SUPPORTED_VOICE_TUNING_BRIDGE_NAMES) {
    const bridge = window[name];
    if (!bridge || typeof bridge !== "object") continue;
    const methods = VOICE_TUNING_SAFE_METHODS.filter((method) => typeof bridge[method] === "function");
    const safeStatusMethod = typeof bridge.getStatus === "function"
      ? "getStatus"
      : typeof bridge.voiceTuningStatus === "function"
        ? "voiceTuningStatus"
        : typeof bridge.getVoiceTuningDiagnostics === "function"
          ? "getVoiceTuningDiagnostics"
          : "";
    const recordingMethod = typeof bridge.startVoiceTuningSample === "function" ? "startVoiceTuningSample" : "";
    if (methods.length || safeStatusMethod || recordingMethod) {
      return { bridge, name, methods, safeStatusMethod, recordingMethod };
    }
  }
  return { bridge: null, name: "", methods: [], safeStatusMethod: "", recordingMethod: "" };
}

function androidNativeVoiceBridge() {
  return getNativeVoiceTuningBridge().bridge;
}

function tuneVoiceBridgeDetails(options = {}) {
  const now = Date.now();
  if (!options.force && tuneVoiceState?.bridgeDetails && now - Number(tuneVoiceState.bridgeDetailsAtMs || 0) < TUNE_VOICE_BRIDGE_DETAILS_TTL_MS) {
    return tuneVoiceState.bridgeDetails;
  }
  const detected = getNativeVoiceTuningBridge();
  const androidShell = androidNativeShellInfo();
  const nativeFlagsPresent = androidShell.native === "android" && androidShell.shell === "android-webview";
  const methodsAvailable = detected.methods || [];
  const safeStatusMethod = detected.safeStatusMethod || "";
  const bridgeStatus = options.status && typeof options.status === "object" ? options.status : (tuneVoiceState?.status || {});
  let bridgeBuildInfo = {};
  let permissionState = {};
  let recordingSupported = null;
  try {
    if (detected.bridge && typeof detected.bridge.getBuildInfo === "function") {
      bridgeBuildInfo = parseNativeBridgePayload(detected.bridge.getBuildInfo()) || {};
    }
  } catch {}
  try {
    if (detected.bridge && typeof detected.bridge.isRecordingSupported === "function") {
      recordingSupported = Boolean(detected.bridge.isRecordingSupported());
    }
  } catch {}
  permissionState = bridgeStatus.permission_state && typeof bridgeStatus.permission_state === "object"
    ? bridgeStatus.permission_state
    : {};
  const failureReasons = [];
  if (!androidShell.isAndroidNativeShell) failureReasons.push("android_shell_not_detected");
  if (androidShell.native !== "android") failureReasons.push("missing_native_android_flag");
  if (androidShell.shell !== "android-webview") failureReasons.push("missing_android_webview_shell_flag");
  if (!detected.bridge) failureReasons.push("voice_tuning_bridge_object_missing");
  if (detected.bridge && !safeStatusMethod) failureReasons.push("voice_tuning_bridge_status_method_missing");
  const details = {
    failure_reason: failureReasons[0] || "",
    failure_reasons: failureReasons,
    android_shell_detected: androidShell.isAndroidNativeShell,
    is_android_webview_guess: isAndroidWebViewGuess(),
    native_flag: androidShell.native,
    shell_flag: androidShell.shell,
    native_flags_present: nativeFlagsPresent,
    available_native_bridge_names: availableNativeBridgeNames(),
    expected_voice_tuning_bridge_name: EXPECTED_VOICE_TUNING_BRIDGE_NAME,
    voice_tuning_bridge_available: Boolean(detected.bridge),
    detected_voice_tuning_bridge_name: detected.name || "",
    voice_tuning_bridge_methods_available: methodsAvailable,
    voice_tuning_bridge_status_method: safeStatusMethod,
    voice_tuning_bridge_recording_method: detected.recordingMethod || "",
    bridge_safe_ready: Boolean(detected.bridge && safeStatusMethod),
    bridge_status: cleanText(bridgeStatus.bridge_status || bridgeStatus.message || "", ""),
    recording_supported: typeof recordingSupported === "boolean" ? recordingSupported : Boolean(bridgeStatus.recording_supported),
    permission_state: permissionState,
    has_android_bridge_object: Boolean(window.wasmAgentAndroid),
    user_agent: navigator.userAgent || "",
    location_href: window.location?.href || "",
    apk_build_id: cleanText(bridgeBuildInfo.apk_build_id || androidShell.packageInfo?.buildId || androidShell.buildId, ""),
    bridge_build_id: cleanText(bridgeBuildInfo.bridge_build_id || bridgeStatus.bridge_build_id, ""),
    web_build_id: cleanText(tuneVoiceWebBuildId(), ""),
  };
  if (tuneVoiceState) {
    tuneVoiceState.bridgeDetails = details;
    tuneVoiceState.bridgeDetailsAtMs = now;
  }
  return details;
}

function tuneVoiceFailureSummary(details = tuneVoiceBridgeDetails()) {
  const bridgeLine = details.voice_tuning_bridge_available
    ? details.recording_supported
      ? "Native voice tuning bridge connected and ready."
      : "Android bridge connected; recording not enabled yet."
    : VOICE_TUNING_BRIDGE_UNAVAILABLE_MESSAGE;
  return [
    bridgeLine,
    `reason: ${details.failure_reason || "unknown"}`,
    `android shell: ${details.android_shell_detected ? "true" : "false"}`,
    `native flags: ${details.native_flags_present ? "present" : "missing"} (${details.native_flag || "-"} / ${details.shell_flag || "-"})`,
    `bridge object: ${details.voice_tuning_bridge_available ? details.detected_voice_tuning_bridge_name || "present" : "missing"}`,
    `bridge methods: ${(details.voice_tuning_bridge_methods_available || []).join(", ") || "-"}`,
    `permission: ${typeof details.permission_state?.record_audio === "string" ? details.permission_state.record_audio : "-"}`,
    `apk build: ${details.apk_build_id || "-"}`,
    `bridge build: ${details.bridge_build_id || "-"}`,
    `web build: ${details.web_build_id || "-"}`,
  ].join("\n");
}

function tuneVoiceBridgeDevPanelMarkup(summary = "Native bridge details", details = tuneVoiceBridgeDetails()) {
  const rows = Object.entries(details).map(([key, value]) => {
    const display = Array.isArray(value) ? value.join(", ") : String(value);
    return `<div><dt>${tuneVoiceEscapeHtml(key)}</dt><dd>${tuneVoiceEscapeHtml(display || "-")}</dd></div>`;
  }).join("");
  return `
    <details class="tune-voice-dev-panel">
      <summary>${tuneVoiceEscapeHtml(summary)}</summary>
      <dl>${rows}</dl>
      <button type="button" data-tune-voice-action="recheck-native-bridge">Recheck Native Bridge</button>
    </details>
  `;
}

function homeTuneVoiceProgressLabel(payload = {}) {
  const counts = payload?.counts && typeof payload.counts === "object" ? payload.counts : {};
  const progress = payload?.progress && typeof payload.progress === "object" ? payload.progress : {};
  const positivesCurrent = Number(progress.positives_current ?? counts.positive ?? 0) || 0;
  const positivesRequired = Number(progress.positives_required ?? 5) || 5;
  const negativesCurrent = Number(progress.negatives_current ?? counts.negative ?? (
    (Number(counts.negative_silence) || 0) + (Number(counts.negative_speech) || 0) + (Number(counts.negative_noise) || 0)
  )) || 0;
  const negativesRequired = Number(progress.negatives_required ?? 10) || 10;
  const ready = Boolean(payload?.dataset_ready || payload?.thresholds?.tiny);
  return `positives: ${positivesCurrent} / ${positivesRequired} · negatives: ${negativesCurrent} / ${negativesRequired}${ready ? " · dataset ready" : ""}`;
}

function homeTuneVoiceNextCategory(payload = {}) {
  const counts = payload?.counts && typeof payload.counts === "object" ? payload.counts : {};
  const positive = Number(counts.positive || 0) || 0;
  const silence = Number(counts.negative_silence || 0) || 0;
  const speech = Number(counts.negative_speech || 0) || 0;
  const noise = Number(counts.negative_noise || 0) || 0;
  if (positive < 5) return "positive";
  if (silence < 4) return "negative/silence";
  if (speech < 3) return "negative/speech";
  if (noise < 3) return "negative/noise";
  return "positive";
}

function homeTuneVoicePromptLabel(category = "positive") {
  const cleanCategory = cleanText(category, "positive");
  if (cleanCategory === "positive") return "Record Hermes positive";
  if (cleanCategory.includes("silence")) return "Record silence negative";
  if (cleanCategory.includes("speech")) return "Record speech negative";
  return "Record noise negative";
}

function homeTuneVoiceRecordingLabel(category = "positive") {
  const prompt = homeTuneVoicePromptLabel(category).replace(/^Record /, "Recording ");
  return `${prompt}...`;
}

function tuneVoiceEscapeHtml(value = "") {
  return String(value).replace(/[&<>"']/g, (char) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    "\"": "&quot;",
    "'": "&#39;",
  }[char] || char));
}

