const tuneVoiceState = {
  step: 0,
  status: null,
  message: "",
  phase: "idle",
  countdown: 0,
  recordTimeout: 0,
  recordStartedAt: 0,
  lastCategory: "positive",
  lastRecordKind: "",
  lastRecordPath: "",
  lastRecordDurationMs: 0,
  diagnostics: {},
  speechPromptIndex: 0,
  exportResult: null,
  bridgeInitializingUntil: 0,
  bridgeDetails: null,
  bridgeDetailsAtMs: 0,
  statusAtMs: 0,
  deferredStatusTimer: 0,
  resetConfirmUntil: 0,
};

const TUNE_VOICE_STEPS = [
  { id: "intro", title: "Train Hermes Wake", subtitle: "Balanced personalized wake dataset" },
  { id: "positive-normal", title: "Say Hermes Normally", category: "positive", target: 10, progressLabel: "Normal Hermes", button: "Record Normal", source: "space-home:tune-voice:positive-normal", prompt: "Say Hermes normally" },
  { id: "positive-soft", title: "Say Hermes Softly", category: "positive", target: 10, progressLabel: "Soft Hermes", button: "Record Soft", source: "space-home:tune-voice:positive-soft", prompt: "Say Hermes softly" },
  { id: "positive-far", title: "Say Hermes Farther Away", category: "positive", target: 10, progressLabel: "Farther Hermes", button: "Record Farther", source: "space-home:tune-voice:positive-far", prompt: "Say Hermes from farther away" },
  { id: "positive-desk", title: "Phone On Desk", category: "positive", target: 10, progressLabel: "Desk Hermes", button: "Record Desk", source: "space-home:tune-voice:positive-desk", prompt: "Put the phone on the desk and say Hermes" },
  { id: "positive-noisy", title: "Noisy Room Hermes", category: "positive", target: 10, progressLabel: "Noisy Hermes", button: "Record Noisy", source: "space-home:tune-voice:positive-noisy", prompt: "Say Hermes in a noisy room" },
  { id: "silence", title: "Stay Silent", category: "negative/silence", target: 20, progressLabel: "Silence/background", button: "Record Silence", source: "space-home:tune-voice:negative-silence", prompt: "Stay silent" },
  { id: "speech", title: "Normal Speech Without Hermes", category: "negative/speech", target: 20, progressLabel: "Speech negatives", button: "Record This Phrase", source: "space-home:tune-voice:negative-speech", prompt: "Speak normally without saying Hermes" },
  { id: "confuser", title: "Similar Words, Not Hermes", category: "negative/speech", target: 10, progressLabel: "Confuser negatives", button: "Record Confuser", source: "space-home:tune-voice:negative-confuser", prompt: "Say similar words, but not Hermes" },
  { id: "noise", title: "Noisy Room Background", category: "negative/noise", target: 10, progressLabel: "Noise samples", button: "Record Room Noise", source: "space-home:tune-voice:negative-noise", prompt: "Let the room sound normal. Do not speak." },
  { id: "readiness", title: "Dataset Readiness", subtitle: "Quality gates and diagnostics" },
  { id: "export", title: "Export Hermes Dataset", subtitle: "Create hermes-dataset.zip" },
];

function tuneVoiceCounts(status = tuneVoiceState.status || {}) {
  const counts = status?.counts && typeof status.counts === "object" ? status.counts : {};
  const diagnostics = status?.diagnostics && typeof status.diagnostics === "object" ? status.diagnostics : {};
  const positive = Number(status.positive_count ?? diagnostics.positive_count ?? counts.positive ?? 0) || 0;
  const silence = Number(status.negative_silence_count ?? diagnostics.negative_silence_count ?? counts.negative_silence ?? 0) || 0;
  const speech = Number(status.negative_speech_count ?? diagnostics.negative_speech_count ?? counts.negative_speech ?? 0) || 0;
  const noise = Number(status.negative_noise_count ?? diagnostics.negative_noise_count ?? counts.negative_noise ?? 0) || 0;
  return {
    positive,
    silence,
    speech,
    noise,
    negative: Number(status.total_negative_count ?? diagnostics.total_negative_count ?? counts.negative ?? silence + speech + noise) || 0,
    zeroByte: Number(diagnostics.zero_byte_count ?? status.zero_byte_count ?? 0) || 0,
    invalidFormat: Number(diagnostics.invalid_format_count ?? status.invalid_format_count ?? 0) || 0,
    smokeReady: Boolean(status.smoke_gate_ready ?? diagnostics.smoke_gate_ready ?? status.dataset_ready ?? status.thresholds?.tiny),
    realReady: Boolean(status.real_gate_ready ?? diagnostics.real_gate_ready ?? status.thresholds?.production),
  };
}

function tuneVoiceRecordKindForCategory(category = "") {
  if (category === "positive") return "hermes";
  if (category === "negative/silence") return "silence";
  if (category === "negative/speech") return "speech";
  if (category === "negative/noise") return "noise";
  return "";
}

function tuneVoiceRecordLabelForCategory(category = "") {
  return category === "positive" ? "positive" : category.startsWith("negative/") ? "negative" : "";
}

function tuneVoiceLogDiagnostic(event, payload = {}, options = {}) {
  const nowMs = Date.now();
  const previous = tuneVoiceState.diagnostics[event];
  const sampleMs = Number(options.sampleMs || 0);
  if (!options.force && sampleMs > 0 && previous?.atMs && nowMs - previous.atMs < sampleMs) {
    return previous;
  }
  const entry = {
    event,
    at: new Date().toISOString(),
    atMs: nowMs,
    ...payload,
  };
  tuneVoiceState.diagnostics[event] = entry;
  if (options.console !== false) console.info("[train-hermes-wake]", event, payload);
  return entry;
}

function tuneVoiceClearRecordTimeout() {
  if (tuneVoiceState.recordTimeout) {
    window.clearTimeout(tuneVoiceState.recordTimeout);
    tuneVoiceState.recordTimeout = 0;
  }
}

function tuneVoiceFinishRecord(message, detail = {}) {
  tuneVoiceClearRecordTimeout();
  tuneVoiceState.phase = "idle";
  tuneVoiceState.message = message;
  tuneVoiceState.lastRecordKind = cleanText(detail.kind || tuneVoiceRecordKindForCategory(detail.category || tuneVoiceState.lastCategory), "");
  tuneVoiceState.lastRecordPath = cleanText(detail.path || detail.storage_path || "", "");
  tuneVoiceState.lastRecordDurationMs = Number(detail.duration_ms || detail.durationMs || 0) || 0;
  tuneVoiceLogDiagnostic("wizard_record_state", {
    phase: tuneVoiceState.phase,
    message,
    last_record_kind: tuneVoiceState.lastRecordKind,
    last_record_path: tuneVoiceState.lastRecordPath,
    last_record_duration_ms: tuneVoiceState.lastRecordDurationMs,
  });
}

function tuneVoiceFailureMessage(error = "", fallback = "Unexpected error. Try again.") {
  const code = cleanText(error, "");
  if (code === "permission_denied" || code === "record_audio_permission_missing") return "Permission denied. Microphone permission is required to record training samples.";
  if (code === "recorder_unavailable" || code === "audio_record_initialization_failed") return "Recorder unavailable. Try again.";
  if (code === "too_quiet") return "Too quiet. Try again.";
  if (code === "too_short") return "Too short. Try again.";
  if (code === "excessive_noise") return "Background audio is too loud for a silence sample. Try a quieter spot or lower mic gain.";
  if (code === "clipped_audio") return "Audio clipped. Move farther away and try again.";
  if (code === "mostly_silence") return "Voice sample was mostly silence. Speak clearly and try again.";
  if (code === "duplicate_sample") return "Sample is too similar to a previous one. Vary the recording and try again.";
  if (code === "timeout") return "Recording timed out. Try again.";
  if (code === "native_bridge_error") return "Native bridge error. Try again.";
  if (code === "voice_tuning_cancelled") return "Recording cancelled.";
  return cleanText(error, fallback);
}

function tuneVoiceCountForStep(step, counts = tuneVoiceCounts()) {
  if (step?.category === "positive") return counts.positive;
  if (step?.id === "silence") return counts.silence;
  if (step?.id === "speech") return counts.speech;
  if (step?.id === "noise") return counts.noise;
  return 0;
}

function getTuneVoiceStatus(options = {}) {
  const now = Date.now();
  if (!options.force && tuneVoiceState.status && now - Number(tuneVoiceState.statusAtMs || 0) < TUNE_VOICE_STATUS_TTL_MS) {
    return tuneVoiceState.status;
  }
  const { bridge, name, safeStatusMethod } = getNativeVoiceTuningBridge();
  tuneVoiceLogDiagnostic("frontend_bridge_detection", tuneVoiceBridgeDetails({ force: options.force }), { sampleMs: 2000, console: false });
  if (bridge) tuneVoiceState.bridgeInitializingUntil = 0;
  if (!safeStatusMethod || typeof bridge?.[safeStatusMethod] !== "function") return tuneVoiceState.status || {};
  try {
    const status = parseNativeBridgePayload(bridge[safeStatusMethod]()) || {};
    if (name) status.detected_voice_tuning_bridge_name = name;
    tuneVoiceState.status = status;
    tuneVoiceState.statusAtMs = now;
    tuneVoiceState.bridgeDetailsAtMs = 0;
    renderHomeTuneVoiceState(status.dataset_ready || status.thresholds?.tiny ? "saved" : "idle", "", status);
    return status;
  } catch {
    return tuneVoiceState.status || {};
  }
}

function scheduleTuneVoiceStatusRefresh(reason = "deferred_status") {
  if (tuneVoiceState.deferredStatusTimer) window.clearTimeout(tuneVoiceState.deferredStatusTimer);
  tuneVoiceState.deferredStatusTimer = window.setTimeout(() => {
    tuneVoiceState.deferredStatusTimer = 0;
    if (!els.tuneVoiceModal || els.tuneVoiceModal.hidden) return;
    getTuneVoiceStatus({ force: true, reason });
    renderTuneVoiceWizard({ skipStatus: true });
  }, 80);
}

function tuneVoiceTotalRecordings(counts = tuneVoiceCounts()) {
  return counts.positive + counts.silence + counts.speech + counts.noise;
}

function tuneVoiceReadinessLabel(counts = tuneVoiceCounts()) {
  if (counts.realReady || (counts.positive >= 50 && counts.negative >= 200)) return "Recommended quality reached";
  if (counts.smokeReady || (counts.positive >= 5 && counts.negative >= 10)) return "Ready for smoke model";
  return "Keep recording for better accuracy";
}

function tuneVoiceLowCountWarning(nextIndex) {
  const current = TUNE_VOICE_STEPS[tuneVoiceState.step];
  const counts = tuneVoiceCounts();
  if (nextIndex <= tuneVoiceState.step || !current?.category) return "";
  const currentCount = tuneVoiceCountForStep(current, counts);
  if (currentCount >= Math.min(current.target || 0, current.id === "speech" ? 10 : 5)) return "";
  return `${current.progressLabel} are still low. You can skip ahead, but more clips improve accuracy.`;
}

function tuneVoiceProgressMarkup() {
  const counts = tuneVoiceCounts();
  const cells = [
    ["Hermes", counts.positive, 50],
    ["Silence", counts.silence, 20],
    ["Speech/confusers", counts.speech, 30],
    ["Noise", counts.noise, 10],
  ];
  return cells.map(([label, value, target]) => `
    <span class="tune-voice-progress-chip${value >= target ? " is-complete" : ""}">
      <strong>${tuneVoiceEscapeHtml(label)}</strong>
      <em>${value} / ${target}</em>
    </span>
  `).join("");
}

function renderTuneVoiceWizard(options = {}) {
  if (!els.tuneVoiceModal || els.tuneVoiceModal.hidden) return;
  const shouldRefreshStatus = Boolean(options.refreshStatus);
  const status = shouldRefreshStatus ? getTuneVoiceStatus({ force: Boolean(options.forceStatus), reason: options.reason || "render" }) : (tuneVoiceState.status || {});
  const counts = tuneVoiceCounts(status);
  const step = TUNE_VOICE_STEPS[tuneVoiceState.step] || TUNE_VOICE_STEPS[0];
  const bridgeDetails = tuneVoiceBridgeDetails({ status });
  const bridgeInitializing = !bridgeDetails.voice_tuning_bridge_available && tuneVoiceState.bridgeInitializingUntil > Date.now();
  if (els.tuneVoiceTitle) els.tuneVoiceTitle.textContent = step.title;
  if (els.tuneVoiceSubtitle) els.tuneVoiceSubtitle.textContent = step.subtitle || tuneVoiceReadinessLabel(counts);
  if (els.tuneVoiceProgress) els.tuneVoiceProgress.innerHTML = tuneVoiceProgressMarkup();
  if (els.tuneVoiceMessage) {
    els.tuneVoiceMessage.textContent = tuneVoiceState.message || (bridgeInitializing ? "Checking native voice tuning bridge..." : "");
  }
  if (els.tuneVoiceResetButton) {
    const totalRecordings = tuneVoiceTotalRecordings(counts);
    const confirmingReset = tuneVoiceState.resetConfirmUntil > Date.now();
    els.tuneVoiceResetButton.hidden = !bridgeDetails.voice_tuning_bridge_available && !bridgeInitializing;
    els.tuneVoiceResetButton.disabled = tuneVoiceState.phase !== "idle" || (!confirmingReset && totalRecordings <= 0);
    els.tuneVoiceResetButton.textContent = confirmingReset ? `Confirm Reset (${totalRecordings})` : "Reset Recordings";
    els.tuneVoiceResetButton.classList.toggle("is-confirming", confirmingReset);
  }
  if (els.tuneVoiceBackButton) {
    els.tuneVoiceBackButton.disabled = tuneVoiceState.step <= 0 && tuneVoiceState.phase === "idle";
    els.tuneVoiceBackButton.textContent = tuneVoiceState.phase === "recording" || tuneVoiceState.phase === "saving" || tuneVoiceState.phase === "countdown" ? "Cancel" : "Back";
  }
  if (els.tuneVoiceNextButton) {
    els.tuneVoiceNextButton.hidden = tuneVoiceState.step >= TUNE_VOICE_STEPS.length - 1;
    els.tuneVoiceNextButton.disabled = tuneVoiceState.phase !== "idle";
    els.tuneVoiceNextButton.textContent = tuneVoiceState.step === 0 ? "Skip Intro" : "Next";
  }
  if (els.tuneVoiceDeleteLastButton) {
    els.tuneVoiceDeleteLastButton.hidden = !step.category;
    els.tuneVoiceDeleteLastButton.disabled = tuneVoiceState.phase !== "idle" || tuneVoiceCountForStep(step, counts) <= 0;
  }
  if (els.tuneVoiceRetryLastButton) {
    els.tuneVoiceRetryLastButton.hidden = !step.category;
    els.tuneVoiceRetryLastButton.disabled = tuneVoiceState.phase !== "idle";
  }
  if (els.tuneVoiceRecordButton) {
    els.tuneVoiceRecordButton.disabled = tuneVoiceState.phase !== "idle" || (!bridgeDetails.voice_tuning_bridge_available && !bridgeInitializing) || (step.id === "export" && !counts.smokeReady);
    els.tuneVoiceRecordButton.hidden = false;
    els.tuneVoiceRecordButton.textContent = step.id === "intro" ? "Start" : step.id === "export" ? "Export Hermes Dataset" : step.button || "Record";
  }
  if (!els.tuneVoiceBody) return;
  if (!bridgeDetails.voice_tuning_bridge_available && !bridgeInitializing) {
    els.tuneVoiceBody.innerHTML = `
      <div class="tune-voice-copy">
        <p>${tuneVoiceEscapeHtml(tuneVoiceFailureSummary(bridgeDetails))}</p>
        ${tuneVoiceBridgeDevPanelMarkup("Developer details", bridgeDetails)}
      </div>
    `;
    return;
  }
  if (step.id === "intro") {
    els.tuneVoiceBody.innerHTML = `
      <div class="tune-voice-copy">
        <p>Your phone will learn to recognize the wake phrase 'Hermes'.</p>
        <p>We'll record short one-second clips across normal, soft, far, desk, and noisy-room positives.</p>
        <p>Then we'll record silence, background, normal speech, and similar-word confusers to reduce false wakes.</p>
        <p>This does not enable always-on wake automatically.</p>
        ${tuneVoiceBridgeDevPanelMarkup("Developer details", bridgeDetails)}
      </div>
    `;
  } else if (step.category) {
    const instruction = step.prompt || (step.category === "positive" ? "Say Hermes normally" : "Record the requested negative sample");
    const prompt = step.id === "speech"
      ? TUNE_VOICE_SPEECH_PROMPTS[tuneVoiceState.speechPromptIndex % TUNE_VOICE_SPEECH_PROMPTS.length]
      : step.id === "confuser"
        ? TUNE_VOICE_CONFUSER_PROMPTS[tuneVoiceState.speechPromptIndex % TUNE_VOICE_CONFUSER_PROMPTS.length]
        : "";
    const count = tuneVoiceCountForStep(step, counts);
    const phaseText = tuneVoiceState.phase === "countdown" ? `${tuneVoiceState.countdown}...` : tuneVoiceState.phase === "recording" ? "Recording for 1 second" : tuneVoiceState.phase === "saving" ? "Saving..." : cleanText(tuneVoiceState.message, "");
    const diagnostics = [
      ["frontend_record_request_sent", tuneVoiceState.diagnostics.frontend_record_request_sent?.at || ""],
      ["renderer_record_result_received", tuneVoiceState.diagnostics.renderer_record_result_received?.at || ""],
      ["wizard_record_state", tuneVoiceState.phase],
      ["last_record_kind", tuneVoiceState.lastRecordKind],
      ["last_record_path", tuneVoiceState.lastRecordPath],
      ["last_record_duration_ms", tuneVoiceState.lastRecordDurationMs || ""],
      ["last_rms_db", tuneVoiceState.diagnostics.renderer_record_result_received?.quality_metrics?.rms_db ?? ""],
      ["last_peak_db", tuneVoiceState.diagnostics.renderer_record_result_received?.quality_metrics?.peak_db ?? ""],
      ["last_clipping_ratio", tuneVoiceState.diagnostics.renderer_record_result_received?.quality_metrics?.clipping_ratio ?? ""],
      ["last_silence_ratio", tuneVoiceState.diagnostics.renderer_record_result_received?.quality_metrics?.silence_ratio ?? ""],
      ["last_rejection_reason", tuneVoiceState.diagnostics.renderer_record_result_received?.rejection_reason || ""],
      ["last_raw_error", tuneVoiceState.diagnostics.renderer_record_result_received?.raw_error || ""],
    ];
    els.tuneVoiceBody.innerHTML = `
      <div class="tune-voice-record-panel">
        <p class="tune-voice-instruction">${tuneVoiceEscapeHtml(instruction)}</p>
        ${prompt ? `<div class="tune-voice-prompt">${tuneVoiceEscapeHtml(prompt)}</div>` : ""}
        <div class="tune-voice-meter" aria-live="polite">${tuneVoiceEscapeHtml(phaseText || "Ready")}</div>
        <div class="tune-voice-step-progress">
          <span>${tuneVoiceEscapeHtml(step.progressLabel)}: ${count} / ${step.target}</span>
          ${step.category === "positive" ? "<span>Balanced target: 50</span>" : ""}
        </div>
        <details class="tune-voice-dev-panel">
          <summary>Recording diagnostics</summary>
          <dl>${diagnostics.map(([key, value]) => `<div><dt>${tuneVoiceEscapeHtml(key)}</dt><dd>${tuneVoiceEscapeHtml(String(value || "-"))}</dd></div>`).join("")}</dl>
        </details>
        ${tuneVoiceBridgeDevPanelMarkup("Native bridge details", bridgeDetails)}
      </div>
    `;
  } else if (step.id === "readiness") {
    const rows = [
      ["positive_count", counts.positive],
      ["negative_silence_count", counts.silence],
      ["negative_speech_count", counts.speech],
      ["negative_noise_count", counts.noise],
      ["total_negative_count", counts.negative],
      ["readiness_score", status.readiness_score ?? "-"],
      ["zero_byte_count", counts.zeroByte],
      ["invalid_format_count", counts.invalidFormat],
      ["smoke_gate_ready", counts.smokeReady ? "yes" : "no"],
      ["real_gate_ready", counts.realReady ? "yes" : "no"],
    ];
    els.tuneVoiceBody.innerHTML = `
      <div class="tune-voice-readiness ${counts.realReady ? "is-real" : counts.smokeReady ? "is-smoke" : ""}">
        <strong>${tuneVoiceEscapeHtml(tuneVoiceReadinessLabel(counts))}</strong>
        <span>${counts.realReady ? "Balanced export is ready for cloud training." : counts.smokeReady ? "Export is available, but production training still needs the balanced targets." : "Need at least 5 Hermes samples and 10 negative samples."}</span>
      </div>
      <dl class="tune-voice-diagnostics">
        ${rows.map(([label, value]) => `<div><dt>${tuneVoiceEscapeHtml(label)}</dt><dd>${tuneVoiceEscapeHtml(String(value))}</dd></div>`).join("")}
      </dl>
      ${tuneVoiceBridgeDevPanelMarkup("Native bridge details", bridgeDetails)}
    `;
  } else {
    const result = tuneVoiceState.exportResult;
    const exportText = result?.ok
      ? `Your dataset zip is ready. Use it with the repo trainer to create base_hermes.onnx. ${cleanText(result.path || result.filename, "")}`
      : result?.error
        ? `Export failed: ${cleanText(result.error, "unknown error")}`
        : counts.smokeReady
          ? "Ready to export a smoke dataset."
          : "Smoke gate is not ready yet. You can keep recording, then export once you have at least 5 Hermes and 10 negative clips.";
    els.tuneVoiceBody.innerHTML = `
      <div class="tune-voice-export">
        <p>${tuneVoiceEscapeHtml(tuneVoiceState.phase === "exporting" ? "Export in progress..." : exportText)}</p>
        <details>
          <summary>Developer command</summary>
          <pre>python3 tools/voice/import-hermes-dataset.py hermes-dataset.zip --out data/voice/hermes
python3 tools/voice/train-hermes-wake.py --dataset data/voice/hermes --out native/android/app/src/main/assets/voice/base_hermes.onnx</pre>
        </details>
        ${tuneVoiceBridgeDevPanelMarkup("Native bridge details", bridgeDetails)}
      </div>
    `;
  }
}

function openTuneVoiceWizard() {
  if (!els.tuneVoiceModal) return;
  tuneVoiceState.bridgeInitializingUntil = Date.now() + 1500;
  tuneVoiceState.step = 0;
  tuneVoiceState.message = "";
  tuneVoiceState.phase = "idle";
  tuneVoiceState.exportResult = null;
  els.tuneVoiceModal.hidden = false;
  renderTuneVoiceWizard({ skipStatus: true });
  scheduleTuneVoiceStatusRefresh("modal_open");
  window.setTimeout(() => {
    if (!els.tuneVoiceModal || els.tuneVoiceModal.hidden) return;
    if (tuneVoiceState.bridgeInitializingUntil && tuneVoiceState.bridgeInitializingUntil <= Date.now()) renderTuneVoiceWizard({ skipStatus: true });
  }, 1600);
  pushUiNavigationLayer("tune-voice-modal", () => closeTuneVoiceWizard({ skipHistory: true, skipStack: true }));
}

function maybeOpenRequestedTuneVoiceWizard(reason = "native_request") {
  let params = null;
  try {
    params = new URL(window.location.href).searchParams;
  } catch {
    params = new URLSearchParams();
  }
  const requested = cleanText(params.get("native_screen") || params.get("debug_screen"), "").toLowerCase();
  if (requested !== "train-hermes-wake") return false;
  if (!state.authUser) return false;
  if (els.tuneVoiceModal && !els.tuneVoiceModal.hidden) return true;
  tuneVoiceLogDiagnostic("native_requested_tune_voice_open", { reason, requested });
  openTuneVoiceWizard();
  return true;
}

function maybeOpenRequestedWakeWordModal(reason = "native_request") {
  let params = null;
  try {
    params = new URL(window.location.href).searchParams;
  } catch {
    params = new URLSearchParams();
  }
  const requested = cleanText(params.get("native_screen") || params.get("debug_screen"), "").toLowerCase();
  if (requested !== "wake-word" && requested !== LEGACY_WAKE_WORD_NATIVE_SCREEN) return false;
  if (!state.authUser) return false;
  triggerAgentAvatarWakeShine({
    listener_mode: "awake",
    last_wake_at: Date.now(),
    wake_hit_count: Number(state.nativeVoiceWakeLastHitCount || 0) + 1,
  }, reason);
  if (els.wakeWordModal && !els.wakeWordModal.hidden) return true;
  openWakeWordModal({ source: reason, autoStart: false });
  return true;
}

function collectTuneVoiceRuntimeDiagnostics(options = {}) {
  const details = tuneVoiceBridgeDetails({ force: true, status: tuneVoiceState.status || {} });
  const payload = {
    requested_by: cleanText(options.requested_by, ""),
    tune_voice_modal_open: Boolean(els.tuneVoiceModal && !els.tuneVoiceModal.hidden),
    active_panel: cleanText(state.activePanel || "", ""),
    auth_state: state.authUser ? "authenticated" : state.authChecked ? "locked" : "checking",
    user_agent: details.user_agent,
    url: details.location_href,
    native_flag_state: details.native_flag,
    shell_flag_state: details.shell_flag,
    native_flags_present: details.native_flags_present,
    bridge_object_present: details.voice_tuning_bridge_available,
    detected_bridge_object: details.detected_voice_tuning_bridge_name || "",
    android_shell_detected: details.android_shell_detected,
    available_native_bridge_names: details.available_native_bridge_names,
    apk_build_id: details.apk_build_id,
    web_build_id: details.web_build_id,
    failure_reason: details.failure_reason,
    failure_reasons: details.failure_reasons,
    bridge_details: details,
    recording_active: tuneVoiceState.phase === "recording" || tuneVoiceState.phase === "saving" || tuneVoiceState.phase === "countdown",
    recording_started_automatically: false,
  };
  tuneVoiceLogDiagnostic("frontend_bridge_detection", payload, { force: true });
  return payload;
}

window.__wasmAgentTuneVoice = {
  diagnostics(requestedBy = "") {
    return collectTuneVoiceRuntimeDiagnostics({ requested_by: requestedBy });
  },
  open(requestedBy = "") {
    maybeOpenRequestedTuneVoiceWizard(requestedBy || "native_open");
    return collectTuneVoiceRuntimeDiagnostics({ requested_by: requestedBy || "native_open" });
  },
};

function closeTuneVoiceWizard(options = {}) {
  if (!els.tuneVoiceModal) return;
  if (!options.skipHistory && closeUiNavigationLayer("tune-voice-modal")) return;
  els.tuneVoiceModal.hidden = true;
  tuneVoiceClearRecordTimeout();
  if (tuneVoiceState.deferredStatusTimer) {
    window.clearTimeout(tuneVoiceState.deferredStatusTimer);
    tuneVoiceState.deferredStatusTimer = 0;
  }
  tuneVoiceState.phase = "idle";
  if (!options.skipStack) closeUiNavigationLayer("tune-voice-modal", { skipHistory: true, replaceHistory: true });
}

function setTuneVoiceStep(stepIndex) {
  tuneVoiceState.resetConfirmUntil = 0;
  const warning = tuneVoiceLowCountWarning(stepIndex);
  tuneVoiceState.step = clamp(stepIndex, 0, TUNE_VOICE_STEPS.length - 1);
  tuneVoiceState.phase = "idle";
  tuneVoiceState.message = warning;
  renderTuneVoiceWizard({ skipStatus: true });
}

function resetTuneVoiceRecordings() {
  const counts = tuneVoiceCounts();
  const totalRecordings = tuneVoiceTotalRecordings(counts);
  if (tuneVoiceState.phase !== "idle") return;
  if (totalRecordings <= 0) {
    tuneVoiceState.message = "No recordings to reset.";
    renderTuneVoiceWizard({ skipStatus: true });
    return;
  }
  const now = Date.now();
  if (tuneVoiceState.resetConfirmUntil <= now) {
    tuneVoiceState.resetConfirmUntil = now + 9000;
    tuneVoiceState.message = `Click Confirm Reset to delete ${totalRecordings} saved recordings and the exported dataset zip.`;
    renderTuneVoiceWizard({ skipStatus: true });
    return;
  }
  const bridge = androidNativeVoiceBridge();
  try {
    if (typeof bridge?.resetVoiceTuningRecordings !== "function") throw new Error("Reset requires the latest Android native bridge.");
    const result = parseNativeBridgePayload(bridge.resetVoiceTuningRecordings());
    tuneVoiceState.status = result?.status || tuneVoiceState.status;
    tuneVoiceState.statusAtMs = Date.now();
    tuneVoiceState.exportResult = null;
    tuneVoiceState.resetConfirmUntil = 0;
    tuneVoiceState.lastRecordKind = "";
    tuneVoiceState.lastRecordPath = "";
    tuneVoiceState.lastRecordDurationMs = 0;
    tuneVoiceState.diagnostics.renderer_record_result_received = null;
    tuneVoiceState.message = result?.ok ? "Recordings reset. Fresh dataset ready." : cleanText(result?.error, "Reset failed.");
    renderHomeTuneVoiceState("idle", tuneVoiceState.message, tuneVoiceState.status);
  } catch (error) {
    tuneVoiceState.message = errorMessage(error) || "Reset failed.";
  }
  renderTuneVoiceWizard({ skipStatus: true });
}

function cancelTuneVoiceRecording() {
  tuneVoiceClearRecordTimeout();
  const bridge = androidNativeVoiceBridge();
  try {
    if (typeof bridge?.cancelVoiceTuning === "function") bridge.cancelVoiceTuning();
  } catch (error) {
    tuneVoiceLogDiagnostic("native_record_error", { error: "native_bridge_error", message: errorMessage(error) });
  }
  tuneVoiceFinishRecord("Recording cancelled.", {
    category: tuneVoiceState.lastCategory,
    kind: tuneVoiceRecordKindForCategory(tuneVoiceState.lastCategory),
    duration_ms: Date.now() - tuneVoiceState.recordStartedAt,
  });
  renderTuneVoiceWizard({ skipStatus: true });
  renderHomeTuneVoiceState("idle", "Recording cancelled.");
}

function runTuneVoiceCountdown(step) {
  if (tuneVoiceState.phase !== "idle") return;
  tuneVoiceState.phase = "countdown";
  tuneVoiceState.countdown = 3;
  tuneVoiceState.message = "";
  renderTuneVoiceWizard({ skipStatus: true });
  const tick = () => {
    tuneVoiceState.countdown -= 1;
    if (tuneVoiceState.countdown > 0) {
      renderTuneVoiceWizard({ skipStatus: true });
      window.setTimeout(tick, 650);
      return;
    }
    tuneVoiceState.phase = "recording";
    tuneVoiceState.message = "Recording for 1 second";
    renderTuneVoiceWizard({ skipStatus: true });
    startHomeTuneVoiceSample(step.category, step.source);
  };
  window.setTimeout(tick, 650);
}

function tuneVoiceRecordCurrent() {
  const step = TUNE_VOICE_STEPS[tuneVoiceState.step] || TUNE_VOICE_STEPS[0];
  if (step.id === "intro") return setTuneVoiceStep(1);
  if (step.id === "export") return exportTuneVoiceDataset();
  if (!step.category) return;
  if (tuneVoiceState.phase !== "idle") return;
  tuneVoiceState.lastCategory = step.category;
  runTuneVoiceCountdown(step);
}

function deleteTuneVoiceLast() {
  const step = TUNE_VOICE_STEPS[tuneVoiceState.step];
  const bridge = androidNativeVoiceBridge();
  if (!step?.category || typeof bridge?.deleteLastVoiceTuningSample !== "function") return;
  try {
    const result = parseNativeBridgePayload(bridge.deleteLastVoiceTuningSample(step.category));
    tuneVoiceState.status = result?.status || tuneVoiceState.status;
    tuneVoiceState.statusAtMs = Date.now();
    tuneVoiceState.message = result?.ok ? "Last sample deleted." : cleanText(result?.error, "Delete failed.");
  } catch (error) {
    tuneVoiceState.message = errorMessage(error) || "Delete failed.";
  }
  renderTuneVoiceWizard({ skipStatus: true });
}

function exportTuneVoiceDataset() {
  const bridge = androidNativeVoiceBridge();
  tuneVoiceState.phase = "exporting";
  tuneVoiceState.message = "Export in progress...";
  renderTuneVoiceWizard({ skipStatus: true });
  try {
    if (typeof bridge?.exportHermesDataset !== "function") throw new Error(VOICE_TUNING_BRIDGE_UNAVAILABLE_MESSAGE);
    const result = parseNativeBridgePayload(bridge.exportHermesDataset());
    tuneVoiceState.exportResult = result || { ok: false, error: "empty_export_result" };
    tuneVoiceState.status = result?.status || tuneVoiceState.status;
    tuneVoiceState.statusAtMs = Date.now();
    tuneVoiceState.message = result?.ok ? "Export success." : cleanText(result?.error, "Export failed.");
  } catch (error) {
    tuneVoiceState.exportResult = { ok: false, error: errorMessage(error) || "Export failed." };
    tuneVoiceState.message = tuneVoiceState.exportResult.error;
  }
  tuneVoiceState.phase = "idle";
  renderTuneVoiceWizard({ skipStatus: true });
}

let hermesWakeExportPollBusy = false;
let hermesWakeExportLastRequestId = "";
let hermesWakeInstallPollBusy = false;
let hermesWakeInstallLastRequestId = "";

async function pollHermesWakeExportRequest() {
  if (isAndroidNativeShell() && androidNativeWakeDisabled()) return;
  if (hermesWakeExportPollBusy) return;
  const bridge = androidNativeVoiceBridge();
  if (typeof bridge?.exportHermesDataset !== "function") return;
  hermesWakeExportPollBusy = true;
  try {
    const response = await fetch("/native/android/hermes-wake-export/request", {
      cache: "no-store",
      credentials: "same-origin",
      headers: { Accept: "application/json" },
    });
    if (!response.ok) return;
    const payload = await response.json();
    const request = payload?.request || {};
    const requestId = cleanText(request.id, "");
    if (!payload?.pending || !requestId || requestId === hermesWakeExportLastRequestId) return;
    hermesWakeExportLastRequestId = requestId;
    let result = null;
    const bridgeDiagnostics = {
      page: {
        href: window.location?.href || "",
        origin: window.location?.origin || "",
        user_agent: navigator.userAgent || "",
      },
      bridge_details: tuneVoiceBridgeDetails({ force: true }),
    };
    try {
      if (typeof bridge.getBuildInfo === "function") {
        bridgeDiagnostics.build_info = parseNativeBridgePayload(bridge.getBuildInfo()) || {};
      }
    } catch (error) {
      bridgeDiagnostics.build_info_error = errorMessage(error) || "get_build_info_failed";
    }
    try {
      if (typeof bridge.getVoiceTuningDiagnostics === "function") {
        bridgeDiagnostics.voice_tuning_diagnostics = parseNativeBridgePayload(bridge.getVoiceTuningDiagnostics()) || {};
      }
    } catch (error) {
      bridgeDiagnostics.voice_tuning_diagnostics_error = errorMessage(error) || "get_voice_tuning_diagnostics_failed";
    }
    try {
      result = parseNativeBridgePayload(bridge.exportHermesDataset()) || { ok: false, error: "empty_export_result" };
    } catch (error) {
      result = { ok: false, error: errorMessage(error) || "export_failed" };
    }
    if (result && typeof result === "object") result.frontend_diagnostics = bridgeDiagnostics;
    await fetch("/native/android/hermes-wake-export/result", {
      method: "POST",
      credentials: "same-origin",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id: requestId, result }),
    });
    tuneVoiceState.exportResult = result;
    tuneVoiceState.status = result?.status || tuneVoiceState.status;
    tuneVoiceState.statusAtMs = Date.now();
  } catch (error) {
    tuneVoiceLogDiagnostic("hermes_wake_export_request_error", { error: errorMessage(error) }, { sampleMs: 5000, console: false });
  } finally {
    hermesWakeExportPollBusy = false;
  }
}

async function pollHermesWakeInstallRequest() {
  if (isAndroidNativeShell() && androidNativeWakeDisabled()) return;
  if (hermesWakeInstallPollBusy) return;
  const bridge = androidNativeVoiceBridge();
  if (typeof bridge?.installHermesWakeModel !== "function" && typeof bridge?.installOpenWakeWordBundle !== "function") return;
  hermesWakeInstallPollBusy = true;
  try {
    const response = await fetch("/native/android/hermes-wake-install/request", {
      cache: "no-store",
      credentials: "same-origin",
      headers: { Accept: "application/json" },
    });
    if (!response.ok) return;
    const payload = await response.json();
    const request = payload?.request || {};
    const requestId = cleanText(request.id, "");
    const model = request.model && typeof request.model === "object" ? request.model : {};
    const modelUrl = cleanText(model.url, "/native/android/hermes-wake-model/latest");
    const sha256 = cleanText(model.sha256, "");
    const wakePhrase = cleanText(model.wakePhrase || model.wake_phrase, "");
    const engineContract = cleanText(model.engineContract || model.engine_contract, "raw_pcm_onnx_single_confidence");
    if (!payload?.pending || !requestId || requestId === hermesWakeInstallLastRequestId || !sha256) return;
    hermesWakeInstallLastRequestId = requestId;
    let result = null;
    let policyResult = null;
    try {
      if (engineContract === "openwakeword_bundle") {
        if (typeof bridge?.installOpenWakeWordBundle !== "function") {
          result = { ok: false, error: "openwakeword_bundle_bridge_missing" };
        } else {
          result = parseNativeBridgePayload(bridge.installOpenWakeWordBundle(modelUrl, sha256)) || { ok: false, error: "empty_install_result" };
        }
      } else {
        if (typeof bridge?.installHermesWakeModel !== "function") {
          result = { ok: false, error: "wake_model_bridge_missing" };
        } else {
          result = parseNativeBridgePayload(bridge.installHermesWakeModel(modelUrl, sha256)) || { ok: false, error: "empty_install_result" };
        }
      }
      if (result?.ok && wakePhrase && wakePhrase !== "configured_by_wake_word_policy") {
        policyResult = runWakeWordOperation("apply_wake_word_policy", {
          wakePhrase,
          origin: "wake-model-install",
        });
      }
    } catch (error) {
      result = { ok: false, error: errorMessage(error) || "install_failed" };
    }
    await fetch("/native/android/hermes-wake-install/result", {
      method: "POST",
      credentials: "same-origin",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id: requestId, result: { ...result, policyResult, model } }),
    });
    tuneVoiceState.status = result?.status || tuneVoiceState.status;
    tuneVoiceState.statusAtMs = Date.now();
  } catch (error) {
    tuneVoiceLogDiagnostic("hermes_wake_install_request_error", { error: errorMessage(error) }, { sampleMs: 5000, console: false });
  } finally {
    hermesWakeInstallPollBusy = false;
  }
}

function renderHomeTuneVoiceState(status = "idle", message = "", payload = null) {
  const button = els.homeTuneVoiceButton;
  const progressLabel = payload ? homeTuneVoiceProgressLabel(payload) : "";
  const nextLabel = payload && !(payload?.dataset_ready || payload?.thresholds?.tiny)
    ? `next: ${homeTuneVoicePromptLabel(homeTuneVoiceNextCategory(payload))}`
    : "";
  const label = cleanText([message, progressLabel, nextLabel].filter(Boolean).join(" · "), "");
  if (els.homeTuneVoiceStatus) els.homeTuneVoiceStatus.textContent = label;
  if (!button) return;
  button.classList.toggle("is-recording", status === "recording");
  button.classList.toggle("is-saved", status === "saved");
  button.classList.toggle("is-error", status === "error");
  button.classList.toggle("is-ready", Boolean(payload?.dataset_ready || payload?.thresholds?.tiny));
  button.disabled = status === "recording";
  button.setAttribute("aria-busy", status === "recording" ? "true" : "false");
}

function startHomeTuneVoiceSample(category = null, source = "") {
  if (category && typeof category === "object" && typeof category.preventDefault === "function") {
    category.preventDefault();
    openTuneVoiceWizard();
    return;
  }
  let cleanCategory = cleanText(category, "");
  let cleanSource = cleanText(source, "");
  const bridge = androidNativeVoiceBridge();
  if (!cleanCategory && typeof bridge?.voiceTuningStatus === "function") {
    const status = parseNativeBridgePayload(bridge.voiceTuningStatus());
    cleanCategory = homeTuneVoiceNextCategory(status);
    tuneVoiceState.status = status || tuneVoiceState.status;
    tuneVoiceState.statusAtMs = Date.now();
    renderHomeTuneVoiceState("idle", "", status);
  }
  if (!cleanCategory) cleanCategory = "positive";
  if (!cleanSource) {
    cleanSource = cleanCategory === "positive"
      ? "space-home:tune-voice"
      : `space-home:tune-voice:${cleanCategory.replace("/", "-")}`;
  }
  const promptLabel = homeTuneVoiceRecordingLabel(cleanCategory);
  const recordPayload = {
    kind: tuneVoiceRecordKindForCategory(cleanCategory),
    label: tuneVoiceRecordLabelForCategory(cleanCategory),
    duration_ms: 1000,
    prompt: cleanCategory === "positive" ? "Hermes" : cleanText(tuneVoiceState.message, ""),
    category: cleanCategory,
    source: cleanSource,
  };
  tuneVoiceState.recordStartedAt = Date.now();
  tuneVoiceState.lastRecordKind = recordPayload.kind;
  tuneVoiceState.lastRecordPath = "";
  tuneVoiceState.lastRecordDurationMs = 0;
  tuneVoiceLogDiagnostic("frontend_record_request_sent", recordPayload);
  tuneVoiceLogDiagnostic("wizard_record_state", { phase: "recording", category: cleanCategory });
  tuneVoiceClearRecordTimeout();
  tuneVoiceState.recordTimeout = window.setTimeout(() => {
    if (tuneVoiceState.phase !== "recording" && tuneVoiceState.phase !== "saving") return;
    tuneVoiceFinishRecord("Recording timed out. Try again.", {
      category: cleanCategory,
      kind: recordPayload.kind,
      duration_ms: Date.now() - tuneVoiceState.recordStartedAt,
    });
    tuneVoiceLogDiagnostic("native_record_error", { error: "timeout", category: cleanCategory });
    renderTuneVoiceWizard({ skipStatus: true });
    renderHomeTuneVoiceState("error", "Recording timed out. Try again.");
  }, 5000);
  renderHomeTuneVoiceState("recording", promptLabel);
  try {
    if (typeof bridge?.startVoiceTuningSample !== "function") {
      throw new Error(VOICE_TUNING_BRIDGE_UNAVAILABLE_MESSAGE);
    }
    const result = parseNativeBridgePayload(bridge.startVoiceTuningSample(JSON.stringify(recordPayload)));
    if (!result?.ok) {
      if (result?.requested) {
        tuneVoiceFinishRecord("Microphone permission is required to record training samples.", { ...recordPayload, duration_ms: 0 });
        tuneVoiceState.status = result.status || tuneVoiceState.status;
        tuneVoiceState.statusAtMs = Date.now();
        renderTuneVoiceWizard({ skipStatus: true });
        renderHomeTuneVoiceState("error", "Microphone permission is required to record training samples.", result.status);
        return;
      }
      throw new Error(tuneVoiceFailureMessage(result?.error, "Voice sample recording failed."));
    }
    tuneVoiceLogDiagnostic("native_record_request_received", { ok: true, result });
    if (result?.status) {
      tuneVoiceState.status = result.status;
      tuneVoiceState.statusAtMs = Date.now();
      renderHomeTuneVoiceState("recording", promptLabel, result.status);
    }
  } catch (error) {
    tuneVoiceLogDiagnostic("native_record_error", { error: "native_bridge_error", message: errorMessage(error) });
    tuneVoiceFinishRecord(errorMessage(error) || "Native bridge error. Try again.", { ...recordPayload, duration_ms: 0 });
    renderHomeTuneVoiceState("error", errorMessage(error) || "Voice sample recording failed.");
    renderTuneVoiceWizard({ skipStatus: true });
  }
}

function recheckTuneVoiceBridge() {
  tuneVoiceState.bridgeInitializingUntil = Date.now() + 1000;
  tuneVoiceState.message = "Checking native voice tuning bridge...";
  tuneVoiceState.bridgeDetailsAtMs = 0;
  tuneVoiceLogDiagnostic("frontend_bridge_detection", tuneVoiceBridgeDetails({ force: true }), { force: true });
  renderTuneVoiceWizard({ skipStatus: true });
  window.setTimeout(() => {
    getTuneVoiceStatus({ force: true, reason: "manual_recheck" });
    const details = tuneVoiceBridgeDetails({ force: true, status: tuneVoiceState.status || {} });
    tuneVoiceState.message = details.voice_tuning_bridge_available
      ? details.recording_supported
        ? "Native voice tuning bridge connected and ready."
        : "Android bridge connected; recording not enabled yet."
      : VOICE_TUNING_BRIDGE_UNAVAILABLE_MESSAGE;
    tuneVoiceLogDiagnostic("frontend_bridge_detection", details, { force: true });
    renderTuneVoiceWizard({ skipStatus: true });
  }, 1000);
}

function handleHomeTuneVoiceEvent(event) {
  const detail = event?.detail || {};
  const type = cleanText(detail.type, "");
  if (type === "voice_tuning_started" || type === "native_record_started") {
    tuneVoiceLogDiagnostic("native_record_started", detail);
    tuneVoiceState.phase = "recording";
    tuneVoiceState.message = "Recording for 1 second";
    renderTuneVoiceWizard({ skipStatus: true });
    renderHomeTuneVoiceState("recording", homeTuneVoiceRecordingLabel(detail.category), detail);
  } else if (type === "native_record_finished") {
    tuneVoiceLogDiagnostic("native_record_finished", detail);
    tuneVoiceState.phase = "saving";
    tuneVoiceState.message = "Saving...";
    renderTuneVoiceWizard({ skipStatus: true });
  } else if (type === "voice_tuning_sample_recorded") {
    tuneVoiceLogDiagnostic("native_record_finished", detail);
    tuneVoiceLogDiagnostic("native_record_result", { ok: true, ...detail });
    tuneVoiceLogDiagnostic("renderer_record_result_received", detail);
    tuneVoiceFinishRecord("Saved", detail);
    tuneVoiceState.status = detail;
    tuneVoiceState.statusAtMs = Date.now();
    if (detail.category === "negative/speech") tuneVoiceState.speechPromptIndex += 1;
    renderTuneVoiceWizard({ skipStatus: true });
    renderHomeTuneVoiceState("saved", "Voice sample saved", detail);
  } else if (type === "voice_tuning_counts_updated" || type === "voice_tuning_threshold_met") {
    tuneVoiceState.status = detail;
    tuneVoiceState.statusAtMs = Date.now();
    renderTuneVoiceWizard({ skipStatus: true });
    renderHomeTuneVoiceState(detail.dataset_ready || detail.thresholds?.tiny ? "saved" : "idle", "", detail);
  } else if (type === "voice_tuning_recording_failed") {
    tuneVoiceLogDiagnostic("native_record_error", detail);
    tuneVoiceLogDiagnostic("renderer_record_result_received", detail);
    tuneVoiceFinishRecord(tuneVoiceFailureMessage(detail.error, cleanText(detail.message, "Try again.")), detail);
    tuneVoiceState.status = detail;
    tuneVoiceState.statusAtMs = Date.now();
    renderTuneVoiceWizard({ skipStatus: true });
    renderHomeTuneVoiceState("error", cleanText(detail.error, "Voice sample recording failed."));
  }
}

function androidElementVisibleRect(element) {
  if (!element || element.hidden) return null;
  const rects = Array.from(element.getClientRects?.() || []);
  const rect = rects.find((item) => item.width > 1 && item.height > 1) || element.getBoundingClientRect?.();
  if (!rect || rect.width <= 1 || rect.height <= 1) return null;
  const style = window.getComputedStyle ? window.getComputedStyle(element) : null;
  if (style && (style.display === "none" || style.visibility === "hidden" || Number(style.opacity) === 0)) return null;
  return rect;
}

function androidGoogleSignInTapTarget() {
  const candidates = [
    ...(document.querySelectorAll?.('[data-native-android-oauth="google-signin"], [data-testid="google-signin-button"], [aria-label="Sign in with Google"]') || []),
    els.authGateLoginButton,
    els.authGateGoogleSignInButton?.firstElementChild,
    els.googleSignInButton?.firstElementChild,
    els.authGateGoogleSignInButton,
    els.googleSignInButton,
  ].filter(Boolean);
  const seen = new Set();
  for (const element of candidates) {
    if (seen.has(element)) continue;
    seen.add(element);
    const rect = androidElementVisibleRect(element);
    if (!rect) continue;
    const viewport = window.visualViewport;
    return {
      tag: cleanText(element.tagName, "").toLowerCase(),
      id: cleanText(element.id, ""),
      testid: cleanText(element.getAttribute?.("data-testid"), ""),
      aria_label: cleanText(element.getAttribute?.("aria-label"), ""),
      native_oauth: cleanText(element.getAttribute?.("data-native-android-oauth"), ""),
      rect: {
        left: Number(rect.left.toFixed(2)),
        top: Number(rect.top.toFixed(2)),
        right: Number(rect.right.toFixed(2)),
        bottom: Number(rect.bottom.toFixed(2)),
        width: Number(rect.width.toFixed(2)),
        height: Number(rect.height.toFixed(2)),
        center_x: Number((rect.left + rect.width / 2).toFixed(2)),
        center_y: Number((rect.top + rect.height / 2).toFixed(2)),
      },
      viewport: {
        inner_width: Number(window.innerWidth || 0),
        inner_height: Number(window.innerHeight || 0),
        device_pixel_ratio: Number(window.devicePixelRatio || 1),
        screen_width: Number(window.screen?.width || 0),
        screen_height: Number(window.screen?.height || 0),
        visual_width: Number(viewport?.width || 0),
        visual_height: Number(viewport?.height || 0),
        visual_offset_left: Number(viewport?.offsetLeft || 0),
        visual_offset_top: Number(viewport?.offsetTop || 0),
        visual_scale: Number(viewport?.scale || 1),
      },
    };
  }
  return null;
}

function androidNativeReadinessState(extra = {}) {
  const authenticated = Boolean(state.authUser);
  const authGateVisible = Boolean(els.app?.dataset.auth === "locked" || (!authenticated && state.authChecked));
  const googleButtonVisible = [
    els.authGateLoginButton,
    els.authGateGoogleSignInButton,
    els.googleSignInButton,
  ].some((item) => Boolean(item && !item.hidden && item.getClientRects?.().length));
  return {
    native_android_shell: isAndroidNativeShell(),
    login_screen_visible: Boolean(!authenticated && authGateVisible),
    google_signin_button_visible: Boolean(!authenticated && googleButtonVisible),
    current_route: cleanText(state.activePanel || "", ""),
    current_url: window.location.href,
    auth_state: authenticated ? "authenticated" : state.authChecked ? "anonymous" : "checking",
    config_checked: Boolean(state.configChecked),
    auth_checked: Boolean(state.authChecked),
    google_client_configured: Boolean(state.googleClientId),
    login_message: cleanText(state.loginMessage, ""),
    google_button_rendered_for: cleanText(state.googleButtonRenderedFor, ""),
    google_signin_tap_target: androidGoogleSignInTapTarget(),
    ...extra,
  };
}

function reportAndroidNativeReadiness(reason = "readiness", extra = {}) {
  if (!isAndroidNativeShell()) return null;
  const payload = androidNativeReadinessState({
    reason: cleanText(reason, ""),
    ...extra,
  });
  nativeShellDiagnostic("first_screen_readiness", payload);
  recordAndroidNativeDiagnostic("first_screen_readiness", payload);
  if (payload.login_screen_visible) {
    recordAndroidNativeDiagnostic("login_screen_visible", payload);
  }
  if (payload.google_signin_button_visible) {
    recordAndroidNativeDiagnostic("google_signin_button_visible", payload);
  }
  return payload;
}

function getAndroidNativeState() {
  const bridge = androidDiagnosticsBridge();
  if (!bridge?.getNativeState) return null;
  try {
    return parseNativeBridgePayload(bridge.getNativeState());
  } catch {
    return null;
  }
}

function androidGeneralNativeBridge() {
  const bridge = window.wasmAgentNative || window.WasmAgentNative;
  return bridge && typeof bridge === "object" ? bridge : null;
}

let wakeWordLastState = {};
let wakeWordLastStateAt = 0;
const LEGACY_WAKE_WORD_NATIVE_SCREEN = ["wake", "world"].join("-");
const LEGACY_WAKE_WORD_STATE_METHOD = ["getWake", "WorldState"].join("");
const LEGACY_WAKE_WORD_STATE_PACKET_KEY = ["wake", "WorldState"].join("");
const LEGACY_FETCH_WAKE_WORD_STATE_OPERATION = ["fetch_wake", "world_state"].join("_");
const LEGACY_PROVE_WAKE_WORD_LOOP_OPERATION = ["prove_wake", "world_loop"].join("_");
const LEGACY_OPEN_WAKE_WORD_COMMAND = ["open_wake", "world"].join("_");
const LEGACY_REFRESH_WAKE_WORD_STATE_COMMAND = ["refresh_wake", "world_state"].join("_");

function getWakeWordState(options = {}) {
  const now = Date.now();
  if (androidNativeWakeDisabled() && options.force !== true) {
    wakeWordLastState = {
      schema: "hermes.wasm_agent.android_wake_word_state.v1",
      enabled: false,
      listener_lane: "disabled",
      listener_mode: "perf_safe_mode",
      wake_service_ready: false,
      wake_engine_ready: false,
      foreground_service_active: false,
      wake_disabled_by_query: true,
    };
    wakeWordLastStateAt = now;
    return wakeWordLastState;
  }
  if (!options.force && wakeWordLastStateAt && now - wakeWordLastStateAt < WAKE_WORD_STATE_CACHE_TTL_MS) {
    return wakeWordLastState;
  }
  let nextState = {};
  const bridge = androidGeneralNativeBridge();
  const stateReader = bridge?.getWakeWordState || bridge?.[LEGACY_WAKE_WORD_STATE_METHOD];
  if (stateReader) {
    try {
      nextState = parseNativeBridgePayload(stateReader.call(bridge)) || {};
      wakeWordLastState = nextState;
      wakeWordLastStateAt = now;
      return nextState;
    } catch {
      wakeWordLastState = {};
      wakeWordLastStateAt = now;
      return {};
    }
  }
  const nativeState = getAndroidNativeState();
  nextState = nativeState?.voice_wake || nativeState?.voiceWake || {};
  wakeWordLastState = nextState;
  wakeWordLastStateAt = now;
  return nextState;
}

let wakeWordRefreshTimer = 0;
const wakeWordRenderedRows = new Map();
const wakeWordTuningSteps = [
  "Place the phone on a table. Stay quiet for 10 seconds, then press Step done.",
  "Speak random non-wake words for 10 seconds, then press Step done.",
  "Say the wake phrase 10 times with natural spacing, then press Step done.",
  "Say the wake phrase once, then say open wake word, then press Step done.",
  "Leave the listener running in normal room noise for 20 seconds, then press Step done.",
];
const wakeWordTuningState = {
  sessionId: "",
  stepIndex: 0,
  snapshots: [],
};

function wakeWordLegacyState(packet = {}) {
  return packet?.wake_word_state || packet?.wakeWordState || packet?.[LEGACY_WAKE_WORD_STATE_PACKET_KEY] || packet || {};
}

function wakeWordCurrentPhrase(packet = {}) {
  const normalized = wakeWordLegacyState(packet);
  return cleanText(
    normalized.wake_word
      || normalized.wakePhrase
      || wakeWordModelMetadata?.wakePhrase
      || wakeWordModelMetadata?.wake_phrase
      || els.wakeWordPhraseInput?.value,
    WAKE_WORD_DEFAULT_PHRASE,
  );
}

function wakeWordCurrentThreshold(packet = {}) {
  const normalized = wakeWordLegacyState(packet);
  const value = Number(normalized.threshold || normalized.wake_threshold || els.wakeWordThresholdInput?.value || WAKE_WORD_DEFAULT_THRESHOLD);
  return Number.isFinite(value) ? Math.max(0.05, Math.min(0.999, value)) : WAKE_WORD_DEFAULT_THRESHOLD;
}

function wakeWordInputLooksPlaceholder() {
  return WAKE_WORD_PLACEHOLDER_PHRASES.has(cleanText(els.wakeWordPhraseInput?.value, "").toLowerCase());
}

function wakeWordThresholdLooksPlaceholder() {
  const value = Number(els.wakeWordThresholdInput?.value || WAKE_WORD_DEFAULT_THRESHOLD);
  return !Number.isFinite(value) || Math.abs(value - WAKE_WORD_DEFAULT_THRESHOLD) < 0.0005 || Math.abs(value - 0.995) < 0.0005 || Math.abs(value - 0.5) < 0.0005;
}

function applyWakeWordModelMetadataToLab(metadata = {}, packet = {}) {
  wakeWordModelMetadata = metadata && typeof metadata === "object" ? metadata : wakeWordModelMetadata;
  const phrase = cleanText(wakeWordModelMetadata?.wakePhrase || wakeWordModelMetadata?.wake_phrase, "");
  if (phrase && els.wakeWordPhraseInput && document.activeElement !== els.wakeWordPhraseInput && !cleanText(wakeWordLegacyState(packet).wake_word, "") && wakeWordInputLooksPlaceholder()) {
    els.wakeWordPhraseInput.value = phrase;
  }
  const threshold = Number(wakeWordModelMetadata?.recommendedThreshold || wakeWordModelMetadata?.recommended_threshold || WAKE_WORD_DEFAULT_THRESHOLD);
  if (els.wakeWordThresholdInput && document.activeElement !== els.wakeWordThresholdInput && Number.isFinite(threshold) && wakeWordThresholdLooksPlaceholder()) {
    els.wakeWordThresholdInput.value = threshold.toFixed(3);
  }
}

async function loadWakeWordModelMetadata(packet = {}) {
  if (wakeWordModelMetadata) {
    applyWakeWordModelMetadataToLab(wakeWordModelMetadata, packet);
    return wakeWordModelMetadata;
  }
  if (!wakeWordModelMetadataPromise) {
    wakeWordModelMetadataPromise = fetchJson("/native/android/hermes-wake-model/latest.json", { timeoutMs: 5000 })
      .then((metadata) => {
        wakeWordModelMetadata = metadata && typeof metadata === "object" ? metadata : {};
        return wakeWordModelMetadata;
      })
      .catch((error) => {
        recordUserEvent("wake_word_model_metadata_failed", { error: errorMessage(error) });
        return null;
      })
      .finally(() => {
        wakeWordModelMetadataPromise = null;
      });
  }
  const metadata = await wakeWordModelMetadataPromise;
  if (metadata) applyWakeWordModelMetadataToLab(metadata, packet);
  return metadata;
}

function runWakeWordOperationOnce(bridge, operationId, inputs = {}) {
  try {
    return parseNativeBridgePayload(bridge.runDownloadedOperation(JSON.stringify({
      operationId,
      requiredNativeCapabilities: ["native.capabilities.downloadedOperations.v1"],
      timeoutMs: 30000,
    }), JSON.stringify(inputs || {})));
  } catch {
    return null;
  }
}

function wakeWordLegacyOperationId(operationId) {
  if (operationId === "fetch_wake_word_state") return LEGACY_FETCH_WAKE_WORD_STATE_OPERATION;
  if (operationId === "prove_wake_word_loop") return LEGACY_PROVE_WAKE_WORD_LOOP_OPERATION;
  return "";
}

function wakeWordOperationUnsupported(result) {
  const code = cleanText(result?.failureClassification || result?.error || result?.code, "");
  return code === "downloaded_operation_not_supported" || code === "unsupported_operation";
}

function runWakeWordOperation(operationId, inputs = {}) {
  const bridge = androidGeneralNativeBridge();
  if (!bridge?.runDownloadedOperation) return null;
  const result = runWakeWordOperationOnce(bridge, operationId, inputs);
  const legacyId = wakeWordLegacyOperationId(operationId);
  if (!legacyId || (result && !wakeWordOperationUnsupported(result))) return result;
  return runWakeWordOperationOnce(bridge, legacyId, inputs) || result;
}

function exportAndroidNativeDiagnostics() {
  const bridge = androidDiagnosticsBridge();
  if (!bridge?.exportLatest) return "";
  try {
    const exported = bridge.exportLatest();
    return typeof exported === "string" ? exported : JSON.stringify(exported || {}, null, 2);
  } catch {
    return "";
  }
}

function androidNativeShellInfo() {
  let params = null;
  try {
    params = new URL(window.location.href).searchParams;
  } catch {
    params = new URLSearchParams();
  }
  let bridgeInfo = null;
  if (window.wasmAgentAndroid?.shellInfo) {
    try {
      bridgeInfo = parseNativeBridgePayload(window.wasmAgentAndroid.shellInfo());
    } catch {
      bridgeInfo = null;
    }
  }
  const native = cleanText(params.get("native"), "").toLowerCase();
  const shell = cleanText(params.get("shell") || bridgeInfo?.shell || bridgeInfo?.nativeShell, "").toLowerCase();
  const platform = cleanText(bridgeInfo?.platform || bridgeInfo?.buildPlatform, "").toLowerCase();
  const isAndroid = native === "android"
    || shell === "android-webview"
    || platform === "android"
    || Boolean(window.wasmAgentAndroid)
    || Boolean(androidDiagnosticsBridge());
  return {
    isAndroidNativeShell: isAndroid,
    native,
    shell: shell || (isAndroid ? "android-webview" : ""),
    platform: platform || (isAndroid ? "android" : ""),
    runtimeMode: cleanText(window.__WASM_AGENT_ANDROID_RUNTIME_MODE__ || "", isAndroid ? "user-full" : ""),
    debugShell: window.__WASM_AGENT_ANDROID_DEBUG_SHELL__ === true,
    perfSafeMode: androidNativePerfSafeMode(),
    wakeStartupMode: androidNativeQueryParam("wake", androidNativePerfSafeMode() ? "off" : "deferred"),
    bridgeDiagnostics: androidNativeQueryParam("bridgeDiagnostics", androidNativePerfSafeMode() ? "off" : "sampled"),
    buildId: cleanText(params.get("buildId") || bridgeInfo?.buildId, ""),
    androidAuthSession: cleanText(params.get("android_auth_session") || bridgeInfo?.androidAuthSession, ""),
    nativeCorrelationId: cleanText(params.get("native_correlation_id") || bridgeInfo?.nativeCorrelationId, ""),
    installDeviceHash: cleanText(params.get("install_device_hash") || bridgeInfo?.installDeviceHash, ""),
    packageInfo: bridgeInfo?.packageInfo || null,
    diagnosticsPath: cleanText(bridgeInfo?.diagnosticsPath, ""),
    hasBridge: Boolean(window.wasmAgentAndroid),
    hasDiagnosticsBridge: Boolean(androidDiagnosticsBridge()),
  };
}

function isAndroidNativeShell() {
  return androidNativeShellInfo().isAndroidNativeShell;
}

function nativeShellDiagnostic(kind, payload = {}) {
  const shell = androidNativeShellInfo();
  const diagnostic = {
    href: window.location.href,
    origin: window.location.origin,
    timestamp: new Date().toISOString(),
    shell,
    ...payload,
  };
  if (shell.isAndroidNativeShell && androidNativeBridgeDiagnosticsOff() && !/error|failed|app_ready|auth/i.test(kind)) {
    return diagnostic;
  }
  if (deferAndroidBridgeDiagnostics) {
    queueAndroidBridgeDiagnostic(kind, diagnostic, "shell");
    return diagnostic;
  }
  try {
    if (window.wasmAgentAndroid?.logDiagnostic) {
      window.wasmAgentAndroid.logDiagnostic(kind, nativeBridgePayload(diagnostic));
    } else if (window.wasmAgentNative?.logDiagnostic) {
      window.wasmAgentNative.logDiagnostic(kind, diagnostic);
    }
  } catch {
    // Native shell diagnostics are best effort.
  }
  return diagnostic;
}

function applyNativeShellUi() {
  if (isWindowsNativeShellHost() && els.homeGoNativeButton) {
    const label = els.homeGoNativeButton.querySelector("span");
    const needsUpdate = nativeInstallerUpdateAvailable();
    const text = needsUpdate ? "Update App" : "Native";
    if (label) label.textContent = text;
    els.homeGoNativeButton.title = text;
    els.homeGoNativeButton.setAttribute("aria-label", text);
  }
  if (nativeShellUiApplied) return;
  if (!isAndroidNativeShell()) return;
  nativeShellUiApplied = true;
  document.documentElement.dataset.nativeShell = "android";
  if (els.app) els.app.dataset.nativeShell = "android";
  if (els.nativeModal) els.nativeModal.hidden = true;
  nativeShellDiagnostic("android_native_shell_detected", {
    user_agent: navigator.userAgent || "",
  });
}

function installAndroidNativeShellEventDiagnostics() {
  if (!isAndroidNativeShell()) return;
  window.addEventListener("load", () => nativeShellDiagnostic("window_load"));
  window.addEventListener("pageshow", (event) => nativeShellDiagnostic("page_show", {
    persisted: Boolean(event.persisted),
  }));
  window.addEventListener("wasm-agent:native-back", (event) => nativeShellDiagnostic("native_back_event", event.detail || {}));
  window.addEventListener("wasm-agent:native-page-finished", (event) => nativeShellDiagnostic("native_page_finished", event.detail || {}));
  window.addEventListener("wasm-agent:native-external-url", (event) => nativeShellDiagnostic("native_external_url_event", event.detail || {}));
  window.addEventListener("wasm-agent:native-permission", (event) => nativeShellDiagnostic("native_permission_event", event.detail || {}));
  window.addEventListener("wasm-agent:native-configuration", (event) => nativeShellDiagnostic("native_configuration_event", event.detail || {}));
  window.addEventListener("wasm-agent:native-wake-detected", (event) => {
    const detail = event.detail || {};
    const receivedAt = Number(detail.received_at || Date.now());
    if (receivedAt > 0 && state.nativeVoiceWakeLastEventAt && receivedAt - state.nativeVoiceWakeLastEventAt < 1200) {
      nativeShellDiagnostic("native_wake_detected_event_debounced", detail);
      return;
    }
    state.nativeVoiceWakeLastEventAt = receivedAt || Date.now();
    nativeShellDiagnostic("native_wake_detected_event", detail);
    triggerAgentAvatarWakeShine({
      listener_mode: "awake",
      last_wake_at: receivedAt,
      wake_hit_count: Number(state.nativeVoiceWakeLastHitCount || 0) + 1,
      last_confidence: Number(detail.wake_confidence || detail.confidence || 0),
      last_wake_confidence: Number(detail.wake_confidence || detail.confidence || 0),
    }, "native-wake-detected");
    window.setTimeout(() => void pollNativeVoiceWakeTimeline("native-wake-detected"), 900);
    window.setTimeout(() => void pollNativeVoiceWakeTimeline("native-transcript-followup"), 3600);
  });
  window.addEventListener("wasm-agent:native-android-auth-canceled", (event) => {
    nativeShellDiagnostic("native_android_auth_canceled_event", event.detail || {});
    resetAndroidNativeGoogleLogin("native-cancel-event", "Google sign-in was canceled. Try again.");
  });
}

function notifyNativeAppReady(reason = "app-ready", payload = {}) {
  if (nativeAppReadyNotified && reason !== "authenticated-app-ready") return;
  nativeAppReadyNotified = true;
  const diagnostic = nativeShellDiagnostic("app_ready", {
    reason,
    authenticated: Boolean(state.authUser),
    auth_checked: Boolean(state.authChecked),
    config_checked: Boolean(state.configChecked),
    active_panel: state.activePanel,
    ...payload,
  });
  if (reason === "authenticated-app-ready" && state.authUser) {
    recordAndroidNativeDiagnostic("authenticated_ui_visible", diagnostic);
  }
  if (window.wasmAgentAndroid?.appReady) {
    try {
      window.wasmAgentAndroid.appReady(nativeBridgePayload(diagnostic));
    } catch {
      // App-ready is a visibility hint only.
    }
  }
}

async function loadNativePreloadConfig() {
  if (!window.wasmAgentNative?.config) return null;
  let timeout = 0;
  const startedAt = performance.now();
  try {
    const payload = await Promise.race([
      window.wasmAgentNative.config(),
      new Promise((resolve) => {
        timeout = window.setTimeout(() => resolve({ __timeout: true }), 2500);
      }),
    ]);
    if (payload?.__timeout) {
      nativeAuthDiagnostic("native_config_timeout", {
        elapsed_ms: Math.round(performance.now() - startedAt),
      });
      return null;
    }
    const parsedPayload = parseNativeBridgePayload(payload);
    nativeAuthDiagnostic("native_config_resolved", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      has_auth: Boolean(parsedPayload?.auth),
      has_native: Boolean(parsedPayload?.native || parsedPayload?.serverUrl),
    });
    return parsedPayload && typeof parsedPayload === "object" ? parsedPayload : null;
  } catch (error) {
    nativeAuthDiagnostic("native_config_error", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      message: errorMessage(error),
    });
    return null;
  } finally {
    if (timeout) window.clearTimeout(timeout);
  }
}

function errorMessage(error) {
  return String(error?.message || error || "").slice(0, 500);
}

function cleanStack(error) {
  return cleanText(error?.stack || "", "").slice(0, 1800);
}

function exposeFrontierRendererState() {
  try {
    window.__wasmAgentFrontierState = () => ({
      href: window.location.href,
      buildId: authDiagnosticBuildId(),
      cloudAssetBuildId: Array.from(document.scripts)
        .map((item) => item.src || "")
        .find((src) => src.includes("/app.js"))?.split("?v=")[1] || "",
      configChecked: Boolean(state.configChecked),
      authChecked: Boolean(state.authChecked),
      authenticated: Boolean(state.authUser),
      authSessionLoadPhase: frontierRuntimeState.authSessionLoadPhase,
      loadAuthSessionReached: Boolean(frontierRuntimeState.loadAuthSessionReached),
      loginMessage: cleanText(state.loginMessage, ""),
      authRedirectMessage: cleanText(state.authRedirectMessage, ""),
      lastError: cleanText(state.lastError, ""),
      lastFatalError: frontierRuntimeState.lastFatalError,
      agentNodeSelect: agentNodeSelectDiagnostic(),
    });
  } catch {
    // Frontier state must never affect the app path.
  }
}

function authDiagnosticDeviceId() {
  return cleanText(state.config?.native?.deviceId, "") || cleanText(localStorage.getItem(CLIENT_DEVICE_STORAGE_KEY), "") || "renderer-unknown";
}

function authDiagnosticBuildId() {
  return cleanText(state.config?.native?.buildId, "") || cleanText(state.config?.native?.installableVersion, "") || "renderer-live";
}

function clientBootElapsedMs() {
  const base = Number(clientBootTrace.startedAtMs || 0);
  return Math.max(0, Math.round(performance.now() - base));
}

function clippedBootTraceValue(value, fallback = "") {
  return cleanText(value, fallback).slice(0, 500);
}

function clientBootMark(phase, data = {}) {
  const mark = {
    at_ms: clientBootElapsedMs(),
    phase: clippedBootTraceValue(phase, "event").slice(0, 120),
    auth_checked: Boolean(state.authChecked),
    config_checked: Boolean(state.configChecked),
    authenticated: Boolean(state.authUser),
    active_panel: cleanText(state.activePanel, ""),
    data: redactClientBootTraceData(data),
  };
  androidNativeLastBootPhase = mark.phase;
  androidNativeLastBootPhaseAtMs = mark.at_ms;
  clientBootTrace.marks.push(mark);
  while (clientBootTrace.marks.length > CLIENT_BOOT_TRACE_LIMIT) clientBootTrace.marks.shift();
  try {
    performance.mark(`wasm-agent:${mark.phase}`);
  } catch {
    // Performance marks are diagnostic only.
  }
  return mark;
}

function clientBootMarkAt(phase, performanceNowMs, data = {}) {
  const absoluteMs = Number(performanceNowMs || 0);
  const mark = clientBootMark(phase, {
    ...data,
    historical_mark: true,
    performance_now_ms: Number.isFinite(absoluteMs) ? Math.round(absoluteMs) : 0,
  });
  if (Number.isFinite(absoluteMs) && absoluteMs > 0) {
    mark.at_ms = Math.round(absoluteMs - Number(clientBootTrace.startedAtMs || 0));
    androidNativeLastBootPhaseAtMs = mark.at_ms;
  }
  return mark;
}

function redactClientBootTraceData(value, depth = 0) {
  if (value === null || typeof value === "undefined") return value;
  if (typeof value === "string") return clippedBootTraceValue(value, "");
  if (typeof value === "number" || typeof value === "boolean") return value;
  if (depth > 4) return "[depth-limit]";
  if (Array.isArray(value)) return value.slice(0, 30).map((item) => redactClientBootTraceData(item, depth + 1));
  if (typeof value === "object") {
    const redacted = {};
    for (const [key, item] of Object.entries(value).slice(0, 80)) {
      const cleanKey = cleanText(key, "").slice(0, 120);
      if (!cleanKey) continue;
      if (/cookie|token|secret|authorization|credential|password|api[_-]?key/i.test(cleanKey)) {
        redacted[cleanKey] = "[redacted]";
      } else {
        redacted[cleanKey] = redactClientBootTraceData(item, depth + 1);
      }
    }
    return redacted;
  }
  return clippedBootTraceValue(String(value), "");
}

function clientBootRecordFetch(entry) {
  clientBootTrace.fetches.push(redactClientBootTraceData(entry));
  while (clientBootTrace.fetches.length > CLIENT_BOOT_TRACE_LIMIT) clientBootTrace.fetches.shift();
  if (Number(entry.duration_ms || 0) >= CLIENT_BOOT_TRACE_SLOW_FETCH_MS || entry.ok === false) {
    clientBootMark("fetch_slow_or_failed", entry);
    scheduleClientBootTraceUpload("fetch_slow_or_failed");
  }
}

function clientBootRecordInput(event, type = "") {
  if (!event) return;
  const androidNative = isAndroidNativeShell();
  if (androidNative) markAndroidNativeUserInput();
  const target = event.target;
  const probeCreatedAtMs = Number(event.__wasmAgentProbeCreatedAtMs || 0);
  const dispatchReferenceMs = Number.isFinite(probeCreatedAtMs) && probeCreatedAtMs > 0
    ? probeCreatedAtMs
    : Number(event.timeStamp || performance.now());
  if (androidNative) {
    const nowMs = performance.now();
    const shouldSample = probeCreatedAtMs > 0
      || androidClientBootLastInputSampleAt <= 0
      || nowMs - androidClientBootLastInputSampleAt >= ANDROID_CLIENT_BOOT_TRACE_INPUT_SAMPLE_MS;
    if (!shouldSample) return;
    androidClientBootLastInputSampleAt = nowMs;
    const input = {
      at_ms: clientBootElapsedMs(),
      type: clippedBootTraceValue(type || event.type || "input", "input").slice(0, 40),
      event_time_ms: Math.round(event.timeStamp || 0),
      dispatch_delay_ms: Math.max(0, Math.round(nowMs - dispatchReferenceMs)),
      dispatch_delay_source: probeCreatedAtMs > 0 ? "probe_created_at" : "event_timeStamp",
      pointer_type: clippedBootTraceValue(event.pointerType || "", ""),
      button: Number.isFinite(event.button) ? event.button : null,
      is_trusted: Boolean(event.isTrusted),
      target: clippedBootTraceValue(summarizeEventTarget(target), "").slice(0, 120),
      active_panel: cleanText(state.activePanel, ""),
      android_fast_input: true,
    };
    clientBootTrace.inputs.push(input);
    while (clientBootTrace.inputs.length > ANDROID_CLIENT_BOOT_TRACE_INPUT_LIMIT) clientBootTrace.inputs.shift();
    if (probeCreatedAtMs > 0 && Number(input.dispatch_delay_ms || 0) >= ANDROID_CLIENT_BOOT_TRACE_LONG_TASK_UPLOAD_MS) {
      clientBootMark("android_probe_input_slow", input);
      scheduleClientBootTraceUpload("android_probe_input_slow");
    }
    return;
  }
  const input = {
    at_ms: clientBootElapsedMs(),
    type: clippedBootTraceValue(type || event.type || "input", "input").slice(0, 40),
    event_time_ms: Math.round(event.timeStamp || 0),
    dispatch_delay_ms: Math.max(0, Math.round(performance.now() - dispatchReferenceMs)),
    dispatch_delay_source: probeCreatedAtMs > 0 ? "probe_created_at" : "event_timeStamp",
    pointer_type: clippedBootTraceValue(event.pointerType || "", ""),
    button: Number.isFinite(event.button) ? event.button : null,
    is_trusted: Boolean(event.isTrusted),
    target: clippedBootTraceValue(describeEventTarget(target), "").slice(0, 220),
    app_status: cleanText(els.app?.dataset?.status, ""),
    app_auth: cleanText(els.app?.dataset?.auth, ""),
    active_panel: cleanText(state.activePanel, ""),
  };
  clientBootTrace.inputs.push(input);
  while (clientBootTrace.inputs.length > CLIENT_BOOT_TRACE_INPUT_LIMIT) clientBootTrace.inputs.shift();
  clientBootMark("user_input_seen", input);
  scheduleClientBootTraceUpload("user_input_seen");
}

function clientBootRecordLongTask(entry) {
  clientBootTrace.longTasks.push(redactClientBootTraceData(entry));
  while (clientBootTrace.longTasks.length > CLIENT_BOOT_TRACE_LONG_TASK_LIMIT) clientBootTrace.longTasks.shift();
  if (Number(entry.duration_ms || 0) >= CLIENT_BOOT_TRACE_LONG_TASK_MS) {
    clientBootMark("main_thread_long_task", entry);
    if (isAndroidNativeShell()) {
      const now = Date.now();
      if (now - androidNativeLastLongTaskTraceUploadAt < ANDROID_CLIENT_BOOT_TRACE_LONG_TASK_UPLOAD_COOLDOWN_MS) return;
      androidNativeLastLongTaskTraceUploadAt = now;
    }
    scheduleClientBootTraceUpload("main_thread_long_task");
  }
}

function installClientBootInteractionProbe() {
  if (clientBootTrace.inputProbeInstalled) return;
  clientBootTrace.inputProbeInstalled = true;
  if (isAndroidNativeShell()) {
    return;
  } else {
  ["pointerdown", "pointerup", "click", "touchstart", "touchend"].forEach((type) => {
    window.addEventListener(type, (event) => clientBootRecordInput(event, type), { capture: true, passive: true });
  });
  }
  if (typeof PerformanceObserver !== "undefined") {
    try {
      const observer = new PerformanceObserver((list) => {
        for (const entry of list.getEntries()) {
          clientBootRecordLongTask({
            at_ms: Math.round(entry.startTime || 0),
            duration_ms: Math.round(entry.duration || 0),
            name: clippedBootTraceValue(entry.name || "longtask", ""),
            entry_type: clippedBootTraceValue(entry.entryType || "", ""),
            last_mark_phase: clippedBootTraceValue(androidNativeLastBootPhase, ""),
            last_mark_at_ms: Math.round(androidNativeLastBootPhaseAtMs || 0),
            input_pending: androidNativeInputPending(),
          });
        }
      });
      observer.observe({ entryTypes: ["longtask"] });
      clientBootTrace.longTaskObserver = observer;
    } catch {
      // Long task timing is diagnostic only and is not available everywhere.
    }
  }
  clientBootMark("input_latency_probe_installed");
}

function clientBootTracePayload(reason = "snapshot") {
  const nav = performance.getEntriesByType?.("navigation")?.[0];
  const resources = (performance.getEntriesByType?.("resource") || [])
    .map((entry) => ({
      name: clippedBootTraceValue(entry.name, "").slice(0, 260),
      initiator_type: clippedBootTraceValue(entry.initiatorType, ""),
      start_ms: Math.round(entry.startTime || 0),
      duration_ms: Math.round(entry.duration || 0),
      transfer_size: Math.round(entry.transferSize || 0),
      encoded_body_size: Math.round(entry.encodedBodySize || 0),
    }))
    .sort((a, b) => b.duration_ms - a.duration_ms)
    .slice(0, CLIENT_BOOT_TRACE_SLOW_RESOURCE_LIMIT);
  return {
    schema: clientBootTrace.schema,
    reason,
    boot_id: clientBootTrace.bootId,
    started_at: clientBootTrace.startedAt,
    elapsed_ms: clientBootElapsedMs(),
    href: window.location.href,
    user_agent: navigator.userAgent || "",
    build_id: authDiagnosticBuildId(),
    native_shell: androidNativeShellInfo(),
    app: {
      auth_checked: Boolean(state.authChecked),
      config_checked: Boolean(state.configChecked),
      authenticated: Boolean(state.authUser),
      active_panel: cleanText(state.activePanel, ""),
      app_status: cleanText(els.app?.dataset?.status, ""),
      app_auth: cleanText(els.app?.dataset?.auth, ""),
      last_error: cleanText(state.lastError, ""),
      auth_session_load_phase: cleanText(frontierRuntimeState.authSessionLoadPhase, ""),
      load_auth_session_reached: Boolean(frontierRuntimeState.loadAuthSessionReached),
      native_app_ready_notified: Boolean(nativeAppReadyNotified),
      android_runtime_mode: cleanText(window.__WASM_AGENT_ANDROID_RUNTIME_MODE__ || "", ""),
      android_debug_shell: window.__WASM_AGENT_ANDROID_DEBUG_SHELL__ === true,
    },
    native_webview_boot: state.config?.native?.nativeWebViewBoot || null,
    navigation: nav ? {
      start_ms: Math.round(nav.startTime || 0),
      duration_ms: Math.round(nav.duration || 0),
      dom_interactive_ms: Math.round(nav.domInteractive || 0),
      dom_content_loaded_ms: Math.round(nav.domContentLoadedEventEnd || 0),
      load_event_ms: Math.round(nav.loadEventEnd || 0),
      transfer_size: Math.round(nav.transferSize || 0),
    } : null,
    marks: clientBootTrace.marks.slice(-CLIENT_BOOT_TRACE_LIMIT),
    fetches: clientBootTrace.fetches.slice(-CLIENT_BOOT_TRACE_LIMIT),
    inputs: clientBootTrace.inputs.slice(-CLIENT_BOOT_TRACE_INPUT_LIMIT),
    long_tasks: clientBootTrace.longTasks.slice(-CLIENT_BOOT_TRACE_LONG_TASK_LIMIT),
    errors: clientBootTrace.errors.slice(-40),
    slow_resources: resources,
    android_native_ux_report: isAndroidNativeShell() ? androidNativeUxReport(reason) : null,
  };
}

function exposeClientBootTrace() {
  try {
    window.__wasmAgentBootTrace = (reason = "manual") => clientBootTracePayload(reason);
  } catch {
    // Debug exposure is best effort.
  }
}

function urgentClientBootTraceUpload(reason = "") {
  return /fatal|error|page_hide|visibility_hidden/i.test(String(reason || ""));
}

function scheduleClientBootTraceUpload(reason = "snapshot") {
  if (clientBootTraceUploadTimer) window.clearTimeout(clientBootTraceUploadTimer);
  const delayMs = isAndroidNativeShell() && !urgentClientBootTraceUpload(reason)
    ? Math.max(CLIENT_BOOT_TRACE_UPLOAD_DEBOUNCE_MS, ANDROID_CLIENT_BOOT_TRACE_UPLOAD_DEBOUNCE_MS)
    : CLIENT_BOOT_TRACE_UPLOAD_DEBOUNCE_MS;
  clientBootTraceUploadTimer = window.setTimeout(() => {
    clientBootTraceUploadTimer = 0;
    if (isAndroidNativeShell() && !urgentClientBootTraceUpload(reason) && androidNativeRecentUserInput(ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS)) {
      scheduleClientBootTraceUpload(reason);
      return;
    }
    void uploadClientBootTrace(reason);
  }, delayMs);
}

async function waitForClientBootTraceUploadWindow(reason = "snapshot", options = {}) {
  if (!isAndroidNativeShell() || urgentClientBootTraceUpload(reason) || options.immediate === true) return;
  await waitForAndroidNativeInputQuiet(ANDROID_CLIENT_BOOT_TRACE_UPLOAD_IDLE_QUIET_MS, {
    maxWaitMs: ANDROID_CLIENT_BOOT_TRACE_UPLOAD_MAX_WAIT_MS,
  });
  await androidNativeYield(0);
}

async function uploadClientBootTrace(reason = "snapshot", options = {}) {
  if (androidNativeBootNetworkQuiet() && !urgentClientBootTraceUpload(reason)) return;
  await waitForClientBootTraceUploadWindow(reason, options);
  const payload = clientBootTracePayload(reason);
  const body = JSON.stringify({
    schema: "hermes.wasm_agent.client_boot_trace_upload.v1",
    device_id: authDiagnosticDeviceId(),
    build_id: authDiagnosticBuildId(),
    reason,
    boot_trace: payload,
  });
  try {
    if (options.beacon && navigator.sendBeacon) {
      const sent = navigator.sendBeacon("/native/diagnostics", new Blob([body], { type: "application/json" }));
      if (sent) return;
    }
    await fetch("/native/diagnostics", {
      method: "POST",
      cache: "no-store",
      keepalive: Boolean(options.keepalive),
      headers: {
        "Accept": "application/json",
        "Content-Type": "application/json",
      },
      body,
    });
  } catch {
    // Boot tracing must never affect the app.
  }
}

function authDiagnosticTail() {
  return authDiagnosticBuffer
    .slice(-AUTH_DIAGNOSTIC_UPLOAD_TAIL_LIMIT)
    .map((entry) => JSON.stringify({
      timestamp: entry.timestamp,
      kind: entry.kind,
      payload: {
        href: cleanText(entry.payload?.href, "").slice(0, 220),
        config_checked: Boolean(entry.payload?.config_checked),
        auth_checked: Boolean(entry.payload?.auth_checked),
        auth_session_load_phase: cleanText(entry.payload?.auth_session_load_phase, ""),
        load_auth_session_reached: Boolean(entry.payload?.load_auth_session_reached),
        build_id: cleanText(entry.payload?.build_id, ""),
        message: cleanText(entry.payload?.message, "").slice(0, 220),
        elapsed_ms: entry.payload?.elapsed_ms || 0,
        reason: cleanText(entry.payload?.reason, "").slice(0, 120),
        has_google_client_id: Boolean(entry.payload?.has_google_client_id),
      },
    }))
    .join("\n");
}

function scheduleRendererAuthDiagnosticUpload(reason = "renderer-auth-diagnostic") {
  if (authDiagnosticUploadTimer) window.clearTimeout(authDiagnosticUploadTimer);
  authDiagnosticUploadTimer = window.setTimeout(() => {
    authDiagnosticUploadTimer = 0;
    void uploadRendererAuthDiagnostics(reason);
  }, 250);
}

async function uploadRendererAuthDiagnostics(reason = "renderer-auth-diagnostic") {
  if (!authDiagnosticBuffer.length) return;
  if (androidNativeBootNetworkQuiet() && !/fatal|error/i.test(reason)) return;
  const shell = androidNativeShellInfo();
  try {
    await fetch("/native/diagnostics", {
      method: "POST",
      cache: "no-store",
      headers: {
        "Accept": "application/json",
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        schema: "hermes.wasm_agent.renderer_auth_diagnostics.v1",
        device_id: authDiagnosticDeviceId(),
        build_id: authDiagnosticBuildId(),
        android_auth_session: shell.androidAuthSession,
        native_correlation_id: shell.nativeCorrelationId,
        install_device_hash: shell.installDeviceHash,
        reason,
        href: window.location.href,
        renderer_auth_diagnostics_tail: authDiagnosticTail(),
      }),
    });
  } catch {
    // Upload is best-effort; local/native diagnostics still continue.
  }
}

function nativeAuthDiagnostic(kind, payload = {}) {
  const uploadWorthy = /error|timeout|finished|skipped/i.test(kind);
  const nativeShell = androidNativeShellInfo();
  const diagnostic = {
    href: window.location.href,
    origin: window.location.origin,
    protocol: window.location.protocol,
    has_native_bridge: Boolean(window.wasmAgentNative),
    has_android_native_bridge: Boolean(window.wasmAgentAndroid),
    native_shell: nativeShell,
    config_checked: Boolean(state.configChecked),
    auth_checked: Boolean(state.authChecked),
    has_google_client_id: Boolean(state.googleClientId),
    google_login_uri: state.googleLoginUri || "",
    login_message: state.loginMessage || "",
    google_button_rendered_for: state.googleButtonRenderedFor || "",
    auth_session_load_phase: frontierRuntimeState.authSessionLoadPhase,
    load_auth_session_reached: Boolean(frontierRuntimeState.loadAuthSessionReached),
    build_id: authDiagnosticBuildId(),
    ...payload,
  };
  const entry = {
    timestamp: new Date().toISOString(),
    kind,
    payload: diagnostic,
  };
  authDiagnosticBuffer.push(entry);
  while (authDiagnosticBuffer.length > AUTH_DIAGNOSTIC_BUFFER_LIMIT) authDiagnosticBuffer.shift();
  if (uploadWorthy) {
    scheduleRendererAuthDiagnosticUpload(kind);
  }
  const nativeDiagnosticSuppressed = nativeShell.isAndroidNativeShell && androidNativeBridgeDiagnosticsOff() && !uploadWorthy;
  if (nativeShell.isAndroidNativeShell && !nativeDiagnosticSuppressed) {
    recordAndroidNativeDiagnostic(kind, diagnostic);
  }
  if (nativeDiagnosticSuppressed) return;
  if (deferAndroidBridgeDiagnostics) {
    queueAndroidBridgeDiagnostic(kind, diagnostic, "auth");
    return;
  }
  if (!window.wasmAgentNative?.logAuthDiagnostic) return;
  try {
    void window.wasmAgentNative.logAuthDiagnostic(kind, nativeShell.isAndroidNativeShell ? nativeBridgePayload(diagnostic) : diagnostic);
    if (
      window.wasmAgentNative.uploadAuthDiagnostics
      && uploadWorthy
    ) {
      void window.wasmAgentNative.uploadAuthDiagnostics();
    }
  } catch {
    // Diagnostics must never affect login.
  }
}

function reportRendererFatalError(kind, error, extra = {}) {
  const fatal = {
    kind,
    message: errorMessage(error),
    name: cleanText(error?.name, ""),
    stack: cleanStack(error),
    href: window.location.href,
    buildId: authDiagnosticBuildId(),
    authSessionLoadPhase: frontierRuntimeState.authSessionLoadPhase,
    loadAuthSessionReached: Boolean(frontierRuntimeState.loadAuthSessionReached),
    configChecked: Boolean(state.configChecked),
    authChecked: Boolean(state.authChecked),
    ...extra,
  };
  frontierRuntimeState.lastFatalError = fatal;
  clientBootTrace.errors.push({
    at_ms: clientBootElapsedMs(),
    ...redactClientBootTraceData(fatal),
  });
  while (clientBootTrace.errors.length > 40) clientBootTrace.errors.shift();
  clientBootMark(kind, fatal);
  try {
    window.__wasmAgentLastFatalError = fatal;
  } catch {
    // Keep reporting best-effort.
  }
  nativeAuthDiagnostic(kind, fatal);
  void uploadClientBootTrace(kind, { keepalive: true });
  void uploadRendererAuthDiagnostics(kind);
  return fatal;
}

function installRendererFatalTrap() {
  exposeClientBootTrace();
  clientBootMark("fatal_trap_installed");
  installClientBootInteractionProbe();
  exposeFrontierRendererState();
  window.addEventListener("error", (event) => {
    reportRendererFatalError("renderer_global_error", event.error || event.message, {
      source: cleanText(event.filename, ""),
      line: event.lineno || 0,
      column: event.colno || 0,
    });
  });
  window.addEventListener("unhandledrejection", (event) => {
    reportRendererFatalError("renderer_unhandled_rejection", event.reason || "Unhandled promise rejection");
  });
  window.addEventListener("visibilitychange", () => {
    clientBootMark("visibility_change", { visibility_state: document.visibilityState });
    if (document.visibilityState === "hidden") void uploadClientBootTrace("visibility_hidden", { beacon: true, keepalive: true });
  });
  window.addEventListener("pagehide", (event) => {
    clientBootMark("page_hide", { persisted: Boolean(event.persisted) });
    void uploadClientBootTrace("page_hide", { beacon: true, keepalive: true });
  });
}

function startNativeAuthDiagnosticHeartbeat() {
  if (!window.wasmAgentNative || nativeAuthDiagnosticHeartbeat) return;
  nativeAuthDiagnosticHeartbeatStartedAt = Date.now();
  nativeAuthDiagnostic("native_auth_diagnostic_heartbeat_started");
  nativeAuthDiagnosticHeartbeat = window.setInterval(() => {
    const elapsed = nativeAuthDiagnosticHeartbeatStartedAt ? Date.now() - nativeAuthDiagnosticHeartbeatStartedAt : 0;
    if (state.configChecked && state.authChecked) {
      window.clearInterval(nativeAuthDiagnosticHeartbeat);
      nativeAuthDiagnosticHeartbeat = 0;
      nativeAuthDiagnosticHeartbeatStartedAt = 0;
      nativeAuthDiagnostic("native_auth_diagnostic_heartbeat_stopped");
      return;
    }
    if (elapsed > 20000) {
      window.clearInterval(nativeAuthDiagnosticHeartbeat);
      nativeAuthDiagnosticHeartbeat = 0;
      nativeAuthDiagnosticHeartbeatStartedAt = 0;
      nativeAuthDiagnostic("native_auth_diagnostic_heartbeat_stopped", { reason: "timeout_cap" });
      return;
    }
    nativeAuthDiagnostic("native_auth_diagnostic_heartbeat", {
      config_load_pending: Boolean(state.configLoadPromise),
    });
  }, 8000);
}

function mergeNativePreloadConfig(config = {}, nativePayload = null) {
  if (!nativePayload || typeof nativePayload !== "object") return config || {};
  const nativeMeta = nativePayload.native && typeof nativePayload.native === "object"
    ? nativePayload.native
    : nativePayload;
  const nativeLooksLikeAppConfig = Boolean(nativePayload.appId || nativePayload.service || nativePayload.auth || nativePayload.deployment || nativePayload.features);
  const merged = {
    ...(nativeLooksLikeAppConfig ? nativePayload : {}),
    ...(config || {}),
  };
  merged.auth = {
    ...(nativePayload.auth || {}),
    ...((config || {}).auth || {}),
  };
  merged.native = {
    ...(nativeMeta || {}),
    ...((config || {}).native || {}),
  };
  if (!cleanText(merged.native.serverUrl, "") && cleanText(nativeMeta?.serverUrl, "")) {
    merged.native.serverUrl = cleanText(nativeMeta.serverUrl, "");
  }
  return merged;
}

function readCachedClientConfig() {
  try {
    const cached = JSON.parse(localStorage.getItem(CLIENT_CONFIG_STORAGE_KEY) || "null");
    return cached && typeof cached === "object" && cached.config && typeof cached.config === "object"
      ? cached.config
      : null;
  } catch {
    return null;
  }
}

function writeCachedClientConfig(config = {}) {
  if (!config || typeof config !== "object" || !config.auth?.googleClientId) return;
  try {
    localStorage.setItem(CLIENT_CONFIG_STORAGE_KEY, JSON.stringify({
      cached_at: new Date().toISOString(),
      config,
    }));
  } catch {
    // Cache is only a fast reload fallback.
  }
}

function readCachedAuthUser() {
  try {
    const cached = JSON.parse(localStorage.getItem(CLIENT_AUTH_USER_STORAGE_KEY) || "null");
    if (!cached || typeof cached !== "object" || !cached.user || typeof cached.user !== "object") return null;
    const cachedAt = Date.parse(cached.cached_at || "");
    if (!Number.isFinite(cachedAt) || Date.now() - cachedAt > 7 * 24 * 60 * 60 * 1000) return null;
    return cached.user;
  } catch {
    return null;
  }
}

function writeCachedAuthUser(user = null) {
  try {
    if (!user || typeof user !== "object") {
      localStorage.removeItem(CLIENT_AUTH_USER_STORAGE_KEY);
      return;
    }
    localStorage.setItem(CLIENT_AUTH_USER_STORAGE_KEY, JSON.stringify({
      cached_at: new Date().toISOString(),
      user,
    }));
  } catch {
    // Cached auth is only used for a fast stale-while-revalidate shell.
  }
}

function readAndroidPrepaintShell() {
  try {
    const shell = window.__WASM_AGENT_PREPAINT_SHELL;
    if (!shell || typeof shell !== "object" || !shell.authenticated) return null;
    return shell.user && typeof shell.user === "object" ? shell : null;
  } catch {
    return null;
  }
}

function markAndroidPrepaintShellVisible(shell = null, user = null) {
  const prepaint = shell || readAndroidPrepaintShell();
  if (!prepaint || prepaint.__app_marked) return Boolean(prepaint?.__app_marked);
  prepaint.__app_marked = true;
  const visibleAtMs = Number(prepaint.visibleAtMs || 0);
  const afterPaintAtMs = Number(prepaint.afterPaintAtMs || visibleAtMs || performance.now());
  const markData = {
    user_id: cleanText(user?.id || prepaint.user?.id, ""),
    email_present: Boolean(user?.email || prepaint.user?.email),
    pre_module: true,
    after_paint: Boolean(prepaint.afterPaintAtMs),
    pre_module_visible_at_ms: Math.round(visibleAtMs || afterPaintAtMs),
    pre_module_after_paint_at_ms: Math.round(afterPaintAtMs),
    pre_module_decorated_at_ms: Math.round(Number(prepaint.decoratedAtMs || 0)),
    config_cached: Boolean(prepaint.configCached),
    route: cleanText(prepaint.route, ""),
  };
  if (visibleAtMs) {
    clientBootMarkAt("pre_module_cached_authenticated_shell_visible", visibleAtMs, markData);
  }
  state.androidNativeFirstShellVisibleAtMs = afterPaintAtMs || performance.now();
  clientBootMarkAt("cached_authenticated_shell_visible", afterPaintAtMs || performance.now(), markData);
  return true;
}

function clearAndroidPrepaintShell(reason = "render") {
  const app = els.app || document.querySelector("#app");
  if (!app?.dataset?.androidPrepaint) return false;
  delete app.dataset.androidPrepaint;
  delete app.dataset.androidPrepaintAfterPaint;
  app.classList.remove("android-prepaint-authenticated");
  clientBootMark("pre_module_cached_authenticated_shell_released", {
    reason,
  });
  return true;
}

function applyClientConfigPayload(config = {}, options = {}) {
  const nativePayload = options.nativePayload || null;
  const merged = mergeNativePreloadConfig(config || {}, nativePayload);
  state.config = merged;
  if (merged.bridgeUrl) state.bridgeUrl = String(merged.bridgeUrl).replace(/\/$/, "");
  state.googleClientId = String(merged.auth?.googleClientId || "").trim();
  state.googleLoginUri = String(merged.auth?.googleLoginUri || "").trim();
  state.adminEmail = cleanText(merged.auth?.adminEmail, state.adminEmail);
  const timeoutSec = Number(merged.agentTurnTimeoutSec);
  if (Number.isFinite(timeoutSec) && timeoutSec >= 30) {
    state.agentTurnTimeoutMs = timeoutSec * 1000;
  }
  state.configChecked = true;
  if (merged.auth?.googleClientId) writeCachedClientConfig(merged);
  return merged;
}

function applyCachedClientConfigForBoot(reason = "cached_config") {
  const cachedConfig = readCachedClientConfig();
  if (!cachedConfig) return false;
  applyClientConfigPayload(cachedConfig, {
    nativePayload: state.config?.native ? { native: state.config.native } : null,
  });
  clientBootMark("cached_config_applied", {
    reason,
    has_google_client_id: Boolean(state.googleClientId),
  });
  return true;
}

async function loadConfig() {
  if (state.configLoadPromise) return state.configLoadPromise;
  state.configLoadPromise = loadConfigOnce();
  try {
    return await state.configLoadPromise;
  } finally {
    state.configLoadPromise = null;
  }
}

async function loadConfigOnce() {
  clientBootMark("config_load_started");
  nativeAuthDiagnostic("config_load_started");
  const nativeConfigPromise = loadNativePreloadConfig();
  let config = readCachedClientConfig() || {};
  let configFetchFailed = false;
  const startedAt = performance.now();
  try {
    config = await fetchJson("/config.json", {
      timeoutMs: isAndroidNativeShell() ? ANDROID_CONFIG_TIMEOUT_MS : window.wasmAgentNative ? 5000 : 10000,
    });
    writeCachedClientConfig(config);
    nativeAuthDiagnostic("config_fetch_resolved", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      has_google_client_id: Boolean(config.auth?.googleClientId),
      google_login_uri: String(config.auth?.googleLoginUri || ""),
    });
  } catch (error) {
    configFetchFailed = true;
    config = readCachedClientConfig() || {};
    nativeAuthDiagnostic("config_fetch_error", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      message: errorMessage(error),
      using_cached_config: Boolean(config.auth?.googleClientId),
    });
  }
  const nativeConfig = await nativeConfigPromise;
  config = window.wasmAgentNative && configFetchFailed && !config.auth?.googleClientId
    ? mergeNativePreloadConfig({ native: nativeConfig?.native || nativeConfig || {} }, nativeConfig && { native: nativeConfig.native || nativeConfig })
    : mergeNativePreloadConfig(config, nativeConfig);
  config = applyClientConfigPayload(config);
  nativeAuthDiagnostic("config_load_finished", {
    config_fetch_failed: configFetchFailed,
    has_google_client_id: Boolean(state.googleClientId),
    google_login_uri: state.googleLoginUri,
    native_server_url: cleanText(config?.native?.serverUrl, ""),
  });
  clientBootMark("config_load_finished", {
    config_fetch_failed: configFetchFailed,
    has_google_client_id: Boolean(state.googleClientId),
    google_login_uri: state.googleLoginUri,
    native_server_url: cleanText(config?.native?.serverUrl, ""),
    elapsed_ms: Math.round(performance.now() - startedAt),
  });
  if (window.wasmAgentNative && configFetchFailed && !state.googleClientId) {
    state.loginMessage = isAndroidNativeShell()
      ? "Loading Google login..."
      : "Backend connected incorrectly: /config.json unavailable";
    if (isAndroidNativeShell()) {
      window.setTimeout(() => {
        if (!state.googleClientId) void loadConfig();
      }, 1500);
    }
  } else if (!state.googleClientId && window.wasmAgentNative) {
    state.loginMessage = nativeBackendUnresolved()
      ? "No validated wasm-agent backend was selected."
      : `Google login config was not received from the wasm-agent backend at ${window.location.origin}.`;
  } else if (state.googleClientId && state.loginMessage === "Google login config was not received from the wasm-agent backend.") {
    state.loginMessage = "";
  }
  applyModuleVisibility();
  renderModules();
  renderLogin();
  if (shouldReloadNativeToRemotePwa(config)) {
    void window.wasmAgentNative.reload();
    return;
  }
  if (!state.authUser) {
    void renderGoogleSignInButton();
  }
  return state.config;
}

function publicUserLabel(user) {
  return cleanText(user?.name || user?.email, "Guest");
}

function publicUserInitial(user) {
  const label = publicUserLabel(user);
  return label.slice(0, 1).toUpperCase();
}

function isAdminUser(user = state.authUser) {
  return String(user?.role || "").toLowerCase() === "admin";
}

function nativeConfigState() {
  return state.config?.native && window.wasmAgentNative ? state.config.native : null;
}

function isWindowsNativeShellHost() {
  const native = nativeConfigState();
  const platform = cleanText(window.wasmAgentNative?.platform || native?.platform || native?.buildPlatform, "").toLowerCase();
  return Boolean(window.wasmAgentNative) && (platform === "windows" || platform === "win32" || platform.startsWith("win"));
}

function windowsNativeShellNeedsDiagnosticsUpdate() {
  return isWindowsNativeShellHost() && !window.wasmAgentNative?.nativeDiagnostics;
}

function windowsNativeShellDiagnosticsBridgeMissing() {
  return isWindowsNativeShellHost() && !window.wasmAgentNative?.nativeDiagnostics;
}

function nativeInstalledBuildId() {
  const androidInfo = androidNativeShellInfo();
  if (androidInfo.isAndroidNativeShell) {
    return cleanText(androidInfo.packageInfo?.buildId || androidInfo.buildId || androidInfo.build_id || nativeConfigState()?.buildId, "");
  }
  return cleanText(nativeConfigState()?.buildId || window.wasmAgentNative?.buildId || androidInfo.buildId || androidInfo.build_id, "");
}

function nativeResolutionBuildId(resolution = state.nativeInstallerResolution) {
  return cleanText(resolution?.buildId || resolution?.nativeBuildId || state.nativeUpdateState?.latestBuildId, "");
}

function nativeInstallerUpdateAvailable(resolution = state.nativeInstallerResolution, profile = state.nativeInstallProfile || detectNativeDeviceProfileSync()) {
  const platform = cleanText(resolution?.platform || profile?.platform || nativePackageInfoSync().platform, "unknown").toLowerCase();
  if (state.nativeUpdateState) {
    return state.nativeUpdateState.status === "update_available"
      && cleanText(state.nativeUpdateState.platform, "").toLowerCase() === platform;
  }
  if (!isWindowsNativeShellHost()) return false;
  const installed = nativeInstalledBuildId();
  const latest = nativeResolutionBuildId(resolution);
  return platform === "windows" && Boolean(resolution?.available && installed && latest && installed !== latest);
}

function nativePackageInfoSync() {
  const androidInfo = androidNativeShellInfo();
  let androidPackage = androidInfo.packageInfo || null;
  if (!androidPackage && window.wasmAgentNative?.packageInfo) {
    try {
      androidPackage = parseNativeBridgePayload(window.wasmAgentNative.packageInfo());
    } catch {
      androidPackage = null;
    }
  }
  return {
    platform: isWindowsNativeShellHost() ? "windows" : androidInfo.isAndroidNativeShell ? "android" : "web",
    buildId: nativeInstalledBuildId() || authDiagnosticBuildId(),
    version: cleanText(nativeConfigState()?.appVersion || nativeConfigState()?.wasmAgentVersion || androidPackage?.versionName, ""),
    packageName: cleanText(androidPackage?.packageName, ""),
    versionCode: Number(androidPackage?.versionCode || 0),
  };
}

function nativeReleaseArtifactForPlatform(manifest, profile = state.nativeInstallProfile || detectNativeDeviceProfileSync()) {
  const platform = cleanText(profile?.platform || nativePackageInfoSync().platform, "web").toLowerCase();
  const arch = cleanText(profile?.arch, "unknown").toLowerCase();
  if (platform === "windows") return manifest?.artifacts?.windows?.x64 || null;
  if (platform === "android") return manifest?.artifacts?.android?.[arch] || manifest?.artifacts?.android?.arm64 || manifest?.artifacts?.android?.universal || null;
  if (platform === "web") return manifest?.artifacts?.web?.current || null;
  return null;
}

function compareNativeUpdateState(current, artifact, profile = state.nativeInstallProfile || detectNativeDeviceProfileSync()) {
  const platform = cleanText(profile?.platform || current.platform, "web").toLowerCase();
  if (!artifact) {
    return { platform, status: "unavailable", currentBuildId: current.buildId, latestBuildId: "", artifactAvailable: false, safeUpdatePath: false };
  }
  const latestBuildId = cleanText(artifact.buildId, "");
  if (platform === "android") {
    if (artifact.packageName && current.packageName && artifact.packageName !== current.packageName) {
      return { platform, status: "update_failed", reason: "package name mismatch", currentBuildId: current.buildId, latestBuildId, artifactAvailable: true, safeUpdatePath: false };
    }
    if (current.buildId && latestBuildId && current.buildId !== latestBuildId) {
      return {
        platform,
        status: artifact.url ? "update_available" : "unavailable",
        currentBuildId: current.buildId,
        latestBuildId,
        artifactAvailable: Boolean(artifact.url),
        safeUpdatePath: Boolean(artifact.url),
        artifact,
        message: "Android requires OS confirmation to install this APK update.",
      };
    }
    if (!latestBuildId && Number(artifact.versionCode || 0) && Number(current.versionCode || 0) >= Number(artifact.versionCode || 0)) {
      return { platform, status: "up_to_date", currentBuildId: current.buildId, latestBuildId, artifactAvailable: true, safeUpdatePath: false };
    }
  }
  if (platform === "windows") {
    const currentBuildId = cleanText(current.buildId, "");
    const currentRank = currentBuildId.replace(/^win-x64-/i, "");
    const latestRank = latestBuildId.replace(/^win-x64-/i, "");
    const sameBuild = currentBuildId && latestBuildId && currentBuildId === latestBuildId;
    const newerBuild = currentBuildId && latestBuildId && latestRank > currentRank;
    const olderBuild = currentBuildId && latestBuildId && latestRank < currentRank;
    const safeUpdatePath = Boolean(artifact.url);
    return {
      platform,
      status: sameBuild || olderBuild ? "up_to_date" : newerBuild && safeUpdatePath ? "update_available" : "unavailable",
      reason: sameBuild ? "same_build" : olderBuild ? "older_build_ignored" : newerBuild ? "newer_build_available" : "missing_build_id",
      comparisonMode: "buildId",
      currentBuildId,
      currentVersion: current.version,
      latestBuildId,
      latestVersion: cleanText(artifact.version, ""),
      artifactAvailable: Boolean(artifact.url),
      safeUpdatePath,
      artifact,
    };
  }
  const sameBuild = current.buildId && latestBuildId && current.buildId === latestBuildId;
  const safeUpdatePath = ["windows", "android", "web"].includes(platform) && Boolean(artifact.url);
  return {
    platform,
    status: sameBuild ? "up_to_date" : safeUpdatePath ? "update_available" : "unavailable",
    currentBuildId: current.buildId,
    currentVersion: current.version,
    latestBuildId,
    latestVersion: cleanText(artifact.version, ""),
    artifactAvailable: Boolean(artifact.url),
    safeUpdatePath,
    artifact,
    message: platform === "android" ? "Android requires OS confirmation to install this APK update." : "",
  };
}

async function loadNativeReleaseManifest() {
  const manifestUrl = `/native/releases/latest.json?_=${Date.now()}`;
  const manifest = await fetchJson(manifestUrl, { timeoutMs: 5000, cache: "no-store" });
  state.nativeReleaseManifest = manifest;
  const artifact = nativeReleaseArtifactForPlatform(manifest);
  state.nativeUpdateState = compareNativeUpdateState(nativePackageInfoSync(), artifact);
  return manifest;
}

function nativeInstallProfileForContext(profile = null) {
  const base = profile || detectNativeDeviceProfileSync();
  if (!isWindowsNativeShellHost() || (!windowsNativeShellNeedsDiagnosticsUpdate() && !nativeInstallerUpdateAvailable())) return base;
  if (!windowsNativeShellNeedsDiagnosticsUpdate() && !nativeInstallerUpdateAvailable(null, base)) return base;
  return {
    ...base,
    platform: "windows",
    os: "Windows",
    device_type: "desktop",
    deviceType: "desktop",
    install_channel: "windows-installer",
    installChannel: "windows-installer",
  };
}

function nativeBackendUnresolved() {
  const native = nativeConfigState();
  return Boolean(native) && !cleanText(native.serverUrl, "");
}

function androidNativeBootNetworkQuiet() {
  return isAndroidNativeShell() && (!state.configChecked || !state.authChecked);
}

function googleLoginConfigPending() {
  return !state.googleClientId && (
    !state.configChecked
      || Boolean(state.configLoadPromise)
      || (isAndroidNativeShell() && state.loginMessage === "Loading Google login...")
  );
}

function nativeInstallVersionLabel() {
  const native = nativeConfigState();
  if (!native) return "";
  const version = cleanText(native.installableVersion || native.wasmAgentVersion || native.nativeShellVersion || native.appVersion, "");
  const buildId = cleanText(native.buildId, "");
  const builtAt = cleanText(native.buildGeneratedAt, "");
  const shortBuild = buildId
    ? buildId.replace(/^win-x64-/, "")
    : builtAt.replace(/[-:]/g, "").replace(/\.\d{3}Z$/, "Z");
  const platform = cleanText(native.buildPlatform || native.platform, "windows");
  return [platform, version, shortBuild ? `build ${shortBuild}` : ""].filter(Boolean).join(" ");
}

function shouldReloadNativeToRemotePwa(config = state.config) {
  const serverUrl = cleanText(config?.native?.serverUrl, "");
  return Boolean(window.wasmAgentNative?.reload && serverUrl && window.location.protocol === "wasm-agent:");
}

function setLoginOpen(open) {
  const nextOpen = Boolean(open);
  if (!nextOpen && closeUiNavigationLayer("login-popover")) return;
  state.loginOpen = nextOpen;
  if (!els.loginPopover || !els.loginButton) return;
  els.loginPopover.hidden = !state.loginOpen;
  els.loginButton.setAttribute("aria-expanded", state.loginOpen ? "true" : "false");
  if (state.loginOpen) {
    renderLogin();
    void renderGoogleSignInButton();
    pushUiNavigationLayer("login-popover", () => {
      state.loginOpen = false;
      if (els.loginPopover) els.loginPopover.hidden = true;
      els.loginButton?.setAttribute("aria-expanded", "false");
    });
  }
}

function renderAuthGate() {
  if (!els.app) return;
  const authenticated = Boolean(state.authUser);
  els.app.dataset.auth = authenticated ? "ready" : state.authChecked ? "locked" : "checking";
  els.app.dataset.status = authenticated ? "ready" : state.authChecked ? "auth-ready" : "booting";
  if (els.authGateCopy) {
    els.authGateCopy.textContent = nativeBackendUnresolved()
      ? "Connect this native app to a validated wasm-agent backend to continue."
      : googleLoginConfigPending()
      ? "Loading Google login..."
      : state.googleClientId
      ? "Sign in with an allowlisted Google account to open wasm-agent."
      : `Google login is not configured on this server yet. Origin: ${window.location.origin}`;
  }
  if (els.authGateMessage) {
    els.authGateMessage.textContent = authenticated
      ? ""
      : googleLoginConfigPending() ? "Loading Google login..."
      : state.authChecked ? state.loginMessage || (nativeBackendUnresolved() ? "No validated wasm-agent backend was selected." : state.googleClientId ? "" : "Google login is not configured.") : "";
  }
}

function renderLogin() {
  if (!els.launcherLogin) return;
  const user = state.authUser;
  const missingGoogleLoginMessage = nativeBackendUnresolved()
    ? "No validated wasm-agent backend was selected."
    : googleLoginConfigPending()
      ? "Loading Google login..."
    : state.configChecked || state.authChecked
      ? `Google login is not configured on this server. Origin: ${window.location.origin}`
      : "Loading Google login...";
  els.launcherLogin.classList.toggle("signed-in", Boolean(user));
  els.launcherLogin.classList.toggle("needs-config", !state.googleClientId && !user);
  els.launcherLogin.classList.toggle("error", Boolean(state.loginMessage) && !user && Boolean(state.googleClientId));
  if (els.loginAvatar) {
    if (user?.picture_url) els.loginAvatar.replaceChildren();
    else if (user) els.loginAvatar.textContent = publicUserInitial(user);
    else if (!els.loginAvatar.querySelector(".google-logo")) {
      const logo = document.createElement("img");
      logo.className = "google-logo";
      logo.src = "/icons/google-logo.svg";
      logo.alt = "";
      els.loginAvatar.replaceChildren(logo);
    }
    els.loginAvatar.style.backgroundImage = user?.picture_url ? `url("${user.picture_url}")` : "";
  }
  if (els.loginButton) {
    els.loginButton.title = user ? publicUserLabel(user) : "Sign in with Google";
    els.loginButton.setAttribute("aria-label", user ? `Account ${publicUserLabel(user)}` : "Sign in with Google");
  }
  if (els.loginTitle) els.loginTitle.textContent = user ? publicUserLabel(user) : "Sign in";
  if (els.loginMeta) {
    const nativeLabel = nativeInstallVersionLabel();
    els.loginMeta.textContent = user
      ? cleanText(user.email, "Google account")
      : nativeLabel ? `Google / ${nativeLabel}` : "Google";
  }
  if (els.loginFluxBalance) {
    const balance = Number(state.agentCredits?.balance || 0);
    els.loginFluxBalance.hidden = !user || isAdminUser();
    els.loginFluxBalance.textContent = `${balance}◇ Flux`;
    els.loginFluxBalance.title = state.agentCredits ? "Available Flux balance" : "Flux balance not loaded yet";
  }
  if (els.googleSignInButton) {
    els.googleSignInButton.setAttribute("aria-label", "Sign in with Google");
    els.googleSignInButton.dataset.testid = "google-signin-slot";
    els.googleSignInButton.hidden = Boolean(user);
    if (user) els.googleSignInButton.replaceChildren();
  }
  if (els.authGateGoogleSignInButton) {
    els.authGateGoogleSignInButton.setAttribute("aria-label", "Sign in with Google");
    els.authGateGoogleSignInButton.dataset.testid = "auth-gate-google-signin-slot";
    els.authGateGoogleSignInButton.hidden = Boolean(user) || !state.googleClientId;
    if (user) els.authGateGoogleSignInButton.replaceChildren();
  }
  if (els.authGateLoginButton) {
    els.authGateLoginButton.setAttribute("aria-label", "Sign in with Google");
    els.authGateLoginButton.dataset.testid = "google-signin-button";
    els.authGateLoginButton.hidden = Boolean(user) || !state.authChecked || !state.googleClientId || (
      Boolean(state.googleClientId) && Boolean(els.authGateGoogleSignInButton?.childElementCount)
    );
  }
  if (els.logoutButton) els.logoutButton.hidden = !user;
  if (els.loginMessage) {
    els.loginMessage.textContent = user
      ? `${cleanText(user.role, "user")} account ${user.id}`
      : state.loginMessage || (state.googleClientId ? "Only allowlisted accounts can enter." : missingGoogleLoginMessage);
  }
  renderAuthGate();
  reportAndroidNativeReadiness("render_login");
}

function loadGoogleIdentityScript() {
  if (!state.googleClientId) return Promise.reject(new Error("Google login is not configured on this server."));
  if (window.google?.accounts?.id) {
    installGoogleStyleOverrides();
    nativeAuthDiagnostic("google_identity_script_already_loaded");
    return Promise.resolve();
  }
  if (window.__wasmAgentGoogleIdentityPromise) return window.__wasmAgentGoogleIdentityPromise;
  window.__wasmAgentGoogleIdentityPromise = new Promise((resolve, reject) => {
    let timeout = 0;
    const startedAt = performance.now();
    const script = document.createElement("script");
    script.src = "https://accounts.google.com/gsi/client";
    script.async = true;
    script.defer = true;
    script.onload = () => {
      if (timeout) window.clearTimeout(timeout);
      installGoogleStyleOverrides();
      nativeAuthDiagnostic("google_identity_script_loaded", {
        elapsed_ms: Math.round(performance.now() - startedAt),
      });
      resolve();
    };
    script.onerror = () => {
      if (timeout) window.clearTimeout(timeout);
      nativeAuthDiagnostic("google_identity_script_error", {
        elapsed_ms: Math.round(performance.now() - startedAt),
      });
      reject(new Error("Google Identity failed to load"));
    };
    timeout = window.setTimeout(() => {
      nativeAuthDiagnostic("google_identity_script_timeout", {
        elapsed_ms: Math.round(performance.now() - startedAt),
      });
      reject(new Error("Google Identity timed out while loading"));
    }, 10000);
    nativeAuthDiagnostic("google_identity_script_append", {
      src: script.src,
    });
    document.head.append(script);
  });
  return window.__wasmAgentGoogleIdentityPromise;
}

function installGoogleStyleOverrides() {
  const id = "wasmAgentGoogleStyleOverrides";
  document.querySelector(`#${id}`)?.remove();
  const style = document.createElement("style");
  style.id = id;
  style.textContent = `
    .google-signin-slot .nsm7Bb-HzV7m-LgbsSe-Bz112c-haAclf,
    .google-signin-slot [id="container-div"] {
      background: transparent !important;
      background-color: transparent !important;
      box-shadow: none !important;
    }
    .google-signin-slot .nsm7Bb-HzV7m-LgbsSe-Bz112c-haAclf {
      min-width: 28px !important;
      width: 28px !important;
      height: 28px !important;
      margin-left: -4px !important;
      margin-right: 10px !important;
    }
    .google-signin-slot .nsm7Bb-HzV7m-LgbsSe {
      background: rgba(10, 18, 30, 0.96) !important;
      border-color: rgba(147, 170, 203, 0.18) !important;
      color: #e8eef7 !important;
    }
  `;
  document.head.append(style);
}

function googleLoginUri() {
  const fallback = new URL("/auth/google/callback", window.location.origin).href;
  try {
    return new URL(state.googleLoginUri || fallback, window.location.origin).href;
  } catch {
    return fallback;
  }
}

function googleSignInUsesCredentialCallback() {
  return Boolean(window.wasmAgentNative && window.location.protocol === "wasm-agent:");
}

function googleSignInConfig(loginUri) {
  const config = {
    client_id: state.googleClientId,
    callback: handleGoogleCredential,
  };
  if (googleSignInUsesCredentialCallback()) return config;
  return {
    ...config,
    ux_mode: "redirect",
    login_uri: loginUri,
  };
}

function androidNativeAuthSessionId() {
  let sessionId = "";
  try {
    sessionId = cleanText(new URL(window.location.href).searchParams.get("android_auth_session"), "");
  } catch {
    sessionId = "";
  }
  if (!sessionId && window.wasmAgentAndroid?.authSessionId) {
    try {
      sessionId = cleanText(window.wasmAgentAndroid.authSessionId(), "");
    } catch {
      sessionId = "";
    }
  }
  if (!sessionId) {
    try {
      sessionId = cleanText(window.localStorage.getItem(ANDROID_NATIVE_AUTH_SESSION_STORAGE_KEY), "");
    } catch {
      sessionId = "";
    }
  }
  if (sessionId) {
    try {
      window.localStorage.setItem(ANDROID_NATIVE_AUTH_SESSION_STORAGE_KEY, sessionId);
    } catch {
      // Losing this only forces the user to retry Android native auth.
    }
  }
  return sessionId;
}

function startAndroidNativeGoogleLoginIfAvailable(reason = "") {
  const sessionId = androidNativeAuthSessionId();
  if (!sessionId || !window.wasmAgentAndroid?.startGoogleLogin) return false;
  recordAndroidNativeDiagnostic("login_clicked", {
    reason: cleanText(reason, ""),
    android_auth_session: sessionId,
  });
  if (state.androidNativeAuthStartedFor === sessionId) {
    recordAndroidNativeDiagnostic("retry", {
      reason: cleanText(reason, ""),
      android_auth_session: sessionId,
    });
    nativeAuthDiagnostic("android_native_google_login_retry_after_stale_start", {
      reason: cleanText(reason, ""),
      session: sessionId,
    });
  }
  state.androidNativeAuthStartedFor = sessionId;
  state.loginMessage = "Opening Google sign-in...";
  nativeAuthDiagnostic("android_native_google_login_start_requested", {
    reason: cleanText(reason, ""),
    session: sessionId,
  });
  recordAndroidNativeDiagnostic("oauth_start", {
    reason: cleanText(reason, ""),
    android_auth_session: sessionId,
  });
  renderLogin();
  try {
    window.wasmAgentAndroid.startGoogleLogin();
    return true;
  } catch (error) {
    state.androidNativeAuthStartedFor = "";
    state.loginMessage = errorMessage(error);
    nativeAuthDiagnostic("android_native_google_login_start_error", {
      message: errorMessage(error),
    });
    renderLogin();
    return false;
  }
}

function resetAndroidNativeGoogleLogin(reason = "", message = "") {
  if (!state.androidNativeAuthStartedFor && state.loginMessage !== "Opening Google sign-in...") return false;
  recordAndroidNativeDiagnostic("reset", {
    reason: cleanText(reason, ""),
    previous_session: state.androidNativeAuthStartedFor,
  });
  nativeAuthDiagnostic("android_native_google_login_reset", {
    reason: cleanText(reason, ""),
    previous_session: state.androidNativeAuthStartedFor,
  });
  state.androidNativeAuthStartedFor = "";
  if (!state.authRedirectMessage && state.loginMessage === "Opening Google sign-in...") {
    state.loginMessage = cleanText(message, "");
  }
  renderLogin();
  void renderGoogleSignInButton();
  return true;
}

function renderAndroidNativeGoogleSignIn(slots, renderKey, reason = "") {
  const sessionId = androidNativeAuthSessionId();
  if (!sessionId || !window.wasmAgentAndroid?.startGoogleLogin) return false;
  slots.forEach((slot) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "native-google-button";
    button.textContent = "Sign in with Google";
    button.setAttribute("aria-label", "Sign in with Google");
    button.setAttribute("data-testid", "google-signin-button");
    button.setAttribute("data-native-android-oauth", "google-signin");
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      startAndroidNativeGoogleLoginIfAvailable("android-native-google-button");
    });
    slot.replaceChildren(button);
    slot.hidden = false;
  });
  state.googleButtonRenderedFor = renderKey;
  state.loginMessage = state.loginMessage === "Loading Google login..." ? "" : state.loginMessage;
  nativeAuthDiagnostic("android_native_google_button_rendered", {
    render_key: renderKey,
    session: sessionId,
    reason: cleanText(reason, ""),
    slot_count: slots.length,
  });
  reportAndroidNativeReadiness("android_native_google_button_rendered", {
    render_key: renderKey,
    session: sessionId,
    slot_count: slots.length,
  });
  if (els.authGateLoginButton) els.authGateLoginButton.hidden = true;
  return true;
}

async function completeAndroidNativeAuthIfNeeded(reason = "") {
  const sessionId = androidNativeAuthSessionId();
  if (!sessionId || state.androidNativeAuthDoneFor === sessionId) return false;
  state.androidNativeAuthDoneFor = sessionId;
  nativeAuthDiagnostic("android_native_browser_completion_blocked", {
    reason: cleanText(reason, ""),
    session: sessionId,
  });
  return false;
}

async function flushNativeAuthCookies(reason) {
  if (!window.wasmAgentNative?.flushAuthCookies) return null;
  try {
    const result = parseNativeBridgePayload(await window.wasmAgentNative.flushAuthCookies(isAndroidNativeShell()
      ? nativeBridgePayload({ reason })
      : { reason }));
    nativeAuthDiagnostic("native_auth_cookie_flush_finished", {
      ok: Boolean(result?.ok),
      has_wa_uid: Boolean(result?.hasWaUid),
      cookie_count: Number(result?.cookieCount || 0),
      reason,
    });
    recordAndroidNativeDiagnostic("cookie_flush", {
      ok: Boolean(result?.ok),
      has_wa_uid: Boolean(result?.hasWaUid),
      cookie_count: Number(result?.cookieCount || 0),
      reason,
    });
    return result;
  } catch (error) {
    nativeAuthDiagnostic("native_auth_cookie_flush_error", {
      message: errorMessage(error),
      reason,
    });
    recordAndroidNativeDiagnostic("error", {
      stage: "cookie_flush",
      message: errorMessage(error),
      reason,
    });
    return null;
  }
}

function authRedirectMessageFromUrl() {
  const params = new URLSearchParams(window.location.search);
  const code = cleanText(params.get("auth_error"), "");
  if (!code) return "";
  const message = cleanText(params.get("message"), "");
  if (message) return message;
  if (code === "google_account_not_allowed") return "This Google account is not allowed to access wasm-agent.";
  if (code === "google_login_not_configured") return "Google login is not configured on this server.";
  if (code === "google_token_rejected") return "Google rejected the sign-in token.";
  return "Google sign-in failed.";
}

function consumeAuthRedirectMessage() {
  const message = authRedirectMessageFromUrl();
  if (!message) return;
  state.authRedirectMessage = message;
  state.loginMessage = message;
  try {
    const url = new URL(window.location.href);
    url.searchParams.delete("auth_error");
    url.searchParams.delete("message");
    window.history.replaceState(window.history.state, "", `${url.pathname}${url.search}${url.hash}`);
  } catch {
    // Leaving the URL untouched is better than hiding the original auth error.
  }
}

function authRedirectCodeFromUrl() {
  try {
    return cleanText(new URL(window.location.href).searchParams.get("auth_code"), "");
  } catch {
    return "";
  }
}

function removeAuthRedirectCodeFromUrl() {
  try {
    const url = new URL(window.location.href);
    url.searchParams.delete("auth_code");
    window.history.replaceState(window.history.state, "", `${url.pathname}${url.search}${url.hash}`);
  } catch {
    // Leaving the URL untouched is better than breaking auth bootstrap.
  }
}

async function redeemAuthRedirectCode() {
  const code = authRedirectCodeFromUrl();
  if (!code) return false;
  const androidAuthSession = androidNativeAuthSessionId();
  const startedAt = performance.now();
  clientBootMark("auth_redirect_code_redeem_started", {
    android_auth_session: androidAuthSession,
  });
  nativeAuthDiagnostic("auth_redirect_code_redeem_started");
  recordAndroidNativeDiagnostic("auth_polling", {
    reason: "auth_redirect_code_redeem_started",
    android_auth_session: androidAuthSession,
  });
  try {
    const payload = await fetchJson("/auth/redeem", {
      method: "POST",
      body: { code, android_auth_session: androidAuthSession },
      timeoutMs: isAndroidNativeShell() ? ANDROID_AUTH_REDEEM_TIMEOUT_MS : 8000,
    });
    state.authUser = payload.user || null;
    writeCachedAuthUser(state.authUser);
    state.authRedirectMessage = "";
    state.loginMessage = "";
    void flushNativeAuthCookies("auth_redirect_redeem");
    removeAuthRedirectCodeFromUrl();
    clientBootMark("auth_redirect_code_redeem_finished", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      authenticated: Boolean(state.authUser),
    });
    nativeAuthDiagnostic("auth_redirect_code_redeem_finished", {
      authenticated: Boolean(state.authUser),
    });
    recordAndroidNativeDiagnostic("authenticated_ui_visible", {
      reason: "auth_redirect_code_redeem_finished",
      authenticated: Boolean(state.authUser),
      android_auth_session: androidAuthSession,
    });
    void completeAndroidNativeAuthIfNeeded("auth_redirect_code_redeemed");
    return Boolean(state.authUser);
  } catch (error) {
    removeAuthRedirectCodeFromUrl();
    state.authRedirectMessage = errorMessage(error);
    state.loginMessage = state.authRedirectMessage;
    clientBootMark("auth_redirect_code_redeem_error", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      message: errorMessage(error),
    });
    nativeAuthDiagnostic("auth_redirect_code_redeem_error", {
      message: errorMessage(error),
    });
    recordAndroidNativeDiagnostic("error", {
      stage: "auth_redirect_code_redeem",
      message: errorMessage(error),
      android_auth_session: androidAuthSession,
    });
    return false;
  }
}

async function renderGoogleSignInButton() {
  const startedAt = performance.now();
  const shouldRender = state.loginOpen || (!state.authUser && els.app?.dataset.auth === "locked");
  const slots = [els.googleSignInButton, els.authGateGoogleSignInButton].filter(Boolean);
  clientBootMark("google_button_render_requested", {
    should_render: shouldRender,
    slot_count: slots.length,
    auth_user: Boolean(state.authUser),
  });
  nativeAuthDiagnostic("google_button_render_requested", {
    should_render: shouldRender,
    slot_count: slots.length,
    auth_user: Boolean(state.authUser),
  });
  if (!state.configChecked) {
    if (isAndroidNativeShell() && renderAndroidNativeGoogleSignIn(slots, "android-native-config-pending", "android-native-shell")) {
      clientBootMark("google_button_rendered", {
        mode: "android-native-shell",
        config_pending: true,
        elapsed_ms: Math.round(performance.now() - startedAt),
        slot_child_counts: slots.map((slot) => slot.childElementCount),
      });
      scheduleClientBootTraceUpload("google_button_rendered");
      void loadConfig();
      return;
    }
    clientBootMark("google_button_render_skipped", { reason: "config_not_checked" });
    nativeAuthDiagnostic("google_button_render_skipped", { reason: "config_not_checked" });
    void loadConfig();
    return;
  }
  if (!shouldRender || state.authUser || !slots.length) {
    clientBootMark("google_button_render_skipped", {
      reason: !shouldRender ? "not_visible" : state.authUser ? "already_authenticated" : "missing_slots",
    });
    nativeAuthDiagnostic("google_button_render_skipped", {
      reason: !shouldRender ? "not_visible" : state.authUser ? "already_authenticated" : "missing_slots",
    });
    return;
  }
  if (!state.googleClientId) {
    if (isAndroidNativeShell() && renderAndroidNativeGoogleSignIn(slots, "android-native-missing-google-client-id", "android-native-shell")) {
      state.loginMessage = "";
      clientBootMark("google_button_rendered", {
        mode: "android-native-shell",
        config_missing_google_client_id: true,
        elapsed_ms: Math.round(performance.now() - startedAt),
        slot_child_counts: slots.map((slot) => slot.childElementCount),
      });
      scheduleClientBootTraceUpload("google_button_rendered");
      return;
    }
    slots.forEach((slot) => slot.replaceChildren());
    state.loginMessage = "Google login is not configured.";
    clientBootMark("google_button_render_skipped", { reason: "missing_google_client_id" });
    nativeAuthDiagnostic("google_button_render_skipped", { reason: "missing_google_client_id" });
    renderLogin();
    return;
  }
  const loginUri = googleLoginUri();
  const renderKey = `${state.googleClientId}|${loginUri}`;
  if (state.googleButtonRenderedFor === renderKey && slots.every((slot) => slot.childElementCount)) {
    clientBootMark("google_button_render_skipped", { reason: "already_rendered", render_key: renderKey });
    nativeAuthDiagnostic("google_button_render_skipped", { reason: "already_rendered", render_key: renderKey });
    return;
  }
  if (!state.authRedirectMessage) state.loginMessage = "";
  renderLogin();
  if (isAndroidNativeShell() && renderAndroidNativeGoogleSignIn(slots, renderKey, "android-native-shell")) {
    clientBootMark("google_button_rendered", {
      mode: "android-native-shell",
      elapsed_ms: Math.round(performance.now() - startedAt),
      slot_child_counts: slots.map((slot) => slot.childElementCount),
    });
    scheduleClientBootTraceUpload("google_button_rendered");
    return;
  }
  try {
    await loadGoogleIdentityScript();
    const signInMode = googleSignInUsesCredentialCallback() ? "native-callback" : "redirect";
    nativeAuthDiagnostic("google_button_initialize", {
      login_uri: loginUri,
      mode: signInMode,
    });
    window.google.accounts.id.initialize(googleSignInConfig(loginUri));
    slots.forEach((slot) => {
      slot.replaceChildren();
      window.google.accounts.id.renderButton(slot, {
        type: "standard",
        theme: "filled_black",
        size: "large",
        text: "signin_with",
        shape: "rectangular",
        logo_alignment: "left",
        width: Math.max(220, Math.min(320, Math.round(slot.getBoundingClientRect().width || 260))),
      });
    });
    installGoogleStyleOverrides();
    state.googleButtonRenderedFor = renderKey;
    clientBootMark("google_button_rendered", {
      mode: signInMode,
      elapsed_ms: Math.round(performance.now() - startedAt),
      render_key: renderKey,
      slot_child_counts: slots.map((slot) => slot.childElementCount),
    });
    scheduleClientBootTraceUpload("google_button_rendered");
    nativeAuthDiagnostic("google_button_rendered", {
      render_key: renderKey,
      slot_child_counts: slots.map((slot) => slot.childElementCount),
    });
    reportAndroidNativeReadiness("google_button_rendered", {
      render_key: renderKey,
      slot_child_counts: slots.map((slot) => slot.childElementCount),
    });
    if (els.authGateLoginButton && els.authGateGoogleSignInButton?.childElementCount) {
      els.authGateLoginButton.hidden = true;
    }
  } catch (error) {
    state.loginMessage = errorMessage(error);
    clientBootMark("google_button_render_error", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      message: errorMessage(error),
    });
    scheduleClientBootTraceUpload("google_button_render_error");
    nativeAuthDiagnostic("google_button_render_error", {
      message: errorMessage(error),
    });
    if (startAndroidNativeGoogleLoginIfAvailable(errorMessage(error))) return;
    renderLogin();
  }
}

async function loadAuthSession() {
  frontierRuntimeState.loadAuthSessionReached = true;
  frontierRuntimeState.authSessionLoadPhase = "started";
  clientBootMark("auth_session_load_started", {
    android_auth_session: androidNativeAuthSessionId(),
  });
  nativeAuthDiagnostic("auth_session_load_started");
  recordAndroidNativeDiagnostic("auth_polling", {
    reason: "auth_session_load_started",
    android_auth_session: androidNativeAuthSessionId(),
  });
  const startedAt = performance.now();
  try {
    const payload = await fetchJson("/auth/session", { timeoutMs: isAndroidNativeShell() ? ANDROID_AUTH_SESSION_TIMEOUT_MS : 8000 });
    state.authUser = payload.user || null;
    frontierRuntimeState.authSessionLoadPhase = payload.user ? "authenticated" : "anonymous";
    nativeAuthDiagnostic("auth_session_load_finished", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      authenticated: Boolean(state.authUser),
    });
    clientBootMark("auth_session_load_finished", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      authenticated: Boolean(state.authUser),
      phase: frontierRuntimeState.authSessionLoadPhase,
    });
    if (state.authUser) {
      writeCachedAuthUser(state.authUser);
      recordAndroidNativeDiagnostic("authenticated_ui_visible", {
        reason: "auth_session_load_finished",
        android_auth_session: androidNativeAuthSessionId(),
      });
    }
    if (state.authUser) {
      state.loginMessage = "";
      state.authRedirectMessage = "";
      void completeAndroidNativeAuthIfNeeded("auth_session_loaded");
    } else if (!state.authRedirectMessage) {
      writeCachedAuthUser(null);
      state.loginMessage = "";
    }
  } catch (error) {
    state.authUser = null;
    frontierRuntimeState.authSessionLoadPhase = "error";
    nativeAuthDiagnostic("auth_session_load_error", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      message: errorMessage(error),
    });
    clientBootMark("auth_session_load_error", {
      elapsed_ms: Math.round(performance.now() - startedAt),
      message: errorMessage(error),
    });
    recordAndroidNativeDiagnostic("error", {
      stage: "auth_session_load",
      message: errorMessage(error),
      android_auth_session: androidNativeAuthSessionId(),
    });
    if (!state.authRedirectMessage) state.loginMessage = error.message;
  }
  loadAgentDirectProviderForUser();
  loadAgentOwnedAgentForUser();
  state.authChecked = true;
  if (state.authUser) startRemoteControlLiveSocket("auth-session");
  else closeRemoteControlLiveSocket({ reconnect: false });
  renderLogin();
  scheduleClientBootTraceUpload("auth_session_checked");
}

async function handleGoogleCredential(response) {
  const credential = String(response?.credential || "");
  if (!credential) return;
  state.loginMessage = "Signing in...";
  renderLogin();
  try {
    const payload = await fetchJson("/auth/google", {
      method: "POST",
      body: { credential },
      timeoutMs: 15000,
    });
    state.authUser = payload.user || null;
    writeCachedAuthUser(state.authUser);
    loadAgentDirectProviderForUser();
    loadAgentOwnedAgentForUser();
    state.loginMessage = "";
    state.authRedirectMessage = "";
    await flushNativeAuthCookies("google_credential_callback");
    void completeAndroidNativeAuthIfNeeded("google_credential_callback");
    setLoginOpen(false);
    await bootstrapAuthenticatedApp();
    recordUserEvent("auth.google_login_finished", {
      target: "account",
      summary: `Signed in ${publicUserLabel(state.authUser)}`,
      data: { user_id: state.authUser?.id || "", email: state.authUser?.email || "" },
      redacted: true,
    });
  } catch (error) {
    state.loginMessage = error.message;
  }
  renderLogin();
}

async function logout() {
  try {
    await fetchJson("/auth/logout", { method: "POST", timeoutMs: 8000 });
  } catch {
    // Clearing local session state keeps the UI honest even if the server is restarting.
  }
  state.authUser = null;
  writeCachedAuthUser(null);
  state.agentDirectProviders = [];
  state.agentDirectProvider = null;
  state.agentOwnedAgent = null;
  state.nodeFormOpen = false;
  state.agentTopicFormOpen = false;
  state.loginMessage = "";
  state.authRedirectMessage = "";
  state.googleButtonRenderedFor = "";
  renderLogin();
  if (state.loginOpen) void renderGoogleSignInButton();
  if (state.refreshInterval) {
    window.clearInterval(state.refreshInterval);
    state.refreshInterval = 0;
  }
  if (state.resourceInterval) {
    window.clearInterval(state.resourceInterval);
    state.resourceInterval = 0;
  }
  if (state.securityInterval) {
    window.clearInterval(state.securityInterval);
    state.securityInterval = 0;
  }
  if (state.socialSyncInterval) {
    window.clearInterval(state.socialSyncInterval);
    state.socialSyncInterval = 0;
  }
  closeRemoteControlLiveSocket({ reconnect: false });
  if (isBrowserStreamOpen() || state.browserLive) stopBrowserLive();
  state.authenticatedBootstrapped = false;
  renderAuthGate();
  recordUserEvent("auth.logout_finished", {
    target: "account",
    summary: "Signed out",
  });
}

async function loadWasm() {
  try {
    const bytes = bytesFromBase64(CORE_WASM_BASE64);
    const result = await WebAssembly.instantiate(bytes);
    state.wasm = result.instance.exports;
    state.wasmReady = typeof state.wasm.add === "function";
  } catch (error) {
    state.wasmReady = false;
    state.lastError = `WASM load error: ${error.message}`;
  }
}

function clientDeviceId() {
  try {
    const raw = JSON.parse(localStorage.getItem(CLIENT_DEVICE_STORAGE_KEY) || "{}");
    if (raw?.id && /^[a-z0-9_-]{8,96}$/i.test(raw.id)) return raw.id;
  } catch {
    // Device identity is local convenience state; a fresh id is safe.
  }
  const id = `dev_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 12)}`;
  try {
    localStorage.setItem(CLIENT_DEVICE_STORAGE_KEY, JSON.stringify({ id, created_at: new Date().toISOString() }));
  } catch {
    // The backend can fall back to user-agent/IP if local storage is blocked.
  }
  return id;
}

async function fetchJson(path, options = {}) {
  const controller = new AbortController();
  const abortFromCaller = () => controller.abort();
  if (options.signal) options.signal.addEventListener("abort", abortFromCaller, { once: true });
  const timeoutMs = Number(options.timeoutMs || 30000);
  const timeout = window.setTimeout(() => controller.abort(), timeoutMs);
  const startedAt = performance.now();
  const tracePath = typeof path === "string" ? path : String(path || "");
  const traceEntry = {
    path: tracePath.replace(/[?&](code|token|auth_code|state|credential|session|android_auth_session)=[^&]*/gi, "$1=[redacted]"),
    method: cleanText(options.method || "GET", "GET"),
    started_at_ms: clientBootElapsedMs(),
    timeout_ms: timeoutMs,
    ok: false,
    status: 0,
    duration_ms: 0,
    error: "",
  };
  try {
    const response = await fetch(path, {
      method: options.method || "GET",
      cache: options.cache || "no-store",
      credentials: options.credentials || "include",
      headers: {
        "Accept": "application/json",
        "Content-Type": "application/json",
        "X-Wasm-Agent-Device-Id": clientDeviceId(),
      },
      body: options.body ? JSON.stringify(options.body) : undefined,
      signal: controller.signal,
    });
    traceEntry.status = response.status;
    const text = await response.text();
    let payload = {};
    try {
      payload = text ? JSON.parse(text) : {};
    } catch {
      payload = { ok: false, error: { message: text.slice(0, 600) } };
    }
    if (!response.ok || payload.ok === false) {
      const error = new Error(payload?.error?.message || `HTTP ${response.status}`);
      error.payload = payload;
      error.status = response.status;
      throw error;
    }
    traceEntry.ok = true;
    return payload;
  } catch (error) {
    traceEntry.error = error?.name === "AbortError" ? "abort_or_timeout" : errorMessage(error);
    throw error;
  } finally {
    traceEntry.duration_ms = Math.round(performance.now() - startedAt);
    clientBootRecordFetch(traceEntry);
    window.clearTimeout(timeout);
    if (options.signal) options.signal.removeEventListener("abort", abortFromCaller);
  }
}

async function fetchAgentKernelTool(path, body = {}, options = {}) {
  if (!isAdminUser()) throw new Error("Agent kernel tools require admin access.");
  return fetchJson(path, {
    method: "POST",
    timeoutMs: options.timeoutMs || 10000,
    body,
    signal: options.signal,
  });
}

function agentKernelRouteSummary(proof = {}) {
  const summary = proof.summary || proof.map_summary || {};
  const routeId = cleanText(summary.route_id || proof.route_id || proof.route_contract?.route_id || "", "");
  const fileCount = Number(proof.file_count ?? proof.files?.count ?? 0);
  return [routeId, fileCount ? `${fileCount} file receipts` : ""].filter(Boolean).join(" / ");
}

async function proveAgentKernelRouteTools(objective, pendingMessage, options = {}) {
  const resolvePayload = await fetchAgentKernelTool("/agent/tools/route.resolve", {
    route_id: "wasm-agent.avatar-chat.ui",
    surface_hint: "avatar-chat",
    objective,
  }, { signal: options.signal, timeoutMs: 8000 });
  const routeContract = resolvePayload.route_contract || {};
  const routeId = cleanText(routeContract.route_id || resolvePayload.summary?.route_id || "", "");
  if (!routeId) throw new Error(resolvePayload.error?.message || "route_contract_missing");
  const [mapPayload, filesPayload] = await Promise.all([
    fetchAgentKernelTool("/agent/tools/map.summary", { route_id: routeId }, { signal: options.signal, timeoutMs: 8000 }),
    fetchAgentKernelTool("/agent/tools/lookup.files", { route_id: routeId }, { signal: options.signal, timeoutMs: 8000 }),
  ]);
  const proof = {
    schema: "hermes.wasm_agent.client_kernel_route_proof.v1",
    route_id: routeId,
    route_contract: routeContract,
    summary: resolvePayload.summary || mapPayload.summary || {},
    map_summary: mapPayload.summary || {},
    files: {
      count: Number(filesPayload.count || 0),
      receipts: Array.isArray(filesPayload.files) ? filesPayload.files.slice(0, 12) : [],
    },
    tools: ["route.resolve", "map.summary", "lookup.files"],
  };
  if (pendingMessage) {
    pendingMessage.kernel_route_proof = proof;
    pendingMessage.route_contract = routeContract;
    mergeAgentAction(pendingMessage, agentAction("Kernel route proof", "done", agentKernelRouteSummary(proof), {
      id: "client_kernel_route_preflight",
      topic: "run-wasm",
      kind: "context",
      meta: "route.resolve/map.summary/lookup.files",
      arguments: proof,
      preview: JSON.stringify({
        route_id: proof.route_id,
        owner: proof.summary.owner,
        workspace_root: proof.summary.workspace_root,
        files: proof.files.receipts.map((item) => ({
          path: item.path,
          bytes: item.bytes,
          sha256: item.sha256 ? item.sha256.slice(0, 12) : "",
        })),
      }, null, 2),
    }));
  }
  return proof;
}

async function fetchExternalJson(url, options = {}) {
  const controller = new AbortController();
  const abortFromCaller = () => controller.abort();
  if (options.signal) options.signal.addEventListener("abort", abortFromCaller, { once: true });
  const timeoutMs = Number(options.timeoutMs || 30000);
  const timeout = window.setTimeout(() => controller.abort(), timeoutMs);
  const headers = {
    "Accept": "application/json",
    ...(options.body ? { "Content-Type": "application/json" } : {}),
    ...(options.headers || {}),
  };
  try {
    const response = await fetch(url, {
      method: options.method || "GET",
      cache: options.cache || "no-store",
      headers,
      body: options.body ? JSON.stringify(options.body) : undefined,
      signal: controller.signal,
    });
    const text = await response.text();
    let payload = {};
    try {
      payload = text ? JSON.parse(text) : {};
    } catch {
      payload = { ok: false, error: { message: text.slice(0, 600) } };
    }
    if (!response.ok || payload.ok === false) {
      const error = new Error(payload?.error?.message || payload?.message || `HTTP ${response.status}`);
      error.payload = payload;
      error.status = response.status;
      throw error;
    }
    return payload;
  } finally {
    window.clearTimeout(timeout);
    if (options.signal) options.signal.removeEventListener("abort", abortFromCaller);
  }
}

function nativeBackendOrigin() {
  const raw = cleanText(state.config?.native?.serverUrl, "");
  return raw ? raw.replace(/\/$/, "") : "";
}

function appHttpOrigin() {
  return window.location.protocol === "wasm-agent:" && nativeBackendOrigin()
    ? nativeBackendOrigin()
    : window.location.origin;
}

function appWebSocketUrl(path) {
  const url = new URL(path, `${appHttpOrigin()}/`);
  url.protocol = url.protocol === "https:" ? "wss:" : "ws:";
  return url;
}

async function bridgeJson(path, options = {}) {
  return fetchJson(`/bridge${path}`, options);
}

function agentReadinessLabel(readiness = state.agentReadiness) {
  if (agentTargetIsNone()) return "No model";
  if (shouldUseOwnedAgentBridge()) return "Private bridge";
  if (shouldUseDirectAgentProvider()) {
    const validation = validateDirectProviderConfig();
    if (!validation.ok) return validation.mode;
    const probe = currentAgentProviderProbe();
    if (state.agentProviderProbeBusy || probe?.mode === "checking") return "checking provider";
    if (!probe) return "provider untested";
    if (probe.ok) return probe.mode;
    return probe.mode || probe.category || "unreachable";
  }
  const status = cleanText(readiness?.status, "");
  if (status === "ready") return "Agent ready";
  if (status === "backend_unavailable") return "Agent backend unavailable";
  if (status === "auth_required") return "Sign in required";
  if (status === "insufficient_flux") return "Insufficient Flux";
  if (status === "provider_not_available") return "Provider not available yet";
  if (["requested", "charging", "provisioning"].includes(status)) return "Provisioning sandbox...";
  if (status === "failed") return "Provisioning failed";
  if (status === "sandbox_billing_incomplete") return "Sandbox billing incomplete";
  if (status === "stopped") return "Sandbox stopped";
  if (status === "archived") return "Sandbox archived";
  if (status === "sandbox_not_provisioned") return "Sandbox not provisioned";
  if (!state.wasmReady) return "WASM runtime blocked or unavailable";
  return state.agentReadinessBusy ? "Checking agent" : "Agent ready";
}

function agentReadinessStatusKey(readiness = state.agentReadiness) {
  if (agentTargetIsNone()) return "config-missing";
  if (shouldUseOwnedAgentBridge()) return "ready";
  if (shouldUseDirectAgentProvider()) {
    const validation = validateDirectProviderConfig();
    if (!validation.ok) return validation.mode;
    const probe = currentAgentProviderProbe();
    if (!probe || state.agentProviderProbeBusy || probe.mode === "checking") return "checking";
    return probe.mode || "unreachable";
  }
  const status = cleanText(readiness?.status, "");
  if (status) return status;
  if (!state.wasmReady) return "wasm_unavailable";
  return state.agentReadinessBusy ? "checking" : "ready";
}

function renderAgentReadinessStatus() {
  if (!els.agentStatus) return;
  const label = agentReadinessLabel();
  els.agentStatus.hidden = false;
  els.agentStatus.textContent = label;
  els.agentStatus.dataset.status = agentReadinessStatusKey();
  const wasmNote = state.wasmReady ? "" : cleanText(state.lastError, "Browser WASM runtime unavailable");
  els.agentStatus.title = wasmNote && label !== "WASM runtime blocked or unavailable" ? `${label}; ${wasmNote}` : wasmNote;
  renderNodesPanel();
}

function agentReadinessPanelMessage(readiness = state.agentReadiness) {
  const status = cleanText(readiness?.status, "");
  if (["requested", "charging", "provisioning"].includes(status)) return "Provisioning sandbox...";
  if (status === "ready") return "Sandbox ready";
  if (status === "failed") return "Provisioning failed";
  if (status === "sandbox_billing_incomplete") return "Sandbox billing incomplete.";
  if (status === "stopped") return "Sandbox stopped";
  if (status === "archived") return "Sandbox archived";
  if (status === "backend_unavailable") return "Backend bridge unavailable.";
  if (status === "insufficient_flux") return "Insufficient Flux.";
  if (status === "provider_not_available") return "Provider not available yet.";
  if (status === "auth_required") return "Sign in required.";
  if (status === "sandbox_not_provisioned") return "Sandbox not provisioned.";
  return cleanText(readiness?.message || "", "");
}

async function loadAgentReadiness(origin = "auto") {
  if (!state.authUser || state.agentReadinessBusy || agentTargetIsNone() || shouldUseOwnedAgentBridge()) return state.agentReadiness;
  state.agentReadinessBusy = true;
  renderAgentReadinessStatus();
  try {
    const query = new URLSearchParams({ target_node: agentTargetNode() });
    const payload = await fetchJson(`/agent/readiness?${query.toString()}`, { timeoutMs: 8000 });
    state.agentReadiness = payload;
    state.nodesPanelStatus = agentReadinessPanelMessage(payload);
    renderAgentNodeSelect();
    if (origin !== "poll") {
      recordUserEvent("agent.readiness_loaded", {
        target: `node:${payload.target_node || agentTargetNode()}`,
        summary: payload.message || payload.status || "Agent readiness loaded",
        data: { status: payload.status, missing_dependency: payload.missing_dependency || "" },
      });
    }
    return payload;
  } catch (error) {
    state.agentReadiness = {
      ok: true,
      schema: "hermes.wasm_agent.agent_readiness.v1",
      status: "backend_unavailable",
      ready: false,
      target_node: agentTargetNode(),
      message: error.message,
      missing_dependency: "agent_readiness_endpoint",
    };
    state.nodesPanelStatus = error.message;
    renderAgentNodeSelect();
    return state.agentReadiness;
  } finally {
    state.agentReadinessBusy = false;
    renderAgentReadinessStatus();
  }
}

async function ensureAgentReadiness(origin = "send") {
  if (!state.agentReadiness || state.agentReadiness.target_node !== agentTargetNode()) {
    return loadAgentReadiness(origin);
  }
  return state.agentReadiness;
}

async function loadAccountCredits(origin = "auto") {
  if (!state.authUser) return null;
  try {
    const payload = await fetchJson("/account/credits", { timeoutMs: 8000 });
    state.agentCredits = payload;
    if (origin !== "poll") {
      recordUserEvent("account.credits_loaded", {
        target: "account:credits",
        summary: `Flux balance ${payload.balance || 0}`,
        data: { balance: payload.balance || 0 },
      });
    }
    renderNodesPanel();
    renderLogin();
    return payload;
  } catch (error) {
    state.nodesPanelStatus = error.message;
    renderNodesPanel();
    renderLogin();
    return null;
  }
}

async function postAgentMessage(body, pendingMessage, options = {}) {
  if (!("ReadableStream" in window) || !("TextDecoder" in window)) {
    return fetchJson("/agent/session/message", {
      ...options,
      timeoutMs: options.timeoutMs || options.idleTimeoutMs,
      method: "POST",
      body,
    });
  }
  try {
    return await streamAgentMessage(body, pendingMessage, options);
  } catch (error) {
    if (error.name !== "AbortError" && body.turn_id) {
      updateAgentPendingMessage(pendingMessage, { phase: "Reconnecting..." });
      await new Promise((resolve) => window.setTimeout(resolve, 2000));
      return fetchJson("/agent/session/message", {
        ...options,
        timeoutMs: options.timeoutMs || options.idleTimeoutMs,
        method: "POST",
        body,
      });
    }
    throw error;
  }
}

async function streamAgentMessage(body, pendingMessage, options = {}) {
  const controller = new AbortController();
  const abortFromCaller = () => controller.abort();
  if (options.signal) options.signal.addEventListener("abort", abortFromCaller, { once: true });
  const idleTimeoutMs = Number(options.idleTimeoutMs || options.timeoutMs || 30000);
  let idleTimeout = 0;
  const resetIdleTimeout = () => {
    window.clearTimeout(idleTimeout);
    idleTimeout = window.setTimeout(() => controller.abort(), idleTimeoutMs);
  };
  resetIdleTimeout();
  try {
    const response = await fetch("/agent/session/message/stream", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Wasm-Agent-Device-Id": clientDeviceId(),
      },
      body: JSON.stringify(body),
      signal: controller.signal,
    });
    resetIdleTimeout();
    if (!response.ok || !response.body) {
      throw new Error(`HTTP ${response.status}`);
    }
    mergeAgentAction(pendingMessage, {
      id: "client_ask_orchestrator",
      topic: "run-hermes",
      kind: "model",
      status: "done",
      detail: "stream accepted",
      meta: "handshake",
    });
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    let finalPayload = null;
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      resetIdleTimeout();
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() || "";
      for (const line of lines) {
        const payload = handleAgentStreamLine(line, pendingMessage);
        if (payload?.type === "final") finalPayload = { ok: true, agent: payload.agent };
      }
    }
    if (buffer.trim()) {
      const payload = handleAgentStreamLine(buffer, pendingMessage);
      if (payload?.type === "final") finalPayload = { ok: true, agent: payload.agent };
    }
    if (!finalPayload) throw new Error("The embedded chat stream ended without a final response.");
    return finalPayload;
  } finally {
    window.clearTimeout(idleTimeout);
    if (options.signal) options.signal.removeEventListener("abort", abortFromCaller);
  }
}

function handleAgentStreamLine(line, pendingMessage) {
  const text = String(line || "").trim();
  if (!text) return null;
  let payload = null;
  try {
    payload = JSON.parse(text);
  } catch {
    // Not valid JSON — will be treated as raw text delta below
  }
  if (!payload || typeof payload === "string") {
    const delta = typeof payload === "string" ? payload : text;
    appendAgentVisibleDelta(pendingMessage, delta);
    return { type: "delta", delta };
  }
  if (payload.run_id) pendingMessage.run_id = cleanText(payload.run_id, "");
  if (Number.isFinite(payload.seq)) pendingMessage.agent_run_seq = Math.max(Number(pendingMessage.agent_run_seq || 0), payload.seq);
  if (payload.type === "run" && payload.run) {
    pendingMessage.run_id = cleanText(payload.run.run_id || payload.run_id, pendingMessage.run_id || "");
    pendingMessage.turn_id = cleanText(payload.run.turn_id, pendingMessage.turn_id || "");
    pendingMessage.agent_run_status = cleanText(payload.run.status, pendingMessage.agent_run_status || "");
    const timeline = Array.isArray(pendingMessage.timeline) ? [...pendingMessage.timeline] : [];
    const runEvent = {
      id: `tl_run_started_${payload.seq || 0}`,
      label: "run.started",
      status: "done",
      detail: `${pendingMessage.run_id || ""} / ${pendingMessage.agent_run_status || ""}`.trim(),
      kind: "timeline",
      event_type: "run.started",
    };
    const existing = timeline.findIndex((item) => item.id === runEvent.id);
    if (existing >= 0) {
      timeline[existing] = { ...timeline[existing], ...runEvent };
    } else {
      timeline.push(runEvent);
    }
    updateAgentPendingMessage(pendingMessage, {
      run_id: pendingMessage.run_id,
      turn_id: pendingMessage.turn_id,
      agent_run_seq: pendingMessage.agent_run_seq || payload.seq || 0,
      agent_run_status: pendingMessage.agent_run_status,
      timeline,
    });
  }
  if (payload.type === "action" && payload.action) {
    mergeAgentAction(pendingMessage, payload.action);
    const actionUsage = agentTokenUsageFromAction(payload.action);
    const actionLedger = agentTokenLedgerFromAction(payload.action);
    if (actionUsage) {
      pendingMessage.diagnostics = {
        ...(pendingMessage.diagnostics || {}),
        token_usage: actionUsage,
        token_usage_total: actionUsage,
      };
      updateAgentTokenUsage(actionUsage);
    }
    if (actionLedger) applyAgentTokenLedger(pendingMessage, actionLedger);
  }
  if (payload.type === "heartbeat") {
    if (payload.action) mergeAgentAction(pendingMessage, payload.action);
    updateAgentPendingMessage(pendingMessage, {
      phase: agentLiveStepFromPayload(payload) || pendingMessage.phase || "Waiting for agent",
      content: payload.message || pendingMessage.content,
    });
  }
  if (payload.type === "delta" && payload.delta) {
    appendAgentVisibleDelta(pendingMessage, payload.delta);
  }
  if (payload.type === "error") {
    const streamError = new Error(payload.error?.message || "Embedded chat stream failed.");
    streamError.diagnostic = payload.error || {};
    throw streamError;
  }
  return payload;
}

function appendAgentVisibleDelta(pendingMessage, delta) {
  const visibleDelta = agentHumanVisibleDelta(pendingMessage, String(delta || ""));
  if (!visibleDelta) {
    if (!pendingMessage.agent_delta_started) {
      updateAgentPendingMessage(pendingMessage, { phase: pendingMessage.phase || "Understanding request" });
    }
    return;
  }
  const currentContent = pendingMessage.agent_delta_started ? pendingMessage.content || "" : "";
  pendingMessage.agent_delta_started = true;
  updateAgentPendingMessage(pendingMessage, {
    phase: pendingMessage.phase || "Streaming answer",
    content: `${currentContent}${visibleDelta}`,
  });
}

function agentHumanVisibleDelta(message, delta) {
  if (!message || !delta) return delta || "";
  let state = message.agent_answer_json_stream;
  if (!state) {
    const first = delta.trimStart()[0] || "";
    if (first !== "{") return delta;
    state = { buffer: "", answerLength: 0, jsonMode: true, complete: false };
    message.agent_answer_json_stream = state;
  }
  if (!state.jsonMode || state.complete) return state.jsonMode ? "" : delta;
  state.buffer += delta;
  const extracted = extractJsonStringValue(state.buffer, "answer");
  if (!extracted.started && state.buffer.trimStart()[0] !== "{") {
    state.jsonMode = false;
    const buffered = state.buffer;
    state.buffer = "";
    return buffered;
  }
  if (!extracted.started) return "";
  const next = extracted.value.slice(state.answerLength);
  state.answerLength = extracted.value.length;
  state.complete = extracted.complete;
  return next;
}

function extractJsonStringValue(text, key) {
  const source = String(text || "");
  const marker = `"${key}"`;
  const keyIndex = source.indexOf(marker);
  if (keyIndex < 0) return { started: false, value: "", complete: false };
  let index = keyIndex + marker.length;
  while (/\s/.test(source[index] || "")) index += 1;
  if (source[index] !== ":") return { started: false, value: "", complete: false };
  index += 1;
  while (/\s/.test(source[index] || "")) index += 1;
  if (source[index] !== "\"") return { started: false, value: "", complete: false };
  index += 1;
  let value = "";
  let escaped = false;
  for (; index < source.length; index += 1) {
    const ch = source[index];
    if (escaped) {
      if (ch === "n") value += "\n";
      else if (ch === "r") value += "\r";
      else if (ch === "t") value += "\t";
      else value += ch;
      escaped = false;
      continue;
    }
    if (ch === "\\") {
      escaped = true;
      continue;
    }
    if (ch === "\"") return { started: true, value, complete: true };
    value += ch;
  }
  return { started: true, value, complete: false };
}

function agentLiveStepFromPayload(payload = {}) {
  if (!payload || typeof payload !== "object") return "";
  if (payload.action && typeof payload.action === "object") return agentLiveStepFromAction(payload.action);
  const phase = cleanText(payload.phase || "", "");
  if (!phase || phase === "Hermes bridge active") return "";
  return phase;
}

function agentLiveStepFromAction(action = {}) {
  if (!action || typeof action !== "object") return "";
  const label = cleanText(action.label || "", "");
  const status = cleanText(action.status || "", "").toLowerCase();
  const meta = cleanText(action.meta || "", "");
  const detail = cleanText(action.detail || "", "");
  if (!label) return "";
  if (label === "tokens.used") return "";
  if (label === "bridge.run.poll") return "";
  if (label === "patch" || label === "repo.edit" || label === "apply_patch") return "Hermes: editing files";
  if (label === "test.run" || label === "run_tests") return "Hermes: running tests";
  if (label === "bridge.run.started") return "Dispatching Hermes";
  if (label === "bridge.run.completed") return "Hermes: preparing final";
  if (label === "backend.run.completed") return "Hermes: preparing final";
  if (label === "backend.tool.started") return "Starting tool";
  if (label === "backend.tool.completed") return "Reviewing tool result";
  if (meta.startsWith("tool.started") || status === "running") {
    if (label === "execute_code") {
      const match = detail.match(/['"]([^'"]+\.(?:test|spec)\.[A-Za-z0-9]+|[^'"]+\.test\.[A-Za-z0-9]+)['"]/);
      return match ? "Hermes: running tests" : "Running code";
    }
    if (label === "patch") return "Hermes: editing files";
    if (label === "read_file") return "Reading file";
    return `Running ${label}`;
  }
  if ((meta.startsWith("tool.completed") || meta.startsWith("tool.finished")) && status === "done") return `Finished ${label}`;
  if (status === "error") return `${label} needs attention`;
  return "";
}

function agentTokenUsageFromAction(action = {}) {
  if (!action || typeof action !== "object") return null;
  const label = cleanText(action.label || "", "");
  const kind = cleanText(action.kind || "", "");
  if (label !== "tokens.used" && kind !== "tokens") return null;
  const args = action.arguments && typeof action.arguments === "object" ? action.arguments : {};
  return normalizeAgentTokenUsage(args.usage || action.usage || action.token_usage || null);
}

function agentTokenLedgerFromAction(action = {}) {
  if (!action || typeof action !== "object") return null;
  const label = cleanText(action.label || "", "");
  const kind = cleanText(action.kind || "", "");
  if (label !== "tokens.used" && kind !== "tokens") return null;
  const args = action.arguments && typeof action.arguments === "object" ? action.arguments : {};
  const ledger = args.ledger || action.ledger || action.token_ledger || null;
  return ledger && typeof ledger === "object" ? ledger : null;
}

function agentTokenLedgerUsage(ledger = {}) {
  if (!ledger || typeof ledger !== "object") return null;
  const calls = Array.isArray(ledger.calls) ? ledger.calls : [];
  const exactCalls = calls.filter((call) => call && typeof call === "object" && call.exact);
  const exact = ledger.exact !== false;
  const sourceCalls = exact ? exactCalls : calls;
  const ledgerTotal = exact ? tokenNumber(ledger.total_tokens) : tokenNumber(ledger.estimated_total_tokens);
  if (!sourceCalls.length && ledgerTotal === null) return null;
  const sum = (items, key) => items.reduce((total, item) => total + Number(tokenNumber(item?.[key]) || 0), 0);
  const input = sum(sourceCalls, exact ? "input_tokens" : "estimated_input_tokens");
  const output = sum(sourceCalls, exact ? "output_tokens" : "estimated_output_tokens");
  const cached = exact ? sum(sourceCalls, "cached_input_tokens") : 0;
  const reasoning = exact ? sum(sourceCalls, "reasoning_tokens") : 0;
  const total = ledgerTotal ?? sum(sourceCalls, exact ? "total_tokens" : "estimated_total_tokens");
  return normalizeAgentTokenUsage({
    input_tokens: input,
    output_tokens: output,
    total_tokens: total,
    cached_input_tokens: cached,
    reasoning_tokens: reasoning,
    usage_accuracy: exact ? "provider_exact" : "estimated",
    usage_scope: "llm_api_call",
    billable: exact,
  });
}

function applyAgentTokenLedger(message, ledger, extra = {}) {
  if (!message || !ledger || typeof ledger !== "object") return null;
  const normalizedLedger = {
    ...ledger,
    source: extra.source || ledger.source || "tokens.used",
  };
  message.token_ledger = normalizedLedger;
  message.diagnostics = {
    ...(message.diagnostics || {}),
    token_ledger: normalizedLedger,
  };
  const usage = agentTokenLedgerUsage(normalizedLedger);
  if (usage) {
    message.diagnostics.token_usage = message.diagnostics.token_usage || usage;
    message.diagnostics.token_usage_total = usage;
    updateAgentTokenUsage(usage);
  }
  return normalizedLedger;
}

async function refreshAgentRunTokenLedger(message, options = {}) {
  const runId = cleanText(message?.run_id || "", "");
  if (!runId || !isAdminUser()) return null;
  const payload = await fetchAgentKernelTool("/agent/tools/cost.status", {
    run_id: runId,
    quest_id: cleanText(options.questId || activeAgentSession()?.id || "", ""),
  }, { signal: options.signal, timeoutMs: options.timeoutMs || 8000 });
  const ledger = payload.ledger && typeof payload.ledger === "object" ? payload.ledger : null;
  if (!ledger) return null;
  return applyAgentTokenLedger(message, ledger, { source: "cost.status" });
}

async function fetchAgentRunForPendingMessage(session, message) {
  if (message.run_id) return cleanText(message.run_id, "");
  if (!message.turn_id || !session?.id) return "";
  const payload = await fetchJson(`/agent/runs?session_id=${encodeURIComponent(session.id)}&limit=20`, {
    timeoutMs: 8000,
  });
  const runs = Array.isArray(payload.runs) ? payload.runs : [];
  const match = runs.find((run) => cleanText(run.turn_id, "") === cleanText(message.turn_id, ""));
  return cleanText(match?.run_id, "");
}

async function streamExistingAgentRun(runId, pendingMessage, options = {}) {
  const afterSeq = Math.max(0, Number(pendingMessage.agent_run_seq || 0));
  const controller = new AbortController();
  const abortFromCaller = () => controller.abort();
  if (options.signal) options.signal.addEventListener("abort", abortFromCaller, { once: true });
  try {
    const response = await fetch(`/agent/runs/${encodeURIComponent(runId)}/stream?after_seq=${afterSeq}`, {
      headers: { "X-Wasm-Agent-Device-Id": clientDeviceId() },
      signal: controller.signal,
    });
    if (!response.ok || !response.body) throw new Error(`HTTP ${response.status}`);
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    let finalPayload = null;
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() || "";
      for (const line of lines) {
        const payload = handleAgentStreamLine(line, pendingMessage);
        if (payload?.type === "final") finalPayload = { ok: true, agent: payload.agent };
      }
    }
    if (buffer.trim()) {
      const payload = handleAgentStreamLine(buffer, pendingMessage);
      if (payload?.type === "final") finalPayload = { ok: true, agent: payload.agent };
    }
    if (finalPayload) return finalPayload;
    const run = await fetchJson(`/agent/runs/${encodeURIComponent(runId)}`, { timeoutMs: 8000 });
    if (run.run?.status === "completed" && run.run.final) return { ok: true, agent: run.run.final };
    if (run.run?.error?.message) throw new Error(run.run.error.message);
    throw new Error("The agent run stream ended without a final response.");
  } finally {
    if (options.signal) options.signal.removeEventListener("abort", abortFromCaller);
  }
}

async function finishAgentBackendPayload(pendingMessage, payload, startedAt) {
  const rawReply = payload.agent?.reply || "I did not receive a response from the embedded agent adapter.";
  const clientWis = await applyClientWisPatchesFromReply(rawReply);
  const clientOps = applyAgentClientOpsFromReply(clientWis.reply);
  const diagnostics = { ...(payload.agent?.diagnostics || {}) };
  if (clientWis.result) diagnostics.client_wis_patch_result = clientWis.result;
  if (clientOps.result) diagnostics.client_ops = clientOps.result;
  if (diagnostics.wis_patch_result?.applied) await refreshWisArtifactsAfterPatch(diagnostics.wis_patch_result, "agent-wis-patch");
  const session = activeAgentSession();
  pendingMessage.content = clientOps.reply;
  pendingMessage.pending = false;
  pendingMessage.phase = "";
  pendingMessage.duration_ms = payload.agent?.duration_ms || Date.now() - Number(startedAt || pendingMessage.turn_started_at || Date.now());
  pendingMessage.changed_files = payload.agent?.changed_files || [];
  pendingMessage.diagnostics = diagnostics;
  pendingMessage.run_id = cleanText(payload.agent?.run_id, pendingMessage.run_id || "");
  pendingMessage.turn_id = cleanText(payload.agent?.turn_id, pendingMessage.turn_id || "");
  pendingMessage.agent_run_status = "completed";
  if (payload.agent?.route_contract) pendingMessage.route_contract = payload.agent.route_contract;
  if (payload.agent?.token_ledger || pendingMessage.token_ledger) {
    applyAgentTokenLedger(pendingMessage, payload.agent?.token_ledger || pendingMessage.token_ledger);
  }
  await refreshAgentRunTokenLedger(pendingMessage, {
    questId: session?.id || "",
    signal: state.agentAbortController?.signal,
  }).catch(() => null);
  const timeline = Array.isArray(pendingMessage.timeline) ? [...pendingMessage.timeline] : [];
  const finalEvent = {
    id: `tl_run_final`,
    label: "run.final",
    status: "done",
    detail: `${pendingMessage.duration_ms || 0} ms`,
    kind: "timeline",
    event_type: "run.final",
  };
  const existingFinal = timeline.findIndex((item) => item.id === finalEvent.id);
  if (existingFinal >= 0) {
    timeline[existingFinal] = { ...timeline[existingFinal], ...finalEvent };
  } else {
    timeline.push(finalEvent);
  }
  const changed = Array.isArray(payload.agent?.changed_files) ? payload.agent.changed_files.length : 0;
  if (changed) {
    const filesEvent = {
      id: "tl_files_changed",
      label: "files.changed",
      status: "done",
      detail: `${changed} paths`,
      kind: "timeline",
      event_type: "files.changed",
    };
    const existingFiles = timeline.findIndex((item) => item.id === filesEvent.id);
    if (existingFiles >= 0) {
      timeline[existingFiles] = { ...timeline[existingFiles], ...filesEvent };
    } else {
      timeline.push(filesEvent);
    }
  }
  pendingMessage.timeline = timeline;
  pendingMessage.actions = agentActionRowsFromPayload(payload.agent, pendingMessage.actions || []);
  if (clientWis.result) pendingMessage.actions.push(wisPatchActionFromResult(clientWis.result));
  session.diagnostics = pendingMessage.diagnostics;
  session.changed_files = pendingMessage.changed_files;
  session.context_preview = payload.agent?.context_preview || [];
  updateAgentTokenUsage(agentTokenLedgerUsage(pendingMessage.token_ledger) || agentDiagnosticsTokenUsageBreakdown(pendingMessage.diagnostics).total);
  saveAgentSessions();
  renderAgentDiagnostics(pendingMessage.diagnostics);
  renderAgentContextPreview(payload.agent?.context_preview || []);
  renderAgentMessages();
}

async function resumePendingAgentRun(origin = "bootstrap") {
  if (!state.authUser || state.agentBusy) return;
  const session = activeAgentSession();
  if (!session || socialChatSession(session)) return;
  const pendingMessage = [...(session.messages || [])].reverse().find((message) => message.pending && (message.run_id || message.turn_id));
  if (!pendingMessage) return;
  let runId = "";
  try {
    runId = await fetchAgentRunForPendingMessage(session, pendingMessage);
    if (!runId) return;
    pendingMessage.run_id = runId;
    state.agentBusy = true;
    state.agentStopRequested = false;
    state.agentAbortController = new AbortController();
    updateAgentSendButton();
    startAgentTurnTimer(pendingMessage);
    updateAgentPendingMessage(pendingMessage, { phase: "Reconnecting...", content: pendingMessage.content || "Reconnecting to the assistant turn..." });
    const payload = await streamExistingAgentRun(runId, pendingMessage, { signal: state.agentAbortController.signal });
    await finishAgentBackendPayload(pendingMessage, payload, pendingMessage.turn_started_at);
    recordUserEvent("agent.message_resumed", {
      target: "agent-overlay",
      summary: "Resumed embedded assistant run",
      data: { origin, run_id: runId },
      redacted: true,
    });
  } catch (error) {
    pendingMessage.content = `I could not resume the embedded assistant run: ${error.message}`;
    pendingMessage.pending = false;
    pendingMessage.phase = "Resume error";
    pendingMessage.duration_ms = Date.now() - Number(pendingMessage.turn_started_at || Date.now());
    pendingMessage.actions = (pendingMessage.actions || []).map((action) => (
      action.status === "running" ? { ...action, status: "error", detail: error.message } : action
    ));
    saveAgentSessions();
    renderAgentMessages();
  } finally {
    if (state.agentAbortController) state.agentAbortController = null;
    state.agentBusy = false;
    state.agentStopRequested = false;
    stopAgentTurnTimer();
    updateAgentSendButton();
    renderAgentReadinessStatus();
    flushDeferredHmrReload();
  }
}

function setAgentOpen(open, options = {}) {
  const nextOpen = Boolean(open);
  const changed = state.agentOpen !== nextOpen;
  state.agentOpen = nextOpen;
  els.agentOverlay.dataset.open = nextOpen ? "true" : "false";
  els.agentAvatarButton.setAttribute("aria-expanded", nextOpen ? "true" : "false");
  if (nextOpen) {
    placeAgentPanel();
    if (isAndroidNativeShell()) {
      androidNativeAfterPaintTask(() => {
        renderAgentSessions();
        renderAgentMessages({ forceBottom: true });
      }, "agent-open-render");
    } else {
      window.requestAnimationFrame(() => {
        renderAgentSessions();
        renderAgentMessages({ forceBottom: true });
      });
    }
    const focusAgent = () => {
      placeAgentPanel();
      queueAgentScrollToBottom();
      els.agentInput.focus();
    };
    if (isAndroidNativeShell()) androidNativeAfterQuiet(focusAgent, "agent-open-focus");
    else window.setTimeout(focusAgent, 0);
  } else {
    setAgentBalloon("");
  }
  if (!changed && !options.forceEvent) return;
  const recordAgentEvent = () => recordUserEvent(nextOpen ? "agent.opened" : "agent.closed", {
    target: "agent-overlay",
    summary: nextOpen ? "Opened embedded assistant" : "Minimized embedded assistant",
    data: { panel: state.activePanel },
  });
  if (isAndroidNativeShell()) androidNativeAfterQuiet(recordAgentEvent, "agent-open-event");
  else recordAgentEvent();
}

function chatQueryIsOpen() {
  return new URLSearchParams(window.location.search).get(CHAT_QUERY_KEY) === CHAT_QUERY_VALUE;
}

function uiNavigationId() {
  const raw = window.history.state;
  return raw && typeof raw === "object" ? String(raw.uiLayerId || "") : "";
}

function uiNavigationLocationKey(url = window.location.href) {
  const nextUrl = url instanceof URL ? url : new URL(url, window.location.href);
  return `${nextUrl.pathname}${nextUrl.search}`;
}

function uiNavigationState(entry = state.uiNavigationStack.at(-1) || null) {
  const raw = window.history.state && typeof window.history.state === "object" ? window.history.state : {};
  return {
    ...raw,
    panel: state.activePanel,
    uiLayer: entry?.layer || "",
    uiLayerId: entry?.id || "",
    uiLayerLocationKey: entry?.locationKey || "",
  };
}

function uiNavigationUrl() {
  const url = new URL(window.location.href);
  if (state.agentOpen) {
    url.searchParams.set(CHAT_QUERY_KEY, CHAT_QUERY_VALUE);
  } else if (url.searchParams.get(CHAT_QUERY_KEY) === CHAT_QUERY_VALUE) {
    url.searchParams.delete(CHAT_QUERY_KEY);
  }
  return url;
}

function replaceCurrentUiNavigationState() {
  if (isAndroidNativeShell() && Date.now() < Number(state.androidNativeVisualLaneUntil || 0)) {
    androidNativeAfterQuiet(() => window.history.replaceState(uiNavigationState(), "", uiNavigationUrl()), "replace-ui-navigation-state");
    return;
  }
  window.history.replaceState(uiNavigationState(), "", uiNavigationUrl());
}

function closeUiNavigationEntry(entry, options = {}) {
  if (!entry) return false;
  state.uiNavigationStack = state.uiNavigationStack.filter((item) => item.id !== entry.id);
  if (options.invoke !== false) entry.close?.({ skipHistory: true, skipStack: true });
  return true;
}

function pushUiNavigationLayer(layer, close, options = {}) {
  if (!layer) return null;
  state.uiNavigationStack
    .filter((entry) => entry.layer === layer)
    .forEach((entry) => closeUiNavigationEntry(entry, { invoke: false }));
  const url = uiNavigationUrl();
  if (options.chat) url.searchParams.set(CHAT_QUERY_KEY, CHAT_QUERY_VALUE);
  const entry = {
    id: `${layer}:${++state.uiNavigationSeq}`,
    layer,
    close,
    locationKey: uiNavigationLocationKey(url),
  };
  state.uiNavigationStack.push(entry);
  if (isAndroidNativeShell()) androidNativeAfterQuiet(() => window.history.pushState(uiNavigationState(entry), "", url), `push-ui-layer:${layer}`);
  else window.history.pushState(uiNavigationState(entry), "", url);
  return entry;
}

function closeUiNavigationLayer(layer, options = {}) {
  const entry = [...state.uiNavigationStack].reverse().find((item) => item.layer === layer);
  if (!entry) return false;
  const currentEntryIsLayer = uiNavigationId() === entry.id;
  const currentEntryIsOriginalLayerUrl = currentEntryIsLayer && entry.locationKey === uiNavigationLocationKey();
  if (!options.skipHistory && currentEntryIsOriginalLayerUrl && !isAndroidNativeShell()) {
    window.history.back();
    return true;
  }
  closeUiNavigationEntry(entry);
  if (options.replaceHistory || currentEntryIsLayer) replaceCurrentUiNavigationState();
  return true;
}

function closeTopUiNavigationLayer() {
  const entry = state.uiNavigationStack.at(-1);
  if (!entry) return false;
  return closeUiNavigationLayer(entry.layer);
}

function syncUiNavigationWithHistory() {
  const targetId = uiNavigationId();
  while (state.uiNavigationStack.length && state.uiNavigationStack.at(-1).id !== targetId) {
    closeUiNavigationEntry(state.uiNavigationStack.at(-1));
  }
  if (targetId && !state.uiNavigationStack.some((entry) => entry.id === targetId)) {
    const raw = window.history.state && typeof window.history.state === "object" ? window.history.state : {};
    if (raw.uiLayer === "agent-chat") {
      const entry = {
        id: targetId,
        layer: "agent-chat",
        close: () => setAgentOpen(false),
        locationKey: String(raw.uiLayerLocationKey || uiNavigationLocationKey()),
      };
      state.uiNavigationStack.push(entry);
      setAgentOpen(true);
    }
  }
  if (!targetId && !chatQueryIsOpen() && state.agentOpen) {
    setAgentOpen(false);
  }
}

function initializeUiNavigationFromUrl() {
  state.uiNavigationStack = [];
  if (chatQueryIsOpen()) {
    const baseUrl = new URL(window.location.href);
    baseUrl.searchParams.delete(CHAT_QUERY_KEY);
    window.history.replaceState(uiNavigationState(null), "", baseUrl);
    setAgentOpen(true);
    pushUiNavigationLayer("agent-chat", () => setAgentOpen(false), { chat: true });
    return;
  }
  window.history.replaceState(uiNavigationState(null), "", window.location.href);
}

function openAgentChat() {
  setAgentOpen(true);
  pushUiNavigationLayer("agent-chat", () => setAgentOpen(false), { chat: true });
}

function closeAgentChat() {
  if (!closeUiNavigationLayer("agent-chat")) setAgentOpen(false);
}

function agentChatDistanceFromBottom() {
  const scroller = els.agentMessages;
  if (!scroller) return 0;
  return Math.max(0, scroller.scrollHeight - scroller.clientHeight - scroller.scrollTop);
}

function updateAgentScrollBottomButton() {
  const scroller = els.agentMessages;
  if (els.agentPanel && els.agentForm) {
    els.agentPanel.style.setProperty("--agent-form-height", `${Math.max(0, Math.round(els.agentForm.getBoundingClientRect().height || 82))}px`);
  }
  const pinned = !scroller || scroller.hidden || agentChatDistanceFromBottom() <= AGENT_CHAT_BOTTOM_EPSILON_PX;
  state.agentChatPinned = pinned;
  if (els.agentScrollBottomButton) {
    els.agentScrollBottomButton.hidden = pinned || !state.agentOpen || state.agentView !== "chat" || state.agentSetupBalloonOpen;
  }
}

function scrollAgentChatToBottom({ smooth = false } = {}) {
  const scroller = els.agentMessages;
  if (!scroller) return;
  const top = scroller.scrollHeight;
  if (smooth && scroller.scrollTo) {
    scroller.scrollTo({ top, behavior: "smooth" });
  } else {
    scroller.scrollTop = top;
  }
  window.setTimeout(updateAgentScrollBottomButton, smooth ? 180 : 0);
}

function queueAgentScrollToBottom(options = {}) {
  window.requestAnimationFrame(() => {
    scrollAgentChatToBottom(options);
    window.requestAnimationFrame(() => scrollAgentChatToBottom(options));
  });
}

function agentChatScrollSnapshot() {
  const scroller = els.agentMessages;
  if (!scroller) return { pinned: true, top: 0 };
  const distanceFromBottom = scroller.scrollHeight - scroller.clientHeight - scroller.scrollTop;
  return {
    pinned: distanceFromBottom <= AGENT_CHAT_BOTTOM_EPSILON_PX,
    top: scroller.scrollTop,
  };
}

function restoreAgentChatScroll(snapshot = {}, options = {}) {
  const scroller = els.agentMessages;
  if (!scroller) return;
  if (options.forceBottom || snapshot.pinned) {
    scrollAgentChatToBottom();
    return;
  }
  const maxTop = Math.max(0, scroller.scrollHeight - scroller.clientHeight);
  scroller.scrollTop = clamp(Number(snapshot.top || 0), 0, maxTop);
  updateAgentScrollBottomButton();
}

function appendAgentMessage(role, content, extra = {}) {
  const session = activeAgentSession();
  const scrollSnapshot = agentChatScrollSnapshot();
  const message = {
    id: `msg_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`,
    role,
    content,
    timestamp: new Date().toISOString(),
    ...extra,
  };
  session.messages.push(message);
  session.updated_at = new Date().toISOString();
  if (role === "user" && !socialChatSession(session)) session.title = truncateText(content, 42) || session.title;
  saveAgentSessions();
  renderAgentSessions();
  els.agentMessages.append(renderAgentMessage(message));
  restoreAgentChatScroll(scrollSnapshot);
  return message;
}

function agentMessageMenuPositionFromEvent(event) {
  if (!event) return null;
  const x = Number(event.clientX);
  const y = Number(event.clientY);
  if (Number.isFinite(x) && Number.isFinite(y)) return { x, y };
  const rect = event.currentTarget?.getBoundingClientRect?.() || event.target?.getBoundingClientRect?.();
  if (!rect) return null;
  return { x: rect.left, y: rect.bottom };
}

function closeAgentMessageMenu() {
  state.agentOpenMessageMenuId = "";
  state.agentMessageMenuPosition = null;
}

function openAgentMessageMenu(message, event = null) {
  state.agentOpenMessageMenuId = message?.id || "";
  state.agentMessageMenuPosition = message?.id ? agentMessageMenuPositionFromEvent(event) : null;
  renderAgentMessages();
}

function installAgentMessageMenuInteractions(wrap, message) {
  if (!wrap || !message?.id) return;
  wrap.addEventListener("contextmenu", (event) => {
    event.preventDefault();
    event.stopPropagation();
    openAgentMessageMenu(message, event);
  });
  wrap.addEventListener("pointerdown", (event) => {
    if (event.pointerType === "mouse" || event.button !== 0) return;
    const pointerEvent = event;
    window.clearTimeout(state.agentMessageLongPressTimer);
    state.agentMessageLongPressTimer = window.setTimeout(() => {
      openAgentMessageMenu(message, pointerEvent);
    }, AGENT_MESSAGE_LONG_PRESS_MS);
  });
  const clearLongPress = () => {
    window.clearTimeout(state.agentMessageLongPressTimer);
    state.agentMessageLongPressTimer = 0;
  };
  wrap.addEventListener("pointerup", clearLongPress);
  wrap.addEventListener("pointercancel", clearLongPress);
  wrap.addEventListener("pointerleave", clearLongPress);
  wrap.addEventListener("lostpointercapture", clearLongPress);
}

function renderAgentCommandChoices(message) {
  const choices = Array.isArray(message.command_choices) ? message.command_choices : [];
  if (!choices.length) return null;
  const list = document.createElement("div");
  list.className = "agent-command-choices";
  for (const choice of choices) {
    const button = document.createElement("button");
    button.type = "button";
    button.className = `agent-command-choice${choice.sticky ? " is-sticky" : ""}`;
    button.dataset.commandAction = cleanText(choice.action, "");
    button.dataset.commandValue = cleanText(choice.value, "");
    const label = document.createElement("strong");
    label.textContent = cleanText(choice.label, "Select");
    button.append(label);
    const detailText = cleanText(choice.detail, "");
    if (detailText) {
      const detail = document.createElement("span");
      detail.textContent = detailText;
      button.append(detail);
    }
    button.addEventListener("click", () => void handleAgentCommandChoice(choice));
    list.append(button);
  }
  return list;
}

function renderAgentMessage(message) {
  const session = activeAgentSession();
  const direct = session.kind === "direct";
  const socialChat = socialChatSession(session);
  const wrap = document.createElement("div");
  wrap.className = `agent-message ${message.role}${socialChat ? " direct-message" : ""}`;
  wrap.dataset.messageId = message.id || "";
  if (message.pending_state) wrap.dataset.pendingState = message.pending_state;
  if (message.pending) wrap.classList.add("is-thinking");
  const header = message.role === "assistant" && (message.pending || Number.isFinite(message.duration_ms))
    ? agentTurnHeader(message)
    : null;
  const body = socialChat && message.kind === "sticker"
    ? renderDirectStickerMessage(message)
    : ["assistant", "user"].includes(message.role) && !message.pending
    ? renderAgentMarkdown(message.content)
    : document.createElement("div");
  if (!body.classList.contains("agent-message-body")) {
    body.className = "agent-message-body";
    body.textContent = message.content;
  }
  if (message.images && message.images.length > 0) {
    const grid = document.createElement("div");
    grid.className = "agent-message-images";
    for (const imgData of message.images) {
      const img = document.createElement("img");
      img.src = imgData.data_url || imgData;
      img.alt = imgData.name || "Attached image";
      img.loading = "lazy";
      grid.append(img);
    }
    wrap.append(grid);
  }
  const imageCards = renderAgentImageCards(message);
  if (imageCards) wrap.append(imageCards);
  const fileAttachments = renderAgentFileAttachments(message);
  if (fileAttachments) wrap.append(fileAttachments);
  if (header) wrap.append(header);
  const timeline = !socialChat && message.role === "assistant" ? renderAgentTimeline(message) : null;
  if (timeline) wrap.append(timeline);
  const tokenLedger = !socialChat && message.role === "assistant" ? renderAgentTokenLedger(message) : null;
  if (tokenLedger) wrap.append(tokenLedger);
  const actions = !socialChat && message.role === "assistant" ? agentActionsChain(message) : null;
  if (actions) wrap.append(actions);
  wrap.append(body);
  const commandChoices = !socialChat && message.role === "assistant" ? renderAgentCommandChoices(message) : null;
  if (commandChoices) wrap.append(commandChoices);
  if (socialChat) {
    const meta = renderDirectMessageMeta(message);
    if (meta) wrap.append(meta);
    const reactions = direct ? renderDirectReactions(message) : null;
    if (reactions) wrap.append(reactions);
  }
  const changedFiles = !socialChat && message.role === "assistant" ? changedFilesFooter(message.changed_files || [], message) : null;
  if (changedFiles) wrap.append(changedFiles);
  if (state.agentOpenMessageMenuId === message.id && !header) wrap.append(agentMessageMenu(message));
  installAgentMessageMenuInteractions(wrap, message);
  return wrap;
}

function renderDirectStickerMessage(message) {
  const body = document.createElement("div");
  body.className = "agent-message-body agent-direct-sticker";
  const emoji = document.createElement("span");
  emoji.textContent = cleanText(message.sticker?.emoji, "◎");
  const label = document.createElement("strong");
  label.textContent = cleanText(message.sticker?.label, "sticker");
  body.append(emoji, label);
  return body;
}

function renderDirectMessageMeta(message) {
  const meta = document.createElement("div");
  meta.className = "agent-direct-meta";
  const time = new Date(message.timestamp || Date.now());
  const status = message.pending_state === "failed" ? "failed" : message.pending_state === "pending" ? "sending" : "sent";
  const timeText = Number.isFinite(time.getTime()) ? time.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "";
  const sender = cleanText(message.sender_label, "");
  meta.textContent = [sender && message.role !== "user" ? sender : "", timeText, status].filter(Boolean).join(" / ");
  return meta;
}

function renderDirectReactions(message) {
  const wrap = document.createElement("div");
  wrap.className = "agent-direct-reactions";
  const reactions = message.reactions && typeof message.reactions === "object" ? message.reactions : {};
  for (const [emoji, users] of Object.entries(reactions)) {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "agent-reaction-chip";
    button.textContent = `${emoji} ${Array.isArray(users) ? users.length : 0}`;
    if (Array.isArray(users) && users.includes(cleanText(state.authUser?.id, ""))) button.classList.add("mine");
    button.addEventListener("click", () => void sendDirectReaction(message, emoji));
    wrap.append(button);
  }
  const quick = document.createElement("div");
  quick.className = "agent-reaction-quick";
  for (const emoji of DIRECT_REACTION_SET.slice(0, 4)) {
    const button = document.createElement("button");
    button.type = "button";
    button.textContent = emoji;
    button.title = `React ${emoji}`;
    button.setAttribute("aria-label", `React ${emoji}`);
    button.disabled = !message.sync_event_id;
    button.addEventListener("click", () => void sendDirectReaction(message, emoji));
    quick.append(button);
  }
  wrap.append(quick);
  return wrap;
}

function renderAgentFileAttachments(message) {
  const entries = (Array.isArray(message.attachments) ? message.attachments : [])
    .filter((item) => item && typeof item === "object" && !item.image_card);
  if (!entries.length) return null;
  const list = document.createElement("div");
  list.className = "agent-file-attachments";
  for (const entry of entries) {
    const item = document.createElement("div");
    item.className = "agent-file-attachment";
    const name = document.createElement("strong");
    const meta = document.createElement("span");
    name.textContent = cleanText(entry.name, "Attachment");
    meta.textContent = attachmentMetaText(entry);
    item.append(name, meta);
    list.append(item);
  }
  return list;
}

function renderAgentMarkdown(content) {
  return renderChatMarkdownTokens(tokenizeChatMarkdown(content), {
    className: "agent-message-body agent-markdown chat-rendered-markdown",
  });
}

function clearAgentInput() {
  state.agentComposer?.clear?.({ focus: true });
}

function initializeAgentComposer() {
  if (state.agentComposer || !els.agentInput) return;
  state.agentComposer = createChatComposer({
    textarea: els.agentInput,
    form: els.agentForm,
    overlay: document.querySelector("#agentInputOverlay"),
    commandPaletteElement: document.querySelector("#agentCommandPalette"),
    createCommandPalette,
    canSubmit: (raw) => (
      state.agentBusy
      || (!agentPendingFileJobCount() && (
        Boolean(String(raw || "").trim())
        || Boolean(state.agentPendingImages.length + state.agentPendingAttachmentSummaries.length)
      ))
    ),
    onSend: (raw) => {
      void sendAgentMessage(raw);
      return false;
    },
  });
}

function recordAgentSpeechDiagnostic(detail = {}) {
  const type = cleanText(detail.type === "diagnostic" ? detail.event : detail.type || detail.event || "", "");
  if (!type || (type !== "error" && type !== "ready" && !type.endsWith("_failed"))) return;
  recordUserEvent("agent.speech_transcription_diagnostic", {
    target: "agent-form",
    summary: type,
    data: {
      type,
      state: state.agentSpeechState,
      engine: cleanText(detail.engine, ""),
      error: cleanText(detail.error, ""),
      device: cleanText(detail.device, ""),
      runtime: detail.runtime && typeof detail.runtime === "object" ? detail.runtime : null,
    },
    redacted: true,
  });
}

function handleAgentSpeechStateChange(detail = {}) {
  state.agentSpeechState = cleanText(detail.state, "idle");
}

function handleAgentSpeechError(detail = {}) {
  recordUserEvent("agent.speech_transcription_error", {
    target: "agent-form",
    summary: cleanText(detail.error, "Voice input error"),
    data: {
      context: cleanText(detail.context, ""),
      state: state.agentSpeechState,
    },
    redacted: true,
  });
}

async function ensureAgentSpeechTranscriber() {
  if (state.agentSpeechTranscriber) return state.agentSpeechTranscriber;
  if (state.agentSpeechTranscriberLoadPromise) return state.agentSpeechTranscriberLoadPromise;
  state.agentSpeechTranscriberLoadPromise = import("./modules/speech-transcription/speech-transcription.js")
    .then(({ createSpeechTranscriber }) => {
      state.agentSpeechTranscriber = createSpeechTranscriber({
        textarea: els.agentInput,
        composer: state.agentComposer,
        button: els.agentMicButton,
        language: "en",
        autoBindButton: false,
        onStateChange: handleAgentSpeechStateChange,
        onError: handleAgentSpeechError,
        onDiagnostic: recordAgentSpeechDiagnostic,
      });
      return state.agentSpeechTranscriber;
    })
    .catch((error) => {
      state.agentSpeechTranscriberLoadPromise = null;
      handleAgentSpeechError({ error: errorMessage(error), context: "module_import" });
      throw error;
    });
  return state.agentSpeechTranscriberLoadPromise;
}

async function toggleAgentSpeechTranscription(preAcquiredStream) {
  let stream = preAcquiredStream || null;
  try {
    const transcriber = await ensureAgentSpeechTranscriber();
    const activeStates = new Set(["requesting-permission", "loading-model", "listening", "quiet", "transcribing"]);
    if (activeStates.has(transcriber.state)) {
      if (stream) stream.getTracks().forEach((track) => track.stop());
      await transcriber.stop();
      return;
    }
    await transcriber.start({ mediaStream: stream });
  } catch (error) {
    if (stream) {
      stream.getTracks().forEach((track) => track.stop());
    }
    handleAgentSpeechError({ error: errorMessage(error), context: "toggle" });
  }
}

function stopAgentSpeechTranscription(reason = "send") {
  const transcriber = state.agentSpeechTranscriber;
  if (!transcriber) return;
  void transcriber.stop({ flush: false, reason }).catch((error) => {
    handleAgentSpeechError({ error: errorMessage(error), context: "stop" });
  });
}

function renderAgentImageCards(message) {
  const entries = [
    ...(Array.isArray(message.images) ? message.images : []),
    ...(Array.isArray(message.attachments) ? message.attachments : []),
  ].filter((item) => item?.image_card);
  if (!entries.length) return null;
  const details = document.createElement("details");
  details.className = "agent-image-card";
  bindAgentDetailsOpenState(details, message?.id ? `image-card:${message.id}` : "", false, {
    status: message?.pending ? "running" : "done",
  });
  const summary = document.createElement("summary");
  summary.className = "agent-image-card-summary";
  const first = imageCardSummary(entries[0]);
  summary.textContent = entries.length === 1
    ? `Image card: ${imageCardOneLine(first)}`
    : `${entries.length} image cards`;
  const list = document.createElement("div");
  list.className = "agent-image-card-list";
  list.replaceChildren(...entries.map(renderAgentImageCard));
  details.append(summary, list);
  return details;
}

function imageCardOneLine(card) {
  const palette = Array.isArray(card.palette) && card.palette.length ? card.palette.slice(0, 3).join(", ") : "palette unknown";
  const gradient = card.composition?.gradient?.kind || "";
  return [card.dimensions, palette, gradient].filter(Boolean).join(" / ");
}

function metricText(value) {
  return Number.isFinite(value) ? String(value) : "-";
}

function renderAgentImageCard(entry) {
  const card = imageCardSummary(entry);
  const article = document.createElement("article");
  article.className = "agent-image-card-item";
  const title = document.createElement("div");
  title.className = "agent-image-card-title";
  const name = document.createElement("strong");
  const dims = document.createElement("span");
  name.textContent = card.name;
  dims.textContent = [card.dimensions, card.size ? `${Math.round(card.size / 1024)} KB` : ""].filter(Boolean).join(" / ");
  title.append(name, dims);
  const tags = document.createElement("div");
  tags.className = "agent-image-card-tags";
  const tagValues = [
    ...(Array.isArray(card.palette) ? card.palette.slice(0, 4) : []),
    card.composition?.gradient?.kind,
  ].filter(Boolean);
  tags.replaceChildren(...tagValues.map((value) => {
    const tag = document.createElement("span");
    tag.textContent = value;
    return tag;
  }));
  const notes = document.createElement("p");
  notes.className = "agent-image-card-notes";
  notes.textContent = Array.isArray(card.visual_notes) && card.visual_notes.length
    ? card.visual_notes.slice(0, 8).join(", ")
    : "No visual notes.";
  const evidence = document.createElement("ul");
  evidence.className = "agent-image-card-evidence";
  const evidenceRows = Array.isArray(card.evidence) ? card.evidence.slice(0, 5) : [];
  evidence.replaceChildren(...evidenceRows.map((item) => {
    const row = document.createElement("li");
    const label = item.title || item.module || "Analyzer";
    const detail = [item.status, item.summary].filter(Boolean).join(" / ");
    row.textContent = `${label}: ${detail}`;
    return row;
  }));
  const metrics = document.createElement("dl");
  metrics.className = "agent-image-card-metrics";
  const analysis = card.analysis || {};
  const gradient = card.composition?.gradient || {};
  const symmetry = card.composition?.symmetry || {};
  const rows = [
    ["Luma", metricText(analysis.average_luminance)],
    ["Contrast", metricText(analysis.contrast)],
    ["Edges", metricText(analysis.edge_density)],
    ["Sharp", metricText(analysis.sharpness)],
    ["Gradient", metricText(gradient.strength)],
    ["Sym", [metricText(symmetry.horizontal), metricText(symmetry.vertical)].join(" / ")],
  ];
  for (const [labelText, valueText] of rows) {
    const dt = document.createElement("dt");
    const dd = document.createElement("dd");
    dt.textContent = labelText;
    dd.textContent = valueText;
    metrics.append(dt, dd);
  }
  article.append(title);
  if (tagValues.length) article.append(tags);
  article.append(notes);
  if (evidenceRows.length) article.append(evidence);
  article.append(metrics);
  if (card.local_url && card.local_url !== "-") {
    const local = document.createElement("code");
    local.className = "agent-image-card-url";
    local.textContent = card.local_url;
    article.append(local);
  }
  return article;
}

function agentTurnHeader(message) {
  const header = document.createElement("div");
  header.className = "agent-turn-header";
  const elapsed = document.createElement("span");
  elapsed.className = "agent-turn-elapsed";
  elapsed.dataset.messageId = message.id || "";
  const elapsedMs = Number.isFinite(message.duration_ms)
    ? message.duration_ms
    : Date.now() - Number(message.turn_started_at || Date.now());
  elapsed.textContent = formatTurnElapsed(elapsedMs);
  const menuButton = document.createElement("button");
  menuButton.className = "agent-message-menu-button";
  menuButton.type = "button";
  menuButton.title = "Message actions";
  menuButton.setAttribute("aria-label", "Message actions");
  menuButton.dataset.messageId = message.id || "";
  menuButton.addEventListener("click", (event) => {
    event.stopPropagation();
    if (state.agentOpenMessageMenuId === message.id) {
      closeAgentMessageMenu();
      renderAgentMessages();
      return;
    }
    openAgentMessageMenu(message, event);
  });
  const arrow = document.createElement("span");
  arrow.className = "agent-menu-arrow";
  arrow.setAttribute("aria-hidden", "true");
  menuButton.append(arrow);
  header.append(elapsed, menuButton);
  if (state.agentOpenMessageMenuId === message.id) header.append(agentMessageMenu(message));
  return header;
}

function agentMessageMenu(message) {
  const menu = document.createElement("div");
  menu.className = "agent-message-menu";
  if (state.agentOpenMessageMenuId === message.id && state.agentMessageMenuPosition) {
    const x = Number(state.agentMessageMenuPosition.x);
    const y = Number(state.agentMessageMenuPosition.y);
    const left = clamp(x, 8, Math.max(8, window.innerWidth - AGENT_MESSAGE_MENU_WIDTH_PX - 8));
    const top = clamp(y, 8, Math.max(8, window.innerHeight - AGENT_MESSAGE_MENU_HEIGHT_PX - 8));
    menu.classList.add("is-positioned");
    menu.style.setProperty("--agent-message-menu-left", `${left}px`);
    menu.style.setProperty("--agent-message-menu-top", `${top}px`);
  }
  const copy = document.createElement("button");
  copy.type = "button";
  copy.className = "agent-message-menu-item";
  copy.addEventListener("click", (event) => {
    event.stopPropagation();
    copyAgentMessageText(message);
    closeAgentMessageMenu();
    renderAgentMessages();
  });
  const icon = document.createElement("span");
  icon.className = "agent-icon-copy";
  icon.setAttribute("aria-hidden", "true");
  const label = document.createElement("span");
  label.textContent = "Copy text";
  copy.append(icon, label);
  menu.append(copy);
  return menu;
}

function copyAgentMessageText(message) {
  const text = agentMessageSourceText(message);
  if (navigator.clipboard?.writeText) {
    navigator.clipboard.writeText(text).catch(() => {});
  }
  recordUserEvent("agent.message_copied", {
    target: `message:${message.id || "unknown"}`,
    summary: "Copied message text",
    data: { message_id: message.id || "", text_length: text.length },
  });
}

function agentMessageSourceText(message = {}) {
  return String(
    message.source_content
    || message.markdown_source
    || message.raw_content
    || message.content
    || ""
  );
}

function bindAgentDetailsOpenState(details, key, defaultOpen = false, options = {}) {
  if (!details || !key) return;
  const overrides = state.agentDetailsOpenOverrides || {};
  state.agentDetailsOpenOverrides = overrides;
  details.dataset.agentOpenKey = key;
  const status = cleanText(options.status, "");
  const existing = overrides[key];
  const overrideOpen = existing && typeof existing === "object"
    ? Boolean(existing.open)
    : Boolean(existing);
  const overrideStatus = existing && typeof existing === "object" ? cleanText(existing.status, "") : "";
  const userInteracted = existing && typeof existing === "object" ? Boolean(existing.user) : false;
  if (options.autoCloseOnDone && status === "done" && overrideOpen && overrideStatus !== "done" && !userInteracted) {
    delete overrides[key];
  }
  details.open = Object.prototype.hasOwnProperty.call(overrides, key)
    ? (overrides[key] && typeof overrides[key] === "object" ? Boolean(overrides[key].open) : Boolean(overrides[key]))
    : Boolean(defaultOpen);
  const rememberInteraction = (event = null) => {
    if (event?.target?.closest?.("summary")) return;
    overrides[key] = { open: Boolean(details.open), status, user: true };
  };
  details.addEventListener("click", (event) => {
    if (!event.target?.closest?.("summary")) return;
    window.setTimeout(() => {
      overrides[key] = { open: Boolean(details.open), status, user: true };
    }, 0);
  });
  details.addEventListener("pointerdown", rememberInteraction, { capture: true });
  details.addEventListener("focusin", rememberInteraction);
  details.addEventListener("wheel", rememberInteraction, { passive: true });
}

function renderAgentMessages(options = {}) {
  const session = activeAgentSession();
  const scrollSnapshot = agentChatScrollSnapshot();
  renderAgentChrome();
  els.agentMessages.replaceChildren();
  for (const message of session.messages) {
    els.agentMessages.append(renderAgentMessage(message));
  }
  if (socialChatSession(session) && !session.messages.length) {
    const empty = document.createElement("div");
    empty.className = "agent-direct-empty";
    empty.textContent = session.kind === "shared-space"
      ? "No shared-space messages yet"
      : `No messages yet with ${socialUserLabel(session.peer, "this friend")}`;
    els.agentMessages.append(empty);
  }
  renderAgentDiagnostics(session.diagnostics || {});
  renderAgentContextPreview(session.context_preview || []);
  restoreAgentChatScroll(scrollSnapshot, { forceBottom: Boolean(options.forceBottom) });
}

function socialUserId(user) {
  return cleanText(user?.id || user?.user_id || "", "");
}

function socialUserLabel(user, fallback = "Person") {
  return cleanText(user?.label || user?.name || user?.email || user?.user_label || user?.id || user?.user_id, fallback);
}

function directConversationId(peerUserId) {
  const current = cleanText(state.authUser?.id, "");
  const peer = cleanText(peerUserId, "");
  if (!current || !peer) return "";
  return `dm-${[current, peer].sort().join("-")}`;
}

function sharedSpaceConversationId(sharedSpaceId) {
  const id = cleanText(sharedSpaceId, "");
  return id ? `space-${id}` : "";
}

function socialChatSession(session = activeAgentSession()) {
  return session?.kind === "direct" || session?.kind === "shared-space";
}

function mainAgentSession() {
  let session = state.agentSessions.find((item) => item.kind !== "direct" && item.kind !== "shared-space");
  if (!session) {
    session = createAgentSession("Main session");
    state.agentSessions.unshift(session);
  }
  return session;
}

function switchToMainAgentChat() {
  state.activeAgentSessionId = mainAgentSession().id;
  state.agentView = "chat";
  setAgentSocialPicker("");
  saveAgentSessions();
  saveActiveAgentSessionPreference();
  renderAgentSessions();
  renderAgentMessages({ forceBottom: true });
  window.setTimeout(() => els.agentInput?.focus(), 0);
}

function returnFromSocialAgentChat() {
  const session = activeAgentSession();
  if (session.kind === "direct") {
    state.agentView = "people";
    setAgentSocialPicker("");
    renderAgentChrome();
    void loadAgentPeople("main-chat-button").catch(() => {});
    saveActiveAgentSessionPreference();
    return;
  }
  switchToMainAgentChat();
}

function renderAgentConfiguredModelList() {
  if (!els.agentConfiguredModelList) return;
  const entries = configuredAgentTargetOptions();
  if (!entries.length) {
    const empty = document.createElement("div");
    empty.className = "agent-configured-model-empty";
    empty.textContent = "None";
    els.agentConfiguredModelList.replaceChildren(empty);
    return;
  }
  els.agentConfiguredModelList.replaceChildren(...entries.map((entry) => {
    const row = document.createElement("div");
    row.className = `agent-configured-model-row kind-${entry.kind || "agent"}`;
    row.dataset.targetValue = entry.value || "";
    row.dataset.targetKind = entry.kind || "";
    const text = document.createElement("div");
    text.className = "agent-configured-model-text";
    const title = document.createElement("strong");
    title.textContent = entry.label || entry.value || "model";
    const detail = document.createElement("span");
    detail.textContent = entry.detail || "";
    text.append(title);
    if (detail.textContent) text.append(detail);
    const actions = document.createElement("div");
    actions.className = "agent-configured-model-actions";
    const use = document.createElement("button");
    use.type = "button";
    use.dataset.action = "use";
    use.textContent = "Use";
    if (entry.kind === "harness" && entry.lifecycle !== "ready") {
      use.disabled = true;
      use.title = entry.lifecycle === "failed" ? "Provisioning failed; edit and create again" : entry.detail || "Harness is not ready";
    }
    const edit = document.createElement("button");
    edit.type = "button";
    edit.dataset.action = "edit";
    edit.textContent = "Edit";
    if (entry.kind === "agent" && entry.value === defaultAgentTargetNode() && userFleetAgentNodes().length) {
      edit.disabled = true;
      edit.title = "Use the listed account node instead.";
    }
    const del = document.createElement("button");
    del.type = "button";
    del.dataset.action = "delete";
    del.textContent = "Delete";
    const nodeHasSavedModel = entry.kind === "agent" && Boolean(state.agentModelSettings.selectedByNode?.[entry.nodeId || entry.value]);
    del.disabled = (entry.kind === "agent" && !nodeHasSavedModel) || entry.kind === "harness";
    del.title = del.disabled
      ? entry.kind === "harness" ? "Harness records are retained with the account fleet" : "This agent is using its current default model"
      : entry.kind === "node" ? "Delete this node" : entry.kind === "owned-agent" ? "Delete this agent" : "Delete this listed model";
    actions.append(use, edit, del);
    row.append(text, actions);
    return row;
  }));
}

function deleteAgentConfiguredTarget(row) {
  const kind = cleanText(row?.dataset?.targetKind, "");
  const value = cleanText(row?.dataset?.targetValue, "");
  if (kind === "node" || kind === "provider") {
    const deletedId = providerIdFromTargetValue(value);
    if (deletedId) {
      saveAgentDirectProviderConfigs(
        state.agentDirectProviders.filter((item) => normalizeAgentProviderNodeId(item?.id || "") !== deletedId)
      );
    } else {
      saveAgentDirectProviderConfig(null);
    }
    state.agentProviderProbe = null;
    if (state.agentTargetNode === value || state.agentTargetNode === AGENT_PROVIDER_TARGET_ID) {
      state.agentTargetNode = state.agentDirectProviders.length ? directProviderTargetValue(state.agentDirectProviders[0]) : AGENT_NONE_TARGET_ID;
      state.agentDirectProvider = state.agentDirectProviders[0] || null;
    }
    state.nodesPanelStatus = "Node deleted";
  } else if (kind === "agent-model") {
    const model = agentModelFromTargetValue(value);
    if (model) {
      removeAgentModelFromCatalog(model);
      state.agentModelSettings.selectedByNode = state.agentModelSettings.selectedByNode || {};
      Object.entries(state.agentModelSettings.selectedByNode || {}).forEach(([nodeId, selected]) => {
        if (sameAgentModel(selected, model)) delete state.agentModelSettings.selectedByNode[nodeId];
      });
      saveAgentModelSettings();
    }
    if (state.agentTargetNode === value) state.agentTargetNode = defaultAgentTargetNode();
    state.nodesPanelStatus = "Agent model deleted";
  } else if (kind === "agent") {
    const selected = normalizeAgentModelEntry(state.agentModelSettings.selectedByNode?.[value]);
    if (selected) removeAgentModelFromCatalog(selected);
    delete state.agentModelSettings.selectedByNode?.[value];
    saveAgentModelSettings();
    state.nodesPanelStatus = "Agent model deleted";
  } else if (kind === "owned-agent") {
    saveAgentOwnedAgentConfig(null);
    if (state.agentTargetNode === AGENT_OWNED_AGENT_TARGET_ID) state.agentTargetNode = AGENT_NONE_TARGET_ID;
    state.nodesPanelStatus = "Agent deleted";
  }
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
  renderNodesPanel();
}

function handleAgentConfiguredModelAction(event) {
  const button = event.target?.closest?.("button[data-action]");
  const row = button?.closest?.(".agent-configured-model-row");
  if (!button || !row) return;
  event.preventDefault();
  event.stopPropagation();
  const action = button.dataset.action || "";
  const kind = cleanText(row.dataset.targetKind, "");
  const value = cleanText(row.dataset.targetValue, "");
  if (action === "use") {
    setAgentTargetNode(value || defaultAgentTargetNode());
    closeAgentSetupBalloon();
    return;
  }
  if (action === "edit") {
    if (kind === "node" || kind === "provider") {
      const providerId = providerIdFromTargetValue(value);
      const providerConfig = activeAgentDirectProviderConfig(value);
      if (providerConfig) state.agentDirectProvider = providerConfig;
      state.agentTargetNode = providerConfig ? directProviderTargetValue(providerConfig) : AGENT_PROVIDER_TARGET_ID;
      openNodeForm("edit", providerId);
      state.agentSetupMode = "provider";
      state.agentSetupBalloonOpen = true;
      renderNodesPanel();
      window.setTimeout(() => els.agentDirectModelInput?.focus(), 0);
      return;
    }
    if (kind === "agent") {
      state.agentTargetNode = value || defaultAgentTargetNode();
      openAgentModelSetup("set", agentModelForNodeOption(state.agentTargetNode));
      return;
    }
    if (kind === "agent-model") {
      state.agentTargetNode = value || defaultAgentTargetNode();
      openAgentModelSetup("set", agentModelFromTargetValue(value));
      return;
    }
    if (kind === "owned-agent") {
      openAgentTopicForm();
      return;
    }
    if (kind === "harness") {
      const harness = state.userFleetHarnesses.find((item) => {
        const readyValue = agentHarnessLifecycleState(item) === "ready" && agentHarnessNodeId(item) ? agentHarnessNodeId(item) : "";
        return readyValue === value || `harness:${cleanText(item.id, "")}` === value;
      }) || null;
      const providerConfig = harness ? directProviderForHarness(harness) : null;
      if (providerConfig) {
        const providerId = normalizeAgentProviderNodeId(providerConfig.id || providerConfig.providerId || "");
        state.agentDirectProvider = providerConfig;
        state.agentTargetNode = directProviderTargetValue(providerConfig);
        openNodeForm("edit", providerId);
      } else {
        openNodeForm("edit");
      }
      if (harness && state.nodeFormDraft) {
        const harnessDraft = state.nodeFormDraft.agentHarness && typeof state.nodeFormDraft.agentHarness === "object" ? state.nodeFormDraft.agentHarness : {};
        state.nodeFormDraft = {
          ...state.nodeFormDraft,
          nodeName: state.nodeFormDraft.nodeName || cleanText(harness.node_name || harness.nodeName || harness.harness_name || harness.name, ""),
          persistedHarnessId: cleanText(harness.id || harness.harness_id || "", ""),
          persistedNodeId: agentHarnessNodeId(harness),
          agentHarnessEnabled: true,
          agentHarness: {
            ...harnessDraft,
            enabled: true,
            name: harnessDraft.name || agentHarnessDisplayName(harness),
            type: harnessDraft.type || AGENT_HARNESS_DEFAULT_TYPE,
            infraMode: harnessDraft.infraMode || normalizeAgentHarnessInfraMode(harness.infra_mode || harness.infraMode),
            bridgeUrl: harnessDraft.bridgeUrl || cleanText(harness.bridge_url || harness.bridgeUrl, ""),
            instructions: harnessDraft.instructions || cleanText(harness.instructions || harness.metadata?.instructions || "", ""),
          },
        };
      }
      state.agentSetupMode = "provider";
      state.agentSetupBalloonOpen = true;
      renderNodesPanel();
      window.setTimeout(() => els.nodeNameInput?.focus(), 0);
      return;
    }
  }
  if (action === "delete" && !button.disabled) deleteAgentConfiguredTarget(row);
}

function directSessions() {
  return state.agentSessions.filter((session) => session.kind === "direct" && session.conversation_id);
}

function sharedSpaceSessions() {
  return state.agentSessions.filter((session) => session.kind === "shared-space" && session.shared_space_id);
}

function unreadTotal() {
  return Object.values(state.agentPeople.unreadByConversation || {})
    .reduce((sum, value) => sum + Math.max(0, Number(value || 0)), 0);
}

function inboundPendingFriendships() {
  return (state.agentPeople.friendships || []).filter((item) => item.status === "pending" && item.direction === "incoming");
}

function updatePeopleButtonState() {
  const unread = unreadTotal();
  const pending = inboundPendingFriendships().length;
  const count = unread + pending;
  if (!els.agentPeopleButton) return;
  els.agentPeopleButton.dataset.count = count ? String(Math.min(99, count)) : "";
  els.agentPeopleButton.classList.toggle("has-social-alerts", count > 0);
}

function setSocialPulse() {
  els.agentPeopleButton?.classList.add("is-ringing");
  window.clearTimeout(state.socialPulseTimer);
  state.socialPulseTimer = window.setTimeout(() => {
    els.agentPeopleButton?.classList.remove("is-ringing");
  }, 1200);
}

function pushSocialToast(kind, title, detail = "", key = "", action = null) {
  const dedupeKey = key || `${kind}:${title}:${detail}`;
  if (state.socialNotificationKeys.has(dedupeKey)) return;
  if (state.socialNotificationKeys.size > 200) state.socialNotificationKeys.clear();
  state.socialNotificationKeys.add(dedupeKey);
  const toast = {
    id: `toast_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`,
    kind,
    title,
    detail,
    key: dedupeKey,
    action,
  };
  state.socialNotifications.push(toast);
  state.socialNotifications = state.socialNotifications.slice(-4);
  setSocialPulse();
  renderSocialToasts();
  window.setTimeout(() => dismissSocialToast(toast.id), SOCIAL_TOAST_TTL_MS);
}

function dismissSocialToast(id) {
  state.socialNotifications = state.socialNotifications.filter((toast) => toast.id !== id);
  renderSocialToasts();
}

function clearSocialToasts(kind, conversationId = "") {
  const before = state.socialNotifications.length;
  state.socialNotifications = state.socialNotifications.filter((toast) => {
    if (toast.kind !== kind) return true;
    if (conversationId) return toast.action?.conversationId !== conversationId;
    return false;
  });
  if (state.socialNotifications.length !== before) renderSocialToasts();
}

function renderSocialToasts() {
  if (!els.agentToastStack) return;
  els.agentToastStack.replaceChildren(...state.socialNotifications.map((toast) => {
    const item = document.createElement("button");
    item.type = "button";
    item.className = `agent-toast ${toast.kind || "info"}`;
    const title = document.createElement("strong");
    title.textContent = toast.title;
    const detail = document.createElement("span");
    detail.textContent = toast.detail;
    item.append(title, detail);
    item.addEventListener("click", () => {
      dismissSocialToast(toast.id);
      setAgentOpen(true);
      if (toast.action?.conversationId) {
        const session = chatSessionForConversation(toast.action.conversationId);
        if (session?.kind === "direct" && session.peer) {
          openDirectChat(session.peer);
          return;
        }
        if (session?.kind === "shared-space") {
          openSharedSpaceChat(session.shared_space_id);
          return;
        }
      }
      setAgentView("people");
    });
    return item;
  }));
}

function agentTopicConfigFromInputs() {
  const first = cleanText(els.nodeNameInput?.value || "", "");
  const firstIsUrl = Boolean(normalizeOwnedAgentBridgeUrl(first));
  return normalizeAgentOwnedAgentConfig({
    name: cleanText(els.agentTopicNameInput?.value || (firstIsUrl ? "" : first), "My agent"),
    role: cleanText(els.agentTopicRoleInput?.value || "", ""),
    type: cleanText(els.agentTopicTypeSelect?.value || "hermes", "hermes"),
    bridgeUrl: cleanText(els.agentTopicBridgeUrlInput?.value || (firstIsUrl ? first : ""), ""),
  }) || {
    name: "My agent",
    role: "",
    type: "hermes",
    bridgeUrl: "",
    service: "hermes-orchestrator",
  };
}

function openAgentTopicForm() {
  state.agentSetupBalloonOpen = true;
  state.agentSetupMode = "agent";
  state.agentSetupMessage = "Add an agent bridge or configure a Hermes agent.";
  state.agentTopicFormOpen = true;
  closeNodeForm();
  const first = cleanText(els.nodeNameInput?.value || "", "");
  const firstIsUrl = Boolean(normalizeOwnedAgentBridgeUrl(first));
  state.agentTopicDraft = normalizeAgentOwnedAgentConfig({
    ...(state.agentOwnedAgent || {}),
    name: state.agentOwnedAgent?.name || (firstIsUrl ? "" : first),
    bridgeUrl: state.agentOwnedAgent?.bridgeUrl || (firstIsUrl ? first : ""),
  });
  renderNodesPanel();
  renderAgentNodeSelect();
  window.setTimeout(() => els.agentTopicNameInput?.focus(), 0);
}

function closeAgentTopicForm() {
  if (state.agentTopicBusy) return;
  state.agentTopicFormOpen = false;
  state.agentTopicDraft = null;
  renderNodesPanel();
}

async function submitAgentTopicForm(event) {
  event?.preventDefault();
  if (state.agentTopicBusy || state.agentProvisionBusy) return;
  const config = agentTopicConfigFromInputs();
  saveAgentOwnedAgentConfig(config);
  state.agentTargetNode = AGENT_OWNED_AGENT_TARGET_ID;
  if (config.bridgeUrl) {
    state.agentTopicFormOpen = false;
    state.agentSetupBalloonOpen = false;
    state.nodesPanelStatus = "Agent saved";
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    renderNodesPanel();
    recordUserEvent("agent.owned_agent_saved", {
      target: "owned-agent",
      summary: `Saved ${config.name}`,
      data: { type: config.type, bridge_url_configured: true },
    });
    return;
  }
  if (config.type !== "hermes") {
    state.nodesPanelStatus = "Only Hermes service agents are available right now";
    renderNodesPanel();
    return;
  }
  const balance = Number(state.agentCredits?.balance || 0);
  const cost = Number(state.agentCredits?.agent_harness_cost || state.agentCredits?.provision_main_cost || state.agentReadiness?.onboarding_options?.find?.((item) => item.id === "flux_credits")?.cost || 10);
  if (balance < cost) {
    state.agentSetupMessage = "Not enough credits to set an agent yet. Your balance is in the account popover.";
    state.nodesPanelStatus = "";
    renderNodesPanel();
    return;
  }
  state.agentTopicBusy = true;
  try {
    await provisionMainWithFlux({
      agent_name: config.name,
      agent_role: config.role,
      agent_type: config.type,
    });
    state.agentTopicFormOpen = false;
    recordUserEvent("agent.service_agent_requested", {
      target: "owned-agent",
      summary: `Requested Hermes agent ${config.name}`,
      data: { type: config.type },
    });
  } finally {
    state.agentTopicBusy = false;
    renderNodesPanel();
  }
}

function renderNodesPanel() {
  if (!els.nodesPanel) return;
  const session = activeAgentSession();
  const socialChat = session.kind === "direct" || session.kind === "shared-space";
  const show = Boolean(state.authUser && !socialChat && state.agentView !== "people" && (state.agentSetupBalloonOpen || state.agentModelSetup.open));
  els.nodesPanel.hidden = !show;
  placeNodesPanel();
  updateAgentScrollBottomButton();
  if (!show) return;
  renderAgentConfiguredModelList();
  const mode = state.agentSetupMode === "agent" ? "agent" : "provider";
  const providerProbe = currentAgentProviderProbe();
  if (els.nodesPanelTitle) {
    els.nodesPanelTitle.textContent = state.agentTopicFormOpen
      ? "Add agent"
      : mode === "agent"
      ? "Set node"
      : providerProbe?.ok ? "Node ready" : directProviderConfigured() ? "Node Configuration" : "Set node";
  }
  if (els.nodesPanelCopy) {
    els.nodesPanelCopy.textContent = state.agentSetupMessage || (mode === "agent"
      ? "Pick a configured node or set one up before sending chat messages."
      : "Edit, add, or delete configured nodes.");
  }
  if (els.nodesPanelStatus) {
    const statusText = state.agentProvisionBusy ? (state.nodesPanelStatus || "Provisioning sandbox...") : state.nodesPanelStatus || "";
    els.nodesPanelStatus.textContent = statusText;
    els.nodesPanelStatus.hidden = !statusText;
  }
  const formConfig = nodeFormConfigSource();
  if (els.nodeNameInput && document.activeElement !== els.nodeNameInput) {
    els.nodeNameInput.value = state.nodeFormOpen
      ? formConfig?.nodeName || ""
      : state.nodeFormDraft?.nodeName || state.agentDirectProvider?.nodeName || "";
  }
  if (els.newNodeButton) {
    els.newNodeButton.disabled = state.agentProviderProbeBusy || state.agentProvisionBusy;
    els.newNodeButton.title = "Edit, add, or delete configured nodes.";
  }
  if (els.agentTopicForm) {
    els.agentTopicForm.hidden = !state.agentTopicFormOpen;
  }
  const topicConfig = state.agentTopicDraft || state.agentOwnedAgent || {};
  if (els.agentTopicNameInput && document.activeElement !== els.agentTopicNameInput) {
    els.agentTopicNameInput.value = topicConfig.name || "";
  }
  if (els.agentTopicRoleInput && document.activeElement !== els.agentTopicRoleInput) {
    els.agentTopicRoleInput.value = topicConfig.role || "";
  }
  if (els.agentTopicTypeSelect) {
    els.agentTopicTypeSelect.value = topicConfig.type || "hermes";
  }
  if (els.agentTopicBridgeUrlInput && document.activeElement !== els.agentTopicBridgeUrlInput) {
    els.agentTopicBridgeUrlInput.value = topicConfig.bridgeUrl || "";
  }
  if (els.agentTopicStatus) {
    els.agentTopicStatus.textContent = state.agentTopicBusy || state.agentProvisionBusy
      ? "Provisioning sandbox..."
      : state.agentOwnedAgent?.bridgeUrl
        ? "Private bridge saved"
        : ownedAgentConfigured() ? "Hermes service agent configured" : "";
  }
  if (els.nodeForm) {
    els.nodeForm.hidden = !state.nodeFormOpen;
  }
  if (els.nodeFormSubmitButton) {
    els.nodeFormSubmitButton.textContent = state.nodeFormMode === "edit" ? "Save configuration" : "Create node";
  }
  const formProvider = normalizeDirectProviderName(formConfig?.provider || directProviderNameFromBaseUrl(formConfig?.baseUrl || ""));
  if (els.agentDirectProviderSelect && document.activeElement !== els.agentDirectProviderSelect) {
    els.agentDirectProviderSelect.value = formProvider || "";
  }
  if (els.agentDirectModelField) {
    els.agentDirectModelField.hidden = !formProvider;
  }
  let formProviderHasModels = false;
  if (els.agentDirectModelInput) {
    const modelOptions = directProviderModelOptions(formProvider, formConfig?.model || "");
    formProviderHasModels = Boolean(modelOptions.length);
    const liveModelOptions = directProviderLiveModelOptions(formProvider);
    const modelStatus = directProviderModelStatus(formProvider);
    if (formProvider && !liveModelOptions.length && modelStatus.status !== "loading" && modelStatus.status !== "snapshot" && modelStatus.status !== "error") {
      void loadDirectProviderModels(formProvider);
    }
    const selectedModel = formConfig?.model && modelOptions.some((model) => model.id === formConfig.model)
      ? formConfig.model
      : modelOptions[0]?.id || "";
    const placeholderText = modelStatus.status === "error"
      ? "Model list unavailable"
      : modelStatus.status === "loading" ? "Loading models..." : "Choose model";
    els.agentDirectModelInput.setAttribute("placeholder", placeholderText);
    els.agentDirectModelInput.replaceChildren(
      ...modelOptions.map((model) => {
        const option = document.createElement("option");
        option.value = model.id;
        option.textContent = model.label || model.id;
        return option;
      })
    );
    els.agentDirectModelInput.disabled = !formProvider || (formProvider && !modelOptions.length);
    if (document.activeElement !== els.agentDirectModelInput) {
      els.agentDirectModelInput.value = selectedModel;
    }
  }
  if (els.agentDirectApiKeyInput && document.activeElement !== els.agentDirectApiKeyInput) {
    els.agentDirectApiKeyInput.value = formConfig?.apiKey ? AGENT_DIRECT_PROVIDER_KEY_MASK : "";
    els.agentDirectApiKeyInput.placeholder = formConfig?.apiKey ? "Saved key" : "";
  }
  const harnessConfig = formConfig?.agentHarness && typeof formConfig.agentHarness === "object" ? formConfig.agentHarness : {};
  const wrapperEnabled = Boolean(harnessConfig.enabled);
  const harnessInfraMode = normalizeAgentHarnessInfraMode(harnessConfig.infraMode || AGENT_HARNESS_DEFAULT_INFRA_MODE);
  const providerFieldsRequired = nodeFormNeedsDirectProvider(formConfig);
  document.querySelectorAll(".node-provider-field").forEach((field) => {
    field.hidden = field === els.agentDirectModelField ? !formProvider : false;
    field.querySelectorAll("input, select, textarea, s-select").forEach((input) => {
      input.disabled = input === els.agentDirectModelInput && (!formProvider || !formProviderHasModels);
      input.required = providerFieldsRequired;
    });
  });
  if (els.nodeAgentWrapperToggle && document.activeElement !== els.nodeAgentWrapperToggle) {
    els.nodeAgentWrapperToggle.checked = wrapperEnabled;
  }
  if (els.nodeAgentWrapperFields) {
    els.nodeAgentWrapperFields.hidden = !wrapperEnabled;
  }
  [els.nodeWrapperNameInput, els.nodeWrapperTypeSelect, els.nodeHarnessInfraSelect, els.nodeHarnessBridgeUrlInput, els.nodeWrapperRoleInput].forEach((input) => {
    if (input) input.disabled = !wrapperEnabled;
  });
  if (els.nodeWrapperNameInput) els.nodeWrapperNameInput.required = wrapperEnabled;
  if (els.nodeWrapperTypeSelect) els.nodeWrapperTypeSelect.required = wrapperEnabled;
  if (els.nodeWrapperNameInput && document.activeElement !== els.nodeWrapperNameInput) {
    els.nodeWrapperNameInput.value = harnessConfig.name || "";
  }
  if (els.nodeWrapperTypeSelect) {
    els.nodeWrapperTypeSelect.value = normalizeAgentHarnessType(harnessConfig.type || AGENT_HARNESS_DEFAULT_TYPE);
  }
  if (els.nodeHarnessInfraSelect) {
    els.nodeHarnessInfraSelect.value = harnessInfraMode;
  }
  if (els.nodeHarnessBridgeUrlField) {
    els.nodeHarnessBridgeUrlField.hidden = !wrapperEnabled || harnessInfraMode !== AGENT_HARNESS_OWN_INFRA_MODE;
  }
  if (els.nodeHarnessBridgeUrlInput) {
    els.nodeHarnessBridgeUrlInput.required = wrapperEnabled && harnessInfraMode === AGENT_HARNESS_OWN_INFRA_MODE;
    els.nodeHarnessBridgeUrlInput.disabled = !wrapperEnabled || harnessInfraMode !== AGENT_HARNESS_OWN_INFRA_MODE;
  }
  if (els.nodeHarnessBridgeInfoBalloon && (!wrapperEnabled || harnessInfraMode !== AGENT_HARNESS_OWN_INFRA_MODE)) {
    els.nodeHarnessBridgeInfoBalloon.hidden = true;
  }
  if (els.nodeHarnessBridgeUrlInput && document.activeElement !== els.nodeHarnessBridgeUrlInput) {
    els.nodeHarnessBridgeUrlInput.value = harnessConfig.bridgeUrl || "";
  }
  if (els.nodeWrapperRoleInput && document.activeElement !== els.nodeWrapperRoleInput) {
    els.nodeWrapperRoleInput.value = harnessConfig.instructions || "";
  }
  if (els.agentProviderLoadingIcon) {
    els.agentProviderLoadingIcon.hidden = !state.agentProviderProbeBusy;
  }
  if (els.nodeFormStatus) {
    els.nodeFormStatus.textContent = state.nodeFormStatus || nodeFormStatusText(nodeFormConfigSource());
    const footer = els.nodeFormStatus.closest?.(".node-form-footer");
    if (footer) footer.classList.toggle("is-attention", state.nodeFormStatusAttention);
  }
}

function placeNodesPanel() {
  if (!els.nodesPanel) return;
  const position = state.nodesPanelPosition;
  if (!position) {
    els.nodesPanel.style.removeProperty("--nodes-panel-left");
    els.nodesPanel.style.removeProperty("--nodes-panel-top");
    return;
  }
  const appRect = appViewportRect();
  const panelRect = els.nodesPanel.getBoundingClientRect();
  const halfWidth = Math.max(160, panelRect.width || 460) / 2;
  const halfHeight = Math.max(120, panelRect.height || 260) / 2;
  const left = clamp(Number(position.left || appRect.left + appRect.width / 2), appRect.left + halfWidth + 8, appRect.right - halfWidth - 8);
  const top = clamp(Number(position.top || appRect.top + appRect.height / 2), appRect.top + halfHeight + 8, appRect.bottom - halfHeight - 8);
  state.nodesPanelPosition = { left, top };
  els.nodesPanel.style.setProperty("--nodes-panel-left", `${left}px`);
  els.nodesPanel.style.setProperty("--nodes-panel-top", `${top}px`);
}

function openAgentSetupBalloon({ mode = "provider", message = "", openProviderForm = false, providerFormMode = "new" } = {}) {
  state.agentSetupBalloonOpen = true;
  state.agentSetupMode = mode === "agent" ? "agent" : "provider";
  state.agentSetupMessage = cleanText(message, "");
  if (openProviderForm) openNodeForm(providerFormMode);
  setAgentView("chat", { keepActiveSession: true });
  setAgentOpen(true);
  renderNodesPanel();
  renderAgentNodeSelect();
  window.setTimeout(() => {
    if (openProviderForm) (state.nodeFormMode === "new" ? els.nodeNameInput : els.agentDirectModelInput)?.focus();
    else if (mode === "agent") els.newNodeButton?.focus();
    else els.agentConfiguredModelList?.querySelector?.("button")?.focus();
  }, 0);
}

function closeAgentSetupBalloon() {
  if (state.agentModelSetup.busy || state.agentTopicBusy || state.agentProvisionBusy) return;
  state.agentSetupBalloonOpen = false;
  state.agentSetupMessage = "";
  closeNodeForm();
  closeAgentTopicForm();
  closeAgentModelSetup();
  renderNodesPanel();
}

function handleAgentProviderSetupAction() {
  state.agentSetupBalloonOpen = true;
  state.agentSetupMode = "provider";
  state.agentSetupMessage = "Edit, add, or delete configured nodes.";
  if (hasDirectProviderConfigured() && !agentTargetIsDirectProvider() && !state.nodeFormOpen) {
    state.agentTargetNode = directProviderTargetValue(activeAgentDirectProviderConfig() || state.agentDirectProviders[0]);
    closeAgentSetupBalloon();
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    return;
  }
  if (state.nodeFormOpen) {
    closeNodeForm();
  } else {
    openNodeForm(hasDirectProviderConfigured() ? "edit" : "new");
  }
  renderNodesPanel();
  if (state.nodeFormOpen) window.setTimeout(() => (state.nodeFormMode === "new" ? els.nodeNameInput : els.agentDirectModelInput)?.focus(), 0);
}

function handleAgentSetAgentAction() {
  if (isAdminUser()) {
    state.agentSetupBalloonOpen = true;
    state.agentSetupMode = "agent";
    openAgentModelSetup("add");
    return;
  }
  state.agentSetupBalloonOpen = true;
  state.agentSetupMode = "agent";
  if (state.agentReadiness?.ready || state.agentReadiness?.status === "ready") {
    state.agentTargetNode = defaultAgentTargetNode();
    closeAgentSetupBalloon();
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    return;
  }
  const balance = Number(state.agentCredits?.balance || 0);
  const cost = Number(state.agentCredits?.agent_harness_cost || state.agentCredits?.provision_main_cost || state.agentReadiness?.onboarding_options?.find?.((item) => item.id === "flux_credits")?.cost || 10);
  if (balance < cost) {
    state.agentSetupMessage = "Not enough credits to set an agent yet. Your balance is in the account popover.";
    state.nodesPanelStatus = "";
    renderNodesPanel();
    return;
  }
  void provisionMainWithFlux();
}

async function submitNodeForm(event) {
  event.preventDefault();
  const config = syncNodeFormDraftFromInputs({ inferBaseUrl: true });
  const harnessValidation = validateAgentHarnessConfig(config);
  if (!harnessValidation.ok) {
    setNodeFormStatus(harnessValidation.message, { attention: true });
    renderNodesPanel();
    return;
  }
  const harness = harnessValidation.harness;
  if (harness?.enabled) {
    const editingPersistedHarness = state.nodeFormMode === "edit"
      && cleanText(config.persistedHarnessId || "", "")
      && normalizeAgentHarnessInfraMode(harness.infraMode) === AGENT_HARNESS_DEFAULT_INFRA_MODE;
    if (harness.infraMode === AGENT_HARNESS_DEFAULT_INFRA_MODE) {
      const cost = Number(state.agentCredits?.agent_harness_cost || 10);
      const balance = Number(state.agentCredits?.balance || 0);
      if (!editingPersistedHarness && balance < cost) {
        state.nodesPanelStatus = "";
        setNodeFormStatus(`Required ${cost} Fluxes.`, { attention: true });
        renderNodesPanel();
        return;
      }
    }
    const providerValidation = nodeFormNeedsDirectProvider(config) ? validateDirectProviderConfig(config) : null;
    if (providerValidation && !providerValidation.ok) {
      setNodeFormStatus(providerValidation.message, { attention: true });
      renderNodesPanel();
      return;
    }
    let providerProbe = null;
    if (providerValidation?.ok) {
      state.agentProviderProbeBusy = true;
      setNodeFormStatus("Checking provider models");
      renderNodesPanel();
      const modelListing = await verifyDirectProviderModelListing(providerValidation.config);
      if (!modelListing.ok) {
        setNodeFormStatus(modelListing.message, { attention: true });
        state.agentProviderProbeBusy = false;
        renderAgentReadinessStatus();
        renderNodesPanel();
        return;
      }
      setNodeFormStatus("Checking provider");
      renderNodesPanel();
      providerProbe = await probeAgentProviderConnectivity({ allowProxy: true, force: true, config: providerValidation.config });
      if (!providerProbe.ok) {
        setNodeFormStatus(`${providerProbe.mode} / ${providerProbe.category}: ${providerProbe.message}`, { attention: true });
        state.agentProviderProbeBusy = false;
        renderAgentReadinessStatus();
        renderNodesPanel();
        return;
      }
    }
    if (editingPersistedHarness && providerValidation?.ok) {
      const savedProvider = saveAgentDirectProviderConfig(withDirectProviderVerification(providerValidation.config, providerProbe));
      state.agentDirectProvider = savedProvider || state.agentDirectProvider;
      state.agentTargetNode = cleanText(config.persistedNodeId || "", "") || state.agentTargetNode;
      closeNodeForm();
      state.nodesPanelStatus = "Configuration saved";
      state.agentSetupBalloonOpen = false;
      await loadUserFleet("harness-edit").catch(() => null);
      renderAgentNodeSelect();
      renderAgentModelSelect();
      renderAgentReadinessStatus();
      renderNodesPanel();
      return;
    }
    if (harness.infraMode === AGENT_HARNESS_OWN_INFRA_MODE && ownedAgentBridgeIsPrivateUrl(harness.bridgeUrl)) {
      state.agentProvisionBusy = true;
      state.nodesPanelStatus = "Checking private bridge";
      setNodeFormStatus("Checking private bridge from this browser");
      renderNodesPanel();
      try {
        await probeOwnedAgentBridge(harness.bridgeUrl);
        saveAgentOwnedAgentConfig({
          name: harness.name || config?.nodeName || "My agent",
          role: harness.instructions || "",
          type: "hermes",
          bridgeUrl: harness.bridgeUrl,
        });
        state.agentTargetNode = AGENT_OWNED_AGENT_TARGET_ID;
        closeNodeForm();
        state.agentSetupBalloonOpen = false;
        state.nodesPanelStatus = "Private bridge saved";
        recordUserEvent("agent.owned_bridge_saved_client", {
          target: "owned-agent",
          summary: `Saved ${harness.name || "private Hermes bridge"}`,
          data: { bridge_host: new URL(harness.bridgeUrl).host, browser_local: true },
        });
        renderAgentNodeSelect();
        renderAgentModelSelect();
        renderAgentReadinessStatus();
        renderNodesPanel();
      } catch (error) {
        state.nodesPanelStatus = "";
        setNodeFormStatus(`Private bridge not reachable: ${error.message || String(error)}`, { attention: true });
        renderAgentReadinessStatus();
        renderNodesPanel();
      } finally {
        state.agentProvisionBusy = false;
        renderNodesPanel();
      }
      return;
    }
    state.agentProvisionBusy = true;
    state.nodesPanelStatus = harness.infraMode === AGENT_HARNESS_DEFAULT_INFRA_MODE ? "Provisioning sandbox..." : "Checking own bridge";
    setNodeFormStatus(state.nodesPanelStatus);
    renderNodesPanel();
    try {
      const payload = await fetchJson("/agent/harnesses/provision", {
        method: "POST",
        timeoutMs: 180000,
        body: agentHarnessProvisionPayload(config),
      });
      const provisionedHarness = payload.harness || {};
      if (providerValidation?.ok && providerProbe?.ok) {
        const savedProvider = saveAgentDirectProviderConfig(withDirectProviderVerification(providerValidation.config, providerProbe));
        state.agentDirectProvider = savedProvider || state.agentDirectProvider;
      }
      if (harness.infraMode === AGENT_HARNESS_OWN_INFRA_MODE) {
        saveAgentOwnedAgentConfig({
          name: provisionedHarness.harness_name || harness.name,
          role: harness.instructions || "",
          type: "hermes",
          bridgeUrl: provisionedHarness.bridge_url || harness.bridgeUrl,
        });
        state.agentTargetNode = AGENT_OWNED_AGENT_TARGET_ID;
      } else {
        state.agentTargetNode = defaultAgentTargetNode();
      }
      closeNodeForm();
      state.agentSetupBalloonOpen = false;
      state.nodesPanelStatus = payload.lifecycle_state === "ready" ? "Sandbox ready" : agentReadinessPanelMessage(payload.readiness || { status: payload.lifecycle_state });
      state.agentReadiness = payload.readiness || state.agentReadiness;
      state.agentCredits = payload.credits || state.agentCredits;
      await loadAccountCredits("harness").catch(() => null);
      await loadAgentReadiness("harness").catch(() => null);
      await loadUserFleet("harness").catch(() => null);
      renderAgentNodeSelect();
      renderAgentModelSelect();
      renderAgentReadinessStatus();
    } catch (error) {
      const cost = Number(state.agentCredits?.agent_harness_cost || 10);
      state.nodesPanelStatus = "";
      const formMessage = error.payload?.error?.code === "insufficient_flux_credits"
        ? `Required ${cost} Fluxes.`
        : error.message || "Provisioning failed";
      setNodeFormStatus(formMessage, { attention: true });
      state.agentReadiness = {
        ok: true,
        schema: "hermes.wasm_agent.agent_readiness.v1",
        status: error.payload?.error?.code === "insufficient_flux_credits" ? "insufficient_flux" : "failed",
        ready: false,
        target_node: agentTargetNode(),
        message: formMessage,
        missing_dependency: error.payload?.error?.code || "harness_provision",
        backend: { diagnostics: error.payload || {} },
      };
      renderAgentReadinessStatus();
    } finally {
      state.agentProvisionBusy = false;
      renderNodesPanel();
    }
    return;
  }
  const validation = validateDirectProviderConfig(config);
  if (!validation.ok) {
    setNodeFormStatus(validation.message, { attention: true });
    renderNodesPanel();
    return;
  }
  setNodeFormStatus("Checking provider models");
  renderNodesPanel();
  const modelListing = await verifyDirectProviderModelListing(validation.config);
  if (!modelListing.ok) {
    setNodeFormStatus(modelListing.message, { attention: true });
    state.nodesPanelStatus = "";
    state.agentSetupBalloonOpen = true;
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    renderNodesPanel();
    return;
  }
  setNodeFormStatus("Checking provider");
  renderNodesPanel();
  const probe = await probeAgentProviderConnectivity({ allowProxy: true, force: true, config: validation.config });
  if (!probe.ok) {
    setNodeFormStatus(`${probe.mode} / ${probe.category}: ${probe.message}`, { attention: true });
    state.nodesPanelStatus = "";
    state.agentSetupBalloonOpen = true;
    renderAgentNodeSelect();
    renderAgentModelSelect();
    renderAgentReadinessStatus();
    renderNodesPanel();
    return;
  }
  const savedProvider = saveAgentDirectProviderConfig(withDirectProviderVerification(validation.config, probe));
  state.agentDirectProvider = savedProvider || state.agentDirectProvider;
  state.agentTargetNode = savedProvider ? directProviderTargetValue(savedProvider) : state.agentTargetNode;
  closeNodeForm();
  state.nodesPanelStatus = `${probe.mode} ready`;
  state.agentSetupBalloonOpen = false;
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
  renderNodesPanel();
}

function directProviderChatUrl(config) {
  return directProviderEndpointForBaseUrl(config?.baseUrl || "", config?.provider || "");
}

async function callDirectAgentProvider(message, transcript = [], imageEntries = []) {
  const validation = validateDirectProviderConfig();
  if (!validation.ok) {
    const error = new Error(validation.message);
    error.diagnostic = validation;
    throw error;
  }
  const config = validation.config;
  const probe = await ensureAgentProviderConnection();
  const shouldForwardImages = providerSupportsImageContentParts(config);
  const messages = providerRequestMessages(message, transcript, shouldForwardImages ? imageEntries : []);
  const fallbackMessages = providerMessagesHaveImageContent(messages)
    ? providerRequestMessages(message, transcript, [])
    : null;
  if (probe.mode === AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY) {
    try {
      return await requestBackendProvider(config, messages);
    } catch (error) {
      if (fallbackMessages && providerShouldRetryWithoutImage(error)) {
        const fallback = await requestBackendProvider(config, fallbackMessages);
        return { ...fallback, image_fallback: providerDiagnosticFromError(error) };
      }
      throw error;
    }
  }
  try {
    return await requestBrowserDirectProvider(config, messages);
  } catch (error) {
    const diagnostic = classifyBrowserProviderError(error);
    if (diagnostic.mode === "cors-blocked") {
      rememberProviderProxyOrigin(config);
      let backend;
      try {
        backend = await requestBackendProvider(config, messages);
      } catch (proxyError) {
        if (fallbackMessages && providerShouldRetryWithoutImage(proxyError)) {
          backend = await requestBackendProvider(config, fallbackMessages);
          backend.image_fallback = providerDiagnosticFromError(proxyError);
        } else {
          throw proxyError;
        }
      }
      setAgentProviderProbe({
        ok: true,
        fingerprint: validation.fingerprint,
        mode: AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY,
        category: "ready",
        message: "Browser direct was blocked by CORS; backend proxy provider request succeeded.",
        endpoint: config.endpoint,
        model: config.model,
        direct_error: diagnostic,
        transport_reason: "cors-fallback",
        checked_at: Date.now(),
      });
      return backend;
    }
    if (fallbackMessages && providerShouldRetryWithoutImage(error)) {
      const fallback = await requestBrowserDirectProvider(config, fallbackMessages);
      return { ...fallback, image_fallback: providerDiagnosticFromError(error) };
    }
    error.diagnostic = diagnostic;
    throw error;
  }
}

function masterFrontierEnvelope(message, transcript = [], observation = {}, options = {}) {
  const activeSpace = options.activeSpace || activeSpaceContext();
  const imageCards = Array.isArray(options.imageCards) ? options.imageCards : [];
  const nodeRunConfig = options.nodeRunConfig || {};
  const continuationContext = options.continuationContext && typeof options.continuationContext === "object"
    ? options.continuationContext
    : null;
  const routeContract = options.routeContract && typeof options.routeContract === "object" ? options.routeContract : null;
  const recentTranscript = (Array.isArray(transcript) ? transcript : []).slice(-6).map((turn) => ({
    role: cleanText(turn.role || "", "user"),
    content: truncateText(cleanText(turn.content || "", ""), 320),
  }));
  const attachments = imageCards.slice(0, 8).map((card) => ({
    name: cleanText(card.name || card.label || "", ""),
    type: cleanText(card.type || card.media_kind || "", ""),
    dimensions: cleanText(card.dimensions || "", ""),
    reason: cleanText(card.reason || "", ""),
  }));
  return {
    schema: "hermes.wasm_agent.master_frontier.envelope.v1",
    trace_id: cleanText(options.turnId || "", ""),
    objective: message,
    surface: "avatar-chat",
    route_id: "wasm-agent.avatar-chat.ui",
    route_contract: routeContract || undefined,
    state_summary: [
      `surface:avatar-chat`,
      `route:wasm-agent.avatar-chat.ui`,
      `target:${AGENT_MASTER_FRONTIER_LABEL}`,
      `node:${AGENT_FRONTIER_NODE_ID}`,
      `space:${cleanText(activeSpace?.display_name || activeSpace?.name || "", "home")}`,
      `panel:${cleanText(observation.workspace?.active_panel || state.activePanel, "")}`,
      `transcript_turns:${recentTranscript.length}`,
      `attachments:${attachments.length}`,
    ].join(" "),
    compact_state: {
      surface: "avatar-chat",
      route_id: "wasm-agent.avatar-chat.ui",
      target: AGENT_MASTER_FRONTIER_LABEL,
      target_node: AGENT_FRONTIER_NODE_ID,
      endpoint: "/agent/provider/envelope/stream",
      receiver: "server-configured",
      mode: "direct-head",
      node_config: {
        node_id: AGENT_FRONTIER_NODE_ID,
        name: nodeRunConfig.name || "frontier",
        type: nodeRunConfig.type || "hermes",
        provider: nodeRunConfig.provider || "",
        model: nodeRunConfig.model || "",
      },
      workspace: {
        active_panel: observation.workspace?.active_panel || state.activePanel,
        active_space: {
          id: activeSpaceStorageId(),
          name: activeSpace?.name || "",
          display_name: activeSpace?.display_name || "",
        },
      },
      fleet: {
        bridge_ready: Boolean(observation.fleet?.bridge_ready),
        selected_node: observation.fleet?.selected_node || "",
        chat_target_node: AGENT_FRONTIER_NODE_ID,
      },
      transcript: recentTranscript,
      continuation_context: continuationContext,
      attachments,
      recent_events: Array.isArray(observation.recent_events) ? observation.recent_events.slice(0, 6) : [],
      requested_click_context: observation.requested_click_context || null,
    },
    capabilities: AGENT_MASTER_FRONTIER_CAPS,
    evidence_refs: [
      { ref: "ctx://avatar-chat/current-turn", kind: "chat", summary: "Current message and compact transcript are inline." },
      { ref: "ctx://workspace/compact-state", kind: "state", summary: "Compact workspace, fleet, and recent event state are inline." },
      { ref: "ctx://direct-head/receiver", kind: "receiver", summary: "Envelope is sent to the server-configured direct-head receiver." },
      ...(continuationContext ? [{ ref: "ctx://avatar-chat/continuation", kind: "resume", summary: "Compact previous-run continuation context is inline." }] : []),
    ],
    allowed_actions: [
      { id: "answer", type: "direct", description: "Answer directly from the envelope when no tool work is required." },
      { id: "dispatch.hermes", type: "bridge", caps: AGENT_MASTER_FRONTIER_CAPS, description: "Dispatch bounded tool/proof work through the wasm-agent Hermes bridge." },
    ],
    constraints: [
      "Do not assume hidden state beyond this envelope.",
      "When continuation_context is present and the user asks to continue or resume, continue that objective instead of asking the user to restate it.",
      "Answer directly when possible; use dispatch.hermes only when tool, file, runtime, or proof work is required.",
      "Keep the answer compact and include proof handles when work is dispatched.",
      "Do not report token usage in the answer text; the UI renders exact provider token usage from diagnostics.",
      "Do not claim inspected, confirmed, verified, or viable unless the claim is supported by envelope evidence or dispatched proof; otherwise say not inspected yet.",
    ],
    proof_requests: [
      "route-used:/agent/provider/envelope/stream",
      "receiver:server-configured",
      "target-label:Master:frontier",
      "target-node:frontier",
    ],
    budget: {
      max_output_tokens: 900,
      max_dispatch_caps: AGENT_MASTER_FRONTIER_CAPS.length,
    },
    stream: true,
    output_schema: {
      type: "object",
      required: ["answer", "decision", "actions", "state_delta", "needs", "confidence"],
      properties: {
        answer: { type: "string" },
        decision: { type: "string" },
        actions: { type: "array", items: { type: "object" } },
        state_delta: { type: "object" },
        needs: { type: "array", items: { type: "string" } },
        proof_requests: { type: "array", items: { type: "string" } },
        confidence: { type: "number" },
      },
      additionalProperties: true,
    },
  };
}

async function callMasterFrontierDirectHead(message, transcript = [], observation = {}, options = {}) {
  const envelope = masterFrontierEnvelope(message, transcript, observation, options);
  const body = {
    session_id: activeAgentSession().id,
    turn_id: cleanText(options.turnId || "", ""),
    space_id: activeSpaceStorageId(),
    envelope,
    instructions: [
      `You are the ${AGENT_MASTER_FRONTIER_LABEL} direct head for avatar-chat.`,
      "Receive this wasm-agent envelope through the server-configured direct-head receiver.",
      "Answer from the envelope protocol; return dispatch.hermes only when the envelope requires bounded bridge tool/proof work.",
      "Do not narrate token usage; runtime diagnostics render exact provider-reported LLM usage outside the answer.",
      "Be proof-honest: distinguish conceptual possibility from inspected or verified runtime proof.",
    ].join(" "),
    max_output_tokens: 900,
    text_verbosity: "low",
  };
  let response = null;
  if ("ReadableStream" in window && "TextDecoder" in window && options.pendingMessage) {
    const fetchResponse = await fetch("/agent/provider/envelope/stream", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Wasm-Agent-Device-Id": clientDeviceId(),
      },
      body: JSON.stringify(body),
      signal: options.signal,
    });
    if (!fetchResponse.ok || !fetchResponse.body) throw new Error(`HTTP ${fetchResponse.status}`);
    const reader = fetchResponse.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    let finalAgent = null;
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split("\n");
      buffer = lines.pop() || "";
      for (const line of lines) {
        const payload = handleAgentStreamLine(line, options.pendingMessage);
        if (payload?.type === "final") finalAgent = payload.agent;
      }
    }
    if (buffer.trim()) {
      const payload = handleAgentStreamLine(buffer, options.pendingMessage);
      if (payload?.type === "final") finalAgent = payload.agent;
    }
    if (!finalAgent) throw new Error("The direct-head stream ended without a final response.");
    response = { ok: true, provider: finalAgent.provider || {}, ...finalAgent };
  } else {
    response = await fetchJson("/agent/provider/envelope", {
      method: "POST",
      body,
      timeoutMs: state.agentTurnTimeoutMs + 5000,
      signal: options.signal,
    });
  }
  const providerPayload = response?.provider && typeof response.provider === "object" ? response.provider : {};
  return {
    ...providerPayload,
    ...response,
    provider_result: providerPayload,
    provider: providerPayload.provider || (typeof response?.provider === "string" ? response.provider : ""),
    base_url: providerPayload.base_url || response?.base_url || "",
    model: response?.model || providerPayload.model || "",
    usage: response?.usage || providerPayload.usage || null,
    token_ledger: response?.token_ledger || providerPayload.token_ledger || response?.ledger || null,
    route_id: response?.route_id || providerPayload.route_id || "",
    route_contract: response?.route_contract || providerPayload.route_contract || null,
    run_id: response?.run_id || providerPayload.run_id || "",
    turn_id: response?.turn_id || providerPayload.turn_id || "",
    hermes_dispatch: response?.hermes_dispatch || providerPayload.hermes_dispatch || null,
    context_measurement: response?.context_measurement || providerPayload.context_measurement || null,
    actions: Array.isArray(response?.actions) ? response.actions : Array.isArray(providerPayload.actions) ? providerPayload.actions : [],
  };
}

function masterFrontierReplyFromPayload(payload = {}) {
  const parsed = payload?.parsed && typeof payload.parsed === "object" ? payload.parsed : {};
  const dispatchReply = payload?.hermes_dispatch && typeof payload.hermes_dispatch === "object"
    ? payload.hermes_dispatch.reply
    : "";
  return cleanText(
    humanAgentReplyFromStructuredJson(dispatchReply)
      || dispatchReply
      || parsed.answer
      || parsed.decision
      || payload?.reply
      || "",
    ""
  );
}

function humanAgentReplyFromStructuredJson(reply = "") {
  const text = cleanText(reply, "");
  if (!text || text[0] !== "{") return "";
  let parsed = null;
  try {
    parsed = JSON.parse(text);
  } catch {
    return "";
  }
  if (!parsed || typeof parsed !== "object") return "";
  const answer = cleanText(parsed.answer || parsed.message || parsed.summary || "", "");
  if (answer) return answer;
  const status = cleanText(parsed.status || "", "");
  const objective = cleanText(parsed.objective || parsed.title || "", "");
  const changedFiles = Array.isArray(parsed.changed_files) ? parsed.changed_files.map((item) => cleanText(item, "")).filter(Boolean) : [];
  const edits = Array.isArray(parsed.edits) ? parsed.edits : [];
  if (!objective && !changedFiles.length && !edits.length) return "";
  const parts = [];
  parts.push(status === "done" ? "Done." : status ? `${status}.` : "Hermes finished.");
  if (objective) parts.push(objective.endsWith(".") ? objective : `${objective}.`);
  if (changedFiles.length) parts.push(`Changed ${changedFiles.map((path) => path.split("/").pop() || path).join(", ")}.`);
  if (edits.length) parts.push(`${edits.length} edit${edits.length === 1 ? "" : "s"} recorded.`);
  return parts.join(" ");
}

function ownedAgentPrompt(message, transcript = [], observation = {}) {
  const config = state.agentOwnedAgent || {};
  const lines = [
    config.role ? `Instructions:\n${config.role}` : "",
    wisPatchClientSystemHint(),
    "User message:",
    message,
  ];
  const recent = Array.isArray(transcript) ? transcript.slice(-8) : [];
  if (recent.length) {
    lines.push(
      "",
      "Recent transcript:",
      ...recent.map((turn) => `${cleanText(turn.role || "user", "user")}: ${cleanText(turn.content || "", "")}`)
    );
  }
  if (observation?.workspace) {
    lines.push("", `Workspace: ${compactJsonForPrompt(observation.workspace, 1200)}`);
  }
  if (observation?.cap) {
    lines.push("", agentCapabilitySystemHint(observation.cap).trim());
  }
  return lines.filter((line) => line !== "").join("\n");
}

function compactJsonForPrompt(value, max = 1200) {
  try {
    return truncateText(JSON.stringify(value), max);
  } catch {
    return "";
  }
}

function ownedAgentBridgeTimeoutMs() {
  return Math.min(Number(state.agentTurnTimeoutMs || DEFAULT_AGENT_TURN_TIMEOUT_MS), 120000);
}

function ownedAgentBridgeTimeoutSec() {
  return Math.max(60, Math.round(ownedAgentBridgeTimeoutMs() / 1000));
}

function ownedAgentReplyFromPayload(payload = {}) {
  if (typeof payload === "string") return cleanText(payload, "");
  if (!payload || typeof payload !== "object") return "";
  const result = payload.result && typeof payload.result === "object" ? payload.result : {};
  const output = payload.output && typeof payload.output === "object" ? payload.output : {};
  const candidates = [
    result.response,
    result.reply,
    result.message,
    result.text,
    result.content,
    result.output,
    result.final_response,
    payload.response,
    payload.reply,
    payload.message,
    payload.text,
    payload.content,
    payload.output,
    payload.final_response,
    output.text,
    output.content,
  ];
  for (const candidate of candidates) {
    if (typeof candidate === "string" && candidate.trim()) return candidate.trim();
    if (candidate && typeof candidate === "object") {
      const nested = ownedAgentReplyFromPayload(candidate);
      if (nested) return nested;
    }
  }
  const choices = Array.isArray(payload.choices)
    ? payload.choices
    : Array.isArray(result.choices) ? result.choices : [];
  for (const choice of choices) {
    const message = choice?.message && typeof choice.message === "object" ? choice.message : {};
    const content = message.content ?? choice?.text ?? choice?.delta?.content;
    if (typeof content === "string" && content.trim()) return content.trim();
    if (Array.isArray(content)) {
      const joined = content.map((part) => {
        if (typeof part === "string") return part;
        if (part?.type === "text") return part.text || "";
        return "";
      }).join("").trim();
      if (joined) return joined;
    }
  }
  return "";
}

function ownedAgentReplyFromTask(task = {}) {
  return ownedAgentReplyFromPayload(task);
}

function ownedAgentTaskStatus(task = {}) {
  return cleanText(task.status || task.state || task.run_status || "", "").toLowerCase();
}

function ownedAgentTaskId(task = {}) {
  return cleanText(task.task_id || task.taskId || task.id || "", "");
}

function ownedAgentRunId(payload = {}) {
  return cleanText(payload.run_id || payload.runId || payload.id || payload.result?.run_id || "", "");
}

function ownedAgentTaskActive(task = {}) {
  return ["running", "queued", "pending", "submitted", "active", "in_progress", "started", "working"].includes(ownedAgentTaskStatus(task));
}

function ownedAgentBridgePromptBody(prompt) {
  return {
    prompt,
    input: prompt,
    target_node: "orchestrator",
    timeout_sec: ownedAgentBridgeTimeoutSec(),
    stream: false,
    messages: [{ role: "user", content: prompt }],
  };
}

async function pollOwnedAgentTask(baseUrl, initialTask = {}) {
  let task = initialTask.task || initialTask;
  const taskId = ownedAgentTaskId(task);
  const started = Date.now();
  const timeoutMs = ownedAgentBridgeTimeoutMs();
  while (taskId && ownedAgentTaskActive(task)) {
    if (Date.now() - started > timeoutMs) throw new Error("Owned agent bridge timed out.");
    await new Promise((resolve) => window.setTimeout(resolve, 1200));
    const latest = await fetchExternalJson(`${baseUrl}/tasks/${encodeURIComponent(taskId)}`, { timeoutMs: 10000 });
    task = latest.task || latest;
  }
  if (task?.error) throw new Error(task.error.message || task.error || "Owned agent bridge returned an error.");
  const reply = ownedAgentReplyFromTask(task);
  if (!reply) throw new Error("Owned agent bridge did not return a reply.");
  return { reply, task };
}

async function callOwnedAgentTasksBridge(baseUrl, prompt) {
  const payload = await fetchExternalJson(`${baseUrl}/tasks`, {
    method: "POST",
    timeoutMs: ownedAgentBridgeTimeoutMs(),
    body: ownedAgentBridgePromptBody(prompt),
  });
  return pollOwnedAgentTask(baseUrl, payload.task || payload);
}

async function callOwnedAgentChatBridge(baseUrl, prompt) {
  const payload = await fetchExternalJson(`${baseUrl}/bridge/v1/chat`, {
    method: "POST",
    timeoutMs: ownedAgentBridgeTimeoutMs(),
    body: ownedAgentBridgePromptBody(prompt),
  });
  const task = payload.task || payload;
  if (ownedAgentTaskId(task) && ownedAgentTaskActive(task)) return pollOwnedAgentTask(baseUrl, task);
  const reply = ownedAgentReplyFromPayload(payload);
  if (!reply) throw new Error("Owned agent bridge chat route did not return a reply.");
  return { reply, task: payload };
}

async function callOwnedAgentChatCompletions(baseUrl, prompt) {
  const payload = await fetchExternalJson(`${baseUrl}/v1/chat/completions`, {
    method: "POST",
    timeoutMs: ownedAgentBridgeTimeoutMs(),
    body: {
      model: state.agentOwnedAgent?.type || "hermes-agent",
      stream: false,
      messages: [{ role: "user", content: prompt }],
      timeout_sec: ownedAgentBridgeTimeoutSec(),
    },
  });
  const reply = ownedAgentReplyFromPayload(payload);
  if (!reply) throw new Error("Owned agent chat completions route did not return a reply.");
  return { reply, task: payload };
}

async function callOwnedAgentRunsApi(baseUrl, prompt) {
  const created = await fetchExternalJson(`${baseUrl}/v1/runs`, {
    method: "POST",
    timeoutMs: ownedAgentBridgeTimeoutMs(),
    body: {
      input: prompt,
      session_id: `wasm-agent-owned-${Date.now().toString(36)}`,
      timeout_sec: ownedAgentBridgeTimeoutSec(),
    },
  });
  const runId = ownedAgentRunId(created);
  if (!runId) throw new Error("Owned Hermes Runs API did not return a run id.");
  let status = created;
  const started = Date.now();
  const timeoutMs = ownedAgentBridgeTimeoutMs();
  while (["", "queued", "pending", "submitted", "running", "active", "in_progress", "started", "working"].includes(ownedAgentTaskStatus(status))) {
    if (Date.now() - started > timeoutMs) throw new Error("Owned Hermes Runs API timed out.");
    await new Promise((resolve) => window.setTimeout(resolve, 1200));
    status = await fetchExternalJson(`${baseUrl}/v1/runs/${encodeURIComponent(runId)}`, { timeoutMs: 10000 });
  }
  if (["failed", "cancelled", "canceled", "error"].includes(ownedAgentTaskStatus(status))) {
    throw new Error(status.error?.message || status.message || `Owned Hermes run ${ownedAgentTaskStatus(status)}.`);
  }
  const reply = ownedAgentReplyFromPayload(status);
  if (!reply) throw new Error("Owned Hermes Runs API did not return a reply.");
  return { reply, task: status };
}

async function probeOwnedAgentBridge(baseUrl) {
  const health = await fetchExternalJson(`${baseUrl}/health`, { timeoutMs: 8000 });
  let models = null;
  let lastError = null;
  for (const path of ["/bridge/v1/models", "/v1/models"]) {
    try {
      models = await fetchExternalJson(`${baseUrl}${path}`, { timeoutMs: 8000 });
      break;
    } catch (error) {
      lastError = error;
    }
  }
  if (!models) throw lastError || new Error("Owned agent bridge model route is unavailable.");
  return { health, models };
}

async function callOwnedAgentBridge(message, transcript = [], observation = {}) {
  const baseUrl = ownedAgentBridgeUrl();
  if (!baseUrl) throw new Error("Missing owned agent bridge URL.");
  const prompt = ownedAgentPrompt(message, transcript, observation);
  const callers = [
    ["bridge chat", () => callOwnedAgentChatBridge(baseUrl, prompt)],
    ["tasks", () => callOwnedAgentTasksBridge(baseUrl, prompt)],
    ["Hermes Runs API", () => callOwnedAgentRunsApi(baseUrl, prompt)],
    ["chat completions", () => callOwnedAgentChatCompletions(baseUrl, prompt)],
  ];
  const errors = [];
  for (const [label, caller] of callers) {
    try {
      return await caller();
    } catch (error) {
      errors.push(`${label}: ${error.message || String(error)}`);
    }
  }
  throw new Error(`Owned agent bridge did not answer. ${errors.join("; ")}`);
}

async function provisionMainWithFlux(agentConfig = {}) {
  if (state.agentProvisionBusy) return;
  state.agentProvisionBusy = true;
  state.nodesPanelStatus = "Provisioning sandbox...";
  renderNodesPanel();
  try {
    const payload = await fetchJson("/fleet/nodes/provision-main", {
      method: "POST",
      timeoutMs: 180000,
      body: {
        idempotency_key: `provision_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`,
        ...agentConfig,
      },
    });
    state.nodesPanelStatus = payload.already_provisioned ? "Sandbox ready" : "Sandbox ready";
    state.agentSetupBalloonOpen = false;
    state.agentSetupMessage = "";
    state.agentTargetNode = defaultAgentTargetNode();
    await loadAccountCredits("provision");
    await loadAgentReadiness("provision");
    await loadUserFleet("provision").catch(() => {});
    renderAgentNodeSelect();
  } catch (error) {
    state.nodesPanelStatus = error.message;
    recordUserEvent("account.fleet_provision_error", {
      target: "fleet",
      summary: error.message,
      data: { error: error.message },
    });
  } finally {
    state.agentProvisionBusy = false;
    renderNodesPanel();
  }
}

async function agentChatSetupBlock(session = activeAgentSession()) {
  const socialChat = session.kind === "direct" || session.kind === "shared-space";
  if (!state.authUser || isAdminUser() || socialChat) return null;
  if (agentTargetIsNone()) {
    return {
      mode: "provider",
      openProviderForm: true,
      message: "Set one node before sending chat messages.",
    };
  }
  if (agentTargetIsDirectProvider()) {
    const validation = validateDirectProviderConfig();
    if (validation.ok) return null;
    return {
      mode: "provider",
      openProviderForm: true,
      message: "Set one node before sending chat messages.",
    };
  }
  if (agentTargetIsOwnedAgent() && state.agentOwnedAgent?.bridgeUrl) return null;
  const readiness = await ensureAgentReadiness("send-preflight").catch((error) => ({
    status: "backend_unavailable",
    ready: false,
    message: error.message,
  }));
  if (readiness?.ready || readiness?.status === "ready") return null;
  if (hasDirectProviderConfigured()) {
    return {
      mode: "agent",
      message: "Pick your saved node before sending chat messages.",
    };
  }
  return {
    mode: "provider",
    openProviderForm: true,
    message: "Set one node before sending chat messages.",
  };
}

async function warnAgentChatNeedsSetup(session = activeAgentSession()) {
  const block = await agentChatSetupBlock(session);
  if (!block) return false;
  openAgentSetupBalloon(block);
  recordUserEvent("agent.message_blocked_setup_required", {
    target: "agent-setup",
    summary: "Message blocked until a node is set",
    data: {
      mode: block.mode || "",
      target_node: agentTargetNode(),
      provider_configured: hasDirectProviderConfigured(),
      readiness_status: state.agentReadiness?.status || "",
    },
  });
  return true;
}

function renderAgentChrome() {
  const session = activeAgentSession();
  const peopleOpen = state.agentView === "people";
  const direct = !peopleOpen && session.kind === "direct";
  const sharedChat = !peopleOpen && session.kind === "shared-space";
  const socialChat = direct || sharedChat;
  const peerLabel = socialUserLabel(session.peer, "DM");
  if (els.agentPanelTitle) els.agentPanelTitle.textContent = peopleOpen ? "People" : direct ? peerLabel : sharedChat ? session.title || "Space chat" : "Chat";
  if (els.agentPeoplePanel) els.agentPeoplePanel.hidden = !peopleOpen;
  if (els.agentMessages) els.agentMessages.hidden = peopleOpen;
  if (els.agentForm) els.agentForm.hidden = peopleOpen;
  if (els.agentMainChatButton) els.agentMainChatButton.hidden = !socialChat;
  els.agentPeopleButton?.setAttribute("aria-pressed", peopleOpen ? "true" : "false");
  const nodePicker = els.agentNodeSelect?.closest?.(".agent-node-picker");
  if (nodePicker) nodePicker.hidden = peopleOpen || socialChat;
  if (els.agentModelSelect) els.agentModelSelect.hidden = true;
  if (els.agentTokenUsage) els.agentTokenUsage.hidden = socialChat;
  if (els.agentDirectTools) els.agentDirectTools.hidden = !direct;
  if (els.agentForm) els.agentForm.dataset.chatKind = direct ? "direct" : sharedChat ? "shared-space" : "agent";
  if (els.agentInput) {
    els.agentInput.placeholder = direct ? `Message ${peerLabel}` : sharedChat ? "Message this space" : "Talk to agent";
    els.agentInput.setAttribute("aria-label", direct ? `Message ${peerLabel}` : sharedChat ? "Message this space" : "Message agent");
  }
  if (!direct) setAgentSocialPicker("");
  updatePeopleButtonState();
  updateAgentSendButton();
  renderAgentReadinessStatus();
  renderAgentPeoplePanel();
  updateAgentScrollBottomButton();
}

function setAgentView(view, options = {}) {
  const nextView = view === "people" ? "people" : "chat";
  if (state.agentView === "people" && nextView === "chat" && !options.keepActiveSession) {
    switchToMainAgentChat();
    return;
  }
  state.agentView = nextView;
  renderAgentChrome();
  if (state.agentView === "people") {
    setAgentOpen(true);
    clearSocialToasts("friend");
    void loadAgentPeople("toggle").catch(() => {});
  } else {
    queueAgentScrollToBottom();
    window.setTimeout(() => els.agentInput?.focus(), 0);
  }
  saveActiveAgentSessionPreference();
}

function friendshipUser(friendship) {
  return friendship?.other_user || friendship?.addressee || friendship?.requester || null;
}

function activeSharedSpaceMembers() {
  const room = activeSharedRoom();
  const entries = [
    ...(Array.isArray(room?.members) ? room.members : []),
    ...(Array.isArray(room?.presence) ? room.presence : []),
  ];
  const seen = new Set();
  return entries.map((entry) => {
    const id = socialUserId(entry);
    if (!id || seen.has(id)) return null;
    seen.add(id);
    return {
      id,
      user_id: id,
      label: socialUserLabel(entry, "Member"),
      source: "shared-space",
      current: id === cleanText(room?.current_user_id || state.authUser?.id, ""),
    };
  }).filter(Boolean);
}

function friendshipByUserId(userId) {
  const target = cleanText(userId, "");
  return (state.agentPeople.friendships || []).find((friendship) => socialUserId(friendshipUser(friendship)) === target) || null;
}

function peopleSection(titleText, rows, emptyText = "") {
  const section = document.createElement("section");
  section.className = "agent-people-section";
  const title = document.createElement("h3");
  title.textContent = titleText;
  section.append(title);
  if (rows.length) {
    const list = document.createElement("div");
    list.className = "agent-people-section-list";
    list.replaceChildren(...rows);
    section.append(list);
  } else if (emptyText) {
    const empty = document.createElement("p");
    empty.className = "agent-people-empty";
    empty.textContent = emptyText;
    section.append(empty);
  }
  return section;
}

function conversationUnreadCount(userId) {
  const conversationId = directConversationId(userId);
  return Math.max(0, Number(state.agentPeople.unreadByConversation?.[conversationId] || 0));
}

function sharedSpaceUnreadCount(sharedSpaceId) {
  const conversationId = sharedSpaceConversationId(sharedSpaceId);
  return Math.max(0, Number(state.agentPeople.unreadByConversation?.[conversationId] || 0));
}

function openCreditGrantModal(user) {
  if (!isAdminUser() || !user || socialUserId(user) === cleanText(state.authUser?.id, "")) return;
  state.creditGrantTargetUser = user;
  if (els.creditGrantTarget) els.creditGrantTarget.textContent = `${socialUserLabel(user, "User")} / ${socialUserId(user)}`;
  if (els.creditGrantAmountInput) els.creditGrantAmountInput.value = "100";
  if (els.creditGrantReasonInput) els.creditGrantReasonInput.value = "";
  if (els.creditGrantStatus) els.creditGrantStatus.textContent = "";
  if (els.creditGrantModal) els.creditGrantModal.hidden = false;
  window.setTimeout(() => els.creditGrantAmountInput?.focus(), 0);
  pushUiNavigationLayer("credit-grant-modal", () => closeCreditGrantModal({ skipHistory: true, skipStack: true }));
}

function closeCreditGrantModal(options = {}) {
  if (!options.skipHistory && closeUiNavigationLayer("credit-grant-modal")) return;
  if (els.creditGrantModal) els.creditGrantModal.hidden = true;
  state.creditGrantTargetUser = null;
  state.creditGrantBusy = false;
  if (!options.skipStack) closeUiNavigationLayer("credit-grant-modal", { skipHistory: true, replaceHistory: true });
}

async function submitCreditGrant(event) {
  event.preventDefault();
  if (state.creditGrantBusy || !state.creditGrantTargetUser) return;
  const targetId = socialUserId(state.creditGrantTargetUser);
  const amount = Number(els.creditGrantAmountInput?.value || 0);
  const reason = cleanText(els.creditGrantReasonInput?.value || "", "");
  state.creditGrantBusy = true;
  if (els.creditGrantStatus) els.creditGrantStatus.textContent = "Adding";
  try {
    await fetchJson(`/admin/users/${encodeURIComponent(targetId)}/credits/grant`, {
      method: "POST",
      timeoutMs: 8000,
      body: {
        amount,
        reason,
        idempotency_key: `grant_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`,
      },
    });
    if (els.creditGrantStatus) els.creditGrantStatus.textContent = "Added";
    recordUserEvent("account.credits_granted", {
      target: `user:${targetId}`,
      summary: `Granted ${amount} Flux credits`,
      data: { user_id: targetId, amount },
    });
    window.setTimeout(() => closeCreditGrantModal(), 250);
  } catch (error) {
    if (els.creditGrantStatus) els.creditGrantStatus.textContent = error.message;
  } finally {
    state.creditGrantBusy = false;
  }
}

function remoteControlId(prefix = "rc") {
  return `${prefix}_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 10)}`;
}

function remoteControlToken() {
  const bytes = new Uint8Array(16);
  if (window.crypto?.getRandomValues) {
    window.crypto.getRandomValues(bytes);
    return Array.from(bytes, (byte) => byte.toString(16).padStart(2, "0")).join("");
  }
  return `${Date.now().toString(36)}${Math.random().toString(36).slice(2, 18)}`;
}

function remoteControlNow() {
  return Date.now();
}

function remoteControlExpired(record = {}) {
  return Number(record.expires_at || record.expiresAt || 0) <= remoteControlNow();
}

function remoteControlEventMs(event = {}) {
  const created = Number(event.created_at || event.createdAt || 0);
  if (!Number.isFinite(created) || created <= 0) return remoteControlNow();
  return created < 1_000_000_000_000 ? created * 1000 : created;
}

function pruneRemoteControlRequestResponses() {
  const now = remoteControlNow();
  const entries = Object.entries(state.remoteControl.requestResponses || {})
    .filter(([, response]) => Number(response?.expires_at || response?.expiresAt || 0) > now)
    .slice(-REMOTE_CONTROL_ACTION_LOG_LIMIT);
  state.remoteControl.requestResponses = Object.fromEntries(entries);
}

function remoteControlRequestResponse(requestId = "") {
  const id = cleanText(requestId, "");
  if (!id) return null;
  pruneRemoteControlRequestResponses();
  return state.remoteControl.requestResponses?.[id] || null;
}

function rememberRemoteControlRequestResponse(requestId = "", response = {}) {
  const id = cleanText(requestId, "");
  if (!id) return null;
  pruneRemoteControlRequestResponses();
  const expiresAt = Number(response.expires_at || response.expiresAt || 0)
    || remoteControlNow() + REMOTE_CONTROL_REQUEST_TTL_MS;
  const stored = {
    ...response,
    request_id: id,
    expires_at: expiresAt,
    remembered_at: remoteControlNow(),
  };
  state.remoteControl.requestResponses[id] = stored;
  return stored;
}

function readRemoteControlAdminCoControlSession() {
  try {
    const raw = window.sessionStorage?.getItem(REMOTE_CONTROL_ADMIN_SESSION_STORAGE_KEY) || "";
    const session = raw ? JSON.parse(raw) : null;
    if (!session || typeof session !== "object" || remoteControlExpired(session)) {
      window.sessionStorage?.removeItem(REMOTE_CONTROL_ADMIN_SESSION_STORAGE_KEY);
      return null;
    }
    return {
      controller_user_id: cleanText(session.controller_user_id || session.controllerUserId, ""),
      controller_device_id: cleanText(session.controller_device_id || session.controllerDeviceId, ""),
      controller_label: cleanText(session.controller_label || session.controllerLabel, "Admin"),
      expires_at: Number(session.expires_at || session.expiresAt || 0),
    };
  } catch {
    return null;
  }
}

function saveRemoteControlAdminCoControlSession(session = null) {
  state.remoteControl.adminCoControlSession = session;
  try {
    if (session) window.sessionStorage?.setItem(REMOTE_CONTROL_ADMIN_SESSION_STORAGE_KEY, JSON.stringify(session));
    else window.sessionStorage?.removeItem(REMOTE_CONTROL_ADMIN_SESSION_STORAGE_KEY);
  } catch {
    // Browser storage can be disabled; in-memory session state still works.
  }
}

function remoteControlAdminCoControlSessionActive(userId = "", deviceId = "") {
  const session = state.remoteControl.adminCoControlSession || readRemoteControlAdminCoControlSession();
  if (!session || remoteControlExpired(session)) {
    saveRemoteControlAdminCoControlSession(null);
    return false;
  }
  const controllerDeviceId = cleanText(session.controller_device_id || session.controllerDeviceId, "");
  const requestedDeviceId = cleanText(deviceId, "");
  return cleanText(session.controller_user_id, "") === cleanText(userId, "")
    && (!requestedDeviceId || !controllerDeviceId || controllerDeviceId === requestedDeviceId);
}

function remoteControlUserById(userId = "") {
  const id = cleanText(userId, "");
  if (!id) return null;
  const friendship = friendshipByUserId(id);
  return friendship ? friendshipUser(friendship) : activeSharedSpaceMembers().find((member) => member.id === id) || null;
}

function remoteControlUserLabel(userId = "", fallback = "Someone") {
  const user = remoteControlUserById(userId);
  if (user) return socialUserLabel(user, fallback);
  return userId === cleanText(state.authUser?.id, "") ? publicUserLabel(state.authUser) : cleanText(userId, fallback);
}

function remoteControlConversationIdForUser(userId = "") {
  const id = cleanText(userId, "");
  return id ? directConversationId(id) : "";
}

function remoteControlCurrentDeviceId() {
  return cleanText(state.deviceAuthority?.current_device_id || "", "");
}

function remoteControlDeviceConversationId(deviceId = "") {
  const userId = cleanText(state.authUser?.id, "");
  const targetDeviceId = cleanText(deviceId, "");
  return userId && targetDeviceId ? `rc-device-${userId}-${targetDeviceId}` : "";
}

function remoteControlKind(kind = "") {
  return cleanText(kind, "");
}

function remoteControlIsKind(kind = "") {
  return [
    "remote-control-request",
    "remote-control-response",
    "remote-control-action",
    REMOTE_CONTROL_VIEWPORT_FRAME_KIND,
    "remote-control-stop",
  ].includes(remoteControlKind(kind));
}

function remoteControlRecordAction(direction, detail = "") {
  const entry = {
    direction,
    detail: truncateText(detail, 120),
    at: new Date().toISOString(),
  };
  state.remoteControl.actionLog.push(entry);
  state.remoteControl.actionLog = state.remoteControl.actionLog.slice(-REMOTE_CONTROL_ACTION_LOG_LIMIT);
  renderRemoteControlChrome();
  recordUserEvent("remote_control.action", {
    target: "remote-control",
    summary: `${direction}: ${entry.detail}`,
    data: { direction, detail: entry.detail },
  });
}

function remoteControlHasLiveTraffic() {
  const hasActiveGrant = state.remoteControl.activeGrant && !remoteControlExpired(state.remoteControl.activeGrant);
  const hasActiveController = state.remoteControl.activeController && !remoteControlExpired(state.remoteControl.activeController);
  const hasIncoming = Object.values(state.remoteControl.incomingRequests || {}).some((request) => !remoteControlExpired(request));
  const hasOutgoing = Object.values(state.remoteControl.outgoingRequests || {}).some((request) => !remoteControlExpired(request));
  return Boolean(hasActiveGrant || hasActiveController || hasIncoming || hasOutgoing);
}

function stopRemoteControlFastSyncIfIdle() {
  if (remoteControlHasLiveTraffic()) return;
  if (state.remoteControl.syncTimer) {
    window.clearInterval(state.remoteControl.syncTimer);
    state.remoteControl.syncTimer = 0;
  }
}

function remoteControlLiveUrl() {
  return appWebSocketUrl("/remote-control/live").toString();
}

function remoteControlEventIdNewer(id = "", cursor = "") {
  const next = cleanText(id, "");
  const current = cleanText(cursor, "");
  if (!next) return false;
  if (!current) return true;
  try {
    return BigInt(next) > BigInt(current);
  } catch {
    return next > current;
  }
}

function advanceRemoteControlSyncCursor(id = "") {
  if (remoteControlEventIdNewer(id, state.remoteControl.syncCursor)) {
    state.remoteControl.syncCursor = cleanText(id, state.remoteControl.syncCursor);
  }
}

function remoteControlLiveConnected() {
  if (!("WebSocket" in window)) return false;
  return Boolean(state.remoteControl.liveSocket?.readyState === WebSocket.OPEN && state.remoteControl.liveSocketReady);
}

function remoteControlLiveShouldConnect() {
  return Boolean(state.authUser && ("WebSocket" in window));
}

function rejectRemoteControlLivePending(error) {
  const pending = state.remoteControl.livePending || {};
  state.remoteControl.livePending = {};
  Object.values(pending).forEach((entry) => {
    window.clearTimeout(entry.timeout);
    entry.reject(error);
  });
}

function closeRemoteControlLiveSocket(options = {}) {
  if (state.remoteControl.liveReconnectTimer) {
    window.clearTimeout(state.remoteControl.liveReconnectTimer);
    state.remoteControl.liveReconnectTimer = 0;
  }
  const socket = state.remoteControl.liveSocket;
  state.remoteControl.liveSocket = null;
  state.remoteControl.liveSocketReady = false;
  state.remoteControl.liveSocketToken += 1;
  rejectRemoteControlLivePending(new Error("Remote control live channel closed."));
  if (socket && socket.readyState !== WebSocket.CLOSED) {
    try {
      socket.close();
    } catch {
      // Socket may already be closing.
    }
  }
  if (options.reconnect && remoteControlLiveShouldConnect()) scheduleRemoteControlLiveReconnect("close");
}

function scheduleRemoteControlLiveReconnect(origin = "reconnect") {
  if (!remoteControlLiveShouldConnect()) return;
  if (state.remoteControl.liveReconnectTimer) return;
  state.remoteControl.liveReconnectTimer = window.setTimeout(() => {
    state.remoteControl.liveReconnectTimer = 0;
    startRemoteControlLiveSocket(origin);
  }, 900);
}

function handleRemoteControlLiveMessage(message = {}) {
  const type = cleanText(message.type, "");
  if (type === "ready") {
    state.remoteControl.liveSocketReady = true;
    return;
  }
  if (type === "ping") {
    try {
      state.remoteControl.liveSocket?.send(JSON.stringify({ type: "pong", ts: message.ts || Date.now() }));
    } catch {
      // The close handler will reconnect if the live session is still needed.
    }
    return;
  }
  if (type === "event") {
    const event = message.event && typeof message.event === "object" ? message.event : {};
    if (!remoteControlIsKind(event.kind)) return;
    if (!event.ephemeral) advanceRemoteControlSyncCursor(event.id);
    handleRemoteControlSyncEvent(event);
    return;
  }
  if (type !== "ack") return;
  const requestId = cleanText(message.request_id || message.requestId, "");
  const pending = requestId ? state.remoteControl.livePending?.[requestId] : null;
  if (!pending) return;
  window.clearTimeout(pending.timeout);
  delete state.remoteControl.livePending[requestId];
  if (message.ok) {
    const event = message.event && typeof message.event === "object" ? message.event : {};
    advanceRemoteControlSyncCursor(event.id);
    pending.resolve({ ok: true, event });
    return;
  }
  const error = new Error(cleanText(message.error?.message, "Remote control live channel failed."));
  error.code = cleanText(message.error?.code, "remote_control_live_error");
  error.payload = message;
  pending.reject(error);
}

function startRemoteControlLiveSocket(origin = "active") {
  if (!remoteControlLiveShouldConnect()) return null;
  const existing = state.remoteControl.liveSocket;
  if (existing && [WebSocket.CONNECTING, WebSocket.OPEN].includes(existing.readyState)) return existing;
  if (state.remoteControl.liveReconnectTimer) {
    window.clearTimeout(state.remoteControl.liveReconnectTimer);
    state.remoteControl.liveReconnectTimer = 0;
  }
  const token = state.remoteControl.liveSocketToken + 1;
  state.remoteControl.liveSocketToken = token;
  state.remoteControl.liveSocketReady = false;
  const socket = new WebSocket(remoteControlLiveUrl());
  state.remoteControl.liveSocket = socket;
  socket.addEventListener("open", () => {
    if (state.remoteControl.liveSocketToken !== token) return;
    try {
      socket.send(JSON.stringify({ type: "hello", origin }));
    } catch {
      // The close handler will reconnect if the live session is still needed.
    }
  });
  socket.addEventListener("message", (event) => {
    if (state.remoteControl.liveSocketToken !== token) return;
    try {
      handleRemoteControlLiveMessage(JSON.parse(event.data));
    } catch (error) {
      remoteControlRecordAction("error", `live channel: ${error.message || String(error)}`);
    }
  });
  socket.addEventListener("close", () => {
    if (state.remoteControl.liveSocketToken !== token) return;
    state.remoteControl.liveSocket = null;
    state.remoteControl.liveSocketReady = false;
    rejectRemoteControlLivePending(new Error("Remote control live channel closed."));
    scheduleRemoteControlLiveReconnect("close");
  });
  socket.addEventListener("error", () => {
    if (state.remoteControl.liveSocketToken !== token) return;
    state.remoteControl.liveSocketReady = false;
  });
  return socket;
}

function appendRemoteControlLiveEvent(body = {}) {
  const socket = startRemoteControlLiveSocket("append");
  if (!socket || !remoteControlLiveConnected()) return null;
  const requestId = remoteControlId("rc_live");
  return new Promise((resolve, reject) => {
    const timeout = window.setTimeout(() => {
      delete state.remoteControl.livePending[requestId];
      reject(new Error("Remote control live channel timed out."));
    }, 650);
    state.remoteControl.livePending[requestId] = { resolve, reject, timeout };
    try {
      socket.send(JSON.stringify({ type: "append", request_id: requestId, body }));
    } catch (error) {
      window.clearTimeout(timeout);
      delete state.remoteControl.livePending[requestId];
      reject(error);
    }
  });
}

function sendRemoteControlLiveFrameEvent(body = {}) {
  const socket = startRemoteControlLiveSocket("viewport-frame");
  if (!socket || !remoteControlLiveConnected()) return false;
  if (Number(socket.bufferedAmount || 0) > REMOTE_CONTROL_LIVE_FRAME_BUFFER_LIMIT_BYTES) return true;
  try {
    socket.send(JSON.stringify({
      type: "frame",
      request_id: remoteControlId("rc_frame_live"),
      body,
    }));
    return true;
  } catch {
    return false;
  }
}

async function syncRemoteControlEvents(origin = "fast-poll") {
  if (!state.authUser || state.remoteControl.syncBusy) return;
  if (!remoteControlHasLiveTraffic()) {
    stopRemoteControlFastSyncIfIdle();
    return;
  }
  state.remoteControl.syncBusy = true;
  try {
    const query = new URLSearchParams({ limit: "120" });
    const cursor = cleanText(state.remoteControl.syncCursor || state.agentPeople?.syncCursor, "");
    if (cursor) query.set("after_id", cursor);
    const payload = await fetchJson(`/sync/events?${query.toString()}`, { timeoutMs: 5000 });
    const allEvents = Array.isArray(payload.events) ? payload.events : [];
    for (const event of allEvents) {
      if (remoteControlIsKind(event.kind)) handleRemoteControlSyncEvent(event);
    }
    state.remoteControl.syncCursor = cleanText(payload.cursor || allEvents.at(-1)?.id || state.remoteControl.syncCursor, "");
    await syncRemoteControlLatestStopEvent(origin);
    await syncRemoteControlLatestViewportFrame(origin);
  } catch (error) {
    if (origin !== "fast-poll") remoteControlRecordAction("error", error.message || String(error));
  } finally {
    state.remoteControl.syncBusy = false;
    stopRemoteControlFastSyncIfIdle();
  }
}

function remoteControlActiveStopSession() {
  const controller = state.remoteControl.activeController;
  if (controller && !remoteControlExpired(controller) && controller.conversation_id) {
    return {
      conversation_id: controller.conversation_id,
      grant_id: controller.grant_id,
      token: controller.token,
    };
  }
  const grant = state.remoteControl.activeGrant;
  if (grant && !remoteControlExpired(grant) && grant.conversation_id) {
    return {
      conversation_id: grant.conversation_id,
      grant_id: grant.grant_id,
      token: grant.token,
    };
  }
  return null;
}

async function syncRemoteControlLatestStopEvent(origin = "latest-stop") {
  if (!state.authUser) return;
  const session = remoteControlActiveStopSession();
  if (!session?.conversation_id || !session.grant_id || !session.token) return;
  const now = remoteControlNow();
  if (now - state.remoteControl.stopLatestProbeAt < REMOTE_CONTROL_SYNC_POLL_MS * 2) return;
  state.remoteControl.stopLatestProbeAt = now;
  try {
    const query = new URLSearchParams({
      conversation_id: session.conversation_id,
      kind: "remote-control-stop",
      latest: "1",
      limit: "8",
    });
    const payload = await fetchJson(`/sync/events?${query.toString()}`, { timeoutMs: 5000 });
    for (const event of Array.isArray(payload.events) ? payload.events : []) {
      if (event.kind === "remote-control-stop") handleRemoteControlStop(event);
    }
  } catch (error) {
    if (origin !== "fast-poll") remoteControlRecordAction("error", error.message || String(error));
  }
}

async function syncRemoteControlLatestViewportFrame(origin = "latest-frame") {
  const controller = state.remoteControl.activeController;
  if (!state.authUser || !controller || remoteControlExpired(controller) || !controller.conversation_id) return;
  const now = remoteControlNow();
  const frameAge = state.remoteControl.viewportFrameReceivedAt
    ? now - state.remoteControl.viewportFrameReceivedAt
    : Number.POSITIVE_INFINITY;
  if (frameAge < REMOTE_CONTROL_VIEWPORT_FRAME_MS * 2) return;
  if (now - state.remoteControl.viewportLatestProbeAt < REMOTE_CONTROL_VIEWPORT_FRAME_MS) return;
  state.remoteControl.viewportLatestProbeAt = now;
  try {
    const query = new URLSearchParams({
      conversation_id: controller.conversation_id,
      kind: REMOTE_CONTROL_VIEWPORT_FRAME_KIND,
      latest: "1",
      limit: "8",
    });
    const payload = await fetchJson(`/sync/events?${query.toString()}`, { timeoutMs: 5000 });
    for (const event of Array.isArray(payload.events) ? payload.events : []) {
      if (event.kind === REMOTE_CONTROL_VIEWPORT_FRAME_KIND) handleRemoteControlFrame(event);
    }
  } catch (error) {
    if (origin !== "fast-poll") remoteControlRecordAction("error", error.message || String(error));
  }
}

function startRemoteControlFastSync(origin = "active") {
  if (!state.authUser || !remoteControlHasLiveTraffic()) return;
  startRemoteControlLiveSocket(origin);
  if (!state.remoteControl.syncCursor) state.remoteControl.syncCursor = cleanText(state.agentPeople?.syncCursor, "");
  if (!state.remoteControl.syncTimer) {
    state.remoteControl.syncTimer = window.setInterval(
      () => void syncRemoteControlEvents("fast-poll"),
      REMOTE_CONTROL_SYNC_POLL_MS
    );
  }
  void syncRemoteControlEvents(origin);
}

function refreshRemoteControlFastSync(origin = "state") {
  if (remoteControlHasLiveTraffic()) startRemoteControlFastSync(origin);
  else stopRemoteControlFastSyncIfIdle();
}

function remoteControlSyncEventBody({ peerUserId, conversationId, kind, payload }) {
  const peerId = cleanText(peerUserId, "");
  const convId = cleanText(conversationId || remoteControlConversationIdForUser(peerId), "");
  if (!convId) throw new Error("Remote control requires a sync conversation.");
  const currentUserId = cleanText(state.authUser?.id, "");
  const body = {
    conversation_id: convId,
    client_event_id: remoteControlId(kind.replace(/[^a-z0-9_-]/gi, "_")),
    kind,
    payload: {
      schema: REMOTE_CONTROL_SCHEMA,
      ...payload,
    },
  };
  if (peerId && peerId !== currentUserId) body.peer_user_id = peerId;
  return body;
}

async function appendRemoteControlSyncEvent({ peerUserId, conversationId, kind, payload, live = true }) {
  const body = remoteControlSyncEventBody({ peerUserId, conversationId, kind, payload });
  const liveResult = remoteControlIsKind(kind) && live
    ? await appendRemoteControlLiveEvent(body).catch(() => null)
    : null;
  if (liveResult?.event) return liveResult;
  return fetchJson("/sync/events", {
    method: "POST",
    timeoutMs: 8000,
    body,
  });
}

async function requestRemoteControl(user, options = {}) {
  const targetUserId = socialUserId(user);
  if (!targetUserId || targetUserId === cleanText(state.authUser?.id, "")) return;
  const friendship = friendshipByUserId(targetUserId);
  const adminSupport = Boolean(options.adminSupport && isAdminUser());
  if (friendship?.status !== "accepted" && !adminSupport) {
    pushSocialToast("error", "Control unavailable", "Accepted friendship required", `remote-control-denied:${targetUserId}`);
    return;
  }
  const requestId = remoteControlId("rc_req");
  const expiresAt = remoteControlNow() + REMOTE_CONTROL_REQUEST_TTL_MS;
  const conversationId = remoteControlConversationIdForUser(targetUserId);
  state.remoteControl.outgoingRequests[requestId] = {
    request_id: requestId,
    target_user_id: targetUserId,
    target_label: socialUserLabel(user, "friend"),
    conversation_id: conversationId,
    expires_at: expiresAt,
    admin_support: adminSupport,
  };
  renderRemoteControlChrome();
  startRemoteControlFastSync("request");
  try {
    await appendRemoteControlSyncEvent({
      peerUserId: targetUserId,
      conversationId,
      kind: "remote-control-request",
      payload: {
        request_id: requestId,
        scope: "app",
        admin_support: adminSupport,
        requester_label: publicUserLabel(state.authUser),
        expires_at: expiresAt,
        controls: ["viewport", "click", "pointer", "text", "scroll", "keys"],
      },
    });
    pushSocialToast("remote-control", adminSupport ? "Co-control request sent" : "Control request sent", socialUserLabel(user, "friend"), `remote-control-requested:${requestId}`);
    recordUserEvent("remote_control.requested", {
      target: `user:${targetUserId}`,
      summary: `${adminSupport ? "Requested admin co-control of" : "Requested control of"} ${socialUserLabel(user, "friend")}`,
      data: { conversation_id: conversationId, request_id: requestId, scope: "app", admin_support: adminSupport },
    });
  } catch (error) {
    delete state.remoteControl.outgoingRequests[requestId];
    renderRemoteControlChrome();
    refreshRemoteControlFastSync("request-error");
    pushSocialToast("error", "Control request failed", error.message, `remote-control-error:${requestId}`);
  }
}

async function requestRemoteControlDevice(device = {}) {
  const targetDeviceId = cleanText(device.id || device.device_id || "", "");
  const fromDeviceId = remoteControlCurrentDeviceId();
  const currentUserId = cleanText(state.authUser?.id, "");
  if (!currentUserId || !targetDeviceId || !fromDeviceId || targetDeviceId === fromDeviceId) return;
  const requestId = remoteControlId("rc_dev_req");
  const expiresAt = remoteControlNow() + REMOTE_CONTROL_REQUEST_TTL_MS;
  const conversationId = remoteControlDeviceConversationId(targetDeviceId);
  const targetLabel = cleanText(device.label, "device");
  state.remoteControl.outgoingRequests[requestId] = {
    request_id: requestId,
    target_user_id: currentUserId,
    target_device_id: targetDeviceId,
    from_device_id: fromDeviceId,
    target_label: targetLabel,
    conversation_id: conversationId,
    expires_at: expiresAt,
    same_account_device: true,
  };
  renderRemoteControlChrome();
  startRemoteControlFastSync("device-request");
  try {
    await appendRemoteControlSyncEvent({
      conversationId,
      kind: "remote-control-request",
      payload: {
        request_id: requestId,
        scope: "app",
        same_account_device: true,
        requester_label: `${publicUserLabel(state.authUser)} / ${remoteControlUserLabel(currentUserId, "desktop")}`,
        target_device_id: targetDeviceId,
        from_device_id: fromDeviceId,
        expires_at: expiresAt,
        controls: ["viewport", "click", "pointer", "text", "scroll", "keys"],
      },
    });
    pushSocialToast("remote-control", "Device co-control request sent", targetLabel, `remote-control-device-requested:${requestId}`);
    recordUserEvent("remote_control.device_requested", {
      target: `device:${targetDeviceId}`,
      summary: `Requested co-control of ${targetLabel}`,
      data: { conversation_id: conversationId, request_id: requestId, target_device_id: targetDeviceId, from_device_id: fromDeviceId },
    });
  } catch (error) {
    delete state.remoteControl.outgoingRequests[requestId];
    renderRemoteControlChrome();
    refreshRemoteControlFastSync("device-request-error");
    pushSocialToast("error", "Device control failed", error.message, `remote-control-device-error:${requestId}`);
  }
}

function handleRemoteControlRequest(event) {
  const currentUserId = cleanText(state.authUser?.id, "");
  const authorId = cleanText(event.author_user_id, "");
  if (!currentUserId || !authorId) return;
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  if (payload.schema && payload.schema !== REMOTE_CONTROL_SCHEMA) return;
  const adminSupport = Boolean(payload.admin_support && payload.admin_verified);
  const currentDeviceId = remoteControlCurrentDeviceId();
  const fromDeviceId = cleanText(payload.from_device_id || payload.fromDeviceId, "");
  const targetDeviceId = cleanText(payload.target_device_id || payload.targetDeviceId, "");
  const sameAccountDevice = Boolean(
    payload.same_account_device
      && authorId === currentUserId
      && currentDeviceId
      && targetDeviceId === currentDeviceId
      && fromDeviceId
      && fromDeviceId !== currentDeviceId
  );
  if (authorId === currentUserId && !sameAccountDevice) return;
  if (friendshipByUserId(authorId)?.status !== "accepted" && !adminSupport && !sameAccountDevice) return;
  const requestId = cleanText(payload.request_id, "");
  if (!requestId || state.remoteControl.incomingRequests[requestId]) return;
  const previousResponse = remoteControlRequestResponse(requestId);
  if (
    previousResponse
    && cleanText(previousResponse.conversation_id, "") === cleanText(event.conversation_id, "")
    && cleanText(previousResponse.requester_user_id, "") === authorId
  ) return;
  const request = {
    request_id: requestId,
    requester_user_id: authorId,
    requester_device_id: fromDeviceId,
    target_device_id: targetDeviceId,
    requester_label: cleanText(payload.requester_label || remoteControlUserLabel(authorId), "Someone"),
    admin_support: adminSupport,
    same_account_device: sameAccountDevice,
    conversation_id: cleanText(event.conversation_id, ""),
    expires_at: Number(payload.expires_at || 0) || remoteControlNow() + REMOTE_CONTROL_REQUEST_TTL_MS,
    sync_event_id: cleanText(event.id, ""),
  };
  if (remoteControlExpired(request)) return;
  state.remoteControl.incomingRequests[requestId] = request;
  startRemoteControlFastSync("incoming-request");
  if ((adminSupport || sameAccountDevice) && remoteControlAdminCoControlSessionActive(authorId, fromDeviceId)) {
    void respondRemoteControlRequest(requestId, true, { automatic: true });
    return;
  }
  pushSocialToast("remote-control", adminSupport || sameAccountDevice ? "Co-control request" : "Control request", request.requester_label, `remote-control-in:${requestId}`);
  renderRemoteControlChrome();
}

async function respondRemoteControlRequest(requestId, accepted, options = {}) {
  const request = state.remoteControl.incomingRequests[requestId];
  if (!request) return;
  if (remoteControlRequestResponse(requestId)) return;
  rememberRemoteControlRequestResponse(requestId, {
    pending: true,
    accepted: false,
    requester_user_id: request.requester_user_id,
    requester_device_id: request.requester_device_id,
    conversation_id: request.conversation_id,
    expires_at: request.expires_at,
  });
  delete state.remoteControl.incomingRequests[requestId];
  let grant = null;
  if (accepted && !remoteControlExpired(request)) {
    if ((request.admin_support || request.same_account_device) && options.rememberAdmin) {
      saveRemoteControlAdminCoControlSession({
        controller_user_id: request.requester_user_id,
        controller_device_id: request.requester_device_id,
        controller_label: request.requester_label,
        expires_at: remoteControlNow() + REMOTE_CONTROL_ADMIN_SESSION_TTL_MS,
      });
    }
    grant = {
      grant_id: remoteControlId("rc_grant"),
      token: remoteControlToken(),
      request_id: request.request_id,
      controller_user_id: request.requester_user_id,
      controller_device_id: request.requester_device_id,
      target_device_id: request.target_device_id,
      controller_label: request.requester_label,
      conversation_id: request.conversation_id,
      expires_at: remoteControlNow() + REMOTE_CONTROL_GRANT_TTL_MS,
      started_at: remoteControlNow(),
      scope: "app",
      admin_support: Boolean(request.admin_support),
      same_account_device: Boolean(request.same_account_device),
    };
    state.remoteControl.activeGrant = grant;
    rememberRemoteControlRequestResponse(requestId, {
      pending: true,
      accepted: true,
      grant_id: grant.grant_id,
      token: grant.token,
      requester_user_id: request.requester_user_id,
      requester_device_id: request.requester_device_id,
      conversation_id: request.conversation_id,
      expires_at: grant.expires_at,
    });
    state.remoteControl.viewportFrameMaxBytes = REMOTE_CONTROL_VIEWPORT_FRAME_DEFAULT_MAX_BYTES;
    remoteControlRecordAction(
      "accepted",
      request.admin_support || request.same_account_device
        ? `${options.automatic ? "Session" : "Browser"} co-control granted to ${grant.controller_label}`
        : `Control granted to ${grant.controller_label}`
    );
    if (!options.automatic) await startRemoteControlExactPixelSharing("accept");
  }
  renderRemoteControlChrome();
  refreshRemoteControlFastSync(grant ? "grant-response" : "request-declined");
  try {
    await appendRemoteControlSyncEvent({
      peerUserId: request.requester_user_id,
      conversationId: request.conversation_id,
      kind: "remote-control-response",
      payload: {
        request_id: request.request_id,
        accepted: Boolean(grant),
        grant_id: grant?.grant_id || "",
        token: grant?.token || "",
        scope: "app",
        admin_support: Boolean(request.admin_support),
        same_account_device: Boolean(request.same_account_device),
        target_device_id: request.target_device_id || "",
        from_device_id: remoteControlCurrentDeviceId(),
        expires_at: grant?.expires_at || remoteControlNow(),
        responder_label: publicUserLabel(state.authUser),
      },
    });
    rememberRemoteControlRequestResponse(requestId, {
      pending: false,
      accepted: Boolean(grant),
      grant_id: grant?.grant_id || "",
      token: grant?.token || "",
      requester_user_id: request.requester_user_id,
      requester_device_id: request.requester_device_id,
      conversation_id: request.conversation_id,
      expires_at: grant?.expires_at || remoteControlNow() + REMOTE_CONTROL_REQUEST_TTL_MS,
    });
    if (grant) startRemoteControlViewportStream("grant-accepted");
    if (!grant) remoteControlRecordAction("declined", `Control request from ${request.requester_label}`);
  } catch (error) {
    delete state.remoteControl.requestResponses[requestId];
    if (grant && state.remoteControl.activeGrant?.grant_id === grant.grant_id) {
      state.remoteControl.activeGrant = null;
      stopRemoteControlViewportStream();
      renderRemoteControlChrome();
      refreshRemoteControlFastSync("response-error");
    }
    pushSocialToast("error", "Control response failed", error.message, `remote-control-response-error:${request.request_id}`);
  }
}

function handleRemoteControlResponse(event) {
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  if (payload.schema && payload.schema !== REMOTE_CONTROL_SCHEMA) return;
  const requestId = cleanText(payload.request_id, "");
  const pendingRequest = state.remoteControl.outgoingRequests[requestId] || null;
  const currentController = state.remoteControl.activeController;
  const duplicateAcceptedResponse = Boolean(
    !pendingRequest
      && payload.accepted
      && payload.grant_id
      && payload.token
      && currentController
      && cleanText(currentController.request_id || currentController.requestId, "") === requestId
      && cleanText(currentController.conversation_id, "") === cleanText(event.conversation_id, "")
      && cleanText(currentController.target_user_id, "") === cleanText(event.author_user_id, "")
  );
  const request = pendingRequest || (duplicateAcceptedResponse ? {
    request_id: currentController.request_id,
    target_user_id: currentController.target_user_id,
    target_device_id: currentController.target_device_id,
    from_device_id: currentController.from_device_id,
    target_label: currentController.target_label,
    conversation_id: currentController.conversation_id,
    admin_support: currentController.admin_support,
    same_account_device: currentController.same_account_device,
  } : null);
  if (!request) return;
  if (cleanText(event.author_user_id, "") !== request.target_user_id) return;
  if (request.target_device_id) {
    const responderDeviceId = cleanText(payload.from_device_id || payload.fromDeviceId, "");
    if (responderDeviceId && responderDeviceId !== request.target_device_id) return;
  }
  if (pendingRequest) delete state.remoteControl.outgoingRequests[requestId];
  if (payload.accepted && payload.grant_id && payload.token) {
    const responseEventId = cleanText(event.id, "");
    const currentEventId = Number(currentController?.response_event_id || 0);
    const nextEventId = Number(responseEventId || 0);
    if (duplicateAcceptedResponse && currentEventId && nextEventId && nextEventId <= currentEventId) return;
    const replacedGrant = Boolean(
      currentController?.grant_id
        && currentController.grant_id !== cleanText(payload.grant_id, "")
    );
    state.remoteControl.activeController = {
      grant_id: cleanText(payload.grant_id, ""),
      token: cleanText(payload.token, ""),
      request_id: request.request_id,
      target_user_id: cleanText(event.author_user_id, ""),
      target_device_id: cleanText(request.target_device_id || payload.from_device_id || payload.fromDeviceId, ""),
      from_device_id: cleanText(request.from_device_id || remoteControlCurrentDeviceId(), ""),
      target_label: request.target_label || remoteControlUserLabel(event.author_user_id, "friend"),
      conversation_id: request.conversation_id,
      expires_at: Number(payload.expires_at || 0) || remoteControlNow() + REMOTE_CONTROL_GRANT_TTL_MS,
      started_at: remoteControlNow(),
      response_event_id: responseEventId,
      response_event_ms: remoteControlEventMs(event),
      scope: "app",
      admin_support: Boolean(request.admin_support || payload.admin_support),
      same_account_device: Boolean(request.same_account_device || payload.same_account_device),
    };
    if (replacedGrant) {
      state.remoteControl.viewportFrame = null;
      state.remoteControl.viewportFrameReceivedAt = 0;
      state.remoteControl.viewportLatestProbeAt = 0;
      resetRemoteControlViewportPointer();
    }
    remoteControlRecordAction(
      duplicateAcceptedResponse ? "updated" : "started",
      duplicateAcceptedResponse
        ? `Synced viewport grant for ${state.remoteControl.activeController.target_label}`
        : state.remoteControl.activeController.same_account_device
          ? `Co-controlling ${state.remoteControl.activeController.target_label}`
          : `Controlling ${state.remoteControl.activeController.target_label}`
    );
    installRemoteControlCapture();
    startRemoteControlFastSync("controller-started");
    if (!duplicateAcceptedResponse) {
      pushSocialToast("remote-control", "Control accepted", state.remoteControl.activeController.target_label, `remote-control-ok:${requestId}`);
    }
  } else {
    if (duplicateAcceptedResponse) return;
    remoteControlRecordAction("declined", `${request.target_label || "Friend"} declined control`);
    pushSocialToast("remote-control", "Control declined", request.target_label || "Friend", `remote-control-declined:${requestId}`);
  }
  refreshRemoteControlFastSync(payload.accepted ? "response" : "response-declined");
  renderRemoteControlChrome();
}

function remoteControlStopMatchesSession(event, session, grantId, token, requestId, expectedAuthorId = "") {
  if (!session) return false;
  if (session.grant_id === grantId && session.token === token) return true;
  const eventConversationId = cleanText(event.conversation_id, "");
  if (!eventConversationId || eventConversationId !== cleanText(session.conversation_id, "")) return false;
  const authorId = cleanText(event.author_user_id, "");
  if (expectedAuthorId && authorId !== cleanText(expectedAuthorId, "")) return false;
  const sessionRequestId = cleanText(session.request_id || session.requestId, "");
  const stopRequestId = cleanText(requestId, "");
  if (sessionRequestId && stopRequestId && sessionRequestId !== stopRequestId) return false;
  const sessionStarted = Number(session.started_at || session.startedAt || 0);
  const stopMs = remoteControlEventMs(event);
  if (sessionStarted && stopMs + 1000 < sessionStarted) return false;
  if (sessionRequestId && stopRequestId && sessionRequestId === stopRequestId) return true;
  return Boolean(grantId && token);
}

function handleRemoteControlStop(event) {
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  if (payload.schema && payload.schema !== REMOTE_CONTROL_SCHEMA) return;
  const grantId = cleanText(payload.grant_id, "");
  const token = cleanText(payload.token, "");
  const requestId = cleanText(payload.request_id || payload.requestId, "");
  const reason = cleanText(payload.reason || "stopped", "stopped");
  let stopped = false;
  if (remoteControlStopMatchesSession(event, state.remoteControl.activeGrant, grantId, token, requestId, state.remoteControl.activeGrant?.controller_user_id)) {
    remoteControlRecordAction("stopped", `${remoteControlUserLabel(event.author_user_id, "Controller")} stopped: ${reason}`);
    state.remoteControl.activeGrant = null;
    state.remoteControl.stopLatestProbeAt = 0;
    stopRemoteControlViewportStream();
    stopped = true;
  }
  if (remoteControlStopMatchesSession(event, state.remoteControl.activeController, grantId, token, requestId, state.remoteControl.activeController?.target_user_id)) {
    remoteControlRecordAction("stopped", `Stopped controlling ${state.remoteControl.activeController.target_label}`);
    state.remoteControl.activeController = null;
    state.remoteControl.viewportFrame = null;
    state.remoteControl.viewportFrameReceivedAt = 0;
    state.remoteControl.viewportLatestProbeAt = 0;
    state.remoteControl.stopLatestProbeAt = 0;
    state.remoteControl.remotePointerTarget = null;
    resetRemoteControlViewportPointer();
    stopped = true;
  }
  if (!stopped) return;
  refreshRemoteControlFastSync("stop");
  renderRemoteControlChrome();
}

async function stopRemoteControl(reason = "user_stop") {
  const controller = state.remoteControl.activeController;
  const grant = state.remoteControl.activeGrant;
  if (grant?.admin_support || grant?.same_account_device) saveRemoteControlAdminCoControlSession(null);
  state.remoteControl.activeController = null;
  state.remoteControl.activeGrant = null;
  state.remoteControl.viewportFrame = null;
  state.remoteControl.viewportFrameReceivedAt = 0;
  state.remoteControl.viewportLatestProbeAt = 0;
  state.remoteControl.stopLatestProbeAt = 0;
  state.remoteControl.remotePointerTarget = null;
  resetRemoteControlViewportPointer();
  stopRemoteControlViewportStream();
  renderRemoteControlChrome();
  refreshRemoteControlFastSync("stop");
  const target = controller
    ? {
      peerUserId: controller.target_user_id,
      conversationId: controller.conversation_id,
      grantId: controller.grant_id,
      token: controller.token,
      requestId: controller.request_id || "",
      targetUserId: controller.target_user_id,
      targetDeviceId: controller.target_device_id || "",
      controllerUserId: cleanText(state.authUser?.id, ""),
      controllerDeviceId: controller.from_device_id || remoteControlCurrentDeviceId(),
    }
    : grant
      ? {
        peerUserId: grant.controller_user_id,
        conversationId: grant.conversation_id,
        grantId: grant.grant_id,
        token: grant.token,
        requestId: grant.request_id || "",
        targetUserId: cleanText(state.authUser?.id, ""),
        targetDeviceId: grant.target_device_id || remoteControlCurrentDeviceId(),
        controllerUserId: grant.controller_user_id,
        controllerDeviceId: grant.controller_device_id || "",
      }
      : null;
  if (!target) return;
  remoteControlRecordAction("stopped", reason);
  try {
    await appendRemoteControlSyncEvent({
      peerUserId: target.peerUserId,
      conversationId: target.conversationId,
      kind: "remote-control-stop",
      payload: {
        grant_id: target.grantId,
        token: target.token,
        request_id: target.requestId,
        target_user_id: target.targetUserId,
        target_device_id: target.targetDeviceId,
        controller_user_id: target.controllerUserId,
        controller_device_id: target.controllerDeviceId,
        reason,
      },
    });
  } catch (error) {
    pushSocialToast("error", "Stop signal failed", error.message, `remote-control-stop-error:${target.grantId}`);
  }
}

setRemoteControlViewportPixelCaptureStopHandler((reason) => {
  if (!state.remoteControl.activeGrant) return;
  void stopRemoteControl(reason || "display_capture_ended");
});

function renderRemoteControlChrome() {
  renderRemoteControlConsent();
  renderRemoteControlBanner();
  renderRemoteControlViewportPanel();
}

function renderRemoteControlConsent() {
  const requests = Object.values(state.remoteControl.incomingRequests || {})
    .filter((request) => !remoteControlExpired(request))
    .sort((a, b) => Number(b.expires_at || 0) - Number(a.expires_at || 0));
  state.remoteControl.incomingRequests = Object.fromEntries(requests.map((request) => [request.request_id, request]));
  let panel = document.querySelector("[data-remote-control-consent]");
  if (!requests.length) {
    panel?.remove();
    return;
  }
  const request = requests[0];
  const coControl = Boolean(request.admin_support || request.same_account_device);
  if (!panel) {
    panel = document.createElement("section");
    panel.className = "remote-control-consent";
    panel.dataset.remoteControl = "true";
    panel.dataset.remoteControlConsent = "true";
    panel.setAttribute("role", "dialog");
    panel.setAttribute("aria-live", "polite");
    document.body.append(panel);
  }
  const title = document.createElement("strong");
  title.textContent = coControl
    ? `${request.requester_label} wants to co-control`
    : `${request.requester_label} wants control`;
  const detail = document.createElement("span");
  detail.textContent = request.same_account_device
    ? "Same account device, app surface and viewport"
    : request.admin_support ? "Browser session, app surface and viewport" : "App surface and viewport";
  const actions = document.createElement("div");
  actions.className = "remote-control-actions";
  const accept = document.createElement("button");
  accept.type = "button";
  accept.textContent = coControl ? "Accept once" : "Accept";
  accept.addEventListener("click", () => void respondRemoteControlRequest(request.request_id, true));
  const decline = document.createElement("button");
  decline.type = "button";
  decline.textContent = "Decline";
  decline.addEventListener("click", () => void respondRemoteControlRequest(request.request_id, false));
  if (coControl) {
    const allowSession = document.createElement("button");
    allowSession.type = "button";
    allowSession.textContent = "Allow session";
    allowSession.addEventListener("click", () => void respondRemoteControlRequest(request.request_id, true, { rememberAdmin: true }));
    actions.append(allowSession, accept, decline);
  } else {
    actions.append(accept, decline);
  }
  panel.replaceChildren(title, detail, actions);
}

async function startRemoteControlExactPixelSharing(origin = "button") {
  const grant = state.remoteControl.activeGrant;
  if (!grant || remoteControlExpired(grant)) return false;
  const wasActive = remoteControlViewportPixelCaptureActive();
  try {
    const active = wasActive || await startRemoteControlViewportPixelCapture();
    if (active && !wasActive) remoteControlRecordAction("accepted", "Exact pixel viewport sharing active");
    if (active) startRemoteControlViewportStream(`exact-pixels:${origin}`);
    else remoteControlRecordAction("info", "Exact pixel sharing unavailable in this browser");
    renderRemoteControlChrome();
    return Boolean(active);
  } catch (error) {
    remoteControlRecordAction("info", `Exact pixel sharing unavailable: ${error.message || String(error)}`);
    renderRemoteControlChrome();
    return false;
  }
}

function renderRemoteControlBanner() {
  if (state.remoteControl.activeGrant && remoteControlExpired(state.remoteControl.activeGrant)) {
    state.remoteControl.activeGrant = null;
    stopRemoteControlViewportStream();
  }
  if (state.remoteControl.activeController && remoteControlExpired(state.remoteControl.activeController)) {
    state.remoteControl.activeController = null;
    state.remoteControl.viewportFrame = null;
    state.remoteControl.viewportFrameReceivedAt = 0;
  }
  const activeGrant = state.remoteControl.activeGrant;
  const activeController = state.remoteControl.activeController;
  let banner = document.querySelector("[data-remote-control-banner]");
  if (!activeGrant && !activeController) {
    banner?.remove();
    return;
  }
  if (!banner) {
    banner = document.createElement("section");
    banner.className = "remote-control-banner";
    banner.dataset.remoteControl = "true";
    banner.dataset.remoteControlBanner = "true";
    banner.setAttribute("aria-live", "polite");
    document.body.append(banner);
  }
  const label = document.createElement("strong");
  const detail = document.createElement("span");
  const latest = state.remoteControl.actionLog.at(-1);
  if (activeGrant) {
    const coControl = Boolean(activeGrant.admin_support || activeGrant.same_account_device);
    label.textContent = coControl ? `Co-controlling with ${activeGrant.controller_label}` : `${activeGrant.controller_label} is controlling`;
    detail.textContent = latest ? latest.detail : coControl ? "Stop revokes this browser session" : "App surface and viewport";
    banner.dataset.mode = "receiving";
  } else {
    const coControl = Boolean(activeController.admin_support || activeController.same_account_device);
    label.textContent = coControl ? `Co-controlling ${activeController.target_label}` : `Controlling ${activeController.target_label}`;
    detail.textContent = latest ? latest.detail : coControl ? "Shared app surface and viewport" : "App surface and viewport";
    banner.dataset.mode = "controlling";
  }
  const stop = document.createElement("button");
  stop.type = "button";
  stop.textContent = activeGrant?.admin_support || activeGrant?.same_account_device ? "Stop access" : "Stop";
  stop.addEventListener("click", () => void stopRemoteControl("stop_button"));
  const actions = document.createElement("div");
  actions.className = "remote-control-banner-actions";
  if (activeGrant && !remoteControlViewportPixelCaptureActive()) {
    const sharePixels = document.createElement("button");
    sharePixels.type = "button";
    sharePixels.textContent = "Share pixels";
    sharePixels.addEventListener("click", () => void startRemoteControlExactPixelSharing("banner"));
    actions.append(sharePixels);
  }
  actions.append(stop);
  banner.replaceChildren(label, detail, actions);
}

async function sendRemoteControlViewportStatus(grant, status, message, reason = "status") {
  if (!grant || remoteControlExpired(grant)) return;
  await appendRemoteControlSyncEvent({
    peerUserId: grant.controller_user_id,
    conversationId: grant.conversation_id,
    kind: REMOTE_CONTROL_VIEWPORT_FRAME_KIND,
    payload: {
      grant_id: grant.grant_id,
      token: grant.token,
      request_id: grant.request_id || "",
      target_user_id: cleanText(state.authUser?.id, ""),
      target_device_id: grant.target_device_id || remoteControlCurrentDeviceId(),
      controller_user_id: grant.controller_user_id,
      controller_device_id: grant.controller_device_id || "",
      seq: state.remoteControl.viewportSeq,
      status,
      message: truncateText(message, 180),
      reason,
      captured_at: new Date().toISOString(),
    },
  });
}

function remoteControlPayloadTooLarge(error) {
  const text = `${error?.message || ""} ${error?.payload?.error?.message || ""} ${error?.payload?.error?.code || ""}`;
  return /payload.*too large|sync_payload_too_large|request entity too large|413/i.test(text);
}

function remoteControlViewportFrameIntervalMs() {
  return remoteControlViewportPixelCaptureActive()
    ? REMOTE_CONTROL_VIEWPORT_LIVE_FRAME_MS
    : REMOTE_CONTROL_VIEWPORT_FRAME_MS;
}

async function sendRemoteControlViewportFramePayload(grant, payload) {
  const eventInput = {
    peerUserId: grant.controller_user_id,
    conversationId: grant.conversation_id,
    kind: REMOTE_CONTROL_VIEWPORT_FRAME_KIND,
    payload,
  };
  const body = remoteControlSyncEventBody(eventInput);
  if (sendRemoteControlLiveFrameEvent(body)) {
    const now = remoteControlNow();
    if (now - state.remoteControl.viewportLastDurableFrameAt >= REMOTE_CONTROL_VIEWPORT_DURABLE_FRAME_MS) {
      state.remoteControl.viewportLastDurableFrameAt = now;
      void appendRemoteControlSyncEvent({ ...eventInput, live: false }).catch((error) => {
        if (remoteControlPayloadTooLarge(error)) return;
        remoteControlRecordAction("error", `viewport keyframe: ${error.message || String(error)}`);
      });
    }
    return { ok: true, live: true };
  }
  return appendRemoteControlSyncEvent({ ...eventInput, live: false });
}

async function sendRemoteControlViewportFrame(reason = "timer") {
  const grant = state.remoteControl.activeGrant;
  if (!grant || remoteControlExpired(grant)) {
    state.remoteControl.activeGrant = null;
    stopRemoteControlViewportStream();
    renderRemoteControlChrome();
    return;
  }
  if (state.remoteControl.viewportStreamBusy) return;
  state.remoteControl.viewportStreamBusy = true;
  try {
    const exactPixels = remoteControlViewportPixelCaptureActive();
    const frame = await captureRemoteControlViewportFrame(reason, {
      maxBytes: exactPixels
        ? Math.min(
          state.remoteControl.viewportFrameMaxBytes || REMOTE_CONTROL_VIEWPORT_FRAME_DEFAULT_MAX_BYTES,
          REMOTE_CONTROL_VIEWPORT_LIVE_MAX_BYTES
        )
        : state.remoteControl.viewportFrameMaxBytes || REMOTE_CONTROL_VIEWPORT_FRAME_DEFAULT_MAX_BYTES,
      fast: exactPixels,
    });
    if (!frame) {
      await sendRemoteControlViewportStatus(
        grant,
        "waiting",
        document.visibilityState === "hidden"
          ? "Remote tab is backgrounded; waiting for browser capture."
          : "Remote viewport capture is starting.",
        reason
      );
      return;
    }
    state.remoteControl.viewportSeq += 1;
    await sendRemoteControlViewportFramePayload(grant, {
      grant_id: grant.grant_id,
      token: grant.token,
      request_id: grant.request_id || "",
      target_user_id: cleanText(state.authUser?.id, ""),
      target_device_id: grant.target_device_id || remoteControlCurrentDeviceId(),
      controller_user_id: grant.controller_user_id,
      controller_device_id: grant.controller_device_id || "",
      seq: state.remoteControl.viewportSeq,
      image: frame.data_url,
      image_type: frame.type,
      image_bytes: frame.size,
      width: frame.width,
      height: frame.height,
      renderer: frame.renderer || "",
      viewport_width: frame.viewport_width,
      viewport_height: frame.viewport_height,
      layout_width: frame.layout_width,
      layout_height: frame.layout_height,
      device_pixel_ratio: frame.device_pixel_ratio,
      reason: frame.reason,
      captured_at: new Date().toISOString(),
    });
    state.remoteControl.viewportFrameError = "";
  } catch (error) {
    const message = error.message || String(error);
    if (
      remoteControlPayloadTooLarge(error)
      && state.remoteControl.viewportFrameMaxBytes > REMOTE_CONTROL_VIEWPORT_FRAME_BOOTSTRAP_MAX_BYTES
    ) {
      state.remoteControl.viewportFrameMaxBytes = REMOTE_CONTROL_VIEWPORT_FRAME_BOOTSTRAP_MAX_BYTES;
      await sendRemoteControlViewportStatus(
        grant,
        "waiting",
        "Remote viewport frame was too large; retrying with a compact preview.",
        reason
      ).catch(() => {});
      window.setTimeout(() => void sendRemoteControlViewportFrame("payload-retry"), 80);
      return;
    }
    await sendRemoteControlViewportStatus(grant, "error", `Remote viewport capture failed: ${message}`, reason).catch(() => {});
    if (state.remoteControl.viewportFrameError !== message) {
      state.remoteControl.viewportFrameError = message;
      remoteControlRecordAction("error", `viewport frame: ${message}`);
    }
  } finally {
    state.remoteControl.viewportStreamBusy = false;
  }
}

function startRemoteControlViewportStream(reason = "start") {
  if (!state.remoteControl.activeGrant) return;
  const intervalMs = remoteControlViewportFrameIntervalMs();
  if (
    state.remoteControl.viewportStreamTimer
    && state.remoteControl.viewportStreamIntervalMs
    && state.remoteControl.viewportStreamIntervalMs !== intervalMs
  ) {
    window.clearInterval(state.remoteControl.viewportStreamTimer);
    state.remoteControl.viewportStreamTimer = 0;
  }
  if (!state.remoteControl.viewportStreamTimer) {
    state.remoteControl.viewportStreamIntervalMs = intervalMs;
    state.remoteControl.viewportStreamTimer = window.setInterval(
      () => void sendRemoteControlViewportFrame("timer"),
      intervalMs
    );
  }
  void sendRemoteControlViewportFrame(reason);
}

function stopRemoteControlViewportStream() {
  if (state.remoteControl.viewportStreamTimer) {
    window.clearInterval(state.remoteControl.viewportStreamTimer);
    state.remoteControl.viewportStreamTimer = 0;
  }
  state.remoteControl.viewportStreamIntervalMs = 0;
  state.remoteControl.viewportStreamBusy = false;
  state.remoteControl.viewportFrameMaxBytes = REMOTE_CONTROL_VIEWPORT_FRAME_DEFAULT_MAX_BYTES;
  state.remoteControl.viewportLastDurableFrameAt = 0;
  stopRemoteControlViewportPixelCapture();
}

function scheduleRemoteControlViewportRender() {
  if (state.remoteControl.viewportRenderTimer) return;
  const schedule = window.requestAnimationFrame || ((callback) => window.setTimeout(callback, 16));
  state.remoteControl.viewportRenderTimer = schedule(() => {
    state.remoteControl.viewportRenderTimer = 0;
    renderRemoteControlViewportPanel();
  });
}

function handleRemoteControlFrame(event) {
  const controller = state.remoteControl.activeController;
  if (!controller || remoteControlExpired(controller)) return;
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  if (payload.schema && payload.schema !== REMOTE_CONTROL_SCHEMA) return;
  const grantId = cleanText(payload.grant_id, "");
  const token = cleanText(payload.token, "");
  const requestId = cleanText(payload.request_id || payload.requestId, "");
  const exactGrant = grantId === controller.grant_id && token === controller.token;
  const siblingGrant = Boolean(
    !exactGrant
      && grantId
      && token
      && requestId
      && requestId === cleanText(controller.request_id || controller.requestId, "")
      && cleanText(event.conversation_id, "") === cleanText(controller.conversation_id, "")
  );
  if (!exactGrant && !siblingGrant) return;
  if (cleanText(event.author_user_id, "") !== controller.target_user_id) return;
  const currentUserId = cleanText(state.authUser?.id, "");
  const controllerUserId = cleanText(payload.controller_user_id, "");
  if (controllerUserId && controllerUserId !== currentUserId) return;
  const targetDeviceId = cleanText(payload.target_device_id || payload.targetDeviceId, "");
  if (controller.target_device_id && targetDeviceId && targetDeviceId !== controller.target_device_id) return;
  const controllerDeviceId = cleanText(payload.controller_device_id || payload.controllerDeviceId, "");
  if (controller.from_device_id && controllerDeviceId && controllerDeviceId !== controller.from_device_id) return;
  const incomingSeq = Number(payload.seq || 0);
  if (siblingGrant) {
    state.remoteControl.activeController = {
      ...controller,
      grant_id: grantId,
      token,
      response_event_id: cleanText(event.id, controller.response_event_id || ""),
      response_event_ms: remoteControlEventMs(event),
    };
    state.remoteControl.viewportFrame = null;
    state.remoteControl.viewportFrameReceivedAt = 0;
    resetRemoteControlViewportPointer();
    remoteControlRecordAction("updated", `Synced viewport frame grant for ${controller.target_label}`);
  }
  const previousSeq = Number(state.remoteControl.viewportFrame?.seq || 0);
  if (incomingSeq && previousSeq && incomingSeq <= previousSeq) return;
  const image = cleanText(payload.image, "");
  if (!image.startsWith("data:image/")) {
    const status = cleanText(payload.status, "");
    const message = cleanText(payload.message || payload.error, "");
    if (!status && !message) return;
    const previous = state.remoteControl.viewportFrame?.image ? state.remoteControl.viewportFrame : {};
    state.remoteControl.viewportFrame = {
      ...previous,
      status: status || "waiting",
      message: message || "Remote viewport capture is starting.",
      seq: Number(incomingSeq || previous.seq || 0),
      captured_at: cleanText(payload.captured_at || payload.capturedAt || previous.captured_at, ""),
      target_device_id: targetDeviceId || previous.target_device_id || "",
    };
    state.remoteControl.viewportFrameReceivedAt = remoteControlNow();
    scheduleRemoteControlViewportRender();
    return;
  }
  state.remoteControl.viewportFrame = {
    image,
    width: Number(payload.width || 0),
    height: Number(payload.height || 0),
    viewport_width: Number(payload.viewport_width || payload.viewportWidth || 0),
    viewport_height: Number(payload.viewport_height || payload.viewportHeight || 0),
    image_bytes: Number(payload.image_bytes || payload.imageBytes || 0),
    renderer: cleanText(payload.renderer, ""),
    status: "ok",
    message: "",
    seq: incomingSeq,
    captured_at: cleanText(payload.captured_at || payload.capturedAt, ""),
    target_device_id: targetDeviceId,
  };
  state.remoteControl.viewportFrameReceivedAt = remoteControlNow();
  scheduleRemoteControlViewportRender();
}

function sendRemoteControlViewportPointerAction(event, type) {
  if (!state.remoteControl.activeController) return false;
  const point = remoteControlViewportPoint(event);
  if (!point) return false;
  event.preventDefault();
  event.stopPropagation();
  const button = Number(event.button);
  const buttons = Number(event.buttons);
  sendRemoteControlAction({
    ...point,
    type,
    pointer_id: Number(event.pointerId || state.remoteControl.viewportPointerId || 1),
    pointer_type: cleanText(event.pointerType || "mouse", "mouse"),
    button: Number.isFinite(button) ? button : 0,
    buttons: type === "pointer_up" ? 0 : Number.isFinite(buttons) ? buttons : 1,
    viewport_width: point.viewport_width || undefined,
    viewport_height: point.viewport_height || undefined,
  });
  return true;
}

function sendRemoteControlViewportClickAction(event) {
  if (!state.remoteControl.activeController) return false;
  const point = remoteControlViewportPoint(event);
  if (!point) return false;
  event.preventDefault();
  event.stopPropagation();
  sendRemoteControlAction({ ...point, type: "click" });
  return true;
}

function resetRemoteControlViewportPointer() {
  state.remoteControl.viewportPointerActive = false;
  state.remoteControl.viewportPointerMoved = false;
  state.remoteControl.viewportPointerId = 0;
  state.remoteControl.viewportPointerStartX = 0;
  state.remoteControl.viewportPointerStartY = 0;
}

function handleRemoteControlViewportPointerDown(event) {
  if (!state.remoteControl.activeController || event.isPrimary === false) return;
  const button = Number(event.button || 0);
  if (button > 0) return;
  state.remoteControl.viewportPointerActive = true;
  state.remoteControl.viewportPointerMoved = false;
  state.remoteControl.viewportPointerId = Number(event.pointerId || 1);
  state.remoteControl.viewportPointerStartX = Number(event.clientX || 0);
  state.remoteControl.viewportPointerStartY = Number(event.clientY || 0);
  event.currentTarget?.closest?.("[data-remote-control-viewport]")?.focus?.({ preventScroll: true });
  try {
    event.currentTarget?.setPointerCapture?.(event.pointerId);
  } catch {
    // Pointer capture can be unavailable after a fast frame refresh.
  }
  sendRemoteControlViewportPointerAction(event, "pointer_down");
}

function handleRemoteControlViewportPointerMove(event) {
  if (!state.remoteControl.viewportPointerActive) return;
  if (state.remoteControl.viewportPointerId && Number(event.pointerId || 0) !== state.remoteControl.viewportPointerId) return;
  const distance = Math.hypot(
    Number(event.clientX || 0) - state.remoteControl.viewportPointerStartX,
    Number(event.clientY || 0) - state.remoteControl.viewportPointerStartY
  );
  if (distance > 3) state.remoteControl.viewportPointerMoved = true;
  if (!state.remoteControl.viewportPointerMoved) return;
  const now = remoteControlNow();
  if (now - state.remoteControl.lastPointerMoveAt < REMOTE_CONTROL_POINTER_MOVE_MIN_MS) return;
  state.remoteControl.lastPointerMoveAt = now;
  sendRemoteControlViewportPointerAction(event, "pointer_move");
}

function handleRemoteControlViewportPointerUp(event) {
  if (!state.remoteControl.viewportPointerActive) return;
  if (event.type === "lostpointercapture") {
    resetRemoteControlViewportPointer();
    return;
  }
  if (state.remoteControl.viewportPointerId && Number(event.pointerId || 0) !== state.remoteControl.viewportPointerId) return;
  const moved = state.remoteControl.viewportPointerMoved;
  sendRemoteControlViewportPointerAction(event, "pointer_up");
  try {
    event.currentTarget?.releasePointerCapture?.(event.pointerId);
  } catch {
    // The browser may release capture before the cleanup handler runs.
  }
  if (moved) state.remoteControl.viewportPointerSuppressClickUntil = remoteControlNow() + REMOTE_CONTROL_DRAG_CLICK_SUPPRESS_MS;
  else if (sendRemoteControlViewportClickAction(event)) {
    state.remoteControl.viewportPointerSuppressClickUntil = remoteControlNow() + REMOTE_CONTROL_DRAG_CLICK_SUPPRESS_MS;
  }
  resetRemoteControlViewportPointer();
}

function handleRemoteControlViewportClick(event) {
  if (!state.remoteControl.activeController) return;
  if (remoteControlNow() < state.remoteControl.viewportPointerSuppressClickUntil) {
    event.preventDefault();
    event.stopPropagation();
    return;
  }
  const point = remoteControlViewportPoint(event);
  if (!point) return;
  event.preventDefault();
  event.stopPropagation();
  event.currentTarget.closest?.("[data-remote-control-viewport]")?.focus?.();
  sendRemoteControlViewportClickAction(event);
}

function handleRemoteControlViewportWheel(event) {
  if (!state.remoteControl.activeController) return;
  const point = remoteControlViewportPoint(event);
  if (!point) return;
  event.preventDefault();
  event.stopPropagation();
  const now = remoteControlNow();
  if (now - state.remoteControl.lastWheelAt < REMOTE_CONTROL_WHEEL_MIN_MS) return;
  state.remoteControl.lastWheelAt = now;
  sendRemoteControlAction({
    ...point,
    type: "scroll",
    delta_x: clamp(Number(event.deltaX || 0), -800, 800),
    delta_y: clamp(Number(event.deltaY || 0), -800, 800),
  });
}

function handleRemoteControlViewportKeydown(event) {
  if (!state.remoteControl.activeController) return;
  if (event.target?.matches?.("button")) return;
  const key = cleanText(event.key, "");
  if (key.length === 1 && !event.metaKey && !event.ctrlKey && !event.altKey) {
    event.preventDefault();
    sendRemoteControlAction({ type: "insert_text", text: key });
    return;
  }
  if (!["Enter", "Escape", "Tab", "Backspace", "Delete", "ArrowUp", "ArrowDown", "ArrowLeft", "ArrowRight"].includes(key)) return;
  event.preventDefault();
  sendRemoteControlAction({ type: "key", key });
}

function renderRemoteControlViewportPanel() {
  const controller = state.remoteControl.activeController;
  if (!controller || remoteControlExpired(controller)) {
    if (controller && remoteControlExpired(controller)) state.remoteControl.activeController = null;
    state.remoteControl.viewportFrame = null;
    state.remoteControl.viewportFrameReceivedAt = 0;
    resetRemoteControlViewportPointer();
    removeRemoteControlViewportPanel();
    return;
  }
  renderRemoteControlViewportSurface({
    controller,
    frame: state.remoteControl.viewportFrame,
    receivedAt: state.remoteControl.viewportFrameReceivedAt,
    now: remoteControlNow(),
    onClick: handleRemoteControlViewportClick,
    onWheel: handleRemoteControlViewportWheel,
    onKeydown: handleRemoteControlViewportKeydown,
    onPointerDown: handleRemoteControlViewportPointerDown,
    onPointerMove: handleRemoteControlViewportPointerMove,
    onPointerUp: handleRemoteControlViewportPointerUp,
  });
}

function remoteControlAppElement(element) {
  const target = element?.nodeType === 1 ? element : element?.parentElement;
  if (!target || target.closest?.("[data-remote-control]")) return null;
  if (!document.body?.contains(target)) return null;
  return target;
}

function remoteControlSecretElement(element) {
  const target = element?.closest?.("input,textarea") || (element?.matches?.("input,textarea") ? element : null);
  if (!target) return false;
  const type = cleanText(target.getAttribute("type") || "", "").toLowerCase();
  const nameBits = [
    target.id,
    target.name,
    target.getAttribute("autocomplete"),
    target.getAttribute("placeholder"),
    target.getAttribute("aria-label"),
  ].join(" ");
  return REMOTE_CONTROL_BLOCKED_INPUT_TYPES.has(type) || REMOTE_CONTROL_SECRET_RE.test(nameBits);
}

function remoteControlTargetAllowed(element, actionType = "") {
  const source = remoteControlAppElement(element);
  if (!source || remoteControlSecretElement(source)) return null;
  const target = source.closest?.(REMOTE_CONTROL_INTERACTIVE_SELECTOR);
  if (!target || target.closest?.("[data-remote-control]")) return null;
  if (remoteControlSecretElement(target)) return null;
  if (actionType === "set_value" && target.matches?.("s-select")) return null;
  return target;
}

function remoteControlClickTarget(element) {
  const target = remoteControlTargetAllowed(element, "click");
  if (target) return target;
  const source = remoteControlAppElement(element);
  if (!source || remoteControlSecretElement(source)) return null;
  return source;
}

function remoteControlSelectorForElement(element) {
  const target = remoteControlTargetAllowed(element, "selector");
  if (!target) return "";
  const escapeCss = (value) => window.CSS?.escape
    ? CSS.escape(value)
    : String(value).replace(/[^a-zA-Z0-9_-]/g, "\\$&");
  if (target.id) return `#${escapeCss(target.id)}`;
  const parts = [];
  let node = target;
  while (node && node.nodeType === 1 && node !== document.body && parts.length < 5) {
    let part = node.tagName.toLowerCase();
    if (node.classList?.length) part += `.${Array.from(node.classList).slice(0, 2).map(escapeCss).join(".")}`;
    const parent = node.parentElement;
    if (parent) {
      const siblings = Array.from(parent.children).filter((item) => item.tagName === node.tagName);
      if (siblings.length > 1) part += `:nth-of-type(${siblings.indexOf(node) + 1})`;
    }
    parts.unshift(part);
    node = parent;
  }
  return parts.join(" > ");
}

function remoteControlElementFromAction(action = {}) {
  if (action.selector) {
    try {
      const selected = document.querySelector(action.selector);
      if (selected) return selected;
    } catch {
      // Fall through to coordinates.
    }
  }
  const xRatio = Number(action.x_ratio ?? action.xRatio);
  const yRatio = Number(action.y_ratio ?? action.yRatio);
  if (Number.isFinite(xRatio) && Number.isFinite(yRatio)) {
    const point = remoteControlActionPoint(action);
    if (point) return document.elementFromPoint(point.x, point.y);
  }
  return document.activeElement;
}

function remoteControlActionPoint(action = {}) {
  const xRatio = Number(action.x_ratio ?? action.xRatio);
  const yRatio = Number(action.y_ratio ?? action.yRatio);
  if (!Number.isFinite(xRatio) || !Number.isFinite(yRatio)) return null;
  const viewport = window.visualViewport;
  const width = Math.max(1, Number(viewport?.width || action.viewport_width || action.viewportWidth || window.innerWidth || 1));
  const height = Math.max(1, Number(viewport?.height || action.viewport_height || action.viewportHeight || window.innerHeight || 1));
  return {
    x: Number(viewport?.offsetLeft || 0) + clamp(xRatio, 0, 1) * width,
    y: Number(viewport?.offsetTop || 0) + clamp(yRatio, 0, 1) * height,
  };
}

function remoteControlPointerEventName(type = "") {
  if (type === "pointer_down") return "pointerdown";
  if (type === "pointer_move") return "pointermove";
  if (type === "pointer_up") return "pointerup";
  return "";
}

function dispatchRemoteControlPointerAction(action = {}, baseElement = null) {
  const type = cleanText(action.type, "");
  const eventName = remoteControlPointerEventName(type);
  const point = remoteControlActionPoint(action);
  if (!eventName || !point) return false;
  let target = eventName === "pointerdown" ? remoteControlAppElement(baseElement) : state.remoteControl.remotePointerTarget;
  if (!target || !document.contains(target)) target = remoteControlAppElement(baseElement);
  if (!target) return false;
  const pointerId = Number(action.pointer_id || action.pointerId || 1);
  const pointerType = cleanText(action.pointer_type || action.pointerType || "mouse", "mouse");
  const button = Number(action.button || 0);
  const buttons = eventName === "pointerup" ? 0 : Number(action.buttons || 1);
  const init = {
    bubbles: true,
    cancelable: true,
    composed: true,
    view: window,
    clientX: point.x,
    clientY: point.y,
    button: Number.isFinite(button) ? button : 0,
    buttons: Number.isFinite(buttons) ? buttons : eventName === "pointerup" ? 0 : 1,
  };
  if (eventName === "pointerdown") {
    state.remoteControl.remotePointerTarget = target;
    state.remoteControl.remotePointerStartX = point.x;
    state.remoteControl.remotePointerStartY = point.y;
    state.remoteControl.remotePointerMoved = false;
  } else if (eventName === "pointermove") {
    const moved = Math.hypot(
      point.x - Number(state.remoteControl.remotePointerStartX || point.x),
      point.y - Number(state.remoteControl.remotePointerStartY || point.y)
    );
    if (moved > 4) state.remoteControl.remotePointerMoved = true;
  }
  if (typeof PointerEvent === "function") {
    target.dispatchEvent(new PointerEvent(eventName, {
      ...init,
      pointerId: Number.isFinite(pointerId) ? pointerId : 1,
      pointerType,
      isPrimary: true,
    }));
  }
  const mouseName = eventName === "pointerdown" ? "mousedown" : eventName === "pointermove" ? "mousemove" : "mouseup";
  target.dispatchEvent(new MouseEvent(mouseName, init));
  if (eventName === "pointerup") {
    const clickDistance = Math.hypot(
      point.x - Number(state.remoteControl.remotePointerStartX || point.x),
      point.y - Number(state.remoteControl.remotePointerStartY || point.y)
    );
    const tapTarget = state.remoteControl.remotePointerTarget || target;
    if (!state.remoteControl.remotePointerMoved && clickDistance <= 6 && dispatchRemoteControlClick(tapTarget, action, { includePress: false, source: "pointer_tap" })) {
      state.remoteControl.remoteSyntheticClickUntil = remoteControlNow() + 700;
      state.remoteControl.remoteSyntheticClickX = point.x;
      state.remoteControl.remoteSyntheticClickY = point.y;
    }
    state.remoteControl.remotePointerTarget = null;
    state.remoteControl.remotePointerStartX = 0;
    state.remoteControl.remotePointerStartY = 0;
    state.remoteControl.remotePointerMoved = false;
  }
  return true;
}

function dispatchRemoteControlClick(element, action = {}, options = {}) {
  const target = remoteControlClickTarget(element);
  const point = remoteControlActionPoint(action);
  if (!target || !point) return false;
  const init = {
    bubbles: true,
    cancelable: true,
    composed: true,
    view: window,
    clientX: point.x,
    clientY: point.y,
    button: 0,
    buttons: 0,
  };
  target.focus?.({ preventScroll: true });
  if (options.includePress !== false) {
    target.dispatchEvent(new MouseEvent("mousedown", { ...init, buttons: 1 }));
    target.dispatchEvent(new MouseEvent("mouseup", init));
  }
  if (typeof target.click === "function" && target.matches?.(REMOTE_CONTROL_INTERACTIVE_SELECTOR)) {
    target.click();
  } else {
    target.dispatchEvent(new MouseEvent("click", init));
  }
  remoteControlRecordAction("received", `${options.source === "pointer_tap" ? "tap" : "click"} ${target.id || target.getAttribute?.("aria-label") || target.tagName?.toLowerCase?.() || "element"}`);
  return true;
}

function remoteControlSuppressDuplicateExplicitClick(action = {}) {
  const until = Number(state.remoteControl.remoteSyntheticClickUntil || 0);
  if (!until || remoteControlNow() > until) return false;
  const point = remoteControlActionPoint(action);
  if (!point) return false;
  const distance = Math.hypot(
    point.x - Number(state.remoteControl.remoteSyntheticClickX || 0),
    point.y - Number(state.remoteControl.remoteSyntheticClickY || 0)
  );
  if (distance > 8) return false;
  state.remoteControl.remoteSyntheticClickUntil = 0;
  return true;
}

function setRemoteControlElementValue(element, value) {
  const target = remoteControlTargetAllowed(element, "set_value");
  if (!target) return false;
  state.remoteControl.suppressEvents = true;
  try {
    if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement) {
      target.focus();
      target.value = String(value ?? "");
      target.dispatchEvent(new Event("input", { bubbles: true }));
      target.dispatchEvent(new Event("change", { bubbles: true }));
      return true;
    }
    if (target.isContentEditable) {
      target.focus();
      target.textContent = String(value ?? "");
      target.dispatchEvent(new InputEvent("input", { bubbles: true, inputType: "insertText", data: String(value ?? "") }));
      return true;
    }
  } finally {
    window.setTimeout(() => {
      state.remoteControl.suppressEvents = false;
    }, 0);
  }
  return false;
}

function remoteControlEditableTarget(element) {
  const target = remoteControlTargetAllowed(element, "set_value");
  if (!target) return null;
  if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement || target.isContentEditable) return target;
  return null;
}

function dispatchRemoteControlEditEvents(target, inputType = "insertText", data = "") {
  try {
    target.dispatchEvent(new InputEvent("input", { bubbles: true, inputType, data }));
  } catch {
    target.dispatchEvent(new Event("input", { bubbles: true }));
  }
  target.dispatchEvent(new Event("change", { bubbles: true }));
}

function insertRemoteControlText(element, text = "") {
  const target = remoteControlEditableTarget(element);
  const value = String(text ?? "").slice(0, 200);
  if (!target || !value) return false;
  target.focus?.();
  if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement) {
    const start = Number.isFinite(target.selectionStart) ? target.selectionStart : target.value.length;
    const end = Number.isFinite(target.selectionEnd) ? target.selectionEnd : start;
    if (typeof target.setRangeText === "function") target.setRangeText(value, start, end, "end");
    else target.value = `${target.value.slice(0, start)}${value}${target.value.slice(end)}`;
    dispatchRemoteControlEditEvents(target, "insertText", value);
    return true;
  }
  if (target.isContentEditable) {
    target.textContent = `${target.textContent || ""}${value}`;
    dispatchRemoteControlEditEvents(target, "insertText", value);
    return true;
  }
  return false;
}

function applyRemoteControlEditKey(element, key = "") {
  const target = remoteControlEditableTarget(element);
  if (!target || !["Backspace", "Delete"].includes(key)) return false;
  target.focus?.();
  if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement) {
    const value = target.value || "";
    let start = Number.isFinite(target.selectionStart) ? target.selectionStart : value.length;
    let end = Number.isFinite(target.selectionEnd) ? target.selectionEnd : start;
    if (start === end && key === "Backspace" && start > 0) start -= 1;
    if (start === end && key === "Delete" && end < value.length) end += 1;
    target.value = `${value.slice(0, start)}${value.slice(end)}`;
    target.setSelectionRange?.(start, start);
    dispatchRemoteControlEditEvents(target, key === "Backspace" ? "deleteContentBackward" : "deleteContentForward", "");
    return true;
  }
  if (target.isContentEditable) {
    target.textContent = key === "Backspace" ? (target.textContent || "").slice(0, -1) : target.textContent || "";
    dispatchRemoteControlEditEvents(target, key === "Backspace" ? "deleteContentBackward" : "deleteContentForward", "");
    return true;
  }
  return false;
}

function scrollableRemoteControlElement(element) {
  let node = element;
  while (node && node !== document.body) {
    const style = window.getComputedStyle(node);
    const canScroll = /(auto|scroll)/.test(`${style.overflow}${style.overflowY}${style.overflowX}`)
      && (node.scrollHeight > node.clientHeight || node.scrollWidth > node.clientWidth);
    if (canScroll) return node;
    node = node.parentElement;
  }
  return document.scrollingElement || document.documentElement;
}

function remoteControlScrollDeltas(action = {}) {
  const deltaX = Number(action.delta_x ?? action.deltaX ?? 0);
  const deltaY = Number(action.delta_y ?? action.deltaY ?? 0);
  return {
    x: Number.isFinite(deltaX) ? deltaX : 0,
    y: Number.isFinite(deltaY) ? deltaY : 0,
  };
}

function applyRemoteControlCanvasWheelZoom(action = {}, element = null) {
  const viewport = els.spaceViewport;
  const source = remoteControlAppElement(element);
  if (!viewport || !source || (source !== viewport && !viewport.contains(source))) return false;
  const deltas = remoteControlScrollDeltas(action);
  const widget = source.closest?.(".widget");
  if (widget && widgetWheelScrollableElement(source, widget, deltas)) return false;
  if (spaceDistanceGestureBlocked(source)) {
    remoteControlRecordAction("received", "scroll contained");
    return true;
  }
  if (!source.closest?.(".space-viewport,.space-board,#spaceCanvas,.app-layer")) return false;
  const point = remoteControlActionPoint(action);
  const anchor = point ? viewportGestureAnchor(point.x, point.y) : null;
  if (!anchor) return true;
  const delta = deltas.y;
  if (Math.abs(delta) < 0.5) return true;
  stopSpacePanMomentum();
  const previous = canvasDistance();
  const next = previous * Math.exp(-delta * 0.0012);
  const applied = setCanvasDistanceAround(next, anchor, {
    origin: "remote-wheel",
    persist: false,
    render: false,
    layout: false,
    renderMiniMap: false,
    zoomInfo: true,
  });
  if (applied !== previous) {
    setSpaceZoomInfoVisible(true);
    scheduleCanvasDistanceCommit("remote-wheel");
    scheduleSpaceZoomMiniMapHide();
    remoteControlRecordAction("received", "canvas zoom");
  }
  return true;
}

function applyRemoteControlAction(action = {}, eventId = "") {
  const grant = state.remoteControl.activeGrant;
  if (!grant || remoteControlExpired(grant)) {
    state.remoteControl.activeGrant = null;
    renderRemoteControlChrome();
    return;
  }
  const type = cleanText(action.type, "");
  const baseElement = remoteControlElementFromAction(action);
  const target = remoteControlTargetAllowed(baseElement, type);
  const appElement = remoteControlAppElement(baseElement);
  const pointerAction = Boolean(remoteControlPointerEventName(type));
  const clickTarget = type === "click" ? remoteControlClickTarget(baseElement) : null;
  if ((!target && !clickTarget && type !== "scroll" && type !== "insert_text" && !pointerAction) || (type === "scroll" && !appElement)) return;
  state.remoteControl.suppressEvents = true;
  try {
    if (pointerAction) {
      if (dispatchRemoteControlPointerAction(action, baseElement) && type !== "pointer_move") remoteControlRecordAction("received", type);
    } else if (type === "click" && clickTarget) {
      if (!remoteControlSuppressDuplicateExplicitClick(action)) dispatchRemoteControlClick(baseElement, action);
    } else if (type === "set_value") {
      if (setRemoteControlElementValue(target, action.value)) remoteControlRecordAction("received", "text input");
    } else if (type === "insert_text") {
      if (insertRemoteControlText(baseElement, action.text)) remoteControlRecordAction("received", "text input");
    } else if (type === "scroll") {
      if (applyRemoteControlCanvasWheelZoom(action, appElement)) return;
      const deltas = remoteControlScrollDeltas(action);
      const scroller = scrollableRemoteControlElement(appElement);
      scroller.scrollBy({
        left: deltas.x,
        top: deltas.y,
        behavior: "auto",
      });
      remoteControlRecordAction("received", "scroll");
    } else if (type === "key" && target) {
      const key = cleanText(action.key, "");
      if (!["Enter", "Escape", "Tab", "Backspace", "Delete", "ArrowUp", "ArrowDown", "ArrowLeft", "ArrowRight"].includes(key)) return;
      if (applyRemoteControlEditKey(target, key)) {
        remoteControlRecordAction("received", `key ${key}`);
        return;
      }
      target.dispatchEvent(new KeyboardEvent("keydown", { key, bubbles: true, cancelable: true }));
      if (key === "Enter" && target.matches?.("button, summary")) target.click?.();
      remoteControlRecordAction("received", `key ${key}`);
    }
  } finally {
    state.remoteControl.appliedEventIds.add(eventId);
    window.setTimeout(() => {
      state.remoteControl.suppressEvents = false;
    }, 0);
  }
}

function handleRemoteControlAction(event) {
  const eventId = cleanText(event.id, "");
  if (eventId && state.remoteControl.appliedEventIds.has(eventId)) return;
  const grant = state.remoteControl.activeGrant;
  if (!grant) return;
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  if (payload.schema && payload.schema !== REMOTE_CONTROL_SCHEMA) return;
  if (cleanText(payload.grant_id, "") !== grant.grant_id || cleanText(payload.token, "") !== grant.token) return;
  if (cleanText(event.author_user_id, "") !== grant.controller_user_id) return;
  if (grant.controller_device_id && cleanText(payload.from_device_id || payload.fromDeviceId, "") !== grant.controller_device_id) return;
  const targetUserId = cleanText(payload.target_user_id, "");
  if (targetUserId && targetUserId !== cleanText(state.authUser?.id, "")) return;
  const targetDeviceId = cleanText(payload.target_device_id || payload.targetDeviceId, "");
  if (targetDeviceId && targetDeviceId !== remoteControlCurrentDeviceId()) return;
  applyRemoteControlAction(payload.action || {}, eventId);
}

function remoteControlActionBase(event, target = event?.target) {
  const element = remoteControlTargetAllowed(target, "send");
  if (!element || element.closest?.("[data-remote-control]")) return null;
  return {
    selector: remoteControlSelectorForElement(element),
    x_ratio: Number.isFinite(event?.clientX) ? clamp(event.clientX / Math.max(1, window.innerWidth), 0, 1) : undefined,
    y_ratio: Number.isFinite(event?.clientY) ? clamp(event.clientY / Math.max(1, window.innerHeight), 0, 1) : undefined,
  };
}

function remoteControlShouldSend(event) {
  const controller = state.remoteControl.activeController;
  if (!controller || remoteControlExpired(controller)) {
    if (controller) state.remoteControl.activeController = null;
    renderRemoteControlChrome();
    return false;
  }
  if (state.remoteControl.suppressEvents || !event?.isTrusted) return false;
  if (event.target?.closest?.("[data-remote-control]")) return false;
  return Boolean(document.querySelector("#app")?.contains(event.target));
}

function sendRemoteControlAction(action) {
  const controller = state.remoteControl.activeController;
  if (!controller || !action?.type) return;
  state.remoteControl.actionSeq += 1;
  const seq = state.remoteControl.actionSeq;
  if (action.type !== "pointer_move") {
    remoteControlRecordAction("sent", ["set_value", "insert_text"].includes(action.type) ? "text input" : action.type);
  }
  state.remoteControl.sendQueue = state.remoteControl.sendQueue
    .catch(() => {})
    .then(() => appendRemoteControlSyncEvent({
      peerUserId: controller.target_user_id,
      conversationId: controller.conversation_id,
      kind: "remote-control-action",
      payload: {
        grant_id: controller.grant_id,
        token: controller.token,
        request_id: controller.request_id || "",
        target_user_id: controller.target_user_id,
        target_device_id: controller.target_device_id || "",
        from_device_id: controller.from_device_id || remoteControlCurrentDeviceId(),
        seq,
        action,
      },
    }))
    .catch((error) => {
      remoteControlRecordAction("error", error.message || String(error));
    });
}

function handleRemoteControlLocalClick(event) {
  if (!remoteControlShouldSend(event)) return;
  const base = remoteControlActionBase(event);
  if (!base) return;
  sendRemoteControlAction({ ...base, type: "click" });
}

function handleRemoteControlLocalInput(event) {
  if (!remoteControlShouldSend(event)) return;
  const target = remoteControlTargetAllowed(event.target, "set_value");
  if (!target) return;
  const value = target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement
    ? target.value
    : target.isContentEditable ? target.textContent || "" : "";
  sendRemoteControlAction({
    ...remoteControlActionBase(event, target),
    type: "set_value",
    value: String(value).slice(0, 4000),
  });
}

function handleRemoteControlLocalWheel(event) {
  if (!remoteControlShouldSend(event)) return;
  const now = remoteControlNow();
  if (now - state.remoteControl.lastWheelAt < REMOTE_CONTROL_WHEEL_MIN_MS) return;
  state.remoteControl.lastWheelAt = now;
  sendRemoteControlAction({
    ...remoteControlActionBase(event),
    type: "scroll",
    delta_x: clamp(Number(event.deltaX || 0), -800, 800),
    delta_y: clamp(Number(event.deltaY || 0), -800, 800),
  });
}

function handleRemoteControlLocalKeydown(event) {
  if (!remoteControlShouldSend(event)) return;
  const key = cleanText(event.key, "");
  if (!["Enter", "Escape", "Tab", "Backspace", "Delete", "ArrowUp", "ArrowDown", "ArrowLeft", "ArrowRight"].includes(key)) return;
  sendRemoteControlAction({
    ...remoteControlActionBase(event),
    type: "key",
    key,
  });
}

function installRemoteControlCapture() {
  if (state.remoteControl.captureInstalled) return;
  state.remoteControl.captureInstalled = true;
  document.addEventListener("click", handleRemoteControlLocalClick, true);
  document.addEventListener("input", handleRemoteControlLocalInput, true);
  document.addEventListener("wheel", handleRemoteControlLocalWheel, { capture: true, passive: true });
  document.querySelector("#app")?.addEventListener("keydown", handleRemoteControlLocalKeydown, true);
}

function handleRemoteControlSyncEvent(event) {
  const kind = remoteControlKind(event.kind);
  if (kind === "remote-control-request") handleRemoteControlRequest(event);
  else if (kind === "remote-control-response") handleRemoteControlResponse(event);
  else if (kind === "remote-control-action") handleRemoteControlAction(event);
  else if (kind === REMOTE_CONTROL_VIEWPORT_FRAME_KIND) handleRemoteControlFrame(event);
  else if (kind === "remote-control-stop") handleRemoteControlStop(event);
}

function hideAgentPersonContextMenu(options = {}) {
  if (!options.skipHistory && closeUiNavigationLayer("agent-person-menu")) return;
  document.querySelector("[data-agent-person-context-menu]")?.remove();
  if (!options.skipStack) closeUiNavigationLayer("agent-person-menu", { skipHistory: true, replaceHistory: true });
}

function agentPersonContextMenuButton(label, handler) {
  const button = document.createElement("button");
  button.type = "button";
  button.setAttribute("role", "menuitem");
  button.textContent = label;
  button.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    hideAgentPersonContextMenu({ skipHistory: true });
    handler();
  });
  return button;
}

function showAgentPersonContextMenu(user, event) {
  event.preventDefault();
  event.stopPropagation();
  if (!isAdminUser() || !user || socialUserId(user) === cleanText(state.authUser?.id, "")) return;
  hideAgentPersonContextMenu({ skipHistory: true, skipStack: true });
  const menu = document.createElement("div");
  menu.className = "app-context-menu agent-person-context-menu";
  menu.dataset.agentPersonContextMenu = "true";
  menu.setAttribute("role", "menu");
  menu.setAttribute("aria-label", `${socialUserLabel(user, "User")} actions`);
  menu.append(
    agentPersonContextMenuButton("Access interface", () => void requestRemoteControl(user, { adminSupport: true })),
    agentPersonContextMenuButton("Grant Flux", () => openCreditGrantModal(user))
  );
  document.body.append(menu);
  positionFixedMenu(menu, event);
  pushUiNavigationLayer("agent-person-menu", () => hideAgentPersonContextMenu({ skipHistory: true, skipStack: true }));
  recordUserEvent("agent.person_context_menu_requested", {
    target: `user:${socialUserId(user)}`,
    summary: `Opened person menu for ${socialUserLabel(user, "user")}`,
    data: { user_id: socialUserId(user), admin: true },
  });
}

function peopleRow(user, options = {}) {
  const id = socialUserId(user);
  const row = document.createElement("article");
  row.className = `agent-person-row ${options.kind || "person"}`;
  if (options.unread) row.classList.add("has-unread");
  const avatar = document.createElement("span");
  avatar.className = "agent-person-avatar";
  avatar.textContent = socialUserLabel(user, "P").slice(0, 1).toUpperCase();
  avatar.setAttribute("aria-hidden", "true");
  const copy = document.createElement("div");
  copy.className = "agent-person-copy";
  const title = document.createElement("strong");
  title.textContent = socialUserLabel(user, "Person");
  const meta = document.createElement("span");
  meta.textContent = options.meta || id;
  copy.append(title, meta);
  if (options.unread) {
    const unread = document.createElement("span");
    unread.className = "agent-person-unread";
    unread.textContent = String(Math.min(99, options.unread));
    copy.append(unread);
  }
  row.append(avatar, copy);
  if (options.action) row.append(options.action);
  if (options.onOpen) {
    row.tabIndex = 0;
    row.addEventListener("click", () => options.onOpen());
    row.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        options.onOpen();
      }
    });
  } else if (options.openDirect && id) {
    row.tabIndex = 0;
    row.addEventListener("click", () => openDirectChat(user));
    row.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        openDirectChat(user);
      }
    });
  }
  if (isAdminUser() && id && id !== cleanText(state.authUser?.id, "") && cleanText(user?.role, "user") !== "admin") {
    row.addEventListener("contextmenu", (event) => showAgentPersonContextMenu(user, event));
  }
  return row;
}

function peopleActionButton(label, title, handler) {
  const button = document.createElement("button");
  button.className = "icon-button agent-person-action";
  button.type = "button";
  button.title = title;
  button.setAttribute("aria-label", title);
  const icon = document.createElement("span");
  icon.className = `agent-icon ${label}`;
  icon.setAttribute("aria-hidden", "true");
  button.append(icon);
  button.addEventListener("click", (event) => {
    event.stopPropagation();
    handler();
  });
  return button;
}

function peopleActionGroup(...buttons) {
  const group = document.createElement("div");
  group.className = "agent-person-actions";
  group.replaceChildren(...buttons.filter(Boolean));
  return group;
}

function renderAgentPeoplePanel() {
  if (!els.agentPeoplePanel || state.agentView !== "people") return;
  const admin = isAdminUser();
  if (els.agentPeopleSearchInput) {
    els.agentPeopleSearchInput.placeholder = "id or email";
  }
  if (els.agentPeopleSearchButton) {
    els.agentPeopleSearchButton.disabled = !state.authUser || state.agentPeople.searchBusy;
    const searchTitle = "Add friend";
    els.agentPeopleSearchButton.title = searchTitle;
    els.agentPeopleSearchButton.setAttribute("aria-label", searchTitle);
  }
  if (els.agentPeopleStatus) {
    const count = (state.agentPeople.friendships || []).length + activeSharedSpaceMembers().length;
    els.agentPeopleStatus.textContent = state.agentPeople.busy ? "Loading" : state.agentPeople.status || `${count} people`;
  }
  if (!els.agentPeopleList) return;
  if (state.agentPeople.busy && !(state.agentPeople.friendships || []).length) {
    els.agentPeopleList.replaceChildren(metric("People", "Loading"));
    return;
  }
  const friendships = Array.isArray(state.agentPeople.friendships) ? state.agentPeople.friendships : [];
  const sharedSpaceRows = [];
  const sharedSpace = sharedUserSpaceForPanel();
  const sharedRoom = activeSharedRoom();
  if (sharedSpace?.shared_space_id) {
    const unread = sharedSpaceUnreadCount(sharedSpace.shared_space_id);
    sharedSpaceRows.push(peopleRow({
      id: sharedSpace.shared_space_id,
      label: sharedRoom?.title || sharedSpace.title || "Shared space",
    }, {
      kind: "shared-chat",
      meta: unread ? `${unread} unread` : "space chat",
      unread,
      onOpen: () => openSharedSpaceChat(sharedSpace.shared_space_id),
    }));
  }
  const friends = [];
  const inbound = [];
  const outbound = [];
  for (const friendship of friendships) {
    const user = friendshipUser(friendship);
    const status = cleanText(friendship.status, "pending");
    if (status === "pending" && friendship.direction === "incoming") {
      inbound.push(peopleRow(user, {
        kind: "pending inbound",
        meta: "wants to connect",
        action: peopleActionGroup(
          peopleActionButton("agent-icon-plus", `Accept ${socialUserLabel(user, "friend")}`, () => void respondToFriendship(friendship, "accepted")),
          peopleActionButton("agent-icon-close", `Decline ${socialUserLabel(user, "friend")}`, () => void respondToFriendship(friendship, "declined"))
        ),
      }));
      continue;
    }
    if (status === "pending" && friendship.direction === "outgoing") {
      outbound.push(peopleRow(user, {
        kind: "pending outbound",
        meta: "request sent",
        action: peopleActionButton("agent-icon-close", `Cancel request to ${socialUserLabel(user, "friend")}`, () => void respondToFriendship(friendship, "canceled")),
      }));
      continue;
    }
    if (status === "accepted") {
      const unread = conversationUnreadCount(socialUserId(user));
      friends.push(peopleRow(user, {
        kind: "friend",
        meta: unread ? `${unread} unread` : "friend",
        unread,
        action: peopleActionGroup(
          peopleActionButton("agent-icon-control", `Request control from ${socialUserLabel(user, "friend")}`, () => void requestRemoteControl(user)),
          peopleActionButton("agent-icon-close", `Remove ${socialUserLabel(user, "friend")}`, () => void respondToFriendship(friendship, "removed"))
        ),
        openDirect: true,
      }));
    }
  }
  const members = [];
  for (const member of activeSharedSpaceMembers()) {
    if (member.current) continue;
    const friendship = friendshipByUserId(member.id);
    if (friendship?.status === "accepted") continue;
    const addAction = peopleActionButton("agent-icon-plus", `Add ${socialUserLabel(member, "member")}`, () => void requestFriendshipByUserId(member.id));
    const action = admin
      ? peopleActionGroup(
        addAction,
        peopleActionButton("agent-icon-control", `Request support control from ${socialUserLabel(member, "member")}`, () => void requestRemoteControl(member, { adminSupport: true }))
      )
      : addAction;
    members.push(peopleRow(member, { kind: "member", meta: "space member", action }));
  }
  const sections = [
    ...(sharedSpaceRows.length ? [peopleSection("Shared chat", sharedSpaceRows)] : []),
    peopleSection("Friends", friends, state.authUser ? "No friends yet" : "Sign in required"),
    peopleSection("Pending inbound", inbound, "No incoming requests"),
    peopleSection("Pending outbound", outbound, "No sent requests"),
  ];
  if (members.length) sections.push(peopleSection("In this space", members));
  els.agentPeopleList.replaceChildren(...sections);
  updatePeopleButtonState();
}

function friendshipKeyMap(friendships) {
  return new Map((friendships || []).map((friendship) => [String(friendship.id || ""), friendship]).filter(([id]) => id));
}

function acceptedFriendUserIds(friendships = state.agentPeople.friendships) {
  return new Set((friendships || [])
    .filter((friendship) => friendship.status === "accepted")
    .map((friendship) => socialUserId(friendshipUser(friendship)))
    .filter(Boolean));
}

function activeDirectFriendshipAccepted(friendships = state.agentPeople.friendships) {
  const session = activeAgentSession();
  if (session.kind !== "direct") return true;
  return acceptedFriendUserIds(friendships).has(socialUserId(session.peer));
}

function notifyFriendshipChanges(previous, next, origin = "sync") {
  if (origin === "cache") return;
  const before = friendshipKeyMap(previous);
  for (const friendship of next || []) {
    const old = before.get(String(friendship.id || ""));
    const user = friendshipUser(friendship);
    const label = socialUserLabel(user, "Someone");
    if (!old && friendship.status === "pending" && friendship.direction === "incoming") {
      pushSocialToast("friend", "Friend request", label, `friend:${friendship.id}:incoming`);
    } else if (old && old.status !== friendship.status && friendship.status === "accepted") {
      pushSocialToast("friend", "Friend accepted", label, `friend:${friendship.id}:accepted`);
    }
  }
}

async function persistPeopleCache() {
  await state.clientFirstStore.put("people", {
    id: "friendships",
    updated_at: state.agentPeople.loadedAt || new Date().toISOString(),
    friendships: state.agentPeople.friendships,
    members: state.agentPeople.members,
    unreadByConversation: state.agentPeople.unreadByConversation,
    readCursorByConversation: state.agentPeople.readCursorByConversation,
    syncCursor: state.agentPeople.syncCursor,
  }).catch(() => {});
}

async function loadAgentPeople(origin = "auto", options = {}) {
  if (!state.authUser || state.agentPeople.busy) return;
  const silent = Boolean(options.silent);
  state.agentPeople.busy = !silent;
  renderAgentPeoplePanel();
  try {
    const payload = await fetchJson("/account/friends", { timeoutMs: 8000 });
    const previous = state.agentPeople.friendships || [];
    state.agentPeople.friendships = Array.isArray(payload.friendships) ? payload.friendships : [];
    state.agentPeople.members = activeSharedSpaceMembers();
    state.agentPeople.loadedAt = new Date().toISOString();
    state.agentPeople.status = `${state.agentPeople.friendships.length} friends`;
    notifyFriendshipChanges(previous, state.agentPeople.friendships, origin);
    if (!activeDirectFriendshipAccepted(state.agentPeople.friendships)) switchToMainAgentChat();
    await persistPeopleCache();
    if (!silent) {
      recordUserEvent("agent.people_loaded", {
        target: "agent-people",
        summary: "Loaded people list",
        data: { origin, friendships: state.agentPeople.friendships.length, members: state.agentPeople.members.length },
      });
    }
  } catch (error) {
    if (!silent) state.agentPeople.status = error.message;
    recordUserEvent("agent.people_error", {
      target: "agent-people",
      summary: error.message,
      data: { origin, error: error.message },
    });
  } finally {
    state.agentPeople.busy = false;
    renderAgentPeoplePanel();
  }
}

async function requestAdminSupportControlByQuery(query = "") {
  const value = cleanText(query, "");
  if (!value || !isAdminUser()) return;
  const params = new URLSearchParams({ q: value });
  const payload = await fetchJson(`/account/users/lookup?${params.toString()}`, { timeoutMs: 8000 });
  const user = payload.user && typeof payload.user === "object" ? payload.user : null;
  if (!user || !socialUserId(user)) throw new Error("That user was not found.");
  await requestRemoteControl(user, { adminSupport: true });
}

async function submitAgentPeopleSearch(event) {
  event.preventDefault();
  const query = cleanText(els.agentPeopleSearchInput?.value || "", "");
  if (!query || state.agentPeople.searchBusy) return;
  state.agentPeople.searchBusy = true;
  state.agentPeople.status = "Adding";
  renderAgentPeoplePanel();
  try {
    await fetchJson("/account/friends", {
      method: "POST",
      timeoutMs: 8000,
      body: { query },
    });
    if (els.agentPeopleSearchInput) els.agentPeopleSearchInput.value = "";
    state.agentPeople.status = "Added";
    await loadAgentPeople("add");
  } catch (error) {
    state.agentPeople.status = error.message;
    recordUserEvent("agent.friend_add_error", {
      target: "agent-people",
      summary: error.message,
      data: { query, error: error.message },
    });
  } finally {
    state.agentPeople.searchBusy = false;
    renderAgentPeoplePanel();
  }
}

async function requestFriendshipByUserId(userId) {
  const target = cleanText(userId, "");
  if (!target || state.agentPeople.searchBusy) return;
  state.agentPeople.searchBusy = true;
  renderAgentPeoplePanel();
  try {
    await fetchJson("/account/friends", {
      method: "POST",
      timeoutMs: 8000,
      body: { user_id: target },
    });
    await loadAgentPeople("member-add");
  } catch (error) {
    state.agentPeople.status = error.message;
  } finally {
    state.agentPeople.searchBusy = false;
    renderAgentPeoplePanel();
  }
}

async function respondToFriendship(friendship, response) {
  if (!friendship?.id) return;
  try {
    await fetchJson("/account/friends/respond", {
      method: "POST",
      timeoutMs: 8000,
      body: { friendship_id: friendship.id, response },
    });
    await loadAgentPeople("respond");
  } catch (error) {
    state.agentPeople.status = error.message;
    renderAgentPeoplePanel();
  }
}

function openDirectChat(user) {
  const peerId = socialUserId(user);
  if (!peerId) return;
  const peer = {
    id: peerId,
    label: socialUserLabel(user, "Person"),
    email: cleanText(user?.email, ""),
  };
  const conversationId = directConversationId(peerId);
  let session = state.agentSessions.find((item) => item.kind === "direct" && item.peer?.id === peerId);
  if (!session) {
    session = createAgentSession(peer.label, { kind: "direct", peer, conversation_id: conversationId });
    state.agentSessions.unshift(session);
  } else {
    session.peer = { ...session.peer, ...peer };
    session.conversation_id = session.conversation_id || conversationId;
  }
  state.activeAgentSessionId = session.id;
  markConversationRead(session.conversation_id);
  clearSocialToasts("message", session.conversation_id);
  saveAgentSessions();
  saveActiveAgentSessionPreference();
  setAgentView("chat", { keepActiveSession: true });
  setAgentOpen(true);
  renderAgentSessions();
  renderAgentMessages({ forceBottom: true });
  void loadDirectChatEvents(session).catch(() => {});
  window.setTimeout(() => els.agentInput?.focus(), 0);
  recordUserEvent("agent.direct_chat_opened", {
    target: `user:${peerId}`,
    summary: `Opened DM with ${peer.label}`,
    data: { peer_user_id: peerId, conversation_id: session.conversation_id },
  });
}

function sharedSpaceUserLabel(userId) {
  const id = cleanText(userId, "");
  if (!id) return "Someone";
  const room = activeSharedRoom();
  const entries = [
    ...(Array.isArray(room?.members) ? room.members : []),
    ...(Array.isArray(room?.presence) ? room.presence : []),
  ];
  const match = entries.find((entry) => socialUserId(entry) === id || cleanText(entry?.user_id, "") === id);
  return match ? socialUserLabel(match, id) : id === cleanText(state.authUser?.id, "") ? publicUserLabel(state.authUser) : id;
}

function sharedSpaceSessionForId(sharedSpaceId) {
  const id = cleanText(sharedSpaceId, "");
  return state.agentSessions.find((session) => session.kind === "shared-space" && session.shared_space_id === id) || null;
}

function openSharedSpaceChat(sharedSpaceId = sharedUserSpaceForPanel()?.shared_space_id || "") {
  const id = cleanText(sharedSpaceId, "");
  if (!id) return;
  const space = state.userSpaces.find((item) => item.shared_space_id === id) || sharedUserSpaceForPanel();
  const room = state.sharedRooms[id] || null;
  const title = room?.title || space?.title || "Space chat";
  const conversationId = sharedSpaceConversationId(id);
  let session = sharedSpaceSessionForId(id);
  if (!session) {
    session = createAgentSession(title, {
      kind: "shared-space",
      shared_space_id: id,
      conversation_id: conversationId,
    });
    state.agentSessions.unshift(session);
  } else {
    session.title = title;
    session.conversation_id = session.conversation_id || conversationId;
  }
  state.activeAgentSessionId = session.id;
  markConversationRead(session.conversation_id);
  clearSocialToasts("message", session.conversation_id);
  saveAgentSessions();
  saveActiveAgentSessionPreference();
  setAgentView("chat", { keepActiveSession: true });
  setAgentOpen(true);
  renderAgentSessions();
  renderAgentMessages({ forceBottom: true });
  void syncSharedSpaceChatEvents(id, "open").catch(() => {});
  window.setTimeout(() => els.agentInput?.focus(), 0);
  recordUserEvent("agent.shared_space_chat_opened", {
    target: `shared-space:${id}`,
    summary: `Opened shared chat for ${title}`,
    data: { shared_space_id: id, conversation_id: session.conversation_id },
  });
}

async function loadDirectChatEvents(session = activeAgentSession()) {
  if (!session || session.kind !== "direct" || !session.conversation_id) return;
  const after = cleanText(session.sync_cursor || "", "");
  const query = new URLSearchParams({
    conversation_id: session.conversation_id,
    limit: "120",
  });
  if (after) query.set("after_id", after);
  const payload = await fetchJson(`/sync/events?${query.toString()}`, { timeoutMs: 8000 });
  const events = Array.isArray(payload.events) ? payload.events : [];
  const changed = await mergeDirectSyncEvents(events, { notify: false });
  if (payload.cursor) session.sync_cursor = String(payload.cursor);
  if (changed) {
    session.updated_at = new Date().toISOString();
    saveAgentSessions();
    renderAgentMessages();
  }
  markConversationRead(session.conversation_id);
}

function eventTimestamp(event) {
  return Number.isFinite(Number(event.created_at)) ? new Date(Number(event.created_at) * 1000).toISOString() : new Date().toISOString();
}

function directMessageFromSyncEvent(event) {
  const currentUserId = cleanText(state.authUser?.id, "");
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  const sticker = payload.sticker && typeof payload.sticker === "object" ? payload.sticker : null;
  return {
    id: `sync_${event.id}`,
    role: cleanText(event.author_user_id, "") === currentUserId ? "user" : "assistant",
    content: cleanText(payload.text || (sticker ? `${sticker.emoji || ""} ${sticker.label || ""}` : ""), ""),
    timestamp: eventTimestamp(event),
    sync_event_id: cleanText(event.id, ""),
    author_user_id: cleanText(event.author_user_id, ""),
    sender_label: cleanText(payload.author_label || payload.sender_label, ""),
    kind: event.kind === "sticker" ? "sticker" : "chat-message",
    sticker,
    pending_state: "sent",
    reactions: {},
  };
}

function directSessionForConversation(conversationId) {
  return state.agentSessions.find((session) => session.kind === "direct" && session.conversation_id === conversationId) || null;
}

function chatSessionForConversation(conversationId) {
  return state.agentSessions.find((session) => socialChatSession(session) && session.conversation_id === conversationId) || null;
}

function directSessionForPeer(peerId) {
  return state.agentSessions.find((session) => session.kind === "direct" && session.peer?.id === peerId) || null;
}

function ensureDirectSessionForConversation(conversationId, event = null) {
  let session = directSessionForConversation(conversationId);
  if (session) return session;
  const currentUserId = cleanText(state.authUser?.id, "");
  const participant = (state.agentPeople.friendships || [])
    .map(friendshipUser)
    .find((user) => conversationId === directConversationId(socialUserId(user)));
  const peerId = socialUserId(participant) || cleanText(event?.author_user_id, "") || "unknown";
  const peer = participant || { id: peerId, label: peerId };
  session = createAgentSession(socialUserLabel(peer, "DM"), {
    kind: "direct",
    peer: { id: peerId, label: socialUserLabel(peer, "DM"), email: cleanText(peer.email, "") },
    conversation_id: conversationId,
  });
  if (peerId === currentUserId) session.title = "Direct chat";
  state.agentSessions.push(session);
  return session;
}

function trimDirectMessages(session) {
  if (!session?.messages || session.messages.length <= DIRECT_CHAT_MESSAGE_CAP) return;
  session.messages = session.messages.slice(-DIRECT_CHAT_MESSAGE_CAP);
}

function applyReactionToMessage(message, event) {
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  const emoji = cleanText(payload.emoji, "");
  const target = cleanText(payload.message_event_id || payload.target_event_id || payload.target_message_id, "");
  if (!emoji || !target || cleanText(message.sync_event_id, "") !== target) return false;
  const userIdValue = cleanText(event.author_user_id, "");
  message.reactions = message.reactions && typeof message.reactions === "object" ? message.reactions : {};
  const users = new Set(Array.isArray(message.reactions[emoji]) ? message.reactions[emoji] : []);
  if (users.has(userIdValue)) users.delete(userIdValue);
  else users.add(userIdValue);
  if (users.size) message.reactions[emoji] = Array.from(users);
  else delete message.reactions[emoji];
  return true;
}

async function persistDirectSession(session) {
  if (!session?.conversation_id) return;
  trimDirectMessages(session);
  const retainedMessageIds = new Set((session.messages || []).map((message) => `${session.conversation_id}:${message.sync_event_id || message.id}`));
  await state.clientFirstStore.put("conversations", {
    id: session.conversation_id,
    kind: "direct",
    peer: session.peer || null,
    shared_space_id: "",
    sync_cursor: session.sync_cursor || "",
    unread_count: Number(state.agentPeople.unreadByConversation?.[session.conversation_id] || 0),
    updated_at: session.updated_at || new Date().toISOString(),
  }).catch(() => {});
  for (const message of session.messages || []) {
    await state.clientFirstStore.put("messages", {
      id: `${session.conversation_id}:${message.sync_event_id || message.id}`,
      conversation_id: session.conversation_id,
      message,
      created_at: message.timestamp || new Date().toISOString(),
    }).catch(() => {});
  }
  const cachedMessages = await state.clientFirstStore.all("messages").catch(() => []);
  await Promise.all(cachedMessages
    .filter((item) => item?.conversation_id === session.conversation_id && !retainedMessageIds.has(item.id))
    .map((item) => state.clientFirstStore.remove("messages", item.id).catch(() => false)));
}

function sharedSpaceMessageFromSyncEvent(event) {
  const currentUserId = cleanText(state.authUser?.id, "");
  const payload = event.payload && typeof event.payload === "object" ? event.payload : {};
  return {
    id: `sync_${event.id}`,
    role: cleanText(event.author_user_id, "") === currentUserId ? "user" : "assistant",
    content: cleanText(payload.text || "", ""),
    timestamp: eventTimestamp(event),
    sync_event_id: cleanText(event.id, ""),
    author_user_id: cleanText(event.author_user_id, ""),
    sender_label: cleanText(payload.author_label || payload.sender_label, sharedSpaceUserLabel(event.author_user_id)),
    kind: "space-message",
    pending_state: "sent",
  };
}

async function persistSharedSpaceSession(session) {
  if (!session?.conversation_id || !session.shared_space_id) return;
  trimDirectMessages(session);
  const retainedMessageIds = new Set((session.messages || []).map((message) => `${session.conversation_id}:${message.sync_event_id || message.id}`));
  await state.clientFirstStore.put("conversations", {
    id: session.conversation_id,
    kind: "shared-space",
    title: session.title || "Space chat",
    shared_space_id: session.shared_space_id,
    sync_cursor: session.sync_cursor || "",
    unread_count: Number(state.agentPeople.unreadByConversation?.[session.conversation_id] || 0),
    updated_at: session.updated_at || new Date().toISOString(),
  }).catch(() => {});
  await state.clientFirstStore.put("syncCursors", {
    id: `shared-space:${session.shared_space_id}`,
    conversation_id: session.conversation_id,
    shared_space_id: session.shared_space_id,
    cursor: session.sync_cursor || "",
    updated_at: new Date().toISOString(),
  }).catch(() => {});
  for (const message of session.messages || []) {
    await state.clientFirstStore.put("messages", {
      id: `${session.conversation_id}:${message.sync_event_id || message.id}`,
      conversation_id: session.conversation_id,
      shared_space_id: session.shared_space_id,
      message,
      created_at: message.timestamp || new Date().toISOString(),
    }).catch(() => {});
  }
  const cachedMessages = await state.clientFirstStore.all("messages").catch(() => []);
  await Promise.all(cachedMessages
    .filter((item) => item?.conversation_id === session.conversation_id && !retainedMessageIds.has(item.id))
    .map((item) => state.clientFirstStore.remove("messages", item.id).catch(() => false)));
}

async function mergeSharedSpaceSyncEvents(sharedSpaceId, events = [], options = {}) {
  const id = cleanText(sharedSpaceId, "");
  if (!id) return false;
  let changed = false;
  const currentUserId = cleanText(state.authUser?.id, "");
  const conversationId = sharedSpaceConversationId(id);
  let session = sharedSpaceSessionForId(id);
  if (!session) {
    const space = state.userSpaces.find((item) => item.shared_space_id === id) || {};
    session = createAgentSession(space.title || "Space chat", {
      kind: "shared-space",
      shared_space_id: id,
      conversation_id: conversationId,
    });
    state.agentSessions.push(session);
  }
  for (const event of events) {
    if (!["chat-message", "message", "space-message"].includes(cleanText(event.kind, ""))) continue;
    session.sync_cursor = String(event.id || session.sync_cursor || "");
    const existingEventIds = new Set((session.messages || []).map((message) => cleanText(message.sync_event_id, "")).filter(Boolean));
    const localId = cleanText(event.payload?.local_message_id, "");
    const existingLocal = localId ? session.messages.find((message) => message.id === localId) : null;
    if (existingLocal) {
      existingLocal.sync_event_id = cleanText(event.id, "");
      existingLocal.pending_state = "sent";
      changed = true;
      continue;
    }
    if (existingEventIds.has(cleanText(event.id, ""))) continue;
    const message = sharedSpaceMessageFromSyncEvent(event);
    if (!message.content) continue;
    session.messages.push(message);
    session.updated_at = new Date().toISOString();
    changed = true;
    const activeSharedChat = activeAgentSession().kind === "shared-space" && activeAgentSession().shared_space_id === id && state.agentView === "chat";
    if (message.author_user_id !== currentUserId && !activeSharedChat) {
      state.agentPeople.unreadByConversation[conversationId] = Number(state.agentPeople.unreadByConversation[conversationId] || 0) + 1;
      if (options.notify !== false) {
        pushSocialToast(
          "message",
          session.title || "Space chat",
          `${message.sender_label}: ${truncateText(message.content, 56)}`,
          `shared-msg:${event.id}`,
          { conversationId }
        );
      }
    }
  }
  if (changed) {
    trimDirectMessages(session);
    saveAgentSessions();
    await persistSharedSpaceSession(session);
    await persistPeopleCache();
    renderAgentSessions();
    renderAgentPeoplePanel();
    updatePeopleButtonState();
  }
  return changed;
}

async function mergeDirectSyncEvents(events = [], options = {}) {
  let changed = false;
  const currentUserId = cleanText(state.authUser?.id, "");
  for (const event of events) {
    const conversationId = cleanText(event.conversation_id, "");
    if (!conversationId) continue;
    if (remoteControlIsKind(event.kind)) {
      handleRemoteControlSyncEvent(event);
      continue;
    }
    const session = ensureDirectSessionForConversation(conversationId, event);
    session.sync_cursor = String(event.id || session.sync_cursor || "");
    if (event.kind === "reaction") {
      const reactionEventId = cleanText(event.id, "");
      session.applied_reaction_event_ids = Array.isArray(session.applied_reaction_event_ids) ? session.applied_reaction_event_ids : [];
      if (reactionEventId && session.applied_reaction_event_ids.includes(reactionEventId)) continue;
      const applied = (session.messages || []).some((message) => applyReactionToMessage(message, event));
      if (applied && reactionEventId) {
        session.applied_reaction_event_ids.push(reactionEventId);
        session.applied_reaction_event_ids = session.applied_reaction_event_ids.slice(-DIRECT_CHAT_MESSAGE_CAP);
      }
      changed = changed || applied;
      continue;
    }
    const existingEventIds = new Set((session.messages || []).map((message) => cleanText(message.sync_event_id, "")).filter(Boolean));
    const localId = cleanText(event.payload?.local_message_id, "");
    const existingLocal = localId ? session.messages.find((message) => message.id === localId) : null;
    if (existingLocal) {
      existingLocal.sync_event_id = cleanText(event.id, "");
      existingLocal.pending_state = "sent";
      changed = true;
      continue;
    }
    if (existingEventIds.has(cleanText(event.id, ""))) continue;
    if (!["chat-message", "message", "sticker"].includes(cleanText(event.kind, ""))) continue;
    const message = directMessageFromSyncEvent(event);
    if (!message.content && !message.sticker) continue;
    session.messages.push(message);
    session.updated_at = new Date().toISOString();
    changed = true;
    const activeDirect = activeAgentSession().kind === "direct" && activeAgentSession().conversation_id === conversationId && state.agentView === "chat";
    if (message.author_user_id !== currentUserId && !activeDirect) {
      state.agentPeople.unreadByConversation[conversationId] = Number(state.agentPeople.unreadByConversation[conversationId] || 0) + 1;
      if (options.notify !== false) {
        pushSocialToast(
          "message",
          socialUserLabel(session.peer, "New message"),
          message.kind === "sticker" && message.sticker ? `${message.sticker.emoji} ${message.sticker.label}` : truncateText(message.content, 64),
          `msg:${event.id}`,
          { conversationId }
        );
      }
    }
  }
  if (changed) {
    state.agentSessions = state.agentSessions.map((session) => {
      if (session.kind !== "direct") return session;
      trimDirectMessages(session);
      return session;
    });
    saveAgentSessions();
    await Promise.all(directSessions().map(persistDirectSession));
    await persistPeopleCache();
    renderAgentSessions();
    renderAgentPeoplePanel();
    updatePeopleButtonState();
  }
  return changed;
}

function markConversationRead(conversationId) {
  const id = cleanText(conversationId, "");
  if (!id) return;
  state.agentPeople.unreadByConversation[id] = 0;
  const session = chatSessionForConversation(id);
  if (session?.sync_cursor) state.agentPeople.readCursorByConversation[id] = session.sync_cursor;
  if (session?.kind === "direct") persistDirectSession(session).catch(() => {});
  if (session?.kind === "shared-space") persistSharedSpaceSession(session).catch(() => {});
  persistPeopleCache().catch(() => {});
  renderAgentPeoplePanel();
  updatePeopleButtonState();
}

async function syncDirectMessages(origin = "poll") {
  if (!state.authUser) return;
  const query = new URLSearchParams({ limit: "120" });
  if (state.agentPeople.syncCursor) query.set("after_id", state.agentPeople.syncCursor);
  try {
    const payload = await fetchJson(`/sync/events?${query.toString()}`, { timeoutMs: 8000 });
    const events = (Array.isArray(payload.events) ? payload.events : [])
      .filter((event) => cleanText(event.conversation_id, "").startsWith("dm-") || remoteControlIsKind(event.kind));
    if (events.length) {
      await mergeDirectSyncEvents(events, { notify: origin !== "startup" && origin !== "cache" });
      state.agentPeople.syncCursor = payload.cursor || events.at(-1)?.id || state.agentPeople.syncCursor;
      await persistPeopleCache();
      if (activeAgentSession().kind === "direct" && state.agentView === "chat") {
        markConversationRead(activeAgentSession().conversation_id);
        renderAgentMessages();
      }
    } else if (payload.cursor) {
      state.agentPeople.syncCursor = payload.cursor;
    }
  } catch (error) {
    if (origin !== "poll") {
      recordUserEvent("agent.direct_sync_error", {
        target: "agent-direct",
        summary: error.message,
        data: { origin, error: error.message },
      });
    }
  }
}

async function syncSharedSpaceChatEvents(sharedSpaceId, origin = "poll") {
  if (!state.authUser || !sharedSpaceId) return;
  const session = sharedSpaceSessionForId(sharedSpaceId);
  const query = new URLSearchParams({
    shared_space_id: sharedSpaceId,
    limit: "120",
  });
  if (session?.sync_cursor) query.set("after_id", session.sync_cursor);
  try {
    const payload = await fetchJson(`/sync/events?${query.toString()}`, { timeoutMs: 8000 });
    const events = Array.isArray(payload.events) ? payload.events : [];
    const changed = await mergeSharedSpaceSyncEvents(sharedSpaceId, events, { notify: origin !== "startup" && origin !== "shared-space-start" });
    const nextSession = sharedSpaceSessionForId(sharedSpaceId);
    if (nextSession && (payload.cursor || events.at(-1)?.id)) {
      nextSession.sync_cursor = payload.cursor || events.at(-1)?.id || nextSession.sync_cursor;
      await persistSharedSpaceSession(nextSession);
    }
    if (activeAgentSession().kind === "shared-space" && activeAgentSession().shared_space_id === sharedSpaceId && state.agentView === "chat") {
      markConversationRead(activeAgentSession().conversation_id);
      if (changed) renderAgentMessages();
    }
  } catch (error) {
    if (origin !== "shared-space-poll") {
      recordUserEvent("agent.shared_space_chat_sync_error", {
        target: `shared-space:${sharedSpaceId}`,
        summary: error.message,
        data: { origin, error: error.message },
      });
    }
  }
}

async function syncSocialLayer(origin = "poll") {
  if (!state.authUser || state.socialSyncBusy) return;
  if (androidNativeBackgroundSyncDeferred(origin)) return;
  state.socialSyncBusy = true;
  try {
    await loadAgentPeople(origin, { silent: origin === "poll" || origin === "focus" });
    if (isAndroidNativeShell()) await androidNativeHydrationYield("social-people");
    await syncDirectMessages(origin);
  } finally {
    state.socialSyncBusy = false;
  }
}

function startSocialSync() {
  if (!state.authUser) return;
  startRemoteControlLiveSocket("social-start");
  if (!state.socialSyncInterval) {
    const pollMs = isAndroidNativeShell() ? Math.max(SOCIAL_SYNC_POLL_MS, ANDROID_NATIVE_BACKGROUND_SYNC_POLL_MS) : SOCIAL_SYNC_POLL_MS;
    state.socialSyncInterval = window.setInterval(() => {
      if (isAndroidNativeShell()) androidNativeAfterQuiet(() => void syncSocialLayer("poll"), "social-poll");
      else void syncSocialLayer("poll");
    }, pollMs);
  }
  if (isAndroidNativeShell()) androidNativeAfterQuiet(() => void syncSocialLayer("startup"), "social-startup");
  else window.setTimeout(() => void syncSocialLayer("startup"), 0);
}

async function loadCachedSocialState() {
  try {
    const people = await state.clientFirstStore.get("people", "friendships");
    if (people) {
      state.agentPeople.friendships = Array.isArray(people.friendships) ? people.friendships : [];
      state.agentPeople.members = Array.isArray(people.members) ? people.members : [];
      state.agentPeople.unreadByConversation = people.unreadByConversation && typeof people.unreadByConversation === "object" ? people.unreadByConversation : {};
      state.agentPeople.readCursorByConversation = people.readCursorByConversation && typeof people.readCursorByConversation === "object" ? people.readCursorByConversation : {};
      state.agentPeople.syncCursor = cleanText(people.syncCursor, "");
    }
    const conversations = await state.clientFirstStore.all("conversations");
    const messages = await state.clientFirstStore.all("messages");
    for (const conversation of conversations) {
      if (!conversation?.id || chatSessionForConversation(conversation.id)) continue;
      if (conversation.kind === "shared-space") {
        const sharedSpaceId = cleanText(conversation.shared_space_id, "");
        if (!sharedSpaceId) continue;
        const session = createAgentSession(conversation.title || "Space chat", {
          kind: "shared-space",
          shared_space_id: sharedSpaceId,
          conversation_id: conversation.id,
        });
        session.sync_cursor = cleanText(conversation.sync_cursor, "");
        session.messages = messages
          .filter((item) => item?.conversation_id === conversation.id && item.message)
          .map((item) => item.message)
          .sort((a, b) => String(a.timestamp || "").localeCompare(String(b.timestamp || "")))
          .slice(-DIRECT_CHAT_MESSAGE_CAP);
        state.agentSessions.push(session);
        continue;
      }
      const peer = conversation.peer && typeof conversation.peer === "object" ? conversation.peer : null;
      if (!peer) continue;
      const session = createAgentSession(socialUserLabel(peer, "DM"), {
        kind: "direct",
        peer,
        conversation_id: conversation.id,
      });
      session.sync_cursor = cleanText(conversation.sync_cursor, "");
      session.messages = messages
        .filter((item) => item?.conversation_id === conversation.id && item.message)
        .map((item) => item.message)
        .sort((a, b) => String(a.timestamp || "").localeCompare(String(b.timestamp || "")))
        .slice(-DIRECT_CHAT_MESSAGE_CAP);
      state.agentSessions.push(session);
    }
    renderAgentPeoplePanel();
    renderAgentSessions();
    updatePeopleButtonState();
  } catch {
    // Cache is an acceleration layer; backend sync will rebuild state.
  }
}

function setAgentSocialPicker(kind) {
  state.agentSocialPicker = kind || "";
  if (els.agentEmojiPicker) els.agentEmojiPicker.hidden = state.agentSocialPicker !== "emoji";
  if (els.agentStickerPicker) els.agentStickerPicker.hidden = state.agentSocialPicker !== "sticker";
}

function renderSocialPickers() {
  if (els.agentEmojiPicker) {
    els.agentEmojiPicker.replaceChildren(...DIRECT_EMOJI_SET.map((emoji) => {
      const button = document.createElement("button");
      button.type = "button";
      button.textContent = emoji;
      button.title = `Insert ${emoji}`;
      button.addEventListener("click", () => insertAgentEmoji(emoji));
      return button;
    }));
  }
  if (els.agentStickerPicker) {
    els.agentStickerPicker.replaceChildren(...DIRECT_STICKERS.map((sticker) => {
      const button = document.createElement("button");
      button.type = "button";
      button.className = "agent-sticker-option";
      button.innerHTML = `<span>${sticker.emoji}</span><strong>${sticker.label}</strong>`;
      button.addEventListener("click", () => void sendDirectSticker(sticker));
      return button;
    }));
  }
}

function insertAgentEmoji(emoji) {
  if (!els.agentInput) return;
  const input = els.agentInput;
  input.focus();
  if (typeof input.setRangeText === "function") {
    input.setRangeText(emoji, input.selectionStart, input.selectionEnd, "end");
  } else {
    input.value += emoji;
  }
  input.dispatchEvent(new Event("input", { bubbles: true }));
  setAgentSocialPicker("");
}

async function sendDirectChatMessage(session, text) {
  const content = String(text ?? "").replace(/\r\n?/g, "\n");
  if (blockSendWhileAttachmentsProcess()) return;
  const attachmentCount = state.agentPendingImages.length + state.agentPendingAttachmentSummaries.length;
  if (!content.trim() && !attachmentCount) return;
  const messageContent = content.trim() ? content : `Attached ${attachmentCount} file${attachmentCount === 1 ? "" : "s"}.`;
  const clientEventId = `direct_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
  const userImages = state.agentPendingImages.map((image) => ({
    data_url: image.data_url,
    name: image.name,
    type: image.type,
    size: image.size,
    width: image.width,
    height: image.height,
    image_card: image.image_card,
    asset: image.asset,
  }));
  const userAttachments = state.agentPendingAttachmentSummaries.map((attachment) => ({
    name: attachment.name,
    type: attachment.type,
    size: attachment.size,
    width: attachment.width,
    height: attachment.height,
    image_card: attachment.image_card,
    asset: attachment.asset,
  }));
  state.agentBusy = true;
  updateAgentSendButton();
  clearAgentPendingImages();
  const message = appendAgentMessage("user", messageContent, {
    images: userImages,
    attachments: userAttachments,
    pending_state: "pending",
    client_event_id: clientEventId,
  });
  clearAgentInput();
  try {
    await state.clientFirstStore.put("messages", {
      id: message.id,
      conversation_id: session.conversation_id,
      peer_user_id: session.peer?.id || "",
      content: messageContent,
      created_at: message.timestamp,
    }).catch(() => {});
    const payload = await fetchJson("/sync/events", {
      method: "POST",
      timeoutMs: 8000,
      body: {
        conversation_id: session.conversation_id || directConversationId(session.peer?.id),
        peer_user_id: session.peer?.id,
        client_event_id: clientEventId,
        kind: "chat-message",
        payload: {
          text: messageContent,
          local_message_id: message.id,
          attachment_count: attachmentCount,
        },
      },
    });
    message.sync_event_id = payload.event?.id || "";
    message.pending_state = "sent";
    session.sync_cursor = payload.event?.id || session.sync_cursor || "";
    saveAgentSessions();
    await persistDirectSession(session);
  } catch (error) {
    message.pending_state = "failed";
    message.error = error.message;
    saveAgentSessions();
    renderAgentMessages();
    state.agentPeople.status = error.message;
    recordUserEvent("agent.direct_message_sync_error", {
      target: `user:${session.peer?.id || ""}`,
      summary: error.message,
      data: { conversation_id: session.conversation_id || "", error: error.message },
    });
  } finally {
    state.agentBusy = false;
    state.agentStopRequested = false;
    updateAgentSendButton();
  }
}

async function sendSharedSpaceChatMessage(session, text) {
  const content = String(text ?? "").replace(/\r\n?/g, "\n");
  if (blockSendWhileAttachmentsProcess()) return;
  const attachmentCount = state.agentPendingImages.length + state.agentPendingAttachmentSummaries.length;
  if (!content.trim() && !attachmentCount) return;
  const messageContent = content.trim() ? content : `Attached ${attachmentCount} file${attachmentCount === 1 ? "" : "s"}.`;
  const clientEventId = `space_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
  state.agentBusy = true;
  updateAgentSendButton();
  clearAgentPendingImages();
  const message = appendAgentMessage("user", messageContent, {
    kind: "space-message",
    author_user_id: cleanText(state.authUser?.id, ""),
    sender_label: publicUserLabel(state.authUser),
    pending_state: "pending",
    client_event_id: clientEventId,
  });
  clearAgentInput();
  try {
    const payload = await fetchJson("/sync/events", {
      method: "POST",
      timeoutMs: 8000,
      body: {
        conversation_id: session.conversation_id || sharedSpaceConversationId(session.shared_space_id),
        shared_space_id: session.shared_space_id,
        client_event_id: clientEventId,
        kind: "space-message",
        payload: {
          text: messageContent,
          local_message_id: message.id,
          author_label: publicUserLabel(state.authUser),
          attachment_count: attachmentCount,
        },
      },
    });
    message.sync_event_id = payload.event?.id || "";
    message.pending_state = "sent";
    session.sync_cursor = payload.event?.id || session.sync_cursor || "";
    saveAgentSessions();
    await persistSharedSpaceSession(session);
  } catch (error) {
    message.pending_state = "failed";
    message.error = error.message;
    saveAgentSessions();
    renderAgentMessages();
    recordUserEvent("agent.shared_space_message_sync_error", {
      target: `shared-space:${session.shared_space_id || ""}`,
      summary: error.message,
      data: { conversation_id: session.conversation_id || "", error: error.message },
    });
  } finally {
    state.agentBusy = false;
    state.agentStopRequested = false;
    updateAgentSendButton();
  }
}

async function sendDirectSticker(sticker) {
  const session = activeAgentSession();
  if (session.kind !== "direct" || !sticker?.id || state.agentBusy) return;
  const clientEventId = `sticker_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 9)}`;
  state.agentBusy = true;
  updateAgentSendButton();
  setAgentSocialPicker("");
  const message = appendAgentMessage("user", `${sticker.emoji} ${sticker.label}`, {
    kind: "sticker",
    sticker,
    pending_state: "pending",
    client_event_id: clientEventId,
  });
  try {
    const payload = await fetchJson("/sync/events", {
      method: "POST",
      timeoutMs: 8000,
      body: {
        conversation_id: session.conversation_id,
        peer_user_id: session.peer?.id,
        client_event_id: clientEventId,
        kind: "sticker",
        payload: {
          text: `${sticker.emoji} ${sticker.label}`,
          sticker,
          local_message_id: message.id,
        },
      },
    });
    message.sync_event_id = payload.event?.id || "";
    message.pending_state = "sent";
    session.sync_cursor = payload.event?.id || session.sync_cursor || "";
    saveAgentSessions();
    await persistDirectSession(session);
    renderAgentMessages();
  } catch (error) {
    message.pending_state = "failed";
    message.error = error.message;
    saveAgentSessions();
    renderAgentMessages();
  } finally {
    state.agentBusy = false;
    updateAgentSendButton();
  }
}

async function sendDirectReaction(message, emoji) {
  const session = activeAgentSession();
  const targetEventId = cleanText(message?.sync_event_id, "");
  if (session.kind !== "direct" || !targetEventId || !emoji) return;
  const clientEventId = `react_${targetEventId}_${emoji}_${Date.now().toString(36)}`;
  try {
    const payload = await fetchJson("/sync/events", {
      method: "POST",
      timeoutMs: 8000,
      body: {
        conversation_id: session.conversation_id,
        peer_user_id: session.peer?.id,
        client_event_id: clientEventId,
        kind: "reaction",
        payload: {
          message_event_id: targetEventId,
          emoji,
        },
      },
    });
    if (payload.event) {
      applyReactionToMessage(message, payload.event);
      const reactionEventId = cleanText(payload.event.id, "");
      session.applied_reaction_event_ids = Array.isArray(session.applied_reaction_event_ids) ? session.applied_reaction_event_ids : [];
      if (reactionEventId && !session.applied_reaction_event_ids.includes(reactionEventId)) {
        session.applied_reaction_event_ids.push(reactionEventId);
        session.applied_reaction_event_ids = session.applied_reaction_event_ids.slice(-DIRECT_CHAT_MESSAGE_CAP);
      }
      session.sync_cursor = payload.event.id || session.sync_cursor || "";
      saveAgentSessions();
      await persistDirectSession(session);
      renderAgentMessages();
    }
  } catch (error) {
    pushSocialToast("error", "Reaction failed", error.message, `reaction-error:${targetEventId}:${emoji}`);
  }
}

function renderAgentSessions() {
  if (!els.agentSessionList) return;
  els.agentSessionList.replaceChildren(
    ...state.agentSessions.map((session) => {
      const button = document.createElement("button");
      button.type = "button";
      button.className = "agent-session-row";
      button.classList.toggle("active", session.id === state.activeAgentSessionId);
      button.dataset.sessionId = session.id;
      const title = document.createElement("strong");
      const meta = document.createElement("span");
      title.textContent = session.title || "Session";
      meta.textContent = session.kind === "direct" ? "DM" : session.kind === "shared-space" ? "Space chat" : `${session.messages?.length || 0} turns`;
      button.append(title, meta);
      button.addEventListener("click", () => {
        switchAgentSession(session.id);
        setAgentBalloon("");
      });
      return button;
    })
  );
}

function switchAgentSession(sessionId) {
  state.activeAgentSessionId = sessionId;
  state.agentView = "chat";
  const session = activeAgentSession();
  if (session.kind === "direct") markConversationRead(session.conversation_id);
  if (session.kind === "shared-space") markConversationRead(session.conversation_id);
  saveActiveAgentSessionPreference();
  renderAgentSessions();
  renderAgentMessages({ forceBottom: true });
}

function newAgentSession() {
  const session = createAgentSession(`Session ${state.agentSessions.length + 1}`);
  state.agentSessions.unshift(session);
  state.activeAgentSessionId = session.id;
  state.agentView = "chat";
  saveAgentSessions();
  saveActiveAgentSessionPreference();
  renderAgentSessions();
  renderAgentMessages({ forceBottom: true });
  setAgentOpen(true);
  window.setTimeout(() => els.agentInput.focus(), 0);
  recordUserEvent("agent.session_created", {
    target: "agent-overlay",
    summary: "Created embedded assistant session",
    data: { session_id: session.id },
  });
}

function renderAgentDiagnostics(diagnostics = {}) {
  if (!els.agentDiagnostics) return;
  const usageBreakdown = agentDiagnosticsTokenUsageBreakdown(diagnostics);
  updateAgentTokenUsage(usageBreakdown.total || null);
  const sessionSummary = agentSessionTokenSummary();
  const measurements = diagnosticsContextMeasurement(diagnostics);
  const directHead = diagnostics.direct_head && typeof diagnostics.direct_head === "object" ? diagnostics.direct_head : {};
  const providerBits = [
    directHead.provider || diagnostics.receiver || diagnostics.source || "",
    directHead.model || diagnostics.model || "",
  ].filter(Boolean);
  const estimatedContextText = formatAgentContextMeasurementSummary(measurements);
  const contextText = state.agentContextString
    || (diagnostics.tools?.length ? diagnostics.tools.join(" ") : "")
    || estimatedContextText
    || (diagnostics.context_estimated_tokens ? `~${diagnostics.context_estimated_tokens} tokens` : "-");
  const rows = [
    ["Last Turn", formatTokenUsageParts(usageBreakdown.total)],
    ["Head", usageBreakdown.head ? formatTokenUsageParts(usageBreakdown.head) : "-"],
    ["Bridge", usageBreakdown.bridge ? formatTokenUsageParts(usageBreakdown.bridge) : "-"],
    ["Session", sessionSummary.usage ? `${formatTokenUsageParts(sessionSummary.usage)} · ${sessionSummary.turns} turns` : "-"],
    ["Envelope", measurements.direct ? `~${compactCount(measurements.direct.estimated_tokens || 0)} est · ${compactCount(measurements.direct.utf8_bytes || 0)} bytes` : "-"],
    ["Dispatch", measurements.dispatch ? `~${compactCount(measurements.dispatch.estimated_tokens || 0)} est` : "-"],
    ["Model", providerBits.length ? providerBits.join(" · ") : "-"],
    ["Turns", Number.isFinite(diagnostics.transcript_turns) ? String(diagnostics.transcript_turns) : "-"],
    ["Context", contextText],
  ];
  els.agentDiagnostics.replaceChildren(
    ...rows.map(([label, value]) => {
      const row = document.createElement("div");
      const term = document.createElement("dt");
      const desc = document.createElement("dd");
      term.textContent = label;
      desc.textContent = value;
      row.append(term, desc);
      return row;
    })
  );
}

function fmtCompactToken(n) {
  if (n == null || !Number.isFinite(n)) return "\u25c8 -";
  if (n < 1000) return `\u25c8 ${n}`;
  const abs = n;
  const [v, unit] = abs >= 1_000_000
    ? [Math.floor(abs / 10_000) / 100, 'M']
    : [Math.floor(abs / 10) / 100, 'K'];
  let s = v.toFixed(2).replace('.', ',');
  s = s.replace(/0$/, ''); // strip trailing zero, keep at least one decimal
  return `\u25c8 ${s}${unit}`;
}

function tokenNumber(value) {
  if (Number.isFinite(value)) return Math.max(0, Math.floor(value));
  if (typeof value === "string") {
    const clean = value.trim().replace(/[, _]/g, "");
    if (/^\d+(\.\d+)?$/.test(clean)) return Math.max(0, Math.floor(Number(clean)));
  }
  return null;
}

function firstTokenNumber(usage, keys) {
  for (const key of keys) {
    const value = tokenNumber(usage?.[key]);
    if (value !== null) return value;
  }
  return null;
}

function normalizeAgentTokenUsage(usage) {
  if (!usage || typeof usage !== "object") return null;
  const prompt = firstTokenNumber(usage, ["prompt_tokens", "input_tokens", "inputTokens", "input_token_count", "inputTokenCount", "promptTokens", "tokens_in", "prompt"]);
  const completion = firstTokenNumber(usage, ["completion_tokens", "output_tokens", "outputTokens", "output_token_count", "outputTokenCount", "completionTokens", "candidatesTokenCount", "tokens_out", "completion"]);
  let total = firstTokenNumber(usage, ["total_tokens", "totalTokens", "total_token_count", "totalTokenCount", "tokens", "total"]);
  const cacheRead = firstTokenNumber(usage, ["cache_read_tokens", "cached_tokens", "cachedTokens", "cached_input_tokens", "cachedInputTokens", "cacheReadInputTokens"]);
  const reasoning = firstTokenNumber(usage, ["reasoning_tokens", "reasoningTokens", "reasoning_output_tokens", "reasoningOutputTokens"]);
  const inputDetails = usage.input_tokens_details && typeof usage.input_tokens_details === "object" ? usage.input_tokens_details : {};
  const outputDetails = usage.output_tokens_details && typeof usage.output_tokens_details === "object" ? usage.output_tokens_details : {};
  const nestedCacheRead = firstTokenNumber(inputDetails, ["cached_tokens", "cache_read_tokens", "cachedTokens"]);
  const nestedReasoning = firstTokenNumber(outputDetails, ["reasoning_tokens", "reasoningTokens"]);
  let input = prompt;
  let output = completion;
  if (total === null && (input !== null || output !== null)) total = (input || 0) + (output || 0);
  if (input === null && total !== null && output !== null) input = Math.max(0, total - output);
  if (output === null && total !== null && input !== null) output = Math.max(0, total - input);
  if (total === null && input === null && output === null) return null;
  return {
    ...usage,
    prompt_tokens: input || 0,
    completion_tokens: output || 0,
    input_tokens: input || 0,
    output_tokens: output || 0,
    total_tokens: total || 0,
    cache_read_tokens: cacheRead ?? nestedCacheRead ?? 0,
    reasoning_tokens: reasoning ?? nestedReasoning ?? 0,
  };
}

function addTokenUsage(a, b) {
  const left = normalizeAgentTokenUsage(a) || {};
  const right = normalizeAgentTokenUsage(b) || {};
  return normalizeAgentTokenUsage({
    input_tokens: Number(left.input_tokens || 0) + Number(right.input_tokens || 0),
    output_tokens: Number(left.output_tokens || 0) + Number(right.output_tokens || 0),
    total_tokens: Number(left.total_tokens || 0) + Number(right.total_tokens || 0),
    cache_read_tokens: Number(left.cache_read_tokens || 0) + Number(right.cache_read_tokens || 0),
    reasoning_tokens: Number(left.reasoning_tokens || 0) + Number(right.reasoning_tokens || 0),
  });
}

function agentSessionTokenSummary(session = activeAgentSession()) {
  const messages = Array.isArray(session?.messages) ? session.messages : [];
  let total = null;
  let turns = 0;
  for (const message of messages) {
    const usage = agentDiagnosticsTokenUsageBreakdown(message?.diagnostics || {}).total;
    if (!usage) continue;
    turns += 1;
    total = addTokenUsage(total, usage);
  }
  return {
    turns,
    usage: total,
  };
}

function agentDiagnosticsTokenUsageBreakdown(diagnostics = {}) {
  const raw = diagnostics && typeof diagnostics === "object" ? diagnostics : {};
  const explicitTotal = normalizeAgentTokenUsage(raw.token_usage_total || raw.total_token_usage);
  const head = normalizeAgentTokenUsage(raw.token_usage_head || raw.head_token_usage);
  const bridge = normalizeAgentTokenUsage(
    raw.token_usage_bridge
      || raw.bridge_token_usage
      || (raw.hermes_dispatch && typeof raw.hermes_dispatch === "object" ? raw.hermes_dispatch.usage : null)
  );
  const exact = normalizeAgentTokenUsage(raw.token_usage);
  const bridgeApiCalls = tokenNumber(bridge?.api_calls);
  const bridgeTrusted = Boolean(
    bridge
      && bridge.usage_scope === "llm_api_call"
      && bridge.usage_accuracy === "provider_exact"
      && bridge.billable !== false
      && (bridgeApiCalls === null || bridgeApiCalls > 0 || bridge.cost_usd || bridge.billable === true)
  );
  const inferredHead = head || (bridge && exact && exact.total_tokens !== bridge.total_tokens ? exact : null);
  const trustedBridge = bridgeTrusted ? bridge : null;
  const total = explicitTotal || (trustedBridge ? addTokenUsage(inferredHead, trustedBridge) : (inferredHead || exact));
  return {
    total: total || null,
    head: inferredHead || (!bridge ? exact : null),
    bridge: trustedBridge,
    bridge_trusted: bridgeTrusted,
  };
}

function formatTokenUsageParts(usage) {
  const normalized = normalizeAgentTokenUsage(usage);
  if (!normalized) return "-";
  const parts = [
    `in ${compactCount(normalized.input_tokens || 0)}`,
    `out ${compactCount(normalized.output_tokens || 0)}`,
    `total ${compactCount(normalized.total_tokens || 0)}`,
  ];
  if (normalized.reasoning_tokens) parts.push(`reason ${compactCount(normalized.reasoning_tokens)}`);
  if (normalized.cache_read_tokens) parts.push(`cached ${compactCount(normalized.cache_read_tokens)}`);
  return parts.join(" ");
}

function diagnosticsContextMeasurement(diagnostics = {}) {
  const direct = diagnostics.context_measurement && typeof diagnostics.context_measurement === "object"
    ? diagnostics.context_measurement
    : null;
  const dispatch = diagnostics.dispatch_context_measurement && typeof diagnostics.dispatch_context_measurement === "object"
    ? diagnostics.dispatch_context_measurement
    : null;
  return { direct, dispatch };
}

function formatAgentContextMeasurementSummary(measurements = {}) {
  const directTokens = tokenNumber(measurements.direct?.estimated_tokens);
  const dispatchTokens = tokenNumber(measurements.dispatch?.estimated_tokens);
  if (directTokens === null && dispatchTokens === null) return "";
  const parts = [];
  if (directTokens !== null) parts.push(`head ~${compactCount(directTokens)} est`);
  if (dispatchTokens !== null) parts.push(`Hermes ~${compactCount(dispatchTokens)} est`);
  const total = Number(directTokens || 0) + Number(dispatchTokens || 0);
  return parts.length > 1 ? `${parts.join(" + ")} = ~${compactCount(total)} est` : parts[0];
}

function updateAgentTokenUsage(usage = state.agentTokenUsage) {
  const normalized = normalizeAgentTokenUsage(usage);
  state.agentTokenUsage = normalized || null;
  if (!els.agentTokenUsage) return;
  const sessionSummary = agentSessionTokenSummary();
  const total = normalized ? normalized.total_tokens : null;
  const sessionTotal = sessionSummary.usage?.total_tokens || 0;
  els.agentTokenUsage.textContent = sessionTotal ? `${fmtCompactToken(total)} / ${compactCount(sessionTotal)}` : fmtCompactToken(total);
  const accuracy = normalized?.usage_accuracy === "estimated" ? "Estimated" : "Exact";
  els.agentTokenUsage.title = normalized
    ? `${accuracy} model token usage for the last turn: ${formatTokenUsageParts(normalized)}. Session exact tokens: ${formatTokenUsageParts(sessionSummary.usage)} across ${sessionSummary.turns} turns.`
    : "Model token usage for the last turn";
}

function agentFileDiffText(file = {}) {
  return cleanText(file.diff_patch || file.patch || file.unified_diff || "", "");
}

function agentFileDiffLines(patch = "") {
  return String(patch || "")
    .replace(/\r\n?/g, "\n")
    .split("\n")
    .map((line) => {
      if (line.startsWith("+++") || line.startsWith("---")) return null;
      if (line.startsWith("+")) return { kind: "now", text: line.slice(1) || " " };
      if (line.startsWith("-")) return { kind: "before", text: line.slice(1) || " " };
      return null;
    })
    .filter(Boolean);
}

function renderAgentFileDiffBalloon(patch = "") {
  const balloon = document.createElement("div");
  balloon.className = "agent-file-diff-balloon";
  const lines = agentFileDiffLines(patch);
  if (!lines.length) {
    const empty = document.createElement("div");
    empty.className = "agent-file-diff-empty";
    empty.textContent = "No changed hunks available.";
    balloon.append(empty);
    return balloon;
  }
  const list = document.createElement("div");
  list.className = "agent-file-diff-lines";
  lines.forEach((line) => {
    const row = document.createElement("div");
    const tag = document.createElement("span");
    const code = document.createElement("code");
    row.className = `agent-file-diff-line is-${line.kind}`;
    tag.className = "agent-file-diff-tag";
    tag.textContent = line.kind === "before" ? "was" : "now";
    code.textContent = line.text;
    row.append(tag, code);
    list.append(row);
  });
  balloon.append(list);
  return balloon;
}

function changedFilesFooter(files = [], message = {}) {
  if (!files.length) return null;
  const checkpoint = message?.diagnostics?.auto_checkpoint || message?.diagnostics?.checkpoint || null;
  const checkpointRef = checkpoint?.ref || "";
  const totals = files.reduce(
    (sum, file) => ({
      additions: sum.additions + (Number.isFinite(file.additions) ? file.additions : 0),
      deletions: sum.deletions + (Number.isFinite(file.deletions) ? file.deletions : 0),
    }),
    { additions: 0, deletions: 0 }
  );
  const details = document.createElement("details");
  const summary = document.createElement("summary");
  details.className = "agent-changed-details";
  if (message?.id) bindAgentDetailsOpenState(details, `changed:${message.id}`);
  summary.className = "agent-changed-summary";
  summary.replaceChildren(
    document.createTextNode(`${files.length} files changed `),
    statSpan(`+${totals.additions}`, "add"),
    document.createTextNode(" "),
    statSpan(`-${totals.deletions}`, "del")
  );
  if (checkpointRef) {
    const stepback = document.createElement("button");
    stepback.type = "button";
    stepback.className = "agent-stepback-button";
    stepback.textContent = "Stepback";
    stepback.title = "Restore the timeline to the point before this run";
    stepback.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      void stepbackTimeline(checkpointRef, message.space_id || activeSpaceStorageId());
    });
    summary.append(stepback);
  }
  const list = document.createElement("div");
  list.className = "agent-file-list";
  list.replaceChildren(
    ...files.map((file) => {
      const patch = agentFileDiffText(file);
      const item = document.createElement(patch ? "details" : "div");
      item.className = "agent-file-row";
      if (patch && message?.id) bindAgentDetailsOpenState(item, `changed-file:${message.id}:${cleanText(file.path || file.full_path || String(file), "")}`);
      const row = document.createElement(patch ? "summary" : "div");
      row.className = "agent-file-row-summary";
      const path = document.createElement("span");
      const stats = document.createElement("span");
      path.className = "agent-file-path";
      stats.className = "agent-file-diff";
      path.textContent = file.full_path || file.path || String(file);
      path.title = patch ? `Show changed hunks for ${path.textContent}` : path.textContent;
      stats.replaceChildren(
        statSpan(`+${Number.isFinite(file.additions) ? file.additions : 0}`, "add"),
        document.createTextNode(" "),
        statSpan(`-${Number.isFinite(file.deletions) ? file.deletions : 0}`, "del")
      );
      row.append(path, stats);
      item.append(row);
      if (patch) {
        item.append(renderAgentFileDiffBalloon(patch));
      }
      return item;
    })
  );
  details.append(summary, list);
  return details;
}

async function stepbackTimeline(ref, spaceId = activeSpaceStorageId()) {
  const checkpointRef = cleanText(ref, "");
  if (!checkpointRef) return;
  if (!window.confirm("Step back this timeline to the point before that run? Current files touched by the run will be restored.")) {
    return;
  }
  const startedAt = performance.now();
  try {
    const payload = await fetchJson("/timeline/stepback", {
      method: "POST",
      timeoutMs: 30000,
      body: {
        ref: checkpointRef,
        space_id: spaceId,
        before_run: true,
      },
    });
    const result = payload.stepback || {};
    state.timeline = null;
    await loadTimeline("stepback").catch(() => {});
    els.taskOutput.textContent = `Timeline stepback restored ${result.restored_paths || 0} paths and removed ${result.deleted_paths || 0}.`;
    recordUserEvent("timeline.stepback_applied", {
      target: "timeline",
      summary: `Stepped back ${spaceId}`,
      data: { ref: checkpointRef, path_count: result.path_count || 0, scope: result.scope || "" },
      duration_ms: performance.now() - startedAt,
    });
  } catch (error) {
    state.lastError = error.message;
    els.taskOutput.textContent = error.message;
    recordUserEvent("timeline.stepback_error", {
      target: "timeline",
      summary: error.message,
      data: { ref: checkpointRef, error: error.message },
      duration_ms: performance.now() - startedAt,
    });
  }
}

function agentTimelineIcon(item = {}) {
  const label = cleanText(item.label, "").toLowerCase();
  const eventType = cleanText(item.event_type, "").toLowerCase();
  const status = cleanText(item.status, "").toLowerCase();
  if (status === "error") return "⚠️";
  if (status === "running") return "⏳";
  if (label === "run.started" || eventType === "run.started") return "▶️";
  if (label === "run.final" || eventType === "run.final") return "🏁";
  if (label === "hermes.dispatch" || eventType === "hermes.dispatch") return "🪽";
  if (label === "tool.started" || eventType === "tool.started") return "🔧";
  if (label === "tool.finished" || eventType === "tool.finished") return "✓";
  if (label.includes("file") || eventType.startsWith("files.")) return "📄";
  if (label.includes("test") || eventType.startsWith("tests.")) return "🧪";
  if (label.includes("proof") || eventType.startsWith("proof.")) return "📋";
  if (label === "tokens.used" || eventType === "tokens.used") return "🔶";
  return "•";
}

function agentMessageRouteSummary(message = {}) {
  const timeline = Array.isArray(message.timeline) ? message.timeline : [];
  const routeEvent = [...timeline].reverse().find((item) => (
    cleanText(item.event_type || item.label, "").toLowerCase() === "route.resolved"
  ));
  const args = routeEvent?.arguments && typeof routeEvent.arguments === "object" ? routeEvent.arguments : {};
  const contract = message.route_contract || args.route_contract || message.kernel_route_proof?.route_contract || {};
  const summary = args.map_summary || message.kernel_route_proof?.summary || {};
  const routeId = cleanText(contract.route_id || summary.route_id || message.diagnostics?.route_id || "", "");
  const owner = cleanText(contract.owner || summary.owner || "", "");
  return {
    route_id: routeId,
    owner,
    label: [routeId, owner].filter(Boolean).join(" / "),
  };
}

function renderAgentTimelineSummary(message) {
  const wrap = document.createElement("div");
  wrap.className = "agent-timeline-summary";
  const objective = document.createElement("span");
  objective.className = "agent-timeline-pill objective";
  objective.textContent = "Objective";
  const route = agentMessageRouteSummary(message);
  const routePill = document.createElement("span");
  routePill.className = "agent-timeline-pill route";
  routePill.textContent = route.route_id ? `Route ${route.route_id}` : "Route pending";
  if (route.label) routePill.title = route.label;
  const current = document.createElement("span");
  current.className = "agent-timeline-pill current";
  current.textContent = message.pending ? (message.phase || "Running") : "Done";
  const evidence = document.createElement("span");
  evidence.className = "agent-timeline-pill evidence";
  const filesCount = Array.isArray(message.changed_files) ? message.changed_files.length : 0;
  evidence.textContent = filesCount ? `${filesCount} files` : "No files";
  const finalStatus = document.createElement("span");
  finalStatus.className = "agent-timeline-pill final";
  finalStatus.textContent = message.agent_run_status === "completed" ? "Final ✓" : "Pending";
  wrap.append(objective, routePill, current, evidence, finalStatus);
  return wrap;
}

function renderAgentTimeline(message) {
  const timeline = Array.isArray(message.timeline) ? message.timeline : [];
  if (!timeline.length) return null;
  const wrap = document.createElement("div");
  wrap.className = "agent-timeline";
  const summary = renderAgentTimelineSummary(message);
  if (summary) wrap.append(summary);
  const rows = document.createElement("div");
  rows.className = "agent-timeline-rows";
  for (const item of timeline) {
    const row = document.createElement("div");
    row.className = `agent-timeline-row ${cleanText(item.status, "done")}`;
    const icon = document.createElement("span");
    icon.className = "agent-timeline-icon";
    icon.textContent = agentTimelineIcon(item);
    const label = document.createElement("span");
    label.className = "agent-timeline-label";
    label.textContent = cleanAgentActionLabel(item, agentActionInnerKind(item));
    const detail = document.createElement("span");
    detail.className = "agent-timeline-detail";
    detail.textContent = cleanText(item.detail, "");
    row.append(icon, label);
    if (detail.textContent) row.append(detail);
    rows.append(row);
  }
  wrap.append(rows);
  return wrap;
}

function agentMessageTokenLedger(message = {}) {
  const ledger = message.token_ledger || message.diagnostics?.token_ledger || null;
  return ledger && typeof ledger === "object" ? ledger : null;
}

function shortLedgerId(value) {
  const text = cleanText(value, "");
  if (!text) return "-";
  if (text.length <= 18) return text;
  return `${text.slice(0, 8)}...${text.slice(-6)}`;
}

function renderAgentTokenLedger(message = {}) {
  const ledger = agentMessageTokenLedger(message);
  if (!ledger) return null;
  const calls = Array.isArray(ledger.calls) ? ledger.calls : [];
  const usage = agentTokenLedgerUsage(ledger);
  if (!calls.length && !usage) return null;
  const details = document.createElement("details");
  details.className = "agent-token-ledger";
  bindAgentDetailsOpenState(details, message?.id ? `token-ledger:${message.id}` : "", Boolean(message.pending), {
    status: message.pending ? "running" : "done",
    autoCloseOnDone: true,
  });
  const summary = document.createElement("summary");
  summary.className = "agent-token-ledger-summary";
  const title = document.createElement("strong");
  title.textContent = "Token ledger";
  const badge = document.createElement("span");
  badge.className = `agent-token-ledger-badge ${ledger.exact === false ? "estimated" : "exact"}`;
  badge.textContent = ledger.exact === false ? "estimated" : "exact";
  const total = document.createElement("span");
  total.className = "agent-token-ledger-total";
  total.textContent = usage ? formatTokenUsageParts(usage) : "-";
  const scope = document.createElement("span");
  scope.className = "agent-token-ledger-scope";
  scope.textContent = [
    `quest ${shortLedgerId(ledger.quest_id || activeAgentSession()?.id || "")}`,
    `turn ${shortLedgerId(calls[0]?.turn_id || message.turn_id || "")}`,
    `${calls.length || Number(ledger.provider_call_count || 0)} calls`,
  ].filter(Boolean).join(" / ");
  summary.append(title, badge, total, scope);
  const list = document.createElement("div");
  list.className = "agent-token-ledger-calls";
  list.replaceChildren(...calls.map((call) => {
    const row = document.createElement("div");
    row.className = `agent-token-ledger-call ${call.exact ? "exact" : "estimated"}`;
    const head = document.createElement("div");
    head.className = "agent-token-ledger-call-head";
    const provider = document.createElement("strong");
    provider.textContent = [call.provider, call.model].map((item) => cleanText(item, "")).filter(Boolean).join(" / ") || "provider call";
    const route = document.createElement("span");
    route.textContent = cleanText(call.route_id, "");
    const callId = document.createElement("code");
    callId.textContent = shortLedgerId(call.provider_call_id);
    head.append(provider, route, callId);
    const metrics = document.createElement("div");
    metrics.className = "agent-token-ledger-metrics";
    const metricRows = call.exact
      ? [
          ["in", call.input_tokens],
          ["out", call.output_tokens],
          ["cached", call.cached_input_tokens],
          ["reason", call.reasoning_tokens],
          ["total", call.total_tokens],
        ]
      : [
          ["est in", call.estimated_input_tokens],
          ["est out", call.estimated_output_tokens],
          ["est total", call.estimated_total_tokens],
        ];
    metricRows
      .filter(([, value]) => tokenNumber(value) !== null)
      .forEach(([label, value]) => {
        const chip = document.createElement("span");
        chip.textContent = `${label} ${compactCount(tokenNumber(value) || 0)}`;
        metrics.append(chip);
      });
    row.append(head, metrics);
    return row;
  }));
  details.append(summary, list);
  return details;
}

function agentActionsChain(message) {
  const rawActions = Array.isArray(message.actions) ? message.actions : [];
  const actions = compactAgentActionRows(message.pending ? rawActions : rawActions.map(finalizeAgentActionRow));
  if (!actions.length) return null;
  const topics = groupAgentActions(actions);
  const details = document.createElement("details");
  details.className = "agent-actions-chain";
  bindAgentDetailsOpenState(details, message?.id ? `actions:${message.id}` : "", Boolean(message.pending), {
    autoCloseOnDone: true,
    status: message.pending ? "running" : "done",
  });
  const summary = document.createElement("summary");
  summary.className = "agent-actions-summary";
  const running = actions.find((action) => action.status === "running");
  const failed = actions.find((action) => action.status === "error");
  const label = message.pending
    ? message.phase || agentLiveStepFromAction(running) || running?.label || "Working"
    : failed
      ? "Actions need attention"
      : `${actions.length} actions completed`;
  const summaryLabel = document.createElement("span");
  summaryLabel.textContent = label;
  summary.append(summaryLabel);
  const list = document.createElement("div");
  list.className = "agent-actions-list";
  list.replaceChildren(...topics.map((topic) => renderAgentActionTopic(topic, message)));
  details.append(summary, list);
  return details;
}

function groupAgentActions(actions) {
  const order = ["run-wasm", "run-api", "run-hermes"];
  const groups = new Map(order.map((topic) => [topic, { topic, actions: [] }]));
  for (const action of actions) {
    const topic = agentActionTopic(action);
    if (!groups.has(topic)) groups.set(topic, { topic, actions: [] });
    groups.get(topic).actions.push(action);
  }
  return [...groups.values()].filter((group) => group.actions.length);
}

function isAgentPollAction(action = {}) {
  return cleanText(action.label, "") === "bridge.run.poll" || cleanText(action.id, "") === "bridge_run_poll";
}

function isAgentTimelineAction(action = {}) {
  const label = cleanText(action.label, "").toLowerCase();
  const meta = cleanText(action.meta, "").toLowerCase();
  const id = cleanText(action.id, "").toLowerCase();
  const eventType = cleanText(action.event_type, "").toLowerCase();
  if (label === "bridge.run.poll" || id === "bridge_run_poll") return false;
  if (label === "tokens.used" || id === "tokens_used" || id === "bridge_token_usage") return true;
  if (label === "route.resolved" || eventType === "route.resolved") return true;
  if (label === "route_contract_missing" || eventType === "route_contract_missing") return true;
  if (label === "run.started" || eventType === "run.started") return true;
  if (label === "hermes.dispatch" || eventType === "hermes.dispatch") return true;
  if (label === "tool.started" || meta.startsWith("tool.started")) return true;
  if (label === "tool.finished" || meta.startsWith("tool.completed") || meta.startsWith("tool.finished")) return true;
  if (label.includes("files") || label.includes("file") || eventType.startsWith("files.")) return true;
  if (label.includes("test") || eventType.startsWith("tests.")) return true;
  if (label.includes("proof") || eventType.startsWith("proof.")) return true;
  if (label === "run.final" || eventType === "run.final") return true;
  if (label === "bridge.run.started" || label === "bridge.run.completed") return true;
  if (label === "backend.run.started" || label === "backend.run.completed") return true;
  if (label === "head.started" || label === "head.decision") return true;
  if (label === "envelope.created") return true;
  return false;
}

function compactAgentActionRows(actions = []) {
  const rows = [];
  for (const action of actions) {
    if (isAgentPollAction(action)) continue;
    if (isAgentTimelineAction(action)) continue;
    rows.push(action);
  }
  return rows;
}

function masterFrontierHermesActions(directHead = {}) {
  const actions = Array.isArray(directHead.actions) ? directHead.actions : [];
  const hermesActions = actions.filter((action) => agentActionTopic(action) === "run-hermes");
  if (hermesActions.length) return hermesActions;
  const dispatch = directHead.hermes_dispatch && typeof directHead.hermes_dispatch === "object" ? directHead.hermes_dispatch : null;
  if (!dispatch) return [];
  const target = cleanText(dispatch.target_node || "Hermes", "Hermes");
  const trace = dispatch.bridge_trace && typeof dispatch.bridge_trace === "object" ? dispatch.bridge_trace : {};
  const toolCalls = Array.isArray(trace.tool_calls) ? trace.tool_calls.length : 0;
  const steps = Array.isArray(trace.steps) ? trace.steps.length : 0;
  const detail = [
    target,
    toolCalls ? `${toolCalls} tools` : "",
    steps ? `${steps} events` : "",
  ].filter(Boolean).join(" · ");
  return [agentAction("Hermes dispatch", "done", detail || target, {
    id: "client_master_frontier_hermes_dispatch",
    topic: "run-hermes",
    kind: "model",
    meta: cleanText(trace.model || dispatch.source || "embedded-hermes", "embedded-hermes"),
    arguments: {
      target_node: target,
      run_id: cleanText(trace.id || "", ""),
      context_measurement: dispatch.context_measurement || null,
      exact_token_usage: dispatch.usage || null,
    },
  })];
}

function agentActionTopic(action) {
  const topic = cleanText(action.topic, "");
  if (topic === "run-wasm" || topic === "run-api" || topic === "run-hermes") return topic;
  const kind = cleanText(action.kind, "");
  const id = cleanText(action.id, "");
  if (kind === "run-api" || kind === "api" || id === "client_call_api" || id === "client_call_provider" || id === "client_probe_provider") return "run-api";
  if (
    kind === "run-hermes"
    || kind === "model"
    || kind === "trace"
    || id === "node_reply"
    || id.startsWith("bridge_")
    || id.startsWith("client_ask_")
  ) {
    return "run-hermes";
  }
  return "run-wasm";
}

function agentActionInnerKind(action) {
  const kind = cleanText(action.kind, "step");
  if (kind !== "run-wasm" && kind !== "run-api" && kind !== "run-hermes") return kind;
  const id = cleanText(action.id, "");
  const label = cleanText(action.label, "").toLowerCase();
  if (id === "turn_intake") return "turn";
  if (id === "mutation_policy") return "policy";
  if (id === "client_call_api" || id === "client_call_provider" || id === "client_probe_provider") return "api";
  if (id === "bridge_token_usage" || label === "tokens.used") return "tokens";
  if (id === "node_reply" || id.startsWith("client_ask_")) return "model";
  if (id === "bridge_steps" || id === "bridge_reasoning_summary") return "trace";
  if (id.startsWith("bridge_tool_") || id.startsWith("tool_")) return "tool";
  if (id.startsWith("client_store_") || id.startsWith("client_decode_") || id.startsWith("client_analyze_") || id.startsWith("client_build_")) return "media";
  if (label.includes("context")) return "context";
  return "step";
}

function actionTopicStatus(actions) {
  if (actions.some((action) => action.status === "error")) return "error";
  if (actions.some((action) => action.status === "running")) return "running";
  return "done";
}

function agentActionIconText(action, kind = "") {
  const status = cleanText(action?.status, "");
  if (status === "error") return "⚠️";
  if (status === "running") return "⏳";
  const id = cleanText(action?.id, "");
  const label = cleanText(action?.label, "").toLowerCase();
  if (kind === "turn" || id === "turn_intake") return "📥";
  if (kind === "policy") return "🛡️";
  if (kind === "context" || label.includes("context")) return "🧭";
  if (kind === "media") return "🖼️";
  if (kind === "api") return "↗";
  if (kind === "model") return "🧠";
  if (kind === "tool") return "🔧";
  if (kind === "trace") return "🔎";
  if (kind === "mutation") return "✏️";
  if (kind === "timeline") return "🕘";
  return "✓";
}

function agentTopicIconText(topic, status = "") {
  if (status === "error") return "⚠️";
  if (status === "running") return "⏳";
  if (topic === "run-api") return "↗";
  return topic === "run-hermes" ? "🪽" : "🧩";
}

function cleanAgentActionLabel(action, kind = "") {
  const raw = cleanText(action?.label, "Action");
  if (raw === "tokens.used" || kind === "tokens") return "Token usage";
  if (raw === "route.resolved") return "Route resolved";
  if (raw === "route_contract_missing") return "Route contract missing";
  if (kind === "tool") return raw.replace(/^tool:\s*/i, "") || "tool";
  return raw;
}

function cleanAgentActionMeta(action, status = "", kind = "") {
  const meta = cleanText(action?.meta, status);
  if (kind === "tool" && /^tool\.(started|completed)$/i.test(meta)) return status === "done" ? "done" : status;
  return meta;
}

function renderAgentActionTopic(group, message) {
  const topicActions = group.actions || [];
  const status = actionTopicStatus(topicActions);
  const details = document.createElement("details");
  details.className = `agent-action-topic ${status} kind-${group.topic}`;
  bindAgentDetailsOpenState(
    details,
    message?.id ? `topic:${message.id}:${group.topic}` : "",
    Boolean(message?.pending && (status === "running" || status === "error")),
    { status, autoCloseOnDone: true }
  );
  const summary = document.createElement("summary");
  summary.className = "agent-action-topic-summary";
  const dot = document.createElement("span");
  dot.className = "agent-action-dot";
  dot.setAttribute("aria-hidden", "true");
  const main = document.createElement("span");
  main.className = "agent-action-main";
  const label = document.createElement("strong");
  const detail = document.createElement("span");
  const badge = document.createElement("span");
  const meta = document.createElement("span");
  badge.className = "agent-action-topic-kind";
  meta.className = "agent-action-meta";
  label.textContent = `${agentTopicIconText(group.topic, status)} ${group.topic}`;
  detail.textContent = topicActions
    .map((action) => agentActionInnerKind(action))
    .filter((kind, index, list) => kind && list.indexOf(kind) === index)
    .slice(0, 4)
    .join(" / ");
  badge.textContent = status;
  meta.textContent = `${topicActions.length}`;
  main.append(label);
  if (detail.textContent) main.append(detail);
  summary.append(dot, main, badge, meta);
  const list = document.createElement("div");
  list.className = "agent-action-topic-list";
  list.replaceChildren(...topicActions.map((action, index) => renderAgentActionRow(action, message, index)));
  details.append(summary, list);
  return details;
}

function renderAgentActionRow(action, message = {}, index = 0) {
  const hasPreview = Boolean(action.preview || action.arguments);
  const row = document.createElement(hasPreview ? "details" : "div");
  const status = cleanText(action.status, "done");
  const kind = agentActionInnerKind(action);
  row.className = `agent-action-row ${status} kind-${kind}`;
  if (hasPreview && message?.id) {
    bindAgentDetailsOpenState(row, `row:${message.id}:${cleanText(action.id, "") || `${kind}-${index}`}`, Boolean(action.open));
  }
  if (hasPreview && action.open && !message?.id) row.open = true;
  const head = document.createElement(hasPreview ? "summary" : "div");
  head.className = "agent-action-row-summary";
  const dot = document.createElement("span");
  dot.className = "agent-action-dot";
  dot.setAttribute("aria-hidden", "true");
  const main = document.createElement("span");
  main.className = "agent-action-main";
  const label = document.createElement("strong");
  const detail = document.createElement("span");
  const badge = document.createElement("span");
  const meta = document.createElement("span");
  badge.className = "agent-action-kind";
  meta.className = "agent-action-meta";
  badge.textContent = kind;
  meta.textContent = cleanAgentActionMeta(action, status, kind);
  label.textContent = `${agentActionIconText(action, kind)} ${cleanAgentActionLabel(action, kind)}`;
  detail.textContent = cleanText(action.detail, "");
  main.append(label);
  if (detail.textContent) main.append(detail);
  head.append(dot, main, badge, meta);
  row.append(head);
  if (hasPreview) {
    const preview = document.createElement("pre");
    preview.className = "agent-action-preview";
    const args = action.arguments ? `args\n${JSON.stringify(action.arguments, null, 2)}` : "";
    const result = action.preview ? `result\n${action.preview}` : "";
    preview.textContent = [args, result].filter(Boolean).join("\n\n");
    row.append(preview);
  }
  return row;
}

function agentAction(label, status = "done", detail = "", extra = {}) {
  return {
    id: `act_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 6)}`,
    kind: "client",
    label,
    status,
    detail,
    ...extra,
  };
}

function mergeAgentAction(message, nextAction) {
  if (!message || !nextAction) return;
  if (isAgentPollAction(nextAction)) {
    const phase = message.pending ? agentLiveStepFromAction(nextAction) : "";
    if (phase) updateAgentPendingMessage(message, { phase });
    return;
  }
  if (isAgentTimelineAction(nextAction)) {
    const timeline = Array.isArray(message.timeline) ? [...message.timeline] : [];
    const eventId = nextAction.id || `tl_${timeline.length + 1}`;
    const normalized = { ...nextAction, id: eventId };
    let index = timeline.findIndex((item) => item.id === eventId);
    if (index < 0 && ["done", "error"].includes(cleanText(normalized.status, "").toLowerCase())) {
      index = timeline.findIndex((item) => (
        cleanText(item.status, "").toLowerCase() === "running"
        && cleanText(item.label, "") === cleanText(normalized.label, "")
        && cleanText(item.meta, "").startsWith("tool.started")
        && (cleanText(normalized.meta, "").startsWith("tool.completed") || cleanText(normalized.meta, "").startsWith("tool.finished"))
      ));
    }
    if (index >= 0) {
      timeline[index] = { ...timeline[index], ...normalized };
    } else {
      timeline.push(normalized);
    }
    const phase = message.pending ? agentLiveStepFromAction(normalized) : "";
    updateAgentPendingMessage(message, phase ? { timeline, phase } : { timeline });
    return;
  }
  const actions = Array.isArray(message.actions) ? [...message.actions] : [];
  const actionId = nextAction.id || `act_${actions.length + 1}`;
  const normalized = { ...nextAction, id: actionId };
  let index = actions.findIndex((action) => action.id === actionId);
  if (index < 0 && ["done", "error"].includes(cleanText(normalized.status, "").toLowerCase())) {
    index = actions.findIndex((action) => (
      cleanText(action.status, "").toLowerCase() === "running"
      && cleanText(action.topic, "") === cleanText(normalized.topic, "")
      && cleanText(action.kind, "") === cleanText(normalized.kind, "")
      && cleanText(action.label, "") === cleanText(normalized.label, "")
      && cleanText(action.meta, "").startsWith("tool.started")
      && (cleanText(normalized.meta, "").startsWith("tool.completed") || cleanText(normalized.meta, "").startsWith("tool.finished"))
    ));
  }
  if (index >= 0) {
    actions[index] = { ...actions[index], ...normalized };
  } else {
    actions.push(normalized);
  }
  const phase = message.pending ? agentLiveStepFromAction(normalized) : "";
  updateAgentPendingMessage(message, phase ? { actions, phase } : { actions });
}

function finalAgentActionStatus(status) {
  const value = cleanText(status, "done").toLowerCase();
  if (["running", "queued", "submitted", "pending", "in_progress", "working"].includes(value)) return "done";
  if (["failed", "failure"].includes(value)) return "error";
  return value || "done";
}

function finalizeAgentActionRow(action = {}) {
  return { ...action, status: finalAgentActionStatus(action.status) };
}

function agentActionRowsFromPayload(agent, fallbackActions = []) {
  const actions = Array.isArray(agent?.actions) ? agent.actions : [];
  if (actions.length) return compactAgentActionRows(actions.map(finalizeAgentActionRow));
  const rows = compactAgentActionRows(fallbackActions.map(finalizeAgentActionRow));
  const previews = Array.isArray(agent?.context_preview) ? agent.context_preview : [];
  previews.forEach((item) => {
    rows.push(agentAction(`Tool: ${cleanText(item.tool, "context")}`, "done", cleanText(item.path || item.query || item.preview, "")));
  });
  const diagnostics = agent?.diagnostics || {};
  rows.push(agentAction("Node reply", "done", `${diagnostics.source || "adapter"} / ${agent?.duration_ms || diagnostics.duration_ms || 0} ms`));
  if (diagnostics.auto_checkpoint?.ref) {
    rows.push(agentAction("Timeline checkpoint", "done", `${diagnostics.auto_checkpoint.label || "auto"} ${diagnostics.auto_checkpoint.sha || ""}`.trim()));
  }
  return rows;
}

function statSpan(text, kind) {
  const span = document.createElement("span");
  span.className = `agent-diff-${kind}`;
  span.textContent = text;
  return span;
}

function dataUrlByteLength(dataUrl) {
  const encoded = String(dataUrl || "").split(",", 2)[1] || "";
  return Math.floor((encoded.length * 3) / 4);
}

function agentImagePayloadBytes(image) {
  const declared = Number(image?.size);
  if (Number.isFinite(declared) && declared > 0) return declared;
  return dataUrlByteLength(image?.data_url || "");
}

function agentPendingImageBytes() {
  return state.agentPendingImages.reduce((sum, image) => sum + agentImagePayloadBytes(image), 0);
}

function agentPendingFileJobCount() {
  return state.agentPendingFileJobs.length;
}

function blockSendWhileAttachmentsProcess() {
  const count = agentPendingFileJobCount();
  if (!count) return false;
  if (els.agentStatus) {
    els.agentStatus.textContent = count === 1 ? "Processing attachment" : `Processing ${count} attachments`;
  }
  renderPendingPreviews();
  updateAgentSendButton();
  return true;
}

function agentAttachmentSummary(image, reason) {
  return {
    data_url: image?.data_url,
    name: cleanText(image?.name, "Attached image"),
    type: cleanText(image?.type || image?.original_type, "image"),
    size: agentImagePayloadBytes(image),
    width: Number.isFinite(image?.width) ? image.width : undefined,
    height: Number.isFinite(image?.height) ? image.height : undefined,
    original_type: cleanText(image?.original_type, ""),
    original_size: Number.isFinite(image?.original_size) ? image.original_size : undefined,
    image_card: image?.image_card,
    asset: image?.asset,
    reason,
  };
}

function agentImageProcessingSkippedCard(file, rawBytes, width, height) {
  const evidence = imageAnalyzerEvidence(
    "image-card-core",
    "disabled",
    "Local image analysis was skipped for this attachment.",
    {
      facts: ["Image processing was disabled in the chat composer."],
      values: {
        original_type: cleanText(file?.type, ""),
        original_size: Number(file?.size || rawBytes || 0),
      },
      confidence: 0,
    }
  );
  return {
    schema: "hermes.wasm_agent.image_card.v1",
    analyzer_revision: IMAGE_CARD_ANALYZER_REVISION,
    name: cleanText(file?.name, "image"),
    size: rawBytes,
    dimensions: `${width}x${height}`,
    width,
    height,
    palette: [],
    visual_notes: ["image processing disabled"],
    analyzer_modules: imageAnalyzerModuleStates(),
    evidence: [evidence],
    module_results: { "image-card-core": evidence },
  };
}

function isAgentImageFile(file) {
  return Boolean(file?.type?.startsWith("image/"));
}

function isAgentVideoFile(file) {
  const type = String(file?.type || "").toLowerCase();
  const name = String(file?.name || "").toLowerCase();
  return type === "video/mp4" || name.endsWith(".mp4");
}

function isAgentAttachmentFile(file) {
  return isAgentImageFile(file) || isAgentVideoFile(file);
}

function attachmentMetaText(entry) {
  const type = cleanText(entry?.type || entry?.original_type, "file");
  const size = bytes(Number(entry?.size || entry?.original_size || 0));
  const duration = Number(entry?.duration_sec ?? entry?.video_card?.duration_sec);
  const durationText = Number.isFinite(duration) && duration > 0 ? `${duration.toFixed(duration >= 10 ? 0 : 1)}s` : "";
  const dimensions = entry?.width && entry?.height ? `${entry.width}x${entry.height}` : "";
  return [type, size, dimensions, durationText].filter((item) => item && item !== "-").join(" / ");
}

function readFileAsDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = () => reject(new Error(`Failed to read ${file.name}`));
    reader.readAsDataURL(file);
  });
}

async function readVideoFileSummary(file) {
  const shouldReadRaw = Number(file?.size || 0) > 0
    && Number(file.size || 0) <= Math.floor(AGENT_PROVIDER_VIDEO_PART_MAX_CHARS * 0.72);
  const rawDataUrlPromise = shouldReadRaw
    ? readFileAsDataUrl(file).catch(() => "")
    : Promise.resolve("");
  const summary = await new Promise((resolve) => {
    const objectUrl = URL.createObjectURL(file);
    const video = document.createElement("video");
    let settled = false;
    const finish = () => {
      if (settled) return;
      settled = true;
      URL.revokeObjectURL(objectUrl);
      const width = Number(video.videoWidth || 0);
      const height = Number(video.videoHeight || 0);
      const duration = Number(video.duration || 0);
      resolve({
        name: cleanText(file.name, "Attached video"),
        type: cleanText(file.type || "video/mp4", "video/mp4"),
        size: Number.isFinite(file.size) ? file.size : undefined,
        width: Number.isFinite(width) && width > 0 ? width : undefined,
        height: Number.isFinite(height) && height > 0 ? height : undefined,
        duration_sec: Number.isFinite(duration) && duration > 0 ? Math.round(duration * 10) / 10 : undefined,
        media_kind: "video",
        video_card: {
          schema: "hermes.wasm_agent.video_card.v1",
          name: cleanText(file.name, "Attached video"),
          type: cleanText(file.type || "video/mp4", "video/mp4"),
          size: Number.isFinite(file.size) ? file.size : undefined,
          width: Number.isFinite(width) && width > 0 ? width : undefined,
          height: Number.isFinite(height) && height > 0 ? height : undefined,
          duration_sec: Number.isFinite(duration) && duration > 0 ? Math.round(duration * 10) / 10 : undefined,
        },
        reason: "video_metadata_only",
      });
    };
    video.preload = "metadata";
    video.muted = true;
    video.onloadedmetadata = finish;
    video.onerror = finish;
    window.setTimeout(finish, 2500);
    video.src = objectUrl;
  });
  const rawDataUrl = await rawDataUrlPromise;
  if (/^data:video\/(mp4|mpeg|quicktime|webm);base64,/i.test(rawDataUrl) && rawDataUrl.length <= AGENT_PROVIDER_VIDEO_PART_MAX_CHARS) {
    summary.data_url = rawDataUrl;
    summary.reason = "video_raw_available";
    if (summary.video_card) summary.video_card.raw_available = true;
  }
  return summary;
}

function loadDataUrlImage(dataUrl, name) {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error(`Could not decode ${name}`));
    img.src = dataUrl;
  });
}

function roundedMetric(value, digits = 3) {
  if (!Number.isFinite(value)) return 0;
  const scale = 10 ** digits;
  return Math.round(value * scale) / scale;
}

function rgbToHex(r, g, b) {
  return `#${[r, g, b].map((value) => Math.max(0, Math.min(255, Math.round(value))).toString(16).padStart(2, "0")).join("")}`;
}

function rgbToHsl(r, g, b) {
  const red = r / 255;
  const green = g / 255;
  const blue = b / 255;
  const max = Math.max(red, green, blue);
  const min = Math.min(red, green, blue);
  const lightness = (max + min) / 2;
  if (max === min) return { hue: 0, saturation: 0, lightness };
  const delta = max - min;
  const saturation = lightness > 0.5 ? delta / (2 - max - min) : delta / (max + min);
  let hue = 0;
  if (max === red) hue = (green - blue) / delta + (green < blue ? 6 : 0);
  if (max === green) hue = (blue - red) / delta + 2;
  if (max === blue) hue = (red - green) / delta + 4;
  return { hue: hue * 60, saturation, lightness };
}

function colorName(r, g, b) {
  const { hue, saturation, lightness } = rgbToHsl(r, g, b);
  if (lightness < 0.12) return "black";
  if (lightness > 0.9 && saturation < 0.2) return "white";
  if (saturation < 0.12) {
    if (lightness < 0.32) return "charcoal";
    if (lightness > 0.72) return "silver";
    return "gray";
  }
  const hueName = hue < 12 || hue >= 345 ? "red"
    : hue < 34 ? "orange"
      : hue < 55 ? "yellow"
        : hue < 86 ? "lime"
          : hue < 145 ? "green"
            : hue < 174 ? "teal"
              : hue < 196 ? "cyan"
                : hue < 232 ? "blue"
                  : hue < 264 ? "indigo"
                    : hue < 292 ? "purple"
                      : hue < 326 ? "magenta"
                        : "pink";
  if (lightness < 0.24) return `dark ${hueName}`;
  if (lightness > 0.78) return `pale ${hueName}`;
  return hueName;
}

function averageHash(image) {
  const canvas = document.createElement("canvas");
  canvas.width = 8;
  canvas.height = 8;
  const ctx = canvas.getContext("2d", { willReadFrequently: true });
  if (!ctx) return "";
  ctx.drawImage(image, 0, 0, 8, 8);
  const { data } = ctx.getImageData(0, 0, 8, 8);
  const luma = [];
  for (let i = 0; i < data.length; i += 4) {
    luma.push((data[i] * 0.299) + (data[i + 1] * 0.587) + (data[i + 2] * 0.114));
  }
  const avg = luma.reduce((sum, value) => sum + value, 0) / luma.length;
  let hex = "";
  for (let i = 0; i < luma.length; i += 4) {
    let nibble = 0;
    for (let bit = 0; bit < 4; bit += 1) {
      if (luma[i + bit] >= avg) nibble |= 1 << (3 - bit);
    }
    hex += nibble.toString(16);
  }
  return `ahash:${hex}`;
}

function luminanceWord(value) {
  if (value < 0.12) return "very dark";
  if (value < 0.28) return "dark";
  if (value < 0.45) return "dim";
  if (value < 0.65) return "medium";
  if (value < 0.82) return "bright";
  return "very bright";
}

function gradientDirection(horizontalDelta, verticalDelta) {
  const absH = Math.abs(horizontalDelta);
  const absV = Math.abs(verticalDelta);
  if (Math.max(absH, absV) < 0.025) return "centered or even";
  if (absH > absV * 1.35) return horizontalDelta > 0 ? "brighter on right" : "brighter on left";
  if (absV > absH * 1.35) return verticalDelta > 0 ? "brighter at bottom" : "brighter at top";
  const vertical = verticalDelta > 0 ? "bottom" : "top";
  const horizontal = horizontalDelta > 0 ? "right" : "left";
  return `brighter toward ${vertical}-${horizontal}`;
}

function textLikeRegionSignals(luma, mask, width, height, avgLuma) {
  const rows = 6;
  const cols = 4;
  const cells = Array.from({ length: rows * cols }, (_, index) => ({
    index,
    row: Math.floor(index / cols),
    col: index % cols,
    count: 0,
    dark: 0,
    bright: 0,
    transitions: 0,
    comparisons: 0,
  }));
  const darkThreshold = Math.max(42, Math.min(125, avgLuma * 0.78));
  const brightThreshold = Math.max(darkThreshold + 28, Math.min(210, avgLuma + 24));
  for (let y = 0; y < height; y += 1) {
    for (let x = 0; x < width; x += 1) {
      const index = y * width + x;
      if (!mask[index]) continue;
      const cellCol = Math.min(cols - 1, Math.floor((x / width) * cols));
      const cellRow = Math.min(rows - 1, Math.floor((y / height) * rows));
      const cell = cells[cellRow * cols + cellCol];
      const lum = luma[index];
      cell.count += 1;
      if (lum <= darkThreshold) cell.dark += 1;
      if (lum >= brightThreshold) cell.bright += 1;
      if (x > 0) {
        const previous = index - 1;
        if (mask[previous]) {
          cell.comparisons += 1;
          if (Math.abs(lum - luma[previous]) > 18) cell.transitions += 1;
        }
      }
      if (y > 0) {
        const previous = index - width;
        if (mask[previous]) {
          cell.comparisons += 1;
          if (Math.abs(lum - luma[previous]) > 18) cell.transitions += 1;
        }
      }
    }
  }
  const scored = cells.map((cell) => {
    const darkRatio = cell.dark / Math.max(1, cell.count);
    const brightRatio = cell.bright / Math.max(1, cell.count);
    const transitionDensity = cell.transitions / Math.max(1, cell.comparisons);
    const hasInkAndSurface = darkRatio > 0.035 && darkRatio < 0.62 && brightRatio > 0.08;
    const centerBias = cell.col > 0 && cell.col < cols - 1 && cell.row > 0 && cell.row < rows - 1 ? 1.18 : 1;
    const score = Math.min(1, (transitionDensity * 2.2 + Math.min(darkRatio, 0.34) * 0.9 + Math.min(brightRatio, 0.5) * 0.2) * centerBias * (hasInkAndSurface ? 1 : 0.45));
    return {
      ...cell,
      dark_ratio: roundedMetric(darkRatio),
      bright_ratio: roundedMetric(brightRatio),
      transition_density: roundedMetric(transitionDensity),
      score: roundedMetric(score),
    };
  }).sort((a, b) => b.score - a.score);
  const active = scored.filter((cell) => cell.score > 0.18);
  const activeRows = new Set(active.map((cell) => cell.row));
  const activeCols = new Set(active.map((cell) => cell.col));
  const horizontalBands = activeRows.size;
  const regionLabels = [];
  if (active.length) {
    const rowAvg = active.reduce((sum, cell) => sum + cell.row, 0) / active.length;
    const colAvg = active.reduce((sum, cell) => sum + cell.col, 0) / active.length;
    const vertical = rowAvg < 1.8 ? "upper" : rowAvg > 3.8 ? "lower" : "middle";
    const horizontal = colAvg < 1.1 ? "left" : colAvg > 1.9 ? "right" : "center";
    regionLabels.push(`${vertical} ${horizontal}`.trim());
  }
  const topScore = scored.slice(0, 4).reduce((sum, cell) => sum + cell.score, 0) / Math.max(1, Math.min(4, scored.length));
  return {
    score: roundedMetric(topScore),
    horizontal_band_estimate: horizontalBands,
    active_cell_count: active.length,
    active_row_count: activeRows.size,
    active_col_count: activeCols.size,
    regions: regionLabels,
    cells: scored.slice(0, 5).map((cell) => ({
      row: cell.row,
      col: cell.col,
      score: cell.score,
      dark_ratio: cell.dark_ratio,
      bright_ratio: cell.bright_ratio,
      transition_density: cell.transition_density,
    })),
  };
}

function imageAnalyzerModules() {
  return MODULE_DEFINITIONS.filter((module) => module.analyzer?.kind === "image");
}

function imageAnalyzerModuleStates() {
  return imageAnalyzerModules().map((module) => ({
    id: module.id,
    title: module.title,
    enabled: isModuleEnabled(module.id),
    status: module.status,
    mode: module.analyzer?.mode || "",
    evidence: module.analyzer?.evidence || "",
    cached: IMAGE_ANALYZER_CACHE.has(module.id),
  }));
}

function imageAnalyzerEvidence(moduleId, status, summary, extra = {}) {
  const module = moduleDefinitionById(moduleId);
  const confidence = Number(extra.confidence);
  const durationMs = Number(extra.duration_ms);
  return {
    module: moduleId,
    title: module?.title || moduleId,
    status,
    summary: cleanText(summary, ""),
    confidence: Number.isFinite(confidence) ? roundedMetric(confidence) : undefined,
    facts: Array.isArray(extra.facts)
      ? extra.facts.map((item) => truncateText(item, 120)).filter(Boolean).slice(0, 8)
      : [],
    values: extra.values && typeof extra.values === "object" ? extra.values : undefined,
    reason: extra.reason ? truncateText(extra.reason, 160) : undefined,
    duration_ms: Number.isFinite(durationMs) ? Math.round(durationMs) : undefined,
    cached: Boolean(extra.cached),
  };
}

function addImageAnalyzerResult(card, result) {
  const evidence = Array.isArray(card.evidence) ? [...card.evidence] : [];
  const moduleResults = card.module_results && typeof card.module_results === "object" ? { ...card.module_results } : {};
  evidence.push(result);
  moduleResults[result.module] = result;
  return {
    ...card,
    evidence,
    module_results: moduleResults,
    analyzer_modules: imageAnalyzerModuleStates(),
  };
}

function createUnavailableImageAnalyzer(module, reason) {
  return async () => imageAnalyzerEvidence(
    module.id,
    "not_loaded",
    `${module.title} runtime is not bundled yet.`,
    {
      reason,
      facts: [`${module.title} was enabled, but no local runtime has been installed for this module.`],
      confidence: 0,
    }
  );
}

async function imageBitmapFromDataUrl(dataUrl) {
  if (!String(dataUrl || "").startsWith("data:image/")) return null;
  if (typeof createImageBitmap !== "function") return loadDataUrlImage(dataUrl, "barcode source");
  const response = await fetch(dataUrl);
  const blob = await response.blob();
  return createImageBitmap(blob);
}

function loadScriptOnce(url) {
  const source = String(url || "").trim();
  if (!source) return Promise.reject(new Error("script URL is empty"));
  if (SCRIPT_RUNTIME_CACHE.has(source)) return SCRIPT_RUNTIME_CACHE.get(source);
  const promise = new Promise((resolve, reject) => {
    const existing = Array.from(document.querySelectorAll("script[data-wasm-agent-runtime]"))
      .find((script) => script.dataset.wasmAgentRuntime === source);
    if (existing) {
      existing.addEventListener("load", () => resolve(existing), { once: true });
      existing.addEventListener("error", () => reject(new Error(`Could not load ${source}`)), { once: true });
      return;
    }
    const script = document.createElement("script");
    script.src = source;
    script.async = true;
    script.crossOrigin = "anonymous";
    script.dataset.wasmAgentRuntime = source;
    script.onload = () => resolve(script);
    script.onerror = () => reject(new Error(`Could not load ${source}`));
    document.head.append(script);
  });
  SCRIPT_RUNTIME_CACHE.set(source, promise);
  return promise;
}

function tesseractRuntimeUrl() {
  if (Object.prototype.hasOwnProperty.call(window, "__WASM_AGENT_TESSERACT_URL__")) {
    return String(window.__WASM_AGENT_TESSERACT_URL__ || "").trim();
  }
  return OCR_TESSERACT_DEFAULT_URL;
}

function normalizeOcrLines(text) {
  return String(text || "")
    .split(/\r?\n+/)
    .map((line) => line.replace(/\s+/g, " ").trim())
    .filter((line) => line.length >= 2)
    .slice(0, 8);
}

function ocrTextSignals(context) {
  const card = context?.card && typeof context.card === "object" ? context.card : {};
  const composition = card.composition && typeof card.composition === "object" ? card.composition : {};
  const signals = context?.textSignals || composition.text_regions;
  return signals && typeof signals === "object" ? signals : {};
}

function shouldRunTesseractOcr(context) {
  const card = context?.card && typeof context.card === "object" ? context.card : {};
  const analysis = card.analysis && typeof card.analysis === "object" ? card.analysis : {};
  const signals = ocrTextSignals(context);
  const score = Number(analysis.text_like_score ?? signals.score ?? 0);
  const bands = Number(analysis.text_band_estimate ?? signals.horizontal_band_estimate ?? 0);
  return score >= OCR_TEXT_SCORE_THRESHOLD || bands >= 2;
}

function ocrCropBox(context, source) {
  const sourceWidth = Math.max(1, source.naturalWidth || source.videoWidth || source.width || context.width || 1);
  const sourceHeight = Math.max(1, source.naturalHeight || source.videoHeight || source.height || context.height || 1);
  const aspect = sourceWidth / sourceHeight;
  const signals = ocrTextSignals(context);
  const cells = Array.isArray(signals.cells) ? signals.cells : [];
  const scoredCells = cells.filter((cell) => Number(cell.score) >= OCR_TEXT_SCORE_THRESHOLD);
  if (scoredCells.length && Number(signals.active_row_count || 0) < 6 && Number(signals.active_col_count || 0) < 4) {
    const minCol = Math.max(0, Math.min(...scoredCells.map((cell) => Number(cell.col) || 0)) - 1);
    const maxCol = Math.min(3, Math.max(...scoredCells.map((cell) => Number(cell.col) || 0)) + 1);
    const minRow = Math.max(0, Math.min(...scoredCells.map((cell) => Number(cell.row) || 0)) - 1);
    const maxRow = Math.min(5, Math.max(...scoredCells.map((cell) => Number(cell.row) || 0)) + 1);
    const x = Math.floor((minCol / 4) * sourceWidth);
    const y = Math.floor((minRow / 6) * sourceHeight);
    const right = Math.ceil(((maxCol + 1) / 4) * sourceWidth);
    const bottom = Math.ceil(((maxRow + 1) / 6) * sourceHeight);
    return {
      x,
      y,
      width: Math.max(1, right - x),
      height: Math.max(1, bottom - y),
      reason: "text_like_grid",
    };
  }
  if (aspect <= 0.84) {
    return {
      x: Math.floor(sourceWidth * 0.04),
      y: Math.floor(sourceHeight * 0.12),
      width: Math.ceil(sourceWidth * 0.92),
      height: Math.ceil(sourceHeight * 0.68),
      reason: "portrait_text_window",
    };
  }
  if (aspect >= 1.2) {
    return {
      x: Math.floor(sourceWidth * 0.04),
      y: Math.floor(sourceHeight * 0.08),
      width: Math.ceil(sourceWidth * 0.92),
      height: Math.ceil(sourceHeight * 0.84),
      reason: "landscape_text_window",
    };
  }
  return {
    x: Math.floor(sourceWidth * 0.05),
    y: Math.floor(sourceHeight * 0.08),
    width: Math.ceil(sourceWidth * 0.9),
    height: Math.ceil(sourceHeight * 0.84),
    reason: "square_text_window",
  };
}

function histogramPercentile(histogram, total, percentile) {
  const target = Math.max(0, Math.min(total - 1, Math.round(total * percentile)));
  let seen = 0;
  for (let index = 0; index < histogram.length; index += 1) {
    seen += histogram[index];
    if (seen >= target) return index;
  }
  return histogram.length - 1;
}

function otsuThreshold(histogram, total) {
  let sum = 0;
  for (let index = 0; index < histogram.length; index += 1) sum += index * histogram[index];
  let sumBackground = 0;
  let weightBackground = 0;
  let bestVariance = -1;
  let threshold = 128;
  for (let index = 0; index < histogram.length; index += 1) {
    weightBackground += histogram[index];
    if (!weightBackground) continue;
    const weightForeground = total - weightBackground;
    if (!weightForeground) break;
    sumBackground += index * histogram[index];
    const meanBackground = sumBackground / weightBackground;
    const meanForeground = (sum - sumBackground) / weightForeground;
    const variance = weightBackground * weightForeground * (meanBackground - meanForeground) ** 2;
    if (variance > bestVariance) {
      bestVariance = variance;
      threshold = index;
    }
  }
  return threshold;
}

function clampByte(value) {
  return Math.max(0, Math.min(255, Math.round(value)));
}

async function prepareOcrInput(context) {
  const source = context.image || await imageBitmapFromDataUrl(context.dataUrl);
  if (!source) return null;
  let closeSource = false;
  if (source !== context.image) closeSource = true;
  try {
    const crop = ocrCropBox(context, source);
    const scale = Math.min(3, OCR_PREPROCESS_MAX_WIDTH / Math.max(1, crop.width));
    const outputWidth = Math.max(320, Math.round(crop.width * scale));
    const outputHeight = Math.max(120, Math.round(crop.height * scale));
    const canvas = document.createElement("canvas");
    canvas.width = outputWidth;
    canvas.height = outputHeight;
    const ctx = canvas.getContext("2d", { willReadFrequently: true });
    if (!ctx) return null;
    ctx.fillStyle = "#fff";
    ctx.fillRect(0, 0, outputWidth, outputHeight);
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = "high";
    ctx.drawImage(source, crop.x, crop.y, crop.width, crop.height, 0, 0, outputWidth, outputHeight);
    const imageData = ctx.getImageData(0, 0, outputWidth, outputHeight);
    const data = imageData.data;
    const histogram = new Array(256).fill(0);
    const luma = new Uint8Array(outputWidth * outputHeight);
    for (let pixel = 0; pixel < luma.length; pixel += 1) {
      const offset = pixel * 4;
      const value = clampByte((data[offset] * 0.299) + (data[offset + 1] * 0.587) + (data[offset + 2] * 0.114));
      luma[pixel] = value;
      histogram[value] += 1;
    }
    const low = histogramPercentile(histogram, luma.length, 0.05);
    const high = Math.max(low + 24, histogramPercentile(histogram, luma.length, 0.95));
    const stretchedHistogram = new Array(256).fill(0);
    const stretched = new Uint8Array(luma.length);
    for (let pixel = 0; pixel < luma.length; pixel += 1) {
      const value = clampByte(((luma[pixel] - low) / (high - low)) * 255);
      stretched[pixel] = value;
      stretchedHistogram[value] += 1;
    }
    const threshold = Math.max(92, Math.min(196, otsuThreshold(stretchedHistogram, stretched.length)));
    for (let pixel = 0; pixel < stretched.length; pixel += 1) {
      const offset = pixel * 4;
      const value = stretched[pixel] < threshold ? 0 : 255;
      data[offset] = value;
      data[offset + 1] = value;
      data[offset + 2] = value;
      data[offset + 3] = 255;
    }
    ctx.putImageData(imageData, 0, 0);
    return {
      dataUrl: canvas.toDataURL("image/png"),
      width: outputWidth,
      height: outputHeight,
      crop: {
        x: crop.x,
        y: crop.y,
        width: crop.width,
        height: crop.height,
        reason: crop.reason,
      },
      threshold,
      contrast_window: [low, high],
      preprocessed: true,
    };
  } finally {
    if (closeSource) source.close?.();
  }
}

async function configureTesseractWorker(worker, tesseract) {
  if (typeof worker?.setParameters !== "function") return;
  const pageSegMode = tesseract?.PSM?.SINGLE_BLOCK || "6";
  try {
    await worker.setParameters({
      tessedit_pageseg_mode: pageSegMode,
      preserve_interword_spaces: "1",
      user_defined_dpi: "180",
    });
  } catch {
    // Some Tesseract.js builds reject optional tuning parameters.
  }
}

function ocrEvidenceFromResult(module, engine, result, input) {
  const data = result?.data && typeof result.data === "object" ? result.data : {};
  const rawText = String(data.text || result?.text || "").trim();
  const lines = normalizeOcrLines(rawText);
  const words = Array.isArray(data.words)
    ? data.words.map((word) => cleanText(word.text || word.rawValue, "")).filter(Boolean).slice(0, 12)
    : [];
  const facts = lines.length ? lines : words.length ? words : [`${engine} found no readable text.`];
  const confidence = Number.isFinite(Number(data.confidence)) ? Number(data.confidence) / 100 : (lines.length ? 0.72 : 0.5);
  return imageAnalyzerEvidence(
    module.id,
    lines.length || words.length ? "detected" : "not_detected",
    lines.length || words.length
      ? `${engine} detected ${lines.length || words.length} text snippet${(lines.length || words.length) === 1 ? "" : "s"}.`
      : `${engine} did not detect readable text.`,
    {
      facts,
      values: {
        engine,
        text: truncateText(rawText, 600),
        lines,
        words,
        input: input ? {
          preprocessed: Boolean(input.preprocessed),
          width: input.width,
          height: input.height,
          crop: input.crop,
          threshold: input.threshold,
          contrast_window: input.contrast_window,
        } : undefined,
      },
      confidence: Math.max(0, Math.min(1, confidence)),
    }
  );
}

async function createBarcodeReaderAnalyzer(module) {
  const Detector = window.BarcodeDetector;
  if (typeof Detector !== "function") {
    return async () => imageAnalyzerEvidence(
      module.id,
      "unsupported",
      "This browser does not expose BarcodeDetector.",
      {
        reason: "BarcodeDetector API unavailable",
        facts: ["No local barcode runtime was available for this turn."],
        confidence: 0,
      }
    );
  }
  const preferredFormats = [
    "qr_code",
    "aztec",
    "data_matrix",
    "pdf417",
    "ean_13",
    "ean_8",
    "code_128",
    "code_39",
    "upc_a",
    "upc_e",
  ];
  let formats = preferredFormats;
  try {
    if (typeof Detector.getSupportedFormats === "function") {
      const supported = await Detector.getSupportedFormats();
      formats = preferredFormats.filter((format) => supported.includes(format));
    }
  } catch {
    formats = preferredFormats;
  }
  let detector = null;
  try {
    detector = formats.length ? new Detector({ formats }) : new Detector();
  } catch (error) {
    return async () => imageAnalyzerEvidence(
      module.id,
      "unsupported",
      "BarcodeDetector could not be initialized.",
      {
        reason: error.message,
        facts: ["Native barcode detection was present but failed during setup."],
        confidence: 0,
      }
    );
  }
  return async (context) => {
    const source = context.image || await imageBitmapFromDataUrl(context.dataUrl);
    if (!source) {
      return imageAnalyzerEvidence(
        module.id,
        "skipped",
        "No image bitmap source was available.",
        { reason: "missing_data_url", confidence: 0 }
      );
    }
    try {
      const codes = await detector.detect(source);
      const facts = codes.slice(0, 6).map((code) => {
        const format = cleanText(code.format, "barcode");
        const value = truncateText(code.rawValue || "", 96);
        return value ? `${format}: ${value}` : format;
      });
      return imageAnalyzerEvidence(
        module.id,
        codes.length ? "detected" : "not_detected",
        codes.length ? `${codes.length} barcode value${codes.length === 1 ? "" : "s"} detected.` : "No supported QR/barcode detected.",
        {
          facts: facts.length ? facts : ["No supported QR/barcode detected."],
          values: {
            count: codes.length,
            formats: [...new Set(codes.map((code) => code.format).filter(Boolean))].slice(0, 8),
            supported_formats: formats.slice(0, 12),
          },
          confidence: codes.length ? 1 : 0.82,
        }
      );
    } finally {
      if (source !== context.image) source.close?.();
    }
  };
}

async function createNativeOcrAnalyzer(module) {
  const Detector = window.TextDetector;
  if (typeof Detector !== "function") {
    return async () => imageAnalyzerEvidence(
      module.id,
      "unsupported",
      "This browser does not expose native TextDetector OCR.",
      {
        reason: "TextDetector API unavailable",
        facts: ["No local OCR runtime was available for this turn."],
        confidence: 0,
      }
    );
  }
  let detector = null;
  try {
    detector = new Detector();
  } catch (error) {
    return async () => imageAnalyzerEvidence(
      module.id,
      "unsupported",
      "Native TextDetector could not be initialized.",
      {
        reason: error.message,
        facts: ["Native OCR was present but failed during setup."],
        confidence: 0,
      }
    );
  }
  return async (context) => {
    const source = context.image || await imageBitmapFromDataUrl(context.dataUrl);
    if (!source) {
      return imageAnalyzerEvidence(
        module.id,
        "skipped",
        "No image source was available for OCR.",
        { reason: "missing_data_url", confidence: 0 }
      );
    }
    try {
      const detections = await detector.detect(source);
      const texts = detections
        .map((item) => cleanText(item.rawValue || item.text || "", ""))
        .filter(Boolean)
        .slice(0, 8);
      return imageAnalyzerEvidence(
        module.id,
        texts.length ? "detected" : "not_detected",
        texts.length ? `${texts.length} text region${texts.length === 1 ? "" : "s"} detected by native OCR.` : "No text detected by native OCR.",
        {
          facts: texts.length ? texts : ["No text detected by native OCR."],
          values: {
            text_region_count: detections.length,
            texts,
          },
          confidence: texts.length ? 0.86 : 0.72,
        }
      );
    } finally {
      if (source !== context.image) source.close?.();
    }
  };
}

async function createTesseractOcrAnalyzer(module) {
  const runtimeUrl = tesseractRuntimeUrl();
  if (!runtimeUrl) {
    return async () => imageAnalyzerEvidence(
      module.id,
      "not_loaded",
      "Tesseract OCR runtime is disabled.",
      {
        reason: "window.__WASM_AGENT_TESSERACT_URL__ is empty",
        facts: ["No native OCR or Tesseract runtime was available for this turn."],
        confidence: 0,
      }
    );
  }
  try {
    if (!window.Tesseract) await loadScriptOnce(runtimeUrl);
  } catch (error) {
    return async () => imageAnalyzerEvidence(
      module.id,
      "not_loaded",
      "Tesseract OCR runtime could not be loaded.",
      {
        reason: error.message,
        facts: [`Tesseract runtime URL failed: ${runtimeUrl}`],
        confidence: 0,
      }
    );
  }
  const tesseract = window.Tesseract;
  if (!tesseract || (typeof tesseract.createWorker !== "function" && typeof tesseract.recognize !== "function")) {
    return async () => imageAnalyzerEvidence(
      module.id,
      "not_loaded",
      "Tesseract OCR API was not found after loading the runtime.",
      {
        reason: "window.Tesseract missing createWorker/recognize",
        facts: ["The OCR runtime loaded but did not expose a compatible API."],
        confidence: 0,
      }
    );
  }
  if (typeof tesseract.createWorker === "function") {
    try {
      const worker = await tesseract.createWorker(OCR_TESSERACT_LANGUAGE, 1, {
        logger: () => {},
      });
      if (typeof worker.load === "function") {
        try {
          await worker.load();
        } catch {
          // Newer Tesseract.js workers may already be loaded.
        }
      }
      if (typeof worker.loadLanguage === "function") {
        try {
          await worker.loadLanguage(OCR_TESSERACT_LANGUAGE);
        } catch {
          // Newer Tesseract.js workers may load language during createWorker.
        }
      }
      if (typeof worker.initialize === "function") {
        try {
          await worker.initialize(OCR_TESSERACT_LANGUAGE);
        } catch {
          // Newer Tesseract.js workers may initialize during createWorker.
        }
      }
      await configureTesseractWorker(worker, tesseract);
      return async (context) => {
        if (!context.dataUrl && !context.image) {
          return imageAnalyzerEvidence(module.id, "skipped", "No data URL was available for Tesseract OCR.", {
            reason: "missing_data_url",
            confidence: 0,
          });
        }
        if (!shouldRunTesseractOcr(context)) {
          return imageAnalyzerEvidence(module.id, "not_detected", "Tesseract OCR skipped because the image card did not find text-like regions.", {
            reason: "low_text_like_score",
            facts: ["No strong local text-like signal was available for OCR."],
            confidence: 0.72,
          });
        }
        const input = await prepareOcrInput(context);
        const result = await worker.recognize(input?.dataUrl || context.dataUrl);
        return ocrEvidenceFromResult(module, "tesseract.js", result, input);
      };
    } catch (error) {
      return async () => imageAnalyzerEvidence(
        module.id,
        "error",
        "Tesseract OCR worker could not be initialized.",
        {
          reason: error.message,
          facts: ["The Tesseract runtime loaded but worker setup failed."],
          confidence: 0,
        }
      );
    }
  }
  return async (context) => {
    if (!context.dataUrl && !context.image) {
      return imageAnalyzerEvidence(module.id, "skipped", "No data URL was available for Tesseract OCR.", {
        reason: "missing_data_url",
        confidence: 0,
      });
    }
    if (!shouldRunTesseractOcr(context)) {
      return imageAnalyzerEvidence(module.id, "not_detected", "Tesseract OCR skipped because the image card did not find text-like regions.", {
        reason: "low_text_like_score",
        facts: ["No strong local text-like signal was available for OCR."],
        confidence: 0.72,
      });
    }
    const input = await prepareOcrInput(context);
    const result = await tesseract.recognize(input?.dataUrl || context.dataUrl, OCR_TESSERACT_LANGUAGE, { logger: () => {} });
    return ocrEvidenceFromResult(module, "tesseract.js", result, input);
  };
}

async function createOcrAnalyzer(module) {
  const nativeAnalyzer = await createNativeOcrAnalyzer(module);
  let tesseractAnalyzerPromise = null;
  return async (context) => {
    const nativeResult = await nativeAnalyzer(context);
    if (nativeResult.status === "detected") return nativeResult;
    if (!tesseractAnalyzerPromise) tesseractAnalyzerPromise = createTesseractOcrAnalyzer(module);
    const tesseractAnalyzer = await tesseractAnalyzerPromise;
    const tesseractResult = await tesseractAnalyzer(context);
    if (tesseractResult.status === "detected") return tesseractResult;
    if (nativeResult.status !== "unsupported" && nativeResult.status !== "not_detected") return nativeResult;
    return {
      ...tesseractResult,
      facts: [
        ...(Array.isArray(tesseractResult.facts) ? tesseractResult.facts : []),
        `Native OCR status: ${nativeResult.status}`,
      ].slice(0, 8),
    };
  };
}

async function createImageAnalyzer(module) {
  if (module.id === "barcode-reader") return createBarcodeReaderAnalyzer(module);
  if (module.id === "ocr") return createOcrAnalyzer(module);
  if (module.id === "cv-shapes") return createUnavailableImageAnalyzer(module, "CV shape runtime not bundled");
  if (module.id === "semantic-vision") return createUnavailableImageAnalyzer(module, "Semantic vision runtime not bundled");
  return createUnavailableImageAnalyzer(module, "No lazy analyzer loader is registered");
}

async function loadImageAnalyzer(module) {
  const cached = IMAGE_ANALYZER_CACHE.has(module.id);
  if (!cached) {
    IMAGE_ANALYZER_CACHE.set(module.id, Promise.resolve(createImageAnalyzer(module)));
  }
  const analyzer = await IMAGE_ANALYZER_CACHE.get(module.id);
  return { analyzer, cached };
}

function withImageAnalyzerTimeout(promise, timeoutMs) {
  return new Promise((resolve, reject) => {
    const timer = window.setTimeout(() => reject(new Error("image analyzer timed out")), timeoutMs);
    Promise.resolve(promise).then(
      (value) => {
        window.clearTimeout(timer);
        resolve(value);
      },
      (error) => {
        window.clearTimeout(timer);
        reject(error);
      }
    );
  });
}

async function runImageAnalyzer(module, context) {
  const startedAt = performance.now();
  try {
    const { analyzer, cached } = await loadImageAnalyzer(module);
    const timeoutMs = module.id === "ocr" ? OCR_ANALYZER_TIMEOUT_MS : IMAGE_ANALYZER_TIMEOUT_MS;
    const result = await withImageAnalyzerTimeout(analyzer(context), timeoutMs);
    return {
      ...result,
      duration_ms: result.duration_ms ?? Math.round(performance.now() - startedAt),
      cached,
    };
  } catch (error) {
    return imageAnalyzerEvidence(
      module.id,
      error.message === "image analyzer timed out" ? "timeout" : "error",
      `${module.title} did not produce evidence.`,
      {
        reason: error.message,
        facts: [`${module.title} failed locally before the model turn.`],
        duration_ms: performance.now() - startedAt,
        confidence: 0,
      }
    );
  }
}

async function enrichImageCardWithModules(card, context) {
  const modules = imageAnalyzerModules()
    .filter((module) => module.id !== "image-card-core" && isModuleEnabled(module.id));
  const moduleContext = {
    ...context,
    card,
    imageCard: card,
    textSignals: card?.composition?.text_regions,
  };
  const results = await Promise.all(modules.map((module) => runImageAnalyzer(module, moduleContext)));
  return results.reduce((nextCard, result) => addImageAnalyzerResult(nextCard, result), {
    ...card,
    analyzer_modules: imageAnalyzerModuleStates(),
  });
}

async function analyzeImageElement(image, file, rawBytes, dataUrl) {
  const sourceWidth = Math.max(1, image.naturalWidth || image.width || AGENT_IMAGE_MAX_EDGE);
  const sourceHeight = Math.max(1, image.naturalHeight || image.height || AGENT_IMAGE_MAX_EDGE);
  const fallback = {
    schema: "hermes.wasm_agent.image_card.v1",
    analyzer_revision: IMAGE_CARD_ANALYZER_REVISION,
    name: file.name || "image",
    size: rawBytes,
    dimensions: `${sourceWidth}x${sourceHeight}`,
    width: sourceWidth,
    height: sourceHeight,
    palette: [],
    visual_notes: ["browser decoded image"],
    analyzer_modules: imageAnalyzerModuleStates(),
    evidence: [
      imageAnalyzerEvidence("image-card-core", isModuleEnabled("image-card-core") ? "active" : "disabled", "Browser decoded the image before the model turn.", {
        facts: isModuleEnabled("image-card-core")
          ? ["Core Canvas analyzer is available."]
          : ["Image Card Core module is disabled; only file metadata is available."],
        confidence: isModuleEnabled("image-card-core") ? 0.7 : 0,
      }),
    ],
  };
  fallback.module_results = { "image-card-core": fallback.evidence[0] };
  const context = { image, file, rawBytes, dataUrl, width: sourceWidth, height: sourceHeight };
  if (!isModuleEnabled("image-card-core")) return enrichImageCardWithModules(fallback, context);
  try {
    const scale = Math.min(1, AGENT_IMAGE_SAMPLE_EDGE / Math.max(sourceWidth, sourceHeight));
    const width = Math.max(1, Math.round(sourceWidth * scale));
    const height = Math.max(1, Math.round(sourceHeight * scale));
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext("2d", { willReadFrequently: true });
    if (!ctx) return enrichImageCardWithModules(fallback, context);
    ctx.drawImage(image, 0, 0, width, height);
    const { data } = ctx.getImageData(0, 0, width, height);
    const bins = new Map();
    const luma = new Float32Array(width * height);
    const mask = new Uint8Array(width * height);
    const lumaHistogram = new Array(16).fill(0);
    const regionStats = {
      center: { sum: 0, count: 0 },
      edges: { sum: 0, count: 0 },
      top_left: { sum: 0, count: 0 },
      top_right: { sum: 0, count: 0 },
      bottom_left: { sum: 0, count: 0 },
      bottom_right: { sum: 0, count: 0 },
      left: { sum: 0, count: 0 },
      right: { sum: 0, count: 0 },
      top: { sum: 0, count: 0 },
      bottom: { sum: 0, count: 0 },
    };
    let count = 0;
    let transparentCount = 0;
    let lumaSum = 0;
    let lumaSq = 0;
    let saturationSum = 0;
    let centerSum = 0;
    let centerCount = 0;
    let outerSum = 0;
    let outerCount = 0;
    let edgeCount = 0;
    let gradientSum = 0;
    let gradientComparisons = 0;
    const centerLeft = width * 0.3;
    const centerRight = width * 0.7;
    const centerTop = height * 0.3;
    const centerBottom = height * 0.7;

    for (let y = 0; y < height; y += 1) {
      for (let x = 0; x < width; x += 1) {
        const offset = (y * width + x) * 4;
        const alpha = data[offset + 3];
        if (alpha < 16) {
          transparentCount += 1;
          continue;
        }
        const red = data[offset];
        const green = data[offset + 1];
        const blue = data[offset + 2];
        const lum = (red * 0.299) + (green * 0.587) + (blue * 0.114);
        const index = y * width + x;
        luma[index] = lum;
        mask[index] = 1;
        lumaSum += lum;
        lumaSq += lum * lum;
        saturationSum += rgbToHsl(red, green, blue).saturation;
        lumaHistogram[Math.max(0, Math.min(15, Math.floor((lum / 256) * 16)))] += 1;
        count += 1;
        const key = `${red >> 5},${green >> 5},${blue >> 5}`;
        const bin = bins.get(key) || { count: 0, red: 0, green: 0, blue: 0 };
        bin.count += 1;
        bin.red += red;
        bin.green += green;
        bin.blue += blue;
        bins.set(key, bin);
        if (x >= centerLeft && x <= centerRight && y >= centerTop && y <= centerBottom) {
          centerSum += lum;
          centerCount += 1;
          regionStats.center.sum += lum;
          regionStats.center.count += 1;
        } else {
          outerSum += lum;
          outerCount += 1;
          regionStats.edges.sum += lum;
          regionStats.edges.count += 1;
        }
        const quadrant = y < height / 2
          ? (x < width / 2 ? "top_left" : "top_right")
          : (x < width / 2 ? "bottom_left" : "bottom_right");
        regionStats[quadrant].sum += lum;
        regionStats[quadrant].count += 1;
        const horizontalRegion = x < width / 2 ? "left" : "right";
        const verticalRegion = y < height / 2 ? "top" : "bottom";
        regionStats[horizontalRegion].sum += lum;
        regionStats[horizontalRegion].count += 1;
        regionStats[verticalRegion].sum += lum;
        regionStats[verticalRegion].count += 1;
        if (x > 0) {
          const previous = y * width + x - 1;
          if (mask[previous]) {
            const diff = Math.abs(lum - luma[previous]);
            gradientSum += diff;
            gradientComparisons += 1;
            if (diff > 32) edgeCount += 1;
          }
        }
        if (y > 0) {
          const previous = (y - 1) * width + x;
          if (mask[previous]) {
            const diff = Math.abs(lum - luma[previous]);
            gradientSum += diff;
            gradientComparisons += 1;
            if (diff > 32) edgeCount += 1;
          }
        }
      }
    }
    if (!count) return enrichImageCardWithModules(fallback, context);
    let mirrorPairs = 0;
    let horizontalMirrorDiff = 0;
    let verticalMirrorDiff = 0;
    for (let y = 0; y < height; y += 1) {
      for (let x = 0; x < Math.floor(width / 2); x += 1) {
        const left = y * width + x;
        const right = y * width + (width - 1 - x);
        if (mask[left] && mask[right]) {
          horizontalMirrorDiff += Math.abs(luma[left] - luma[right]);
          mirrorPairs += 1;
        }
      }
    }
    let verticalPairs = 0;
    for (let y = 0; y < Math.floor(height / 2); y += 1) {
      for (let x = 0; x < width; x += 1) {
        const top = y * width + x;
        const bottom = (height - 1 - y) * width + x;
        if (mask[top] && mask[bottom]) {
          verticalMirrorDiff += Math.abs(luma[top] - luma[bottom]);
          verticalPairs += 1;
        }
      }
    }
    const palette = [];
    const paletteHex = [];
    for (const bin of Array.from(bins.values()).sort((a, b) => b.count - a.count)) {
      const red = bin.red / bin.count;
      const green = bin.green / bin.count;
      const blue = bin.blue / bin.count;
      const name = colorName(red, green, blue);
      if (!palette.includes(name)) palette.push(name);
      const hex = rgbToHex(red, green, blue);
      if (!paletteHex.includes(hex)) paletteHex.push(hex);
      if (palette.length >= 5 && paletteHex.length >= 5) break;
    }
    const avgLuma = lumaSum / count;
    const contrast = Math.sqrt(Math.max(0, (lumaSq / count) - (avgLuma * avgLuma)));
    const edgeDensity = edgeCount / Math.max(1, (width - 1) * height + (height - 1) * width);
    const centerLuma = centerCount ? centerSum / centerCount : avgLuma;
    const outerLuma = outerCount ? outerSum / outerCount : avgLuma;
    const regionLuma = Object.fromEntries(
      Object.entries(regionStats).map(([key, stat]) => [key, stat.count ? stat.sum / stat.count : avgLuma])
    );
    const normalizedRegions = Object.fromEntries(
      Object.entries(regionLuma).map(([key, value]) => [key, roundedMetric(value / 255)])
    );
    const horizontalDelta = (regionLuma.right - regionLuma.left) / 255;
    const verticalDelta = (regionLuma.bottom - regionLuma.top) / 255;
    const centerEdgeDelta = (centerLuma - outerLuma) / 255;
    const entropy = lumaHistogram.reduce((sum, bin) => {
      if (!bin) return sum;
      const p = bin / count;
      return sum - (p * Math.log2(p));
    }, 0) / 4;
    const sharpness = gradientSum / Math.max(1, gradientComparisons) / 255;
    const horizontalSymmetry = 1 - Math.min(1, (horizontalMirrorDiff / Math.max(1, mirrorPairs)) / 255);
    const verticalSymmetry = 1 - Math.min(1, (verticalMirrorDiff / Math.max(1, verticalPairs)) / 255);
    const gradientStrength = Math.max(Math.abs(horizontalDelta), Math.abs(verticalDelta), Math.abs(centerEdgeDelta));
    const gradientKind = Math.abs(centerEdgeDelta) > Math.max(Math.abs(horizontalDelta), Math.abs(verticalDelta)) * 1.3
      ? (centerEdgeDelta > 0 ? "radial center glow" : "radial edge glow")
      : gradientDirection(horizontalDelta, verticalDelta);
    const textSignals = textLikeRegionSignals(luma, mask, width, height, avgLuma);
    const notes = [];
    const aspect = sourceWidth / sourceHeight;
    if (aspect >= 1.2) notes.push("landscape layout");
    else if (aspect <= 0.84) notes.push("portrait layout");
    else if (aspect >= 0.92 && aspect <= 1.08) notes.push("near-square layout");
    else notes.push("slightly rectangular layout");
    if (avgLuma < 72) notes.push("dark overall");
    else if (avgLuma > 182) notes.push("bright overall");
    if (contrast > 62) notes.push("high contrast");
    else if (contrast < 26) notes.push("low contrast");
    if (centerEdgeDelta > 0.11) notes.push("bright center");
    else if (centerEdgeDelta > 0.025) notes.push("center slightly brighter than edges");
    else if (centerEdgeDelta < -0.11) notes.push("brighter edges");
    else if (centerEdgeDelta < -0.025) notes.push("edges slightly brighter than center");
    if (edgeDensity > 0.2) notes.push("dense edge detail");
    else if (edgeDensity < 0.015) notes.push("almost no hard edges");
    else if (edgeDensity < 0.055) notes.push("soft or low-detail image");
    if (sharpness < 0.018 && edgeDensity < 0.03) notes.push("smooth gradient-like surface");
    if (textSignals.score > 0.32) notes.push("strong text-like dark strokes on lighter regions");
    else if (textSignals.score > 0.2) notes.push("possible printed text or label-like markings");
    if (textSignals.horizontal_band_estimate >= 2) notes.push(`${textSignals.horizontal_band_estimate} horizontal text-like bands`);
    if (textSignals.regions.length && textSignals.score > 0.2) notes.push(`text-like detail strongest near ${textSignals.regions[0]}`);
    if (gradientKind.includes("radial")) notes.push(gradientKind);
    if (horizontalSymmetry > 0.94 && verticalSymmetry > 0.94) notes.push("highly symmetrical brightness");
    if (saturationSum / count < 0.16) notes.push("mostly desaturated colors");
    else if (saturationSum / count > 0.55) notes.push("saturated colors");
    if (transparentCount / (width * height) > 0.05) notes.push("contains transparent regions");
    if (palette.length) notes.push(`dominant ${palette.slice(0, 3).join(", ")} palette`);
    const card = {
      ...fallback,
      analyzer_revision: IMAGE_CARD_ANALYZER_REVISION,
      palette,
      palette_hex: paletteHex.slice(0, 5),
      visual_notes: notes.slice(0, 12),
      perceptual_hash: averageHash(image),
      analysis: {
        average_luminance: roundedMetric(avgLuma / 255),
        contrast: roundedMetric(contrast / 255),
        edge_density: roundedMetric(edgeDensity),
        center_luminance: roundedMetric(centerLuma / 255),
        edge_luminance: roundedMetric(outerLuma / 255),
        center_edge_delta: roundedMetric(centerEdgeDelta),
        average_saturation: roundedMetric(saturationSum / count),
        sharpness: roundedMetric(sharpness),
        entropy: roundedMetric(entropy),
        transparency: roundedMetric(transparentCount / (width * height)),
        text_like_score: textSignals.score,
        text_band_estimate: textSignals.horizontal_band_estimate,
        text_active_cell_count: textSignals.active_cell_count,
        sample_size: `${width}x${height}`,
      },
      composition: {
        brightness_distribution: {
          ...normalizedRegions,
          center_label: luminanceWord(centerLuma / 255),
          edge_label: luminanceWord(outerLuma / 255),
        },
        gradient: {
          kind: gradientKind,
          strength: roundedMetric(gradientStrength),
          horizontal_delta: roundedMetric(horizontalDelta),
          vertical_delta: roundedMetric(verticalDelta),
          center_edge_delta: roundedMetric(centerEdgeDelta),
        },
        symmetry: {
          horizontal: roundedMetric(horizontalSymmetry),
          vertical: roundedMetric(verticalSymmetry),
        },
        text_regions: textSignals,
      },
    };
    card.evidence = [
      imageAnalyzerEvidence("image-card-core", "active", "Canvas pixel metrics computed locally.", {
        facts: [
          `${width}x${height} sample`,
          `${notes.length} visual notes`,
          `${palette.length} palette names`,
          `edge density ${roundedMetric(edgeDensity)}`,
          `text-like score ${textSignals.score}`,
        ],
        values: {
          sample_size: `${width}x${height}`,
          palette_count: palette.length,
          note_count: notes.length,
          text_like_score: textSignals.score,
          text_band_estimate: textSignals.horizontal_band_estimate,
        },
        confidence: 0.9,
      }),
    ];
    card.module_results = { "image-card-core": card.evidence[0] };
    card.analyzer_modules = imageAnalyzerModuleStates();
    return enrichImageCardWithModules(card, context);
  } catch {
    return enrichImageCardWithModules(fallback, context);
  }
}

async function readFileDataUrl(file, options = {}) {
  const processImage = options.processImage !== false;
  const rawDataUrl = await readFileAsDataUrl(file);
  const rawBytes = dataUrlByteLength(rawDataUrl);
  const base = {
    name: file.name || "image",
    original_type: file.type || "",
    original_size: file.size || rawBytes,
  };
  const image = await loadDataUrlImage(rawDataUrl, file.name || "image");
  const sourceWidth = Math.max(1, image.naturalWidth || image.width || AGENT_IMAGE_MAX_EDGE);
  const sourceHeight = Math.max(1, image.naturalHeight || image.height || AGENT_IMAGE_MAX_EDGE);
  const imageCard = processImage
    ? await analyzeImageElement(image, file, rawBytes, rawDataUrl)
    : agentImageProcessingSkippedCard(file, rawBytes, sourceWidth, sourceHeight);
  if (rawBytes <= AGENT_IMAGE_MAX_BYTES && file.type !== "image/svg+xml") {
    return {
      ...base,
      data_url: rawDataUrl,
      type: file.type || "image/png",
      size: rawBytes,
      width: sourceWidth,
      height: sourceHeight,
      image_card: imageCard,
    };
  }

  const scale = Math.min(1, AGENT_IMAGE_MAX_EDGE / Math.max(sourceWidth, sourceHeight));
  const width = Math.max(1, Math.round(sourceWidth * scale));
  const height = Math.max(1, Math.round(sourceHeight * scale));
  const canvas = document.createElement("canvas");
  let targetWidth = width;
  let targetHeight = height;
  canvas.width = targetWidth;
  canvas.height = targetHeight;
  const ctx = canvas.getContext("2d");
  if (!ctx) throw new Error(`Could not prepare ${file.name || "image"} for upload`);
  ctx.fillStyle = "#090f1b";
  ctx.fillRect(0, 0, targetWidth, targetHeight);
  ctx.drawImage(image, 0, 0, targetWidth, targetHeight);

  let dataUrl = "";
  for (let resizeAttempt = 0; resizeAttempt < 4; resizeAttempt += 1) {
    let quality = AGENT_IMAGE_QUALITY;
    for (let qualityAttempt = 0; qualityAttempt < 5; qualityAttempt += 1) {
      dataUrl = canvas.toDataURL("image/jpeg", quality);
      if (dataUrlByteLength(dataUrl) <= AGENT_IMAGE_MAX_BYTES || quality <= 0.42) break;
      quality -= 0.12;
    }
    if (dataUrlByteLength(dataUrl) <= AGENT_IMAGE_MAX_BYTES) break;
    targetWidth = Math.max(360, Math.round(targetWidth * 0.82));
    targetHeight = Math.max(240, Math.round(targetHeight * 0.82));
    canvas.width = targetWidth;
    canvas.height = targetHeight;
    ctx.fillStyle = "#090f1b";
    ctx.fillRect(0, 0, targetWidth, targetHeight);
    ctx.drawImage(image, 0, 0, targetWidth, targetHeight);
  }
  return {
    ...base,
    data_url: dataUrl,
    type: "image/jpeg",
    size: dataUrlByteLength(dataUrl),
    width: targetWidth,
    height: targetHeight,
    image_card: {
      ...imageCard,
      size: dataUrlByteLength(dataUrl),
      rendered_dimensions: `${targetWidth}x${targetHeight}`,
    },
  };
}

function handleAgentFiles(fileList) {
  const files = Array.from(fileList).filter(isAgentAttachmentFile);
  if (!files.length) return;
  const pendingCount = state.agentPendingImages.length
    + state.agentPendingAttachmentSummaries.length
    + state.agentPendingFileJobs.length;
  const slots = Math.max(0, AGENT_MAX_IMAGES - pendingCount);
  const selected = files.slice(0, slots);
  if (!selected.length) return;
  if (selected.length < files.length && els.agentStatus) {
    els.agentStatus.textContent = "Attachment limit reached";
  }
  const processingEnabled = state.agentImageProcessingEnabled;
  const jobs = selected.map((file) => createAgentPendingFileJob(file, processingEnabled));
  state.agentPendingFileJobs.push(...jobs);
  renderPendingPreviews();
  updateAgentSendButton();
  selected.forEach((file, index) => {
    void processAgentPendingFile(file, jobs[index]);
  });
}

function createAgentPendingFileJob(file, processingEnabled) {
  let previewUrl = "";
  if (isAgentImageFile(file) && typeof URL !== "undefined" && typeof URL.createObjectURL === "function") {
    try {
      previewUrl = URL.createObjectURL(file);
    } catch {
      previewUrl = "";
    }
  }
  return {
    id: `file_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`,
    name: cleanText(file?.name, "Attachment"),
    type: cleanText(file?.type, ""),
    size: Number(file?.size || 0),
    media_kind: isAgentVideoFile(file) ? "video" : "image",
    preview_url: previewUrl,
    processing_enabled: Boolean(processingEnabled),
  };
}

function revokeAgentPendingFileJob(job) {
  if (!job?.preview_url || typeof URL === "undefined" || typeof URL.revokeObjectURL !== "function") return;
  try {
    URL.revokeObjectURL(job.preview_url);
  } catch {
    // Object URL revocation is best-effort cleanup.
  }
}

function removePendingFileJob(index) {
  const [job] = state.agentPendingFileJobs.splice(index, 1);
  revokeAgentPendingFileJob(job);
  renderPendingPreviews();
  updateAgentSendButton();
}

function finishPendingFileJob(job) {
  const index = state.agentPendingFileJobs.findIndex((item) => item.id === job?.id);
  if (index < 0) return false;
  const [removed] = state.agentPendingFileJobs.splice(index, 1);
  revokeAgentPendingFileJob(removed);
  return true;
}

function acceptAgentAttachmentEntry(entry) {
  if (String(entry?.media_kind || "").toLowerCase() === "video" || String(entry?.type || "").startsWith("video/")) {
    state.agentPendingAttachmentSummaries.push(entry);
    return "summarized";
  }
  const bytes = agentImagePayloadBytes(entry);
  const nextBytes = agentPendingImageBytes();
  if (bytes > AGENT_IMAGE_MAX_BYTES || nextBytes + bytes > AGENT_IMAGE_TOTAL_MAX_BYTES) {
    state.agentPendingAttachmentSummaries.push(agentAttachmentSummary(entry, "summarized_to_fit_request_budget"));
    return "summarized";
  }
  state.agentPendingImages.push(entry);
  return "raw";
}

async function processAgentPendingFile(file, job) {
  try {
    const entry = isAgentVideoFile(file)
      ? await readVideoFileSummary(file)
      : await readFileDataUrl(file, { processImage: job.processing_enabled });
    if (!finishPendingFileJob(job)) return;
    const acceptedAs = acceptAgentAttachmentEntry(entry);
    renderPendingPreviews();
    updateAgentSendButton();
    if (acceptedAs === "summarized" && els.agentStatus) {
      els.agentStatus.textContent = "Attachments summarized";
      recordUserEvent("agent.image_attach_error", {
        target: "agent-form",
        summary: `${entry.name || "Attachment"} was summarized for the request budget`,
        data: {
          summarized_count: 1,
          raw_budget_bytes: AGENT_IMAGE_TOTAL_MAX_BYTES,
        },
      });
    }
  } catch (error) {
    if (!finishPendingFileJob(job)) return;
    renderPendingPreviews();
    updateAgentSendButton();
    if (els.agentStatus) els.agentStatus.textContent = "Attachment failed";
    recordUserEvent("agent.image_attach_error", {
      target: "agent-form",
      summary: `Could not attach ${file?.name || "file"} as raw payload`,
      data: { error: error.message || String(error || "") },
    });
  }
}

function removePendingImage(index) {
  state.agentPendingImages.splice(index, 1);
  renderPendingPreviews();
  updateAgentSendButton();
}

function removePendingAttachmentSummary(index) {
  state.agentPendingAttachmentSummaries.splice(index, 1);
  renderPendingPreviews();
  updateAgentSendButton();
}

function clearAgentPendingImages() {
  state.agentPendingFileJobs.forEach(revokeAgentPendingFileJob);
  state.agentPendingFileJobs = [];
  state.agentPendingImages = [];
  state.agentPendingAttachmentSummaries = [];
  renderPendingPreviews();
  updateAgentSendButton();
}

function renderAgentImageProcessingToggle() {
  if (!els.agentImageProcessingToggle) return;
  els.agentImageProcessingToggle.checked = Boolean(state.agentImageProcessingEnabled);
  if (els.agentImageScanInfoButton) {
    els.agentImageScanInfoButton.setAttribute("aria-expanded", state.agentImageScanInfoOpen ? "true" : "false");
  }
  if (els.agentImageScanInfoBalloon) {
    els.agentImageScanInfoBalloon.hidden = !state.agentImageScanInfoOpen;
  }
}

function closeAgentImageScanInfo() {
  if (!state.agentImageScanInfoOpen) return;
  state.agentImageScanInfoOpen = false;
  renderAgentImageProcessingToggle();
}

function attachmentUsesImageScan(entry) {
  if (!entry) return false;
  if (String(entry.media_kind || "").toLowerCase() === "image") return true;
  const type = String(entry.type || entry.original_type || "").toLowerCase();
  return type.startsWith("image/") || Boolean(entry.image_card);
}

function pendingAttachmentsUseImageScan() {
  return state.agentPendingFileJobs.some((job) => job.media_kind === "image")
    || state.agentPendingImages.some(attachmentUsesImageScan)
    || state.agentPendingAttachmentSummaries.some(attachmentUsesImageScan);
}

function renderPendingPreviews() {
  const preview = els.agentImagePreview;
  renderAgentImageProcessingToggle();
  const previewList = els.agentImagePreviewList || preview;
  if (!preview || !previewList) return;
  const summaryEntries = state.agentPendingAttachmentSummaries;
  const processingJobs = state.agentPendingFileJobs;
  if (!state.agentPendingImages.length && !summaryEntries.length && !processingJobs.length) {
    previewList.replaceChildren();
    preview.hidden = true;
    closeAgentImageScanInfo();
    if (els.agentImagePreviewControls) els.agentImagePreviewControls.hidden = true;
    renderAgentImageProcessingToggle();
    return;
  }
  preview.hidden = false;
  const scanRelevant = pendingAttachmentsUseImageScan();
  if (!scanRelevant) closeAgentImageScanInfo();
  if (els.agentImagePreviewControls) els.agentImagePreviewControls.hidden = !scanRelevant;
  renderAgentImageProcessingToggle();
  const processingItems = processingJobs.map((job, i) => {
    const item = document.createElement("div");
    item.className = "agent-image-preview-item is-processing";
    if (job.preview_url) {
      const img = document.createElement("img");
      img.src = job.preview_url;
      img.alt = job.name;
      item.append(img);
    } else {
      const file = document.createElement("span");
      file.className = "agent-image-preview-file";
      file.textContent = job.media_kind === "video" ? "MP4" : "IMG";
      item.append(file);
    }
    const status = document.createElement("span");
    status.className = "agent-image-preview-status";
    status.textContent = job.processing_enabled ? "Processing" : "Preparing";
    const remove = document.createElement("button");
    remove.className = "agent-image-preview-remove";
    remove.type = "button";
    remove.setAttribute("aria-label", `Remove ${job.name}`);
    remove.innerHTML = '<svg viewBox="0 0 10 10"><path d="M2 2l6 6M8 2l-6 6"/></svg>';
    remove.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      removePendingFileJob(i);
    });
    item.append(status, remove);
    return item;
  });
  const rawItems = state.agentPendingImages.map((entry, i) => {
    const item = document.createElement("div");
    item.className = "agent-image-preview-item";
    const img = document.createElement("img");
    img.src = entry.data_url;
    img.alt = entry.name;
    const remove = document.createElement("button");
    remove.className = "agent-image-preview-remove";
    remove.type = "button";
    remove.setAttribute("aria-label", `Remove ${entry.name}`);
    remove.innerHTML = '<svg viewBox="0 0 10 10"><path d="M2 2l6 6M8 2l-6 6"/></svg>';
    remove.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      removePendingImage(i);
    });
    item.append(img, remove);
    return item;
  });
  const summaryItems = summaryEntries.map((entry, i) => {
    const item = document.createElement("div");
    item.className = "agent-image-preview-item is-summary";
    const label = document.createElement("span");
    label.className = "agent-image-preview-file";
    label.textContent = entry.name;
    const meta = document.createElement("span");
    meta.className = "agent-image-preview-file-meta";
    meta.textContent = entry.media_kind === "video" || String(entry.type || "").startsWith("video/")
      ? attachmentMetaText(entry)
      : "summarized";
    const remove = document.createElement("button");
    remove.className = "agent-image-preview-remove";
    remove.type = "button";
    remove.setAttribute("aria-label", `Remove ${entry.name}`);
    remove.innerHTML = '<svg viewBox="0 0 10 10"><path d="M2 2l6 6M8 2l-6 6"/></svg>';
    remove.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      removePendingAttachmentSummary(i);
    });
    item.append(label, meta, remove);
    return item;
  });
  previewList.replaceChildren(...processingItems, ...rawItems, ...summaryItems);
}

function imageCardSummary(image) {
  const card = image?.image_card && typeof image.image_card === "object" ? image.image_card : {};
  const evidence = Array.isArray(card.evidence) ? card.evidence.slice(0, 8) : [];
  const moduleResults = card.module_results && typeof card.module_results === "object" ? card.module_results : undefined;
  const analyzerModules = Array.isArray(card.analyzer_modules) ? card.analyzer_modules.slice(0, 8) : [];
  return {
    analyzer_revision: cleanText(card.analyzer_revision, ""),
    name: cleanText(card.name || image?.name, "image"),
    size: Number.isFinite(card.size) ? card.size : agentImagePayloadBytes(image),
    dimensions: cleanText(card.dimensions || (image?.width && image?.height ? `${image.width}x${image.height}` : ""), ""),
    palette: Array.isArray(card.palette) ? card.palette.slice(0, 5) : [],
    visual_notes: Array.isArray(card.visual_notes) ? card.visual_notes.slice(0, 10) : [],
    composition: card.composition && typeof card.composition === "object" ? card.composition : undefined,
    analysis: card.analysis && typeof card.analysis === "object" ? card.analysis : undefined,
    evidence,
    module_results: moduleResults,
    analyzer_modules: analyzerModules,
    local_url: String(card.local_url || image?.asset?.local_url || "").trim(),
    hash: String(card.hash || image?.asset?.hash || card.perceptual_hash || "").trim(),
  };
}

function providerAttachmentManifestText(imageCards) {
  const cards = (Array.isArray(imageCards) ? imageCards : []).map((card, index) => ({
    index: index + 1,
    name: cleanText(card.name, `attachment-${index + 1}`),
    dimensions: cleanText(card.dimensions, ""),
    size: Number.isFinite(card.size) ? card.size : undefined,
    palette: Array.isArray(card.palette) ? card.palette.slice(0, 4) : [],
    visual_notes: Array.isArray(card.visual_notes) ? card.visual_notes.slice(0, 8) : [],
    text_like_score: Number.isFinite(card.analysis?.text_like_score) ? card.analysis.text_like_score : undefined,
    modules: Object.values(card.module_results || {}).map((result) => ({
      module: cleanText(result.module, ""),
      status: cleanText(result.status, ""),
      summary: cleanText(result.summary, ""),
      facts: Array.isArray(result.facts) ? result.facts.slice(0, 4) : [],
    })).slice(0, 6),
  }));
  if (!cards.length) return "";
  return `\n\nAttached media manifest (local browser analysis; OpenRouter provider turns also try image_url content parts when local image data is available):\n${JSON.stringify(cards, null, 2)}`;
}

function agentImageCardPreview(images, attachments) {
  return JSON.stringify([...images, ...attachments].map(imageCardSummary), null, 2);
}

async function storeAgentImageAsset(entry, signal) {
  if (!entry?.data_url || entry.asset?.local_url) return entry;
  const payload = await fetchJson("/agent/attachments", {
    method: "POST",
    timeoutMs: 45000,
    signal,
    body: {
      image: {
        data_url: entry.data_url,
        name: entry.name,
        type: entry.type,
        size: entry.size,
        width: entry.width,
        height: entry.height,
        original_type: entry.original_type,
        original_size: entry.original_size,
        image_card: entry.image_card,
      },
    },
  });
  if (payload.asset) {
    entry.asset = payload.asset;
    entry.image_card = payload.asset.image_card || entry.image_card;
  }
  return entry;
}

async function storeAgentAttachmentAssets(images, attachments, pendingMessage) {
  const allEntries = [...images, ...attachments];
  const entries = allEntries.filter((entry) => entry?.data_url);
  const metadataOnly = allEntries.length - entries.length;
  if (!entries.length) {
    if (allEntries.length) {
      mergeAgentAction(pendingMessage, {
        id: "client_store_image_assets",
        topic: "run-wasm",
        kind: "media",
        label: "Prepare attachments",
        status: "done",
        detail: `${metadataOnly} metadata-only`,
        meta: "local metadata",
        preview: agentImageCardPreview(images, attachments),
      });
    }
    return { stored: 0, failed: 0 };
  }
  let stored = 0;
  let failed = 0;
  for (const entry of entries) {
    try {
      await storeAgentImageAsset(entry, state.agentAbortController?.signal);
      stored += 1;
    } catch (error) {
      failed += 1;
      recordUserEvent("agent.image_store_error", {
        target: "agent-overlay",
        summary: `Could not store ${entry.name || "image"} locally`,
        data: { error: error.message },
      });
    }
    mergeAgentAction(pendingMessage, {
      id: "client_store_image_assets",
      topic: "run-wasm",
      kind: "media",
      label: "Prepare attachments",
      status: failed ? "error" : "running",
      detail: `${stored}/${entries.length} stored${metadataOnly ? ` / ${metadataOnly} metadata-only` : ""}${failed ? ` / ${failed} failed` : ""}`,
      meta: "local store",
      preview: agentImageCardPreview(images, attachments),
    });
  }
  mergeAgentAction(pendingMessage, {
    id: "client_store_image_assets",
    topic: "run-wasm",
    kind: "media",
    label: "Prepare attachments",
    status: failed ? "error" : "done",
    detail: `${stored}/${entries.length} stored${metadataOnly ? ` / ${metadataOnly} metadata-only` : ""}${failed ? ` / ${failed} failed` : ""}`,
    meta: "local store",
    preview: agentImageCardPreview(images, attachments),
  });
  return { stored, failed };
}

function updateAgentSendButton() {
  if (!els.agentSendButton) return;
  const socialChat = socialChatSession(activeAgentSession());
  const processingAttachments = !state.agentBusy && agentPendingFileJobCount() > 0;
  els.agentSendButton.classList.toggle("is-busy", state.agentBusy);
  els.agentSendButton.disabled = processingAttachments || (socialChat && state.agentBusy);
  els.agentSendButton.setAttribute("aria-label", state.agentBusy ? (socialChat ? "Syncing message" : "Stop response") : "Send message");
  els.agentSendButton.title = processingAttachments ? "Processing attachments" : state.agentBusy ? (socialChat ? "Syncing" : "Stop") : "Send";
}

function updateAgentTurnTimer() {
  if (!state.agentThinkingMessageId) return;
  const session = activeAgentSession();
  const message = session.messages.find((item) => item.id === state.agentThinkingMessageId);
  if (!message?.pending) return;
  const elapsed = Date.now() - Number(message.turn_started_at || Date.now());
  document.querySelectorAll(`.agent-turn-elapsed[data-message-id="${message.id}"]`).forEach((element) => {
    element.textContent = formatTurnElapsed(elapsed);
  });
}

function startAgentTurnTimer(message) {
  window.clearInterval(state.agentTurnTimer);
  state.agentThinkingMessageId = message?.id || "";
  updateAgentTurnTimer();
  state.agentTurnTimer = window.setInterval(updateAgentTurnTimer, 1000);
}

function stopAgentTurnTimer() {
  window.clearInterval(state.agentTurnTimer);
  state.agentTurnTimer = 0;
  state.agentThinkingMessageId = "";
}

function updateAgentPendingMessage(message, updates = {}) {
  if (!message) return;
  Object.assign(message, updates);
  saveAgentSessions();
  scheduleRenderAgentMessages();
}

let agentMessagesRafId = 0;
function scheduleRenderAgentMessages() {
  if (!agentMessagesRafId) {
    agentMessagesRafId = requestAnimationFrame(() => {
      agentMessagesRafId = 0;
      renderAgentMessages();
    });
  }
}

function stopAgentMessage() {
  if (!state.agentBusy) return;
  state.agentStopRequested = true;
  state.agentAbortController?.abort();
}

function installDevHmrBridge() {
  const bridge = {
    requestReload(paths = []) {
      if (!state.agentBusy) {
        if (requestAndroidNativeWebRuntimeReload(paths, "dev_hmr")) return true;
        const nativeBridge = (window.__wasmAgentNativeDevHmr && window.__wasmAgentNativeDevHmr !== bridge)
          ? window.__wasmAgentNativeDevHmr
          : (window.__wasmAgentDevHmr && window.__wasmAgentDevHmr !== bridge)
            ? window.__wasmAgentDevHmr
            : null;
        try {
          const reloadResult = nativeBridge?.requestReload?.(paths);
          if (reloadResult) {
            if (typeof reloadResult.catch === "function") {
              reloadResult.catch((error) => {
                nativeAuthDiagnostic("dev_hmr_native_bridge_reload_error", {
                  message: errorMessage(error),
                  name: cleanText(error?.name, ""),
                });
              });
            }
            return true;
          }
        } catch (error) {
          nativeAuthDiagnostic("dev_hmr_native_bridge_reload_error", {
            message: errorMessage(error),
            name: cleanText(error?.name, ""),
          });
        }
        return false;
      }
      state.agentDeferredHmrReload = {
        paths: Array.isArray(paths) ? paths : [],
        requested_at: Date.now(),
      };
      const pendingMessage = activeAgentSession().messages.find((item) => item.id === state.agentThinkingMessageId);
      if (pendingMessage) {
        const actions = Array.isArray(pendingMessage.actions) ? [...pendingMessage.actions] : [];
        if (!actions.some((action) => action.id === "dev_hmr_deferred")) {
          const changedCount = state.agentDeferredHmrReload.paths.length || 1;
          actions.push({
            id: "dev_hmr_deferred",
            kind: "hmr",
            label: "Dev HMR update queued",
            status: "running",
            detail: `${changedCount} source change${changedCount === 1 ? "" : "s"}`,
            meta: "deferred",
            preview: state.agentDeferredHmrReload.paths.slice(0, 20).join("\n"),
          });
        }
        updateAgentPendingMessage(pendingMessage, { actions });
      }
      recordUserEvent("agent.hmr_deferred", {
        target: "agent-overlay",
        summary: "Deferred dev HMR until the embedded assistant turn finishes",
        data: { paths: state.agentDeferredHmrReload.paths.slice(0, 12) },
      });
      return true;
    },
  };
  try {
    window.__wasmAgentAppDevHmr = bridge;
  } catch (error) {
    nativeAuthDiagnostic("dev_hmr_app_bridge_install_error", {
      message: errorMessage(error),
      name: cleanText(error?.name, ""),
    });
  }
  try {
    if (!window.__wasmAgentDevHmr) {
      window.__wasmAgentDevHmr = bridge;
    } else if (window.__wasmAgentDevHmr !== bridge) {
      nativeAuthDiagnostic("dev_hmr_legacy_bridge_preserved", {
        has_request_reload: Boolean(window.__wasmAgentDevHmr?.requestReload),
      });
    }
  } catch (error) {
    nativeAuthDiagnostic("dev_hmr_legacy_bridge_install_error", {
      message: errorMessage(error),
      name: cleanText(error?.name, ""),
    });
  }
}

function flushDeferredHmrReload() {
  if (!state.agentDeferredHmrReload || state.agentBusy) return;
  const deferred = state.agentDeferredHmrReload;
  state.agentDeferredHmrReload = null;
  saveAgentSessions();
  window.setTimeout(() => {
    recordUserEvent("agent.hmr_reloading", {
      target: "agent-overlay",
      summary: "Applying deferred dev HMR reload",
      data: { paths: deferred.paths.slice(0, 12) },
    });
    if (!requestAndroidNativeWebRuntimeReload(deferred.paths, "deferred_dev_hmr")) {
      window.location.reload();
    }
  }, 240);
}

function requestAndroidNativeWebRuntimeReload(paths = [], reason = "dev_hmr") {
  if (!isAndroidNativeShell()) return false;
  const bridge = window.wasmAgentNative || window.wasmAgentAndroid;
  if (typeof bridge?.hardReloadWebRuntime !== "function") {
    void clearAndroidWebRuntimeCachesAndReload(paths, reason);
    return true;
  }
  try {
    const result = parseNativeBridgePayload(bridge.hardReloadWebRuntime(JSON.stringify({
      reason,
      paths: Array.isArray(paths) ? paths.slice(0, 20) : [],
    })));
    nativeAuthDiagnostic("dev_hmr_android_hard_reload_requested", {
      ok: result?.ok !== false,
      reason,
      path_count: Array.isArray(paths) ? paths.length : 0,
    });
    return result?.ok !== false;
  } catch (error) {
    nativeAuthDiagnostic("dev_hmr_android_hard_reload_error", {
      message: errorMessage(error),
      name: cleanText(error?.name, ""),
    });
    return false;
  }
}

async function clearAndroidWebRuntimeCachesAndReload(paths = [], reason = "dev_hmr_fallback") {
  nativeAuthDiagnostic("dev_hmr_android_web_fallback_reload_started", {
    reason,
    path_count: Array.isArray(paths) ? paths.length : 0,
  });
  try {
    if (navigator.serviceWorker?.getRegistrations) {
      const registrations = await navigator.serviceWorker.getRegistrations();
      await Promise.all(registrations.map((registration) => registration.unregister()));
    }
  } catch (error) {
    nativeAuthDiagnostic("dev_hmr_android_web_fallback_sw_error", {
      message: errorMessage(error),
    });
  }
  try {
    if (window.caches?.keys) {
      const keys = await window.caches.keys();
      await Promise.all(keys.map((key) => window.caches.delete(key)));
    }
  } catch (error) {
    nativeAuthDiagnostic("dev_hmr_android_web_fallback_cache_error", {
      message: errorMessage(error),
    });
  }
  const url = new URL(window.location.href);
  url.searchParams.set("native_refresh", Date.now().toString());
  url.searchParams.set("hmr_reason", reason);
  window.location.replace(url.toString());
}

function shouldStartDevHmr() {
  if (isAndroidNativeShell()) return !window.__WASM_AGENT_DISABLE_HMR__;
  return !window.__WASM_AGENT_DISABLE_HMR__ && (window.__WASM_AGENT_DISABLE_SW__ || isModuleEnabled("dev-hmr"));
}

function agentContextDialectString(items = []) {
  return (Array.isArray(items) ? items : [])
    .map((item) => [
      item.tool || "",
      item.path || "",
      item.query ? `query=${item.query}` : "",
      Number.isFinite(item.bytes) ? `${item.bytes}b` : "",
      item.preview || "",
    ].filter(Boolean).join(" "))
    .map((value) => String(value || "").replace(/\s+/g, " ").trim())
    .filter(Boolean)
    .join(" | ");
}

function renderAgentContextPreview(items = []) {
  state.agentContextString = agentContextDialectString(items);
  if (els.agentContextPreview) {
    els.agentContextPreview.textContent = state.agentContextString;
    els.agentContextPreview.hidden = true;
  }
  renderAgentDiagnostics(activeAgentSession().diagnostics || {});
}

function setAgentBalloon(kind) {
  const sessionsOpen = kind === "sessions";
  const contextOpen = kind === "context";
  const settingsOpen = kind === "settings";
  const modelOpen = kind === "model";
  if (els.agentSessionsBalloon) els.agentSessionsBalloon.hidden = !sessionsOpen;
  if (els.agentContextBalloon) els.agentContextBalloon.hidden = !contextOpen;
  if (els.agentSettingsBalloon) els.agentSettingsBalloon.hidden = !settingsOpen;
  if (els.agentModelBalloon && !modelOpen && !state.agentModelSetup.busy) {
    state.agentModelSetup.open = false;
    renderAgentModelSetupBalloon();
  }
  els.agentSessionsButton?.setAttribute("aria-expanded", sessionsOpen ? "true" : "false");
  els.agentTokenUsage?.setAttribute("aria-expanded", contextOpen ? "true" : "false");
  els.agentSettingsButton?.setAttribute("aria-expanded", settingsOpen ? "true" : "false");
  if (settingsOpen) renderAgentVoiceWakeSettings();
}

function toggleAgentBalloon(kind) {
  const target = kind === "sessions"
    ? els.agentSessionsBalloon
    : kind === "settings"
      ? els.agentSettingsBalloon
      : kind === "model"
        ? els.agentModelBalloon
        : els.agentContextBalloon;
  setAgentBalloon(target?.hidden ? kind : "");
}

function applyAgentLayout() {
  applyAgentPanelSize();
  state.agentLayout = clampAgentLayout(state.agentLayout);
  const { left, top } = state.agentLayout;
  if (Number.isFinite(left) && Number.isFinite(top)) {
    els.agentOverlay.style.left = `${left}px`;
    els.agentOverlay.style.top = `${top}px`;
    els.agentOverlay.style.right = "auto";
    els.agentOverlay.style.bottom = "auto";
  }
  placeAgentPanel();
}

function appViewportRect() {
  const viewport = window.visualViewport;
  if (viewport) {
    return {
      left: viewport.offsetLeft,
      top: viewport.offsetTop,
      right: viewport.offsetLeft + viewport.width,
      bottom: viewport.offsetTop + viewport.height,
      width: viewport.width,
      height: viewport.height,
    };
  }
  return els.app?.getBoundingClientRect?.() || {
    left: 0,
    top: 0,
    right: window.innerWidth,
    bottom: window.innerHeight,
    width: window.innerWidth,
    height: window.innerHeight,
  };
}

function defaultAgentLayout() {
  const appRect = appViewportRect();
  const { width, height } = agentAvatarSize();
  return {
    left: appRect.right - width - AGENT_AVATAR_VIEWPORT_GAP_PX,
    top: appRect.bottom - height - AGENT_AVATAR_VIEWPORT_GAP_PX,
  };
}

function agentAvatarSize() {
  const rect = els.agentAvatarButton?.getBoundingClientRect?.();
  return {
    width: Math.max(58, rect?.width || els.agentAvatarButton?.offsetWidth || 58),
    height: Math.max(58, rect?.height || els.agentAvatarButton?.offsetHeight || 58),
  };
}

function clampAgentLayout(layout) {
  const appRect = appViewportRect();
  const { width, height } = agentAvatarSize();
  const gap = AGENT_AVATAR_VIEWPORT_GAP_PX;
  const fallback = defaultAgentLayout();
  const fallbackLeft = fallback.left;
  const fallbackTop = fallback.top;
  const rawLeft = Number.isFinite(layout?.left) ? layout.left : fallbackLeft;
  const rawTop = Number.isFinite(layout?.top) ? layout.top : fallbackTop;
  const minLeft = appRect.left + gap;
  const maxLeft = Math.max(minLeft, appRect.right - width - gap);
  const minTop = appRect.top + gap;
  const maxTop = Math.max(minTop, appRect.bottom - height - gap);
  return {
    left: Math.max(minLeft, Math.min(maxLeft, rawLeft)),
    top: Math.max(minTop, Math.min(maxTop, rawTop)),
  };
}

function resetAgentToViewportCorner() {
  const size = clampAgentPanelSize(state.agentLayout);
  state.agentLayout = { ...clampAgentLayout(defaultAgentLayout()), panelWidth: size.width, panelHeight: size.height };
  els.agentOverlay.style.left = `${state.agentLayout.left}px`;
  els.agentOverlay.style.top = `${state.agentLayout.top}px`;
  els.agentOverlay.style.right = "auto";
  els.agentOverlay.style.bottom = "auto";
  state.agentPanelSide = "";
  placeAgentPanel();
}

function syncAgentAppBounds() {
  const rect = appViewportRect();
  els.agentOverlay.style.setProperty("--agent-app-width", `${Math.max(320, rect.width)}px`);
  els.agentOverlay.style.setProperty("--agent-app-height", `${Math.max(1, rect.height)}px`);
}

function placeAgentPanel() {
  const overlay = els.agentOverlay;
  const panel = els.agentPanel;
  if (!overlay || !panel) return;
  syncAgentAppBounds();
  applyAgentPanelSize();
  if (!state.agentOpen) return;
  const gap = AGENT_PANEL_VIEWPORT_GAP_PX;
  const avatarGap = AGENT_PANEL_AVATAR_GAP_PX;
  const appRect = appViewportRect();
  const overlayRect = overlay.getBoundingClientRect();
  const panelRect = panel.getBoundingClientRect();
  const panelWidth = panelRect.width || 430;
  const panelHeight = panelRect.height || 620;
  if (isCompactViewport()) {
    panel.style.left = `${appRect.left - overlayRect.left}px`;
    panel.style.top = `${appRect.top - overlayRect.top}px`;
    panel.style.right = "auto";
    panel.style.bottom = "auto";
    panel.dataset.x = "fullscreen";
    panel.dataset.y = "fullscreen";
    return;
  }
  const minLeft = appRect.left + gap;
  const maxLeft = Math.max(minLeft, appRect.right - panelWidth - gap);
  const minTop = appRect.top + gap;
  const maxTop = Math.max(minTop, appRect.bottom - panelHeight - gap);
  const leftSideLeft = overlayRect.left - panelWidth - avatarGap;
  const rightSideLeft = overlayRect.right + avatarGap;
  const leftFits = leftSideLeft >= minLeft;
  const rightFits = rightSideLeft <= maxLeft;
  let side = state.agentPanelSide || "left";
  if (side === "left" && !leftFits && rightFits) side = "right";
  if (side === "right" && !rightFits && leftFits) side = "left";
  if (!leftFits && !rightFits) side = overlayRect.left > appRect.left + appRect.width / 2 ? "left" : "right";
  state.agentPanelSide = side;
  const rawLeft = side === "right" ? rightSideLeft : leftSideLeft;
  const preferredTop = overlayRect.top + overlayRect.height / 2 - panelHeight / 2;
  const left = Math.max(minLeft, Math.min(maxLeft, rawLeft));
  const top = Math.max(minTop, Math.min(maxTop, preferredTop));
  panel.style.left = `${left - overlayRect.left}px`;
  panel.style.top = `${top - overlayRect.top}px`;
  panel.style.right = "auto";
  panel.style.bottom = "auto";
  panel.dataset.y = top > preferredTop + 1 ? "lower" : top < preferredTop - 1 ? "upper" : "center";
  panel.dataset.x = side;
}

function moveAgentGroupFromPanelRect(panelLeft, panelTop, panelWidth, panelHeight) {
  const appRect = appViewportRect();
  const avatar = agentAvatarSize();
  const gap = AGENT_PANEL_AVATAR_GAP_PX;
  const minPanelLeft = appRect.left + AGENT_PANEL_VIEWPORT_GAP_PX;
  const maxPanelLeft = Math.max(minPanelLeft, appRect.right - panelWidth - AGENT_PANEL_VIEWPORT_GAP_PX);
  const minPanelTop = appRect.top + AGENT_PANEL_VIEWPORT_GAP_PX;
  const maxPanelTop = Math.max(minPanelTop, appRect.bottom - panelHeight - AGENT_PANEL_VIEWPORT_GAP_PX);
  const left = clamp(panelLeft, minPanelLeft, maxPanelLeft);
  const top = clamp(panelTop, minPanelTop, maxPanelTop);
  const avatarOnRight = left + panelWidth / 2 < appRect.left + appRect.width / 2;
  state.agentPanelSide = avatarOnRight ? "left" : "right";
  const overlayLeft = avatarOnRight ? left + panelWidth + gap : left - avatar.width - gap;
  const overlayTop = top + panelHeight / 2 - avatar.height / 2;
  state.agentLayout = clampAgentLayout({ left: overlayLeft, top: overlayTop });
  els.agentOverlay.style.left = `${state.agentLayout.left}px`;
  els.agentOverlay.style.top = `${state.agentLayout.top}px`;
  els.agentOverlay.style.right = "auto";
  els.agentOverlay.style.bottom = "auto";
  placeAgentPanel();
}

function installAgentDragging() {
  els.agentAvatarButton.addEventListener("pointerdown", (event) => {
    if (!isPrimaryPointer(event)) return;
    event.preventDefault();
    const start = els.agentOverlay.getBoundingClientRect();
    const offsetX = event.clientX - start.left;
    const offsetY = event.clientY - start.top;
    const startX = event.clientX;
    const startY = event.clientY;
    let moved = false;
    document.body.classList.add("is-agent-dragging");
    try {
      els.agentAvatarButton.setPointerCapture(event.pointerId);
    } catch {
      // Some browser/devtool reload states can drop capture; window listeners still carry the drag.
    }
    const move = (moveEvent) => {
      if (Math.hypot(moveEvent.clientX - startX, moveEvent.clientY - startY) > 3) moved = true;
      const { left, top } = clampAgentLayout({
        left: moveEvent.clientX - offsetX,
        top: moveEvent.clientY - offsetY,
      });
      els.agentOverlay.style.left = `${left}px`;
      els.agentOverlay.style.top = `${top}px`;
      els.agentOverlay.style.right = "auto";
      els.agentOverlay.style.bottom = "auto";
      state.agentLayout = { left, top };
      placeAgentPanel();
    };
    const end = () => {
      document.body.classList.remove("is-agent-dragging");
      window.removeEventListener("pointermove", move);
      window.removeEventListener("pointerup", end);
      window.removeEventListener("pointercancel", end);
      state.agentLayout = clampAgentLayout(state.agentLayout);
      els.agentOverlay.style.left = `${state.agentLayout.left}px`;
      els.agentOverlay.style.top = `${state.agentLayout.top}px`;
      placeAgentPanel();
      saveAgentLayout();
      if (moved) {
        state.agentDragSuppressClick = true;
        window.setTimeout(() => {
          state.agentDragSuppressClick = false;
        }, 0);
        recordUserEvent("agent.dragged", {
          target: "agent-overlay",
          summary: "Moved embedded assistant avatar",
          data: state.agentLayout,
        });
      }
    };
    window.addEventListener("pointermove", move);
    window.addEventListener("pointerup", end, { once: true });
    window.addEventListener("pointercancel", end, { once: true });
  });
}

function installAgentPanelDragging() {
  const handle = els.agentPanel?.querySelector(".agent-panel-head");
  if (!handle) return;
  handle.addEventListener("pointerdown", (event) => {
    if (!isPrimaryPointer(event)) return;
    if (event.target.closest("button,input,textarea,select,s-select,a")) return;
    event.preventDefault();
    const panelRect = els.agentPanel.getBoundingClientRect();
    const offsetX = event.clientX - panelRect.left;
    const offsetY = event.clientY - panelRect.top;
    const startX = event.clientX;
    const startY = event.clientY;
    let moved = false;
    document.body.classList.add("is-agent-dragging");
    try {
      handle.setPointerCapture(event.pointerId);
    } catch {
      // Window listeners below keep the drag alive if capture is interrupted.
    }
    const move = (moveEvent) => {
      if (Math.hypot(moveEvent.clientX - startX, moveEvent.clientY - startY) > 3) moved = true;
      moveAgentGroupFromPanelRect(
        moveEvent.clientX - offsetX,
        moveEvent.clientY - offsetY,
        els.agentPanel.offsetWidth || 430,
        els.agentPanel.offsetHeight || 620
      );
    };
    const end = () => {
      document.body.classList.remove("is-agent-dragging");
      window.removeEventListener("pointermove", move);
      window.removeEventListener("pointerup", end);
      window.removeEventListener("pointercancel", end);
      placeAgentPanel();
      saveAgentLayout();
      if (moved) {
        recordUserEvent("agent.dragged", {
          target: "agent-overlay",
          summary: "Moved embedded assistant avatar and chat together",
          data: state.agentLayout,
        });
      }
    };
    window.addEventListener("pointermove", move);
    window.addEventListener("pointerup", end, { once: true });
    window.addEventListener("pointercancel", end, { once: true });
  });
}

function installNodesPanelDragging() {
  const panel = els.nodesPanel;
  const handle = panel?.querySelector(".nodes-panel-head");
  if (!panel || !handle) return;
  handle.addEventListener("pointerdown", (event) => {
    if (!isPrimaryPointer(event)) return;
    if (event.target.closest("button,input,textarea,select,s-select,a")) return;
    event.preventDefault();
    const startRect = panel.getBoundingClientRect();
    const startCenter = {
      left: startRect.left + startRect.width / 2,
      top: startRect.top + startRect.height / 2,
    };
    const startX = event.clientX;
    const startY = event.clientY;
    panel.classList.add("is-dragging");
    document.body.classList.add("is-nodes-panel-dragging");
    try {
      handle.setPointerCapture(event.pointerId);
    } catch {
      // Window listeners keep the modal draggable if capture is interrupted.
    }
    const move = (moveEvent) => {
      state.nodesPanelPosition = {
        left: startCenter.left + moveEvent.clientX - startX,
        top: startCenter.top + moveEvent.clientY - startY,
      };
      placeNodesPanel();
    };
    const end = () => {
      panel.classList.remove("is-dragging");
      document.body.classList.remove("is-nodes-panel-dragging");
      window.removeEventListener("pointermove", move);
      window.removeEventListener("pointerup", end);
      window.removeEventListener("pointercancel", end);
      try {
        handle.releasePointerCapture(event.pointerId);
      } catch {
        // The browser may already have released capture.
      }
      recordUserEvent("agent.onboarding_dragged", {
        target: "nodes-panel",
        summary: "Moved nodes panel",
        data: state.nodesPanelPosition || {},
      });
    };
    window.addEventListener("pointermove", move);
    window.addEventListener("pointerup", end, { once: true });
    window.addEventListener("pointercancel", end, { once: true });
  });
}

function appendAgentCommandReply(content, choices = []) {
  appendAgentMessage("assistant", content, {
    command_choices: choices,
  });
}

function providerCommandChoices() {
  const choices = verifiedAgentProviderConfigs().map((config) => ({
    action: "select-provider",
    value: normalizeAgentProviderNodeId(config.id || ""),
    label: agentProviderNodeLabel(config),
    detail: `${cleanText(config.provider, "provider")}/${compactModelDisplayName(config.model, config.provider) || "model"}`,
  }));
  choices.push({
    action: "open-provider-config",
    value: "config",
    label: "> Providers Config...",
    detail: "Create, update, delete, and verify provider configs",
    sticky: true,
  });
  return choices;
}

async function modelCommandChoices(providerConfig = selectedAgentProviderConfig()) {
  if (!providerConfig) return [];
  const provider = cleanText(providerConfig.provider, "");
  await loadDirectProviderModels(provider, { force: false }).catch(() => []);
  return directProviderModelOptions(provider, providerConfig.model).map((model) => ({
    action: "select-model",
    value: cleanText(model.id, ""),
    provider_id: normalizeAgentProviderNodeId(providerConfig.id || ""),
    label: compactModelDisplayName(model.id, provider) || model.label || model.id,
    detail: cleanText(model.id, ""),
  }));
}

function openProviderConfigFromCommand() {
  openAgentSetupBalloon({
    mode: "provider",
    message: "Edit, add, or delete provider configs. Providers become selectable after verification succeeds.",
    openProviderForm: !verifiedAgentProviderConfigs().length,
    providerFormMode: verifiedAgentProviderConfigs().length ? "edit" : "new",
  });
}

async function showProviderCommand() {
  const choices = providerCommandChoices();
  const selectable = choices.filter((choice) => choice.action === "select-provider").length;
  appendAgentCommandReply(
    selectable
      ? "Choose a verified provider for this chat target."
      : "No verified providers are selectable yet. Open provider config to add and verify one.",
    choices
  );
}

async function showModelCommand() {
  const providerConfig = selectedAgentProviderConfig();
  if (!providerConfig) {
    appendAgentCommandReply("Choose or verify a provider before selecting a model.", providerCommandChoices());
    return;
  }
  const choices = await modelCommandChoices(providerConfig);
  appendAgentCommandReply(
    choices.length
      ? `Choose a model for ${cleanText(providerConfig.provider, "provider")}.`
      : `No models are available for ${cleanText(providerConfig.provider, "provider")} yet.`,
    choices
  );
}

function persistModelSelectionForCurrentTarget(modelId = "", providerConfig = selectedAgentProviderConfig()) {
  const provider = cleanText(providerConfig?.provider, "");
  const model = normalizeAgentModelEntry({ id: modelId, provider, name: compactModelDisplayName(modelId, provider) });
  if (!model || !providerConfig) return null;
  if (agentTargetIsDirectProvider()) {
    const nextConfig = {
      ...providerConfig,
      model: model.id,
      provider: provider || providerConfig.provider || "",
    };
    const savedProvider = saveAgentDirectProviderConfig(withDirectProviderVerification(nextConfig, {
      ok: true,
      fingerprint: directProviderConfigFingerprint(nextConfig),
      mode: "model-list",
      category: "ready",
      message: "Model selected from verified provider list.",
      checked_at: Date.now(),
    }));
    state.agentDirectProvider = savedProvider || state.agentDirectProvider;
    if (savedProvider) state.agentTargetNode = directProviderTargetValue(savedProvider);
  } else {
    persistAgentProviderSelectionForCurrentTarget(providerConfig);
    applyAgentModelToTarget(model);
    persistAgentModelSelection();
  }
  renderAgentNodeSelect();
  renderAgentModelSelect();
  renderAgentReadinessStatus();
  return model;
}

async function handleAgentCommandChoice(choice = {}) {
  const action = cleanText(choice.action, "");
  if (action === "open-provider-config") {
    openProviderConfigFromCommand();
    appendAgentCommandReply("Opened provider configuration.", []);
    return;
  }
  if (action === "select-provider") {
    const provider = agentProviderConfigById(choice.value);
    if (!provider || !directProviderVerified(provider)) {
      appendAgentCommandReply("That provider is not verified anymore. Open provider config and verify it again.", providerCommandChoices());
      return;
    }
    persistAgentProviderSelectionForCurrentTarget(provider);
    await loadDirectProviderModels(provider.provider).catch(() => []);
    appendAgentCommandReply(
      `Provider set to ${cleanText(provider.provider, "provider")}.`,
      await modelCommandChoices(provider)
    );
    return;
  }
  if (action === "select-model") {
    const provider = agentProviderConfigById(choice.provider_id) || selectedAgentProviderConfig();
    const model = persistModelSelectionForCurrentTarget(choice.value, provider);
    appendAgentCommandReply(
      model ? `Model set to ${compactModelDisplayName(model.id, model.provider) || model.id}.` : "Could not set that model.",
      []
    );
  }
}

async function handleAgentSlashCommand(content = "") {
  const trimmed = String(content || "").trim();
  const command = trimmed.split(/\s+/, 1)[0].toLowerCase();
  if (command !== "/provider" && command !== "/model") return false;
  appendAgentMessage("user", trimmed);
  clearAgentInput();
  if (command === "/provider") {
    await showProviderCommand();
  } else {
    await showModelCommand();
  }
  saveAgentSessions();
  renderAgentMessages({ forceBottom: true });
  return true;
}

async function sendAgentMessage(text) {
  stopAgentSpeechTranscription("send");
  if (state.agentBusy) {
    stopAgentMessage();
    return;
  }
  const activeSession = activeAgentSession();
  if (activeSession.kind === "direct") {
    await sendDirectChatMessage(activeSession, text);
    return;
  }
  if (activeSession.kind === "shared-space") {
    await sendSharedSpaceChatMessage(activeSession, text);
    return;
  }
  const content = String(text ?? "").replace(/\r\n?/g, "\n");
  if (blockSendWhileAttachmentsProcess()) return;
  const attachmentCount = state.agentPendingImages.length + state.agentPendingAttachmentSummaries.length;
  if (!content.trim() && !attachmentCount) return;
  if (!attachmentCount && await handleAgentSlashCommand(content)) return;
  if (await warnAgentChatNeedsSetup(activeSession)) return;
  const userMessageContent = content.trim() ? content : `Attached ${attachmentCount} file${attachmentCount === 1 ? "" : "s"}.`;
  state.agentBusy = true;
  state.agentStopRequested = false;
  state.agentAbortController = new AbortController();
  updateAgentTokenUsage(null);
  updateAgentSendButton();
  els.agentStatus.textContent = "Thinking";
  const targetNode = agentTargetNode();
  const chatModel = selectedAgentModel();
  const nodeRunConfig = activeAgentNodeRunConfig(targetNode, chatModel);
  const turnStartedAt = Date.now();
  const runHintId = `chat_${turnStartedAt}_${Math.random().toString(36).slice(2, 7)}`;
  const mode = els.agentModeSelect.value;
  const useDirectApi = shouldUseDirectAgentProvider(activeSession);
  const useMasterFrontier = agentTargetIsMasterFrontier(state.agentTargetNode);
  const directHeadLike = useDirectApi || useMasterFrontier;
  const directProviderConfig = directHeadLike ? activeAgentDirectProviderConfig(state.agentTargetNode) : null;
  const useOwnedBridge = shouldUseOwnedAgentBridge(activeSession);
  const backendTurnId = useDirectApi || useOwnedBridge
    ? ""
    : window.crypto?.randomUUID?.() || `${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
  const runHintTarget = useDirectApi || useOwnedBridge || useMasterFrontier ? "" : targetNode;
  if (runHintTarget) {
    setNodeRunHint(runHintTarget, {
      id: runHintId,
      source: "embedded chat",
      status: "running",
      started_at: new Date(turnStartedAt).toISOString(),
      preview: truncateText(userMessageContent, 120),
    });
  }
  const userImages = state.agentPendingImages.map((image) => ({
    data_url: image.data_url,
    name: image.name,
    type: image.type,
    size: image.size,
    width: image.width,
    height: image.height,
    original_type: image.original_type,
    original_size: image.original_size,
    image_card: image.image_card,
    asset: image.asset,
  }));
  const userAttachments = state.agentPendingAttachmentSummaries.map((attachment) => ({
    data_url: attachment.data_url,
    name: attachment.name,
    type: attachment.type,
    size: attachment.size,
    width: attachment.width,
    height: attachment.height,
    original_type: attachment.original_type,
    original_size: attachment.original_size,
    image_card: attachment.image_card,
    asset: attachment.asset,
    reason: attachment.reason,
    media_kind: attachment.media_kind,
    duration_sec: attachment.duration_sec,
    video_card: attachment.video_card,
  }));
  const requestTranscript = agentTranscriptForRequest();
  const continuationContext = isAgentContinuationRequest(userMessageContent)
    ? latestAgentContinuationContext(activeSession)
    : null;
  clearAgentPendingImages();
  appendAgentMessage("user", userMessageContent, {
    images: userImages,
    attachments: userAttachments.map((attachment) => ({
      name: attachment.name,
      type: attachment.type,
      size: attachment.size,
      width: attachment.width,
      height: attachment.height,
      original_type: attachment.original_type,
      original_size: attachment.original_size,
      image_card: attachment.image_card,
      asset: attachment.asset,
      reason: attachment.reason,
      media_kind: attachment.media_kind,
      duration_sec: attachment.duration_sec,
      video_card: attachment.video_card,
    })),
  });
  clearAgentInput();
  recordUserEvent("agent.message_submitted", {
    target: useMasterFrontier ? "master-frontier" : useDirectApi ? "provider-api" : useOwnedBridge ? "owned-agent" : `node:${targetNode}`,
    summary: useDirectApi
      ? "Submitted embedded assistant message to provider"
      : useMasterFrontier ? `Submitted embedded assistant message to ${AGENT_MASTER_FRONTIER_LABEL}`
      : useOwnedBridge ? "Submitted embedded assistant message to owned agent" : `Submitted embedded assistant message to ${targetNode}`,
    data: {
      message_length: userMessageContent.length,
      image_count: userImages.length,
      attachment_count: attachmentCount,
      summarized_attachment_count: userAttachments.length,
      image_bytes: userImages.reduce((sum, image) => sum + (Number.isFinite(image.size) ? image.size : 0), 0),
      panel: state.activePanel,
      space_name: activeSpaceContext().name,
      target_node: targetNode,
      direct_api: useDirectApi,
      direct_head: useMasterFrontier,
      owned_bridge: useOwnedBridge,
    },
    redacted: true,
  });
  try {
    const observation = buildObservationSnapshot();
    const activeSpace = activeSpaceContext();
    const compactObservation = {
      timestamp: observation.timestamp,
      cap: observation.cap,
      workspace: observation.workspace,
      browser: observation.browser,
      fleet: {
        bridge_ready: observation.fleet.bridge_ready,
        selected_node: observation.fleet.selected_node,
        chat_target_node: targetNode,
        node_count: observation.fleet.node_count,
        nodes: (observation.fleet.nodes || []).slice(0, 12),
        last_error: observation.fleet.last_error,
      },
      tasks: {
        active_task_id: observation.tasks.active_task_id,
        status: observation.tasks.status,
        recent: (observation.tasks.recent || []).slice(0, 8),
        last_output_summary: observation.tasks.last_output_summary,
      },
      logs: observation.logs,
      requested_click_context: {
        last_non_agent_click: observation.analytics.last_non_agent_click,
        note: "Use last_non_agent_click, not chat open/send events, when the user asks what UI button they clicked last.",
      },
      interaction: {
        recent_trace: (observation.interaction?.recent_trace || []).slice(0, 16),
        active_pointers: observation.interaction?.active_pointers || [],
      },
      recent_events: observation.user_events.slice(0, 12),
    };
    const transcript = requestTranscript;
    const imageBytes = userImages.reduce((sum, image) => sum + (Number.isFinite(image.size) ? image.size : 0), 0);
    const summarizedCount = userAttachments.length;
    const imageCards = [...userImages, ...userAttachments].map(imageCardSummary);
    const providerMessageContent = useDirectApi && imageCards.length
      ? `${userMessageContent}${providerAttachmentManifestText(imageCards)}`
      : userMessageContent;
    const analyzerModules = Object.values(Object.fromEntries(
      imageCards
        .flatMap((card) => Array.isArray(card.analyzer_modules) ? card.analyzer_modules : [])
        .map((module) => [module.id, module])
    ));
    const initialActions = [
      agentAction("Prepare compact context", "done", `${transcript.length} transcript turns / ${compactObservation.recent_events.length} UI events`, {
        topic: "run-wasm",
        kind: "context",
        meta: "snapshot",
        arguments: {
          transcript_turns: transcript.length,
          recent_events: compactObservation.recent_events.length,
          active_panel: compactObservation.workspace?.active_panel,
          active_space: activeSpace,
          target_node: targetNode,
          node_config: {
            node_id: nodeRunConfig.node_id,
            name: nodeRunConfig.name,
            type: nodeRunConfig.type,
            instruction_source: nodeRunConfig.instruction_source,
            provider_model_source: nodeRunConfig.provider_model_source,
          },
        },
        preview: JSON.stringify({
          workspace: compactObservation.workspace,
          requested_click_context: compactObservation.requested_click_context,
          recent_events: compactObservation.recent_events.slice(0, 3),
        }, null, 2),
      }),
    ];
    if (continuationContext) {
      initialActions.push(agentAction("Resume context", "done", continuationContext.previous_run_id || continuationContext.previous_phase || "previous turn", {
        id: "client_resume_context",
        topic: "run-wasm",
        kind: "context",
        meta: continuationContext.previous_status || "continuation",
        arguments: continuationContext,
      }));
    }
    if (attachmentCount) {
      initialActions.push(
        agentAction("Prepare attachments", directHeadLike ? "done" : "running", directHeadLike ? `${attachmentCount} ready for direct head` : `${attachmentCount} queued`, {
        id: "client_store_image_assets",
        topic: "run-wasm",
        kind: "media",
        meta: directHeadLike ? "provider metadata" : "local store",
        arguments: directHeadLike
          ? { count: attachmentCount, storage: "skipped-direct-head" }
          : { endpoint: "/agent/attachments", count: attachmentCount },
        preview: directHeadLike ? agentImageCardPreview(userImages, userAttachments) : undefined,
      }),
        agentAction("Decode pixels", "done", `${imageCards.filter((card) => card.dimensions).length}/${attachmentCount} decoded`, {
        id: "client_decode_pixels",
        topic: "run-wasm",
        kind: "media",
        meta: "Canvas",
      }),
        agentAction("Analyze attachments", "done", `${imageCards.length} local cards`, {
        id: "client_analyze_image",
        topic: "run-wasm",
        kind: "media",
        meta: "browser + lazy modules",
        arguments: {
              raw_images: userImages.length,
              summarized: summarizedCount,
              raw_budget_bytes: AGENT_IMAGE_TOTAL_MAX_BYTES,
              raw_bytes: imageBytes,
              analyzer_modules: analyzerModules,
            },
      }),
        agentAction("Build attachment cards", "done", `${imageCards.length} cards`, {
        id: "client_build_image_cards",
        topic: "run-wasm",
        kind: "media",
        meta: `${Math.round(imageBytes / 1024)} KB raw`,
        preview: JSON.stringify(imageCards, null, 2),
      })
      );
    }
    const providerProbeActionId = "client_probe_provider";
    const askActionId = useMasterFrontier ? "client_call_master_frontier" : useDirectApi ? "client_call_provider" : useOwnedBridge ? "client_call_owned_agent" : "client_ask_orchestrator";
    if (useDirectApi) {
      initialActions.push(
        agentAction("Probe provider", "running", directProviderChatUrl(directProviderConfig), {
          id: providerProbeActionId,
          topic: "run-api",
          kind: "api",
          meta: "checking",
          arguments: {
            endpoint: directProviderChatUrl(directProviderConfig),
            model: directProviderConfig?.model || "",
            provider: directProviderConfig?.provider || "",
          },
        })
      );
    }
    initialActions.push(
      agentAction(
        useMasterFrontier ? `Call ${AGENT_MASTER_FRONTIER_LABEL}` : useDirectApi ? "Call provider" : useOwnedBridge ? `Call ${state.agentOwnedAgent?.name || "owned agent"}` : `Ask ${targetNode}`,
        "running",
        useMasterFrontier ? "POST /agent/provider/envelope/stream" : useDirectApi ? directProviderChatUrl(directProviderConfig) : useOwnedBridge ? ownedAgentBridgeUrl() : "POST /agent/session/message",
        {
        id: askActionId,
        topic: useDirectApi || useOwnedBridge || useMasterFrontier ? "run-api" : "run-hermes",
        kind: useDirectApi || useOwnedBridge || useMasterFrontier ? "api" : "model",
        meta: useMasterFrontier
          ? AGENT_MASTER_FRONTIER_LABEL
          : useDirectApi
          ? directProviderConfig?.model || "provider"
          : useOwnedBridge
            ? state.agentOwnedAgent?.type || "hermes"
          : chatModel?.label ? `${mode} / ${chatModel.label}` : mode,
        arguments: useMasterFrontier
          ? { endpoint: "/agent/provider/envelope/stream", target_node: AGENT_FRONTIER_NODE_ID, provider: directProviderConfig?.provider || "", model: directProviderConfig?.model || "" }
          : useDirectApi
          ? { endpoint: directProviderChatUrl(directProviderConfig), model: directProviderConfig?.model || "", provider: directProviderConfig?.provider || "" }
          : useOwnedBridge
            ? { endpoint: ownedAgentBridgeUrl(), type: state.agentOwnedAgent?.type || "hermes", name: state.agentOwnedAgent?.name || "" }
          : { endpoint: "/agent/session/message", mode, target_node: targetNode, model: chatModel?.id || "" },
      })
    );
    const pendingMessage = appendAgentMessage("assistant", useMasterFrontier ? `Calling ${AGENT_MASTER_FRONTIER_LABEL}...` : useDirectApi ? "Calling provider..." : useOwnedBridge ? "Calling agent..." : `Waiting for ${targetNode}...`, {
      pending: true,
      phase: useMasterFrontier ? "Direct head" : useDirectApi ? "Provider" : useOwnedBridge ? "Owned agent" : "Inspecting context",
      target_node: targetNode,
      mode: useMasterFrontier ? "direct_head" : useDirectApi ? "direct_api" : useOwnedBridge ? "owned_bridge" : mode,
      turn_id: backendTurnId || undefined,
      turn_started_at: turnStartedAt,
      space_id: activeSpaceStorageId(),
      space_name: activeSpace.name,
      active_space: activeSpace,
      actions: initialActions,
    });
    startAgentTurnTimer(pendingMessage);
    if (useMasterFrontier) {
      els.agentStatus.textContent = "Calling direct head";
      updateAgentPendingMessage(pendingMessage, {
        phase: "Resolving route",
        content: `Preparing ${AGENT_MASTER_FRONTIER_LABEL} route...`,
      });
      try {
        const kernelRouteProof = await proveAgentKernelRouteTools(userMessageContent, pendingMessage, {
          signal: state.agentAbortController.signal,
        });
        updateAgentPendingMessage(pendingMessage, {
          phase: "Direct head",
          content: `Calling ${AGENT_MASTER_FRONTIER_LABEL}...`,
        });
        const directHead = await callMasterFrontierDirectHead(userMessageContent, transcript, compactObservation, {
          activeSpace,
          imageCards,
          nodeRunConfig,
          continuationContext,
          turnId: backendTurnId,
          routeContract: kernelRouteProof?.route_contract,
          pendingMessage,
          signal: state.agentAbortController.signal,
        });
        const rawReply = masterFrontierReplyFromPayload(directHead) || "The direct head returned an empty response.";
        const clientWis = await applyClientWisPatchesFromReply(rawReply);
        const clientOps = applyAgentClientOpsFromReply(clientWis.reply);
        const directHeadUsage = directHead.usage && typeof directHead.usage === "object" ? directHead.usage : {};
        const dispatch = directHead.hermes_dispatch && typeof directHead.hermes_dispatch === "object" ? directHead.hermes_dispatch : null;
        const changedFiles = Array.isArray(directHead.changed_files) ? directHead.changed_files : [];
        pendingMessage.content = clientOps.reply;
        pendingMessage.pending = false;
        pendingMessage.phase = "";
        pendingMessage.duration_ms = Date.now() - turnStartedAt;
        pendingMessage.changed_files = changedFiles;
        pendingMessage.run_id = cleanText(directHead.run_id, pendingMessage.run_id || "");
        pendingMessage.turn_id = cleanText(directHead.turn_id, pendingMessage.turn_id || backendTurnId || "");
        pendingMessage.agent_run_status = "completed";
        pendingMessage.route_contract = directHead.route_contract || pendingMessage.route_contract || kernelRouteProof?.route_contract || null;
        pendingMessage.actions = (pendingMessage.actions || initialActions).map((action) => (
          action.id === askActionId
            ? { ...action, label: AGENT_MASTER_FRONTIER_LABEL, status: "done", detail: dispatch ? "Hermes dispatch" : "direct decision", meta: "direct-head" }
            : action
        ));
        pendingMessage.actions.push(...masterFrontierHermesActions(directHead));
        if (clientWis.result) pendingMessage.actions.push(wisPatchActionFromResult(clientWis.result));
        if (directHead.context_measurement) {
          pendingMessage.actions.push(agentAction("Envelope estimate", "done", `~${directHead.context_measurement.estimated_tokens || 0} tokens`, {
            id: "client_master_frontier_context_measurement",
            topic: "run-api",
            kind: "context",
            meta: "direct-head",
            arguments: directHead.context_measurement,
          }));
        }
        pendingMessage.diagnostics = {
          source: dispatch ? "master_frontier_hermes_dispatch" : "master_frontier_direct_head",
          mode: "direct_head",
          target_node: AGENT_FRONTIER_NODE_ID,
          duration_ms: pendingMessage.duration_ms,
          tool_count: 0,
          tools: [],
          transcript_turns: transcript.length,
          token_usage: directHeadUsage,
          token_usage_head: directHeadUsage,
          token_usage_bridge: dispatch?.usage || null,
          token_ledger: directHead.token_ledger || pendingMessage.token_ledger || pendingMessage.diagnostics?.token_ledger || null,
          route_id: directHead.route_id || pendingMessage.route_contract?.route_id || "wasm-agent.avatar-chat.ui",
          route_contract: pendingMessage.route_contract,
          kernel_route_proof: pendingMessage.kernel_route_proof || kernelRouteProof || null,
          run_id: pendingMessage.run_id,
          turn_id: pendingMessage.turn_id,
          context_measurement: directHead.context_measurement || null,
          dispatch_context_measurement: dispatch?.context_measurement || null,
          changed_files_complete: directHead.diagnostics?.changed_files_complete || changedFiles.length > 0,
          before_checkpoint: directHead.diagnostics?.before_checkpoint || null,
          auto_checkpoint: directHead.diagnostics?.auto_checkpoint || null,
          direct_head: {
            label: AGENT_MASTER_FRONTIER_LABEL,
            endpoint: "/agent/provider/envelope/stream",
            provider: directProviderConfig?.provider || directHead.provider || "",
            model: directProviderConfig?.model || directHead.model || "",
            base_url: directProviderConfig?.baseUrl || directHead.base_url || "",
            provider_config_source: directProviderConfig ? "browser-local" : "server-default",
            parsed: directHead.parsed || null,
          },
          hermes_dispatch: dispatch,
          backend_tools_enabled: true,
          source_mutations_enabled: Boolean(dispatch),
          wis_patch_result: clientWis.result,
          client_ops: clientOps.result,
        };
        await refreshAgentRunTokenLedger(pendingMessage, {
          questId: activeAgentSession()?.id || "",
          signal: state.agentAbortController.signal,
        }).catch(() => null);
        const session = activeAgentSession();
        session.diagnostics = pendingMessage.diagnostics;
        updateAgentTokenUsage(agentTokenLedgerUsage(pendingMessage.token_ledger) || agentDiagnosticsTokenUsageBreakdown(pendingMessage.diagnostics).total);
        session.changed_files = changedFiles;
        session.context_preview = Array.isArray(directHead.context_preview) && directHead.context_preview.length
          ? directHead.context_preview
          : directHead.envelope_text ? [{ tool: "direct_envelope", preview: truncateText(directHead.envelope_text, 1200) }] : [];
        saveAgentSessions();
        renderAgentDiagnostics(pendingMessage.diagnostics);
        renderAgentContextPreview(session.context_preview);
        renderAgentMessages();
        recordUserEvent("agent.master_frontier_finished", {
          target: "master-frontier",
          summary: `${AGENT_MASTER_FRONTIER_LABEL} replied`,
          data: { run_id: pendingMessage.run_id, dispatched: Boolean(dispatch), usage: directHeadUsage },
        });
        void publishClientSnapshot("agent-master-frontier-finished", { silent: true });
        return;
      } catch (directHeadError) {
        const diagnostic = directHeadError.diagnostic || directHeadError.payload?.error || providerDiagnosticFromError(directHeadError) || {};
        const reason = diagnostic.message || directHeadError.message;
        const category = cleanText(diagnostic.code || diagnostic.category || diagnostic.mode || "", "error");
        mergeAgentAction(pendingMessage, {
          id: category === "route_contract_missing" ? "tl_route_contract_missing" : "tl_direct_head_error",
          label: category === "route_contract_missing" ? "route_contract_missing" : "direct_head.error",
          status: "error",
          detail: reason,
          kind: "timeline",
          event_type: category === "route_contract_missing" ? "route_contract_missing" : "direct_head.error",
          arguments: { error: diagnostic },
        });
        pendingMessage.content = `The ${AGENT_MASTER_FRONTIER_LABEL} direct head could not answer: ${reason}`;
        pendingMessage.pending = false;
        pendingMessage.phase = "Direct head error";
        pendingMessage.duration_ms = Date.now() - turnStartedAt;
        pendingMessage.actions = (pendingMessage.actions || initialActions).map((action) => (
          action.id === askActionId
            ? { ...action, label: AGENT_MASTER_FRONTIER_LABEL, status: "error", detail: reason, meta: category }
            : action
        ));
        pendingMessage.diagnostics = {
          source: "master_frontier_direct_head_error",
          mode: "direct_head",
          target_node: AGENT_FRONTIER_NODE_ID,
          provider_error: diagnostic,
          direct_head: {
            label: AGENT_MASTER_FRONTIER_LABEL,
            endpoint: "/agent/provider/envelope/stream",
            provider: directProviderConfig?.provider || "",
            model: directProviderConfig?.model || "",
            provider_config_source: directProviderConfig ? "browser-local" : "server-default",
          },
        };
        saveAgentSessions();
        renderAgentMessages();
        renderNodesPanel();
        void publishClientSnapshot("agent-master-frontier-error", { silent: true });
        return;
      }
    }
    if (useDirectApi) {
      els.agentStatus.textContent = "Calling API";
      updateAgentPendingMessage(pendingMessage, {
        phase: "Provider probe",
        content: "Checking provider connectivity...",
      });
      try {
        const providerProbe = await ensureAgentProviderConnection();
        mergeAgentAction(pendingMessage, {
          id: providerProbeActionId,
          topic: "run-api",
          kind: "api",
          label: "Probe provider",
          status: "done",
          detail: providerProbe.mode,
          meta: providerProbe.category,
        });
        updateAgentPendingMessage(pendingMessage, {
          phase: providerProbe.mode,
          content: providerProbe.mode === "backend-proxy" ? "Calling provider through backend proxy..." : "Calling browser-direct provider...",
        });
        const direct = await callDirectAgentProvider(providerMessageContent, transcript, [...userImages, ...userAttachments]);
        const directUsage = direct.usage && typeof direct.usage === "object" ? direct.usage : {};
        const providerMode = direct.mode || currentAgentProviderProbe()?.mode || "browser-direct";
        if (direct.image_fallback) {
          mergeAgentAction(pendingMessage, {
            id: "client_provider_image_fallback",
            topic: "run-api",
            kind: "api",
            label: "Image request fallback",
            status: "done",
            detail: direct.image_fallback.category || direct.image_fallback.mode || "text fallback",
            meta: "manifest",
          });
        }
        const clientWis = await applyClientWisPatchesFromReply(direct.reply);
        const clientOps = applyAgentClientOpsFromReply(clientWis.reply);
        pendingMessage.content = clientOps.reply;
        pendingMessage.pending = false;
        pendingMessage.phase = "";
        pendingMessage.duration_ms = Date.now() - turnStartedAt;
        pendingMessage.changed_files = [];
        pendingMessage.actions = (pendingMessage.actions || initialActions).map((action) => (
          action.id === askActionId
            ? { ...action, label: providerMode, status: "done", detail: direct.model || directProviderConfig?.model || "direct", meta: providerMode }
            : action
        ));
        if (clientWis.result) pendingMessage.actions.push(wisPatchActionFromResult(clientWis.result));
        pendingMessage.diagnostics = {
          source: providerMode === AGENT_PROVIDER_TRANSPORTS.BACKEND_PROXY ? "provider_backend_proxy" : "browser_direct_provider",
          mode: providerMode,
          target_node: targetNode,
          duration_ms: pendingMessage.duration_ms,
          tool_count: 0,
          tools: [],
          transcript_turns: transcript.length,
          token_usage: directUsage,
          direct_provider: {
            provider: directProviderConfig?.provider || "",
            model: direct.model || directProviderConfig?.model || "",
            base_url: directProviderConfig?.baseUrl || "",
            endpoint: directProviderChatUrl(directProviderConfig),
            mode: providerMode,
            probe: currentAgentProviderProbe(),
            transport_reason: currentAgentProviderProbe()?.transport_reason || "",
          },
          backend_tools_enabled: false,
          source_mutations_enabled: false,
          wis_patch_result: clientWis.result,
          client_ops: clientOps.result,
        };
        const session = activeAgentSession();
        session.diagnostics = pendingMessage.diagnostics;
        session.context_preview = [];
        updateAgentTokenUsage(directUsage);
        saveAgentSessions();
        renderAgentDiagnostics(pendingMessage.diagnostics);
        renderAgentContextPreview([]);
        renderAgentMessages();
        recordUserEvent("agent.direct_api_finished", {
          target: providerMode,
          summary: "Provider replied",
          data: { model: direct.model || directProviderConfig?.model || "", usage: directUsage, mode: providerMode },
        });
        void publishClientSnapshot("agent-direct-provider-finished", { silent: true });
        return;
      } catch (directError) {
        const diagnostic = providerDiagnosticFromError(directError) || currentAgentProviderProbe();
        const reason = diagnostic.message || directError.message;
        pendingMessage.content = `The provider could not answer (${diagnostic.mode || "unreachable"} / ${diagnostic.category || "error"}): ${reason}`;
        pendingMessage.pending = false;
        pendingMessage.phase = "Provider error";
        pendingMessage.duration_ms = Date.now() - turnStartedAt;
        pendingMessage.actions = (pendingMessage.actions || initialActions).map((action) => (
          action.id === askActionId || action.id === providerProbeActionId
            ? { ...action, label: action.id === providerProbeActionId ? "Probe provider" : "Provider call", status: "error", detail: reason, meta: diagnostic.category || diagnostic.mode || "error" }
            : action
        ));
        pendingMessage.diagnostics = {
          source: "provider_error",
          mode: diagnostic.mode || "unreachable",
          provider_error: diagnostic,
          direct_provider: {
            provider: directProviderConfig?.provider || "",
            model: directProviderConfig?.model || "",
            base_url: directProviderConfig?.baseUrl || "",
            endpoint: directProviderChatUrl(directProviderConfig),
          },
        };
        saveAgentSessions();
        renderAgentMessages();
        renderNodesPanel();
        void publishClientSnapshot("agent-direct-provider-error", { silent: true });
        return;
      }
    }
    if (useOwnedBridge) {
      els.agentStatus.textContent = "Calling agent";
      updateAgentPendingMessage(pendingMessage, {
        phase: "Owned agent",
        content: `Calling ${state.agentOwnedAgent?.name || "owned agent"}...`,
      });
      try {
        const owned = await callOwnedAgentBridge(userMessageContent, transcript, compactObservation);
        const clientWis = await applyClientWisPatchesFromReply(owned.reply);
        const clientOps = applyAgentClientOpsFromReply(clientWis.reply);
        pendingMessage.content = clientOps.reply;
        pendingMessage.pending = false;
        pendingMessage.phase = "";
        pendingMessage.duration_ms = Date.now() - turnStartedAt;
        pendingMessage.changed_files = [];
        pendingMessage.actions = (pendingMessage.actions || initialActions).map((action) => (
          action.id === askActionId
            ? { ...action, label: "Owned bridge", status: "done", detail: owned.task?.task_id || state.agentOwnedAgent?.name || "agent", meta: state.agentOwnedAgent?.type || "hermes" }
            : action
        ));
        if (clientWis.result) pendingMessage.actions.push(wisPatchActionFromResult(clientWis.result));
        pendingMessage.diagnostics = {
          source: "owned_agent_bridge",
          mode: "owned_bridge",
          target_node: targetNode,
          duration_ms: pendingMessage.duration_ms,
          tool_count: 0,
          tools: [],
          transcript_turns: transcript.length,
          owned_agent: {
            name: state.agentOwnedAgent?.name || "",
            type: state.agentOwnedAgent?.type || "hermes",
            bridge_url: ownedAgentBridgeUrl(),
            task_id: owned.task?.task_id || "",
            status: owned.task?.status || "",
          },
          backend_tools_enabled: true,
          source_mutations_enabled: false,
          wis_patch_result: clientWis.result,
          client_ops: clientOps.result,
        };
        const session = activeAgentSession();
        session.diagnostics = pendingMessage.diagnostics;
        session.context_preview = [];
        saveAgentSessions();
        renderAgentDiagnostics(pendingMessage.diagnostics);
        renderAgentContextPreview([]);
        renderAgentMessages();
        recordUserEvent("agent.owned_bridge_finished", {
          target: "owned-agent",
          summary: "Owned agent replied",
          data: { task_id: owned.task?.task_id || "", status: owned.task?.status || "" },
        });
        void publishClientSnapshot("agent-owned-bridge-finished", { silent: true });
        return;
      } catch (ownedError) {
        pendingMessage.content = `The owned agent bridge could not answer: ${ownedError.message}`;
        pendingMessage.pending = false;
        pendingMessage.phase = "Owned agent error";
        pendingMessage.duration_ms = Date.now() - turnStartedAt;
        pendingMessage.actions = (pendingMessage.actions || initialActions).map((action) => (
          action.id === askActionId
            ? { ...action, label: "Owned bridge", status: "error", detail: ownedError.message, meta: "error" }
            : action
        ));
        pendingMessage.diagnostics = {
          source: "owned_agent_bridge_error",
          mode: "owned_bridge",
          owned_agent: {
            name: state.agentOwnedAgent?.name || "",
            type: state.agentOwnedAgent?.type || "hermes",
            bridge_url: ownedAgentBridgeUrl(),
          },
        };
        saveAgentSessions();
        renderAgentMessages();
        renderNodesPanel();
        void publishClientSnapshot("agent-owned-bridge-error", { silent: true });
        return;
      }
    }
    await ensureAgentReadiness("send");
    await storeAgentAttachmentAssets(userImages, userAttachments, pendingMessage);
    els.agentStatus.textContent = "Inspecting context";
    updateAgentPendingMessage(pendingMessage, {
      phase: "Waiting for node",
      content: `Waiting for ${targetNode}...`,
      actions: (pendingMessage.actions || initialActions).map((action) => action.id === "client_ask_orchestrator" ? { ...action, status: "running" } : action),
    });
    const payloadAttachments = userAttachments.map((attachment) => ({
      name: attachment.name,
      type: attachment.type,
      size: attachment.size,
      width: attachment.width,
      height: attachment.height,
      original_type: attachment.original_type,
      original_size: attachment.original_size,
      image_card: attachment.image_card,
      asset: attachment.asset,
      reason: attachment.reason,
      media_kind: attachment.media_kind,
      duration_sec: attachment.duration_sec,
      video_card: attachment.video_card,
    }));
    const payload = await postAgentMessage({
      session_id: activeAgentSession().id,
      turn_id: backendTurnId,
      message: userMessageContent,
      images: userImages.length ? userImages : undefined,
      attachments: payloadAttachments.length ? payloadAttachments : undefined,
      mode,
      target_node: targetNode,
      node_config: nodeRunConfig,
      model: chatModel?.id || undefined,
      model_provider: chatModel?.provider || undefined,
      space_id: activeSpaceStorageId(),
      space_name: activeSpace.name,
      space_display_name: activeSpace.display_name,
      active_space: activeSpace,
      observation: compactObservation,
      transcript,
    }, pendingMessage, {
      idleTimeoutMs: state.agentTurnTimeoutMs + 5000,
      signal: state.agentAbortController.signal,
    });
    const rawReply = payload.agent?.reply || "I did not receive a response from the embedded agent adapter.";
    const clientWis = await applyClientWisPatchesFromReply(rawReply);
    const clientOps = applyAgentClientOpsFromReply(clientWis.reply);
    const reply = clientOps.reply;
    const session = activeAgentSession();
    const changedFiles = payload.agent?.changed_files || [];
    const diagnostics = { ...(payload.agent?.diagnostics || {}) };
    if (clientWis.result) diagnostics.client_wis_patch_result = clientWis.result;
    if (clientOps.result) diagnostics.client_ops = clientOps.result;
    if (diagnostics.wis_patch_result?.applied) await refreshWisArtifactsAfterPatch(diagnostics.wis_patch_result, "agent-wis-patch");
    pendingMessage.content = reply;
    pendingMessage.pending = false;
    pendingMessage.phase = "";
    pendingMessage.duration_ms = payload.agent?.duration_ms || Date.now() - turnStartedAt;
    pendingMessage.changed_files = changedFiles;
    pendingMessage.diagnostics = diagnostics;
    pendingMessage.run_id = cleanText(payload.agent?.run_id, pendingMessage.run_id || "");
    pendingMessage.turn_id = cleanText(payload.agent?.turn_id, pendingMessage.turn_id || backendTurnId || "");
    pendingMessage.agent_run_status = "completed";
    if (payload.agent?.route_contract) pendingMessage.route_contract = payload.agent.route_contract;
    if (payload.agent?.token_ledger || pendingMessage.token_ledger) {
      applyAgentTokenLedger(pendingMessage, payload.agent?.token_ledger || pendingMessage.token_ledger);
    }
    await refreshAgentRunTokenLedger(pendingMessage, {
      questId: session?.id || "",
      signal: state.agentAbortController?.signal,
    }).catch(() => null);
    pendingMessage.space_id = activeSpaceStorageId();
    pendingMessage.actions = agentActionRowsFromPayload(payload.agent, initialActions);
    if (clientWis.result) pendingMessage.actions.push(wisPatchActionFromResult(clientWis.result));
    session.diagnostics = pendingMessage.diagnostics;
    updateAgentTokenUsage(agentTokenLedgerUsage(pendingMessage.token_ledger) || agentDiagnosticsTokenUsageBreakdown(pendingMessage.diagnostics).total);
    session.changed_files = changedFiles;
    session.context_preview = payload.agent?.context_preview || [];
    saveAgentSessions();
    renderAgentDiagnostics(pendingMessage.diagnostics);
    renderAgentContextPreview(payload.agent?.context_preview || []);
    renderAgentMessages();
    recordUserEvent("agent.message_finished", {
      target: "agent-overlay",
      summary: "Embedded assistant replied",
      data: { reply_length: reply.length, diagnostics },
    });
    void publishClientSnapshot("agent-message-finished", { silent: true });
  } catch (error) {
    const timeoutSeconds = Math.round(state.agentTurnTimeoutMs / 1000);
    const message = error.name === "AbortError"
      ? state.agentStopRequested
        ? "Stopped the embedded assistant turn."
        : `The selected node did not answer within ${formatTurnElapsed(timeoutSeconds * 1000)}. I received your message, but the bridge-backed path was too slow for this turn. You can switch to Local mode for quick workspace inspection, choose another node, or check the bridge/model backend.`
      : `I could not reach the embedded chat adapter yet: ${error.message}`;
    const pendingMessage = activeAgentSession().messages.find((item) => item.id === state.agentThinkingMessageId);
    if (pendingMessage) {
      pendingMessage.content = message;
      pendingMessage.pending = false;
      pendingMessage.phase = state.agentStopRequested ? "Stopped" : "Timed out";
      pendingMessage.duration_ms = Date.now() - Number(pendingMessage.turn_started_at || turnStartedAt);
      pendingMessage.actions = (pendingMessage.actions || []).map((action) => (
        action.status === "running" ? { ...action, status: state.agentStopRequested ? "done" : "error", detail: error.message } : action
      ));
      saveAgentSessions();
      renderAgentMessages();
    } else {
      appendAgentMessage("assistant", message, {
        phase: state.agentStopRequested ? "Stopped" : "Error",
        duration_ms: Date.now() - turnStartedAt,
        actions: [agentAction("Adapter request", state.agentStopRequested ? "done" : "error", error.message, {
          kind: "error",
          meta: error.name || "request",
        })],
      });
    }
    renderAgentDiagnostics({ source: "error", target_node: targetNode, duration_ms: null, tools: [], context_estimated_tokens: 0 });
    recordUserEvent("agent.message_error", {
      target: "agent-overlay",
      summary: "Embedded assistant message failed",
      data: { error: error.message },
    });
    void publishClientSnapshot("agent-message-error", { silent: true });
  } finally {
    if (runHintTarget) clearNodeRunHint(runHintTarget, runHintId);
    state.agentBusy = false;
    state.agentAbortController = null;
    state.agentStopRequested = false;
    stopAgentTurnTimer();
    updateAgentSendButton();
    renderAgentReadinessStatus();
    flushDeferredHmrReload();
  }
}

function nodeTokenBaseline(nodeId, currentTotal) {
  const id = cleanText(nodeId, "");
  const total = Number(currentTotal || 0);
  const safeTotal = Number.isFinite(total) && total > 0 ? total : 0;
  if (!id) return safeTotal;
  if (!Object.prototype.hasOwnProperty.call(state.nodeTokenBaselines, id) || safeTotal < Number(state.nodeTokenBaselines[id] || 0)) {
    state.nodeTokenBaselines[id] = safeTotal;
  }
  return Number(state.nodeTokenBaselines[id] || 0);
}

function nodeAbsoluteTokens(node) {
  const value = Number(node?.tokenUsage?.absolute_total_tokens ?? node?.tokenUsage?.total_tokens ?? 0);
  return Number.isFinite(value) && value > 0 ? value : 0;
}

function timestampAgeMs(value) {
  const stamp = Date.parse(String(value || ""));
  if (!Number.isFinite(stamp)) return null;
  return Math.max(0, Date.now() - stamp);
}

function nodeActivityIsFresh(activity = {}) {
  const ageSec = Number(activity.last_signal_age_sec);
  const windowSec = Number(activity.active_window_sec || 30);
  const maxAgeSec = Math.max(1, windowSec) + NODE_ACTIVITY_FRESH_GRACE_SEC;
  if (Number.isFinite(ageSec)) return ageSec <= maxAgeSec;
  const ageMs = timestampAgeMs(activity.last_signal_at);
  if (ageMs !== null) return ageMs <= maxAgeSec * 1000;
  return true;
}

function bridgeTaskIsFresh(task) {
  if (!task) return false;
  const detail = task && typeof task.task === "object" ? task.task : {};
  const ageMs = timestampAgeMs(detail.updated_at || task.updated_at || detail.created_at || task.created_at);
  return ageMs === null || ageMs <= BRIDGE_TASK_ACTIVE_MAX_AGE_MS;
}

function normalizeNode(raw) {
  const id = cleanText(raw.id || raw.node_id || raw.title, "unknown");
  const activity = raw.activity || {};
  const rawStatus = raw.raw || {};
  const statusActivity = rawStatus.status?.activity || raw.status?.activity || rawStatus.activity || {};
  const combinedActivity = { ...statusActivity, ...activity };
  const freshActivity = nodeActivityIsFresh(combinedActivity);
  const rawStatusValue = cleanText(raw.status, "");
  const rawStatusKey = rawStatusValue.toLowerCase();
  const running = Boolean(raw.running || rawStatusKey === "running" || rawStatusKey === "working");
  const llmActive = freshActivity && Boolean(activity.llm_active || statusActivity.llm_active);
  const activeStatus = freshActivity ? cleanText(activity.state || statusActivity.state, "") : "";
  const status = cleanText(activeStatus || (running ? "idle" : rawStatusValue || "stopped"), "unknown");
  const engineStatus = running ? "online" : status;
  const statusKey = status.toLowerCase().replace(/[^a-z0-9_-]+/g, "-");
  const statusClass = /error|fail|missing|unhealthy/.test(statusKey)
    ? "error"
    : /stop|exit|down|offline/.test(statusKey)
      ? "stopped"
      : running || /work|run|active|ready|idle|online|healthy/.test(statusKey)
        ? (statusKey === "working" ? "running" : (statusKey || "running"))
        : "unknown";
  const runtime = cleanText(raw.runtime?.type || raw.raw?.runtime_type, "runtime");
  const hermesRuntime = raw.hermes || rawStatus._space_ui_hermes || {};
  const hermesVersion = cleanText(hermesRuntime.version ? `Hermes v${hermesRuntime.version}` : "", "");
  const modelOverride = nodeModelOverride(id);
  const overriddenModel = formatNodeModel(modelOverride.name, modelOverride.provider);
  const modelName = rawStatus.default_model_env || raw.default_model_env || activity.model || "";
  const modelProvider = rawStatus.default_model_provider_env || raw.default_model_provider_env || "";
  const tokenTotal = Number(activity.total_tokens || statusActivity.total_tokens || rawStatus.session_total_tokens || 0);
  return {
	    raw,
	    id,
	    title: cleanText(raw.title || id, id),
	    running,
	    llmActive,
	    status,
	    engineStatus,
	    statusClass,
    runtime,
    hermesVersion,
    model: cleanText(overriddenModel || formatNodeModel(modelName, modelProvider), ""),
    modelName: cleanText(modelName, ""),
    modelProvider: cleanText(modelProvider, ""),
    modelOverride,
	    tokenUsage: {
	      total_tokens: Number.isFinite(tokenTotal) && tokenTotal > 0 ? tokenTotal : 0,
	      absolute_total_tokens: Number.isFinite(tokenTotal) && tokenTotal > 0 ? tokenTotal : 0,
	      api_calls: Number(activity.api_calls || statusActivity.api_calls || 0),
	      delta_tokens: 0,
	      source: cleanText(activity.source || statusActivity.source, ""),
	    },
    taskPreview: cleanText(activity.task_preview || statusActivity.message_preview || statusActivity.response_preview, ""),
    actions: Array.isArray(raw.actions) ? raw.actions : [],
  };
}

function taskPreview(task) {
  const response = task?.result?.response || task?.error?.message || task?.prompt || "";
  return String(response).replace(/\s+/g, " ").slice(0, 150);
}

function androidNativeBackgroundRefreshDeferred(origin = "auto") {
  if (!isAndroidNativeShell() || !["startup", "auto", "poll"].includes(origin)) return false;
  if (androidNativeWakeListenerActive() || androidNativeResponsivenessOverloadedNow()) return true;
  return !isAdminPanel(state.activePanel)
    && !resourcesWidgetIsOpen()
    && !securityLoopIsOpen();
}

function androidNativeWakeListenerActive() {
  if (!isAndroidNativeShell()) return false;
  const packet = wakeWordLegacyState(wakeWordLastState || {});
  return Boolean(
    packet.foreground_service_active
      || packet.wake_service_ready
      || ["standby", "listening", "transcribing", "awake"].includes(cleanText(packet.listener_mode, ""))
  );
}

function androidNativeBackgroundSyncDeferred(origin = "poll") {
  if (!isAndroidNativeShell()) return false;
  if (!["startup", "start", "auto", "poll", "focus"].includes(String(origin || ""))) return false;
  return androidNativeWakeListenerActive() || androidNativeResponsivenessOverloadedNow() || androidNativeRecentUserInput(ANDROID_NATIVE_INPUT_FIRST_QUIET_MS);
}

function androidNativeLeanHomeBootstrap() {
  return isAndroidNativeShell()
    && normalizePanel(panelFromPath()) === "home"
    && !chatQueryIsOpen();
}

function scheduleAndroidNativeDeferredHomeUi(enabled = false) {
  if (!enabled) return;
  window.setTimeout(() => {
    void (async () => {
      await waitForAndroidNativeInputQuiet(ANDROID_NATIVE_INPUT_FIRST_QUIET_MS, { maxWaitMs: 20000 });
      if (androidNativeResponsivenessOverloadedNow()) {
        clientBootMark("android_home_deferred_ui_postponed", { reason: "responsiveness_gate" });
        scheduleAndroidNativeDeferredHomeUi(enabled);
        return;
      }
      renderModules();
      await androidNativeHydrationYield("deferred_home_modules");
      if (androidNativeResponsivenessOverloadedNow()) {
        clientBootMark("android_home_deferred_messages_postponed", { reason: "responsiveness_gate" });
        scheduleAndroidNativeDeferredHomeUi(enabled);
        return;
      }
      if (!state.agentOpen) renderAgentMessages({ forceBottom: true });
      applyAgentLayout();
      clientBootMark("android_home_deferred_ui_rendered");
    })();
  }, ANDROID_NATIVE_HYDRATION_START_DELAY_MS);
}

function scheduleAndroidNativeHydrationRender(reason = "hydration_render") {
  if (!isAndroidNativeShell()) {
    renderModules();
    renderAll();
    return;
  }
  window.setTimeout(() => {
    void (async () => {
      await waitForAndroidNativeInputQuiet(ANDROID_NATIVE_INPUT_FIRST_QUIET_MS, { maxWaitMs: 20000 });
      if (androidNativeResponsivenessOverloadedNow()) {
        clientBootMark("android_hydration_render_postponed", { reason });
        scheduleAndroidNativeHydrationRender(reason);
        return;
      }
      renderAll();
      clientBootMark("android_hydration_render_finished", { reason });
    })();
  }, ANDROID_NATIVE_HYDRATION_STEP_DELAY_MS);
}

async function refresh(origin = "auto") {
  const refreshTraceStartedAt = performance.now();
  if (origin === "startup") clientBootMark("refresh_startup_started");
  await syncUserSpacesForOpenClient(origin);
  if (androidNativeBackgroundRefreshDeferred(origin)) {
    if (origin === "startup") {
      clientBootMark("refresh_startup_deferred", {
        android_native: true,
        active_panel: cleanText(state.activePanel, ""),
        elapsed_ms: Math.round(performance.now() - refreshTraceStartedAt),
      });
    }
    return;
  }
  if (!isAdminUser()) {
    state.bridgeReady = false;
    state.nodes = [];
    state.tasks = [];
	    state.securityLoop = null;
	    state.securityLatestRun = null;
	    state.securityRuns = [];
	    state.securityFindings = [];
    renderAll();
    if (origin === "startup") {
      clientBootMark("refresh_startup_finished", {
        admin: false,
        elapsed_ms: Math.round(performance.now() - refreshTraceStartedAt),
      });
    }
    return;
  }
  const startedAt = performance.now();
  try {
    await bridgeJson("/health");
    state.bridgeReady = true;
    state.lastError = "";

	    const previousTokens = new Map(state.nodes.map((node) => [node.id, nodeAbsoluteTokens(node)]));
	    const [nodes, tasks] = await Promise.all([
	      bridgeJson("/nodes").catch(() => ({ nodes: [] })),
	      bridgeJson("/tasks").catch(() => ({ tasks: [] })),
	    ]);
	    state.nodes = (nodes.nodes || []).map(normalizeNode).map((node) => {
	      const previous = previousTokens.get(node.id);
	      const current = nodeAbsoluteTokens(node);
	      const baseline = nodeTokenBaseline(node.id, current);
	      const sinceRestart = Math.max(0, current - baseline);
	      const delta = Number.isFinite(previous) && current > previous ? current - previous : 0;
	      return {
	        ...node,
	        tokenUsage: {
	          ...node.tokenUsage,
	          absolute_total_tokens: current,
	          baseline_tokens: baseline,
	          total_tokens: sinceRestart,
	          delta_tokens: delta,
	          reset_scope: "widget",
	        }
	      };
	    });
    state.tasks = tasks.tasks || [];
    if (!state.resourceInterval && (resourcesWidgetIsOpen() || !["auto", "startup"].includes(origin))) {
      await loadResources(origin).catch(() => {});
    }
    if (state.nodes.length && !state.nodes.some((node) => node.id === state.selectedNode)) {
      state.selectedNode = state.nodes[0].id;
    }
    await loadSecurityLoop(origin).catch(() => {});
    renderAll();
    if (origin !== "auto") {
      recordUserEvent("workspace.refresh_finished", {
        target: "bridge",
        summary: `Refreshed ${state.nodes.length} nodes and ${state.tasks.length} tasks`,
        data: { origin, node_count: state.nodes.length, task_count: state.tasks.length, bridge_ready: state.bridgeReady },
        duration_ms: performance.now() - startedAt,
      });
    }
    if (origin === "startup") {
      clientBootMark("refresh_startup_finished", {
        admin: true,
        bridge_ready: Boolean(state.bridgeReady),
        node_count: state.nodes.length,
        task_count: state.tasks.length,
        elapsed_ms: Math.round(performance.now() - refreshTraceStartedAt),
      });
    }
  } catch (error) {
    state.bridgeReady = false;
    state.lastError = error.message;
    await loadSecurityLoop(origin).catch(() => {});
    renderAll();
    recordUserEvent("workspace.refresh_error", {
      target: "bridge",
      summary: error.message,
      data: { origin, error: error.message },
      duration_ms: performance.now() - startedAt,
    });
    if (origin === "startup") {
      clientBootMark("refresh_startup_error", {
        elapsed_ms: Math.round(performance.now() - refreshTraceStartedAt),
        message: errorMessage(error),
      });
    }
  } finally {
    renderAppLayer();
    syncResourcePolling();
    syncSecurityPolling();
  }
}

async function loadResources(origin = "auto") {
  try {
    const payload = await bridgeJson("/resources");
    state.resources = payload.resources || null;
    renderResources();
    if (origin !== "poll") {
      recordUserEvent("resources.loaded", {
        target: "resources",
        summary: state.resources?.timestamp ? `Loaded resources ${state.resources.timestamp}` : "Loaded resources",
        data: { origin, timestamp: state.resources?.timestamp || "" },
      });
    }
  } catch (error) {
    state.lastError = error.message;
    if (!state.resources) renderResources();
    if (origin !== "poll") {
      recordUserEvent("resources.load_error", {
        target: "resources",
        summary: error.message,
        data: { origin, error: error.message },
      });
    }
    throw error;
  }
}

function resourcesWidgetIsOpen() {
  const widget = widgetById("resources");
  return Boolean(state.authUser && widget && !widget.hidden && !widget.classList.contains("is-minimized"));
}

function securityLoopIsOpen() {
  const widget = widgetById("security-loop");
  return Boolean(isAdminUser() && (
    state.activePanel === "security"
    || (widget && !widget.hidden && !widget.classList.contains("is-minimized"))
  ));
}

function syncSecurityPolling() {
  if (securityLoopIsOpen()) {
    if (!state.securityInterval) {
      state.securityInterval = window.setInterval(() => void loadSecurityLoop("poll").catch(() => {}), SECURITY_POLL_MS);
      void loadSecurityLoop("open").catch(() => {});
    }
    return;
  }
  if (state.securityInterval) {
    window.clearInterval(state.securityInterval);
    state.securityInterval = 0;
  }
}

function syncResourcePolling() {
  if (resourcesWidgetIsOpen()) {
    if (!state.resourceInterval) {
      state.resourceInterval = window.setInterval(() => void loadResources("poll").catch(() => {}), RESOURCE_POLL_MS);
      void loadResources("open").catch(() => {});
    }
    return;
  }
  if (state.resourceInterval) {
    window.clearInterval(state.resourceInterval);
    state.resourceInterval = 0;
  }
}

function detectNativeDeviceProfileSync() {
  const userAgent = cleanText(navigator.userAgent || "", "Browser");
  const shell = androidNativeShellInfo();
  const ua = userAgent.toLowerCase();
  const platform = cleanText(navigator.platform || "", "");
  const maxTouchPoints = Number(navigator.maxTouchPoints || 0);
  const iPadOs = platform === "MacIntel" && maxTouchPoints > 1;
  const detectedPlatform = ua.includes("android")
    ? "android"
    : (ua.includes("iphone") || ua.includes("ipad") || iPadOs)
      ? "ios"
      : (ua.includes("mac os x") || ua.includes("macintosh"))
        ? "macos"
        : ua.includes("windows")
          ? "windows"
          : ua.includes("linux")
            ? "linux"
            : "unknown";
  const osLabel = {
    android: "Android",
    ios: "iOS/iPadOS",
    macos: "macOS",
    windows: "Windows",
    linux: "Linux",
    unknown: "Unknown",
  }[detectedPlatform] || "Unknown";
  const browser = shell.isAndroidNativeShell
    ? "android-webview"
    : ua.includes("edg/")
    ? "edge"
    : (ua.includes("chrome/") || ua.includes("crios/"))
      ? "chrome"
      : (ua.includes("firefox/") || ua.includes("fxios/"))
        ? "firefox"
        : ua.includes("safari/")
          ? "safari"
          : "unknown";
  const browserLabel = {
    chrome: "Chrome",
    edge: "Edge",
    firefox: "Firefox",
    safari: "Safari",
    "android-webview": "Android WebView",
    unknown: "Unknown",
  }[browser] || "Unknown";
  const deviceType = detectedPlatform === "android" || detectedPlatform === "ios"
    ? (ua.includes("ipad") || iPadOs || (detectedPlatform === "android" && !ua.includes("mobile")) ? "tablet" : "phone")
    : detectedPlatform === "unknown"
      ? "unknown"
      : "desktop";
  const installChannel = shell.isAndroidNativeShell
    ? "android-native-shell"
    : {
    android: "android-apk",
    ios: "ios-testflight-or-app-store",
    macos: "macos-installer",
    windows: "windows-installer",
    linux: "linux-installer",
    unknown: "manual-platform-choice",
  }[detectedPlatform] || "manual-platform-choice";
  return {
    schema: "hermes.wasm_agent.native_device_profile.v1",
    platform: detectedPlatform,
    arch: "unknown",
    os: osLabel,
    browser,
    browser_label: browserLabel,
    deviceType,
    device_type: deviceType,
    installChannel: installChannel,
    install_channel: installChannel,
    user_agent: userAgent,
    navigator_platform: platform,
    max_touch_points: Number.isFinite(maxTouchPoints) ? maxTouchPoints : 0,
    display_mode: shell.isAndroidNativeShell
      ? "android-native-shell"
      : window.matchMedia?.("(display-mode: standalone)")?.matches ? "standalone" : "browser",
    native_shell: shell.isAndroidNativeShell ? shell : null,
    pwa_capabilities: {
      microphone: Boolean(navigator.mediaDevices?.getUserMedia),
      service_worker: Boolean(navigator.serviceWorker),
      wake_lock: Boolean(navigator.wakeLock),
      screen_off_standby: false,
    },
  };
}

async function detectNativeDeviceProfile() {
  const profile = detectNativeDeviceProfileSync();
  const userAgentData = navigator.userAgentData;
  if (userAgentData?.getHighEntropyValues) {
    try {
      const high = await userAgentData.getHighEntropyValues(["architecture", "bitness", "model", "platform", "platformVersion"]);
      profile.user_agent_data = {
        architecture: cleanText(high.architecture, ""),
        bitness: cleanText(high.bitness, ""),
        model: cleanText(high.model, ""),
        platform: cleanText(high.platform, ""),
        platform_version: cleanText(high.platformVersion, ""),
        mobile: Boolean(userAgentData.mobile),
      };
      const arch = cleanText(high.architecture, "").toLowerCase();
      const bitness = cleanText(high.bitness, "").toLowerCase();
      profile.arch = arch.includes("arm") ? (bitness === "64" || arch.includes("64") ? "arm64" : "arm") : bitness === "64" ? "x64" : "unknown";
      if (userAgentData.mobile && profile.device_type === "desktop") profile.device_type = "phone";
      profile.deviceType = profile.device_type;
    } catch {
      // User-agent high entropy fields are optional and may be denied.
    }
  }
  return profile;
}

function nativeInstallCurrentDevice() {
  return state.devices.find((device) => device.current) || null;
}

function filenameFromContentDisposition(header = "") {
  const match = String(header || "").match(/filename\*?=(?:UTF-8''|")?([^";\r\n]+)/i);
  if (!match) return "";
  try {
    return decodeURIComponent(match[1].replace(/^"|"$/g, ""));
  } catch {
    return match[1].replace(/^"|"$/g, "");
  }
}

function downloadBlob(filename, blob) {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.append(link);
  link.click();
  link.remove();
  window.setTimeout(() => URL.revokeObjectURL(url), 0);
}

function downloadUrl(filename, url) {
  if (isAndroidNativeShell()) {
    nativeShellDiagnostic("renderer_download_url_requested", {
      filename: cleanText(filename, ""),
      url: cleanText(url, ""),
    });
  }
  const link = document.createElement("a");
  link.href = url;
  link.download = filename || "";
  link.rel = "noopener";
  document.body.append(link);
  link.click();
  link.remove();
}

function nativePrimaryCtaLabel(resolution = state.nativeInstallerResolution, profile = state.nativeInstallProfile) {
  const platform = cleanText(resolution?.platform || profile?.platform, "unknown").toLowerCase();
  if (platform === "windows") return nativeInstallerUpdateAvailable(resolution, profile) ? "Update App" : "Download Windows Installer";
  if (platform === "android") return nativeInstallerUpdateAvailable(resolution, profile) ? "Update APK" : "Download Android APK";
  if (platform === "web") return nativeInstallerUpdateAvailable(resolution, profile) ? "Refresh App" : "Open Web App";
  if (platform === "macos") return "Download macOS Installer";
  if (platform === "linux") return "Download Linux Installer";
  if (platform === "ios") return "View iOS install options";
  return "Choose platform manually";
}

async function resolveNativeInstaller(profile) {
  const controller = new AbortController();
  const timer = window.setTimeout(() => controller.abort(), 10000);
  try {
    const body = {
      platform: profile.platform || "unknown",
      arch: profile.arch || "unknown",
      deviceType: profile.deviceType || profile.device_type || "unknown",
      browser: profile.browser || "unknown",
      userAgent: profile.user_agent || navigator.userAgent || "",
      accountId: state.authUser?.id || "",
      deviceId: nativeInstallCurrentDevice()?.id || state.deviceAuthority?.current_device_id || clientDeviceId(),
    };
    const response = await fetch("/native/resolve", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Wasm-Agent-Device-Id": clientDeviceId(),
      },
      body: JSON.stringify(body),
      signal: controller.signal,
    });
    const payload = await response.json();
    if (!response.ok) throw new Error(payload?.error?.message || `Native installer resolve failed (${response.status})`);
    return payload;
  } finally {
    window.clearTimeout(timer);
  }
}

function renderNativeInstall() {
  if (!els.nativeDeviceSummary || !els.nativePackageSummary || !els.nativeInstallStatus) return;
  const profile = nativeInstallProfileForContext(state.nativeInstallProfile || detectNativeDeviceProfileSync());
  const device = nativeInstallCurrentDevice();
  const resolution = state.nativeInstallerResolution || null;
  const updateAvailable = nativeInstallerUpdateAvailable(resolution, profile);
  const updateState = state.nativeUpdateState || null;
  const updatePlatform = cleanText(updateState?.platform, "").toLowerCase();
  const profilePlatform = cleanText(profile.platform, "").toLowerCase();
  const updateStateForProfile = updatePlatform && updatePlatform === profilePlatform ? updateState : null;
  const diagnosticsBridgeMissing = windowsNativeShellDiagnosticsBridgeMissing();
  const installedBuildId = nativeInstalledBuildId();
  const latestBuildId = nativeResolutionBuildId(resolution);
  const updateSubtitle = profilePlatform === "android"
    ? "Android APK update available"
    : profilePlatform === "windows"
      ? "Windows app update required"
      : `${profile.os} update available`;
  const status = state.nativeInstallBusy
    ? "checking"
    : state.nativeInstallError
      ? "error"
      : updateStateForProfile?.status === "up_to_date"
        ? "up to date"
        : updateStateForProfile?.status === "update_available"
          ? "update"
      : resolution?.available
        ? updateAvailable ? "update" : "available"
        : resolution
          ? "missing"
          : "native";
  els.nativeInstallStatus.textContent = status;
  els.nativeInstallStatus.className = `widget-chip ${status === "available" ? "ok" : status === "update" ? "warn" : status === "error" || status === "missing" ? "err" : ""}`;
  if (els.nativeModalSubtitle) {
    els.nativeModalSubtitle.textContent = updateAvailable
      ? updateSubtitle
      : diagnosticsBridgeMissing
        ? "Diagnostics bridge missing; update the Windows app"
      : `${profile.os} / ${profile.device_type || profile.deviceType}`;
  }
  if (els.nativeDownloadButton) {
    els.nativeDownloadButton.textContent = nativePrimaryCtaLabel(resolution, profile);
    els.nativeDownloadButton.disabled = !state.authUser || state.nativeInstallBusy || updateStateForProfile?.status === "up_to_date" || (resolution && !resolution.available && resolution.platform !== "ios" && resolution.platform !== "unknown");
    els.nativeDownloadButton.classList.toggle("is-busy", Boolean(state.nativeInstallBusy));
  }

  const deviceTitle = document.createElement("h3");
  deviceTitle.textContent = "Detected Device";
  els.nativeDeviceSummary.replaceChildren(
    deviceTitle,
    metric("OS", profile.os),
    metric("Device type", cleanText(profile.device_type || profile.deviceType, "unknown")),
    metric("Browser", `${cleanText(profile.browser_label, profile.browser)} / ${profile.display_mode}`),
    metric("Architecture", cleanText(profile.arch, "unknown")),
    metric("Installer channel", cleanText(profile.install_channel || profile.installChannel, "manual-platform-choice")),
    metric("Account", cleanText(device?.id || state.deviceAuthority?.current_device_id, "pending")),
  );

  const packageTitle = document.createElement("h3");
  packageTitle.textContent = "Native Installer";
  const packageRows = state.nativeInstallError
    ? [
        metric("Status", "error"),
        metric("Error", truncateText(state.nativeInstallError, 120)),
      ]
    : resolution
      ? [
          metric("Status", updateAvailable ? "update available" : resolution.available ? "available" : cleanText(resolution.message, "Native installer not built yet")),
          metric("Kind", cleanText(resolution.kind, "native-installer")),
          metric("File", cleanText(resolution.filename, "not built")),
          metric("Build", cleanText(resolution.buildStatus, resolution.available ? "built" : "missing")),
          metric("Current", installedBuildId || updateState?.currentBuildId || "unknown"),
          metric("Latest", latestBuildId || updateState?.latestBuildId || "unknown"),
          updateStateForProfile?.artifactAvailable === false ? metric("Artifact", "unavailable") : null,
          updateStateForProfile?.message ? metric("Install", updateStateForProfile.message) : null,
          diagnosticsBridgeMissing ? metric("Bridge", "Diagnostics bridge missing") : null,
          updateAvailable && profilePlatform === "windows" && !windowsNativeShellNeedsDiagnosticsUpdate() ? metric("Reason", "New Windows build available") : null,
          updateAvailable && profilePlatform === "android" ? metric("Reason", "New Android APK available") : null,
          metric("Fallbacks", Array.isArray(resolution.fallbacks) && resolution.fallbacks.length ? resolution.fallbacks.map((item) => cleanText(item?.label || item?.kind, "")).filter(Boolean).join(", ") : "none"),
        ].filter(Boolean)
      : [
          metric("Status", state.nativeInstallBusy ? "checking" : "pending"),
          metric("Kind", cleanText(profile.install_channel || profile.installChannel, "native-installer")),
          metric("File", "pending"),
          metric("Build", "checking"),
        ];
  els.nativePackageSummary.replaceChildren(packageTitle, ...packageRows);

  if (els.nativeManualChooser) {
    const title = document.createElement("h3");
    title.textContent = "Manual chooser";
    const list = document.createElement("div");
    list.className = "native-choice-list";
    [
      ["windows", "Windows"],
      ["android", "Android"],
      ["macos", "macOS"],
      ["linux", "Linux"],
      ["ios", "iOS/iPadOS"],
      ["pwa", "Install PWA fallback"],
    ].forEach(([platformId, label]) => {
      const button = document.createElement("button");
      button.type = "button";
      button.textContent = label;
      button.addEventListener("click", () => chooseNativePlatform(platformId));
      list.append(button);
    });
    els.nativeManualChooser.replaceChildren(title, list);
  }
}

function chooseNativePlatform(platform) {
  if (platform === "pwa") {
    state.nativeInstallError = "Install PWA is a separate fallback lane; use the browser install control.";
    renderNativeInstall();
    return;
  }
  state.nativeInstallProfile = {
    ...(state.nativeInstallProfile || detectNativeDeviceProfileSync()),
    platform,
    os: { windows: "Windows", android: "Android", macos: "macOS", linux: "Linux", ios: "iOS/iPadOS" }[platform] || "Unknown",
    install_channel: {
      windows: "windows-installer",
      android: "android-apk",
      macos: "macos-installer",
      linux: "linux-installer",
      ios: "ios-testflight-or-app-store",
    }[platform] || "manual-platform-choice",
  };
  state.nativeInstallProfile.installChannel = state.nativeInstallProfile.install_channel;
  state.nativeInstallerResolution = null;
  void startNativeInstall("manual-platform", { keepProfile: true });
}

function openNativeModal(options = {}) {
  applyNativeShellUi();
  setPanel("home", { updateUrl: false });
  state.nativeInstallProfile = nativeInstallProfileForContext(detectNativeDeviceProfileSync());
  state.nativeInstallerResolution = null;
  state.nativeInstallError = "";
  if (els.nativeModal) els.nativeModal.hidden = false;
  const renderAndResolve = () => {
    renderNativeInstall();
    void loadNativeReleaseManifest().catch(() => {});
    if (options.autoStart !== false) void startNativeInstall(options.origin || "home-go-native", { resolveOnly: true }).catch(() => {});
  };
  if (isAndroidNativeShell()) {
    window.requestAnimationFrame?.(() => window.setTimeout(renderAndResolve, ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS))
      || window.setTimeout(renderAndResolve, ANDROID_NATIVE_CONTROL_INTERACTION_QUIET_MS);
  } else {
    renderAndResolve();
  }
  if (!options.skipHistory) {
    pushUiNavigationLayer("native-modal", () => closeNativeModal({ skipHistory: true, skipStack: true }));
  }
  recordUserEvent("home.go_native_opened", {
    target: "home:go-native",
    summary: "Opened native installer",
    data: {
      os: state.nativeInstallProfile.os,
      device_type: state.nativeInstallProfile.device_type,
      install_channel: state.nativeInstallProfile.install_channel,
      update_required: nativeInstallerUpdateAvailable(state.nativeInstallerResolution),
      diagnostics_bridge_missing: windowsNativeShellDiagnosticsBridgeMissing(),
    },
  });
}

function closeNativeModal(options = {}) {
  if (!options.skipHistory && closeUiNavigationLayer("native-modal")) return;
  if (els.nativeModal) els.nativeModal.hidden = true;
  if (!options.skipStack) {
    closeUiNavigationLayer("native-modal", { skipHistory: true, replaceHistory: true });
  }
}

function shouldOpenNativeDebugFromLocation() {
  return window.location.pathname === "/native/debug";
}

